const s={id:"uti",name:"Urinary Tract Infections",icon:"🔬",category:"Infectious Disease",overview:{definition:"Infections of the urinary tract encompassing the bladder (cystitis), kidneys (pyelonephritis), and associated structures. Classification depends on anatomical location, severity, and presence of complicating factors.",epidemiology:"Among the most common bacterial infections worldwide. ~50-60% of women will experience at least one UTI in their lifetime. Recurrence rate of ~25% within 6 months of initial episode.",keyGuidelines:[{name:"IDSA 2025 cUTI Guideline (NEW)",detail:"First-ever IDSA guideline on complicated UTI. Introduces a 4-step empiric therapy approach (severity → resistance risk factors → patient factors → antibiogram). Supports shorter durations (FQ 5-7d, non-FQ 7d) and early IV-to-PO switch even in bacteremia. Reclassifies cUTI based on systemic symptoms, not anatomy. Endorsed by AUA, ESCMID, ASM, SAEM, SHM, SIDP, AMMI-CA."},{name:"IDSA/ESCMID 2011",detail:"International Clinical Practice Guidelines for uncomplicated cystitis and pyelonephritis in women — remains relevant for uncomplicated UTI management"},{name:"AUA/CUA/SUFU 2019",detail:"Recurrent UTI guideline — important for prophylaxis strategies"},{name:"IDSA 2010 CAUTI",detail:"Diagnosis, prevention, and treatment of catheter-associated UTI"},{name:"EAU 2024",detail:"European Association of Urology guidelines — frequently updated, good for emerging resistance data"}],landmarkTrials:[{name:"IDSA 2025 cUTI Guideline",detail:"First-ever IDSA guideline on complicated UTI. Paradigm shift: reclassifies UTI by symptoms (systemic signs) not anatomy, introduces 4-step empiric approach, endorses 7-day courses even for bacteremic UTI, formalizes IV-to-PO switch in bacteremia, and restricts novel agents to definitive therapy only."},{name:"ALTAR Trial (2018)",detail:"Demonstrated non-inferiority of antibiotic advice vs. immediate antibiotics for uncomplicated UTI in women. Delayed/back-up prescription is a viable strategy."},{name:"Pivmecillinam vs TMP-SMX (Nicolle, 2000s)",detail:"Established pivmecillinam as a viable alternative in regions with high TMP-SMX resistance."},{name:"Hooton et al. NEJM 2012",detail:"Ibuprofen vs. fosfomycin for uncomplicated cystitis — showed ~⅔ of women with uncomplicated cystitis resolved with ibuprofen alone, but higher pyelonephritis risk. Does NOT support replacing antibiotics with NSAIDs."},{name:"COMBINE Trial (2023)",detail:"Nitrofurantoin 3 days vs 5 days for uncomplicated cystitis — 3 days was non-inferior, supporting shorter courses."}],riskFactors:"Sexual intercourse, spermicide use, prior UTI history, diabetes, urinary catheterization, anatomical abnormalities, post-menopausal status (estrogen depletion), pregnancy, immunosuppression, urinary retention/obstruction."},subcategories:[{id:"uncomplicated-cystitis",name:"Uncomplicated Cystitis",definition:"Acute cystitis in a non-pregnant, pre-menopausal woman with no known urological abnormalities, no recent instrumentation, and no systemic signs of infection.",clinicalPresentation:"Dysuria, urinary frequency, urgency, suprapubic pain/discomfort. Absence of fever, flank pain, or systemic symptoms.",diagnostics:"Urinalysis (positive LE and/or nitrites) is sufficient. Urine culture NOT routinely required per IDSA guidelines for straightforward presentations. Culture recommended if: recurrent infection, recent antibiotic use, or uncertain diagnosis.",durationGuidance:{standard:"3–5 days (nitrofurantoin/fosfomycin)",severe:"7 days (TMP-SMX/fluoroquinolone)",stewardshipNote:"Shorter courses non-inferior in uncomplicated cystitis. Avoid fluoroquinolones as first-line per IDSA 2011."},empiricTherapy:[{line:"First-Line",options:[{drug:"nitrofurantoin",regimen:"Nitrofurantoin monohydrate/macrocrystals 100mg PO BID × 5 days",notes:"Preferred agent. COMBINE trial supports potential 3-day course. Avoid if CrCl <30 mL/min (though recent data supports use down to ~20). Not effective for anything beyond the bladder.",evidence:"A-I",evidenceSource:"IDSA 2011"},{drug:"tmp-smx",regimen:"TMP-SMX DS (160/800mg) PO BID × 3 days",notes:"Use only if local resistance <20%. Avoid if used in prior 3 months. Check sulfa allergy. 3-day course is well established.",evidence:"A-I",evidenceSource:"IDSA 2011"},{drug:"fosfomycin",regimen:"Fosfomycin trometamol 3g PO × 1 dose",notes:"Single-dose convenience. Slightly inferior efficacy vs. multi-day regimens per meta-analyses. Good for adherence-challenged patients. Mix in water, not hot beverages.",evidence:"A-I",evidenceSource:"IDSA 2011"}]},{line:"Second-Line (use when first-line agents cannot be used)",options:[{drug:"amox-clav",regimen:"Amoxicillin-Clavulanate 500/125mg PO BID × 5-7 days",notes:"Inferior efficacy to first-line agents for uncomplicated cystitis. More collateral damage. Reserve when others unavailable.",evidence:"B-II",evidenceSource:"IDSA 2011"},{drug:"cephalexin",regimen:"Cephalexin 500mg PO BID-QID × 5-7 days",notes:"Reasonable alternative. Better tolerated than amox-clav. Limited guideline support as first choice.",evidence:"B-II",evidenceSource:"IDSA 2011"},{drug:"cefpodoxime",regimen:"Cefpodoxime 100mg PO BID × 5-7 days",notes:"Third-gen oral cephalosporin option. Broader spectrum than needed for most uncomplicated cases.",evidence:"B-II",evidenceSource:"IDSA 2011"}]},{line:"AVOID for Uncomplicated Cystitis",options:[{drug:"fluoroquinolones",regimen:"Ciprofloxacin, Levofloxacin",notes:"FDA boxed warning — reserve for infections with no other options. Massive collateral ecological damage. Risk of tendinopathy, aortic dissection, QT prolongation, CNS effects, peripheral neuropathy. IDSA explicitly recommends AGAINST for uncomplicated cystitis."}]}],organismSpecific:[{organism:"E. coli (75-95%)",preferred:"Per empiric guidelines above — nitrofurantoin, TMP-SMX (if susceptible), fosfomycin",alternative:"Cephalexin, cefpodoxime, amox-clav",notes:"Dominant pathogen. Rising resistance to TMP-SMX (15-25% in US) and fluoroquinolones (10-20%). Always check local antibiogram."},{organism:"Klebsiella pneumoniae (5-10%)",preferred:"TMP-SMX (if susceptible), cephalexin, cefpodoxime",alternative:"Amox-clav, fluoroquinolone",notes:"Intrinsically resistant to ampicillin. Watch for ESBL producers. Nitrofurantoin has borderline activity — generally avoid."},{organism:"Staphylococcus saprophyticus (5-10%)",preferred:"Nitrofurantoin, TMP-SMX, cephalexin",alternative:"Amox-clav",notes:"Second most common cause in young sexually active women. Typically very susceptible. Nitrite test often NEGATIVE (doesn't reduce nitrates)."},{organism:"Proteus mirabilis (3-5%)",preferred:"TMP-SMX (if susceptible), amox-clav, cephalosporins",alternative:"Fluoroquinolone",notes:"Intrinsically resistant to nitrofurantoin. Urease producer — associated with struvite stones. Alkaline urine is a clue."},{organism:"Enterococcus faecalis",preferred:"Amoxicillin 500mg TID, Nitrofurantoin",alternative:"Fosfomycin",notes:"Intrinsically resistant to cephalosporins and TMP-SMX. Do NOT use these even if lab reports 'susceptible' for cephalosporins — this is a known lab/clinical discordance."}],pearls:["Pyuria without bacteriuria? Think: recent antibiotics, interstitial cystitis, STI (chlamydia/gonorrhea), renal TB, or contamination.","Asymptomatic bacteriuria (ASB) should NOT be treated except in pregnancy and before urologic procedures. Treating ASB drives resistance.","Nitrofurantoin achieves excellent bladder concentrations but negligible serum/tissue levels — it ONLY treats cystitis, never pyelonephritis or bacteremia.","The classic 'cranberry juice prevents UTIs' has weak evidence. PAC-A (proanthocyanidins) at 36mg/day in supplement form has slightly better data but is not a substitute for antibiotics.","Post-menopausal women with recurrent UTI: vaginal estrogen cream is evidence-based prophylaxis (Cochrane review supports). Counsel patients on this.","D-mannose 2g daily has RCT data (Kranjčec 2014) showing similar recurrence prevention to nitrofurantoin prophylaxis. Reasonable to trial."]},{id:"complicated-uti",name:"Complicated UTI",definition:"Per IDSA 2025 reclassification: UTI with localized symptoms AND systemic signs (fever ≥38°C, hemodynamic instability, or signs of sepsis) suggesting infection beyond the bladder. Also includes UTI with indwelling urinary catheter. IMPORTANT: The 2025 guidelines shift classification from anatomy-based (old: structural abnormalities, male sex) to symptom-based (new: presence of systemic signs at point-of-care). Pyelonephritis with fever is now classified as cUTI. Male UTI with fever is cUTI. Male UTI without systemic signs may be treated as uncomplicated.",clinicalPresentation:"Fever ≥38°C, flank pain, CVA tenderness, rigors, hemodynamic instability, altered mental status — any systemic sign suggesting infection beyond the bladder. The 2025 classification emphasizes point-of-care assessment: vital signs and catheter status are the primary drivers, NOT anatomical workup.",diagnostics:"Urine culture is REQUIRED (pre-treatment). Blood cultures if systemic signs or sepsis suspected. Assess severity: is the patient septic? Use Sepsis-3 criteria (SOFA ≥2), qSOFA, or SIRS as screening tools. CBC, BMP, lactate if sepsis concern. Imaging (CT/US) if obstruction, abscess, or failure to improve at 48-72h.",empiricTherapy:[{line:"IDSA 2025 Four-Step Approach",options:[{drug:"four-step-overview",regimen:"Step 1: Severity (sepsis vs. non-sepsis) → Step 2: Resistance risk factors → Step 3: Patient-specific factors → Step 4: Antibiogram (sepsis only)",notes:"This structured approach replaces the old 'pick an antibiotic' model. Each step narrows the empiric selection. The guideline emphasizes that inappropriate empiric therapy has little impact on mortality in NON-SEPTIC cUTI (mortality ≤5%), but is critical in sepsis/septic shock."}]},{line:"First-Line — cUTI WITHOUT Sepsis",options:[{drug:"ceftriaxone",regimen:"Ceftriaxone 1-2g IV daily (or cefepime 2g IV q8h if AmpC/Pseudomonas concern)",notes:"IDSA 2025 preferred: 3rd/4th-gen cephalosporins. Carbapenems are NOT first-line for non-septic cUTI — this is a key stewardship change. Reserve carbapenems for sepsis or confirmed ESBL.",evidence:"A-I",evidenceSource:"IDSA 2011"},{drug:"pip-tazo",regimen:"Piperacillin-tazobactam 3.375g IV q6h (or 4.5g q8h extended infusion)",notes:"IDSA 2025 preferred empiric option. Extended infusion (over 4h) optimizes PK/PD. Appropriate when broader coverage desired (Pseudomonas risk).",evidence:"A-I",evidenceSource:"IDSA 2011"},{drug:"ciprofloxacin",regimen:"Ciprofloxacin 500mg PO BID or Levofloxacin 750mg PO daily",notes:"IDSA 2025 preferred IF no FQ exposure in past 12 months (Step 2). Advantage: oral administration avoids IV, enables outpatient treatment. AVOID if FQ used in prior 12 months — guideline-specific recommendation.",evidence:"A-I",evidenceSource:"IDSA 2011"}]},{line:"First-Line — cUTI WITH Sepsis",options:[{drug:"ceftriaxone-sepsis",regimen:"Ceftriaxone 2g IV daily or Cefepime 2g IV q8h",notes:"IDSA 2025: same preferred classes but carbapenems now INCLUDED as first-line for sepsis (not restricted to ESBL). Priority shifts to ensuring early appropriate therapy — stewardship deferred to definitive phase."},{drug:"pip-tazo-sepsis",regimen:"Piperacillin-tazobactam 4.5g IV q6-8h (extended infusion)",notes:"Preferred in sepsis. Extended infusion standard of care. Consider if Pseudomonas risk based on prior cultures."},{drug:"meropenem",regimen:"Meropenem 1g IV q8h (extended infusion over 3h)",notes:"IDSA 2025 includes carbapenems as first-line option for SEPSIS (unlike non-septic cUTI). Use if ESBL risk, prior MDR organisms, or septic shock. Antibiogram step: select agent with ≥90% susceptibility for septic shock, ≥80% for sepsis without shock."},{drug:"levofloxacin-sepsis",regimen:"Levofloxacin 750mg IV daily",notes:"FQs remain a preferred class even in sepsis IF no prior FQ exposure in 12 months. 100% bioavailability supports early PO switch once stable."}]},{line:"Newer Agents (Reserve — NOT First-Line per IDSA 2025)",options:[{drug:"newer-agents",regimen:"Ceftazidime-avibactam, Meropenem-vaborbactam, Ceftolozane-tazobactam, Cefiderocol, Plazomicin",notes:"IDSA 2025 explicitly recommends AGAINST using novel BL-BLI agents and cefiderocol as empiric first-line, even in sepsis. Reserve for definitive therapy of MDR/XDR organisms (CRE, MBL-producers, DTR Pseudomonas). This is a major stewardship statement — protect these agents."}]},{line:"Duration (IDSA 2025 — Shorter Courses Endorsed)",options:[{drug:"duration-fq",regimen:"Fluoroquinolone: 5-7 days total (moderate certainty evidence)",notes:"Counted from first day of EFFECTIVE therapy. Shorter than traditional 7-14 day recommendations. Practice-changing for stewardship."},{drug:"duration-non-fq",regimen:"Non-fluoroquinolone: 7 days total (very low certainty evidence)",notes:"7 days is now the suggested standard, NOT 10-14 days. Applies to cephalosporins, pip-tazo, carbapenems. Exception: suspected prostatitis in men — may need 10-14 days."},{drug:"duration-bacteremia",regimen:"cUTI with gram-negative bacteremia: 7 days total (low certainty evidence)",notes:"IDSA 2025 suggests 7 days even for BACTEREMIC cUTI, not 14 days. This is a landmark recommendation — shorter courses for bacteremic UTI are now guideline-endorsed. Count from first day of effective therapy."}]},{line:"IV-to-PO Step-Down (IDSA 2025 — Formally Endorsed)",options:[{drug:"iv-po-switch",regimen:"Switch when: clinically improving, able to take oral meds, effective oral option available",notes:"IDSA 2025 formally endorses early IV-to-PO transition, even in gram-negative bacteremia (conditional recommendation). Oral options: FQs (ciprofloxacin, levofloxacin), TMP-SMX, amox-clav (if susceptible). Effective oral agent must achieve therapeutic levels in urine AND tissue AND be active against the pathogen."}]}],organismSpecific:[{organism:"ESBL-producing Enterobacterales",preferred:"Carbapenems (ertapenem 1g IV daily for non-Pseudomonal; meropenem if Pseudomonas risk)",alternative:"IDSA 2025 lists novel BL-BLIs for definitive therapy of confirmed ESBL. Pip-tazo controversial per MERINO trial for bacteremia but IDSA 2025 does not exclude it for UTI-source if susceptible.",notes:"MERINO Trial (2018, JAMA): Pip-tazo inferior to meropenem for ESBL E. coli/Kleb bacteremia. For ESBL cUTI without bacteremia, pip-tazo may suffice if MIC ≤16. Nitrofurantoin or fosfomycin may work for ESBL cystitis (uncomplicated). IDSA 2025 Step 2: prior urine culture showing ESBL = avoid cephalosporins/pip-tazo empirically → go to carbapenem."},{organism:"Pseudomonas aeruginosa",preferred:"Cefepime, pip-tazo, meropenem (IV); Ciprofloxacin (only reliable oral anti-pseudomonal)",alternative:"Ceftazidime, tobramycin",notes:"Culture-guided therapy essential. IDSA 2025 Step 2: if prior urine culture grew Pseudomonas, select agent with known activity. Cipro is the only oral option with reliable Pseudomonal activity — critical for step-down."},{organism:"Enterococcus faecium (VRE)",preferred:"Linezolid 600mg PO/IV BID, Nitrofurantoin (if cystitis only)",alternative:"Fosfomycin (limited data), Daptomycin (poor urinary excretion — unreliable for UTI)",notes:"Confirm true infection vs colonization. Many VRE UTIs are ASB. Linezolid achieves urinary concentrations. IDSA 2025 does not specifically address VRE UTI in the cUTI guideline — expert opinion applies."},{organism:"CRE (Carbapenem-Resistant Enterobacterales)",preferred:"Ceftazidime-avibactam (KPC), Meropenem-vaborbactam (KPC), Cefiderocol (MBL/broad)",alternative:"Plazomicin, Imipenem-relebactam",notes:"IDSA 2025 explicitly reserves these novel agents for DEFINITIVE therapy of confirmed resistant organisms. Do NOT use empirically unless prior cultures confirm CRE. Know your mechanism: KPC → ceftaz-avi or mer-vab. MBL (NDM, VIM) → cefiderocol or aztreonam + ceftaz-avi."}],pearls:["IDSA 2025 RECLASSIFICATION: The biggest conceptual change — complicated vs uncomplicated UTI is now based on SYMPTOMS (systemic signs like fever, hemodynamic instability), NOT anatomy. A male with cystitis symptoms only and no fever may be treated as uncomplicated. This is a paradigm shift from the old 'male UTI = always complicated' teaching.","THE FOUR-STEP APPROACH: (1) Sepsis? → determines which agents are first-line. (2) Prior resistant urine cultures? Prior FQ in 12 months? → avoid those agents empirically. (3) Allergies, drug interactions, renal function? → refine selection. (4) Septic? → check antibiogram, target ≥90% susceptibility for shock, ≥80% for sepsis without shock.","SHORTER DURATIONS ARE HERE: 5-7 days for FQ, 7 days for non-FQ, and 7 days even for BACTEREMIC cUTI. The traditional 10-14 day courses are no longer guideline-supported for most patients. This is a massive stewardship win — advocate for it.","CARBAPENEMS RESTRICTED FOR NON-SEPTIC cUTI: IDSA 2025 explicitly recommends against carbapenems as first-line for cUTI without sepsis. This is carbapenem-sparing stewardship at the guideline level. Push cephalosporins and pip-tazo first.","NOVEL AGENTS ARE NOT EMPIRIC: Ceftazidime-avibactam, meropenem-vaborbactam, cefiderocol, plazomicin — these are reserved for DEFINITIVE therapy of confirmed MDR/XDR organisms. Using them empirically drives resistance to our last-line agents. Protect them.","FQ AVOIDANCE IF PRIOR EXPOSURE: If the patient received ANY fluoroquinolone in the past 12 months, the 2025 guideline specifically recommends avoiding empiric FQ for cUTI. The risk of FQ-resistant uropathogen is substantially increased. Use a cephalosporin or pip-tazo instead.","IV-TO-PO SWITCH IN BACTEREMIA: IDSA 2025 formally endorses oral step-down even in gram-negative bacteremia from UTI source — when clinically improving, afebrile, hemodynamically stable, source controlled, and effective oral option available. This eliminates the 'must complete IV for bacteremia' dogma. Champion this.","ANTIBIOGRAM THRESHOLDS: For septic shock, select an agent with ≥90% susceptibility on the local antibiogram. For sepsis without shock, ≥80% is acceptable. These thresholds are derived from mortality modeling — not arbitrary numbers.","Male UTI nuance: The 2025 guidelines note that men with febrile UTI where prostatitis is suspected may need 10-14 days (the 7-day recommendation may not apply). Always consider prostatitis in febrile male UTI — it changes duration AND agent selection (need prostate-penetrating drugs: FQs, TMP-SMX)."]},{id:"pyelonephritis",name:"Acute Pyelonephritis",definition:"Upper urinary tract infection involving the renal parenchyma. NOTE: Per IDSA 2025 reclassification, pyelonephritis WITH fever/systemic signs is now classified as COMPLICATED UTI — see the Complicated UTI section for the 4-step empiric approach, duration, and IV-to-PO switch guidance. This section retains the clinical presentation, organism-specific data, and outpatient management details. Uncomplicated pyelonephritis (non-pregnant, pre-menopausal woman, no systemic toxicity) can still be managed outpatient per IDSA/ESCMID 2011.",clinicalPresentation:"Fever (>38°C), flank pain, costovertebral angle (CVA) tenderness, with or without lower urinary tract symptoms. Nausea, vomiting common. May present with sepsis. Per IDSA 2025: the presence of fever makes this a complicated UTI by new classification.",diagnostics:"Urine culture REQUIRED. Blood cultures recommended (bacteremia present in 15-30% of cases). CBC, BMP (assess renal function). CT abdomen/pelvis if: no improvement at 48-72h, suspected obstruction, or abscess concern.",durationGuidance:{standard:"7 days (fluoroquinolone IV→PO)",severe:"14 days (complex/bacteremic)",opatNote:"IV→PO switch appropriate once afebrile ≥24h and tolerating oral intake",stewardshipNote:"IDSA 2011 recommends ciprofloxacin 500mg BID × 7d or TMP-SMX × 14d"},empiricTherapy:[{line:"Outpatient (Uncomplicated, Tolerating PO, Not Septic)",options:[{drug:"ciprofloxacin",regimen:"Ciprofloxacin 500mg PO BID × 7 days",notes:"IDSA first-line for outpatient pyelo IF local FQ resistance <10%. 7-day course is established.",evidence:"A-I",evidenceSource:"IDSA 2011"},{drug:"tmp-smx",regimen:"TMP-SMX DS PO BID × 14 days",notes:"Alternative if FQ cannot be used. Requires 14 days (longer than FQ). IDSA recommends a one-time IV dose of ceftriaxone 1g or aminoglycoside with initiation if using TMP-SMX empirically (pending cultures).",evidence:"B-II",evidenceSource:"IDSA 2011"},{drug:"ceftriaxone-oral-step",regimen:"Ceftriaxone 1g IV/IM × 1 dose THEN oral step-down (cefpodoxime, TMP-SMX, or FQ per susceptibility)",notes:"Excellent strategy for ED-treat-and-release. The single IV dose provides immediate high tissue levels while you await culture results for definitive oral selection.",evidence:"B-II",evidenceSource:"IDSA 2011"}]},{line:"Inpatient (Complicated, Septic, Unable to Tolerate PO)",options:[{drug:"ceftriaxone",regimen:"Ceftriaxone 2g IV daily",notes:"Workhorse empiric. Broad gram-negative coverage. Step down when clinically improved."},{drug:"pip-tazo",regimen:"Piperacillin-tazobactam 3.375g IV q6h (or 4.5g q8h EI)",notes:"Use if Pseudomonas risk or healthcare-associated exposure. Extended infusion preferred."},{drug:"meropenem",regimen:"Meropenem 1g IV q8h",notes:"Reserve for ESBL risk, prior MDR organisms, or septic shock. De-escalate aggressively."}]},{line:"Adjunctive",options:[{drug:"supportive",regimen:"IV fluids, antipyretics, antiemetics",notes:"Aggressive hydration is critical. Urology consult if obstructive cause suspected — may require percutaneous nephrostomy or ureteral stent urgently."}]}],organismSpecific:[{organism:"E. coli (>80%)",preferred:"Fluoroquinolone (outpatient) or ceftriaxone (inpatient)",alternative:"TMP-SMX if susceptible (14-day course)",notes:"Dominant pathogen. Bacteremia common. ESBL E. coli pyelo rising — always check prior cultures."},{organism:"Proteus, Klebsiella, Enterobacter",preferred:"Ceftriaxone, fluoroquinolone",alternative:"Pip-tazo, carbapenems for resistant isolates",notes:"Proteus + stones = think struvite/staghorn calculus. Enterobacter: avoid ceftriaxone (AmpC induction risk) — use cefepime instead."}],pearls:["CRITICAL: Enterobacter, Citrobacter freundii, Serratia — these are AmpC producers. Ceftriaxone can induce AmpC and fail clinically even if the lab reports susceptible. Use cefepime for these 'SPACE' organisms.","Outpatient pyelo: always give the first dose in the ED/clinic and observe 4-6 hours. If tolerating PO and hemodynamically stable, safe to discharge with close follow-up.","Failure to improve at 48-72h? Get imaging. Think: perinephric abscess (requires drainage), obstruction (requires decompression), or wrong antibiotic (check cultures).","Pregnancy + pyelonephritis = ALWAYS inpatient. Risk of preterm labor and sepsis. Ceftriaxone is preferred. Avoid fluoroquinolones and TMP-SMX (first trimester folate antagonism, third trimester kernicterus risk).","Duration debates: IDSA 2025 now formally endorses shorter courses for cUTI (which includes febrile pyelo): FQ 5-7 days, non-FQ 7 days, even bacteremic UTI 7 days. The old 10-14 day default is no longer guideline-supported. For FQs, 7 days is well-established; for beta-lactams, 7 days is the new target based on the 2025 guideline (very low certainty evidence for non-FQ, but the direction is clear)."]},{id:"cauti",name:"Catheter-Associated UTI (CAUTI)",definition:"UTI in a patient with an indwelling urethral catheter, suprapubic catheter, or intermittent catheterization within the past 48 hours. Requires BOTH symptoms AND significant bacteriuria (≥10³ CFU/mL). Do NOT treat asymptomatic catheter-associated bacteriuria (CA-ASB).",clinicalPresentation:"Fever, rigors, altered mental status, malaise, flank pain, CVA tenderness, acute hematuria, pelvic discomfort. NOTE: Cloudy or malodorous urine ALONE is NOT an indication to treat — this reflects colonization and catheter biofilm, not infection.",diagnostics:"Replace catheter BEFORE collecting specimen (biofilm on old catheter = misleading results). Culture from the freshly placed catheter. Blood cultures if systemic signs. ≥10³ CFU/mL is the CAUTI diagnostic threshold (lower than standard UTI).",durationGuidance:{standard:"7–14 days",opatNote:"Remove or replace catheter when possible before starting antimicrobials"},empiricTherapy:[{line:"Empiric (Pending Cultures — Always De-escalate)",options:[{drug:"ceftriaxone",regimen:"Ceftriaxone 1-2g IV daily",notes:"Reasonable empiric for non-critically ill. Narrow once cultures return. Always assess for Pseudomonas risk.",evidence:"A-I",evidenceSource:"IDSA 2011"},{drug:"pip-tazo",regimen:"Piperacillin-tazobactam 4.5g IV q8h (EI over 4h)",notes:"Use if Pseudomonas or MDR risk (prior cultures, healthcare exposure). Extended infusion recommended.",evidence:"B-II",evidenceSource:"IDSA 2011"},{drug:"ciprofloxacin",regimen:"Ciprofloxacin 500mg PO BID (if can take PO and not critically ill)",notes:"Only oral option with Pseudomonal activity. But FQ resistance is high in catheterized populations — empiric use risky without prior culture data.",evidence:"B-II",evidenceSource:"IDSA 2011"}]},{line:"Duration",options:[{drug:"duration-guide",regimen:"7 days if rapid clinical response; 10-14 days if delayed response",notes:"IDSA 2010: 7 days is adequate for most CAUTI with prompt clinical improvement. Shorter courses reduce C. diff risk and resistance selection."}]}],organismSpecific:[{organism:"Polymicrobial (common in CAUTI)",preferred:"Target the most pathogenic organism, not every isolate",alternative:"Broad-spectrum if critically ill, then narrow",notes:"CAUTI cultures are frequently polymicrobial. Not every organism needs treatment. Focus on gram-negative rods and enterococci. Coagulase-negative staph is almost always contamination in this setting."},{organism:"Candida species",preferred:"Remove/replace catheter — this alone may resolve candiduria",alternative:"Fluconazole 200mg daily × 14 days if symptomatic and catheter removal doesn't clear",notes:"DO NOT reflexively treat candiduria. Most is colonization. Treat only if: symptomatic, neutropenic, undergoing urologic procedure, or renal transplant. Echinocandins achieve poor urinary concentrations."}],pearls:["THE cardinal rule of CAUTI: Remove the catheter. If the catheter must stay, replace it before starting antibiotics. Biofilm = treatment failure.","Cloudy/smelly urine in a catheterized patient is NOT an indication for antibiotics. This is the #1 driver of inappropriate antibiotic use in hospitals.","CA-ASB (asymptomatic bacteriuria with catheter) should NOT be treated. Treat symptoms, not the lab result.","CAUTI prevention bundle: daily assessment of catheter necessity, aseptic insertion, closed drainage, maintain below bladder level. Nurse-driven removal protocols reduce CAUTI rates by 50%+.","Candiduria pearl: Echinocandins (micafungin, caspofungin) do NOT achieve therapeutic urinary concentrations. Only fluconazole and flucytosine reliably treat urinary Candida. Amphotericin B bladder irrigation is a last resort.","Antibiotic stewardship role: Pharmacists should flag treatment of CA-ASB as a stewardship intervention. Many institutions have reduced unnecessary CAUTI treatment by 30-40% with pharmacist-driven protocols."]}],drugMonographs:[{id:"nitrofurantoin",name:"Nitrofurantoin",brandNames:"Macrobid (monohydrate/macrocrystals), Macrodantin (macrocrystals), Furadantin (microcrystals)",drugClass:"Nitrofuran antibiotic",mechanismOfAction:"Reduced by bacterial nitroreductases to reactive intermediates that damage DNA, RNA, proteins, and cell wall synthesis. Multiple mechanisms make resistance development slow and uncommon.",spectrum:"Gram-positive: E. faecalis, S. saprophyticus, Group B Strep. Gram-negative: E. coli (>95% susceptible), Citrobacter. GAPS: NO Pseudomonas, Proteus, Serratia, Klebsiella (variable), Enterobacter. Does NOT cover any organism outside the bladder (no tissue/serum levels).",dosing:{standard:"100mg PO BID × 5 days (COMBINE trial supports 3-day course)",prophylaxis:"50-100mg PO at bedtime (for recurrent UTI prevention)",pediatric:"5-7 mg/kg/day divided BID-QID"},renalAdjustment:"Traditionally contraindicated at CrCl <30 mL/min (lack of urinary concentration + risk of toxicity). HOWEVER: Recent AAC study (Oplinger & Andrews 2013) and real-world data suggest usability down to CrCl ~20 mL/min for short courses (5 days) of cystitis treatment. Many ID pharmacists now use it cautiously in this range. Prophylactic use still avoid at <30.",hepaticAdjustment:"Use with caution. Rare hepatotoxicity (cholestatic and hepatocellular) — more common with prolonged use (>6 months). Baseline LFTs if planning prophylaxis.",adverseEffects:{common:"Nausea, headache, flatulence (GI effects significantly less with macrocrystal formulation — always use Macrobid)",serious:"Pulmonary toxicity (acute hypersensitivity pneumonitis OR chronic interstitial fibrosis with prolonged use >6 months), peripheral neuropathy, hepatotoxicity",rare:"Hemolytic anemia in G6PD deficiency (though actual risk is debated and may be lower than traditionally taught), lupus-like syndrome"},drugInteractions:["Magnesium trisilicate antacids — decrease absorption","Probenecid — blocks tubular secretion, reduces urinary levels and increases serum toxicity risk","Norfloxacin — antagonism in vitro (clinical significance unclear, but avoid combination)"],monitoring:"Short course: none routinely needed. Prophylaxis >6 months: CBC (monitor for megaloblastic anemia), LFTs q6 months, pulmonary symptoms review. Counsel patients to report any new cough or SOB immediately.",pregnancyLactation:"Category B. Generally safe in 2nd and 3rd trimesters. AVOID at term (≥38 weeks) — theoretical risk of hemolytic anemia in newborn. Avoid in 1st trimester if alternatives available (AAP guidance). Compatible with breastfeeding (but avoid if infant <1 month or G6PD deficient).",pharmacistPearls:["ALWAYS dispense as Macrobid (macrocrystals/monohydrate), NOT Macrodantin or generic microcrystalline — dramatically less nausea.","MUST be taken with food — absorption increases by ~40% and reduces GI side effects.","It only works in the urine. If you suspect anything beyond cystitis (pyelo, bacteremia, prostatitis) — nitrofurantoin is the WRONG drug.","The CrCl <30 'contraindication' is being re-evaluated. For a short course of cystitis in an elderly patient with CrCl 20-30, it's often the best option vs. fluoroquinolones. Document your clinical rationale.","Turns urine brown/rust-colored — always counsel patients or they'll call in panicked.","Despite decades of use, resistance rates remain remarkably low (~3-5% for E. coli). This is likely because of its multiple mechanisms — a lesson in antibiotic stewardship."]},{id:"tmp-smx",name:"Trimethoprim-Sulfamethoxazole",brandNames:"Bactrim, Bactrim DS, Septra, Sulfatrim",drugClass:"Folate pathway inhibitor (dihydrofolate reductase inhibitor + dihydropteroate synthase inhibitor)",mechanismOfAction:"Sequential blockade of folate synthesis. Trimethoprim inhibits dihydrofolate reductase (DHFR); sulfamethoxazole inhibits dihydropteroate synthase (DHPS). Synergistic bactericidal effect due to dual pathway inhibition.",spectrum:"Broad: E. coli, Proteus, Klebsiella (variable), S. saprophyticus, MRSA (PO option!), Stenotrophomonas maltophilia (drug of choice), PJP, Nocardia, Listeria, Toxoplasma. GAPS: Pseudomonas, Enterococci, Anaerobes, Group A & B Strep.",dosing:{standard:"1 DS tab (160/800mg) PO BID × 3 days (cystitis), 7-14 days (complicated UTI/pyelo)",uti:"DS PO BID × 3 days for uncomplicated cystitis",prostatitis:"DS PO BID × 4-6 weeks (excellent prostatic penetration)",mrsa:"1-2 DS PO BID (skin/soft tissue)",pjp:"15-20 mg/kg/day (TMP component) divided q6-8h"},renalAdjustment:"CrCl 15-30: reduce dose by 50%. CrCl <15: avoid (risk of hyperkalemia and myelosuppression). Monitor potassium — trimethoprim blocks ENaC in the collecting duct (acts like amiloride).",hepaticAdjustment:"Hepatotoxicity rare but can occur. Avoid in severe hepatic disease. Sulfonamide component can cause cholestatic jaundice.",adverseEffects:{common:"Nausea, vomiting, rash (morbilliform), photosensitivity",serious:"Hyperkalemia (TMP blocks ENaC — acts like K-sparing diuretic), myelosuppression (folate antagonism), Stevens-Johnson Syndrome/TEN (sulfonamide component), acute kidney injury (TMP inhibits creatinine secretion — serum Cr rises ~0.5-1 mg/dL without true GFR change)",rare:"Aseptic meningitis, C. diff, hemolytic anemia in G6PD deficiency, pancreatitis"},drugInteractions:["Warfarin — MAJOR: TMP inhibits CYP2C9, potentiates warfarin. INR can spike dangerously. Monitor closely or choose alternative antibiotic.","Methotrexate — additive folate antagonism → bone marrow suppression. Avoid combination if possible.","ACE inhibitors/ARBs/spironolactone — additive hyperkalemia risk (TMP + RAAS blockade). Check K within 3-5 days.","Phenytoin — increased phenytoin levels (CYP2C9 inhibition by TMP)","Dapsone — both cause methemoglobinemia and marrow suppression. Monitor closely.","CREATININE ARTIFACT: TMP competitively inhibits tubular creatinine secretion. Serum creatinine rises 0.5-1 mg/dL without actual GFR decline. Do NOT reflexively change dosing of renally-cleared drugs based on this."],monitoring:"Short course (3 days): potassium if on RAAS inhibitors. Prolonged use: CBC weekly (first month, then monthly), BMP (K, Cr), LFTs. Watch for rash — discontinue immediately if any mucosal involvement.",pregnancyLactation:"AVOID in 1st trimester (neural tube defect risk — folate antagonism) and near term/3rd trimester (risk of kernicterus in newborn, displacement of bilirubin from albumin). Category D. Compatible with breastfeeding in term, healthy infants, but avoid in premature or G6PD-deficient infants.",pharmacistPearls:["The creatinine rise is NOT real AKI — teach this to your medical teams. TMP blocks tubular secretion of creatinine. Cystatin C-based GFR is unaffected. This is a high-value pharmacist intervention.","Hyperkalemia from TMP is real and clinically significant, especially in elderly patients on ACE/ARB + TMP-SMX. One study showed 7-fold increase in hyperkalemia-related hospitalizations. Check K at day 3-5.","For MRSA: TMP-SMX is one of the few ORAL options. Pairs well with doxycycline for complicated SSTI.","Sulfa allergy is often over-reported. True IgE-mediated allergy (anaphylaxis) is rare. Rash with sulfonamide antibiotics does NOT necessarily cross-react with non-antibiotic sulfonamides (furosemide, thiazides) — different chemical structures.","Desensitization protocols exist for PJP prophylaxis in HIV patients with sulfa allergy — critical knowledge for pharmacy.","Always check local antibiogram for TMP-SMX resistance before using empirically for UTI. If resistance >20%, it's not appropriate as empiric therapy."]},{id:"fosfomycin",name:"Fosfomycin",brandNames:"Monurol (oral trometamol salt)",drugClass:"Phosphonic acid derivative (cell wall synthesis inhibitor — unique MOA)",mechanismOfAction:"Inhibits MurA (UDP-N-acetylglucosamine enolpyruvyl transferase), the first committed step of peptidoglycan synthesis. Completely unique mechanism — no cross-resistance with any other antibiotic class.",spectrum:"E. coli (excellent, >90% susceptible including many ESBL producers), Enterococcus faecalis (including VRE — useful niche!), Klebsiella (variable). GAPS: Pseudomonas (oral formulation), Acinetobacter, poor against many non-fermenters.",dosing:{standard:"3g PO × 1 dose (dissolved in cold water)",recurrent:"3g PO every 72 hours × 3 doses (some clinicians use this for recurrent/resistant cystitis — off-label but published data supports)",iv:"IV formulation available in Europe (not US) — used for serious systemic infections at doses of 12-24g/day divided q6-8h. Under investigation for ESBL/MDR infections."},renalAdjustment:"No dose adjustment needed for oral single-dose. Excreted renally — concentrations adequate even in moderate renal impairment.",hepaticAdjustment:"No adjustment needed.",adverseEffects:{common:"Diarrhea (~10%), nausea, headache, vaginitis",serious:"Very rare with single-dose therapy. Aplastic anemia reported with prolonged/IV use.",rare:"Angioedema, toxic epidermal necrolysis (extremely rare case reports)"},drugInteractions:["Metoclopramide — decreases fosfomycin absorption (increased GI motility reduces absorption time)","Minimal drug interactions overall — a significant advantage"],monitoring:"Single-dose therapy: none required. For off-label multi-dose regimens: BMP, CBC.",pregnancyLactation:"Category B. Single-dose considered safe in pregnancy for uncomplicated cystitis. Italian and European data support use in pregnant women. A useful option when nitrofurantoin and cephalosporins aren't suitable.",pharmacistPearls:["Dissolve in 3-4 oz of COLD water. Not hot — not juice (acid reduces efficacy). Take on empty stomach or it doesn't matter much, but cold water specifically.","Single-dose convenience is the biggest selling point. Perfect for the patient you know won't complete a course.","Slightly inferior clinical cure rate vs. multi-day regimens (meta-analyses show ~85% vs ~90%). Accept this trade-off for adherence.","Useful for ESBL E. coli cystitis — one of the few oral options. The oral formulation only treats cystitis (poor tissue penetration).","The IV formulation (available in EU, not US) is a game-changer for ESBL/CRE — 12-24g/day divided doses. Be aware of this if doing international stewardship work.","Can use for E. faecalis UTI (including VRE urinary isolates) — niche but valuable.","Susceptibility testing: Agar dilution is the reference method. Disk diffusion is unreliable for fosfomycin — if your lab uses disk diffusion, interpret with caution.","E. coli resistance to fosfomycin is mediated by chromosomal mutations (not plasmid) — resistance develops slowly and remains low (~1-3%)."]},{id:"ciprofloxacin",name:"Ciprofloxacin",brandNames:"Cipro, Cipro XR",drugClass:"Fluoroquinolone (2nd generation) — DNA gyrase and topoisomerase IV inhibitor",mechanismOfAction:"Inhibits bacterial DNA gyrase (primarily gram-negative target) and topoisomerase IV (primarily gram-positive target). Causes double-strand DNA breaks. Bactericidal and concentration-dependent killing.",spectrum:"Excellent gram-negative: E. coli, Klebsiella, Proteus, Pseudomonas aeruginosa (most reliable oral anti-pseudomonal agent), Salmonella, Shigella, H. influenzae. Moderate: some atypicals (Legionella, Mycoplasma). GAPS: Poor gram-positive (especially Streptococcus pneumoniae — never use for CAP), MRSA, Anaerobes.",dosing:{uncomplicated_uti:"250mg PO BID × 3 days or Cipro XR 500mg daily × 3 days (but should be AVOIDED for uncomplicated cystitis per IDSA/FDA)",complicated_uti:"500mg PO BID × 7-14 days",pyelonephritis:"500mg PO BID × 7 days",iv:"400mg IV q12h (equivalent to 500mg PO — excellent bioavailability makes IV rarely necessary if GI tract functional)",pseudomonal:"750mg PO BID or 400mg IV q8h for serious Pseudomonal infections"},renalAdjustment:"CrCl 30-50: no change. CrCl 5-29: 250-500mg PO q12-18h or 200-400mg IV q18-24h. Hemodialysis: dose after dialysis (slightly dialyzed).",hepaticAdjustment:"No routine adjustment, but use caution in severe hepatic impairment (hepatotoxicity reported).",adverseEffects:{common:"Nausea, diarrhea, headache, dizziness, photosensitivity, insomnia",serious:"Tendon rupture/tendinopathy (Achilles most common — risk increases with age >60, corticosteroids, renal disease, solid organ transplant), aortic aneurysm/dissection, QT prolongation, peripheral neuropathy (may be irreversible), C. difficile, seizures, CNS effects (anxiety, confusion, psychosis), retinal detachment (epidemiologic signal)",rare:"Myasthenia gravis exacerbation (FQs have neuromuscular blocking activity), crystalluria (ensure hydration)",fdaBoxedWarnings:"Tendinitis/tendon rupture, peripheral neuropathy, CNS effects, myasthenia gravis exacerbation. FDA restricts use for uncomplicated infections when alternatives exist."},drugInteractions:["Divalent/trivalent cations (Ca²⁺, Mg²⁺, Al³⁺, Fe²⁺/³⁺, Zn²⁺) — chelation reduces absorption 50-90%. Separate by 2h before or 6h after. This includes antacids, dairy, multivitamins, sucralfate, calcium supplements, tube feeds.","Tizanidine — CONTRAINDICATED. Cipro inhibits CYP1A2, causing 10-fold increase in tizanidine levels → severe hypotension and sedation.","Theophylline — CYP1A2 inhibition → theophylline toxicity (seizures, arrhythmias). Monitor levels.","Warfarin — enhanced anticoagulant effect. Monitor INR.","QT-prolonging drugs — additive risk. Avoid with Class IA/III antiarrhythmics.","NSAIDs — may lower seizure threshold in combination with FQs.","Methotrexate — FQs reduce renal tubular secretion of MTX → increased toxicity."],monitoring:"Short course: clinical response. Longer courses: BMP (crystalluria risk — hydrate well), tendon symptoms review, neuropsychiatric assessment. Educate patient to report tendon pain immediately.",pregnancyLactation:"Category C. Traditionally avoided due to arthropathy in juvenile animals. However, human data doesn't show clear joint toxicity. Generally avoid if alternatives exist. AAP considers compatible with breastfeeding, but caution advised.",pharmacistPearls:["The cation interaction is the #1 pharmacist intervention for ciprofloxacin. Patients on calcium, iron, or antacids WILL have treatment failure if not counseled. Separate by 2h before or 6h after.","Cipro has ~70-80% oral bioavailability. IV-to-PO conversion is a major stewardship opportunity — 500mg PO ≈ 400mg IV. Push for early switch.","NEVER use cipro for pneumonia — it has poor Streptococcus pneumoniae activity. This is a common and dangerous error. Levofloxacin is the 'respiratory FQ,' not cipro.","Cipro is THE oral anti-pseudomonal agent. When you need oral Pseudomonas coverage (step-down from IV, outpatient UTI), cipro is often your only choice. This is its niche value — don't waste it on uncomplicated cystitis.","For tube feeds: must hold feeds 1-2h before and after cipro administration (cation chelation with formula calcium). This is frequently missed in hospitals.","Achilles tendon rupture risk is real but often over-feared. Absolute risk is ~0.4%. Highest risk: age >60, concurrent steroids, renal impairment, prior tendon issues. Still — always counsel.","Photosensitivity: counsel patients to use SPF 30+ sunscreen. Some patients develop severe phototoxic reactions."]},{id:"ceftriaxone",name:"Ceftriaxone",brandNames:"Rocephin",drugClass:"Third-generation cephalosporin",mechanismOfAction:"Inhibits penicillin-binding proteins (PBPs), primarily PBP-3, disrupting cell wall synthesis. Bactericidal. Time-dependent killing (T>MIC drives efficacy).",spectrum:"Broad gram-negative: E. coli, Klebsiella, Proteus, Serratia, H. influenzae, N. gonorrhoeae, N. meningitidis, Salmonella. Moderate gram-positive: Streptococci (including S. pneumoniae), but NOT MRSA, NOT Enterococcus. GAPS: ESBL producers (typically resistant), AmpC producers (may induce — avoid for SPACE organisms), Pseudomonas, Listeria, Anaerobes (poor).",dosing:{uti:"1-2g IV/IM daily",meningitis:"2g IV q12h",gonorrhea:"500mg IM × 1 (updated CDC 2021 — was previously 250mg)",cap:"1-2g IV daily (usually with azithromycin or doxycycline)",sbp:"2g IV daily × 5-7 days",singleDose:"1g IV/IM × 1 dose as empiric bridge for outpatient pyelo/UTI step-down"},renalAdjustment:"No adjustment needed in renal impairment alone (biliary excretion ~40%). If COMBINED hepatic + renal impairment: max 2g/day.",hepaticAdjustment:"Monitor closely in hepatic impairment due to biliary excretion. Risk of biliary sludge/pseudolithiasis (especially in children, prolonged courses, fasting patients).",adverseEffects:{common:"Diarrhea, injection site pain (IM), rash, elevated LFTs",serious:"C. difficile (higher risk than narrow-spectrum agents), biliary sludge/pseudolithiasis (reversible, US-detectable), hypersensitivity/anaphylaxis (cross-reactivity with penicillin is ~1-2%, much lower than the old 10% myth)",rare:"Hemolytic anemia (immune-mediated), neurotoxicity at very high doses, leukopenia (prolonged use)",contraindications:"Neonates (<28 days) receiving calcium-containing IV solutions (risk of fatal cardiopulmonary precipitates). NEVER co-infuse with calcium in neonates."},drugInteractions:["Calcium-containing IV solutions — contraindicated in neonates, use caution in other patients (precipitation risk in the line, not systemically in adults)","Warfarin — may enhance effect (vitamin K depletion from gut flora suppression). Monitor INR.","Ringer's lactate — contains calcium. Use NS for reconstitution/infusion in neonates."],monitoring:"Short courses: clinical response. Prolonged use (>2 weeks): CBC, LFTs, RUS if symptomatic for biliary sludge. Assess for C. diff if diarrhea develops.",pregnancyLactation:"Category B. Considered safe in all trimesters. Preferred agent for UTI/pyelo in pregnancy when IV needed. Low breast milk excretion — compatible with breastfeeding.",pharmacistPearls:["Ceftriaxone is the pharmacist's Swiss Army knife for empiric gram-negative coverage. Know its limitations: NO Pseudomonas, NO ESBL, NO Enterococcus, NO MRSA.","The penicillin-cephalosporin cross-reactivity myth: The old '10% cross-reactivity' number came from contaminated early penicillin batches. Actual cross-reactivity is ~1-2% and is based on R1 side chain similarity. Ceftriaxone has DIFFERENT side chains than ampicillin/amoxicillin — cross-reactivity is very low. Most penicillin-allergic patients can safely receive ceftriaxone.","IM administration: reconstitute with 1% lidocaine to reduce pain. This is standard of care and drastically improves patient experience. Make sure there's no lidocaine allergy.","AmpC warning: For SPACE organisms (Serratia, Providencia/Pseudomonas, Acinetobacter, Citrobacter freundii, Enterobacter), ceftriaxone can induce AmpC beta-lactamase production, leading to clinical failure even if initial susceptibility testing says 'susceptible.' Switch to cefepime.","Once-daily dosing with a long half-life (~8h) makes it ideal for OPAT (outpatient parenteral antibiotic therapy). Perfect for ED treat-and-release strategies.","Biliary sludge risk: more common with doses >2g/day, courses >14 days, fasting/TPN patients, and children. Usually reversible upon discontinuation. Counsel to stay hydrated."]},{id:"levofloxacin",name:"Levofloxacin",brandNames:"Levaquin",drugClass:"Fluoroquinolone (3rd generation, 'respiratory fluoroquinolone')",mechanismOfAction:"L-isomer of ofloxacin. Inhibits DNA gyrase and topoisomerase IV. Enhanced gram-positive activity (especially S. pneumoniae) compared to ciprofloxacin. Concentration-dependent killing with prolonged PAE.",spectrum:"Broad gram-negative (similar to cipro but slightly less anti-pseudomonal potency), PLUS excellent gram-positive: S. pneumoniae (including drug-resistant — hence 'respiratory FQ'), atypicals (Legionella, Mycoplasma, Chlamydophila). GAPS: MRSA, Anaerobes (limited), some Pseudomonas strains.",dosing:{uti_uncomplicated:"250mg PO daily × 3 days (AVOID per IDSA/FDA for uncomplicated — same as cipro)",uti_complicated:"750mg PO daily × 5-7 days",pyelonephritis:"750mg PO daily × 5 days",cap:"750mg PO/IV daily × 5 days (CABP standard)",iv:"750mg IV daily (100% bioavailability — PO = IV, nearly dollar-for-dollar)"},renalAdjustment:"750mg dose: CrCl 20-49: 750mg q48h. CrCl 10-19: 500mg q48h. Hemodialysis: 500mg q48h (not significantly dialyzed). 500mg dose: CrCl 20-49: 250mg q24h. CrCl 10-19: 250mg q48h.",hepaticAdjustment:"No specific adjustment. Use caution — hepatotoxicity reported (rare).",adverseEffects:{common:"Same as ciprofloxacin class effects: nausea, diarrhea, headache, insomnia",serious:"Same FDA boxed warnings as cipro: tendinitis/rupture, peripheral neuropathy, CNS effects, MG exacerbation. Additionally: hypoglycemia (especially in diabetic patients on sulfonylureas/insulin), QT prolongation (more pronounced than cipro)",rare:"Hepatic failure, toxic epidermal necrolysis, torsades de pointes"},drugInteractions:["Cation chelation — same as ciprofloxacin. Separate from Ca, Mg, Al, Fe, Zn.","QT-prolonging agents — levofloxacin has MORE QT effect than cipro. Be extra cautious with amiodarone, sotalol, ondansetron, methadone.","Insulin/sulfonylureas — FQs can cause both hypo- and hyperglycemia. Levo seems to have a higher dysglycemia signal than cipro.","Warfarin — enhanced anticoagulation. Monitor INR.","Note: UNLIKE cipro, levofloxacin does NOT significantly inhibit CYP1A2, so NO tizanidine or theophylline interaction. This is a key differentiator."],monitoring:"Blood glucose (especially diabetics), QTc if on other QT-prolonging agents, tendon symptoms, neuropsychiatric effects.",pregnancyLactation:"Category C. Same general FQ avoidance in pregnancy. Breastfeeding: enters breast milk — generally avoided.",pharmacistPearls:["Levo vs. Cipro: Cipro is better for Pseudomonas; Levo is better for respiratory pathogens (S. pneumoniae). Use the right one for the right bug.","100% oral bioavailability — there is ZERO reason to use IV levofloxacin if the patient can swallow. This is one of the most impactful stewardship interventions (cost savings: IV ~$30-80/dose vs. PO ~$1-5).","750mg × 5 days for pyelo is a well-validated short course. Higher dose, shorter duration — takes advantage of concentration-dependent killing.","Unlike cipro, levo does NOT inhibit CYP1A2. So: tizanidine is safe with levo (CONTRAINDICATED with cipro). Theophylline is safer with levo. Know this distinction — it matters clinically.","Hypoglycemia risk: FDA strengthened warning in 2018. Highest risk in elderly diabetics on sulfonylureas. Some cases resulted in coma. Always check diabetes medication list.","QT prolongation: levo has a stronger QT signal than cipro. Always check the QTc and concomitant meds. If baseline QTc >500ms, avoid."]}]},c={id:"cap",name:"Community-Acquired Pneumonia",icon:"🫁",category:"Infectious Disease",overview:{definition:"Acute infection of the pulmonary parenchyma acquired outside of a hospital or long-term care facility. Classified by severity and treatment setting: outpatient, inpatient (non-ICU), and ICU/severe CAP. The 2019 ATS/IDSA guidelines eliminated the old 'HCAP' category — all pneumonia acquired in the community is now CAP regardless of healthcare exposure.",epidemiology:"Leading infectious cause of death in the US. ~1.5 million adults hospitalized annually. Mortality: outpatient <1%, inpatient 5-15%, ICU 20-50%. Incidence increases dramatically with age >65 and comorbidities.",keyGuidelines:[{name:"ATS/IDSA 2019 CAP Guidelines",detail:"Current definitive guideline. Eliminated HCAP category. Emphasizes severity-based treatment, procalcitonin-guided de-escalation, and steroid role in severe CAP. Replaced the 2007 guidelines."},{name:"NICE 2023 Pneumonia Update",detail:"UK guideline — useful perspective on amoxicillin monotherapy and shorter courses. CRB-65 scoring emphasis."},{name:"GOLD 2024 (for AECOPD overlap)",detail:"Important for distinguishing CAP from acute exacerbation of COPD with pneumonia — treatment differs."},{name:"Surviving Sepsis Campaign 2021",detail:"Relevant for severe CAP with sepsis — 1-hour bundle, lactate-guided resuscitation, vasopressor selection."}],landmarkTrials:[{name:"CAP-START Trial (2015, NEJM)",detail:"Dutch RCT comparing beta-lactam monotherapy vs. beta-lactam + macrolide vs. respiratory FQ monotherapy for moderate-severe CAP. Non-inferiority for all three strategies at 90-day mortality. KEY TAKEAWAY: Beta-lactam monotherapy may be sufficient for non-ICU inpatients — challenged the dogma of mandatory macrolide addition."},{name:"EPIC Study (Jain et al., 2015, NEJM)",detail:"CDC landmark epidemiologic study of hospitalized CAP in the US. Found a pathogen in only 38% of cases. Rhinovirus and influenza were the most common pathogens overall. S. pneumoniae was the most common bacterial pathogen but detected in only 5%. Changed our understanding of CAP etiology."},{name:"Postma et al. (2015) — Adjunctive Dexamethasone",detail:"RCT showing dexamethasone 5mg IV × 4 days reduced length of stay by ~1 day in hospitalized CAP. Did NOT reduce mortality. Steroid role remains nuanced — most benefit in severe CAP."},{name:"STEP Trial (2023, NEJM)",detail:"3-day vs. 8-day amoxicillin for CAP in hospitalized patients who achieved clinical stability by day 3. 3 days was non-inferior. Landmark for antibiotic stewardship — shortest validated course for inpatient CAP."},{name:"Garin et al. (2014, JAMA IM)",detail:"Beta-lactam + macrolide vs. beta-lactam alone for hospitalized non-ICU CAP. Combination was NOT superior for non-severe cases. Supports monotherapy approach from CAP-START."},{name:"CAPE COD Trial (2023, NEJM)",detail:"Hydrocortisone 200mg/day × 4 days then tapered for severe CAP. Significantly reduced 28-day mortality (6.2% vs. 11.9%). Practice-changing for severe/ICU CAP. NNT = 18."}],riskFactors:"Age >65, smoking, COPD, asthma, diabetes, heart failure, chronic liver/renal disease, immunosuppression, alcohol use disorder, recent viral URI, poor dental hygiene, dysphagia/aspiration risk, PPI use (controversial but epidemiologically associated)."},subcategories:[{id:"cap-outpatient-healthy",name:"Outpatient CAP — No Comorbidities",definition:"CAP in a previously healthy outpatient with no significant comorbidities, no recent antibiotic use (past 90 days), and no risk factors for drug-resistant pathogens. These patients can be safely treated at home with oral monotherapy.",clinicalPresentation:"Cough (productive or dry), fever, pleuritic chest pain, dyspnea, tachypnea. Physical exam: focal crackles/rales, dullness to percussion, bronchial breath sounds, egophony. Mild cases may have subtle findings.",diagnostics:"Chest X-ray is recommended to confirm diagnosis (ATS/IDSA). Sputum culture and blood cultures NOT recommended for outpatients. No procalcitonin needed. Assessment with CURB-65 or PSI/PORT score to confirm outpatient appropriateness (CURB-65 score 0-1, PSI class I-II).",durationGuidance:{standard:"5 days",severe:"7–10 days (ICU/bacteremic)",stewardshipNote:"IDSA/ATS 2019: 5-day course non-inferior for uncomplicated CAP. Reassess at day 5 using clinical stability criteria."},empiricTherapy:[{line:"First-Line (Pick ONE — Monotherapy)",options:[{drug:"amoxicillin",regimen:"Amoxicillin 1g PO TID × 5 days",notes:"ATS/IDSA 2019 first-line. HIGH-DOSE (1g, not 500mg) targets intermediate-resistant S. pneumoniae. Excellent safety profile. STEP trial supports even 3-day courses if rapid clinical improvement.",evidence:"A-I",evidenceSource:"IDSA/ATS 2019"},{drug:"doxycycline",regimen:"Doxycycline 100mg PO BID × 5 days",notes:"Covers typicals AND atypicals (Mycoplasma, Chlamydophila). Good alternative for penicillin-allergic patients. Avoids azithromycin resistance selection. Well-tolerated.",evidence:"A-I",evidenceSource:"IDSA/ATS 2019"},{drug:"azithromycin",regimen:"Azithromycin 500mg PO day 1, then 250mg daily × 4 days (Z-pack)",notes:"Covers atypicals well. HOWEVER: Rising S. pneumoniae macrolide resistance (~30-40% in US) is a concern. ATS/IDSA 2019 only recommends as monotherapy where local pneumococcal macrolide resistance <25%. QT risk. Many ID physicians now prefer doxycycline over azithromycin.",evidence:"A-I",evidenceSource:"IDSA/ATS 2019"}]}],organismSpecific:[{organism:"Streptococcus pneumoniae",preferred:"Amoxicillin 1g TID (high-dose overcomes intermediate resistance)",alternative:"Doxycycline, respiratory FQ",notes:"Most common bacterial cause of CAP. PCV13/PCV20 vaccine has reduced invasive disease but not eliminated it. Drug-resistant S. pneumoniae (DRSP): penicillin intermediate resistance ~20-30%, macrolide resistance ~30-40%. High-dose amoxicillin achieves PK/PD targets for intermediately resistant isolates."},{organism:"Mycoplasma pneumoniae",preferred:"Doxycycline 100mg BID or Azithromycin",alternative:"Respiratory FQ (levofloxacin, moxifloxacin)",notes:"Most common cause of 'atypical' CAP. Walking pneumonia. Younger adults (5-40 years). Can cause bullous myringitis, rash, cold agglutinins. Usually self-limited but antibiotics shorten duration. Macrolide-resistant Mycoplasma emerging (~10-15% in US, >80% in parts of Asia) — doxycycline unaffected by this resistance."},{organism:"Chlamydophila pneumoniae",preferred:"Doxycycline or Azithromycin",alternative:"Respiratory FQ",notes:"Often indistinguishable from Mycoplasma clinically. Can cause laryngitis (hoarseness is a clue). Prolonged cough. Usually mild."},{organism:"Respiratory viruses (Influenza, SARS-CoV-2, RSV)",preferred:"Oseltamivir (influenza), Paxlovid (COVID-19)",alternative:"Supportive care",notes:"EPIC study showed viruses are the most common CAP pathogens overall. Always consider influenza in season — early oseltamivir (within 48h, ideally 24h) reduces complications. COVID-19: follow current NIH guidelines. RSV: no specific approved antiviral for adults as of early 2025, but nirsevimab for infants."},{organism:"Haemophilus influenzae",preferred:"Amoxicillin-clavulanate, doxycycline",alternative:"Respiratory FQ, cephalosporins",notes:"Non-typeable H. influenzae is common in COPD patients. ~30-40% produce beta-lactamase → amoxicillin alone may fail. Amox-clav or doxycycline covers this. Ceftriaxone is reliable."}],pearls:["Amoxicillin 1g TID — the dose matters. Standard 500mg TID does NOT achieve adequate PK/PD targets for intermediately resistant S. pneumoniae. Always use the high dose.","Doxycycline is the underappreciated gem for outpatient CAP: covers typicals + atypicals, no QT prolongation, no macrolide resistance selection, and it's cheap. Many ID physicians now prefer it over azithromycin.","The Z-pack (azithromycin) is massively overprescribed. With ~30-40% macrolide resistance in S. pneumoniae, it's becoming unreliable as monotherapy. If you use it, make sure local resistance data supports it.","Duration: ATS/IDSA recommends minimum 5 days, with the caveat that the patient should be clinically stable for 48-72h before stopping. The STEP trial validates even shorter (3-day) courses for patients who stabilize rapidly.","CURB-65 score: Confusion, Uremia (BUN >19), Respiratory rate ≥30, Blood pressure (SBP <90 or DBP ≤60), Age ≥65. Score 0-1 = outpatient. 2 = consider admission. ≥3 = inpatient. Simple, bedside, no labs needed (CRB-65 drops the U).","Always ask about influenza exposure and symptoms during flu season. If influenza CAP is suspected, add oseltamivir regardless of presentation timing — late treatment still reduces complications in severe cases."]},{id:"cap-outpatient-comorbid",name:"Outpatient CAP — With Comorbidities",definition:"CAP in outpatients with significant comorbidities (COPD, diabetes, chronic heart/liver/renal disease, alcoholism, malignancy, asplenia) OR recent antibiotic use within 90 days. These patients need broader empiric coverage.",clinicalPresentation:"Same as above, but comorbidities may blunt typical presentation. Elderly/diabetic patients may present without fever. COPD patients may be difficult to distinguish from AECOPD. Heart failure patients may mimic pneumonia with pulmonary edema.",diagnostics:"Chest X-ray recommended. Consider procalcitonin to help differentiate bacterial CAP from viral/AECOPD (PCT >0.25 supports bacterial). Sputum culture not routinely needed for outpatients. Calculate CURB-65/PSI to confirm outpatient safety.",durationGuidance:{standard:"5 days",severe:"7–10 days (ICU/bacteremic)",stewardshipNote:"IDSA/ATS 2019: 5-day course non-inferior for uncomplicated CAP. Reassess at day 5 using clinical stability criteria."},empiricTherapy:[{line:"First-Line (Combination Therapy)",options:[{drug:"amox-clav-combo",regimen:"Amoxicillin-Clavulanate 875/125mg PO BID + Azithromycin 500mg day 1 then 250mg × 4 days",notes:"OR Amox-clav + Doxycycline 100mg BID. The beta-lactam covers S. pneumoniae, H. influenzae (beta-lactamase producers), M. catarrhalis. Macrolide/doxy adds atypical coverage. Duration: 5 days.",evidence:"A-I",evidenceSource:"IDSA/ATS 2019"},{drug:"cephalexin-combo",regimen:"Cephalexin 500mg PO TID (or Cefpodoxime 200mg BID) + Azithromycin or Doxycycline",notes:"Alternative beta-lactam backbone. Cefpodoxime preferred over cephalexin for broader gram-negative coverage.",evidence:"B-II",evidenceSource:"IDSA/ATS 2019"}]},{line:"Second-Line (Monotherapy — Respiratory Fluoroquinolone)",options:[{drug:"levofloxacin",regimen:"Levofloxacin 750mg PO daily × 5 days",notes:"Respiratory FQ covers typicals + atypicals in one agent. Reserve as second-line per ATS/IDSA due to FDA boxed warnings and collateral damage. Appropriate when beta-lactam allergy is severe or combination therapy not feasible."},{drug:"moxifloxacin",regimen:"Moxifloxacin 400mg PO daily × 5 days",notes:"Best anti-pneumococcal FQ. Excellent bioavailability. NO Pseudomonas activity (unlike levo). Higher QT risk than levofloxacin. No renal adjustment needed. AVOID if any QT concern."}]}],organismSpecific:[{organism:"S. pneumoniae (DRSP risk higher)",preferred:"Amox-clav (high-dose amoxicillin component), respiratory FQ",alternative:"Ceftriaxone IM/IV single dose + oral step-down",notes:"Recent antibiotics select for resistant pneumococci. Prior beta-lactam → consider FQ. Prior FQ → use beta-lactam + macrolide. Don't repeat the same class within 90 days."},{organism:"H. influenzae (beta-lactamase producer)",preferred:"Amox-clav, cefpodoxime, doxycycline",alternative:"Respiratory FQ",notes:"Beta-lactamase production: ~30-40%. Amoxicillin alone insufficient. Clavulanate or cephalosporin overcomes this."},{organism:"Moraxella catarrhalis",preferred:"Amox-clav, cephalosporins, macrolides",alternative:"Doxycycline, respiratory FQ",notes:"Nearly 100% beta-lactamase positive — amoxicillin alone WILL fail. Common in COPD patients. Usually self-limited but can cause severe disease in immunocompromised."},{organism:"S. aureus (MSSA post-influenza)",preferred:"Amox-clav, cephalexin (MSSA)",alternative:"TMP-SMX + beta-lactam if MRSA concern",notes:"Post-influenza staphylococcal pneumonia is a classic lethal combination. Rapidly progressive, necrotizing. If suspected, treat aggressively — don't wait for cultures. Consider MRSA coverage (vancomycin or linezolid) if risk factors present."}],pearls:["The 90-day antibiotic rule: If the patient received ANY antibiotic in the past 90 days, use a different class for CAP. Beta-lactam recently? Use respiratory FQ. FQ recently? Use beta-lactam + macrolide. This reduces treatment failure from resistant organisms.","Moxifloxacin vs. Levofloxacin: Moxi has better pneumococcal activity and no renal dosing needed. Levo has Pseudomonas coverage (moxi does NOT). Moxi has higher QT risk. Choose based on patient factors.","Don't forget to vaccinate: PCV20 (Prevnar 20) for all adults ≥65 or at high risk. This is a pharmacist-driven intervention that prevents the disease you're treating.","Procalcitonin <0.25: consider viral etiology or non-infectious cause. Can help you withhold antibiotics or stop them early. Not perfect but a useful stewardship tool.","COPD + CAP: The organism profile shifts — H. influenzae and M. catarrhalis become more common. Amox-clav is a strong choice here because it handles all three common pathogens (pneumococcus, H. flu, Moraxella)."]},{id:"cap-inpatient",name:"Inpatient CAP (Non-ICU)",definition:"CAP requiring hospital admission but NOT ICU-level care. CURB-65 ≥2 or PSI class III-IV. Patients who are hypoxic, tachypneic, confused, or have significant comorbidity exacerbation warranting admission.",clinicalPresentation:"Moderate-severe symptoms: high fever, productive cough, dyspnea, tachypnea (RR ≥22-30), hypoxia (SpO2 <94% on room air), dehydration, confusion (especially elderly). May have multilobar infiltrates on CXR.",diagnostics:"Chest X-ray (REQUIRED). Blood cultures × 2 BEFORE antibiotics (ATS/IDSA recommends for inpatients). Sputum culture (if quality specimen obtainable). Procalcitonin (baseline — helps guide de-escalation). Legionella urinary antigen and pneumococcal urinary antigen if severity warrants. Consider respiratory viral panel (especially flu season). Lactate if sepsis suspected.",durationGuidance:{standard:"5 days",severe:"7–10 days (ICU/bacteremic)",stewardshipNote:"IDSA/ATS 2019: 5-day course non-inferior for uncomplicated CAP. Reassess at day 5 using clinical stability criteria."},empiricTherapy:[{line:"First-Line (Combination — Preferred by ATS/IDSA)",options:[{drug:"ceftriaxone",regimen:"Ceftriaxone 1-2g IV daily + Azithromycin 500mg IV/PO daily",notes:"The classic inpatient CAP regimen. Beta-lactam covers typicals; macrolide adds atypical coverage + immunomodulatory effects. ATS/IDSA 2019 preferred combination. Note: CAP-START suggests beta-lactam monotherapy may suffice — but most US institutions still use combination.",evidence:"A-I",evidenceSource:"IDSA/ATS 2019"},{drug:"ampicillin-sulbactam",regimen:"Ampicillin-Sulbactam 3g IV q6h + Azithromycin 500mg IV/PO daily",notes:"Alternative beta-lactam backbone. Better anaerobic coverage than ceftriaxone (relevant if aspiration component suspected). Covers H. influenzae and M. catarrhalis beta-lactamase producers.",evidence:"A-I",evidenceSource:"IDSA/ATS 2019"},{drug:"ceftriaxone-doxy",regimen:"Ceftriaxone 1-2g IV daily + Doxycycline 100mg PO/IV BID",notes:"Doxycycline substitution for macrolide-intolerant patients (QT concern, azithromycin allergy). Equally effective for atypical coverage.",evidence:"B-II",evidenceSource:"IDSA/ATS 2019"}]},{line:"Second-Line (Monotherapy — Respiratory FQ)",options:[{drug:"levofloxacin",regimen:"Levofloxacin 750mg IV/PO daily",notes:"Monotherapy alternative. Covers typicals + atypicals in one drug. 100% oral bioavailability — switch to PO as soon as patient can swallow. Reserve for beta-lactam allergy or when combination therapy not feasible."},{drug:"moxifloxacin",regimen:"Moxifloxacin 400mg IV/PO daily",notes:"Superior pneumococcal activity vs. levo. NO Pseudomonal coverage. Higher QT prolongation risk. No IV-to-PO dose change needed. No renal adjustment."}]}],organismSpecific:[{organism:"S. pneumoniae (still #1 bacterial cause)",preferred:"Ceftriaxone, ampicillin (high-dose), respiratory FQ",alternative:"Vancomycin (only if highly resistant — rare in US)",notes:"Even with PCV13/20, still the most common identified bacterial cause of CAP. Penicillin 'resistance' in pneumonia is defined differently than meningitis — MIC breakpoint for IV penicillin in non-meningitis is ≤2 (vs ≤0.06 for meningitis). Most 'resistant' isolates are treatable with ceftriaxone or high-dose ampicillin."},{organism:"Legionella pneumophila",preferred:"Azithromycin 500mg daily or Levofloxacin 750mg daily",alternative:"Doxycycline (less data but reasonable)",notes:"Classic presentation: high fever, GI symptoms (diarrhea), hyponatremia, elevated LFTs, relative bradycardia. Urinary antigen only detects serogroup 1 (~70% of disease). Culture on BCYE agar is gold standard but rarely done. Outbreaks linked to water systems."},{organism:"Mycoplasma pneumoniae",preferred:"Azithromycin, Doxycycline",alternative:"Respiratory FQ",notes:"Less common cause of hospitalized CAP (more outpatient). When severe enough to hospitalize, doxycycline may be preferred over azithromycin given rising macrolide resistance. Extrapulmonary manifestations: encephalitis, hemolytic anemia, Stevens-Johnson Syndrome, cardiac."},{organism:"Influenza A/B",preferred:"Oseltamivir 75mg PO BID × 5 days",alternative:"Baloxavir (single dose — useful for adherence, but less data in hospitalized severe influenza)",notes:"Treat ALL hospitalized influenza patients regardless of symptom duration. Even >48h from onset, oseltamivir reduces mortality in hospitalized patients. Always add bacterial CAP coverage if concurrent bacterial pneumonia suspected (influenza + S. aureus or S. pneumoniae is a deadly combination)."},{organism:"MRSA (if risk factors present)",preferred:"Vancomycin (trough 15-20 or AUC/MIC 400-600) or Linezolid 600mg PO/IV BID",alternative:"TMP-SMX (for mild cases, oral step-down)",notes:"ATS/IDSA 2019: Only add MRSA coverage if risk factors present (prior MRSA colonization/infection, IV drug use, recent influenza, empyema/cavitation on imaging). Do NOT add empirically for all CAP. Nasal MRSA swab has excellent negative predictive value (~95%) — if negative, safely de-escalate."},{organism:"Pseudomonas aeruginosa (if risk factors present)",preferred:"Pip-tazo, cefepime, meropenem (IV) + Ciprofloxacin or Levofloxacin (if susceptible)",alternative:"Double-cover pending susceptibilities",notes:"ATS/IDSA 2019: Only add Pseudomonas coverage if VALIDATED risk factors: structural lung disease (bronchiectasis, CF), prior Pseudomonas respiratory cultures, very severe immunosuppression. Prior hospitalization alone is NOT sufficient — this was the key change from old HCAP guidelines."}],pearls:["CAP-START changed the game: For non-ICU inpatient CAP, beta-lactam monotherapy was non-inferior to beta-lactam + macrolide and to respiratory FQ monotherapy. Many stewardship programs now support ceftriaxone monotherapy for non-severe CAP without Legionella risk factors. The macrolide adds most value when Legionella is a concern.","The macrolide immunomodulatory effect: Beyond atypical coverage, azithromycin has anti-inflammatory properties that may improve outcomes in severe CAP (reduced IL-6, IL-8). This is why many clinicians still add it even when atypical coverage isn't needed. The data is strongest for severe/bacteremic pneumococcal CAP.","IV-to-PO switch: Both levofloxacin and azithromycin have excellent oral bioavailability. Switch to PO as soon as the patient can swallow and is not vomiting. This is a pharmacist-driven intervention that reduces line infections and LOS.","Nasal MRSA swab: Negative predictive value ~95% for MRSA pneumonia. If the swab is negative, you can safely stop vancomycin/linezolid. Champion this at your institution — it's one of the highest-impact stewardship tools.","Procalcitonin-guided de-escalation: If PCT <0.25 or drops by >80%, consider stopping antibiotics. Multiple RCTs support this approach for reducing antibiotic duration without increasing mortality. Pharmacists should actively engage with PCT trending.","Blood cultures: ATS/IDSA recommends for all inpatients. Positivity rate is only 5-14%, but when positive, it changes management significantly (organism identification, targeted therapy, ID consult trigger).","Don't forget the vaccinations before discharge: PCV20 and annual influenza vaccine. Pharmacist-driven immunization at discharge is evidence-based and is a CMS quality measure."]},{id:"cap-icu",name:"Severe CAP / ICU Admission",definition:"CAP requiring ICU admission. ATS/IDSA defines severe CAP by meeting ≥1 major criterion (mechanical ventilation or vasopressor-dependent septic shock) OR ≥3 minor criteria (RR ≥30, PaO2/FiO2 ≤250, multilobar infiltrates, confusion, BUN ≥20, WBC <4000, platelets <100K, hypothermia <36°C, hypotension requiring aggressive fluids).",clinicalPresentation:"Respiratory failure, septic shock, multilobar/bilateral infiltrates, rapidly progressive disease. May present with ARDS. High mortality — 20-50% depending on severity and organism.",diagnostics:"Full workup: blood cultures × 2, sputum culture (intubated: BAL or mini-BAL preferred), Legionella urinary antigen, pneumococcal urinary antigen, respiratory viral panel (including COVID-19), procalcitonin, lactate, CBC with differential, CMP, ABG. Consider CT chest if CXR unclear or complications suspected (empyema, abscess, PE). Consider bronchoscopy if not improving.",durationGuidance:{standard:"5 days",severe:"7–10 days (ICU/bacteremic)",stewardshipNote:"IDSA/ATS 2019: 5-day course non-inferior for uncomplicated CAP. Reassess at day 5 using clinical stability criteria."},empiricTherapy:[{line:"First-Line (ALWAYS Combination for Severe CAP)",options:[{drug:"ceftriaxone",regimen:"Ceftriaxone 2g IV daily + Azithromycin 500mg IV daily",notes:"ATS/IDSA standard for severe CAP. The macrolide is STRONGLY recommended here (not optional like non-ICU). Macrolide immunomodulatory effect is most impactful in severe/bacteremic disease. Duration: minimum 5 days, typically 7 days.",evidence:"A-I",evidenceSource:"IDSA/ATS 2019"},{drug:"ceftriaxone-fq",regimen:"Ceftriaxone 2g IV daily + Levofloxacin 750mg IV daily",notes:"Alternative combination if macrolide cannot be used (QT prolongation, allergy). Note: combining ceftriaxone + FQ gives broader coverage but loses the macrolide immunomodulatory benefit.",evidence:"A-I",evidenceSource:"IDSA/ATS 2019"},{drug:"amp-sulbactam-combo",regimen:"Ampicillin-sulbactam 3g IV q6h + Azithromycin 500mg IV daily",notes:"Alternative beta-lactam backbone with better anaerobic coverage. Useful if aspiration component suspected in ICU CAP.",evidence:"B-II",evidenceSource:"IDSA/ATS 2019"}]},{line:"Add-On for MRSA Risk Factors",options:[{drug:"vancomycin",regimen:"Vancomycin IV (AUC/MIC-guided dosing, target AUC 400-600)",notes:"Add if: prior MRSA infection/colonization, IVDU, post-influenza necrotizing pneumonia, cavitation/empyema. Check nasal MRSA swab — if negative, de-escalate within 48h. AUC-guided dosing is now preferred over trough-based (2020 vancomycin consensus guidelines)."},{drug:"linezolid",regimen:"Linezolid 600mg IV/PO BID",notes:"Alternative to vancomycin for MRSA pneumonia. Some data suggests better lung penetration. 100% oral bioavailability. Myelosuppression risk with courses >14 days. Monitor CBC weekly. Serotonin syndrome risk with SSRIs/MAOIs."}]},{line:"Add-On for Pseudomonas Risk Factors",options:[{drug:"pip-tazo",regimen:"Piperacillin-tazobactam 4.5g IV q6h (extended infusion over 4h)",notes:"Replace ceftriaxone with pip-tazo + azithromycin or FQ. Extended infusion critical for optimizing time above MIC. Consider adding an aminoglycoside or anti-pseudomonal FQ for double coverage in critically ill."},{drug:"cefepime",regimen:"Cefepime 2g IV q8h (extended infusion)",notes:"Alternative anti-pseudomonal beta-lactam. Also covers SPACE organisms (AmpC producers) — better than ceftriaxone for Enterobacter, Citrobacter, Serratia."},{drug:"meropenem",regimen:"Meropenem 1-2g IV q8h (extended infusion over 3h)",notes:"Reserve for severe septic shock, ESBL/MDR risk, or failure of other agents. Always de-escalate aggressively once cultures return. Extended infusion is standard of care in the ICU."}]},{line:"Adjunctive Therapy",options:[{drug:"corticosteroids",regimen:"Hydrocortisone 200mg IV daily (50mg q6h) × 4-7 days, then taper",notes:"CAPE COD Trial (2023): Hydrocortisone reduced 28-day mortality in severe CAP (6.2% vs 11.9%, NNT=18). Practice-changing. ATS/IDSA 2019 conditionally recommends for refractory septic shock. Now extending to all severe CAP based on CAPE COD. Avoid in influenza pneumonia (worsens outcomes) and suspected fungal infection."},{drug:"oseltamivir",regimen:"Oseltamivir 75mg PO BID × 5 days (or longer if immunocompromised)",notes:"Add empirically during influenza season for all ICU CAP until influenza is ruled out. Even if >48h from symptom onset, treat in severe/hospitalized cases."}]}],organismSpecific:[{organism:"S. pneumoniae (bacteremic)",preferred:"Ceftriaxone + Azithromycin (dual therapy reduces mortality in bacteremic pneumococcal CAP per observational data)",alternative:"Respiratory FQ + beta-lactam",notes:"Baddour et al. and Martinez et al. observational studies showed mortality benefit of combination therapy (beta-lactam + macrolide) over monotherapy in bacteremic pneumococcal CAP. The macrolide immunomodulatory effect appears to be the key — not just the antimicrobial coverage."},{organism:"Legionella (severe)",preferred:"Levofloxacin 750mg IV daily (preferred in severe) or Azithromycin 500mg IV daily",alternative:"Combination of both for severe Legionella",notes:"FQ may be preferred in severe Legionella due to intracellular killing kinetics. Legionella is the second most common identified cause of severe CAP in some series. Hyponatremia + diarrhea + high fever in a severely ill patient = think Legionella until proven otherwise."},{organism:"PVL+ MRSA (necrotizing)",preferred:"Vancomycin + Linezolid (some experts use both for toxin suppression) + Clindamycin (toxin suppression)",alternative:"Linezolid preferred over vancomycin (suppresses PVL toxin production at ribosomal level)",notes:"PVL-positive (Panton-Valentine Leukocidin) MRSA causes rapidly necrotizing, cavitary pneumonia with extremely high mortality. Often post-influenza in young, previously healthy adults. Clindamycin or linezolid suppress toxin production (ribosomal inhibitors). Vancomycin does NOT suppress toxin production — this is a critical distinction."},{organism:"Pseudomonas aeruginosa",preferred:"Anti-pseudomonal beta-lactam (pip-tazo, cefepime, meropenem) + anti-pseudomonal FQ or aminoglycoside",alternative:"Monotherapy after susceptibilities confirmed and clinical improvement",notes:"Double coverage recommended empirically in septic shock pending susceptibilities. De-escalate to monotherapy once susceptibilities confirm sensitivity. Cipro has better anti-pseudomonal activity than levo in vitro."}],pearls:["CAPE COD trial is practice-changing: Hydrocortisone for severe CAP reduced 28-day mortality with NNT of 18. This is being rapidly adopted. KEY EXCEPTION: Do NOT give steroids for influenza pneumonia — steroids worsen outcomes in influenza (increased mortality, superinfections).","PVL-MRSA pneumonia: Think about this when you see a previously healthy young person with rapidly necrotizing pneumonia, especially post-influenza. Toxin suppression is the key — use linezolid or clindamycin (ribosomal inhibitors), not just vancomycin. Some experts add clindamycin to vancomycin specifically for toxin suppression.","Extended infusion beta-lactams in ICU: This is mandatory stewardship at this severity level. Pip-tazo over 4h, cefepime over 3-4h, meropenem over 3h. Monte Carlo simulations show dramatically improved PTA (probability of target attainment). Push for this as a pharmacy protocol.","Day 1 matters: In septic shock, every hour of delayed appropriate antibiotics increases mortality by ~7.6% (Kumar et al., 2006). Ensure antibiotics are administered within 1 hour of recognition. This is a pharmacist operational responsibility — have them available, mixed, and ready.","De-escalation is as important as escalation: Once cultures return (48-72h), aggressively narrow therapy. If MRSA swab negative → stop vancomycin. If Pseudomonas cultures negative and no risk factors → step down from pip-tazo to ceftriaxone. Stewardship in the ICU has the biggest impact.","ARDS from CAP: Lung-protective ventilation (6 mL/kg IBW) is the cornerstone. Prone positioning for P/F <150. Neither is a pharmacy intervention directly, but understanding the pathophysiology helps with drug dosing (increased Vd in ARDS, altered PK for many drugs)."]},{id:"aspiration-pneumonia",name:"Aspiration Pneumonia",definition:"Pneumonia resulting from aspiration of oropharyngeal or gastric contents into the lower respiratory tract. Distinguished from aspiration pneumonitis (chemical inflammation without infection). True aspiration pneumonia involves bacterial infection and typically occurs in patients with impaired swallowing, altered consciousness, or impaired cough reflex.",clinicalPresentation:"Often insidious onset. Fever, cough, purulent sputum, dyspnea. Classic: dependent lung segments affected (right lower lobe if upright, posterior segments of upper lobes or superior segments of lower lobes if supine). May present with lung abscess or empyema if delayed diagnosis. Risk factors: stroke, dementia, intubation, alcoholism, GERD, poor dentition, procedural sedation.",diagnostics:"CXR showing infiltrate in dependent lung segments. Blood cultures if febrile/systemic signs. Sputum culture (often polymicrobial). CT chest if abscess or empyema suspected. Distinguish from aspiration pneumonitis: pneumonitis occurs within hours of witnessed aspiration, is chemical/inflammatory, and typically resolves within 24-48h WITHOUT antibiotics.",durationGuidance:{standard:"5 days",severe:"7–10 days (ICU/bacteremic)",stewardshipNote:"IDSA/ATS 2019: 5-day course non-inferior for uncomplicated CAP. Reassess at day 5 using clinical stability criteria."},empiricTherapy:[{line:"First-Line (Community-Acquired Aspiration)",options:[{drug:"amp-sulbactam-asp",regimen:"Ampicillin-sulbactam 3g IV q6h",notes:"Excellent choice — covers streptococci, oral anaerobes, H. influenzae, and gram-negatives. The gold standard for aspiration pneumonia. Good anaerobic coverage without being overly broad.",evidence:"A-I",evidenceSource:"IDSA/ATS 2019"},{drug:"amox-clav-asp",regimen:"Amoxicillin-clavulanate 875/125mg PO BID (if outpatient/mild)",notes:"Oral equivalent for mild aspiration pneumonia that can be treated outpatient. Same spectrum as IV amp-sulbactam. Duration: 5-7 days.",evidence:"B-II",evidenceSource:"IDSA/ATS 2019"}]},{line:"Alternatives",options:[{drug:"ceftriaxone-metro",regimen:"Ceftriaxone 1-2g IV daily + Metronidazole 500mg IV q8h",notes:"If amp-sulbactam unavailable. Ceftriaxone handles gram-negatives and streptococci; metronidazole adds anaerobic coverage. Note: the role of anaerobic coverage is debated — some experts argue it's unnecessary for most community-acquired aspiration."},{drug:"clindamycin",regimen:"Clindamycin 600mg IV q8h (or 300-450mg PO QID)",notes:"Traditional aspiration pneumonia drug — excellent anaerobic and streptococcal coverage. Fallen somewhat out of favor due to high C. diff risk. Still useful for penicillin-allergic patients or lung abscess."},{drug:"moxifloxacin-asp",regimen:"Moxifloxacin 400mg IV/PO daily",notes:"Covers typicals, atypicals, AND has moderate anaerobic activity (unique among FQs). Can be used as monotherapy for mild-moderate aspiration pneumonia. No Pseudomonas coverage."}]},{line:"Lung Abscess / Empyema",options:[{drug:"prolonged-course",regimen:"Amp-sulbactam or clindamycin × 4-6 weeks minimum for lung abscess",notes:"Lung abscess requires prolonged therapy — typically until radiographic resolution or significant improvement. Some abscesses >6cm may require percutaneous drainage or surgical intervention. Empyema requires chest tube drainage ± fibrinolytics (tPA + DNase per MIST2 trial) + antibiotics."}]}],organismSpecific:[{organism:"Mixed oral flora (Streptococcus spp. + anaerobes)",preferred:"Amp-sulbactam, amox-clav",alternative:"Clindamycin, moxifloxacin",notes:"The traditional teaching of 'aspiration = anaerobes' has been challenged. Modern studies using molecular diagnostics show that streptococci (viridans group, S. intermedius/anginosus group) are actually the dominant pathogens. Anaerobes play a supporting role, especially in abscess formation."},{organism:"S. anginosus/intermedius/constellatus group (milleri group)",preferred:"Ampicillin, amox-clav, penicillin",alternative:"Ceftriaxone, clindamycin",notes:"These are the streptococci most associated with abscess formation anywhere in the body — lung, brain, liver. Very common in aspiration pneumonia complicated by abscess. Usually penicillin-susceptible. If you see a lung abscess, think milleri group."},{organism:"Gram-negative rods (Klebsiella, E. coli — if healthcare-associated)",preferred:"Ceftriaxone, pip-tazo",alternative:"Meropenem if MDR risk",notes:"Healthcare-associated aspiration (nursing home, recent hospitalization) shifts the flora toward gram-negative rods. Empiric coverage should be broader. Consider local antibiogram."}],pearls:["Aspiration pneumonitis ≠ aspiration pneumonia. Pneumonitis is a chemical inflammation from gastric acid — it occurs within hours, causes bilateral infiltrates, and typically resolves in 24-48h WITHOUT antibiotics. DO NOT reflexively start antibiotics for witnessed aspiration in the OR or intubation — observe and only treat if fever/infiltrate persists >48h.","The 'anaerobe dogma' is being dismantled: Modern molecular studies show that streptococci (especially the anginosus/milleri group) are the primary pathogens in aspiration pneumonia, not anaerobes. Anaerobes play a role in abscess formation and empyema but may not be necessary to cover in simple aspiration pneumonia. This is why ceftriaxone alone sometimes works.","Metronidazole monotherapy does NOT work for aspiration pneumonia — it misses the streptococci and aerobic gram-negatives that are actually the dominant pathogens. Never use metronidazole alone; always combine with a cephalosporin or similar.","Clindamycin: Once the drug of choice for aspiration pneumonia and lung abscess. Still effective but high C. diff rate (~10-15%) has pushed it to second-line. Amp-sulbactam has comparable efficacy with less C. diff risk.","Poor dentition is the modifiable risk factor that gets overlooked. Dental care reduces aspiration pneumonia risk in elderly and institutionalized patients. Advocate for oral care protocols in your institution — chlorhexidine oral care reduces ventilator-associated pneumonia by ~40%.","Lung abscess duration: Unlike most pneumonias, lung abscess requires extended treatment — typically 3-6 weeks or until radiographic improvement. Patients often need outpatient IV antibiotics (OPAT) or prolonged oral therapy (amox-clav or clindamycin). Plan for this at discharge."]}],drugMonographs:[{id:"amoxicillin",name:"Amoxicillin",brandNames:"Amoxil, Trimox, Moxatag (ER)",drugClass:"Aminopenicillin (beta-lactam)",mechanismOfAction:"Inhibits penicillin-binding proteins (PBPs), primarily PBP-1a, 1b, 2, and 3, disrupting peptidoglycan cross-linking in the bacterial cell wall. Bactericidal. Time-dependent killing (T>MIC drives efficacy).",spectrum:"Excellent: Streptococcus pneumoniae (including intermediate-resistant at high doses), Group A and B Strep, Enterococcus faecalis, Listeria, H. influenzae (non-beta-lactamase producing ~60-70%). Moderate: E. coli (variable, ~50-60% susceptible). GAPS: MRSA, beta-lactamase producing organisms (H. flu, M. catarrhalis, many gram-negatives), Pseudomonas, Mycoplasma, Legionella.",dosing:{standard:"500mg PO TID or 875mg PO BID",cap_high_dose:"1g PO TID (HIGH-DOSE for CAP per ATS/IDSA 2019 — targets intermediate-resistant S. pneumoniae)",aom:"80-90 mg/kg/day divided BID (pediatric acute otitis media — high-dose)",endocarditis_prophylaxis:"2g PO × 1 dose, 30-60 min before procedure",helicobacter:"1g PO BID (as part of triple/quadruple therapy)"},renalAdjustment:"GFR 10-30: 250-500mg q12h. GFR <10: 250-500mg q24h. Hemodialysis: dose after HD (removed by dialysis). For high-dose CAP regimen, reduce frequency proportionally.",hepaticAdjustment:"No adjustment needed. Primarily renally eliminated.",adverseEffects:{common:"Diarrhea (~5-10%), nausea, rash (maculopapular — important: distinguish from true allergy)",serious:"Anaphylaxis (rare, ~0.01-0.05%), C. difficile, seizures at very high IV doses (penicillin class effect), interstitial nephritis (rare)",rare:"Serum sickness-like reaction (especially in children), hepatitis, crystalluria at very high doses"},drugInteractions:["Methotrexate — reduced renal tubular secretion → increased MTX levels. Monitor closely.","Warfarin — rare reports of increased INR. Monitor if initiating amoxicillin in a patient on warfarin.","Allopurinol — increased incidence of maculopapular rash (not true allergy — benign but alarming). Counsel patients.","Oral contraceptives — historically cited interaction is largely mythical. No dose adjustment needed, but counsel to use backup method during acute GI illness (diarrhea reduces absorption of OCP, not the antibiotic interaction itself).","Probenecid — blocks renal tubular secretion of amoxicillin → increased levels/duration. Actually therapeutically used in some settings."],monitoring:"Short courses: none routinely needed. Prolonged courses (endocarditis): CBC, BMP, LFTs periodically. Monitor for rash (distinguish maculopapular 'amoxicillin rash' from urticarial true allergy).",pregnancyLactation:"Category B. Safe in all trimesters. One of the most commonly used antibiotics in pregnancy. Compatible with breastfeeding — small amounts in breast milk but not clinically significant.",pharmacistPearls:["High-dose amoxicillin for CAP: The 1g TID dosing is critical for pneumonia. Standard 500mg TID does NOT achieve the PK/PD target (T>MIC >50%) for intermediately resistant S. pneumoniae (MIC 2-4). This is the single most important dosing pearl for outpatient CAP.","The 'amoxicillin rash' in mononucleosis: ~70-100% of patients with EBV mono develop a maculopapular (NOT urticarial) rash when given amoxicillin/ampicillin. This is NOT a true penicillin allergy and does NOT predict future penicillin reactions. Do NOT label these patients as penicillin-allergic — this leads to years of unnecessary broad-spectrum antibiotic use.","Amoxicillin has ~80-90% oral bioavailability (much better than ampicillin ~50%). This is why amoxicillin replaced ampicillin for oral therapy. The IV equivalent is ampicillin, not 'IV amoxicillin' (which doesn't exist in the US).","Suspension stability: Reconstituted amoxicillin suspension is stable for 14 days refrigerated. Always label with expiration date. Unused portion should be discarded — patients often save it.","For H. pylori regimens: Amoxicillin is not affected by the clarithromycin resistance that plagues triple therapy. In areas with high clarithromycin resistance, bismuth quadruple therapy (with amoxicillin) is preferred.","Penicillin allergy de-labeling: ~90% of patients labeled 'penicillin-allergic' are NOT truly allergic on testing. Pharmacist-driven penicillin allergy assessment and de-labeling programs improve patient outcomes and reduce broad-spectrum antibiotic use. Champion this."]},{id:"azithromycin",name:"Azithromycin",brandNames:"Zithromax, Z-pack, Zmax (ER)",drugClass:"Macrolide (azalide subclass — 15-membered ring)",mechanismOfAction:"Binds to the 50S ribosomal subunit (23S rRNA), inhibiting translocation of peptidyl-tRNA. Bacteriostatic at standard concentrations (can be bactericidal at high concentrations for certain organisms). Unique azalide structure gives it exceptional tissue penetration and long half-life.",spectrum:"Gram-positive: S. pneumoniae (BUT 30-40% resistance in US), Group A Strep (alternative for penicillin allergy), S. aureus (limited, not reliable for serious infections). Atypicals: Mycoplasma, Chlamydophila, Legionella (excellent). Others: H. influenzae (moderate), M. catarrhalis, Bordetella pertussis, NTM (MAC — in combination). GAPS: MRSA, Enterococcus, most Enterobacterales, Pseudomonas, anaerobes.",dosing:{cap:"500mg PO day 1, then 250mg daily × 4 days (Z-pack) — OR 500mg PO/IV daily × 3 days for inpatient",iv_cap:"500mg IV daily (for inpatient CAP as part of combination therapy)",mac_prophylaxis:"1200mg PO weekly (HIV, CD4 <50 — largely replaced by effective ART)",pertussis:"500mg day 1, then 250mg × 4 days",traveler_diarrhea:"1000mg PO × 1 dose (or 500mg daily × 3 days)",chlamydia:"1g PO × 1 dose (being replaced by doxycycline 100mg BID × 7d per updated CDC STI guidelines)"},renalAdjustment:"No adjustment needed — hepatically metabolized, biliary excretion. Safe in renal impairment.",hepaticAdjustment:"Use with caution in severe hepatic disease. Rare but potentially fatal hepatotoxicity reported (cholestatic hepatitis). Avoid if prior azithromycin-induced hepatitis.",adverseEffects:{common:"Diarrhea (~5%), nausea, abdominal pain, headache",serious:"QT prolongation / Torsades de Pointes (FDA safety communication 2013 — increased risk of cardiovascular death in patients with baseline QT prolongation or risk factors), hepatotoxicity (cholestatic, can be severe), C. difficile",rare:"Hearing loss (high-dose, prolonged use — usually reversible), myasthenia gravis exacerbation, interstitial nephritis"},drugInteractions:["QT-prolonging drugs — ADDITIVE risk. Avoid with: Class IA/III antiarrhythmics (amiodarone, sotalol, dofetilide), fluoroquinolones, ondansetron, methadone, certain antipsychotics. This is the most clinically important interaction.","Warfarin — enhanced anticoagulant effect (mechanism unclear, possibly gut flora disruption). Monitor INR.","Digoxin — azithromycin can increase digoxin levels by inhibiting P-glycoprotein in the gut and by reducing gut flora that metabolize digoxin. Monitor digoxin levels.","Nelfinavir — significantly increases azithromycin levels. Monitor for toxicity.","NOTABLE ABSENCE: Unlike clarithromycin and erythromycin, azithromycin does NOT significantly inhibit CYP3A4. This makes it far safer with statins, calcineurin inhibitors, and other CYP3A4 substrates. This is a key clinical advantage."],monitoring:"Short courses: clinical response. QTc if patient has risk factors for QT prolongation (baseline ECG if concern). LFTs if symptoms of hepatitis develop. Hearing assessment if prolonged/high-dose use.",pregnancyLactation:"Category B. Generally considered safe in pregnancy. Used for chlamydia treatment in pregnancy. Compatible with breastfeeding — low breast milk levels.",pharmacistPearls:["The Z-pack is America's most overprescribed antibiotic. ~30-40% of S. pneumoniae in the US are macrolide-resistant (erm(B) and mef(A) genes). Using azithromycin as monotherapy for CAP in areas with high resistance is gambling with the patient's life.","Azithromycin's tissue penetration is its superpower: Tissue concentrations are 10-100× higher than serum levels. This is why a 5-day course works — the drug persists in tissues for 5-7 days after the last dose. The 'Z-pack is too short' criticism misunderstands its pharmacokinetics.","QT prolongation: The 2013 FDA warning was based on the Ray et al. NEJM study showing increased cardiovascular death in azithromycin users. Risk is highest in patients with: baseline prolonged QT, hypokalemia, hypomagnesemia, bradycardia, or concomitant QT-prolonging drugs. Always check the QTc and K/Mg.","CYP3A4 advantage: Unlike clarithromycin (potent CYP3A4 inhibitor), azithromycin has minimal CYP interactions. This makes it safe with statins, tacrolimus, cyclosporine, and many other drugs. When a patient needs a macrolide and is on a CYP3A4-sensitive drug, azithromycin is the clear choice.","Immunomodulatory effects: Beyond antimicrobial activity, azithromycin reduces neutrophilic inflammation, decreases pro-inflammatory cytokines (IL-6, IL-8, TNF-α), and modulates macrophage function. This is why it's used in COPD exacerbation prophylaxis (MACRO trial: azithromycin 250mg daily reduced AECOPD frequency) and CF lung disease. In severe CAP, this immunomodulatory effect may contribute to mortality reduction beyond pathogen coverage.","For chlamydia: CDC 2021 STI guidelines now recommend doxycycline 100mg BID × 7 days OVER azithromycin 1g single dose due to better cure rates. The single-dose azithromycin era for chlamydia is ending.","Storage: azithromycin oral suspension does NOT need refrigeration (stable at room temperature for 10 days). This is a practical counseling point for parents — one less thing in the fridge."]},{id:"doxycycline",name:"Doxycycline",brandNames:"Vibramycin, Doryx, Monodox, Acticlate, Oracea (sub-antimicrobial)",drugClass:"Tetracycline (2nd generation — lipophilic tetracycline)",mechanismOfAction:"Binds to the 30S ribosomal subunit, blocking aminoacyl-tRNA from binding to the mRNA-ribosome complex. Bacteriostatic (but bactericidal against some organisms at higher concentrations). Also has anti-inflammatory and immunomodulatory properties independent of antimicrobial activity.",spectrum:"Remarkably broad: Gram-positive: S. pneumoniae (~85-90% susceptible), MRSA (many strains), Enterococcus (some). Gram-negative: H. influenzae, Brucella, Vibrio, Yersinia. Atypicals: Mycoplasma (excellent — NOT affected by macrolide resistance), Chlamydophila, Chlamydia trachomatis, Rickettsia (drug of choice for all rickettsial diseases). Spirochetes: Borrelia (Lyme), Leptospira. Parasites: Malaria (prophylaxis/treatment). Others: Bartonella, Coxiella (Q fever). GAPS: Pseudomonas, Proteus, most Enterobacterales (variable), group A strep (may be resistant), Bacteroides fragilis.",dosing:{standard:"100mg PO BID (loading dose 200mg on day 1 sometimes used for serious infections)",cap:"100mg PO BID × 5 days (outpatient CAP)",mrsa_ssti:"100mg PO BID × 5-10 days",chlamydia:"100mg PO BID × 7 days (now CDC preferred over azithromycin single dose)",malaria_prophylaxis:"100mg PO daily (start 1-2 days before, continue 4 weeks after travel)",acne:"50-100mg PO daily (sub-antimicrobial: 40mg MR daily — Oracea)",lyme:"100mg PO BID × 10-21 days (depending on manifestation)",rocky_mountain_spotted_fever:"100mg PO/IV BID (ALL ages — including children, even <8 years)"},renalAdjustment:"NO adjustment needed — a major advantage over other tetracyclines. Doxycycline is primarily eliminated via the GI tract (chelated with bile salts). Safe in renal impairment, including dialysis patients. This is unlike tetracycline (which accumulates in renal failure).",hepaticAdjustment:"Use with caution in severe hepatic impairment. Primarily hepatically metabolized. Can cause hepatotoxicity, especially with high doses or in pregnancy (rare fatty liver of pregnancy).",adverseEffects:{common:"Nausea, esophageal irritation/ulceration (TAKE WITH WATER, upright × 30 min), photosensitivity (dose-dependent), vaginal candidiasis",serious:"Esophageal ulceration (if taken improperly), severe photosensitivity/phototoxicity, intracranial hypertension (pseudotumor cerebri — especially with isotretinoin combination), C. difficile",rare:"Drug-induced lupus, pancreatitis, hepatotoxicity, hypersensitivity syndrome"},drugInteractions:["Divalent/trivalent cations (Ca²⁺, Mg²⁺, Al³⁺, Fe²⁺, Zn²⁺, Bi³⁺) — chelation reduces absorption. Separate by 2-3h. Includes dairy products, antacids, calcium supplements, iron, bismuth subsalicylate.","Warfarin — doxycycline can enhance anticoagulant effect. Monitor INR (mechanism: reduced vitamin K production from gut flora + possible protein binding displacement).","Isotretinoin — CONTRAINDICATED combination. Both cause intracranial hypertension (pseudotumor cerebri). NEVER combine.","Methotrexate — potential increased toxicity (mechanism not fully elucidated).","Oral contraceptives — theoretical interaction, clinically not significant. Backup contraception not routinely needed (unlike with rifampin).","Phenytoin, carbamazepine, barbiturates — enzyme induction can reduce doxycycline half-life by ~50%. May need 200mg BID in patients on these enzymes inducers.","Sucralfate — chelation, reduced absorption. Separate by 2h."],monitoring:"Short courses: clinical response. Prolonged courses (acne, Lyme): No routine labs needed for standard dosing. Monitor for photosensitivity symptoms. Consider BMP if prolonged use in elderly (rare reports of increased BUN without true renal injury). If using sub-antimicrobial dose (Oracea 40mg), no specific monitoring needed.",pregnancyLactation:"Category D. AVOID in pregnancy (permanent tooth discoloration in fetus after ~4 months gestation, inhibits bone growth). AVOID in children <8 years old EXCEPT for life-threatening infections: Rocky Mountain Spotted Fever is the classic exception — doxycycline is the drug of choice even in children and pregnant women when RMSF is suspected because the alternative (chloramphenicol) is worse and delay kills. Compatible with short-term breastfeeding per AAP (calcium in breast milk chelates doxycycline, reducing infant exposure).",pharmacistPearls:["Esophageal ulceration prevention: ALWAYS counsel patients to take doxycycline with a FULL glass of water (8 oz), remain upright for at least 30 minutes after, and NOT take it right before bed. Esophageal ulcers from doxycycline are preventable but cause severe retrosternal pain and odynophagia.","The renal advantage: Unlike tetracycline, doxycycline does NOT accumulate in renal failure and does NOT need dose adjustment. It's eliminated via the GI tract. This makes it one of the most versatile antibiotics in CKD/dialysis patients.","Photosensitivity is dose-dependent. At 100mg BID for a short CAP course, the risk is moderate. At 200mg daily for prolonged acne treatment, it's significant. Always counsel on sun protection (SPF 30+, protective clothing, avoid peak UV hours).","Doxycycline for MRSA: Many community MRSA strains are doxycycline-susceptible. For uncomplicated MRSA SSTI, doxycycline is an effective oral option alongside TMP-SMX and clindamycin. It's underutilized for this indication.","Food interaction nuance: Unlike tetracycline, doxycycline absorption is NOT significantly reduced by food (only ~20% reduction with dairy). You CAN take it with food to reduce nausea — this is a major tolerability advantage. The cation (Ca/Mg/Fe/Al) chelation still applies for supplements/antacids, but a normal meal is fine.","The RMSF exception for children: Doxycycline is the DRUG OF CHOICE for suspected RMSF in ALL ages, including children <8 and pregnant women. The CDC, AAP, and IDSA are unanimous on this. Delayed treatment of RMSF kills. A short course of doxycycline does NOT cause tooth staining. Do not let the pediatric 'tetracycline rule' prevent life-saving treatment.","Macrolide-resistant Mycoplasma: This is the emerging reason doxycycline is gaining favor over azithromycin for outpatient CAP. Macrolide-resistant Mycoplasma (>80% in parts of Asia, ~10-15% in US) is fully susceptible to doxycycline. As resistance rises, doxycycline will become the preferred atypical agent."]},{id:"moxifloxacin",name:"Moxifloxacin",brandNames:"Avelox",drugClass:"Fluoroquinolone (4th generation — 'respiratory fluoroquinolone')",mechanismOfAction:"Inhibits both DNA gyrase (topoisomerase II) and topoisomerase IV with balanced dual-targeting. The 8-methoxy group provides enhanced gram-positive activity and reduced selection for resistance compared to older FQs. Concentration-dependent bactericidal activity with prolonged PAE.",spectrum:"Best-in-class gram-positive for an FQ: S. pneumoniae (including DRSP — MPC is well above achievable concentrations), S. aureus (MSSA, some MRSA activity but not reliable). Good gram-negative: H. influenzae, M. catarrhalis, Klebsiella. Excellent atypicals: Mycoplasma, Chlamydophila, Legionella. MODERATE anaerobes: Bacteroides, Peptostreptococcus (unique among FQs). GAPS: Pseudomonas aeruginosa (NO activity — critical distinction from levo/cipro), ESBL Enterobacterales, MRSA.",dosing:{standard:"400mg PO/IV once daily",cap:"400mg PO daily × 5 days (outpatient) or 400mg IV/PO daily (inpatient)",absssi:"400mg PO/IV daily × 5-14 days",intraabdominal:"400mg IV daily (mild-moderate, monomicrobial — rare use)"},renalAdjustment:"NO adjustment needed at any level of renal function, including dialysis. Hepatically metabolized (glucuronide and sulfate conjugation). This is a significant advantage over levofloxacin.",hepaticAdjustment:"Avoid in severe hepatic impairment (Child-Pugh C). Hepatotoxicity reported. Cases of fulminant hepatic failure have occurred.",adverseEffects:{common:"Nausea (~7%), diarrhea (~5%), dizziness, headache",serious:"QT prolongation (MOST significant among fluoroquinolones — mean QTc prolongation ~6-10 ms), tendinitis/tendon rupture, peripheral neuropathy, CNS effects, C. difficile, hepatotoxicity (including fatal hepatic failure), myasthenia gravis exacerbation",rare:"Torsades de Pointes, aortic aneurysm/dissection, retinal detachment",fdaBoxedWarnings:"Same class warnings as all FQs: tendinitis/rupture, peripheral neuropathy, CNS effects, MG exacerbation. Additional: moxifloxacin was withdrawn from the European IV market in some countries due to hepatotoxicity concerns (oral remains available)."},drugInteractions:["QT-prolonging drugs — HIGHEST RISK among fluoroquinolones. Absolutely avoid with Class IA/III antiarrhythmics, and use extreme caution with ondansetron, methadone, antipsychotics, TCAs, and other QT-prolonging agents.","Divalent/trivalent cations — same chelation as other FQs. Separate from Ca, Mg, Al, Fe, Zn by 4h before or 8h after (moxifloxacin package insert uses 4h/8h, unlike cipro's 2h/6h).","Warfarin — enhanced anticoagulation. Monitor INR.","Insulin/sulfonylureas — dysglycemia risk (hypo- and hyperglycemia).","NOTABLE: Moxifloxacin does NOT significantly inhibit CYP enzymes — no tizanidine or theophylline interaction (similar to levofloxacin, unlike ciprofloxacin)."],monitoring:"Baseline ECG recommended if any QT risk factors. Monitor QTc during therapy if concurrent QT-prolonging drugs. Blood glucose in diabetics. LFTs if symptoms of hepatitis develop. Tendon symptoms — discontinue immediately if tendinopathy suspected.",pregnancyLactation:"Category C. Avoid in pregnancy (same class concerns as all FQs — arthropathy in juvenile animals). Breastfeeding: enters breast milk, generally avoided.",pharmacistPearls:["Moxi vs. Levo — know the critical differences: Moxi has NO Pseudomonas activity (levo does). Moxi has better pneumococcal killing. Moxi has MORE QT prolongation. Moxi needs NO renal adjustment (levo does). Moxi has anaerobic activity (levo doesn't). Choose wisely based on the clinical scenario.","The QT prolongation risk is real and significant. Moxifloxacin causes ~6-10 ms mean QTc prolongation. In a patient with baseline QTc 480 and on methadone, moxifloxacin could tip them into Torsades. ALWAYS check baseline QTc and concomitant medications.","No renal dosing needed — ever. This makes moxi attractive in elderly patients with fluctuating renal function, dialysis patients, and AKI situations where levofloxacin dosing becomes complicated.","Anaerobic coverage: Moxifloxacin is the ONLY fluoroquinolone with meaningful anaerobic activity. This is why it appears in some aspiration pneumonia regimens and intra-abdominal infection guidelines. However, this moderate anaerobic coverage is not as reliable as metronidazole or amp-sulbactam.","Once-daily dosing with excellent oral bioavailability (~90%) and no food interaction makes moxifloxacin extremely convenient. IV-to-PO conversion is seamless — same dose, same frequency.","In TB treatment: Moxifloxacin has a niche role in drug-resistant TB regimens and in the shortened TB-PRACTECAL and STREAM regimens. If you work in a setting with TB patients, know that moxi is a WHO Group A drug for MDR-TB treatment."]},{id:"ampicillin-sulbactam",name:"Ampicillin-Sulbactam",brandNames:"Unasyn",drugClass:"Aminopenicillin + beta-lactamase inhibitor (BLI)",mechanismOfAction:"Ampicillin inhibits PBPs (cell wall synthesis). Sulbactam irreversibly inhibits class A beta-lactamases (TEM, SHV — NOT AmpC or ESBL), restoring ampicillin activity against beta-lactamase producers. Sulbactam also has intrinsic activity against Acinetobacter baumannii (unique among BLIs).",spectrum:"Broad: S. pneumoniae, Group A/B Strep, Enterococcus faecalis, H. influenzae (including beta-lactamase+), M. catarrhalis, E. coli (many), Klebsiella (some), oral anaerobes (excellent), Bacteroides (moderate — less reliable than metronidazole/carbapenems for B. fragilis). GAPS: MRSA, Pseudomonas, ESBL producers, AmpC producers, Acinetobacter (sulbactam has activity, but resistance rising).",dosing:{standard:"3g (2g ampicillin/1g sulbactam) IV q6h",aspiration_pna:"3g IV q6h",intraabdominal:"3g IV q6h",pelvic_inflammatory:"3g IV q6h + doxycycline",epiglottitis:"3g IV q6h",high_dose_acinetobacter:"9g IV q8h (3g ampicillin + 6g sulbactam — high-dose sulbactam for Acinetobacter, off-label)"},renalAdjustment:"CrCl 15-29: 3g q12h. CrCl 5-14: 3g q24h. Hemodialysis: 3g q24h + supplemental dose after HD.",hepaticAdjustment:"No specific adjustment. Monitor LFTs with prolonged use.",adverseEffects:{common:"Diarrhea (~10%), injection site pain, rash",serious:"C. difficile, anaphylaxis (penicillin allergy cross-reactivity), seizures (high doses in renal impairment — ampicillin lowers seizure threshold more than other beta-lactams)",rare:"Interstitial nephritis, hemolytic anemia, serum sickness"},drugInteractions:["Methotrexate — reduced renal clearance → increased MTX toxicity. Monitor levels.","Allopurinol — increased rash incidence (same as amoxicillin).","Warfarin — potential INR increase. Monitor.","Probenecid — increases ampicillin levels (blocks tubular secretion).","Aminoglycosides — in vitro inactivation if mixed in same IV line. Administer separately."],monitoring:"Short courses: clinical response. Prolonged: CBC (leukopenia, thrombocytopenia with extended courses), BMP (renal function — guides dosing), LFTs. Monitor for C. diff if diarrhea develops.",pregnancyLactation:"Category B. Safe in pregnancy — commonly used for intrapartum GBS prophylaxis (ampicillin), obstetric infections (chorioamnionitis, postpartum endometritis). Compatible with breastfeeding.",pharmacistPearls:["Amp-sulbactam is the GOLD STANDARD for aspiration pneumonia. Covers streptococci (including viridans/anginosus group), oral anaerobes, and H. influenzae in one drug. Better tolerated than clindamycin with less C. diff risk.","Oral equivalent: Amoxicillin-clavulanate (Augmentin) is the oral step-down. The sulbactam component of Unasyn inhibits the same beta-lactamases as clavulanate. Use amox-clav 875/125mg PO BID for discharge.","Sulbactam's intrinsic activity against Acinetobacter baumannii is unique and clinically important. In MDR Acinetobacter infections, high-dose sulbactam (up to 4g q6h) is used as a therapeutic agent — the ampicillin is essentially along for the ride. This is a niche but life-saving application.","q6h dosing: The 6-hour dosing interval is important for time-dependent killing. Do not extend to q8h — you'll fall below the MIC target. This can be a nursing compliance challenge; advocate for consistent timing.","For diabetic foot infections: Amp-sulbactam is an excellent empiric choice — covers streptococci, staphylococci (MSSA), gram-negatives, and anaerobes. Add vancomycin if MRSA risk is present.","Seizure risk: Ampicillin (like all penicillins) can lower seizure threshold, especially at high doses in renal impairment. Adjust dose in renal failure to avoid accumulation. This is more relevant for amp-sulbactam than for piperacillin-tazobactam."]}]},l={id:"hap-vap",name:"Hospital-Acquired & Ventilator-Associated Pneumonia",icon:"🏥",category:"Infectious Disease",overview:{definition:"Hospital-Acquired Pneumonia (HAP): pneumonia occurring ≥48 hours after hospital admission that was not incubating at admission. Ventilator-Associated Pneumonia (VAP): pneumonia occurring >48 hours after endotracheal intubation. The 2016 ATS/IDSA guidelines separated HAP/VAP from CAP and eliminated the old 'HCAP' category entirely.",epidemiology:"HAP is the most common healthcare-associated infection contributing to death. VAP occurs in 5-15% of mechanically ventilated patients. Crude mortality: HAP 20-50%, VAP 20-40% (attributable mortality debated — likely 5-13%). VAP adds ~7-9 days to ICU length of stay per episode. HAP/VAP represents the largest single target for inpatient antibiotic stewardship.",keyGuidelines:[{name:"ATS/IDSA 2016 HAP/VAP Guidelines",detail:"Current definitive US guideline. Eliminated HCAP category. Emphasizes local antibiogram-driven empiric therapy, de-escalation, 7-day treatment courses, and avoiding unnecessary broad-spectrum coverage. Recommends AGAINST routine biomarkers (PCT, CRP, sTREM-1) for VAP diagnosis."},{name:"ERS/ESICM/ESCMID/ALAT 2017",detail:"European/Latin American guidelines. More emphasis on risk stratification for MDR pathogens and biomarker-guided duration. Endorses PCT-guided de-escalation more strongly than ATS/IDSA."},{name:"Surviving Sepsis Campaign 2021",detail:"Relevant for HAP/VAP with sepsis — 1-hour antibiotic administration, source control, de-escalation within 48-72h of culture results."},{name:"SHEA/IDSA/APIC Practice Recommendation 2022",detail:"VAP prevention bundle: head-of-bed elevation, daily sedation vacation + SBT, oral care with chlorhexidine (note: some institutions moving away from CHG oral care due to mortality signal in meta-analyses), subglottic secretion drainage, stress ulcer prophylaxis, DVT prophylaxis."}],landmarkTrials:[{name:"IDAT Trial (2015, JAMA)",detail:"Antibiotic de-escalation in VAP: De-escalation was non-inferior to continuation of broad-spectrum therapy in clinical cure. However, de-escalation group had MORE superinfections (paradoxical finding, possibly due to selection of resistant organisms). Trial challenged the assumption that de-escalation is always beneficial, but consensus still supports it."},{name:"PTC Trial (Bouadma 2010, Lancet)",detail:"Procalcitonin-guided antibiotic discontinuation in ICU respiratory infections reduced antibiotic exposure by ~3 days without affecting mortality. Supports PCT-guided de-escalation, though ATS/IDSA 2016 did not strongly endorse this for VAP specifically."},{name:"Chastre et al. (2003, JAMA)",detail:"Landmark trial comparing 8 vs 15 days of antibiotics for VAP. 8 days was non-inferior for most pathogens EXCEPT non-fermenting GNRs (Pseudomonas, Acinetobacter) where relapse was higher with 8 days. Established 7-day courses as standard and flagged non-fermenters as an exception."},{name:"PROSEVA Trial (2013, NEJM)",detail:"Prone positioning in severe ARDS reduced mortality (16% vs 32.8%). While not a HAP-specific trial, relevant because many HAP/VAP patients develop ARDS and proning affects drug distribution and PK."},{name:"VAPORIZE Trial (2024)",detail:"Inhaled amikacin + IV antibiotics vs IV antibiotics alone for VAP. Inhaled aminoglycosides did NOT improve clinical outcomes despite achieving higher lung concentrations. Challenged the practice of adjunctive inhaled antibiotics for VAP."},{name:"MerINO-2 / ACORN (2023-2024)",detail:"Ongoing and recent trials examining pip-tazo vs carbapenems for ESBL bacteremia (relevant to HAP-source bacteremia). Evolving evidence on whether pip-tazo can be used for ESBL infections in certain contexts."}],riskFactors:"Prolonged mechanical ventilation (>5-7 days), prior antibiotic use (strongest MDR risk factor), prolonged hospitalization, ARDS, supine positioning, reintubation, enteral feeding, immunosuppression, chronic lung disease (COPD, bronchiectasis), witnessed aspiration, prior MDR colonization, high local MDR prevalence on the unit's antibiogram."},subcategories:[{id:"hap-no-mdr",name:"HAP — No MDR Risk Factors, Not High Mortality Risk",definition:"Hospital-acquired pneumonia (≥48h after admission) in patients WITHOUT risk factors for MDR pathogens and NOT at high risk of mortality. ATS/IDSA 2016 defines MDR risk factors as: IV antibiotic use in prior 90 days AND structural lung disease (bronchiectasis, CF) for Pseudomonas; IV antibiotics in prior 90 days for MRSA; >5 days hospitalization before HAP onset. High mortality risk: requiring ventilatory support for HAP or septic shock.",clinicalPresentation:"New or progressive radiographic infiltrate + at least 2 of: fever >38°C, leukocytosis (>10K) or leukopenia (<4K), purulent secretions. Modified Clinical Pulmonary Infection Score (CPIS) can assist but is not validated for diagnosis. ATS/IDSA 2016: clinical criteria alone are sufficient — do NOT require invasive sampling for HAP (unlike VAP).",diagnostics:"Non-invasive respiratory sampling (sputum culture). Blood cultures × 2. CXR or CT chest. ATS/IDSA 2016: recommends AGAINST routine invasive sampling (BAL, mini-BAL) for HAP (differs from VAP). Procalcitonin and other biomarkers NOT recommended as sole diagnostic criteria but may assist with de-escalation.",durationGuidance:{standard:"7 days",severe:"14 days (MDR pathogens/poor clinical response)",stewardshipNote:"IDSA/ATS 2016: 7-day duration recommended for most HAP/VAP. De-escalate based on culture and clinical response."},empiricTherapy:[{line:"First-Line (Monotherapy — Standard Risk)",options:[{drug:"pip-tazo-hap",regimen:"Piperacillin-tazobactam 4.5g IV q6h (extended infusion over 4h)",notes:"ATS/IDSA 2016 preferred for HAP without MDR risk. Extended infusion standard of care. Covers Enterobacterales, Pseudomonas (empiric), MSSA, and anaerobes.",evidence:"A-I",evidenceSource:"IDSA/ATS 2016"},{drug:"cefepime",regimen:"Cefepime 2g IV q8h (extended infusion over 3-4h)",notes:"Alternative first-line. Covers gram-negatives including most Pseudomonas and AmpC producers (SPACE organisms). NO anaerobic coverage. NO MRSA coverage.",evidence:"A-I",evidenceSource:"IDSA/ATS 2016"},{drug:"levofloxacin",regimen:"Levofloxacin 750mg IV daily",notes:"ATS/IDSA lists as an option. Covers typicals + atypicals. BUT: high rates of FQ resistance in hospital-acquired gram-negatives limit utility. Check local antibiogram before selecting. 100% bioavailability — PO = IV.",evidence:"B-II",evidenceSource:"IDSA/ATS 2016"},{drug:"meropenem-hap",regimen:"Meropenem 1g IV q8h (extended infusion)",notes:"Listed by ATS/IDSA as an option even without MDR risk, but stewardship principles favor reserving carbapenems. Use if high local ESBL prevalence or patient has multiple beta-lactam allergies limiting options.",evidence:"B-II",evidenceSource:"IDSA/ATS 2016"}]}],organismSpecific:[{organism:"S. aureus (MSSA — most common gram-positive)",preferred:"Pip-tazo, cefepime, oxacillin/nafcillin (if confirmed MSSA)",alternative:"Vancomycin (if MRSA not yet excluded)",notes:"MSSA is common in HAP. Once confirmed MSSA, de-escalate from vancomycin to nafcillin/oxacillin or cefazolin — these have SUPERIOR anti-MSSA activity and better outcomes than vancomycin for MSSA. This is a critical stewardship intervention."},{organism:"Enterobacterales (E. coli, Klebsiella, Enterobacter)",preferred:"Cefepime, pip-tazo",alternative:"Meropenem (if ESBL), levofloxacin (if susceptible)",notes:"Enterobacter, Citrobacter, Serratia — AmpC producers. Use cefepime, NOT ceftriaxone (AmpC induction risk). Hospital-acquired E. coli/Klebsiella have higher ESBL rates than community isolates — check prior cultures."},{organism:"Pseudomonas aeruginosa",preferred:"Pip-tazo, cefepime, meropenem",alternative:"Ciprofloxacin/levofloxacin (if susceptible)",notes:"Even in 'low-risk' HAP, Pseudomonas is possible. Monotherapy is acceptable for non-MDR-risk patients per ATS/IDSA. De-escalate or stop anti-pseudomonal coverage if cultures are negative for Pseudomonas."}],pearls:["Monotherapy is appropriate for HAP without MDR risk factors. ATS/IDSA 2016 is explicit: do NOT reflexively double-cover or add MRSA coverage in every HAP patient. Overtreatment drives resistance.","The HCAP category is DEAD. Nursing home residents, dialysis patients, recent hospitalization — these no longer automatically get broad-spectrum 'HCAP' regimens. Treat based on actual MDR risk factors, not just healthcare exposure. This was the single biggest change in the 2016 guidelines.","Sputum quality matters: Gram stain showing >25 WBCs and <10 squamous epithelial cells per low-power field = adequate specimen. Reject specimens with high squamous cells — they represent mouth flora, not lung infection.","Start antibiotics promptly but don't wait for perfect diagnostics. In HAP, clinical diagnosis is sufficient to initiate therapy. Adjust at 48-72h based on culture results and clinical trajectory."]},{id:"hap-mdr-risk",name:"HAP — MDR Risk Factors OR High Mortality Risk",definition:"HAP in patients with risk factors for MDR pathogens (IV antibiotics in prior 90 days, ≥5 days hospitalization before HAP onset, septic shock, ARDS/ventilatory support requirement, prior MDR colonization) OR at high mortality risk (requiring ventilatory support for HAP, or septic shock). These patients need empiric broadening to cover MRSA and/or Pseudomonas.",clinicalPresentation:"Same as standard HAP but with higher acuity. More likely to present with sepsis, respiratory failure, or rapid clinical decline. These patients are often in the ICU or step-down unit.",diagnostics:"Same as standard HAP plus: consider broader microbiology (fungal cultures if immunosuppressed, respiratory viral panel). Blood cultures essential. Nasal MRSA PCR swab — negative predictive value ~95% for MRSA pneumonia (de-escalation tool). Consider CT chest if CXR unclear or complications suspected.",durationGuidance:{standard:"7 days",severe:"14 days (MDR pathogens/poor clinical response)",stewardshipNote:"IDSA/ATS 2016: 7-day duration recommended for most HAP/VAP. De-escalate based on culture and clinical response."},empiricTherapy:[{line:"Empiric — Anti-Pseudomonal Beta-Lactam (choose one)",options:[{drug:"pip-tazo-mdr",regimen:"Piperacillin-tazobactam 4.5g IV q6h (extended infusion over 4h)",notes:"Preferred anti-pseudomonal backbone. Extended infusion is mandatory at this severity level. Covers gram-negatives, MSSA, anaerobes.",evidence:"A-I",evidenceSource:"IDSA/ATS 2016"},{drug:"cefepime-mdr",regimen:"Cefepime 2g IV q8h (extended infusion)",notes:"Preferred if AmpC producers suspected (Enterobacter, Serratia, Citrobacter). NO anaerobic or MRSA coverage — add metronidazole if aspiration component, add vancomycin if MRSA risk.",evidence:"A-I",evidenceSource:"IDSA/ATS 2016"},{drug:"meropenem-mdr",regimen:"Meropenem 2g IV q8h (extended infusion over 3h)",notes:"Use for ESBL risk, prior MDR gram-negatives, or septic shock with high local resistance. Higher dose (2g) for pneumonia — lung penetration requires higher serum levels. De-escalate aggressively.",evidence:"A-I",evidenceSource:"IDSA/ATS 2016"},{drug:"imipenem",regimen:"Imipenem-cilastatin 500mg IV q6h",notes:"Alternative carbapenem. Slightly better gram-positive coverage than meropenem. Seizure risk higher than meropenem (especially renal impairment, CNS disease). Requires cilastatin to prevent renal metabolism."}]},{line:"ADD MRSA Coverage (if risk factors present)",options:[{drug:"vancomycin",regimen:"Vancomycin IV — AUC/MIC-guided dosing (target AUC 400-600 mg·h/L)",notes:"ATS/IDSA 2016: add MRSA coverage if: IV antibiotics in prior 90 days, unit with >20% MRSA prevalence (or unknown), or prior MRSA colonization/infection. AUC-guided dosing is now standard (2020 vancomycin consensus). Check nasal MRSA swab — if negative, de-escalate within 48-72h.",evidence:"A-I",evidenceSource:"IDSA/ATS 2016"},{drug:"linezolid",regimen:"Linezolid 600mg IV/PO BID",notes:"Alternative to vancomycin. Potential advantages in pneumonia: better lung penetration, 100% oral bioavailability, no renal dosing. ZEPHyR trial showed linezolid non-inferior to vancomycin for MRSA nosocomial pneumonia with some secondary outcome advantages. Risk: myelosuppression (>14 days), serotonin syndrome with SSRIs.",evidence:"A-I",evidenceSource:"IDSA/ATS 2016"}]},{line:"ADD Second Anti-Pseudomonal Agent (if MDR Pseudomonas risk)",options:[{drug:"ciprofloxacin-hap",regimen:"Ciprofloxacin 400mg IV q8h",notes:"ATS/IDSA 2016: add a second anti-pseudomonal agent from a DIFFERENT class if: prior IV antibiotics in 90 days AND unit with >10% gram-negative resistance to monotherapy agent. FQ provides the different class from the beta-lactam backbone. Check local Pseudomonal FQ susceptibility."},{drug:"tobramycin",regimen:"Tobramycin 5-7 mg/kg IV daily (extended-interval dosing)",notes:"Alternative second anti-pseudomonal agent. Best gram-negative aminoglycoside for Pseudomonas. Extended-interval (once-daily) dosing maximizes peak:MIC ratio (concentration-dependent killing). Monitor levels: target peak >20× MIC, trough <1. Nephrotoxicity and ototoxicity with prolonged courses."},{drug:"amikacin",regimen:"Amikacin 15-20 mg/kg IV daily (extended-interval dosing)",notes:"Most resistant to aminoglycoside-modifying enzymes — use when tobramycin-resistant. Higher doses needed for pneumonia due to poor lung penetration. Monitor levels closely."},{drug:"aztreonam",regimen:"Aztreonam 2g IV q8h",notes:"Monobactam — NO cross-allergenicity with penicillins (safe in true penicillin allergy). Anti-pseudomonal. Covers gram-negatives only — no gram-positive or anaerobic activity. Useful in penicillin/cephalosporin allergy with Pseudomonas risk."}]}],organismSpecific:[{organism:"MRSA",preferred:"Vancomycin (AUC 400-600) or Linezolid 600mg BID",alternative:"TMP-SMX (limited pneumonia data, but used in some settings for mild-moderate disease)",notes:"Nasal MRSA PCR: ~95% negative predictive value. ATS/IDSA 2016 recommends using it to de-escalate. If nasal swab negative AND cultures negative at 48h → STOP vancomycin/linezolid. This is a pharmacist-champion intervention. Vancomycin for MSSA is INFERIOR to beta-lactams — always de-escalate to nafcillin/oxacillin/cefazolin if MSSA confirmed."},{organism:"MDR Pseudomonas aeruginosa",preferred:"Cefepime, pip-tazo, or meropenem (based on susceptibility) + second agent from different class",alternative:"Ceftolozane-tazobactam, ceftazidime-avibactam, imipenem-relebactam for DTR (difficult-to-treat resistance) Pseudomonas",notes:"Double-cover empirically, then de-escalate to monotherapy once susceptibilities confirm. DTR Pseudomonas (resistant to all standard agents) — consult ID and consider novel BL-BLIs or cefiderocol. Inhaled aminoglycosides: VAPORIZE trial showed NO benefit of adjunctive inhaled amikacin — not recommended routinely."},{organism:"ESBL-producing Enterobacterales",preferred:"Meropenem (or ertapenem if non-critical)",alternative:"Ceftazidime-avibactam, meropenem-vaborbactam for carbapenem-resistant isolates",notes:"For HAP-source ESBL bacteremia, carbapenems remain standard per MERINO. Pip-tazo is NOT reliable empirically for ESBL. Once cultures confirm ESBL, de-escalate to ertapenem (narrowest carbapenem) if possible."},{organism:"Acinetobacter baumannii",preferred:"Ampicillin-sulbactam (high-dose sulbactam component), meropenem",alternative:"Polymyxin B or colistin (last resort), cefiderocol",notes:"Rising global threat in ICUs. Intrinsically resistant to many agents. Sulbactam has intrinsic activity against Acinetobacter — high-dose sulbactam (9g amp-sulbactam q8h = 3g sulbactam q8h) is a key strategy. Carbapenems are first-line if susceptible. For CRAB (carbapenem-resistant Acinetobacter): polymyxins + high-dose sulbactam ± meropenem (combination therapy, consult ID). Tigecycline achieves poor serum levels — avoid for pneumonia despite in vitro activity."},{organism:"Stenotrophomonas maltophilia",preferred:"TMP-SMX (drug of choice — 15-20 mg/kg/day TMP component divided q6-8h)",alternative:"Levofloxacin, ceftazidime, minocycline/tigecycline",notes:"Intrinsically resistant to carbapenems, aminoglycosides, and most beta-lactams. TMP-SMX is THE drug. Often emerges during prolonged carbapenem therapy — a reason to de-escalate carbapenems as soon as possible. If S. maltophilia appears in cultures of a patient on meropenem, this is not surprising — it's selection pressure."}],pearls:["THE 20% MRSA THRESHOLD: ATS/IDSA 2016 says add empiric MRSA coverage if the unit's MRSA prevalence is >20% or unknown. Many ICUs exceed this threshold. Know YOUR unit's MRSA rate — it should drive your empiric protocol.","THE 10% GNR RESISTANCE THRESHOLD: If >10% of gram-negatives on the unit's antibiogram are resistant to the monotherapy agent you'd choose, add a second anti-pseudomonal agent from a different class. This is why every ICU needs a unit-specific antibiogram, not just a hospital-wide one.","Nasal MRSA swab is the stewardship MVP for HAP/VAP: ~95% NPV for MRSA pneumonia. If negative, you can safely stop vancomycin/linezolid within 48-72h. Multiple studies show this reduces unnecessary vancomycin days by 2-3 days per patient. Champion this protocol.","Extended infusion beta-lactams in HAP/VAP: This is NOT optional at this severity level. Pip-tazo over 4h, cefepime over 3-4h, meropenem over 3h. Monte Carlo simulations show 30-60% improvement in probability of target attainment vs. intermittent bolus. Make this an institutional protocol.","De-escalation at 48-72h: Once cultures return, narrow therapy. Stop MRSA coverage if swab/cultures negative. Stop double Pseudomonal coverage if Pseudomonas not isolated. Switch from meropenem to narrower agents if non-ESBL organism. The ATS/IDSA guideline explicitly recommends this.","Vancomycin AUC-guided dosing: The 2020 vancomycin consensus (ASHP/IDSA/SIDP/PIDS) recommends AUC/MIC 400-600 over trough-based dosing. AUC-guided dosing achieves the same efficacy with LESS nephrotoxicity. If your institution still uses trough goals of 15-20, advocate for switching to AUC-guided protocols with Bayesian software (e.g., PrecisePK, DoseMeRx)."]},{id:"vap",name:"Ventilator-Associated Pneumonia (VAP)",definition:"Pneumonia developing >48 hours after endotracheal intubation. Distinguished from ventilator-associated tracheobronchitis (VAT) which has purulent secretions without new infiltrate. VAP diagnosis is notoriously difficult — no gold standard exists. Clinical criteria have ~70% sensitivity/specificity vs. histopathology.",clinicalPresentation:"New or progressive infiltrate on CXR + at least 2 of: fever >38°C, leukocytosis/leukopenia, purulent tracheal secretions, worsening oxygenation (PaO2/FiO2 decline). Portable CXR in ICU is notoriously unreliable — CT chest may be needed for equivocal cases. VAP should be suspected when a ventilated patient develops new fever + purulent secretions + worsening gas exchange.",diagnostics:"ATS/IDSA 2016 recommends NON-INVASIVE quantitative cultures (endotracheal aspirate, ETA) over invasive sampling (BAL, mini-BAL) — based on evidence showing no mortality difference. ETA threshold: ≥10⁶ CFU/mL. BAL threshold: ≥10⁴ CFU/mL. Blood cultures × 2 (positive in only ~15% but changes management). ATS/IDSA 2016 recommends AGAINST using biomarkers (PCT, CRP, sTREM-1) ALONE to decide whether to initiate antibiotics for VAP, but PCT may guide DURATION.",durationGuidance:{standard:"7 days",severe:"14 days (P. aeruginosa/non-fermenter MDR)",opatNote:"OPAT not applicable — ICU-level care required",stewardshipNote:"Target procalcitonin-guided de-escalation. 8 days non-inferior to 15 days in TRALI trial."},empiricTherapy:[{line:"VAP — No MDR Risk Factors (Low-Risk)",options:[{drug:"pip-tazo-vap",regimen:"Piperacillin-tazobactam 4.5g IV q6h (extended infusion)",notes:"Monotherapy is appropriate if no MDR risk factors AND unit gram-negative resistance <10% to the chosen agent. Same first-line agents as HAP without MDR risk.",evidence:"A-I",evidenceSource:"IDSA/ATS 2016"},{drug:"cefepime-vap",regimen:"Cefepime 2g IV q8h (extended infusion)",notes:"Good choice for AmpC producers. Extended infusion essential. Neurotoxicity risk in renal impairment — monitor for confusion, myoclonus, seizures (cefepime encephalopathy).",evidence:"A-I",evidenceSource:"IDSA/ATS 2016"},{drug:"levofloxacin-vap",regimen:"Levofloxacin 750mg IV daily",notes:"Alternative monotherapy. Check local FQ susceptibility — hospital-acquired gram-negatives often have high FQ resistance. May not be reliable in many ICUs.",evidence:"B-II",evidenceSource:"IDSA/ATS 2016"}]},{line:"VAP — MDR Risk Factors (High-Risk)",options:[{drug:"vap-mdr-backbone",regimen:"Anti-pseudomonal beta-lactam (pip-tazo, cefepime, or meropenem) + second anti-gram-negative agent (FQ or aminoglycoside) + MRSA coverage (vancomycin or linezolid)",notes:"Triple therapy for high-risk VAP. ATS/IDSA 2016: two anti-pseudomonal agents from different classes + MRSA coverage when risk factors present. The goal is to maximize probability of at least one active agent against the causative pathogen. De-escalate aggressively at 48-72h."}]},{line:"Duration (ATS/IDSA 2016 — 7 Days Standard)",options:[{drug:"duration-vap",regimen:"7 days for most VAP (strong recommendation, moderate quality evidence)",notes:"Chastre 2003 trial established 8 vs 15 days — 8 days non-inferior for most pathogens. ATS/IDSA 2016 recommends 7 days for ALL HAP/VAP (not 8, not 14). EXCEPTION: non-fermenting GNRs (Pseudomonas, Acinetobacter, Stenotrophomonas) — some experts extend to 10-14 days due to higher relapse rates at 8 days, though ATS/IDSA still recommends 7 days even for these. Clinical judgment applies."}]},{line:"Adjunctive Therapies",options:[{drug:"inhaled-abx",regimen:"Inhaled aminoglycosides or colistin — NOT routinely recommended",notes:"ATS/IDSA 2016: recommends AGAINST adjunctive inhaled antibiotics for HAP/VAP. VAPORIZE trial (2024) confirmed no benefit of inhaled amikacin. Exception: may consider for MDR/XDR gram-negatives susceptible only to aminoglycosides or polymyxins, where systemic therapy alone is failing — last-resort measure, consult ID."}]}],organismSpecific:[{organism:"Pseudomonas aeruginosa (20-30% of VAP)",preferred:"Anti-pseudomonal beta-lactam (pip-tazo, cefepime, meropenem) ± second agent",alternative:"Ceftolozane-tazobactam, ceftazidime-avibactam, cefiderocol for DTR Pseudomonas",notes:"The most feared VAP pathogen. Biofilm formation on ETT complicates eradication. Empiric double-coverage is for maximizing probability of initial appropriate therapy — NOT for synergy (synergy is unproven in clinical trials for Pseudomonas VAP). Once susceptibility confirmed, de-escalate to monotherapy. Consider extending to 10-14 days for confirmed Pseudomonas VAP given higher relapse rates."},{organism:"MRSA (10-20% of VAP in many ICUs)",preferred:"Vancomycin (AUC 400-600) or Linezolid 600mg BID",alternative:"None with strong evidence for nosocomial pneumonia",notes:"ZEPHyR trial: linezolid vs. vancomycin for MRSA nosocomial pneumonia — linezolid was non-inferior with numerically higher clinical cure rates at end-of-study visit. Linezolid advantages: better lung penetration (ELF concentrations 5-10× serum), 100% oral bioavailability, no renal dosing needed. Linezolid disadvantages: thrombocytopenia (>14 days), serotonin syndrome, cost. Vancomycin advantages: most experience, can monitor AUC. Vancomycin disadvantages: nephrotoxicity, poor lung penetration (ELF levels only 20-30% of serum)."},{organism:"Klebsiella pneumoniae (including KPC)",preferred:"Meropenem (if susceptible), ceftazidime-avibactam (KPC)",alternative:"Meropenem-vaborbactam, imipenem-relebactam, cefiderocol",notes:"Carbapenem-resistant Klebsiella (KPC producers) is an ICU nightmare. Know your mechanism of resistance: KPC → ceftaz-avi or mer-vab are excellent options. MBL (NDM) → cefiderocol or aztreonam + ceftaz-avi (combination). OXA-48 → ceftaz-avi usually active. Always get ID consultation for CRE infections."},{organism:"Acinetobacter baumannii (MDR/XDR)",preferred:"High-dose ampicillin-sulbactam (sulbactam for Acinetobacter activity), meropenem (if susceptible)",alternative:"Polymyxin B + high-dose sulbactam ± meropenem for CRAB",notes:"CRAB (carbapenem-resistant Acinetobacter) mortality exceeds 50%. Combination therapy is standard for CRAB: sulbactam-based + polymyxin ± carbapenem. Durlobactam-sulbactam (Xacduro) — FDA approved 2023 specifically for CRAB HAP/VAP. Tigecycline: adequate in vitro activity but LOW serum/lung levels; associated with increased mortality in VAP — FDA boxed warning. Avoid tigecycline for pneumonia."}],pearls:["VAP prevention is better than VAP treatment: The VAP bundle (HOB elevation 30-45°, daily sedation vacation + SBT, DVT and stress ulcer prophylaxis, oral care, subglottic secretion drainage) reduces VAP rates by 40-70%. Pharmacists contribute to the bundle through stress ulcer and DVT prophylaxis protocols.","The 7-day rule: ATS/IDSA 2016 recommends 7 days for ALL HAP/VAP. Resist the temptation to extend courses. Each additional day of broad-spectrum antibiotics in the ICU increases C. diff risk, MDR selection, and drug toxicity. The only time to consider extension is confirmed non-fermenting GNR with slow clinical response.","Cefepime neurotoxicity: Often missed and underdiagnosed. Presents as confusion, myoclonus, nonconvulsive status epilepticus, and reduced consciousness. Risk factors: renal impairment, elderly, high doses. Check cefepime trough levels if available (target <20 mg/L to avoid neurotoxicity). This is a pharmacist recognition and intervention opportunity.","Vancomycin lung penetration is POOR: ELF concentrations are only 20-30% of serum levels. This is why AUC targets of 400-600 are needed — you need high serum levels to get adequate lung levels. Linezolid achieves ELF concentrations 5-10× serum — a pharmacokinetic advantage for pneumonia. Discuss with the team if vancomycin is failing clinically.","Tigecycline trap: Tigecycline has excellent Acinetobacter activity in vitro, but FDA boxed warning notes increased mortality. The problem is pharmacokinetic — serum and lung levels are inadequate for pneumonia. NEVER use tigecycline monotherapy for HAP/VAP. This error kills patients.","Culture BEFORE antibiotics: VAP cultures become unreliable within hours of starting antibiotics. If you suspect VAP, get the ETA or BAL BEFORE the first dose. Post-antibiotic cultures may be falsely negative, leading to inappropriate de-escalation.","Pseudomonas relapse: Even with 'curative' therapy, Pseudomonas VAP has a 30-40% recurrence rate. If a patient develops VAP again after treating Pseudomonas, assume it's a relapse with the same (or more resistant) strain until proven otherwise. Re-culture and consider different class antibiotics."]},{id:"vap-prevention",name:"VAP Prevention Bundle & Stewardship",definition:"Evidence-based interventions to prevent VAP and optimize antibiotic use in ventilated patients. Prevention is the most effective 'treatment' for VAP. The VAP bundle has been shown to reduce VAP rates by 40-70% in multiple studies.",clinicalPresentation:"N/A — Prevention and stewardship section.",diagnostics:"N/A — This section covers prevention, not diagnosis.",empiricTherapy:[{line:"VAP Prevention Bundle Components",options:[{drug:"hob-elevation",regimen:"Head-of-bed elevation 30-45 degrees",notes:"Reduces aspiration of colonized oropharyngeal secretions. One of the simplest and most effective interventions. Should be maintained at all times unless contraindicated (spinal injury, hemodynamic instability)."},{drug:"sedation-vacation",regimen:"Daily sedation interruption + spontaneous breathing trial (SBT)",notes:"Reduces duration of mechanical ventilation (the single strongest risk factor for VAP). The ABC trial (Awakening and Breathing Controlled) showed this combination reduced ICU LOS and mortality. Pharmacist role: optimize sedation protocols, advocate for daily sedation vacation, manage analgo-sedation."},{drug:"oral-care",regimen:"Oral care protocol (chlorhexidine 0.12% oral rinse BID — note controversy)",notes:"Chlorhexidine oral care reduces oropharyngeal colonization and has been associated with reduced VAP in many studies. HOWEVER: Deschepper et al. (2018) meta-analysis found a possible mortality INCREASE with CHG oral care in non-cardiac surgery ICU patients. Some institutions have removed CHG oral care. Know your institution's stance. Regardless, tooth brushing and oral hygiene are beneficial."},{drug:"subglottic-drainage",regimen:"Continuous or intermittent subglottic secretion drainage (via specialized ETT)",notes:"Reduces early-onset VAP by draining secretions pooled above the ETT cuff. Requires specialized endotracheal tube with a subglottic suction port. Meta-analyses show 45% reduction in VAP. Cost-effective. Should be standard for patients expected to be ventilated >48h."},{drug:"dvt-prophylaxis",regimen:"Enoxaparin 40mg SQ daily (or heparin 5000 units SQ q8-12h)",notes:"DVT prophylaxis is a bundle component for VAP prevention bundles — not directly preventing VAP but part of the comprehensive ICU quality bundle. Pharmacist role: ensure appropriate dosing, renal adjustment, anti-Xa monitoring for enoxaparin in obesity/renal impairment."},{drug:"stress-ulcer",regimen:"PPI or H2RA for stress ulcer prophylaxis in at-risk patients",notes:"Controversial component: PPIs may increase risk of C. diff and HAP/VAP (gastric pH elevation → bacterial overgrowth → aspiration). SUP-ICU trial (2018): pantoprazole vs. placebo in ICU patients at risk of GI bleeding — pantoprazole reduced GI bleeding but no mortality difference. Balance GI bleed prevention vs. infection risk. Pharmacist role: ensure appropriate indication and discontinue at ICU discharge."}]},{line:"Antibiotic Stewardship in HAP/VAP",options:[{drug:"de-escalation",regimen:"Mandatory culture review at 48-72h with de-escalation plan",notes:"ATS/IDSA 2016 strongly recommends de-escalation based on culture results. Stop MRSA coverage if MRSA swab/cultures negative. Stop double Pseudomonal coverage if Pseudomonas not isolated. Switch from carbapenem to narrower agent if non-ESBL organism. Document rationale."},{drug:"antibiotic-timeout",regimen:"Antibiotic time-out at 48-72h and at day 7",notes:"Structured reassessment: Is there still evidence of infection? Are cultures positive? Can therapy be narrowed? Should therapy be stopped (7-day mark)? Pharmacist-driven antibiotic time-outs reduce unnecessary antibiotic days by 1-3 days per patient."},{drug:"pct-guided",regimen:"Procalcitonin-guided discontinuation (PCT <0.25 or >80% decline)",notes:"PTC trial (Bouadma 2010): PCT-guided strategy reduced antibiotic days by ~3 without affecting mortality. ATS/IDSA 2016 does not strongly endorse PCT for VAP diagnosis but supports its use for guiding DURATION. If PCT is trending down and patient is improving, consider stopping antibiotics even before day 7."}]}],organismSpecific:[],pearls:["The pharmacist's role in VAP prevention is bigger than most realize: sedation management (less sedation = earlier extubation = less VAP), stress ulcer prophylaxis optimization, DVT prophylaxis protocols, antibiotic stewardship with de-escalation, and medication-related bundle compliance audits.","Chlorhexidine oral care controversy: The cardiac surgery data strongly supports CHG oral care. The non-cardiac ICU data is murkier — Deschepper meta-analysis raised mortality concerns. Many institutions now do CHG for cardiac surgery patients only and tooth brushing + oral hygiene for all other ICU patients. Know your institution's protocol and the evidence behind it.","Early mobility reduces ventilator days, which reduces VAP. Advocate for physical therapy consults in the ICU and minimize sedation to enable patient participation. The ABCDEF bundle (A: assess pain, B: both SATs and SBTs, C: choice of analgesia and sedation, D: delirium monitoring, E: early mobility, F: family engagement) is the comprehensive framework.","Antibiotic stewardship in the ICU has the highest potential impact of any setting. ICU patients receive ~10× more antibiotic days than floor patients. Every unnecessary antibiotic day increases C. diff risk by ~2-3% and selects for MDR organisms that cause the next patient's infection.","Subglottic secretion drainage ETTs should be placed at intubation for any patient expected to be ventilated >48-72h. This requires PROSPECTIVE identification — you can't retrofit a standard ETT. Work with respiratory therapy and anesthesia to build this into intubation protocols."]}],drugMonographs:[{id:"pip-tazo",name:"Piperacillin-Tazobactam",brandNames:"Zosyn",drugClass:"Extended-spectrum penicillin + beta-lactamase inhibitor (BLI)",mechanismOfAction:"Piperacillin inhibits PBPs (acylates PBP-3 in gram-negatives, disrupting septum formation → filamentation → cell lysis). Tazobactam irreversibly inhibits class A beta-lactamases (TEM, SHV, CTX-M partially). Bactericidal. Time-dependent killing (T>MIC drives efficacy — the foundation for extended infusion).",spectrum:"Broadest spectrum among penicillins. Gram-negative: E. coli, Klebsiella, Proteus, Enterobacter (but NOT reliable for ESBL or AmpC producers), Pseudomonas aeruginosa, H. influenzae. Gram-positive: Streptococci, MSSA (NOT MRSA), Enterococcus faecalis. Anaerobes: Excellent — Bacteroides fragilis, Peptostreptococcus, Fusobacterium. GAPS: MRSA, ESBL producers (tazobactam has limited ESBL inhibition — MERINO trial), AmpC producers (variable), Stenotrophomonas, Acinetobacter (variable).",dosing:{standard:"3.375g IV q6h (intermittent) or 4.5g IV q8h extended infusion (over 4h)",extended_infusion:"4.5g IV q8h, each dose infused over 4 hours (preferred for HAP/VAP, serious infections — maximizes T>MIC)",continuous_infusion:"13.5-18g IV over 24h (continuous infusion — some ICUs use this for critically ill patients; requires stability data)",febrile_neutropenia:"4.5g IV q6h (higher dose for immunocompromised)",nosocomial_pneumonia:"4.5g IV q6h (or q8h extended infusion)"},renalAdjustment:"CrCl 20-40: 2.25g q6h (intermittent) or 3.375g q8h EI. CrCl <20: 2.25g q8h. Hemodialysis: 2.25g q8h + supplemental dose 0.75g after HD. CRRT: 3.375g q6-8h (facility-dependent). Extended infusion dosing in renal impairment is nuanced — consult pharmacy.",hepaticAdjustment:"No specific adjustment. Monitor LFTs — hepatotoxicity is rare but can occur.",adverseEffects:{common:"Diarrhea (~11%), nausea, headache, insomnia, rash",serious:"C. difficile, hypersensitivity/anaphylaxis (penicillin cross-reactivity), leukopenia/neutropenia (prolonged courses >10-14 days — mechanism: immune-mediated), thrombocytopenia, seizures (rare, high doses in renal impairment), interstitial nephritis",rare:"Drug fever, hemolytic anemia, Stevens-Johnson Syndrome"},drugInteractions:["Vancomycin — Combination increases risk of AKI by 2-3× compared to pip-tazo or vancomycin alone (multiple retrospective studies, Navarro et al., Luther et al.). Mechanism debated (interstitial nephritis, tubular toxicity). If possible, use cefepime instead of pip-tazo when co-administering with vancomycin. If combination unavoidable, monitor renal function closely (BMP q24-48h).","Aminoglycosides — in vitro inactivation if mixed in same IV line (piperacillin physically inactivates aminoglycosides). Administer through separate lines or flush between. This applies to tobramycin and gentamicin more than amikacin.","Methotrexate — reduced renal clearance → increased MTX toxicity. Avoid combination or monitor MTX levels closely.","Probenecid — blocks renal secretion of piperacillin → increased levels.","Warfarin — potential enhanced anticoagulation. Monitor INR.","Vecuronium — prolonged neuromuscular blockade. Monitor in OR/ICU setting."],monitoring:"Renal function (BMP q48-72h, especially if co-administered with vancomycin). CBC with differential weekly (neutropenia signal usually appears day 10-14). LFTs if prolonged course. Clinical response. In extended infusion, ensure adequate stability data — pip-tazo is stable at room temperature for 24h.",pregnancyLactation:"Category B. Generally safe in pregnancy. Used for chorioamnionitis and other obstetric infections. Compatible with breastfeeding — low breast milk excretion.",pharmacistPearls:["THE NEPHROTOXICITY SIGNAL WITH VANCOMYCIN: The pip-tazo + vancomycin combination is associated with significantly higher rates of AKI compared to cefepime + vancomycin. Multiple studies confirm this (RR ~2-3×). If MRSA + gram-negative coverage needed, consider cefepime + vancomycin as a less nephrotoxic combination. This is one of the highest-impact pharmacist interventions in the ICU.","Extended infusion is NOT optional for serious infections: Monte Carlo simulations show that standard intermittent pip-tazo (3.375g q6h over 30 min) achieves only ~60% probability of target attainment for organisms with MIC 16 (the CLSI breakpoint). Extended infusion (4.5g over 4h q8h) achieves >90%. The difference is clinical cure vs. treatment failure. Advocate for institutional extended infusion protocols.","Neutropenia from pip-tazo: Immune-mediated neutropenia typically appears after 10-14 days. Monitor CBC weekly. If ANC drops, stop pip-tazo and switch to another agent. Recovery usually occurs within 3-7 days of discontinuation.","Stability matters for extended infusion: Pip-tazo is stable at room temperature for 24h after reconstitution. For continuous infusion, verify stability data with your pharmacy's IV room. Ethylenediamine (EDTA)-containing formulations may have different stability profiles.","Pip-tazo for Enterococcus: Piperacillin has intrinsic activity against E. faecalis (NOT E. faecium/VRE). This means pip-tazo provides empiric enterococcal coverage — useful in intra-abdominal infections. However, for serious enterococcal infections (endocarditis), use ampicillin, not pip-tazo.","MERINO trial impact: Pip-tazo was inferior to meropenem for ESBL E. coli/Klebsiella bacteremia (30-day mortality 12.3% vs 3.7%). This shifted practice globally — do NOT rely on pip-tazo for known ESBL infections. However, for empiric coverage when ESBL prevalence is <10-15% in your institution, pip-tazo remains reasonable.","Y-site incompatibilities: Pip-tazo is incompatible in the same line as vancomycin, aminoglycosides, and many other drugs. Always use separate lines or flush with NS between infusions. This is a common source of medication errors."]},{id:"cefepime",name:"Cefepime",brandNames:"Maxipime",drugClass:"Fourth-generation cephalosporin",mechanismOfAction:"Inhibits PBPs (high affinity for PBP-3). The zwitterionic structure allows rapid penetration through gram-negative outer membrane porins. Uniquely stable against AmpC beta-lactamases (chromosomal cephalosporinases) — does NOT induce AmpC like ceftriaxone/ceftazidime. Bactericidal, time-dependent killing.",spectrum:"Broadest spectrum of conventional cephalosporins. Gram-negative: E. coli, Klebsiella, Enterobacter/Citrobacter/Serratia (AmpC producers — stable), Pseudomonas aeruginosa, H. influenzae, Proteus, Neisseria. Gram-positive: S. pneumoniae (excellent), MSSA, Streptococci. GAPS: MRSA, ESBL producers (most, though MIC-dependent), anaerobes (poor), Enterococcus, Acinetobacter (variable), Stenotrophomonas.",dosing:{standard:"2g IV q8h (extended infusion preferred for serious infections)",hap_vap:"2g IV q8h (extended infusion over 3-4h)",meningitis:"2g IV q8h (standard infusion — need high peaks for CSF penetration)",febrile_neutropenia:"2g IV q8h (monotherapy per IDSA FN guidelines)",uti:"1-2g IV q8-12h",extended_infusion:"2g IV q8h, each dose infused over 3-4 hours"},renalAdjustment:"CrCl 30-60: 2g q12h. CrCl 11-29: 2g q24h. CrCl ≤10: 1g q24h. Hemodialysis: 1g q24h + supplemental dose after HD. CRRT: 1-2g q8-12h (ICU-specific). CRITICAL: dose adjustments are essential — cefepime accumulates in renal impairment and causes neurotoxicity.",hepaticAdjustment:"No adjustment needed — renally eliminated.",adverseEffects:{common:"Rash (~3%), diarrhea, nausea, headache, injection site reactions",serious:"NEUROTOXICITY (most clinically important — see pearls): confusion, myoclonus, nonconvulsive status epilepticus, encephalopathy, reduced consciousness. Also: C. difficile, hypersensitivity, leukopenia (prolonged courses), positive Coombs test (rarely clinically significant hemolysis)",rare:"Seizures (especially renal impairment), agranulocytosis, toxic epidermal necrolysis"},drugInteractions:["Aminoglycosides — synergistic for gram-negatives (useful for Pseudomonas double-coverage). Administer separately (physical incompatibility in IV line).","Probenecid — decreased renal clearance of cefepime. Monitor for toxicity.","Warfarin — possible enhanced anticoagulation (vitamin K disruption from gut flora). Monitor INR.","Loop diuretics (furosemide) — theoretical increase in nephrotoxicity risk. Clinical significance uncertain but monitor renal function.","Valproic acid — cephalosporins (including cefepime) can reduce valproic acid levels substantially. Monitor VPA levels if co-administered."],monitoring:"Renal function (BMP q48-72h — guides dosing). Neurological status (mental status, myoclonus — cefepime neurotoxicity). CBC weekly for prolonged courses. Consider cefepime trough levels if available (target <20 mg/L to avoid neurotoxicity, though not widely standardized). If patient develops confusion on cefepime, consider EEG (nonconvulsive status epilepticus).",pregnancyLactation:"Category B. Generally considered safe in pregnancy. Low breast milk excretion — compatible with breastfeeding.",pharmacistPearls:["CEFEPIME NEUROTOXICITY: This is underdiagnosed and the pharmacist's responsibility to catch. Risk factors: renal impairment (GFR <50), age >65, high doses without renal adjustment. Presents as altered mental status, myoclonus, tremors, confusion, and nonconvulsive status epilepticus (NCSE). If a patient on cefepime becomes confused — check renal function, check dose appropriateness, and consider EEG. Trough >20 mg/L associated with neurotoxicity. Symptoms are REVERSIBLE upon discontinuation.","AmpC stability is cefepime's superpower: For SPACE organisms (Serratia, Providencia, Acinetobacter, Citrobacter freundii, Enterobacter), cefepime is SUPERIOR to ceftriaxone. Ceftriaxone can induce AmpC beta-lactamase production → clinical failure even if initially susceptible. Cefepime passes through the AmpC without being hydrolyzed. This is why cefepime is preferred for Enterobacter, Citrobacter, and Serratia infections.","Extended infusion matters: Like all beta-lactams, cefepime's efficacy depends on T>MIC. Extended infusion (3-4h) increases the probability of target attainment from ~60-70% to >90% for organisms with MIC at breakpoint. This is especially important for Pseudomonas, which tends to have higher MICs.","Cefepime vs. pip-tazo when combined with vancomycin: Cefepime + vancomycin causes significantly LESS nephrotoxicity than pip-tazo + vancomycin (RR reduction ~50%). When MRSA + gram-negative coverage is needed, cefepime is the preferred beta-lactam backbone. Note: cefepime lacks anaerobic coverage — add metronidazole if anaerobes are a concern.","Febrile neutropenia: Cefepime 2g IV q8h is one of the first-line monotherapy options per IDSA FN guidelines. Its broad gram-negative coverage (including Pseudomonas) and gram-positive coverage (including streptococci) make it well-suited for neutropenic patients.","Cefepime has NO anaerobic coverage. This is a critical gap: if aspiration component is suspected in HAP/VAP, add metronidazole. Or switch to pip-tazo which covers anaerobes inherently. This decision point matters clinically.","Cross-reactivity with penicillin: Cefepime has a different R1 side chain than most penicillins. Cross-reactivity risk with reported penicillin allergy is ~1-2%. Most patients with penicillin allergy can receive cefepime safely. Use clinical judgment and allergy history (urticaria/anaphylaxis vs. remote vague 'allergy')."]},{id:"vancomycin",name:"Vancomycin",brandNames:"Vancocin (oral), various IV manufacturers",drugClass:"Glycopeptide antibiotic",mechanismOfAction:"Binds to D-Ala-D-Ala terminus of peptidoglycan precursors (lipid II), preventing transglycosylation and transpeptidation. Inhibits cell wall synthesis at a step PRIOR to the PBPs (which is why it works against MRSA — MRSA modifies PBPs but vancomycin bypasses PBPs entirely). Bactericidal against most organisms. Slow concentration-dependent killing (AUC/MIC is the primary PK/PD driver).",spectrum:"GRAM-POSITIVE ONLY. Excellent: MRSA, MSSA (inferior to beta-lactams for MSSA — important), coagulase-negative Staphylococci, Streptococci (including S. pneumoniae), Enterococcus faecalis (NOT VRE), Clostridium difficile (oral only — does not reach colon systemically). GAPS: ALL gram-negatives (no activity), VRE (vanB/vanA), some CoNS with vancomycin MIC creep.",dosing:{standard_iv:"15-20 mg/kg IV q8-12h (based on ACTUAL body weight), loading dose 25-30 mg/kg for seriously ill",auc_guided:"Target AUC/MIC 400-600 mg·h/L (2020 ASHP/IDSA/SIDP/PIDS consensus — preferred over trough-based dosing)",loading_dose:"25-30 mg/kg IV × 1 (for serious infections, sepsis, meningitis — maximum ~3g single dose)",oral_cdiff:"125mg PO QID × 10 days (for C. diff — IV vancomycin does NOT reach the colon)",trough_based:"Troughs 15-20 mg/L (LEGACY method — AUC-guided is now preferred due to less nephrotoxicity)",obese:"Use actual body weight for dosing. Obese patients need higher doses. Consider loading dose 25-30 mg/kg."},renalAdjustment:"Vancomycin is primarily renally cleared. Dosing must be individualized. Reduced CrCl → extend interval. CrCl <30: may dose q24-48h. Hemodialysis: dose post-HD (removed ~30% by conventional HD; less by high-flux). CRRT: 15-20 mg/kg q24h (institution-dependent). AUC-guided dosing handles renal adjustment automatically through Bayesian software. Always use clinical pharmacokinetics consultation for complex patients.",hepaticAdjustment:"No adjustment needed — not hepatically metabolized.",adverseEffects:{common:"Red Man Syndrome (histamine-mediated infusion reaction — NOT allergy; prevent by slowing infusion rate to ≥1h, can premedicate with diphenhydramine), nephrotoxicity (AKI — risk increases with troughs >20, concurrent nephrotoxins, prolonged courses)",serious:"Nephrotoxicity (dose-dependent, increased with pip-tazo combination), ototoxicity (usually with concurrent aminoglycosides or very high levels), DRESS syndrome, linear IgA bullous dermatosis, neutropenia/thrombocytopenia (immune-mediated, prolonged courses >14 days)",rare:"Vancomycin-induced linear IgA bullous dermatosis (LABD — drug-induced blistering skin disease), anaphylaxis (true IgE-mediated — distinct from Red Man Syndrome)"},drugInteractions:["Piperacillin-tazobactam — SYNERGISTIC NEPHROTOXICITY. AKI risk 2-3× higher than vancomycin alone or cefepime + vancomycin. If possible, substitute cefepime for pip-tazo when vancomycin is needed.","Aminoglycosides — additive nephrotoxicity AND ototoxicity. Monitor renal function and drug levels closely. Avoid prolonged concurrent use if possible.","Loop diuretics (furosemide) — additive ototoxicity risk, potential volume depletion → increased vancomycin levels.","IV contrast — additive nephrotoxicity. Hydrate adequately and hold vancomycin if possible around contrast administration.","NSAIDs — may decrease renal clearance of vancomycin → increased levels. Monitor."],monitoring:"AUC-guided dosing (preferred): Use Bayesian software (PrecisePK, DoseMeRx, InsightRx). Draw 2 levels per dosing interval (peak 1-2h post-infusion, trough before next dose) for first estimation, then 1 level per interval for subsequent adjustments. Target AUC 400-600. If Bayesian software unavailable: trough-based dosing with target 15-20 mg/L (legacy method). Monitor: BMP q48-72h (SCr, BUN), CBC weekly (neutropenia), signs of ototoxicity (hearing changes), infusion reactions.",pregnancyLactation:"Category C (limited human data). Used in pregnancy when benefits outweigh risks (MRSA infections, penicillin allergy for GBS prophylaxis). Potential fetal auditory nerve damage reported in animals at very high doses. Compatible with breastfeeding — poorly absorbed orally by infant.",pharmacistPearls:["AUC-GUIDED DOSING IS THE NEW STANDARD: The 2020 ASHP/IDSA/SIDP/PIDS consensus guideline recommends AUC/MIC 400-600 over trough-based dosing. AUC-guided dosing achieves EQUIVALENT efficacy with 25-40% LESS nephrotoxicity compared to trough-based targeting. If your institution is still using trough goals of 15-20, champion the transition to AUC-guided protocols. Bayesian software makes this practical.","Red Man Syndrome is NOT an allergy: It's a rate-related histamine release reaction. Slow the infusion (infuse over ≥2 hours), premedicate with diphenhydramine 25-50mg. Do NOT label the patient as 'vancomycin-allergic' for Red Man Syndrome. True vancomycin allergy (anaphylaxis, DRESS, LABD) is different and rare.","Vancomycin is INFERIOR to beta-lactams for MSSA: Multiple studies show higher mortality, higher treatment failure, and slower bactericidal activity when vancomycin is used for MSSA vs. nafcillin/oxacillin/cefazolin. ALWAYS de-escalate from vancomycin to a beta-lactam when MSSA is confirmed. This is a life-saving intervention.","Loading dose: 25-30 mg/kg (actual body weight, cap ~3g) for seriously ill patients achieves therapeutic levels 12-24h faster. Calculate carefully in obese patients. A 120kg patient needs a 3g loading dose — this is a large dose but pharmacokinetically appropriate.","The pip-tazo + vancomycin nephrotoxicity signal is robust: At least 15 studies show ~2-3× increased AKI risk. The ACORN trial (2023) partially addressed this. If you must combine vancomycin with an anti-pseudomonal beta-lactam, cefepime is the safer choice. This is a pharmacist stewardship opportunity that prevents harm.","Oral vancomycin does NOT achieve systemic levels. ONLY use oral vancomycin for C. diff colitis. IV vancomycin does NOT reach the colonic lumen at therapeutic levels. These are completely different clinical uses despite being the same drug.","MIC creep: Some MRSA strains have vancomycin MIC of 2 (susceptible but at the breakpoint). At MIC = 2, achieving AUC/MIC 400 requires very high serum levels, increasing nephrotoxicity risk. If MRSA MIC = 2, consider linezolid or daptomycin (for non-pneumonia indications) instead. For pneumonia specifically, linezolid may be preferred at MIC = 2.","Vancomycin trough timing: Draw the trough within 30 minutes BEFORE the next dose (at true steady-state, typically before the 4th dose). Incorrectly timed troughs lead to dosing errors. For AUC-guided dosing, draw a peak 1-2h after the end of infusion AND a trough — both levels feed into the Bayesian calculation."]},{id:"linezolid",name:"Linezolid",brandNames:"Zyvox",drugClass:"Oxazolidinone (first-in-class)",mechanismOfAction:"Binds to the 23S rRNA of the 50S ribosomal subunit at the peptidyl transferase center, preventing formation of the 70S initiation complex. Blocks the very first step of translation (initiation complex formation) — a unique mechanism shared by no other antibiotic class. Bacteriostatic against staphylococci and enterococci. Bactericidal against streptococci. Importantly: as a ribosomal inhibitor, linezolid SUPPRESSES TOXIN PRODUCTION (PVL, TSST-1, alpha-hemolysin) — relevant for toxin-mediated disease.",spectrum:"GRAM-POSITIVE ONLY. Excellent: MRSA (all strains including hVISA/VISA), VRE (E. faecium and E. faecalis — one of few oral options), MSSA, Streptococci (including DRSP), Nocardia, some Mycobacteria (M. tuberculosis — component of bedaquiline-based MDR-TB regimens). GAPS: ALL gram-negatives, ALL anaerobes (variable, not reliable).",dosing:{standard:"600mg PO/IV BID (100% oral bioavailability — PO = IV)",pneumonia:"600mg PO/IV BID × 7-10 days",ssti:"600mg PO/IV BID × 10-14 days (400mg BID for uncomplicated SSTI)",vre:"600mg PO/IV BID",mdr_tb:"600mg PO daily (reduced dose for prolonged use to minimize toxicity)"},renalAdjustment:"No dose adjustment needed for any level of renal impairment, including dialysis. 30% removed by HD — give dose after HD as a precaution but no dose change. This is a MAJOR advantage over vancomycin in renal impairment.",hepaticAdjustment:"No adjustment for mild-moderate (Child-Pugh A/B). Caution in severe hepatic impairment. Linezolid is a weak reversible MAOI — hepatic dysfunction may increase serotonergic risk.",adverseEffects:{common:"Nausea, diarrhea, headache, insomnia, altered taste (metallic)",serious:"Myelosuppression (thrombocytopenia most common, then anemia, then neutropenia — dose- and duration-dependent, usually >10-14 days), serotonin syndrome (MAOI activity — see interactions), peripheral and optic neuropathy (prolonged use >28 days, may be irreversible), lactic acidosis (mitochondrial toxicity, prolonged use)",rare:"Optic neuritis (vision changes — counsel patients), hypoglycemia (MAOI effect on insulin secretion), convulsions"},drugInteractions:["SSRIs/SNRIs (sertraline, fluoxetine, venlafaxine, duloxetine, etc.) — SEROTONIN SYNDROME RISK. Linezolid is a reversible, non-selective MAO inhibitor. Concurrent use with serotonergic drugs can cause life-threatening serotonin syndrome (hyperthermia, rigidity, myoclonus, autonomic instability). FDA has issued specific warnings. Management: ideally hold SSRI/SNRI, or if linezolid is essential and short-course (<14 days), monitor very closely with daily assessment.","Tyramine-rich foods — MAOI effect means potential hypertensive crisis with high-tyramine foods (aged cheese, cured meats, draft beer, fermented foods). Practical significance is LOW with linezolid (it's a weak, reversible MAOI), but counsel patients to avoid excessive quantities.","Tramadol, meperidine, methadone — serotonergic effects + MAOI → serotonin syndrome risk. Avoid meperidine absolutely. Tramadol and methadone: use with caution.","Sympathomimetics (pseudoephedrine, phenylephrine) — MAOI potentiation → hypertensive crisis. Avoid OTC cold medications containing these during linezolid therapy.","Insulin/oral hypoglycemics — linezolid can cause hypoglycemia via MAOI mechanism. Monitor blood glucose in diabetic patients."],monitoring:"CBC with differential weekly (thrombocytopenia is the red flag — usually appears day 10-14). Visual acuity assessment if course exceeds 28 days (optic neuropathy). Lactate if prolonged course and symptoms of lactic acidosis (nausea, vomiting, fatigue). Blood glucose in diabetics. Serotonin syndrome assessment (mental status, vital signs, neuromuscular exam) especially if on serotonergic drugs.",pregnancyLactation:"Category C. Limited human data. Animal studies showed decreased fetal viability. Use only if benefit clearly outweighs risk. Breastfeeding: enters breast milk — weigh risks and benefits.",pharmacistPearls:["100% ORAL BIOAVAILABILITY: There is ZERO pharmacokinetic reason to use IV linezolid in a patient who can swallow. This is one of the most impactful IV-to-PO conversion opportunities. The cost difference is enormous (~$150-300/day IV vs. ~$60-100/day PO, varies by institution).","Lung penetration superiority: Linezolid achieves ELF (epithelial lining fluid) concentrations that are 5-10× serum levels. Vancomycin ELF levels are only 20-30% of serum. This pharmacokinetic advantage is why many experts prefer linezolid for MRSA pneumonia, and why the ZEPHyR trial showed numerically better outcomes.","Toxin suppression: As a ribosomal inhibitor, linezolid suppresses production of staphylococcal toxins (PVL, TSST-1, alpha-hemolysin). Vancomycin (a cell wall agent) does NOT suppress toxins. For PVL-positive MRSA necrotizing pneumonia or toxic shock syndrome, linezolid (or clindamycin) should be part of the regimen for toxin suppression. This is a pharmacology-based clinical pearl that saves lives.","Thrombocytopenia is the duration-limiting toxicity: Monitor CBC weekly. Platelet count typically drops after day 10-14. If platelets drop below 100K or drop >50% from baseline, consider discontinuation. Recovery usually occurs within 5-7 days. For prolonged courses (TB, bone/joint infections), this becomes a real limiting factor.","The serotonin syndrome risk is REAL but manageable: ~50% of hospitalized patients are on SSRIs/SNRIs. You CANNOT always stop the SSRI. For short courses (<14 days), many experts continue the SSRI with close monitoring (daily assessment for agitation, tremor, diaphoresis, clonus). For longer courses, discuss with psychiatry about temporary SSRI hold or alternative antibiotic. Document your risk-benefit analysis.","No renal dosing needed: In contrast to vancomycin (which requires complex PK monitoring and dose adjustments), linezolid needs no renal adjustment at any GFR. For MRSA infections in patients with fluctuating renal function, AKI, or dialysis, linezolid is often the simpler and safer choice.","Linezolid-resistant organisms are rare but emerging: cfr gene (methylation of 23S rRNA) and optrA gene confer resistance. Prevalence is <1% for MRSA but up to 5-10% for some VRE strains. If linezolid resistance is suspected, daptomycin is the alternative for non-pulmonary infections."]},{id:"meropenem",name:"Meropenem",brandNames:"Merrem",drugClass:"Carbapenem (beta-lactam)",mechanismOfAction:"Binds to PBPs (high affinity for PBP-2 and PBP-3 in gram-negatives). Uniquely stable against class A, C, and D serine beta-lactamases (including ESBLs and AmpC) — but NOT stable against metallo-beta-lactamases (MBLs: NDM, VIM, IMP) or KPC (class A carbapenemase). Bactericidal, time-dependent killing.",spectrum:"The broadest-spectrum conventional antibiotic. Gram-negative: E. coli, Klebsiella, Enterobacter, Serratia, Citrobacter (including ESBL and AmpC producers), Pseudomonas aeruginosa, H. influenzae, Neisseria. Gram-positive: Streptococci, MSSA (less active than cefazolin for MSSA), Listeria (imipenem better). Anaerobes: Excellent — Bacteroides fragilis, Clostridium (except C. diff). GAPS: MRSA, VRE, Stenotrophomonas maltophilia (intrinsically resistant), Mycoplasma/Chlamydophila, CRE (KPC, MBL producers).",dosing:{standard:"1g IV q8h",extended_infusion:"1-2g IV q8h, each dose infused over 3 hours (preferred for serious infections — maximizes T>MIC)",meningitis:"2g IV q8h (standard infusion — need high Cmax for CSF penetration)",hap_vap:"1-2g IV q8h (extended infusion; 2g for Pseudomonas MIC close to breakpoint)",febrile_neutropenia:"1g IV q8h (IDSA-recommended monotherapy option)",esbl_bacteremia:"1g IV q8h (standard of care per MERINO trial)"},renalAdjustment:"CrCl 26-50: 1g q12h. CrCl 10-25: 500mg q12h. CrCl <10: 500mg q24h. Hemodialysis: 500mg q24h + supplemental dose after HD. CRRT: 1g q8-12h (institution-dependent). Extended infusion adjustments may differ — consult pharmacy PK service.",hepaticAdjustment:"No adjustment needed. Renally eliminated.",adverseEffects:{common:"Diarrhea (~5%), nausea/vomiting, headache, rash, injection site reaction",serious:"C. difficile (broad-spectrum → high ecological damage), seizures (LOWER risk than imipenem — meropenem is the preferred carbapenem in CNS infections), hypersensitivity/anaphylaxis, leukopenia/thrombocytopenia (prolonged courses)",rare:"Stevens-Johnson Syndrome, hepatotoxicity, hemolytic anemia"},drugInteractions:["Valproic acid — CRITICAL INTERACTION. Carbapenems (meropenem, imipenem, ertapenem, doripenem) drastically reduce valproic acid levels (by 60-100%) within 24 hours. The interaction is NOT manageable by increasing VPA dose. If a patient on valproic acid needs a carbapenem, switch the antiepileptic (e.g., to levetiracetam) for the duration of carbapenem therapy. NEVER co-administer.","Probenecid — blocks renal secretion → increased meropenem levels. Avoid combination.","Aminoglycosides — physically incompatible in the same IV line. Administer separately."],monitoring:"Renal function (BMP q48-72h — dose adjustments needed in AKI). Seizure activity (lower risk than imipenem, but monitor in CNS disease, renal impairment, or elderly). CBC weekly for prolonged courses. C. diff surveillance (any new diarrhea). LFTs periodically.",pregnancyLactation:"Category B. Limited human data but no evidence of teratogenicity. Used in pregnancy for serious infections when benefits outweigh risks. Enters breast milk in low concentrations — likely compatible with breastfeeding.",pharmacistPearls:["THE VALPROIC ACID INTERACTION: This is a HARD STOP interaction. All carbapenems reduce VPA levels by 60-100% within 24 hours, and increasing VPA dose does NOT compensate. The mechanism is multifactorial (increased glucuronidation, impaired enterohepatic recirculation). Solution: switch VPA to levetiracetam (or another non-interacting AED) before starting the carbapenem. Switch back after the carbapenem course ends. This is a pharmacist-driven intervention that prevents breakthrough seizures.","Extended infusion is standard of care for serious infections: Meropenem's PK/PD target is T>MIC >40-50%. Extended infusion (3h) dramatically improves the probability of target attainment, especially for Pseudomonas (MIC breakpoint = 2). For MIC = 2: standard bolus achieves ~60% PTA; extended infusion achieves >95%. This difference can be the difference between clinical cure and failure.","Meropenem vs. Imipenem: Meropenem has LOWER seizure risk (does NOT antagonize GABA receptors like imipenem). Preferred in CNS infections (meningitis, brain abscess), renal impairment, and elderly patients. Imipenem has slightly better gram-positive coverage (Enterococcus faecalis).","CARBAPENEM STEWARDSHIP: Meropenem is the broadest-spectrum standard antibiotic. Every unnecessary day of meropenem selects for CRE — the most feared resistance mechanism. De-escalate AGGRESSIVELY: if cultures show susceptibility to ceftriaxone, pip-tazo, or other narrower agents, SWITCH. If ESBL but non-Pseudomonal, consider ertapenem (narrowest carbapenem). Document your de-escalation rationale.","ESBL gold standard: MERINO trial established meropenem as the definitive treatment for ESBL E. coli/Klebsiella bacteremia. Pip-tazo failed non-inferiority. For serious ESBL infections (bacteremia, HAP/VAP), carbapenems remain the standard of care. Don't let stewardship pressure override this evidence when the patient needs a carbapenem.","Meropenem has poor CSF penetration with inflamed meninges (~10-20% of serum). Despite this, it achieves concentrations above the MIC for most CNS pathogens. Dose at 2g q8h for meningitis — standard infusion (need high peaks for CSF penetration, unlike the extended infusion approach for non-CNS infections)."]}]},d={id:"ssti",name:"Skin & Soft Tissue Infections",icon:"🩹",category:"Infectious Disease",overview:{definition:"Skin and soft tissue infections (SSTIs) encompass a spectrum from superficial impetigo to life-threatening necrotizing fasciitis. The 2014 IDSA SSTI guidelines classify infections by the critical decision point: PURULENT vs NON-PURULENT. This distinction drives empiric therapy — purulent infections require Staphylococcal coverage (including MRSA), while non-purulent infections are primarily Streptococcal and may not need MRSA coverage unless risk factors present.",epidemiology:"SSTIs account for ~14 million outpatient visits and ~870,000 hospitalizations annually in the US. Cellulitis and abscess are the most common subtypes. MRSA prevalence in purulent SSTIs varies by region (30-75% in many US EDs). Community-associated MRSA (CA-MRSA, predominantly USA300/ST8) has been the dominant purulent SSTI pathogen since the early 2000s. Necrotizing fasciitis is rare (~1,000 cases/year in the US) but carries 20-40% mortality.",keyGuidelines:[{name:"IDSA 2014 SSTI Guidelines (Practice Guidelines for the Diagnosis and Management of SSTIs)",detail:"Current definitive US guideline. Key framework: purulent vs non-purulent classification. Emphasizes I&D as primary therapy for purulent SSTIs, oral antibiotics for mild-moderate, IV for severe. Defines mild (no systemic signs), moderate (systemic signs), and severe (failed oral therapy, immunocompromised, signs of deep infection/necrotizing). Recommends AGAINST antibiotics for uncomplicated abscesses after adequate I&D in mild disease."},{name:"IDSA 2023 Diabetic Foot Infection Guidelines (Update)",detail:"Updated DFI guidance emphasizing wound classification (IDSA/IWGDF severity), probe-to-bone test, MRI for osteomyelitis, and culture-directed therapy. Shorter antibiotic courses endorsed (1-2 weeks soft tissue, 4-6 weeks osteomyelitis). Stresses multidisciplinary approach: ID, surgery, vascular, podiatry, wound care."},{name:"IDSA 2011 MRSA Guidelines",detail:"Comprehensive MRSA management including SSTIs. Recommends I&D alone for uncomplicated abscesses; TMP-SMX or doxycycline for outpatient MRSA SSTI; vancomycin, daptomycin, linezolid, or clindamycin for severe MRSA SSTI. Still widely referenced despite age."},{name:"Surviving Sepsis Campaign 2021",detail:"Relevant for necrotizing fasciitis with sepsis — 1-hour antibiotic bundle, aggressive resuscitation, emergent surgical source control."}],landmarkTrials:[{name:"Talan et al. (2016, NEJM) — TMP-SMX for Abscess After I&D",detail:"Landmark RCT: TMP-SMX added to I&D for uncomplicated abscess improved cure rates (80.5% vs 73.6%) and reduced new abscesses and skin infections at 1 month. Changed practice — previously many guidelines said I&D alone was sufficient for uncomplicated abscess. Supports adding oral antibiotics after I&D for most purulent SSTIs."},{name:"ESTABLISH-1 & ESTABLISH-2 (Moran et al., 2017, NEJM)",detail:"Clindamycin vs TMP-SMX for uncomplicated SSTI (abscess + cellulitis). Both were equivalent for cure rates (~83%). TMP-SMX had fewer adverse effects than clindamycin. Established TMP-SMX and clindamycin as equivalent first-line oral MRSA options."},{name:"Daum et al. (2017, NEJM) — Clindamycin vs TMP-SMX in Children",detail:"Pediatric SSTI trial. Clindamycin and TMP-SMX were equivalent in children with uncomplicated SSTIs. TMP-SMX preferred by many due to fewer GI side effects and lower C. diff risk."},{name:"SOLO I & II (Dalbavancin, 2014-2015, NEJM)",detail:"Dalbavancin (long-acting lipoglycopeptide) single IV dose or 2-dose regimen was non-inferior to vancomycin followed by linezolid for ABSSSI. Demonstrated feasibility of single-dose SSTI treatment — relevant for patients with adherence challenges, IVDU, or OPAT candidates."},{name:"Eron Classification (2003)",detail:"Foundational severity classification for SSTIs: Class 1 (afebrile, healthy), Class 2 (febrile OR comorbid), Class 3 (toxic/septic OR limb-threatening), Class 4 (necrotizing/sepsis). Guides disposition: Class 1 = outpatient, Class 2 = outpatient or observation, Class 3 = inpatient IV, Class 4 = ICU + surgery."},{name:"Wong et al. LRINEC Score (2004)",detail:"Laboratory Risk Indicator for Necrotizing Fasciitis. Scoring system (WBC, hemoglobin, sodium, glucose, creatinine, CRP) to identify necrotizing fasciitis. Score >=6 has PPV of 92%. Useful screening tool but should NOT delay surgical exploration if clinical suspicion is high — sensitivity is imperfect and false negatives kill."}],riskFactors:"Skin breaks (trauma, surgical wounds, injection drug use, dermatitis, tinea pedis), obesity, diabetes mellitus, peripheral vascular disease, lymphedema, chronic venous insufficiency, immunosuppression (HIV, transplant, steroids), prior SSTI/cellulitis (recurrence rate 20-40%), prior MRSA colonization/infection, household MRSA contacts, crowded living conditions (shelters, prisons), recent hospitalization, chronic wounds."},subcategories:[{id:"nonpurulent-ssti",name:"Non-Purulent SSTI (Cellulitis & Erysipelas)",definition:"Non-purulent SSTIs lack a drainable focus of pus. Includes cellulitis (deeper dermis/subcutaneous tissue) and erysipelas (superficial dermis/lymphatics with sharply demarcated raised borders). Primarily caused by beta-hemolytic Streptococci (Group A Strep predominates). S. aureus is a less common cause in TRUE non-purulent cellulitis without wound/trauma entry point. IDSA 2014: empiric therapy should target Streptococci; MRSA coverage is NOT routinely needed unless specific risk factors present.",clinicalPresentation:"Erysipelas: well-demarcated, raised, erythematous, painful plaque, often on face or lower extremities. Peau d'orange texture. Rapid onset with fever/chills. Cellulitis: poorly demarcated, spreading erythema, warmth, tenderness, edema. Lower extremities most common. May have lymphangitis (red streaking). Fever present in moderate-severe. CRITICAL MIMICS to rule out: DVT (unilateral leg swelling), stasis dermatitis (bilateral, chronic, pruritic), contact dermatitis, gout/septic arthritis (periarticular), necrotizing fasciitis (pain out of proportion, dusky skin, crepitus, rapid progression).",diagnostics:"CLINICAL DIAGNOSIS — no specific labs required for mild cellulitis. Blood cultures: positive in only 2-5% of cellulitis cases; obtain only if severe/septic, immunocompromised, or special exposures (water, animal bite). Wound cultures: N/A for non-purulent cellulitis (no wound to culture). Skin biopsy/aspirate: very low yield (<30%), NOT recommended routinely. Mark borders with pen to track progression. Imaging: NOT routine; ultrasound if concern for occult abscess; CT/MRI if concern for necrotizing fasciitis or osteomyelitis.",durationGuidance:{standard:"5 days (extensible to 14 if slow response)",stewardshipNote:"IDSA 2014: Re-evaluate at 5 days. Most cellulitis responds within 3 days."},empiricTherapy:[{line:"First-Line — Mild (Outpatient, Oral)",options:[{drug:"cephalexin-ssti",regimen:"Cephalexin 500mg PO QID (or 1000mg PO BID)",notes:"IDSA 2014 first-line for non-purulent cellulitis. Targets Streptococci and MSSA. NO MRSA coverage. QID dosing is traditional but BID dosing of 1g achieves adequate T>MIC and improves adherence — many experts now prefer this. Duration: 5 days (IDSA), extend to 7-10 if slow response.",evidence:"A-I",evidenceSource:"IDSA 2014"},{drug:"dicloxacillin-ssti",regimen:"Dicloxacillin 500mg PO QID",notes:"Alternative first-line. Anti-staphylococcal penicillin. Narrower spectrum than cephalexin. Must be taken on empty stomach (1h before or 2h after meals). Poor adherence due to QID + empty stomach. Cephalexin preferred by most clinicians.",evidence:"B-II",evidenceSource:"IDSA 2014"},{drug:"clindamycin-ssti-oral",regimen:"Clindamycin 300-450mg PO TID",notes:"Alternative if penicillin allergy. Covers Streptococci, MSSA, most CA-MRSA (check local susceptibility — resistance rising, now 15-25% in some areas). Also covers anaerobes. C. diff risk higher than beta-lactams. Use when MRSA coverage desired in outpatient non-purulent SSTI with risk factors.",evidence:"B-II",evidenceSource:"IDSA 2014"}]},{line:"First-Line — Moderate/Severe (Inpatient, IV)",options:[{drug:"cefazolin",regimen:"Cefazolin 2g IV q8h",notes:"IDSA 2014 first-line IV for non-purulent cellulitis requiring hospitalization. MSSA + Streptococcal coverage. The simplest, narrowest IV option. No MRSA coverage — add vancomycin only if MRSA risk factors present. Convert to oral cephalexin when improving."},{drug:"nafcillin-ssti",regimen:"Nafcillin 2g IV q4h (or Oxacillin 2g IV q4h)",notes:"Anti-staphylococcal penicillins. Narrowest anti-MSSA agents. Superior to vancomycin for MSSA (multiple studies show faster bactericidal activity). Disadvantages: q4h dosing, phlebitis, hepatotoxicity (oxacillin > nafcillin), interstitial nephritis. Cefazolin is generally preferred due to ease of dosing."}]},{line:"ADD MRSA Coverage If Risk Factors Present",options:[{drug:"vancomycin-ssti",regimen:"Vancomycin IV (AUC/MIC 400-600) — add to cefazolin",notes:"Add MRSA coverage for: prior MRSA infection/colonization, IVDU, failed initial beta-lactam therapy, penetrating trauma, concurrent purulent wound. Continue cefazolin for Streptococcal coverage — vancomycin alone has suboptimal Streptococcal killing kinetics. De-escalate when cultures return."},{drug:"linezolid-ssti",regimen:"Linezolid 600mg IV/PO BID",notes:"Alternative to vancomycin for MRSA cellulitis. 100% oral bioavailability. FDA-approved for complicated SSTIs. Advantage: PO = IV, no renal dosing, no levels to monitor. Disadvantage: cost, myelosuppression risk if >14 days, serotonin syndrome risk."}]},{line:"Duration",options:[{drug:"duration-cellulitis",regimen:"5 days (IDSA 2014), extend to 7-10 days if slow clinical response",notes:"IDSA 2014 recommends 5 days for uncomplicated cellulitis, with extension if not improved. Multiple RCTs support 5-day courses as non-inferior to 10 days. Longer courses (10-14 days) may be needed for: immunosuppressed patients, slow-responding infections, cellulitis with associated bacteremia. Reassess at 48-72h — failure to improve should prompt imaging (abscess? necrotizing?) and broadening."}]}],organismSpecific:[{organism:"Group A Streptococcus (S. pyogenes)",preferred:"Penicillin VK, amoxicillin, cephalexin, cefazolin",alternative:"Clindamycin (if penicillin-allergic), azithromycin",notes:"GAS is the PREDOMINANT cause of true non-purulent cellulitis. Universally penicillin-susceptible — no resistance. Penicillin VK 500mg QID is technically the most targeted oral agent but cephalexin is used more often due to broader coverage of potential co-pathogens. For severe/invasive GAS (necrotizing fasciitis, toxic shock): add clindamycin for toxin suppression."},{organism:"S. aureus (MSSA)",preferred:"Cefazolin IV, cephalexin PO, nafcillin/oxacillin IV",alternative:"Clindamycin, dicloxacillin",notes:"MSSA causes cellulitis particularly when there's a wound, surgical site, or device entry point. Cefazolin is SUPERIOR to vancomycin for MSSA — this has been demonstrated repeatedly. Always de-escalate from vancomycin to cefazolin/nafcillin when MSSA confirmed."},{organism:"MRSA (if risk factors present)",preferred:"TMP-SMX PO, doxycycline PO (outpatient); vancomycin IV, daptomycin IV, linezolid IV/PO (inpatient)",alternative:"Clindamycin PO/IV (check susceptibility — D-test for inducible resistance)",notes:"MRSA is NOT the primary cause of non-purulent cellulitis in most patients. However, always consider MRSA if: prior MRSA, IVDU, failed beta-lactam, purulent component develops. CA-MRSA (USA300) remains susceptible to TMP-SMX (>95%) and doxycycline (>95%) in most regions."}],pearls:["THE PURULENT vs NON-PURULENT DISTINCTION IS THE SINGLE MOST IMPORTANT DECISION IN SSTI: Non-purulent = Streptococcal = beta-lactam. Purulent = Staphylococcal = consider MRSA. Reflexive MRSA coverage for all cellulitis is inappropriate and drives resistance.","Bilateral cellulitis is almost NEVER bilateral cellulitis. If both legs are red, think stasis dermatitis, contact dermatitis, or heart failure — not infection. True bilateral cellulitis is exceedingly rare and should prompt investigation for alternative diagnoses.","Mark the borders with a pen and timestamp. This is the most reliable way to track response to therapy. Cellulitis frequently looks WORSE in the first 24-48 hours due to ongoing inflammation even with effective antibiotics. Don't panic-switch antibiotics at 24h — reassess at 48-72h.","Predisposing factors drive recurrence: Tinea pedis is the #1 modifiable risk factor for lower extremity cellulitis. Treating the tinea (topical antifungal) and maintaining skin hydration reduces cellulitis recurrence by 50%+. Lymphedema management (compression, elevation) is the other major intervention.","Blood cultures in cellulitis are almost always negative (<5% positive). IDSA says obtain only if: severe sepsis, immunocompromised, special exposures (water/animal bite), or failed outpatient therapy. Don't order blood cultures reflexively on every cellulitis admission — it wastes resources.","Cephalexin BID vs QID: Pharmacokinetically, cephalexin 1000mg BID achieves comparable T>MIC to 500mg QID for susceptible Streptococci and MSSA (MIC <=2). BID dosing dramatically improves adherence. Many ID pharmacists now recommend the BID regimen as default.","Outpatient parenteral antibiotic therapy (OPAT) with cefazolin: Cefazolin has the longest half-life of first-gen cephalosporins (~2h). Can be given as 2g IV q8h in a clinic setting or via home infusion. For cellulitis failing oral therapy but not requiring admission, OPAT cefazolin is an excellent step-up before hospitalization.","Elevation is therapeutic: Lower extremity cellulitis improves significantly with leg elevation above the heart. This reduces edema, improves lymphatic drainage, and accelerates resolution. It is an actual therapeutic intervention, not just comfort care."]},{id:"purulent-ssti",name:"Purulent SSTI (Abscess, Furuncle, Carbuncle)",definition:"Purulent SSTIs are characterized by a drainable collection of pus. Includes cutaneous abscesses, furuncles (infected hair follicles), and carbuncles (coalescent furuncles). S. aureus is the dominant pathogen — in the US, CA-MRSA (USA300) causes 50-75% of purulent SSTIs in most communities. IDSA 2014: Incision and drainage (I&D) is the PRIMARY therapy. Antibiotics are ADJUNCTIVE, not a substitute for drainage.",clinicalPresentation:"Fluctuant, tender, erythematous nodule with overlying warmth. May have a visible pustule or point of drainage. Surrounding cellulitis common. Furuncles center on hair follicles. Carbuncles are larger, deeper, with multiple drainage tracts — more common in diabetics and immunocompromised. Abscess may be deeper and require imaging (ultrasound) to confirm collection. Fever and systemic symptoms suggest moderate-severe disease.",diagnostics:"Ultrasound: Point-of-care ultrasound (POCUS) is the best tool to confirm a drainable abscess vs. cellulitis without collection. Sensitivity 96%, specificity 83%. Should be used when exam is equivocal. Wound culture: Obtain at time of I&D — guides targeted therapy and tracks local resistance. Blood cultures: only if systemic signs (fever, tachycardia, hypotension). Gram stain of purulent material can provide rapid pathogen identification.",durationGuidance:{standard:"5 days after I&D",stewardshipNote:"IDSA 2014: TMP-SMX × 5–7 days reduces treatment failure vs placebo post I&D (NEJM 2017 IDSA-funded trial)."},empiricTherapy:[{line:"First-Line — Mild (Outpatient, After I&D)",options:[{drug:"tmp-smx-ssti",regimen:"TMP-SMX DS 1-2 tablets PO BID",notes:"IDSA 2014 + Talan 2016 trial first-line after I&D. Excellent CA-MRSA activity (>95% susceptibility). Talan trial showed adding TMP-SMX to I&D improved cure rates from 73.6% to 80.5%. DS = 160/800mg. Double-strength dosing (2 DS BID) used by some for larger abscesses. Duration: 5-7 days.",evidence:"A-I",evidenceSource:"IDSA 2014"},{drug:"doxycycline-ssti",regimen:"Doxycycline 100mg PO BID",notes:"ESTABLISH trials: equivalent to clindamycin for uncomplicated SSTI. Excellent CA-MRSA activity (>95%). Advantages: BID dosing, low C. diff risk, no renal dosing. Disadvantages: photosensitivity, esophageal ulceration (take with full glass of water, upright), limited Streptococcal coverage (a gap if surrounding cellulitis is significant). Duration: 5-7 days.",evidence:"A-I",evidenceSource:"IDSA 2014"},{drug:"clindamycin-ssti",regimen:"Clindamycin 300-450mg PO TID",notes:"ESTABLISH trials: equivalent to TMP-SMX. Covers MRSA + Streptococci + anaerobes. KEY LIMITATION: rising clindamycin resistance (15-25% in some areas). MUST check D-test for inducible clindamycin resistance (erythromycin-resistant, clindamycin-susceptible isolates need D-test). If D-test positive, clindamycin will fail. C. diff risk higher than TMP-SMX or doxycycline.",evidence:"A-I",evidenceSource:"IDSA 2014"}]},{line:"First-Line — Moderate/Severe (Inpatient, IV)",options:[{drug:"vancomycin-purulent",regimen:"Vancomycin IV (AUC/MIC 400-600)",notes:"IDSA 2014 first-line IV for severe purulent SSTI (failed oral therapy, systemic toxicity, immunocompromised). Provides definitive MRSA coverage. AUC-guided dosing standard (2020 consensus). Convert to oral TMP-SMX or doxycycline when improving."},{drug:"daptomycin",regimen:"Daptomycin 4-6 mg/kg IV once daily",notes:"FDA-approved for complicated SSTIs at 4mg/kg. Many experts dose 6mg/kg for serious infections. Rapidly bactericidal against MRSA. MUST NOT use for pneumonia (inactivated by pulmonary surfactant). Advantages: once-daily dosing, no nephrotoxicity at standard doses. Monitor CPK weekly."},{drug:"linezolid-purulent",regimen:"Linezolid 600mg IV/PO BID",notes:"FDA-approved for complicated SSTIs including MRSA. 100% PO bioavailability — can step down to oral immediately. Suppresses toxin production (PVL). Monitor CBC weekly for thrombocytopenia if >7 days."},{drug:"cefazolin-purulent",regimen:"Cefazolin 2g IV q8h (if MSSA confirmed or low MRSA suspicion)",notes:"Use when cultures confirm MSSA. SUPERIOR to vancomycin for MSSA. De-escalation target: once MSSA confirmed, switch from vancomycin to cefazolin. This is one of the highest-impact stewardship interventions in SSTI."}]},{line:"I&D Without Antibiotics — When to Consider",options:[{drug:"id-alone",regimen:"I&D alone for small (<2cm), uncomplicated abscess in healthy patient",notes:"IDSA 2014 suggests I&D alone MAY be sufficient for small, uncomplicated abscesses in immunocompetent patients. HOWEVER: Talan 2016 trial showed antibiotics after I&D improved outcomes even for uncomplicated abscesses. Current practice has shifted toward adding a 5-day course of TMP-SMX or doxycycline after I&D for most abscesses. I&D alone may still be reasonable for very small (<2cm) abscesses that are completely drained with no surrounding cellulitis."}]},{line:"Duration",options:[{drug:"duration-purulent",regimen:"5-7 days (outpatient); 7-14 days (severe/complicated)",notes:"Mild-moderate after I&D: 5-7 days. Severe: 7-14 days depending on response. Bacteremia from SSTI source: 14 days minimum for S. aureus (longer if endocarditis — see below). KEY: S. aureus bacteremia ALWAYS warrants echocardiography and ID consultation to rule out endocarditis — even if the apparent source is 'just' a skin infection."}]}],organismSpecific:[{organism:"CA-MRSA (USA300/ST8)",preferred:"TMP-SMX PO, doxycycline PO (outpatient); vancomycin IV, daptomycin IV, linezolid (inpatient)",alternative:"Clindamycin (if susceptible and D-test negative)",notes:"USA300 is the dominant CA-MRSA clone in the US. Characteristically: PVL-positive (Panton-Valentine Leukocidin — cytotoxin that causes tissue necrosis and abscess formation), resistant to beta-lactams and erythromycin, typically susceptible to TMP-SMX, doxycycline, clindamycin (variable), and vancomycin. PVL positivity drives the purulent, necrotic presentation. For severe PVL-positive infections, add a toxin-suppressing agent (clindamycin or linezolid) to the cell-wall-active drug."},{organism:"MSSA",preferred:"Cefazolin IV, cephalexin PO, nafcillin/oxacillin IV",alternative:"Clindamycin, dicloxacillin",notes:"MSSA still causes 25-50% of purulent SSTIs depending on local epidemiology. Always de-escalate from vancomycin to beta-lactam when MSSA confirmed — mortality benefit in bacteremia and faster clinical response. Do NOT use vancomycin for definitive MSSA treatment."},{organism:"Streptococcus pyogenes (mixed with Staph)",preferred:"Amoxicillin-clavulanate (covers both), cephalexin (if MSSA)",alternative:"Clindamycin (covers both Strep + Staph including most MRSA)",notes:"Mixed Streptococcal-Staphylococcal infections occur when purulent SSTIs have significant surrounding cellulitis. TMP-SMX has limited Streptococcal activity — if significant cellulitis surrounds the abscess, consider clindamycin (covers both) or add cephalexin/amoxicillin to TMP-SMX for dual coverage."}],pearls:["I&D IS THE TREATMENT — antibiotics are adjunctive. No antibiotic can sterilize an undrained abscess. If a patient with an abscess is not improving on antibiotics, the answer is almost always DRAINAGE, not broader antibiotics. Ensure adequate I&D was performed before escalating therapy.","TMP-SMX vs doxycycline: Both are excellent oral MRSA agents. TMP-SMX advantages: better data (Talan trial), covers UTIs simultaneously, pediatric-friendly. Doxycycline advantages: BID dosing, broader coverage (Rickettsia, atypicals), lower C. diff risk. TMP-SMX disadvantage: limited Streptococcal coverage. Doxycycline disadvantage: limited Streptococcal coverage. For purulent SSTIs with significant surrounding cellulitis, either agent may leave a Streptococcal gap.","The Streptococcal gap of TMP-SMX and doxycycline: Neither drug reliably covers Group A Strep. For a pure abscess, this doesn't matter (Staph is the target). But for abscess with extensive surrounding cellulitis, consider: clindamycin (covers both), or TMP-SMX + cephalexin, or doxycycline + amoxicillin. This combination addresses both the Staphylococcal abscess and the Streptococcal cellulitis.","S. aureus bacteremia from SSTI: ALWAYS get an echocardiogram. ALWAYS consult ID. Even 'transient' S. aureus bacteremia has a 10-25% rate of occult endocarditis. This is not cellulitis-level care anymore — it's a completely different management pathway requiring 2-6 weeks of IV antibiotics. Missing endocarditis is catastrophic.","Recurrent abscesses: If a patient has recurrent MRSA SSTIs, address decolonization: mupirocin 2% nasal ointment BID × 5 days + chlorhexidine body washes × 5 days, repeated monthly × 3 months. Decolonize household contacts simultaneously. Bleach baths (1/4 cup bleach per bathtub) 2× weekly can reduce recurrence. Environmental cleaning of high-touch surfaces.","D-test for clindamycin: If the isolate is erythromycin-resistant and clindamycin-susceptible, the lab MUST perform a D-test to check for inducible clindamycin resistance (erm gene). If D-test positive: clindamycin will fail clinically despite in vitro susceptibility. If D-test negative: clindamycin is safe to use. Check your lab's reporting — some automatically report D-test results, others require you to request it.","Point-of-care ultrasound changes management: Studies show POCUS changes the diagnosis in 50% of cases where the clinician is unsure if there's a drainable collection. A patient labeled as 'cellulitis' may actually have an abscess that needs I&D. Advocate for ultrasound when the exam is equivocal."]},{id:"necrotizing-ssti",name:"Necrotizing Soft Tissue Infections (NSTI / Necrotizing Fasciitis)",definition:"Life-threatening deep soft tissue infection causing rapidly progressive necrosis of fascia, subcutaneous tissue, and sometimes muscle (myonecrosis). Two major types: Type I (polymicrobial — mixed aerobes + anaerobes, often in diabetics, post-surgical, or perineal/Fournier's) and Type II (monomicrobial — Group A Strep or occasionally MRSA/Clostridium). Mortality: 20-40% overall, higher with delayed surgical intervention. TIME TO SURGERY IS THE SINGLE MOST IMPORTANT PROGNOSTIC FACTOR.",clinicalPresentation:"PAIN OUT OF PROPORTION to exam findings is the hallmark — often the earliest and most reliable sign. Skin changes progress rapidly: erythema → dusky/violaceous → hemorrhagic bullae → frank necrosis (black eschar). Crepitus (gas in tissues) is classic but LATE and present in only ~18% of cases. Wooden-hard induration of subcutaneous tissue. Rapidly expanding area. Hemodynamic instability and sepsis. Fournier's gangrene: necrotizing infection of the perineum/genitalia — surgical emergency. CLINICAL SUSPICION ALONE warrants surgical exploration — do NOT wait for imaging or labs to confirm.",diagnostics:"SURGICAL EXPLORATION IS DIAGNOSTIC AND THERAPEUTIC — do NOT delay for imaging. CT with contrast: most sensitive imaging modality (gas tracking along fascial planes, fascial thickening/enhancement, fluid collections). MRI: highest sensitivity but takes too long in emergencies. LRINEC Score (WBC, Hgb, Na, glucose, Cr, CRP): score >=6 suggests necrotizing infection, but sensitivity is only ~60-80% — a negative score does NOT rule it out. Blood cultures, wound cultures, surgical tissue cultures (Gram stain + aerobic + anaerobic). Lactate (prognostic marker). CBC, BMP, CRP, procalcitonin for trending.",durationGuidance:{standard:"Until debridement complete + 48–72h afebrile + hemodynamically stable",severe:"Extended as needed for source control"},empiricTherapy:[{line:"First-Line — Empiric Broad-Spectrum (Start Immediately, Before Surgery)",options:[{drug:"nsti-backbone",regimen:"Vancomycin IV (AUC 400-600) + Piperacillin-tazobactam 4.5g IV q6h (extended infusion) + Clindamycin 900mg IV q8h",notes:"IDSA 2014 recommended triple therapy: (1) MRSA coverage (vancomycin), (2) Broad gram-negative + anaerobic coverage (pip-tazo), (3) Toxin suppression (clindamycin). Clindamycin is added specifically for its ribosomal-mediated suppression of Streptococcal exotoxins (SPE-A, SPE-B), Staphylococcal PVL, and Clostridial alpha-toxin. This toxin suppression reduces inflammatory cascade and improves survival. Do NOT omit clindamycin.",evidence:"A-I",evidenceSource:"IDSA 2014"},{drug:"nsti-alt",regimen:"Vancomycin + Meropenem 1g IV q8h + Clindamycin 900mg IV q8h",notes:"Alternative backbone using meropenem instead of pip-tazo. Preferred if: ESBL risk, prior resistant organisms, or concern for polymicrobial infection with resistant gram-negatives. Same triple-therapy rationale: MRSA + broad gram-negative/anaerobic + toxin suppression.",evidence:"B-II",evidenceSource:"IDSA 2014"}]},{line:"Adjunctive — Toxin Suppression (Critical Component)",options:[{drug:"clindamycin-nsti",regimen:"Clindamycin 900mg IV q8h",notes:"NON-NEGOTIABLE component of NSTI therapy. Mechanism: inhibits ribosomal protein synthesis, thereby suppressing production of bacterial exotoxins (superantigens, cytolysins, tissue-destroying enzymes). Beta-lactams and vancomycin (cell wall agents) do NOT suppress toxin production — in fact, cell lysis from beta-lactams can RELEASE preformed toxins. Clindamycin addresses this by shutting down the toxin factory. Eagle effect: at high bacterial density (as in NSTI), beta-lactam killing slows because bacteria are in stationary phase with reduced PBP expression. Clindamycin is NOT affected by inoculum size. Continue until clinical improvement or de-escalation per ID."}]},{line:"Duration",options:[{drug:"duration-nsti",regimen:"Continue until surgical debridement complete + clinical improvement, typically 2-4 weeks total",notes:"No fixed duration — guided by surgical findings and clinical response. Multiple debridements are common (every 24-48h until no further necrotic tissue). Antibiotics continue through the surgical phase. De-escalate based on cultures once pathogen identified. Transition to targeted therapy: Type I (polymicrobial) — may narrow to amp-sulbactam or pip-tazo; Type II (GAS) — penicillin G + clindamycin; Type II (MRSA) — vancomycin + clindamycin."}]}],organismSpecific:[{organism:"Group A Streptococcus (Type II NSTI)",preferred:"Penicillin G 4MU IV q4h + Clindamycin 900mg IV q8h",alternative:"Ceftriaxone + Clindamycin (if penicillin allergy unclear)",notes:"GAS necrotizing fasciitis carries 30% mortality even with optimal care. The penicillin + clindamycin combination is the gold standard: penicillin for bactericidal activity, clindamycin for toxin suppression. Streptococcal toxic shock syndrome (STSS) occurs in ~50% of GAS NSTI. IVIG (intravenous immunoglobulin) has been used adjunctively for STSS — mechanism: neutralizes superantigens. Evidence is mixed but many experts recommend it for refractory STSS."},{organism:"Polymicrobial / Type I (mixed aerobes + anaerobes)",preferred:"Pip-tazo or meropenem + vancomycin + clindamycin",alternative:"Amp-sulbactam + vancomycin + metronidazole",notes:"Type I is more common than Type II. Typical pathogens: mixed Enterobacterales, anaerobes (Bacteroides, Peptostreptococcus), Streptococci, Staphylococci. Risk factors: diabetes, post-surgical, perineal location (Fournier's), peripheral vascular disease. Polymicrobial coverage is essential until cultures clarify."},{organism:"Clostridium perfringens (gas gangrene/myonecrosis)",preferred:"Penicillin G + Clindamycin (for alpha-toxin suppression)",alternative:"Meropenem + Clindamycin",notes:"Clostridial myonecrosis is the most rapidly fatal soft tissue infection. Produces alpha-toxin (phospholipase C) that causes massive tissue destruction and hemolysis. Gas in tissues is characteristic. Penicillin for bactericidal activity, clindamycin for toxin suppression (same rationale as for Strep). EMERGENT wide surgical debridement/amputation may be required. Hyperbaric oxygen is controversial but used at some centers."},{organism:"Vibrio vulnificus (saltwater exposure NSTI)",preferred:"Doxycycline 100mg IV BID + Ceftriaxone 2g IV daily (or cefotaxime)",alternative:"FQ + doxycycline",notes:"Occurs after saltwater/shellfish exposure, particularly in patients with liver disease, hemochromatosis, or immunosuppression. Fulminant course — can progress from cellulitis to necrotizing infection within hours. Characteristic hemorrhagic bullae. Doxycycline + 3rd-gen cephalosporin is the recommended combination. Mortality 50%+ in necrotizing presentations. Maintain high suspicion in any patient with rapidly progressive SSTI and water exposure history."}],pearls:["TIME TO SURGERY IS EVERYTHING: Every hour of delay in surgical debridement increases mortality. A meta-analysis showed that patients taken to the OR within 12 hours of presentation had significantly lower mortality than those delayed >24 hours. If you suspect NSTI, call surgery IMMEDIATELY. Do not wait for CT confirmation, culture results, or antibiotic effect.","Pain out of proportion is the most sensitive early sign: The patient screams when you touch the skin gently. The pain extends far beyond the visible area of erythema. This disconnect between minimal skin findings and severe pain should trigger NSTI concern. By the time bullae, crepitus, and necrosis are visible, the infection is far advanced.","Clindamycin for toxin suppression is NOT optional: The evidence for clindamycin in NSTI is based on the Eagle effect and toxin suppression. At high bacterial inocula (characteristic of NSTI), beta-lactams lose efficacy because bacteria are in stationary phase. Clindamycin works regardless of growth phase. Additionally, cell-wall-active agents cause bacterial lysis → toxin release. Clindamycin prevents new toxin synthesis. Omitting clindamycin from NSTI therapy is a treatment error.","LRINEC score limitations: While the LRINEC score (>=6 = concern for NSTI) is a useful screening tool, it has important limitations: sensitivity is only 60-80% in validation studies, meaning 20-40% of true NSTI cases will be missed. A negative LRINEC score should NEVER be used to rule out NSTI if clinical suspicion is present. The score was designed to raise suspicion, not to exclude the diagnosis. When in doubt, explore surgically.","Fournier's gangrene is a true emergency: Necrotizing fasciitis of the perineum and genitalia. Often occurs in diabetics. Polymicrobial (Type I). Mortality 20-40%. Requires emergent wide debridement that may include orchiectomy, penectomy, or colostomy for source control. Broad-spectrum coverage from the start. Delay = death.","Post-NSTI recovery: Patients who survive often require extensive reconstruction (skin grafts, flaps), prolonged rehabilitation, and psychological support. Wound VAC therapy is commonly used between debridements. Pharmacists contribute to long-term antibiotic management, pain control (often chronic), and metabolic optimization (nutrition, glucose control)."]},{id:"diabetic-foot",name:"Diabetic Foot Infections (DFI)",definition:"Infection of soft tissue and/or bone in the diabetic foot, typically arising from a neuropathic ulcer. Classified by IDSA/IWGDF severity: Grade 1 (uninfected ulcer), Grade 2 (mild — superficial, <2cm cellulitis), Grade 3 (moderate — deeper than dermis OR >2cm cellulitis OR lymphangitis OR involving muscle/tendon/joint/bone), Grade 4 (severe — systemic toxicity, metabolic instability). Polymicrobial infections are the norm in moderate-severe DFI. Osteomyelitis complicates 20-60% of moderate-severe DFIs.",clinicalPresentation:"Ulcer with surrounding erythema, warmth, tenderness, or purulent drainage. Hallmarks of neuropathic ulcers: painless (neuropathy), plantar location (pressure points), callus formation. Signs of infection: purulence, erythema >0.5cm from wound edge, warmth, tenderness, induration. Fetid odor suggests anaerobic involvement. Probe-to-bone test: if a sterile metal probe inserted through the ulcer contacts bone (gritty sensation), positive predictive value for osteomyelitis is ~89% in high-risk populations. Sausage toe (dactylitis) suggests osteomyelitis.",diagnostics:"Wound culture: Obtain from DEEP tissue (curettage of ulcer base after debridement, NOT superficial swab — superficial swabs grow colonizers). Probe-to-bone test (PTB): positive PTB + compatible imaging = presumed osteomyelitis. Imaging: plain radiographs first (cortical erosion, periosteal reaction, but 30-50% sensitivity early); MRI is the gold standard for osteomyelitis (sensitivity 90%, specificity 80%). ESR/CRP: ESR >70 has high specificity for osteomyelitis. Bone biopsy: gold standard for osteomyelitis diagnosis — culture + histology. Obtain whenever possible before starting antibiotics for osteomyelitis. Blood cultures: obtain for moderate-severe infections.",empiricTherapy:[{line:"First-Line — Mild DFI (Grade 2, Outpatient)",options:[{drug:"cephalexin-dfi",regimen:"Cephalexin 500mg PO QID",notes:"For mild DFI, acute (<2 weeks), in antibiotic-naive patient. Targets gram-positive cocci (Streptococci, MSSA). Mild DFIs are predominantly gram-positive monomicrobial. NO MRSA coverage — add TMP-SMX or doxycycline if MRSA risk. Duration: 1-2 weeks."},{drug:"amox-clav-dfi",regimen:"Amoxicillin-clavulanate 875/125mg PO BID",notes:"Broader option covering gram-positives + anaerobes + some gram-negatives. Useful for mild DFIs with wound features suggesting polymicrobial etiology (chronic ulcers, fetid discharge, deeper wounds). Duration: 1-2 weeks."},{drug:"clindamycin-dfi",regimen:"Clindamycin 300mg PO TID + Ciprofloxacin 500mg PO BID",notes:"If MRSA risk + need for gram-negative coverage. Clindamycin covers MRSA + Streptococci + anaerobes; ciprofloxacin adds gram-negative coverage. Check local clindamycin susceptibility patterns."}]},{line:"First-Line — Moderate-Severe DFI (Grade 3-4, Inpatient)",options:[{drug:"pip-tazo-dfi",regimen:"Pip-tazo 4.5g IV q6h (extended infusion) + Vancomycin IV",notes:"Standard empiric regimen for moderate-severe DFI. Pip-tazo covers Streptococci, MSSA, Enterobacterales, Pseudomonas, and anaerobes. Vancomycin adds MRSA coverage. De-escalate based on deep wound cultures. This covers the typical polymicrobial flora of chronic DFIs."},{drug:"ertapenem-dfi",regimen:"Ertapenem 1g IV daily + Vancomycin IV",notes:"Alternative backbone. Ertapenem covers Streptococci, MSSA, Enterobacterales, and anaerobes with convenient once-daily dosing (excellent for OPAT). Does NOT cover Pseudomonas — use pip-tazo or meropenem if Pseudomonas suspected (chronic wounds, prior Pseudomonas). Add vancomycin for MRSA."},{drug:"meropenem-dfi",regimen:"Meropenem 1g IV q8h + Vancomycin IV",notes:"Reserve for severe DFI with risk for ESBL or MDR gram-negatives (prior antibiotics, prior resistant cultures, prolonged hospitalization). De-escalate aggressively based on cultures."}]},{line:"Duration — Soft Tissue vs Osteomyelitis",options:[{drug:"duration-dfi-soft",regimen:"Soft tissue DFI: 1-2 weeks (mild), 2-3 weeks (moderate-severe)",notes:"IDSA 2023: shorter courses preferred for soft tissue DFI. Treat the INFECTION, not the wound — antibiotics do not heal wounds, they clear infection. A clean ulcer base without signs of infection does not require antibiotics regardless of appearance. Continuing antibiotics beyond the infectious period drives resistance and C. diff."},{drug:"duration-dfi-osteo",regimen:"Osteomyelitis: 4-6 weeks (no surgery), 1-3 weeks (after complete resection)",notes:"If osteomyelitis is present: 4-6 weeks of antibiotic therapy if treated medically (no bone resection). If infected bone is completely resected (amputation, debridement with clean margins): 1-3 weeks of antibiotics may suffice (some experts use 5-7 days post-resection if clean margins confirmed). Bone culture guides targeted therapy. Oral step-down is supported by the OVIVA trial for osteomyelitis."}]}],organismSpecific:[{organism:"Gram-positive cocci (Streptococci, MSSA) — acute, mild DFI",preferred:"Cephalexin, amoxicillin-clavulanate, cefazolin",alternative:"Clindamycin, dicloxacillin",notes:"Acute, previously untreated DFIs are often monomicrobial gram-positive. Don't over-treat mild DFI with broad-spectrum IV antibiotics. Target gram-positives and reassess."},{organism:"Polymicrobial (chronic/moderate-severe DFI)",preferred:"Pip-tazo, amp-sulbactam, ertapenem (each + vancomycin)",alternative:"Meropenem + vancomycin",notes:"Chronic, deep, previously treated DFIs are typically polymicrobial: Streptococci, Staphylococci, Enterobacterales, Pseudomonas (if chronic/macerated), anaerobes (especially in necrotic/ischemic wounds). Deep tissue culture is essential — treat what grows, not what you imagine."},{organism:"MRSA in DFI",preferred:"Vancomycin IV, linezolid, daptomycin (soft tissue); vancomycin IV or linezolid (osteomyelitis)",alternative:"TMP-SMX, doxycycline (mild DFI, oral step-down)",notes:"MRSA in DFI: use vancomycin or linezolid for serious infections. For osteomyelitis, linezolid has good bone penetration but limit to 6 weeks due to myelosuppression. Daptomycin has limited bone penetration data but is used. Oral step-down: TMP-SMX or doxycycline for MRSA soft tissue DFI."},{organism:"Pseudomonas aeruginosa",preferred:"Pip-tazo, cefepime, ciprofloxacin",alternative:"Meropenem (if resistant)",notes:"Pseudomonas is overdiagnosed in DFI — often a colonizer. True Pseudomonas infection is more common in chronic macerated wounds, patients with prior Pseudomonas antibiotics, and water-exposed wounds. Don't treat Pseudomonas empirically in all DFIs — treat based on culture results. If present and pathogenic, pip-tazo or ciprofloxacin are first-line."}],pearls:["TREAT THE INFECTION, NOT THE WOUND: The most common antibiotic stewardship error in DFI is continuing antibiotics for a 'bad-looking' ulcer that has no signs of infection. Chronic ulcers are colonized by bacteria — this is NOT infection. Signs of infection require at least 2 of: erythema, warmth, tenderness/pain, purulence, induration. If absent, no antibiotics needed regardless of wound appearance.","Probe-to-bone test: Simple, free, and highly informative. Insert a sterile blunt metal probe through the ulcer. If it contacts hard, gritty bone: osteomyelitis until proven otherwise (PPV ~89% in high-pretest-probability populations). If negative: lower probability but doesn't exclude it (sensitivity ~60%). Every clinician seeing DFI should perform this test.","Superficial swabs are USELESS: Culturing the surface of a chronic wound grows colonizers (Pseudomonas, Corynebacterium, mixed skin flora) that are NOT causing the deep infection. ALWAYS obtain deep tissue cultures — curettage of the ulcer base after debridement, or tissue biopsy. This is the culture that should guide your antibiotic choices.","OVIVA trial impact: The Oral vs IV Antibiotics for Bone and Joint Infection (OVIVA, 2019 NEJM) trial showed oral step-down was non-inferior to continued IV therapy for bone/joint infections including some osteomyelitis cases. This supports oral step-down in DFI osteomyelitis using agents with good oral bioavailability and bone penetration (FQs, TMP-SMX, doxycycline, linezolid). Not all patients are candidates, but it reduces PICC lines, hospital days, and complications.","Vascular assessment is NON-NEGOTIABLE: No amount of antibiotics will cure a DFI in an ischemic limb. Check ABI (ankle-brachial index), toe pressures, or transcutaneous oxygen. If vascular disease is present, revascularization is essential for healing. The multidisciplinary team (vascular surgery, podiatry, wound care) is as important as the antibiotic selection.","Osteomyelitis bone biopsy: When feasible, obtain before starting antibiotics. Bone culture + histology is the gold standard for diagnosing osteomyelitis and guiding targeted therapy. Empiric therapy without a pathogen-directed approach leads to unnecessarily broad 6-week courses. A bone biopsy that identifies MSSA means 6 weeks of cefazolin, not 6 weeks of vancomycin + meropenem.","Ertapenem for OPAT: Ertapenem 1g IV once daily is an excellent OPAT option for moderate DFI (after initial inpatient stabilization). Covers Streptococci, MSSA, Enterobacterales, and anaerobes. The once-daily dosing makes home infusion practical. Does NOT cover Pseudomonas or MRSA — ensure cultures don't show these before switching."]}],drugMonographs:[{id:"cefazolin",name:"Cefazolin",brandNames:"Ancef, Kefzol",drugClass:"First-generation cephalosporin",mechanismOfAction:"Binds PBPs (primarily PBP-1 and PBP-3), inhibiting cell wall synthesis. Bactericidal, time-dependent killing. First-generation cephalosporins have the BEST gram-positive activity within the cephalosporin class. Narrow spectrum compared to later generations — this is an ADVANTAGE (less collateral damage, less resistance selection, less C. diff).",spectrum:"Gram-positive: Excellent MSSA (drug of choice for MSSA infections), Streptococci (S. pyogenes, S. agalactiae). Gram-negative: Limited but useful — E. coli, Klebsiella (non-ESBL), Proteus mirabilis. GAPS: MRSA (no activity), Enterococcus, ESBL producers, AmpC producers (Enterobacter, Citrobacter, Serratia), Pseudomonas, anaerobes (variable, poor for B. fragilis), atypicals.",dosing:{standard:"1-2g IV q8h",ssti:"2g IV q8h",surgical_prophylaxis:"2g IV within 60 min before incision (3g if >=120kg); redose q4h intra-op",uti:"1g IV q8h",endocarditis_mssa:"2g IV q8h (native valve), 6 weeks",bone_joint:"2g IV q8h",weight_based:"Standard adult: 2g IV q8h. Severe infections or obesity: can increase to 2g q6h"},renalAdjustment:"CrCl 35-54: 1g q8h. CrCl 11-34: 1g q12h. CrCl <=10: 1g q24h. Hemodialysis: 1g after each HD session. CRRT: 2g q12h (institution-dependent). One advantage over nafcillin/oxacillin — cefazolin is renally cleared and easier to dose-adjust.",hepaticAdjustment:"No adjustment needed — renally eliminated. This is another advantage over nafcillin (which has hepatotoxicity concerns).",adverseEffects:{common:"Diarrhea, nausea, injection site reactions, rash (~1-2%)",serious:"Hypersensitivity/anaphylaxis (0.01-0.05%), C. difficile (lower risk than broader cephalosporins), hemolytic anemia (Coombs-positive, usually not clinically significant), leukopenia (rare, prolonged courses)",rare:"Seizures (very rare, unlike cefepime — minimal neurotoxicity), interstitial nephritis, Stevens-Johnson Syndrome"},drugInteractions:["Probenecid — blocks renal tubular secretion of cefazolin, increasing levels. Can be used intentionally to prolong half-life for outpatient use (probenecid + cefazolin allows less frequent dosing).","Warfarin — cephalosporins may enhance anticoagulant effect through vitamin K-related mechanism. Monitor INR, especially in malnourished or critically ill patients.","Aminoglycosides — potential additive nephrotoxicity. Administer separately (physical incompatibility in some IV solutions)."],monitoring:"Renal function (BMP) — for dose adjustment. CBC if prolonged course (>14 days). Clinical response. Unlike vancomycin, cefazolin does NOT require drug level monitoring — a major practical advantage.",pregnancyLactation:"Category B. Widely used in pregnancy — standard for cesarean section prophylaxis (2g IV before incision). Safe for GBS prophylaxis in penicillin-allergic patients without anaphylaxis history. Compatible with breastfeeding.",pharmacistPearls:["CEFAZOLIN IS THE GOLD STANDARD FOR MSSA: Multiple studies demonstrate cefazolin is equivalent or SUPERIOR to nafcillin/oxacillin for MSSA bacteremia and endocarditis, with FEWER adverse effects (less nephrotoxicity, less hepatotoxicity, easier dosing). The CEFAB trial and subsequent meta-analyses cemented this. If your institution still defaults to nafcillin for MSSA, advocate for the cefazolin switch. This is one of the most impactful antimicrobial stewardship initiatives.","Cefazolin for surgical prophylaxis: THE most commonly used antibiotic in the world for surgical prophylaxis. Weight-based dosing matters: 2g for patients <120kg, 3g for patients >=120kg. Timing: within 60 minutes of incision (unlike vancomycin which needs 120 min). Redose every 4 hours intra-operatively for long surgeries or major blood loss (>1.5L).","Cross-reactivity with penicillin: Cefazolin has a unique R1 side chain that differs from most penicillins. Cross-reactivity risk is ~1%. Even patients with documented penicillin allergy (non-anaphylactic) can safely receive cefazolin in most cases. For patients with penicillin anaphylaxis: skin testing or graded dose challenge under allergist supervision. Don't let a vague 'penicillin allergy' deprive a patient of the best MSSA drug available.","Probenecid trick for OPAT: Adding probenecid 1g PO BID to cefazolin extends the effective half-life, potentially allowing q12h dosing for less serious infections. This is used at some OPAT programs to reduce nursing visits. Evidence is limited to PK studies — discuss with your ID team before implementing.","Cefazolin vs. nafcillin/oxacillin comparison: Cefazolin advantages — q8h dosing (vs q4h), less phlebitis, no hepatotoxicity (vs oxacillin), less interstitial nephritis, easier dose adjustment in renal impairment, suitable for OPAT. Nafcillin advantages — does not require renal adjustment (hepatically cleared), potentially faster bactericidal activity (debated). For nearly all MSSA infections, cefazolin is the preferred agent.","Low C. diff risk: Among parenteral antibiotics, cefazolin has one of the LOWEST rates of C. difficile infection. Narrower spectrum = less disruption of colonic flora. This is clinically meaningful compared to broad-spectrum alternatives like pip-tazo or meropenem."]},{id:"clindamycin",name:"Clindamycin",brandNames:"Cleocin",drugClass:"Lincosamide antibiotic",mechanismOfAction:"Binds to the 50S ribosomal subunit (23S rRNA at the peptidyl transferase center), inhibiting bacterial protein synthesis. Bacteriostatic at standard doses (bactericidal at high concentrations against some organisms). The CRITICAL clinical property: as a ribosomal inhibitor, clindamycin SUPPRESSES BACTERIAL TOXIN PRODUCTION. This makes it essential in toxin-mediated diseases (necrotizing fasciitis, toxic shock syndrome, PVL-positive MRSA). Also concentrates in bone, abscesses, and neutrophils (excellent intracellular penetration).",spectrum:"Gram-positive: Streptococci (excellent), MSSA, most CA-MRSA (but rising resistance — check local rates). Anaerobes: good above-the-diaphragm activity (Peptostreptococcus, Prevotella, Fusobacterium). VARIABLE for B. fragilis (30-40% resistance). GAPS: Enterococcus (no activity), gram-negatives (no activity), MRSA in areas with >15-20% clindamycin resistance, some B. fragilis.",dosing:{oral:"300-450mg PO TID (or QID for serious infections)",iv_standard:"600mg IV q8h",iv_severe:"900mg IV q8h (necrotizing fasciitis, severe SSTI)",bone_joint:"600mg IV q8h or 300-450mg PO TID",toxin_suppression:"900mg IV q8h (always as combination with cell-wall-active agent)"},renalAdjustment:"No dose adjustment needed — hepatically metabolized. This is an advantage in renal impairment.",hepaticAdjustment:"Use with caution in severe hepatic impairment. Half-life is prolonged in liver disease. No specific dose reduction established, but monitor closely and consider reduced dosing if severe hepatic dysfunction.",adverseEffects:{common:"Diarrhea (10-20% — among the highest rates of any antibiotic), nausea, metallic taste, rash",serious:"C. difficile colitis (historically the drug MOST associated with C. diff — though FQs and 3rd-gen cephalosporins have surpassed it in some studies), maculopapular rash, hepatotoxicity, neutropenia",rare:"Anaphylaxis, Stevens-Johnson Syndrome, esophageal ulceration (take capsules with full glass of water), pseudomembranous colitis (severe C. diff presentation)"},drugInteractions:["Erythromycin/azithromycin — antagonistic interaction. Erythromycin and clindamycin bind to overlapping sites on the 50S ribosome. Do NOT combine.","Neuromuscular blocking agents (vecuronium, pancuronium) — clindamycin potentiates neuromuscular blockade. Monitor closely in OR/ICU settings. Can cause prolonged paralysis.","Cyclosporine — clindamycin may decrease cyclosporine levels. Monitor in transplant patients.","Kaolin-pectin antidiarrheals — reduce clindamycin absorption if taken simultaneously. Separate by 2 hours.","Warfarin — possible enhanced anticoagulation. Monitor INR."],monitoring:"Liver function tests (baseline and periodic in prolonged courses). CBC (for neutropenia in courses >14 days). Stool frequency and character (C. diff surveillance). Clinical response. No drug level monitoring needed.",pregnancyLactation:"Category B. Generally considered safe in pregnancy. Used for GBS prophylaxis in patients with high-risk penicillin allergy (ONLY if isolate is clindamycin-susceptible). Enters breast milk — AAP considers compatible with breastfeeding but monitor infant for diarrhea.",pharmacistPearls:["TOXIN SUPPRESSION IS CLINDAMYCIN'S SUPERPOWER: In necrotizing fasciitis (GAS), toxic shock syndrome, and PVL-positive MRSA infections, clindamycin shuts down toxin production. Beta-lactams and vancomycin (cell wall agents) cause bacterial lysis, which RELEASES preformed toxins. Clindamycin prevents NEW toxin synthesis. This is the pharmacological rationale for triple therapy in NSTI. Never omit clindamycin from NSTI regimens.","The D-test is YOUR responsibility: When an isolate is erythromycin-resistant and clindamycin-susceptible, inducible clindamycin resistance (erm gene) may be present. The D-zone test (placing erythromycin and clindamycin disks near each other — flattening of the clindamycin zone creates a 'D' shape) detects this. If D-test positive: clindamycin will FAIL clinically. If D-test negative: safe to use. Many labs report this automatically, but verify. If the report says 'clindamycin susceptible' without mention of D-test, call the lab.","Bone and abscess penetration: Clindamycin achieves bone concentrations that are 40-75% of serum levels — among the highest of any antibiotic. Also concentrates well in abscesses (unlike aminoglycosides, which are inactivated in acidic, anaerobic abscess environments). This makes clindamycin valuable for osteomyelitis and deep abscess treatment.","Rising MRSA resistance: CA-MRSA clindamycin susceptibility has been declining. In some US communities, 15-25% of MRSA is now clindamycin-resistant. This limits clindamycin's utility as an empiric MRSA agent. Always check local antibiogram data. TMP-SMX and doxycycline have more consistently maintained MRSA activity (>95% susceptibility in most areas).","C. diff risk is real but contextual: Clindamycin carries one of the highest C. diff risks among oral antibiotics. However, this must be balanced against its unique toxin-suppressing properties. For life-threatening NSTI or toxic shock, the benefit of clindamycin far outweighs the C. diff risk. For routine uncomplicated SSTI where TMP-SMX or doxycycline would work, prefer those lower-risk agents.","Oral bioavailability is ~90%: Clindamycin PO achieves serum levels approaching IV. For step-down therapy, the oral route is highly effective. This makes clindamycin an excellent OPAT-avoidance option for bone/joint infections and deep SSTIs."]},{id:"daptomycin",name:"Daptomycin",brandNames:"Cubicin",drugClass:"Cyclic lipopeptide (first-in-class)",mechanismOfAction:"Inserts into the gram-positive cell membrane in a calcium-dependent manner, forming ion channels that cause rapid membrane depolarization. This leads to loss of membrane potential, cessation of DNA/RNA/protein synthesis, and cell death. Rapidly bactericidal — concentration-dependent killing (Cmax/MIC drives efficacy). Unique mechanism: no other antibiotic class works this way. CRITICAL LIMITATION: inactivated by pulmonary surfactant — NEVER use for pneumonia.",spectrum:"GRAM-POSITIVE ONLY. Excellent: MRSA (including hVISA/VISA strains with vancomycin MIC creep), MSSA, VRE (E. faecium and E. faecalis — one of few bactericidal options), Streptococci, CoNS. GAPS: ALL gram-negatives (no activity), ALL anaerobes, pneumonia (inactivated by surfactant — this is a CONTRAINDICATION, not just a gap).",dosing:{ssti:"4 mg/kg IV once daily (FDA-approved dose for SSTI)",bacteremia_endocarditis:"6 mg/kg IV once daily (some experts use 8-10 mg/kg for high MIC, endocarditis, or osteomyelitis)",vre:"8-12 mg/kg IV once daily (higher doses for serious VRE infections)",high_dose:"8-12 mg/kg IV daily for: endocarditis, osteomyelitis, persistent bacteremia, prosthetic joint infections, or MIC >=1"},renalAdjustment:"CrCl >=30: no adjustment. CrCl <30 (including HD): 4-6 mg/kg IV q48h (or dose after HD on dialysis days). Some experts maintain daily dosing with standard doses even in renal impairment for serious infections (PK data supports this) — consult ID/pharmacy. CRRT: 8 mg/kg q48h (limited data, institution-dependent).",hepaticAdjustment:"No adjustment for mild-moderate hepatic impairment. Limited data in severe hepatic disease.",adverseEffects:{common:"CPK elevation (2-7%), diarrhea, headache, injection site reactions, insomnia",serious:"Rhabdomyolysis/myopathy (dose-related — monitor CPK weekly; hold if CPK >5-10× ULN with symptoms), eosinophilic pneumonia (rare but important — presents as new infiltrates, fever, dyspnea on daptomycin; discontinue immediately), peripheral neuropathy",rare:"Anaphylaxis, renal failure secondary to rhabdomyolysis, hepatitis"},drugInteractions:["Statins (HMG-CoA reductase inhibitors) — both daptomycin and statins can cause myopathy/rhabdomyolysis. HOLD STATINS during daptomycin therapy. Restart after daptomycin course is complete. This is a pharmacist-driven intervention that prevents serious harm.","Tobramycin — daptomycin trough levels may increase when co-administered. Clinical significance uncertain but monitor CPK more closely.","Warfarin — no significant interaction, but monitor INR as with any antibiotic course."],monitoring:"CPK: obtain baseline and at least WEEKLY during therapy (more frequently if symptoms of myalgia, weakness). HOLD daptomycin if CPK >5× ULN with symptoms or >10× ULN regardless of symptoms. Renal function (BMP) — for dose adjustment. Clinical response. Watch for respiratory symptoms (eosinophilic pneumonia — rare but requires discontinuation).",pregnancyLactation:"Category B. Limited human data. Animal studies showed no harm. Use only if clearly needed. Breastfeeding: unknown whether excreted in milk — use with caution.",pharmacistPearls:["NEVER USE FOR PNEUMONIA: Daptomycin is inactivated by pulmonary surfactant. The pivotal MRSA pneumonia trial was stopped because daptomycin FAILED in pneumonia. This is not a dosing issue — it is a pharmacological incompatibility. If a patient on daptomycin develops pneumonia, switch to vancomycin or linezolid. This is a HARD STOP — no exceptions.","HOLD STATINS: This is one of the most important pharmacist interventions for daptomycin. Both agents cause myopathy through different mechanisms, and the combination dramatically increases rhabdomyolysis risk. Temporarily discontinue all statins when daptomycin is initiated. Set a reminder to restart them after daptomycin is completed. Document this in the chart.","High-dose daptomycin (8-12 mg/kg): The FDA-approved doses (4 mg/kg SSTI, 6 mg/kg bacteremia) are increasingly considered suboptimal for serious infections. Many ID experts now routinely use 8-10 mg/kg for MRSA bacteremia, endocarditis, and osteomyelitis. Higher doses improve the Cmax/MIC ratio (concentration-dependent killing). The evidence is from observational studies and PK modeling — no RCTs, but the trend is clear. Higher doses increase CPK monitoring importance.","Daptomycin for MRSA with vancomycin MIC creep: When MRSA has vancomycin MIC = 2, achieving AUC 400-600 requires dangerously high vancomycin doses with significant nephrotoxicity risk. Daptomycin is the preferred alternative for non-pulmonary MRSA infections with elevated vancomycin MICs. This is an increasingly common clinical scenario.","Eosinophilic pneumonia: Rare (<1%) but can mimic treatment failure or new infection. Patient on daptomycin develops fever, dyspnea, new infiltrates — instinct is to broaden antibiotics. CHECK eosinophil count on CBC differential. If elevated eosinophils + new infiltrates on daptomycin = eosinophilic pneumonia until proven otherwise. Treatment: stop daptomycin, consider steroids. Symptoms resolve rapidly.","Daptomycin is one of few BACTERICIDAL options for VRE: Unlike linezolid (bacteriostatic for enterococci), daptomycin is bactericidal against VRE. For VRE endocarditis or bacteremia where bactericidal activity matters, daptomycin at 8-12 mg/kg is preferred. Often combined with ampicillin or ceftaroline for synergy in difficult VRE infections."]}]},m={id:"iai",name:"Intra-Abdominal Infections",icon:"🫁",category:"Infectious Disease",overview:{definition:"Intra-abdominal infections (IAI) encompass peritonitis and intra-abdominal abscesses resulting from disruption of the GI tract. The 2010 IDSA/SIS guidelines (Solomkin et al.) classify IAIs as UNCOMPLICATED (infection confined to a single organ without peritoneal extension — e.g., uncomplicated appendicitis, cholecystitis) vs COMPLICATED (cIAI — infection extends beyond the source organ into the peritoneal space, causing localized/diffuse peritonitis or abscess formation). This distinction drives the need for source control and breadth of antimicrobial therapy. Community-acquired vs healthcare-associated IAI is the second key distinction driving empiric choices.",epidemiology:"IAIs are the second most common cause of sepsis in ICU patients. Appendicitis is the most common surgical cause (~300,000 cases/year in US). Secondary peritonitis (perforated viscus, anastomotic leak) carries 20-60% mortality depending on severity and timing of intervention. Intra-abdominal abscesses develop in 10-30% of patients after GI perforation or surgery. Healthcare-associated IAI (post-operative leaks, tertiary peritonitis) involve MDR organisms in up to 30-50% of cases.",keyGuidelines:[{name:"IDSA/SIS 2010 — Guidelines for Diagnosis and Management of cIAI (Solomkin et al.)",detail:"Current definitive US guideline. Key principles: source control within 24h, empiric antibiotics covering enteric gram-negatives + anaerobes ± Enterococcus based on severity. Stratifies by community-acquired (mild-moderate vs high-risk/severe) and healthcare-associated. Recommends AGAINST routine anti-enterococcal or anti-Candidal empiric therapy in community-acquired IAI. Duration: 4-7 days with adequate source control."},{name:"STOP-IT Trial (Sawyer et al., 2015 NEJM)",detail:"Landmark RCT that changed IAI duration paradigm. 4 days of antibiotics after source control was non-inferior to conventional longer courses (mean ~8 days) for cIAI. Outcome-based stopping (treat until clinical resolution) was NOT superior to fixed 4-day courses. This trial established short-course therapy as the standard. Pharmacist impact: advocate for 4-day courses and antibiotic time-outs."},{name:"SIS/IDSA 2017 Revised Guidelines (Mazuski et al.)",detail:"Updated guidance emphasizing source control adequacy, short antibiotic courses (4 days), de-escalation based on cultures, and limiting empiric breadth in community-acquired IAI. Reinforced that anti-enterococcal coverage is NOT needed in most community-acquired IAI. Defined risk factors for healthcare-associated IAI requiring broader coverage."},{name:"Tokyo Guidelines 2018 (TG18) — Acute Cholangitis and Cholecystitis",detail:"International evidence-based guidelines for biliary infections. Severity grading: Grade I (mild — responds to antibiotics), Grade II (moderate — biliary drainage needed), Grade III (severe — organ dysfunction). Guides timing of intervention (cholecystectomy for cholecystitis, ERCP for cholangitis) and antibiotic selection. Key biliary pathogen: E. coli, Klebsiella, Enterococcus."}],landmarkTrials:[{name:"STOP-IT (Sawyer et al., 2015 NEJM)",detail:"518 patients with cIAI and adequate source control randomized to 4 days fixed-duration antibiotics vs outcome-based continuation (stop 2 days after resolution of fever/leukocytosis/ileus). No difference in SSI, recurrent IAI, or death. Fixed 4-day course used 1.5 fewer antibiotic days. Practice-changing: 4 days is sufficient with adequate source control."},{name:"CIAOW Study (Sartelli et al., 2013)",detail:"Largest worldwide observational study of cIAI management (68 countries, >4,500 patients). Key finding: inadequate source control was the strongest independent predictor of mortality and treatment failure. Reinforced that NO antibiotic regimen can compensate for inadequate source control — source control is primary, antibiotics are adjunctive."},{name:"Montravers et al. (2009) — De-escalation in IAI",detail:"Showed de-escalation of empiric broad-spectrum therapy in cIAI (based on culture results at 48-72h) was safe and did not increase treatment failure. Supports aggressive culture-directed narrowing."},{name:"DURAPOP (Montravers et al., 2018)",detail:"Randomized trial in postoperative peritonitis: 8 days vs 15 days of antibiotics. No difference in treatment failure. Shorter courses were safe for complicated postoperative IAI with adequate source control. Extended the STOP-IT principle to healthcare-associated IAI."},{name:"Solomkin et al. (2010) Ertapenem vs Pip-Tazo",detail:"Multiple trials established ertapenem as non-inferior to pip-tazo for community-acquired cIAI. Advantage: once-daily dosing ideal for OPAT. Limitation: no Pseudomonas or Enterococcus coverage. Cemented ertapenem as a first-line option for mild-moderate community-acquired IAI."}],riskFactors:"Healthcare-associated risk factors (post-operative IAI, prior antibiotics, prior hospitalization, immunosuppression) drive the need for broader empiric therapy. Severity indicators: APACHE II >=15, organ dysfunction, delayed source control (>24h), inability to achieve adequate source control, diffuse peritonitis, malnutrition, advanced age. Risk factors for resistant organisms: prior antibiotics (within 90 days), prior MDR culture, prolonged hospitalization, tertiary peritonitis, healthcare-associated origin."},subcategories:[{id:"ca-iai-uncomplicated",name:"Uncomplicated IAI (Appendicitis, Cholecystitis)",definition:"Infection confined to a single organ without peritoneal extension. Includes: uncomplicated (non-perforated) appendicitis, uncomplicated (non-gangrenous) acute cholecystitis, uncomplicated diverticulitis (Hinchey I — confined pericolic phlegmon). Source control (appendectomy, cholecystectomy) is definitive; antibiotics are peri-operative prophylactic or very short-course. These infections do NOT require the broad, prolonged courses used for complicated IAI.",clinicalPresentation:"Acute appendicitis: periumbilical pain migrating to RLQ (McBurney's point), anorexia, nausea/vomiting, low-grade fever. Acute cholecystitis: RUQ pain (Murphy's sign positive), fever, nausea, post-prandial exacerbation. Uncomplicated diverticulitis: LLQ pain, low-grade fever, mild leukocytosis, CT showing pericolic fat stranding without abscess or free perforation.",diagnostics:"Appendicitis: CT abdomen/pelvis with IV contrast (sensitivity >95%), ultrasound (preferred in pediatric and pregnant patients). Cholecystitis: RUQ ultrasound (gallstones + gallbladder wall thickening + pericholecystic fluid + sonographic Murphy's sign), HIDA scan if ultrasound equivocal. Diverticulitis: CT abdomen/pelvis with IV contrast (confirms diagnosis, classifies Hinchey stage, identifies abscess/perforation). Blood cultures NOT routinely needed for uncomplicated IAI. WBC, CRP for trending.",empiricTherapy:[{line:"Uncomplicated Appendicitis — Peri-Operative",options:[{drug:"cefazolin-appx",regimen:"Cefazolin 2g IV + Metronidazole 500mg IV (single pre-op dose)",notes:"Standard peri-operative prophylaxis for appendectomy. Cefazolin covers enteric gram-positives and common Enterobacterales; metronidazole covers anaerobes (Bacteroides). SINGLE pre-operative dose is sufficient if appendix is non-perforated and no spillage. No post-operative antibiotics needed for uncomplicated appendicitis."},{drug:"ceftriaxone-appx",regimen:"Ceftriaxone 2g IV + Metronidazole 500mg IV (single pre-op dose)",notes:"Alternative prophylaxis. Broader gram-negative coverage than cefazolin. Some institutions use this for appendectomy, but cefazolin + metronidazole is equally effective and narrower. Single dose; no post-op continuation."}]},{line:"Uncomplicated Cholecystitis — Peri-Operative",options:[{drug:"cefazolin-chole",regimen:"Cefazolin 2g IV (single pre-op dose for early cholecystectomy)",notes:"TG18: for mild (Grade I) acute cholecystitis with early cholecystectomy (<72h), a single pre-operative dose is sufficient. No post-operative antibiotics unless gangrenous or perforated. Biliary pathogens: E. coli, Klebsiella, Enterococcus — cefazolin covers the first two."},{drug:"ctx-metro-chole",regimen:"Ceftriaxone 2g IV daily + Metronidazole 500mg IV q8h",notes:"For moderate (Grade II) cholecystitis or delayed surgery. Continue until cholecystectomy or clinical resolution. Ceftriaxone has excellent biliary excretion (40% excreted in bile). Anaerobic coverage with metronidazole added for complicated biliary-enteric connections."}]},{line:"Uncomplicated Diverticulitis — Outpatient",options:[{drug:"cipro-metro-div",regimen:"Ciprofloxacin 500mg PO BID + Metronidazole 500mg PO TID",notes:"Traditional outpatient regimen. Covers enteric gram-negatives + anaerobes. HOWEVER: Recent evidence (DIABOLO trial 2017, AVOD trial) showed antibiotics provide NO benefit for uncomplicated diverticulitis (Hinchey Ia — phlegmon only). AGA 2021 guidelines conditionally recommend AGAINST routine antibiotics for uncomplicated diverticulitis in immunocompetent patients. Discuss with the team."},{drug:"amox-clav-div",regimen:"Amoxicillin-clavulanate 875/125mg PO BID",notes:"Alternative single-agent oral option covering gram-negatives + anaerobes. Simpler regimen than cipro + metronidazole. Same caveat: may not be needed at all for uncomplicated diverticulitis per current evidence."}]},{line:"Duration — Uncomplicated IAI",options:[{drug:"duration-uncomplicated",regimen:"Single pre-op dose (appendectomy/cholecystectomy), or ≤24h post-op, or NO antibiotics (uncomplicated diverticulitis)",notes:"Uncomplicated appendicitis: Pre-op dose only. Uncomplicated cholecystitis: Pre-op dose to 24h max. Uncomplicated diverticulitis: Increasingly treated without antibiotics (bowel rest, observation). The era of 7-14 day antibiotic courses for uncomplicated IAI is over. Source control (surgery) is the definitive treatment."}]}],organismSpecific:[{organism:"E. coli (most common aerobic IAI pathogen)",preferred:"Ceftriaxone, cefazolin, ciprofloxacin",alternative:"Pip-tazo, ertapenem",notes:"E. coli causes 50-60% of community-acquired IAI. Usually susceptible to ceftriaxone, FQs, and pip-tazo. ESBL-producing E. coli is emerging in community-acquired IAI — consider if prior FQ/cephalosporin use."},{organism:"Bacteroides fragilis (most common anaerobe)",preferred:"Metronidazole, pip-tazo, meropenem, ampicillin-sulbactam",alternative:"Ertapenem",notes:"Bacteroides fragilis is universally resistant to cephalosporins and most penicillins. ALWAYS add anaerobic coverage to any cephalosporin-based IAI regimen. Metronidazole is the most targeted agent. Clindamycin has rising B. fragilis resistance (30-40%) — unreliable for IAI."},{organism:"Enterococcus (biliary tract emphasis)",preferred:"Ampicillin, amoxicillin, pip-tazo (inherent activity)",alternative:"Vancomycin (if ampicillin-resistant)",notes:"Enterococcus is commonly cultured from biliary tract infections but is a PATHOGENIC DEBATE in non-biliary IAI. IDSA 2010: routine empiric Enterococcal coverage NOT recommended for community-acquired IAI. Coverage recommended for: biliary-origin IAI, healthcare-associated IAI, immunocompromised, prosthetic material infections, Enterococcal bacteremia."}],pearls:["UNCOMPLICATED DIVERTICULITIS MAY NOT NEED ANTIBIOTICS AT ALL: DIABOLO (2017, Lancet) and AVOD trials showed no difference in outcomes for uncomplicated diverticulitis treated with vs. without antibiotics. AGA 2021 conditionally recommends against routine antibiotics for immunocompetent patients with uncomplicated diverticulitis. This is a major paradigm shift — discuss with the surgical team and advocate for guideline-concordant care.","Single-dose prophylaxis for appendectomy/cholecystectomy: If the organ is not perforated and there's no spillage, a single pre-operative antibiotic dose is all that's needed. Post-operative antibiotics for uncomplicated appendectomy or cholecystectomy are unnecessary and represent antibiotic overuse. Stewardship opportunity: review post-op orders and discontinue if not indicated.","Ceftriaxone biliary excretion: Ceftriaxone is unique among cephalosporins — ~40% is excreted unchanged in bile, achieving biliary concentrations 20-150× serum levels. This makes it particularly effective for biliary infections. Caveat: ceftriaxone can form biliary sludge/pseudolithiasis (calcium-ceftriaxone precipitate) — usually reversible but avoid in patients with active biliary obstruction."]},{id:"ca-iai-complicated",name:"Community-Acquired Complicated IAI (cIAI)",definition:"Infection that extends beyond the source organ into the peritoneal space. Includes: perforated appendicitis with peritonitis, perforated diverticulitis (Hinchey II-IV), perforated peptic ulcer, small bowel perforation, intra-abdominal abscess, secondary peritonitis from any GI perforation. Requires BOTH source control (surgical or percutaneous drainage) AND antimicrobial therapy covering enteric gram-negatives and anaerobes. IDSA 2010 further stratifies into mild-moderate (APACHE <15, healthy host) vs high-risk/severe (APACHE >=15, immunosuppression, healthcare exposure).",clinicalPresentation:"Diffuse or localized abdominal pain, guarding, rigidity (peritoneal signs). Fever, tachycardia, leukocytosis. Diffuse peritonitis: board-like abdomen, absent bowel sounds, hemodynamic instability. Localized abscess: focal tenderness, fever, persistent leukocytosis after initial intervention. Free air on imaging indicates perforation. Sepsis/septic shock may be the presenting picture — IAI is the 2nd most common cause of abdominal sepsis.",diagnostics:"CT abdomen/pelvis with IV contrast: imaging modality of choice (free air, abscess, bowel wall thickening, mesenteric fat stranding, extraluminal contrast extravasation). Blood cultures: obtain before antibiotics in moderate-severe. Peritoneal fluid cultures: obtain at time of surgery or percutaneous drainage — aerobic + anaerobic cultures. Gram stain helpful for rapid pathogen identification. Lactate (prognostic, indicates tissue hypoperfusion). Procalcitonin: can guide duration (trending down supports discontinuation).",durationGuidance:{standard:"4–7 days",stewardshipNote:"SIS/IDSA 2017: Limit to 4 days if source control achieved. Extended duration not supported."},empiricTherapy:[{line:"First-Line — Mild-Moderate cIAI (APACHE <15, No MDR Risk)",options:[{drug:"ctx-metro-ciai",regimen:"Ceftriaxone 2g IV daily + Metronidazole 500mg IV q8h",notes:"IDSA 2010 recommended combination. Ceftriaxone covers enteric gram-negatives; metronidazole covers anaerobes (particularly B. fragilis). Simple, well-tolerated, once-daily ceftriaxone component. NO Pseudomonal or Enterococcal coverage — appropriate for community-acquired, mild-moderate cIAI. Duration: 4 days post source control (STOP-IT).",evidence:"A-I",evidenceSource:"SIS/IDSA 2017"},{drug:"ertapenem-ciai",regimen:"Ertapenem 1g IV once daily",notes:"IDSA 2010 first-line single-agent option for mild-moderate cIAI. Covers Enterobacterales + anaerobes + Streptococci + MSSA in one drug. Once-daily = excellent for OPAT. Equivalent to pip-tazo in multiple RCTs. GAPS: no Pseudomonas, no Enterococcus, no MRSA. The narrowest carbapenem — minimal Pseudomonal selection pressure compared to meropenem.",evidence:"A-I",evidenceSource:"SIS/IDSA 2017"},{drug:"amp-sulb-ciai",regimen:"Ampicillin-sulbactam 3g IV q6h",notes:"IDSA 2010 recommended for mild-moderate cIAI. Covers Enterobacterales + anaerobes + Enterococcus + Streptococci. UNIQUE ADVANTAGE: the only first-line cIAI regimen with intrinsic Enterococcal coverage. Good choice for biliary-origin cIAI. LIMITATION: rising E. coli resistance (20-30% in many regions) — check local antibiogram. Not reliable for Pseudomonas.",evidence:"B-II",evidenceSource:"SIS/IDSA 2017"}]},{line:"First-Line — High-Risk/Severe cIAI (APACHE >=15 or MDR Risk Factors)",options:[{drug:"pip-tazo-ciai",regimen:"Pip-tazo 4.5g IV q6h (extended infusion over 4h)",notes:"IDSA 2010 first-line for high-risk/severe community-acquired cIAI. Broadest non-carbapenem single-agent option: covers Enterobacterales, Pseudomonas, anaerobes, Enterococcus (faecalis), Streptococci, MSSA. Extended infusion optimizes PK for sicker patients. Duration: 4 days post source control (STOP-IT).",evidence:"A-I",evidenceSource:"SIS/IDSA 2017"},{drug:"meropenem-ciai",regimen:"Meropenem 1g IV q8h (extended infusion over 3h)",notes:"Reserve for: APACHE >=15, ESBL risk, prior resistant organisms, failed initial therapy. Broadest coverage. Always de-escalate based on cultures (within 48-72h). Meropenem should NOT be first-line for mild-moderate community-acquired IAI — this is carbapenem overuse and drives CRE.",evidence:"B-II",evidenceSource:"SIS/IDSA 2017"},{drug:"cefepime-metro-ciai",regimen:"Cefepime 2g IV q8h + Metronidazole 500mg IV q8h",notes:"Alternative for severe cIAI with Pseudomonal concern. Cefepime provides anti-pseudomonal and AmpC-stable gram-negative coverage; metronidazole adds anaerobes. No inherent Enterococcal coverage. Consider adding ampicillin if biliary source or Enterococcal risk.",evidence:"B-II",evidenceSource:"SIS/IDSA 2017"}]},{line:"Duration — STOP-IT Standard",options:[{drug:"duration-ciai",regimen:"4 days after adequate source control (STOP-IT trial standard)",notes:"STOP-IT trial (2015 NEJM): 4 fixed days of antibiotics after source control was equivalent to outcome-based longer courses. This is the new standard. KEY CAVEAT: adequate source control MUST be achieved. If source control is inadequate (persistent abscess, ongoing leak, unable to operate), longer courses may be needed — but the answer is better source control, not more antibiotics. Pharmacist role: antibiotic time-out at day 4, advocate for discontinuation if source controlled and clinically improving."}]}],organismSpecific:[{organism:"E. coli + Klebsiella (dominant aerobic gram-negatives)",preferred:"Ceftriaxone, ertapenem, pip-tazo",alternative:"Ciprofloxacin, meropenem (ESBL)",notes:"Together cause 60-70% of aerobic IAI isolates. Community-acquired strains usually susceptible to cephalosporins and pip-tazo. ESBL prevalence rising — risk factors: prior cephalosporins/FQs, recent hospitalization, travel to endemic areas (South/Southeast Asia). If ESBL confirmed: meropenem is the gold standard (MERINO trial). Ertapenem also effective for non-Pseudomonal ESBL."},{organism:"Bacteroides fragilis group",preferred:"Metronidazole, pip-tazo, meropenem, ertapenem",alternative:"Ampicillin-sulbactam",notes:"Present in virtually all IAI from colonic sources. ALWAYS include anaerobic coverage in IAI regimens. Metronidazole is the most targeted agent and maintains >99% B. fragilis susceptibility despite decades of use. Clindamycin is NOT reliable for B. fragilis in IAI (30-40% resistance). Cephalosporins (ceftriaxone, cefepime) have NO B. fragilis activity — never use them alone for IAI."},{organism:"Enterococcus faecalis",preferred:"Ampicillin, pip-tazo (inherent activity), vancomycin (if resistant)",alternative:"Linezolid (for VRE)",notes:"THE ENTEROCOCCAL CONTROVERSY: Enterococcus is frequently cultured from IAI but its pathogenic role is debated. IDSA 2010: empiric Enterococcal coverage NOT recommended for community-acquired IAI. Cover Enterococcus empirically ONLY when: biliary source, healthcare-associated IAI, post-operative peritonitis, immunocompromised, Enterococcus in blood cultures, or failure with non-Enterococcal regimen."},{organism:"Pseudomonas aeruginosa",preferred:"Pip-tazo, cefepime, meropenem",alternative:"Ciprofloxacin + metronidazole",notes:"Uncommon in community-acquired IAI (<5% of isolates). More common in healthcare-associated IAI. IDSA 2010: empiric anti-pseudomonal coverage NOT needed for community-acquired IAI unless severe or healthcare-associated risk factors. Overtreatment of Pseudomonas in community IAI is common stewardship target."}],pearls:["STOP-IT = 4 DAYS: This is the single most important trial in IAI management. With adequate source control, 4 days of antibiotics is sufficient for cIAI. Every additional day beyond 4 days increases C. diff risk, resistance selection, and cost without improving outcomes. Pharmacist intervention: flag patients on day 4 who are improving and advocate for discontinuation.","SOURCE CONTROL IS PRIMARY, ANTIBIOTICS ARE ADJUNCTIVE: The CIAOW study showed inadequate source control is the #1 predictor of mortality in cIAI. No antibiotic regimen — no matter how broad — can substitute for proper surgical/percutaneous drainage. If a patient is failing antibiotics for IAI, the question is 'Is source control adequate?' not 'Should we escalate antibiotics?'","The Enterococcal trap: Enterococcus grows frequently in IAI cultures, tempting clinicians to add ampicillin or vancomycin. IDSA 2010 says DON'T routinely cover Enterococcus in community-acquired IAI — outcomes are the same with or without specific Enterococcal coverage. The exception: biliary infections, healthcare-associated IAI, Enterococcal bacteremia, or immunocompromised patients. This is a high-value stewardship intervention.","Ertapenem is NOT meropenem: Ertapenem is the narrowest carbapenem. It does NOT cover Pseudomonas or Acinetobacter (unlike meropenem/imipenem/doripenem). This is an ADVANTAGE for community-acquired IAI: carbapenem-level anaerobic + Enterobacterales coverage without the Pseudomonal selection pressure. Using meropenem when ertapenem would suffice is carbapenem misuse.","Ceftriaxone has NO anaerobic coverage: This is the most common empiric error in IAI management. A surgeon orders 'ceftriaxone for peritonitis' — this leaves Bacteroides completely uncovered. ALWAYS pair ceftriaxone with metronidazole for any IAI. If you see ceftriaxone monotherapy for IAI, intervene immediately.","FQ resistance in E. coli is rising: Ciprofloxacin/levofloxacin resistance in E. coli has reached 20-30% in many communities. The cipro + metronidazole regimen for IAI is becoming less reliable. Ceftriaxone + metronidazole or amoxicillin-clavulanate are more reliable empiric oral/IV options. Check local antibiogram before prescribing FQ-based IAI regimens."]},{id:"ha-iai",name:"Healthcare-Associated & Post-Operative IAI",definition:"IAI occurring after recent healthcare exposure: post-operative peritonitis (anastomotic leak, surgical site infection), tertiary peritonitis (persistent/recurrent peritonitis after adequate treatment of secondary peritonitis), IAI in patients with recent hospitalization (>48h in past 90 days), recent IV antibiotics, or immunosuppression. MDR organisms are significantly more common (20-50%): ESBL Enterobacterales, Pseudomonas, VRE, Candida. Requires broader empiric coverage and aggressive culture-directed de-escalation.",clinicalPresentation:"Post-operative: fever, increasing WBC, ileus persisting beyond expected, new abdominal pain, wound drainage (purulent or enteric content), hemodynamic instability. Often subtle in ICU patients — may manifest as only unexplained clinical deterioration. Tertiary peritonitis: persistent fever and organ dysfunction despite adequate initial treatment — carries the worst prognosis (mortality 30-60%). CT findings: new or enlarging fluid collections, abscess, free air (anastomotic leak), bowel wall thickening.",diagnostics:"CT abdomen/pelvis with IV and oral contrast (oral contrast particularly helpful for identifying leak). Peritoneal/abscess fluid cultures (aerobic + anaerobic + fungal — Candida is an important pathogen in this setting). Blood cultures. Procalcitonin trending. Gram stain of peritoneal fluid (yeast forms may indicate Candida peritonitis). Consider beta-D-glucan if Candida suspected.",durationGuidance:{standard:"4–7 days after adequate source control",severe:"7–14 days (no adequate source control)",stewardshipNote:"Duration driven by source control adequacy, not by severity. STOP trial supports 4-day courses."},empiricTherapy:[{line:"Empiric — Post-Operative / Healthcare-Associated cIAI",options:[{drug:"pip-tazo-ha-iai",regimen:"Pip-tazo 4.5g IV q6h (extended infusion) + Vancomycin IV",notes:"Standard empiric regimen for healthcare-associated IAI. Pip-tazo covers Pseudomonas, Enterobacterales, anaerobes, Enterococcus faecalis. Add vancomycin for VRE (E. faecium) and MRSA coverage in high-risk patients. De-escalate aggressively at 48-72h based on cultures.",evidence:"A-I",evidenceSource:"SIS/IDSA 2017"},{drug:"meropenem-ha-iai",regimen:"Meropenem 1g IV q8h (extended infusion) + Vancomycin IV",notes:"For patients with ESBL risk, prior resistant organisms, or severe sepsis/septic shock. Meropenem covers ESBL, AmpC, Pseudomonas, anaerobes. Vancomycin for VRE/MRSA. THIS is the appropriate use of meropenem — healthcare-associated cIAI with MDR risk, not routine community-acquired IAI.",evidence:"A-I",evidenceSource:"SIS/IDSA 2017"},{drug:"cefepime-metro-ha",regimen:"Cefepime 2g IV q8h (extended infusion) + Metronidazole 500mg IV q8h + Vancomycin IV",notes:"Alternative triple therapy. Cefepime for anti-pseudomonal + AmpC stability; metronidazole for anaerobes; vancomycin for VRE/MRSA. More components but allows carbapenem-sparing approach when ESBL risk is not high.",evidence:"B-II",evidenceSource:"SIS/IDSA 2017"}]},{line:"ADD Antifungal If Candida Risk Factors",options:[{drug:"fluconazole-iai",regimen:"Fluconazole 400mg IV/PO daily (loading 800mg day 1) — or — Micafungin 100mg IV daily",notes:"Candida peritonitis risk factors: upper GI perforation (especially with acid suppression), recurrent GI surgery, anastomotic leak, immunosuppression, prolonged antibiotics, TPN, Candida in peritoneal cultures. IDSA 2010: empiric antifungal NOT routine — add when risk factors present or yeast seen on Gram stain. Fluconazole for susceptible Candida albicans; echinocandin (micafungin, caspofungin) for C. glabrata/C. krusei or critically ill. Source control is critical for Candida peritonitis."}]},{line:"Duration — Healthcare-Associated IAI",options:[{drug:"duration-ha-iai",regimen:"4-7 days after adequate source control; longer if source control inadequate or tertiary peritonitis",notes:"DURAPOP trial: 8 days was safe for postoperative peritonitis (vs 15 days). Apply STOP-IT principles: fixed short-course with adequate source control. Tertiary peritonitis is the exception — may require prolonged courses (2-4 weeks) due to ongoing infection with resistant organisms and often inadequate source control. Focus on optimizing source control rather than extending antibiotics."}]}],organismSpecific:[{organism:"ESBL-producing Enterobacterales",preferred:"Meropenem, ertapenem (non-Pseudomonal)",alternative:"Pip-tazo (controversial — MERINO trial showed inferiority for bacteremia)",notes:"ESBL prevalence in healthcare-associated IAI: 15-30%. MERINO trial caution: pip-tazo was inferior to meropenem for ESBL bacteremia. For serious ESBL IAI, carbapenems remain preferred. Ertapenem appropriate for non-critical, non-Pseudomonal ESBL IAI."},{organism:"Pseudomonas aeruginosa",preferred:"Pip-tazo, cefepime, meropenem",alternative:"Ciprofloxacin (check susceptibility)",notes:"Present in 10-20% of healthcare-associated IAI. Risk factors: prior broad-spectrum antibiotics, chronic illness, prolonged hospitalization. Double-cover empirically in septic shock; de-escalate to monotherapy when susceptibility known."},{organism:"Enterococcus faecium (including VRE)",preferred:"Linezolid, daptomycin",alternative:"Ampicillin (if susceptible — rare for E. faecium)",notes:"VRE is a real pathogen in healthcare-associated IAI (unlike the debate over Enterococcus in community-acquired IAI). E. faecium is intrinsically resistant to cephalosporins and often resistant to ampicillin. If VRE in peritoneal cultures with clinical infection: linezolid 600mg IV/PO BID (excellent peritoneal penetration) or daptomycin."},{organism:"Candida species",preferred:"Fluconazole (C. albicans), echinocandin (C. glabrata, C. krusei, critically ill)",alternative:"Amphotericin B (resistant Candida)",notes:"Candida in peritoneal fluid is a true pathogen requiring treatment (unlike Candida in sputum/urine which is often colonization). Source control (drainage) is essential. Species identification guides therapy: C. albicans is usually fluconazole-susceptible; C. glabrata requires echinocandin; C. auris is an emerging MDR threat requiring ID consultation."}],pearls:["Healthcare-associated IAI is a completely different disease than community-acquired IAI: MDR organisms, polymicrobial with resistant gram-negatives and VRE, Candida risk, higher mortality. The empiric regimen should be broader, the source control more aggressive, and the culture-directed de-escalation more diligent. Don't apply community-acquired IAI regimens to post-operative peritonitis.","Tertiary peritonitis is the most challenging IAI scenario: Defined as persistent/recurrent peritonitis after adequate treatment of secondary peritonitis. Organisms shift to low-virulence, highly resistant pathogens (VRE, Pseudomonas, Candida, CoNS). Mortality 30-60%. Often reflects persistent source control failure rather than antibiotic failure. Surgical re-exploration and optimized source control are more important than escalating antibiotics.","Candida in peritoneal cultures matters: Unlike Candida in urine or respiratory cultures (usually colonization), Candida isolated from peritoneal fluid obtained surgically or via drain IS pathogenic and requires treatment. Risk factors: upper GI perforation, recurrent surgery, TPN, broad-spectrum antibiotics. Always speciate Candida — treatment differs significantly by species.","De-escalation is a pharmacist responsibility: Healthcare-associated IAI requires broad empiric therapy, but MUST be narrowed at 48-72h based on cultures. This is where pharmacists add the most value: reviewing culture results, recommending targeted narrowing (meropenem → ertapenem if no Pseudomonas; vancomycin → discontinue if no MRSA/VRE), and ensuring the STOP-IT 4-day timeline is followed."]},{id:"biliary-iai",name:"Biliary Infections (Cholangitis & Complicated Cholecystitis)",definition:"Infections of the biliary system, primarily acute cholangitis (infection of the bile duct, usually from obstruction — choledocholithiasis, stricture, or stent occlusion) and complicated cholecystitis (gangrenous, emphysematous, or perforated gallbladder). Tokyo Guidelines 2018 (TG18) classification: Grade I (mild — responds to antibiotics), Grade II (moderate — requires biliary drainage), Grade III (severe — organ dysfunction). Charcot's triad (fever, RUQ pain, jaundice) is present in only 50-70% of cholangitis. Reynolds' pentad adds hypotension and mental status changes (severe cholangitis).",clinicalPresentation:"Cholangitis: Charcot's triad (fever + RUQ pain + jaundice) — classic but often incomplete. Reynolds' pentad (adds hypotension + AMS) indicates severe cholangitis with sepsis. Labs: elevated WBC, conjugated bilirubin, ALP, GGT, often elevated lipase. Complicated cholecystitis: RUQ pain, high fever, marked tenderness, peritoneal signs if perforated. Emphysematous cholecystitis (gas in gallbladder wall on imaging) — higher risk of perforation, more common in diabetics.",diagnostics:"RUQ ultrasound: first-line for cholecystitis (stones, wall thickening, pericholecystic fluid). Common bile duct dilation (>6mm) suggests choledocholithiasis. MRCP (magnetic resonance cholangiopancreatography): non-invasive cholangiography to visualize CBD stones/strictures. ERCP: both diagnostic and therapeutic — sphincterotomy, stone extraction, stent placement. Blood cultures: ESSENTIAL in cholangitis (bacteremia rate 30-50%). Bile cultures: obtain at ERCP or surgery. Liver function panel: bilirubin, ALP, GGT trending.",empiricTherapy:[{line:"First-Line — Acute Cholangitis (Grade I-II)",options:[{drug:"ctx-metro-bil",regimen:"Ceftriaxone 2g IV daily + Metronidazole 500mg IV q8h",notes:"TG18 first-line. Ceftriaxone excellent biliary penetration (40% biliary excretion). Metronidazole for anaerobes (important in biliary-enteric anastomosis or instrumented ducts). Add ampicillin 2g IV q4h if Enterococcal coverage desired (biliary infections have higher Enterococcal prevalence). Duration: 4-7 days post drainage (shorter if adequately drained)."},{drug:"pip-tazo-bil",regimen:"Pip-tazo 4.5g IV q6h (extended infusion)",notes:"Single-agent alternative covering gram-negatives, anaerobes, and Enterococcus. Good biliary penetration. Particularly useful when Enterococcal coverage desired without adding a separate agent. For Grade II-III cholangitis with sepsis."},{drug:"amp-sulb-bil",regimen:"Ampicillin-sulbactam 3g IV q6h",notes:"TG18 recommended. Covers Enterobacterales, anaerobes, and Enterococcus. The Enterococcal coverage is particularly relevant for biliary infections. Limitation: E. coli resistance (check local rates). Excellent option when local susceptibility supports it."}]},{line:"First-Line — Severe Cholangitis (Grade III) or Healthcare-Associated Biliary",options:[{drug:"meropenem-bil",regimen:"Meropenem 1g IV q8h + Vancomycin IV (if VRE risk)",notes:"For severe (Grade III) cholangitis with organ dysfunction, healthcare-associated biliary infection, or prior resistant organisms. Broadest coverage. De-escalate based on bile and blood cultures at 48-72h."},{drug:"pip-tazo-vanco-bil",regimen:"Pip-tazo 4.5g IV q6h (extended infusion) + Vancomycin IV",notes:"Alternative for severe cholangitis when carbapenem-sparing desired. Pip-tazo covers most gram-negatives + anaerobes + E. faecalis. Add vancomycin for E. faecium/VRE/MRSA coverage."}]},{line:"Duration — Biliary Infections",options:[{drug:"duration-biliary",regimen:"4-7 days after adequate biliary drainage; shorter if uncomplicated with good source control",notes:"TG18 + STOP-IT principles: once biliary obstruction is relieved (ERCP with sphincterotomy/stent, cholecystectomy, percutaneous drainage), 4-7 days is sufficient. Bacteremia: treat for minimum 7-14 days per bloodstream infection standards. Without adequate drainage: antibiotics alone are usually insufficient — biliary decompression is the source control equivalent for cholangitis."}]}],organismSpecific:[{organism:"E. coli (50-60% of biliary infections)",preferred:"Ceftriaxone, pip-tazo, ertapenem",alternative:"Ciprofloxacin (if susceptible), meropenem (ESBL)",notes:"Dominant biliary pathogen. Usually susceptible to cephalosporins. ESBL risk higher in patients with prior instrumentation, stents, or recent antibiotics."},{organism:"Klebsiella species (15-20%)",preferred:"Ceftriaxone, pip-tazo",alternative:"Meropenem (ESBL/KPC)",notes:"Second most common biliary aerobe. Same resistance concerns as E. coli."},{organism:"Enterococcus species (10-20%)",preferred:"Ampicillin, pip-tazo",alternative:"Vancomycin, linezolid (VRE)",notes:"Enterococcal coverage IS recommended for biliary infections (unlike non-biliary community-acquired IAI). The biliary tract is a niche where Enterococcus is a true pathogen. Ampicillin-sulbactam and pip-tazo have inherent E. faecalis activity. For E. faecium (often ampicillin-resistant): vancomycin or linezolid."},{organism:"Anaerobes (Bacteroides, Clostridium)",preferred:"Metronidazole, pip-tazo, meropenem",alternative:"Ampicillin-sulbactam",notes:"More common in complicated biliary disease: biliary-enteric anastomosis (prior surgery), elderly patients, recurrent cholangitis, emphysematous cholecystitis. Always cover when these risk factors present."}],pearls:["BILIARY DRAINAGE IS THE SOURCE CONTROL: In cholangitis, ERCP with biliary decompression is the equivalent of surgical source control. Antibiotics alone without drainage have high failure rates for moderate-severe cholangitis. Timing: Grade II should have drainage within 24-48h; Grade III is emergent within 12h (after initial resuscitation).","Enterococcal coverage matters here: Unlike non-biliary community-acquired IAI, biliary infections have a higher prevalence of Enterococcus as a true pathogen (10-20% of biliary cultures). Ampicillin-sulbactam and pip-tazo provide intrinsic E. faecalis coverage. Ceftriaxone-based regimens leave an Enterococcal gap — consider adding ampicillin if biliary source confirmed.","Ceftriaxone biliary sludge: Ceftriaxone forms calcium-ceftriaxone precipitate in bile (biliary pseudolithiasis). Usually asymptomatic and reversible after stopping the drug. However, avoid ceftriaxone in patients with complete biliary obstruction or patients on high-calcium infusions (neonates on calcium-containing IV solutions — CONTRAINDICATED). In adults with biliary stents and adequate flow, ceftriaxone is generally safe.","Blood culture yield in cholangitis is HIGH: Unlike cellulitis (2-5%), cholangitis has bacteremia rates of 30-50%. Always obtain blood cultures before antibiotics. Positive blood cultures guide duration (minimum 7-14 days for Enterobacterales bacteremia) and may reveal organisms not seen in bile cultures.","Percutaneous cholecystostomy tube: For patients too ill for cholecystectomy (Grade III cholecystitis, poor surgical candidates), IR-guided percutaneous cholecystostomy provides biliary decompression. Antibiotics + percutaneous drainage is the bridge strategy. Pharmacists should anticipate prolonged antibiotic courses in these patients since definitive source control is delayed."]}],drugMonographs:[{id:"metronidazole",name:"Metronidazole",brandNames:"Flagyl",drugClass:"Nitroimidazole antibiotic",mechanismOfAction:"Prodrug that is reduced intracellularly in anaerobic organisms to form reactive intermediates (nitroso free radicals and hydroxylamine). These intermediates damage DNA through strand breakage, inhibiting nucleic acid synthesis and causing cell death. Bactericidal with concentration-dependent killing. Requires LOW oxygen environment for activation — this is why it ONLY works against anaerobes and certain microaerophilic organisms. Has no activity against aerobes (the prodrug is never activated).",spectrum:"ANAEROBES ONLY (with few exceptions). Gram-negative anaerobes: Bacteroides fragilis group (>99% susceptibility — the GOLD STANDARD anti-Bacteroides agent), Prevotella, Fusobacterium. Gram-positive anaerobes: Clostridium species (including C. difficile — oral metronidazole is a treatment option), Peptostreptococcus. Protozoa: Giardia, Entamoeba histolytica, Trichomonas vaginalis. GAPS: ALL aerobes (no activity against Enterobacterales, Staphylococci, Streptococci, Pseudomonas), Propionibacterium (Cutibacterium) acnes, Actinomyces, Lactobacillus.",dosing:{iai:"500mg IV/PO q8h (or 1g IV q12h loading for severe infections)",c_diff:"500mg PO TID × 10-14 days (now second-line per IDSA 2021 — vancomycin PO preferred)",brain_abscess:"500mg IV q8h (excellent CNS penetration)",h_pylori:"500mg PO BID (in combination regimens)",surgical_prophylaxis:"500mg IV within 60 min before incision (combined with cefazolin for colorectal procedures)",bv_trichomoniasis:"500mg PO BID × 7 days (BV), 2g PO single dose (trichomoniasis)"},renalAdjustment:"No dose adjustment for standard renal impairment. Hemodialysis: metronidazole is dialyzable — dose after HD. Supplemental dose after HD recommended.",hepaticAdjustment:"SIGNIFICANT: Metronidazole is hepatically metabolized. In severe hepatic impairment (Child-Pugh C), clearance is reduced by 50% — reduce dose to q12h or use alternative. Monitor for neurotoxicity in liver disease.",adverseEffects:{common:"Metallic taste (very common — warn patients), nausea/vomiting (10-15%), anorexia, headache, dark urine (harmless — warn patients to expect this)",serious:"Peripheral neuropathy (dose-related and duration-related — usually after >4 weeks of cumulative therapy; presents as numbness/tingling in extremities; may be irreversible if not caught early), seizures (rare), optic neuropathy",rare:"CNS toxicity (cerebellar toxicity — ataxia, dysarthria, particularly in high-dose or prolonged courses), pancreatitis, neutropenia (reversible), Stevens-Johnson Syndrome"},drugInteractions:["DISULFIRAM-LIKE REACTION WITH ALCOHOL: Metronidazole inhibits aldehyde dehydrogenase. Consuming alcohol during therapy (or within 48-72h after completing) causes severe nausea, vomiting, flushing, headache, and abdominal cramps. COUNSEL EVERY PATIENT about alcohol avoidance. This includes alcohol-containing medications, mouthwashes, and hand sanitizers (theoretical concern with heavy exposure).","Warfarin — metronidazole is a potent CYP2C9 inhibitor. INCREASES warfarin effect significantly (INR can double or triple). Monitor INR closely and reduce warfarin dose proactively. This is one of the most clinically significant antibiotic-warfarin interactions.","Lithium — metronidazole reduces lithium renal clearance, increasing lithium levels. Monitor lithium levels if co-administered.","Phenytoin/fosphenytoin — metronidazole inhibits phenytoin metabolism. Monitor phenytoin levels.","Disulfiram — avoid combination. Psychotic reactions have been reported.","Busulfan — metronidazole may increase busulfan levels. Avoid combination if possible."],monitoring:"Neurological assessment: monitor for peripheral neuropathy symptoms (numbness, tingling, paresthesias) — especially in courses >2 weeks. If symptoms develop, STOP metronidazole immediately. Liver function (baseline if hepatic impairment). INR if on warfarin (within 3-5 days of starting metronidazole). No drug level monitoring needed.",pregnancyLactation:"Category B. Historically avoided in first trimester due to theoretical mutagenicity concerns, but large meta-analyses have NOT shown increased birth defect risk. Acceptable for use in pregnancy when benefits outweigh risks (e.g., trichomoniasis, severe anaerobic infections). Enters breast milk — AAP considers compatible but some recommend pump-and-dump for 12-24h after single high-dose treatment.",pharmacistPearls:["ORAL BIOAVAILABILITY IS ~100%: Metronidazole IV and PO are essentially interchangeable. If a patient is tolerating oral medications, there is ZERO reason to continue IV metronidazole. IV-to-PO conversion is one of the easiest stewardship wins. The PO formulation achieves identical serum levels, identical tissue penetration, and costs a fraction of IV.","Warfarin interaction is SEVERE and predictable: Every patient on warfarin who starts metronidazole will have a rising INR. This is not a 'possible' interaction — it is pharmacologically inevitable (CYP2C9 inhibition). Proactively reduce warfarin dose by 25-50% when starting metronidazole and check INR within 3-5 days. Setting up monitoring at the time of metronidazole initiation prevents bleeding events.","Peripheral neuropathy is the dose-limiting toxicity: Unlike most antibiotic adverse effects that resolve upon discontinuation, metronidazole-induced peripheral neuropathy can be IRREVERSIBLE if not caught early. The risk increases with cumulative dose and duration (typically >4 weeks). Monitor for numbness/tingling and discontinue immediately if symptoms develop. For IAI courses (4-7 days), this is not a concern — it becomes relevant for prolonged courses (brain abscess, C. diff retreatment).","Metronidazole has EXCELLENT CNS penetration: It crosses the blood-brain barrier effectively, achieving CSF levels 40-100% of serum. This makes it the drug of choice for the anaerobic component of brain abscess therapy (usually combined with ceftriaxone for the aerobic component). Very few antibiotics penetrate the CNS this well.","C. diff treatment hierarchy: Metronidazole has been DEMOTED from first-line C. diff treatment. IDSA/SHEA 2021 guidelines: vancomycin PO or fidaxomicin PO are preferred over metronidazole for all C. diff episodes. Metronidazole is now reserved for initial non-severe C. diff when vancomycin/fidaxomicin are not accessible. Oral vancomycin 125mg QID is the standard.","The alcohol interaction is real but the risk window is debated: The traditional teaching is to avoid alcohol for 48-72h after metronidazole. Some pharmacology references suggest the disulfiram-like reaction may be less consistent than previously thought. Regardless, it's best practice to counsel patients to avoid alcohol during treatment and for at least 48h after. The consequences of the reaction (severe vomiting, cardiovascular effects) are significant enough that the counsel is justified."]},{id:"ampicillin-sulbactam-iai",name:"Ampicillin-Sulbactam",brandNames:"Unasyn",drugClass:"Aminopenicillin + beta-lactamase inhibitor",mechanismOfAction:"Ampicillin binds PBPs, inhibiting cell wall synthesis (bactericidal, time-dependent). Sulbactam is a beta-lactamase inhibitor that irreversibly binds and inactivates many Class A beta-lactamases (TEM, SHV), protecting ampicillin from enzymatic degradation. Sulbactam also has INTRINSIC antimicrobial activity against Acinetobacter species — this is pharmacologically unique and clinically relevant for MDR Acinetobacter infections where sulbactam itself is the active agent.",spectrum:"Gram-positive: Streptococci (excellent), MSSA, Enterococcus faecalis (ampicillin is drug of choice for susceptible Enterococcus). Gram-negative: E. coli, Klebsiella, Proteus, H. influenzae (including beta-lactamase producers). Acinetobacter (sulbactam component). Anaerobes: good — Bacteroides fragilis (70-80% susceptibility), Peptostreptococcus, Clostridium. GAPS: MRSA, ESBL producers (sulbactam does not inhibit ESBLs effectively), AmpC producers (Enterobacter, Citrobacter, Serratia), Pseudomonas (no activity), VRE (E. faecium usually ampicillin-resistant).",dosing:{standard:"3g (2g ampicillin + 1g sulbactam) IV q6h",iai:"3g IV q6h",aspiration_pneumonia:"3g IV q6h (one of few agents covering oral anaerobes + aerobes for aspiration)",acinetobacter:"9g IV q8h (high-dose sulbactam — 3g sulbactam per dose, given as 9g amp-sulb q8h or using sulbactam separately)",pelvic_infections:"3g IV q6h",max_daily:"12g/day (8g ampicillin + 4g sulbactam)"},renalAdjustment:"CrCl 15-29: 3g IV q12h. CrCl 5-14: 3g IV q24h. Hemodialysis: 3g IV q24h (dose after HD on dialysis days). Both ampicillin and sulbactam are renally eliminated.",hepaticAdjustment:"No adjustment needed — renally eliminated.",adverseEffects:{common:"Diarrhea (9%), rash (2-5%), injection site pain/phlebitis, nausea",serious:"C. difficile colitis, hypersensitivity reactions (cross-reactive with penicillin — same beta-lactam ring), seizures (high doses or renal impairment), interstitial nephritis, hemolytic anemia",rare:"Anaphylaxis (0.01-0.05%), Stevens-Johnson Syndrome, acute generalized exanthematous pustulosis (AGEP)",contraindications:"History of serious penicillin allergy (anaphylaxis, angioedema, severe urticaria). Infectious mononucleosis (ampicillin causes characteristic maculopapular rash in 70-100% of mono patients)."},drugInteractions:["Allopurinol — increases incidence of ampicillin rash (not a true allergy — mechanism unclear but well-documented).","Warfarin — ampicillin may enhance anticoagulant effect through vitamin K-related mechanism. Monitor INR.","Methotrexate — ampicillin reduces renal clearance of methotrexate, increasing levels and toxicity. Monitor methotrexate levels and renal function.","Oral contraceptives — theoretical reduction in efficacy (disruption of enterohepatic circulation of estrogen). Clinical significance debated but counsel patients about backup contraception."],monitoring:"Renal function (for dose adjustment). CBC (prolonged courses — leukopenia risk). Clinical response. Hepatic function (rare hepatotoxicity). Rash assessment (distinguish allergic rash from ampicillin-associated rash in EBV infection).",pregnancyLactation:"Category B. Widely used in pregnancy — particularly for IAI and pelvic infections. Compatible with breastfeeding.",pharmacistPearls:["RISING E. COLI RESISTANCE LIMITS UTILITY: E. coli susceptibility to ampicillin-sulbactam has declined to 60-80% in many US institutions. Before using as empiric therapy, CHECK YOUR LOCAL ANTIBIOGRAM. If E. coli susceptibility is <80%, consider ceftriaxone + metronidazole or ertapenem as more reliable empiric choices for IAI.","Aspiration pneumonia coverage: Amp-sulbactam is one of the few single agents that covers the mixed flora of aspiration pneumonia (oral anaerobes + aerobic streptococci + enteric gram-negatives). IDSA CAP guidelines: for aspiration pneumonia with risk of anaerobic infection, amp-sulbactam is a reasonable monotherapy option.","Sulbactam for Acinetobacter: Sulbactam has intrinsic activity against Acinetobacter baumannii independent of ampicillin. For MDR/XDR Acinetobacter, high-dose sulbactam (total 4g/day or more, achieved through high-dose amp-sulb or IV sulbactam where available) is a treatment option, usually combined with other agents (polymyxins, tigecycline, meropenem). The new agent durlobactam-sulbactam (Xacduro, FDA approved 2023) specifically leverages sulbactam's Acinetobacter activity.","Q6h dosing is a compliance barrier: The q6h IV dosing schedule makes amp-sulbactam less convenient than alternatives like ertapenem (daily) or ceftriaxone (daily). For OPAT, this is a significant disadvantage. If transitioning to outpatient therapy, consider switching to an agent with less frequent dosing rather than continuing amp-sulb via home infusion q6h.","The Enterococcal advantage: Amp-sulb is one of the few first-line IAI agents with intrinsic Enterococcus faecalis coverage (via the ampicillin component). For biliary IAI or situations where Enterococcal coverage is specifically desired, amp-sulb provides this without adding a separate agent. Pip-tazo also covers E. faecalis but through a different mechanism.","Do NOT use for ESBL infections: Sulbactam does NOT effectively inhibit ESBLs (CTX-M, TEM variants, SHV variants). Isolates reported as 'ampicillin-sulbactam resistant' but 'pip-tazo susceptible' reflect the different beta-lactamase inhibitor profiles. For suspected or confirmed ESBL: use carbapenems."]},{id:"ertapenem",name:"Ertapenem",brandNames:"Invanz",drugClass:"Group 1 Carbapenem (narrow-spectrum carbapenem)",mechanismOfAction:"Binds PBPs (PBP-2, PBP-3, PBP-4), inhibiting cell wall synthesis. Bactericidal, time-dependent killing (T>MIC drives efficacy). Unlike broader carbapenems (meropenem, imipenem), ertapenem does NOT effectively bind PBP-2 of Pseudomonas aeruginosa or PBPs of Acinetobacter/Enterococcus — this is why it lacks activity against these organisms. Highly stable against most beta-lactamases including ESBLs and AmpC enzymes. NOT hydrolyzed by most metallo-beta-lactamases or KPC carbapenemases (resistance pattern differs from meropenem).",spectrum:"Broad but with defined gaps. Gram-positive: Streptococci (excellent), MSSA. Gram-negative: E. coli (including ESBL), Klebsiella (including ESBL), Proteus, Citrobacter, Serratia, H. influenzae, M. catarrhalis. Anaerobes: excellent — B. fragilis (>95%), Peptostreptococcus, Clostridium, Prevotella, Fusobacterium. DEFINED GAPS: Pseudomonas (NO activity), Acinetobacter (NO activity), Enterococcus (NO activity), MRSA (NO activity). These gaps are FEATURES, not bugs — they mean ertapenem exerts less selection pressure for Pseudomonas/Acinetobacter resistance compared to meropenem.",dosing:{standard:"1g IV/IM once daily",iai:"1g IV once daily",uti:"1g IV once daily",cap:"1g IV once daily",diabetic_foot:"1g IV once daily",surgical_prophylaxis:"1g IV within 60 min before incision (colorectal procedures)"},renalAdjustment:"CrCl >30: no adjustment. CrCl <=30 (including HD): 500mg IV once daily. Give supplemental 150mg after hemodialysis if daily dose was given >6h before HD. One of the simplest renal adjustments among carbapenems.",hepaticAdjustment:"No dose adjustment needed. Ertapenem undergoes minimal hepatic metabolism.",adverseEffects:{common:"Diarrhea (10%), nausea (8%), headache, infusion site reactions (5-7%)",serious:"C. difficile colitis, seizures (0.5% — lower than imipenem, comparable to meropenem), hypersensitivity/anaphylaxis",rare:"Hallucinations (reported, mechanism unclear), hepatitis, thrombocytopenia, neutropenia"},drugInteractions:["Valproic acid — ALL carbapenems (including ertapenem) reduce VPA levels by 60-100% within 24h. HARD STOP: switch VPA to levetiracetam before starting any carbapenem.","Probenecid — inhibits renal tubular secretion of ertapenem, increasing levels by ~25%. Generally not clinically significant but be aware.","Warfarin — carbapenems may enhance anticoagulant effect. Monitor INR."],monitoring:"Renal function (for dose adjustment). Clinical response. Seizure monitoring (lower risk than imipenem but still present, especially in renal impairment or CNS disease). No drug level monitoring needed.",pregnancyLactation:"Category B. Limited human pregnancy data. Animal studies showed no harm. Use only if clearly needed. Excreted in breast milk — use with caution.",pharmacistPearls:["ERTAPENEM IS NOT MEROPENEM — AND THAT'S THE POINT: Ertapenem deliberately lacks Pseudomonas and Acinetobacter activity. This means: (1) less selection pressure for MDR Pseudomonas and Acinetobacter, (2) appropriate for community-acquired IAI where these organisms are rare, (3) preserves the ecological niche that broader carbapenems disrupt. Using meropenem when ertapenem would suffice is antibiotic misuse — it provides no additional benefit while increasing resistance selection.","OPAT SUPERSTAR: Once-daily IV dosing makes ertapenem the ideal OPAT carbapenem. For community-acquired IAI, diabetic foot infections, or complicated UTI being treated with home infusion, ertapenem reduces nursing visits to once daily. Compare: meropenem q8h (3 infusions/day) vs ertapenem q24h (1 infusion/day). Cost and convenience difference is dramatic.","IM administration is an option: Ertapenem can be given intramuscularly (1g IM once daily, reconstituted with lidocaine). This is unique among carbapenems and useful for patients without IV access or for OPAT when port/PICC is not feasible. Absorbed well from IM site with bioavailability approaching IV.","ESBL coverage WITHOUT Pseudomonal selection: For confirmed ESBL infections where Pseudomonas is not a concern (community-acquired IAI, UTI), ertapenem is the preferred carbapenem. It achieves the same ESBL killing as meropenem without the ecological cost. This is a cornerstone of carbapenem stewardship: use ertapenem for non-Pseudomonal ESBL, reserve meropenem for when you NEED Pseudomonal coverage.","Colorectal surgical prophylaxis: Ertapenem 1g IV is FDA-approved for colorectal surgical prophylaxis. Studies showed superior SSI prevention compared to cefotetan. The once-daily dosing eliminates the need for intra-operative redosing. However, some stewardship programs discourage routine carbapenem prophylaxis due to resistance concerns — institutional guidelines vary.","Valproic acid interaction applies to ALL carbapenems: The VPA-carbapenem interaction is pharmacological, not just a meropenem issue. Ertapenem reduces VPA levels just as dramatically (60-100% reduction). Even short courses of ertapenem with VPA risk breakthrough seizures. The solution is always the same: switch VPA to levetiracetam before starting the carbapenem."]}]},p={id:"amr-gn",name:"AMR Gram-Negative Infections",icon:"🛡️",category:"Antimicrobial Resistance — IDSA 2024 Guidance (Tamma et al.)",overview:{definition:"The IDSA 2024 Guidance on the Treatment of Antimicrobial-Resistant Gram-Negative Infections (Tamma et al., CID 2024, v4.0) is the definitive US resource for managing resistant gram-negative pathogens. It covers six resistance phenotypes: ESBL-E, AmpC-E, CRE, DTR P. aeruginosa, CRAB, and S. maltophilia. This is NOT a disease-state guideline — it is a RESISTANCE-PATTERN guideline. It assumes the causative organism and susceptibilities are KNOWN, and provides preferred/alternative agent selection stratified by site of infection (cystitis vs pyelonephritis/cUTI vs non-urinary). The key principle: treatment selection should be guided by the specific resistance mechanism, not just the organism name.",epidemiology:"AMR gram-negatives caused >2.8 million infections and >35,000 deaths annually in the US (2012-2017, CDC). ESBL-E are the most common resistance phenotype encountered in clinical practice — CTX-M-15 is the dominant ESBL in the US. CRE are classified as an urgent threat by the CDC. KPC is the dominant US carbapenemase (~80-86% of carbapenemase-producing CRE), but MBL prevalence (NDM, VIM, IMP) is RISING (from 4% to 20% of CRE between 2019-2021). DTR P. aeruginosa (non-susceptible to all standard beta-lactams, FQs, and carbapenems) represents the most challenging Pseudomonal infections. CRAB carries the highest crude mortality of any gram-negative resistance phenotype (40-60%).",keyGuidelines:[{name:"IDSA 2024 AMR Guidance v4.0 (Tamma et al., CID 2024)",detail:"Fourth iteration of the living guidance document. Panel of 6 ID specialists. Key updates from v3.0 (2023): sulbactam-durlobactam added as preferred for CRAB, high-dose amp-sulb downgraded to alternative for CRAB, MBL prevalence increasing in US acknowledged, cefepime MIC 4-8 concern for AmpC-E removed, ceftolozane-tazobactam acknowledged as likely effective for ESBL-E but reserved for DTR-PA. Current as of December 31, 2023. Updated annually at idsociety.org/practice-guideline/amr-guidance/."},{name:"MERINO Trial (Harris et al., JAMA 2018)",detail:"Landmark RCT: pip-tazo vs meropenem for ESBL-E bloodstream infections. 30-day mortality 12.3% (pip-tazo) vs 3.7% (meropenem). Pip-tazo FAILED non-inferiority. Established carbapenems as standard of care for serious ESBL-E infections. Even on reanalysis restricting to pip-tazo MIC <=16, risk difference still favored meropenem (9% vs 4%). Practice-changing: do NOT use pip-tazo for serious ESBL-E infections."},{name:"CLSI Breakpoint Updates (2022-2024)",detail:"Pip-tazo Enterobacterales breakpoints lowered (2022): susceptible <=8/4, susceptible dose-dependent 16. Aminoglycoside breakpoints revised (2023). Ceftazidime breakpoints for S. maltophilia removed (2024). Broth disk elution method endorsed for testing ceftazidime-avibactam/aztreonam combination against MBL-producers and S. maltophilia."},{name:"CDC Antibiotic Resistance Threats Report (2019)",detail:"Classified resistance threats by urgency. URGENT: CRE, CRAB, C. auris. SERIOUS: ESBL-E, DTR P. aeruginosa, S. maltophilia (not formally classified but covered in IDSA guidance). Guides national stewardship priorities and funding allocation."}],landmarkTrials:[{name:"MERINO (Harris et al., 2018 JAMA)",detail:"391 patients with ceftriaxone-non-susceptible E. coli/K. pneumoniae BSI (87% confirmed ESBL). Pip-tazo 4.5g q6h vs meropenem 1g q8h (both standard infusion). 30-day mortality: 12.3% vs 3.7%. Pip-tazo failed non-inferiority. Cemented carbapenems as preferred for serious ESBL-E. Key nuance: standard infusion was used — extended infusion pip-tazo was NOT tested."},{name:"TANGO II (Wunderink et al., 2018 CID)",detail:"Meropenem-vaborbactam vs best available therapy (BAT, often polymyxin-based) for CRE infections. Clinical cure 59% vs 26%. 28-day mortality 16% vs 33%. Demonstrated superiority of novel BL-BLI agents over polymyxin-based regimens for CRE."},{name:"TANGO III / CREDIBLE-CR (Bassetti et al., 2021 Lancet ID)",detail:"Cefiderocol vs BAT for carbapenem-resistant infections (CRE, CRAB, DTR-PA). All-cause mortality numerically higher with cefiderocol in CRAB subgroup, raising caution about cefiderocol monotherapy for CRAB. Supported cefiderocol use for CRE and DTR-PA but led to recommendation for combination therapy for CRAB."},{name:"RESTORE-IMI 1 (Motsch et al., 2020 CID)",detail:"Imipenem-cilastatin-relebactam vs imipenem + colistin for imipenem-non-susceptible infections. Favorable response 71% vs 40%. Supported imipenem-relebactam for CRE and DTR-PA with lower toxicity than colistin-based regimens."},{name:"ATTACK Trial (Kaye et al., 2023 Lancet ID)",detail:"Sulbactam-durlobactam + imipenem-cilastatin vs colistin + imipenem-cilastatin for CRAB. 28-day mortality 19% vs 32%. Led to FDA approval of sulbactam-durlobactam (Xacduro) and its addition as preferred agent for CRAB in 2024 guidance update."},{name:"Observational: Ceftazidime-avibactam + Aztreonam for MBL (Falcone et al., 2021)",detail:"102 patients with MBL-producing Enterobacterales BSI. Ceftazidime-avibactam + aztreonam vs other regimens. 30-day mortality 19% vs 44%. Established caz-avi + aztreonam as preferred treatment for MBL-CRE pending FDA-approved aztreonam-avibactam."}],riskFactors:"Risk factors for AMR gram-negatives: prior antibiotic exposure (especially FQs, cephalosporins) within 90 days, prior MDR culture within 12 months, recent hospitalization (>48h in past 90 days), residence in long-term care facility, international travel (especially South/Southeast Asia for ESBL/NDM), presence of indwelling devices (urinary catheters, central lines), immunosuppression, recurrent UTIs, prior organ transplant, chronic wounds, ICU stay, mechanical ventilation (for DTR-PA, CRAB)."},subcategories:[{id:"esbl-e",name:"ESBL-Producing Enterobacterales (ESBL-E)",definition:"ESBLs are enzymes that hydrolyze most penicillins, cephalosporins, and aztreonam. CTX-M-15 is the dominant ESBL in the US. Most prevalent in E. coli, K. pneumoniae, K. oxytoca, and P. mirabilis. ESBL-E generally remain susceptible to carbapenems. Non-susceptibility to ceftriaxone (MIC >=2) is used as a proxy for ESBL production. IDSA 2024: Carbapenems are preferred for serious ESBL-E infections outside the urinary tract. Pip-tazo is NOT recommended (MERINO). Cefepime is NOT recommended for ESBL-E even if susceptible.",clinicalPresentation:"ESBL-E cause the same clinical syndromes as susceptible Enterobacterales — UTIs, bacteremia, IAI, pneumonia, SSTIs. The difference is not the presentation but the TREATMENT. Suspect ESBL when: prior ESBL culture, recent cephalosporin/FQ exposure, travel to endemic areas, recurrent UTIs with resistance, nursing home residence. The microbiology lab identifies ESBL via ceftriaxone non-susceptibility (MIC >=2) — routine ESBL confirmatory testing is not performed at most labs.",diagnostics:"Identified by antimicrobial susceptibility testing: ceftriaxone non-susceptible (MIC >=2) is used as a proxy for ESBL production. Molecular testing (PCR for blaCTX-M, blaTEM, blaSHV genes) confirms ESBL type but is not routine. CLSI breakpoints guide interpretation. KEY: pip-tazo MIC testing may be INACCURATE for ESBL-E (poor reproducibility with commercial AST methods) — susceptibility on the report does NOT guarantee clinical efficacy.",empiricTherapy:[{line:"Preferred — Uncomplicated Cystitis",options:[{drug:"nitrofurantoin",regimen:"Nitrofurantoin 100mg PO BID × 5 days",notes:"IDSA 2024 preferred for ESBL-E uncomplicated cystitis. NOT affected by ESBL enzymes (different mechanism). Achieves high urinary concentrations. Does NOT achieve systemic levels — for cystitis ONLY, never for pyelonephritis or bacteremia."},{drug:"tmp-smx",regimen:"TMP-SMX DS 1 tab PO BID × 3 days",notes:"IDSA 2024 preferred for ESBL-E uncomplicated cystitis IF susceptible. Not a beta-lactam — unaffected by ESBLs. Co-resistance is common (ESBL-E often carry additional resistance genes), so susceptibility must be confirmed."}]},{line:"Preferred — Pyelonephritis / Complicated UTI",options:[{drug:"tmp-smx",regimen:"TMP-SMX DS 1 tab PO BID × 5-7 days",notes:"IDSA 2024 preferred for ESBL-E pyelonephritis/cUTI if susceptible. High urinary AND renal parenchymal concentrations. Oral step-down target from carbapenems. Achieves adequate serum levels for tissue penetration."},{drug:"ciprofloxacin",regimen:"Ciprofloxacin 500mg PO BID × 5-7 days (or Levofloxacin 750mg PO daily)",notes:"IDSA 2024 preferred for ESBL-E pyelonephritis/cUTI if susceptible. High bioavailability. However, ESBL-E frequently co-resistant to FQs. Reserve for confirmed susceptible isolates to limit further FQ selection pressure."},{drug:"ertapenem",regimen:"Ertapenem 1g IV daily",notes:"IDSA 2024 preferred when TMP-SMX/FQ are not options (resistance or toxicity). Transition to oral TMP-SMX or FQ when susceptible and clinically improving. NOT for critically ill or hypoalbuminemic patients — use meropenem instead."}]},{line:"Preferred — Non-Urinary Infections (BSI, IAI, Pneumonia)",options:[{drug:"meropenem",regimen:"Meropenem 1g IV q8h (extended infusion over 3h)",notes:"IDSA 2024 preferred for ESBL-E infections outside urinary tract. MERINO trial standard of care. Extended infusion optimizes T>MIC. For critically ill or hypoalbuminemic patients, use meropenem or imipenem — NOT ertapenem."},{drug:"ertapenem",regimen:"Ertapenem 1g IV daily",notes:"IDSA 2024 preferred for non-critically ill with normal albumin. Once-daily dosing ideal for OPAT. Ertapenem clearance increases with hypoalbuminemia (highly protein-bound) — observational data showed 5× higher mortality in hypoalbuminemic patients receiving ertapenem vs meropenem."}]},{line:"Avoid for ESBL-E (Even If Susceptible on Report)",options:[{drug:"pip-tazo-avoid",regimen:"Piperacillin-tazobactam — NOT recommended for ESBL-E",notes:"MERINO trial: pip-tazo FAILED non-inferiority vs meropenem for ESBL-E BSI (12% vs 4% mortality). Mechanistic concerns: tazobactam may not reliably inhibit ESBLs (low tazobactam:piperacillin ratio of 1:8, MIC testing unreliable, inoculum effect). In vitro susceptibility does NOT guarantee clinical efficacy. Exception: if pip-tazo was started empirically for uncomplicated cystitis and patient improves, no change needed."},{drug:"cefepime-avoid",regimen:"Cefepime — NOT recommended for ESBL-E",notes:"ESBLs commonly hydrolyze cefepime. Cefepime MIC testing unreliable for ESBL-E. Clinical trial arm terminated early for high failure signal in ESBL-E pyelonephritis/cUTI despite MICs of 1-2. Observational data show poorer outcomes vs carbapenems for invasive ESBL-E. Do NOT trust cefepime susceptibility for confirmed ESBL-E."}]}],organismSpecific:[{organism:"ESBL-E — Uncomplicated Cystitis",preferred:"Nitrofurantoin, TMP-SMX",alternative:"FQs, single-dose aminoglycoside, fosfomycin (E. coli only), carbapenems",notes:"For cystitis: use narrow-spectrum agents. Nitrofurantoin and TMP-SMX are unaffected by ESBLs. Reserve carbapenems and FQs for when narrow agents are not active. Fosfomycin only for E. coli (other species carry fosA gene = intrinsic resistance). Doxycycline NOT recommended for ESBL-E cystitis (limited urinary excretion)."},{organism:"ESBL-E — Pyelonephritis / Complicated UTI",preferred:"TMP-SMX, FQs (if susceptible); carbapenems (if TMP-SMX/FQ not options)",alternative:"Aminoglycosides (once-daily, duration-limited)",notes:"Step down to oral TMP-SMX or FQ whenever possible. Carbapenems for initial therapy if severely ill, then de-escalate. Nitrofurantoin and fosfomycin do NOT achieve adequate renal parenchymal concentrations — never use for pyelonephritis."},{organism:"ESBL-E — Non-Urinary (BSI, IAI, Pneumonia)",preferred:"Meropenem, imipenem-cilastatin (critically ill/hypoalbuminemic); ertapenem (stable, normal albumin)",alternative:"Oral step-down to TMP-SMX or FQ after clinical improvement",notes:"MERINO established carbapenems as the standard. Step down to oral agents aggressively. Novel BL-BLIs (caz-avi, mer-vab, imi-rele) are effective but should be RESERVED for CRE. Using caz-avi for ESBL-E is wasteful stewardship."}],pearls:["MERINO IS THE DEFINING TRIAL: Pip-tazo failed non-inferiority to meropenem for ESBL-E BSI. This is not a debatable point — it's a completed, well-designed RCT. When someone wants to use pip-tazo for ESBL-E bacteremia because 'it was susceptible on the report,' cite MERINO. The AST result is unreliable for ESBL-E with pip-tazo.","Pip-tazo susceptibility is MECHANISTICALLY unreliable for ESBL-E: The tazobactam:piperacillin ratio in a dose (1:8) means relatively little inhibitor is present. With high ESBL expression, increased inoculum, or multiple beta-lactamases, tazobactam is overwhelmed. MIC testing doesn't capture this — 94% of MERINO isolates were pip-tazo 'susceptible' by current breakpoints, yet pip-tazo still failed.","Ertapenem vs meropenem selection matters: Ertapenem is highly protein-bound (92-95%). Hypoalbuminemia increases free drug, increases clearance, decreases half-life — potentially leading to subtherapeutic levels. Observational data showed 5× higher mortality in hypoalbuminemic patients (albumin <2.5) receiving ertapenem vs meropenem. Rule: critically ill or albumin <2.5 → meropenem. Stable outpatient with normal albumin → ertapenem (OPAT-friendly).","Cefepime for ESBL-E: DON'T. A randomized trial for ESBL-E pyelonephritis TERMINATED the cefepime arm early for high clinical failure, even with cefepime MICs of 1-2. This is not just about MIC accuracy — ESBLs hydrolyze cefepime, and commercial AST may not reliably detect this. Cefepime is for AmpC-E, not ESBL-E.","ORAL STEP-DOWN IS THE GOAL: The biggest stewardship win in ESBL-E management is transitioning from carbapenem to oral TMP-SMX or FQ. Multiple observational studies support oral step-down for ESBL-E BSI after clinical milestones (hemodynamically stable, source controlled, susceptibility confirmed). Every day of unnecessary carbapenem selects for CRE.","Novel BL-BLIs for ESBL-E = stewardship failure: Caz-avi, mer-vab, and imi-rele are all active against ESBL-E but should be RESERVED for CRE. Using these agents for ESBL-E when a standard carbapenem would suffice wastes the agents we need for much harder-to-treat CRE infections."]},{id:"ampc-e",name:"AmpC β-Lactamase-Producing Enterobacterales (AmpC-E)",definition:"AmpC β-lactamases are chromosomally encoded enzymes that hydrolyze cephalosporins when overexpressed. The IDSA 2024 guidance identifies three organisms at MODERATE risk for clinically significant inducible AmpC production: Enterobacter cloacae complex, Klebsiella aerogenes, and Citrobacter freundii. Key concept: an isolate may initially test SUSCEPTIBLE to ceftriaxone, but exposure to ceftriaxone INDUCES ampC expression → resistance emerges during treatment (~20% risk). Cefepime is the preferred agent — it is both a weak ampC inducer AND resistant to AmpC hydrolysis. The old SPACE/SPICE mnemonics are oversimplified and outdated.",clinicalPresentation:"Same clinical syndromes as other Enterobacterales. The clinical challenge is not the presentation but the TREATMENT TRAP: cultures return susceptible to ceftriaxone, clinician starts ceftriaxone, resistance emerges during therapy, patient fails treatment. This is the classic AmpC story and occurs in ~20% of E. cloacae/K. aerogenes/C. freundii infections treated with ceftriaxone.",diagnostics:"Routine AST identifies susceptibility patterns. There is NO CLSI-endorsed test for AmpC detection in clinical isolates. The pharmacist must KNOW which organisms carry inducible ampC genes and intervene regardless of reported ceftriaxone susceptibility. If the lab reports 'E. cloacae susceptible to ceftriaxone,' YOUR job is to flag this and recommend cefepime instead.",empiricTherapy:[{line:"Preferred — Invasive Infections (E. cloacae, K. aerogenes, C. freundii)",options:[{drug:"cefepime",regimen:"Cefepime 2g IV q8h (extended infusion over 3h)",notes:"IDSA 2024 preferred for AmpC-E infections. Weak ampC inducer AND stable against AmpC hydrolysis (forms stable acyl enzyme complexes). Observational studies and meta-analysis show similar outcomes to carbapenems. No clinical trial exists comparing cefepime vs carbapenem for AmpC-E, but mechanism and observational data strongly support cefepime. CARBAPENEM-SPARING — this is the critical stewardship advantage."},{drug:"meropenem",regimen:"Meropenem 1g IV q8h (extended infusion)",notes:"Carbapenems are stable against AmpC hydrolysis. Use for AmpC-E when cefepime cannot be used (allergy, cefepime neurotoxicity, polymicrobial infection requiring broader coverage). Imipenem is a potent ampC inducer but remains stable to hydrolysis. Ertapenem reasonable for stable, non-critically ill."}]},{line:"Preferred — Uncomplicated Cystitis",options:[{drug:"nitrofurantoin",regimen:"Nitrofurantoin 100mg PO BID × 5 days",notes:"IDSA 2024 preferred for AmpC-E uncomplicated cystitis. Not a beta-lactam — unaffected by AmpC. Ceftriaxone is also acceptable for uncomplicated cystitis (high urinary concentrations overcome AmpC concerns)."},{drug:"tmp-smx",regimen:"TMP-SMX DS 1 tab PO BID × 3 days",notes:"IDSA 2024 preferred for AmpC-E cystitis if susceptible. Not a beta-lactam substrate."}]},{line:"Avoid for Invasive AmpC-E Infections",options:[{drug:"ceftriaxone-avoid",regimen:"Ceftriaxone — NOT recommended for invasive E. cloacae, K. aerogenes, C. freundii",notes:"EVEN IF SUSCEPTIBLE on initial AST. ~20% resistance emergence during therapy. Ceftriaxone is a substrate for AmpC hydrolysis — once ampC is induced/derepressed, ceftriaxone fails. This is the most common AmpC treatment error. Exception: uncomplicated cystitis (high urinary concentrations) or step-down after clear clinical improvement with no ongoing source."},{drug:"pip-tazo-ampc-avoid",regimen:"Piperacillin-tazobactam — NOT recommended for invasive AmpC-E infections",notes:"Tazobactam is a POOR inhibitor of AmpC enzymes (unlike avibactam/relebactam/vaborbactam). Multiple observational studies show poorer outcomes with pip-tazo vs cefepime or carbapenems for AmpC-E bacteremia. Pilot RCT showed higher microbiological failure with pip-tazo vs meropenem for AmpC-E BSI."}]}],organismSpecific:[{organism:"E. cloacae complex, K. aerogenes, C. freundii (MODERATE AmpC risk)",preferred:"Cefepime, carbapenems (meropenem/ertapenem/imipenem)",alternative:"TMP-SMX, FQs (if susceptible, for oral step-down)",notes:"These three organisms: ~20% risk of resistance emergence on ceftriaxone. ALWAYS use cefepime or carbapenem for invasive infections regardless of ceftriaxone susceptibility. Basal AmpC production makes them intrinsically resistant to ampicillin, amoxicillin-clavulanate, amp-sulbactam, and first/second-gen cephalosporins."},{organism:"S. marcescens, M. morganii, Providencia spp. (LOW AmpC risk)",preferred:"Treat per AST results — ceftriaxone acceptable if susceptible",alternative:"Cefepime (if high bacterial burden or limited source control)",notes:"IDSA 2024: <5% clinically significant ampC induction. Treat according to AST. DO NOT reflexively avoid ceftriaxone for these organisms — the old SPACE mnemonic overestimates their AmpC risk. Exception: for high-inoculum infections (endocarditis, undrained abscess), reasonable to use cefepime over ceftriaxone even for these organisms."}],pearls:["CEFEPIME IS THE KEY DRUG FOR AmpC-E: It is both a weak inducer AND resistant to hydrolysis. This dual property makes it uniquely suited for AmpC-E. Carbapenems also work but are broader than necessary. Cefepime = carbapenem-sparing first-line for AmpC-E. This is a high-value stewardship intervention.","The SPACE/SPICE mnemonics are OUTDATED: These mnemonics lump organisms with very different ampC induction potential into one group. Serratia and Providencia have <5% induction risk — treating them like Enterobacter is stewardship overcorrection. IDSA 2024 simplifies it: MODERATE risk = E. cloacae, K. aerogenes, C. freundii. LOW risk = S. marcescens, M. morganii, Providencia. Treat accordingly.","Ceftriaxone susceptibility is a TRAP for E. cloacae: The isolate tests susceptible today. You start ceftriaxone. By day 3-5, ampC is induced, resistance emerges, the patient fails. This happens in ~20% of cases — that's 1 in 5 patients. The cost of using cefepime instead is zero additional toxicity and massively reduced risk of treatment failure.","Cefepime SDD (MIC 4-8) for AmpC-E: IDSA 2024 REMOVED the previous concern about cefepime MICs 4-8 indicating ESBL co-production. Updated data show no reliable correlation between cefepime SDD MICs and ESBL presence in AmpC-E. Cefepime 2g q8h extended infusion is appropriate for cefepime SDD isolates.","Pip-tazo is NOT a good AmpC-E agent: Tazobactam is a poor AmpC inhibitor compared to avibactam, relebactam, and vaborbactam. Observational studies consistently show higher failure rates with pip-tazo vs cefepime or carbapenems for AmpC-E BSI. Save pip-tazo for infections where AmpC is not a concern."]},{id:"cre-kpc",name:"CRE — KPC-Producing Enterobacterales",definition:"KPC (Klebsiella pneumoniae carbapenemase) is the dominant carbapenemase in the US, accounting for 80-86% of carbapenemase-producing CRE. KPC hydrolyzes all beta-lactams including carbapenems. It is inhibited by avibactam, vaborbactam, and relebactam — making the newer BL-BLI combinations the treatment of choice. The IDSA 2024 guidance slightly favors meropenem-vaborbactam, followed by ceftazidime-avibactam, then imipenem-cilastatin-relebactam, based on clinical outcomes data and resistance emergence risk.",clinicalPresentation:"CRE cause the same syndromes as other Enterobacterales but with dramatically higher mortality (30-50% for BSI). CDC classifies CRE as an URGENT threat. Common presentations: BSI (often from urinary or abdominal source), complicated UTI, hospital-acquired pneumonia, IAI. Most CRE infections are healthcare-associated — suspect in patients with recent hospitalization, ICU stays, prior broad-spectrum antibiotics, or residence in endemic facilities.",diagnostics:"AST identifies carbapenem non-susceptibility. Carbapenemase detection: phenotypic (modified carbapenem inactivation method — mCIM, distinguishes carbapenemase vs non-carbapenemase CRE) and molecular (PCR for blaKPC, blaNDM, blaVIM, blaIMP, blaOXA-48-like). IDSA strongly encourages labs to implement SPECIFIC carbapenemase identification — the choice of preferred agent depends on WHICH carbapenemase is present. Knowing 'CRE' is not enough; knowing 'KPC-producing CRE' drives treatment selection.",empiricTherapy:[{line:"Preferred — KPC-Producing CRE (Non-Urinary Infections)",options:[{drug:"meropenem-vaborbactam",regimen:"Meropenem-vaborbactam 4g IV q8h (extended infusion over 3h)",notes:"IDSA 2024: slightly favored among the three preferred agents. TANGO II trial: 59% clinical cure vs 26% with BAT for CRE. >95% activity against KPC-producing CRE. Vaborbactam is a potent boronic acid inhibitor of KPCs. Lowest resistance emergence risk of the three preferred agents. 4g = 2g meropenem + 2g vaborbactam per dose."},{drug:"ceftazidime-avibactam",regimen:"Ceftazidime-avibactam 2.5g IV q8h (infused over 2h)",notes:"IDSA 2024 preferred. >95% activity against KPC-CRE. Avibactam inhibits KPC, ESBL, AmpC, and OXA-48-like enzymes. Most clinical experience of any novel BL-BLI for CRE. CAUTION: higher resistance emergence risk than mer-vab (KPC mutations in omega loop can cause caz-avi resistance). 2.5g = 2g ceftazidime + 0.5g avibactam."},{drug:"imipenem-relebactam",regimen:"Imipenem-cilastatin-relebactam 1.25g IV q6h (infused over 30 min)",notes:"IDSA 2024 preferred. RESTORE-IMI 1: 71% favorable response vs 40% for imipenem + colistin. >95% activity against KPC-CRE. Relebactam inhibits KPC and AmpC. Fewest clinical data of the three preferred agents, hence ranked third. 1.25g = 500mg imipenem + 500mg cilastatin + 250mg relebactam."}]},{line:"Preferred — CRE Pyelonephritis / Complicated UTI",options:[{drug:"tmp-smx-cre-uti",regimen:"TMP-SMX, ciprofloxacin, or levofloxacin (if susceptible)",notes:"IDSA 2024: if susceptibility confirmed, non-beta-lactam agents are preferred for CRE UTI to preserve novel BL-BLIs. Minority of CRE will be susceptible to these agents, but always check. Oral agents allow outpatient completion."},{drug:"caz-avi-cre-uti",regimen:"Ceftazidime-avibactam, meropenem-vaborbactam, or imipenem-relebactam (any preferred for CRE UTI)",notes:"Use novel BL-BLIs for CRE pyelonephritis/cUTI when TMP-SMX/FQ not available. Aminoglycosides (once-daily) are alternative for CRE UTI — good renal cortex concentrations, convenient dosing for short courses."}]},{line:"Alternative — KPC-CRE",options:[{drug:"cefiderocol-cre",regimen:"Cefiderocol 2g IV q8h (infused over 3h)",notes:"IDSA 2024 alternative for KPC-CRE. Siderophore cephalosporin — uses bacterial iron transport for cell entry. >95% activity against KPC-CRE. Reserved as alternative to preserve for MBL-CRE and CRAB where fewer options exist. Clinical data for KPC-CRE more limited than the three preferred BL-BLIs."}]}],organismSpecific:[{organism:"KPC-producing K. pneumoniae (most common US CRE)",preferred:"Meropenem-vaborbactam > ceftazidime-avibactam > imipenem-relebactam",alternative:"Cefiderocol; tigecycline/eravacycline (non-BSI, non-UTI only)",notes:"The '>' indicates slight preference based on clinical outcomes and resistance emergence data, not a strict hierarchy. All three are >95% active and any is acceptable. Resistance emergence: caz-avi resistance most reported (KPC omega loop mutations like D179Y). Mer-vab and imi-rele appear more stable. If caz-avi resistance emerges, switch to mer-vab or imi-rele (cross-resistance is not automatic)."},{organism:"KPC-producing E. coli (less common)",preferred:"Same as KPC-KP: meropenem-vaborbactam, ceftazidime-avibactam, imipenem-relebactam",notes:"KPC in E. coli is less common than in K. pneumoniae but treatment approach is identical. Check susceptibility — E. coli may retain TMP-SMX or FQ susceptibility more often than K. pneumoniae."}],pearls:["KNOW YOUR CARBAPENEMASE: The single most important piece of information for CRE treatment is WHICH carbapenemase is present. KPC → mer-vab, caz-avi, or imi-rele. NDM/MBL → caz-avi + aztreonam or cefiderocol. OXA-48-like → caz-avi. The treatment is completely different depending on the mechanism. Push your lab to perform molecular or antigen-based carbapenemase identification.","Meropenem-vaborbactam is slightly favored for KPC: Based on TANGO II trial data (strongest clinical trial), observational studies showing slightly higher cure rates and lower resistance emergence vs caz-avi, and potent boronic acid inhibition of KPC. However, all three preferred agents are >95% active and acceptable. Don't delay therapy waiting for a specific agent — use what's on your formulary.","Caz-avi resistance is the BIGGEST concern: KPC mutations (particularly omega loop mutations like D179Y) can render caz-avi ineffective while potentially RESTORING meropenem activity. This has created the phenomenon of 'caz-avi resistant, meropenem restored' CRE. If caz-avi resistance emerges during therapy: (1) check meropenem MIC (may be restored), (2) switch to mer-vab or imi-rele. This pattern is well-described in the literature.","DO NOT use polymyxin-based regimens for CRE if BL-BLIs are available: The era of polymyxin-based CRE treatment is OVER. Every comparative study (TANGO II, RESTORE-IMI 1, observational) shows BL-BLIs are superior with dramatically lower toxicity. Using colistin/polymyxin B for CRE when caz-avi/mer-vab/imi-rele are available is substandard care.","Extended-infusion meropenem monotherapy for CRE is NO LONGER recommended: Previously, some used high-dose extended-infusion meropenem for CRE with MICs of 8-16. This is obsolete — novel BL-BLIs are superior. Do not attempt to 'push through' carbapenem resistance with high-dose meropenem. Use the right drug for the resistance mechanism."]},{id:"cre-mbl",name:"CRE — Metallo-β-Lactamase Producers (NDM, VIM, IMP)",definition:"Metallo-β-lactamases (MBLs) — including NDM, VIM, and IMP — are zinc-dependent carbapenemases that hydrolyze ALL beta-lactams EXCEPT aztreonam. Critically, MBLs are NOT inhibited by avibactam, vaborbactam, or relebactam — meaning caz-avi, mer-vab, and imi-rele used ALONE are ineffective. Treatment requires either: (1) ceftazidime-avibactam PLUS aztreonam (avibactam protects aztreonam from co-produced serine beta-lactamases; aztreonam is intrinsically stable to MBLs), or (2) cefiderocol (siderophore cephalosporin, stable to MBL hydrolysis). MBL prevalence in US CRE is RISING: from 4% to 20% between 2019-2021. NDM is the dominant MBL in the US.",clinicalPresentation:"Same as other CRE — BSI, UTI, IAI, pneumonia. MBL-producing CRE are often MORE resistant than KPC-CRE because MBL genes are frequently co-located on plasmids carrying additional resistance determinants (aminoglycoside-modifying enzymes, FQ resistance, etc.). The treatment options are severely limited. These are among the hardest-to-treat infections in medicine. ID consultation is mandatory.",diagnostics:"Carbapenemase-specific testing is ESSENTIAL. Phenotypic: EDTA-based tests (EDTA inhibits MBLs by chelating zinc). Molecular: PCR for blaNDM, blaVIM, blaIMP genes. CLSI has endorsed broth disk elution (BDE) method for testing ceftazidime-avibactam/aztreonam combination susceptibility against MBL-producers. Knowing 'MBL' vs 'KPC' vs 'OXA-48' completely changes the treatment algorithm.",empiricTherapy:[{line:"Preferred — MBL-Producing CRE (Non-Urinary Infections)",options:[{drug:"caz-avi-aztreonam",regimen:"Ceftazidime-avibactam 2.5g IV q8h + Aztreonam 2g IV q8h (simultaneous administration)",notes:"IDSA 2024 preferred for MBL-CRE. Rationale: aztreonam is intrinsically stable to MBL hydrolysis, but MBL-producers usually co-produce ESBLs/AmpC that would hydrolyze aztreonam. Avibactam inhibits those co-produced serine beta-lactamases, allowing aztreonam to work. ~90% activity against MBL-producing Enterobacterales. Observational data: 19% mortality vs 44% for other regimens. Administer q8h simultaneously. Monitor LFTs (elevated in ~40% in phase 1 study)."},{drug:"cefiderocol",regimen:"Cefiderocol 2g IV q8h (infused over 3h)",notes:"IDSA 2024 preferred for MBL-CRE. Siderophore cephalosporin — enters bacteria via iron transporters, bypassing porin-dependent entry. Stable against MBL hydrolysis. ~92% activity against MBL-producing Enterobacterales. Limited clinical trial data specifically for MBL-CRE but clinical trial showed 80% cure vs 0% for BAT in MBL-E infections. Monitor for resistance emergence — described with and without prior cefiderocol exposure."}]},{line:"Alternative — MBL-CRE",options:[{drug:"aztreonam-mervab",regimen:"Aztreonam 2g IV q8h + meropenem-vaborbactam or imipenem-relebactam",notes:"If caz-avi + aztreonam or cefiderocol not possible (allergy, intolerance). Limited clinical data. Rationale: vaborbactam/relebactam inhibit co-produced serine beta-lactamases, allowing aztreonam to function. NOT effective if OXA-type carbapenemases are also present."},{drug:"tigecycline-mbl",regimen:"Tigecycline 100mg IV load then 50mg IV q12h (or eravacycline 1mg/kg IV q12h)",notes:"Alternative for non-BSI, non-UTI MBL-CRE infections (IAI, SSTI, pneumonia). Activity is independent of carbapenemase type. NOT for BSI (low serum concentrations) or UTI (minimal urinary excretion). Nausea/vomiting common. FDA boxed warning for increased mortality."}]}],organismSpecific:[{organism:"NDM-producing Enterobacterales",preferred:"Caz-avi + aztreonam, or cefiderocol",alternative:"Aztreonam + mer-vab or imi-rele; tigecycline/eravacycline (non-BSI/UTI)",notes:"NDM is the most common MBL in US. Rising prevalence is a major concern. Often carried on highly transmissible plasmids with additional resistance genes. Co-resistance to aminoglycosides, FQs, TMP-SMX is common. Extremely limited treatment options — ID consultation mandatory."},{organism:"VIM/IMP-producing Enterobacterales",preferred:"Same as NDM: caz-avi + aztreonam, or cefiderocol",notes:"VIM and IMP are less common MBLs in the US but treatment approach is identical to NDM. Ceftolozane-tazobactam has NO activity against MBL-producers — never use. Pip-tazo, cefepime, carbapenems alone — all ineffective against MBLs."}],pearls:["Caz-avi ALONE does NOT work for MBL-CRE: Avibactam does NOT inhibit MBLs (zinc-dependent enzymes are structurally different from serine beta-lactamases). Ceftazidime alone would be hydrolyzed by the MBL. The caz-avi is there to provide avibactam to protect the AZTREONAM from co-produced serine enzymes. Without aztreonam, caz-avi is useless for MBL-CRE. This is a common and dangerous misconception.","MBL prevalence in the US is RISING FAST: CDC data show MBL genes increased from 4% to 20% of carbapenemase-producing CRE between 2019-2021. This has treatment implications: if your institution uses caz-avi as first-line for all CRE, you WILL miss MBL-producers. Know your local epidemiology and always obtain carbapenemase-specific testing.","Aztreonam-avibactam (Emblaveo) is in development: This fixed combination is the ideal agent for MBL-CRE. Until it's available, we use the workaround of caz-avi + aztreonam. The ceftazidime component is essentially along for the ride — it's the avibactam we need. Administer both drugs q8h simultaneously to ensure avibactam levels are adequate when aztreonam is present.","Cefiderocol is an option but monitor for resistance: ~92% activity against MBL-CRE, but resistance emergence has been described both during therapy and de novo. For critical infections, some experts advocate combination therapy (cefiderocol + another active agent) until the clinical field has more experience with cefiderocol monotherapy for MBL-CRE.","These infections REQUIRE ID consultation: MBL-CRE are among the most dangerous infections a hospitalized patient can develop. The treatment algorithm is complex (carbapenemase identification → agent selection → dosing optimization → monitoring for resistance). Non-ID clinicians should not manage these independently."]},{id:"dtr-pa",name:"DTR Pseudomonas aeruginosa",definition:"Difficult-to-treat resistant (DTR) P. aeruginosa is defined as non-susceptible to ALL of the following: piperacillin-tazobactam, ceftazidime, cefepime, aztreonam, meropenem, imipenem, ciprofloxacin, and levofloxacin. This is the most restrictive definition of resistant Pseudomonas — only novel BL-BLIs and cefiderocol remain active. IDSA 2024 preferred agents: ceftolozane-tazobactam, ceftazidime-avibactam, imipenem-cilastatin-relebactam, or cefiderocol. Important: if the isolate IS susceptible to a traditional agent (e.g., cefepime), use that agent as HIGH-DOSE EXTENDED INFUSION first.",clinicalPresentation:"DTR-PA typically occurs in patients with significant healthcare exposure: prolonged ICU stays, chronic ventilator dependence, cystic fibrosis, bronchiectasis, recurrent hospital admissions with multiple antibiotic courses. Common sites: ventilator-associated pneumonia (most common serious DTR-PA infection), bloodstream infections, complicated UTI, wound infections, osteomyelitis. Pseudomonal infections are characterized by biofilm formation, making eradication difficult.",diagnostics:"Standard AST identifies susceptibility pattern. DTR is defined by NON-susceptibility to ALL traditional anti-pseudomonal agents. If the isolate retains susceptibility to ANY traditional agent (cefepime, meropenem, pip-tazo, etc.), administer that agent as high-dose extended infusion rather than jumping to novel BL-BLIs. Susceptibility to ceftolozane-tazobactam, ceftazidime-avibactam, imipenem-relebactam, and cefiderocol should be tested when DTR phenotype is identified.",empiricTherapy:[{line:"FIRST: If Susceptible to ANY Traditional Agent — Use It",options:[{drug:"cefepime-dtr-traditional",regimen:"Cefepime 2g IV q8h (extended infusion over 3h) — or whichever traditional agent retains activity",notes:"IDSA 2024: If isolate is NOT susceptible to carbapenems but IS susceptible to cefepime (or vice versa), use the susceptible traditional agent as high-dose extended infusion. This is NOT truly DTR — it's resistant to some but not all standard agents. Reserve novel BL-BLIs for TRUE DTR (resistant to ALL traditional agents)."}]},{line:"Preferred — True DTR P. aeruginosa (Non-Urinary Infections)",options:[{drug:"ceftolozane-tazobactam-dtr",regimen:"Ceftolozane-tazobactam 3g IV q8h (infused over 3h) — use HAP/VAP dose for all serious infections",notes:"IDSA 2024 preferred for DTR-PA. Ceftolozane has intrinsic anti-pseudomonal potency greater than ceftazidime. 3g dose (2g ceftolozane + 1g tazobactam) is the HAP/VAP dose — many experts use this dose for all serious DTR-PA infections. Activity is independent of MBL/KPC status — relies on ceftolozane's stability to Pseudomonal AmpC and efflux resistance."},{drug:"ceftazidime-avibactam-dtr",regimen:"Ceftazidime-avibactam 2.5g IV q8h (infused over 2h)",notes:"IDSA 2024 preferred. Avibactam inhibits Pseudomonal AmpC and some OXA enzymes. Activity varies by regional resistance mechanisms — some areas show lower DTR-PA susceptibility to caz-avi than to ceftolozane-tazobactam."},{drug:"imipenem-relebactam-dtr",regimen:"Imipenem-cilastatin-relebactam 1.25g IV q6h (infused over 30 min)",notes:"IDSA 2024 preferred. Relebactam restores imipenem activity against Pseudomonas with AmpC/OXA-mediated resistance. RESTORE-IMI 1 trial supports efficacy. Less data specifically for DTR-PA compared to ceftolozane-tazobactam."},{drug:"cefiderocol-dtr",regimen:"Cefiderocol 2g IV q8h (infused over 3h)",notes:"IDSA 2024 preferred. Siderophore mechanism bypasses porin loss and efflux — two major Pseudomonal resistance mechanisms. Broadest activity against DTR-PA of any single agent. Some experts prefer to use combination therapy initially, transitioning to monotherapy if clinical improvement occurs."}]},{line:"Preferred — DTR P. aeruginosa UTI",options:[{drug:"ceftolozane-taz-uti",regimen:"Ceftolozane-tazobactam 1.5g IV q8h (UTI dose)",notes:"Standard UTI/cUTI dose (lower than HAP/VAP dose). Any of the four preferred novel agents can be used for DTR-PA UTI. Once-daily tobramycin or amikacin are IDSA 2024 alternatives for DTR-PA UTI (prolonged renal cortex activity, convenient dosing)."}]}],organismSpecific:[{organism:"DTR P. aeruginosa (all mechanisms)",preferred:"Ceftolozane-tazobactam, ceftazidime-avibactam, imipenem-relebactam, cefiderocol",alternative:"Aminoglycosides (UTI only); combination therapy for life-threatening infections",notes:"If an MBL (VIM, IMP) is identified in DTR-PA: ceftolozane-tazobactam and caz-avi are likely INEFFECTIVE. Use cefiderocol or caz-avi + aztreonam. MBL-producing Pseudomonas is rare but check. Nebulized antibiotics NOT recommended for respiratory DTR-PA infections (IDSA 2024)."}],pearls:["NOT ALL 'RESISTANT PSEUDOMONAS' IS DTR: DTR requires non-susceptibility to ALL traditional anti-pseudomonal agents. If the isolate is meropenem-resistant but cefepime-susceptible, use high-dose extended infusion cefepime — this is NOT DTR and does not need a novel BL-BLI. Correctly identifying DTR vs selective resistance preserves novel agents for when they're truly needed.","Ceftolozane-tazobactam dose matters: UTI = 1.5g q8h. Serious non-UTI infections = 3g q8h (the HAP/VAP dose). Many experts now use the 3g dose for ALL serious DTR-PA infections regardless of site. Underdosing ceftolozane-tazobactam for DTR-PA is a common error.","Regional DTR-PA susceptibility patterns vary: In some US regions, ceftolozane-tazobactam retains higher activity against DTR-PA than caz-avi. In others, the reverse is true. This is driven by local resistance mechanisms (AmpC mutations vs MBL vs efflux vs porin loss). Know your institutional antibiogram for novel agents.","Nebulized antibiotics for DTR-PA pneumonia: IDSA 2024 does NOT recommend nebulized antibiotics (tobramycin, colistin) for DTR-PA respiratory infections. Evidence does not support improved outcomes, and nebulized delivery is associated with bronchospasm, variable drug delivery, and selection for further resistance.","MBL-producing P. aeruginosa is the hardest scenario: If DTR-PA produces VIM or IMP, both ceftolozane-tazobactam and caz-avi are inactive. Cefiderocol becomes the primary option. This is rare in the US but increasing globally. Always check for MBL if DTR-PA is identified."]},{id:"crab-steno",name:"CRAB & Stenotrophomonas maltophilia",definition:"CRAB (carbapenem-resistant Acinetobacter baumannii) carries the highest mortality of any gram-negative AMR phenotype (40-60% crude mortality). IDSA 2024: sulbactam-durlobactam (+ carbapenem backbone) is now the PREFERRED agent. S. maltophilia is an intrinsically resistant, opportunistic glucose non-fermenter found in ICU patients, immunocompromised hosts, and CF patients. Intrinsically resistant to carbapenems, aminoglycosides, and most beta-lactams. Preferred agents: cefiderocol (+ second agent initially), caz-avi + aztreonam, minocycline, TMP-SMX, or levofloxacin (each with a second agent).",clinicalPresentation:"CRAB: predominantly healthcare-associated — ventilator-associated pneumonia (most common), bloodstream infections, wound infections, meningitis (post-neurosurgical). Environmental reservoir (survives on surfaces for weeks). Outbreaks in ICUs. Mortality: 40-60% for BSI. S. maltophilia: hospital-acquired pneumonia (especially ventilated patients), bloodstream infections (often catheter-related), immunocompromised hosts (hematologic malignancy, transplant). KEY for both: distinguish colonization from true infection. Unnecessary treatment drives further resistance.",diagnostics:"CRAB: AST shows resistance to carbapenems + most other agents. Most CRAB produce OXA-type carbapenemases (OXA-23, OXA-24/40, OXA-58). Sulbactam-durlobactam susceptibility testing should be performed. S. maltophilia: intrinsically resistant to carbapenems (L1 metallo-beta-lactamase) and aminoglycosides. CLSI 2024: ceftazidime breakpoints REMOVED for S. maltophilia (do not test). TMP-SMX, minocycline, levofloxacin, and cefiderocol susceptibility should be tested. BDE method available for caz-avi/aztreonam combination testing.",empiricTherapy:[{line:"Preferred — CRAB Infections",options:[{drug:"sulbactam-durlobactam",regimen:"Sulbactam-durlobactam 1g/0.5g IV q6h + Imipenem-cilastatin 500mg IV q6h (or Meropenem 2g IV q8h)",notes:"IDSA 2024 preferred for CRAB. ATTACK trial: 28-day mortality 19% vs 32% with colistin. Durlobactam is a diazabicyclooctane BLI that inhibits Acinetobacter OXA carbapenemases + Class A/C enzymes. Sulbactam provides the intrinsic anti-Acinetobacter killing. Carbapenem backbone adds additional activity and covers potential co-pathogens. Brand name: Xacduro."}]},{line:"Alternative — CRAB (If Sulbactam-Durlobactam Unavailable)",options:[{drug:"high-dose-amp-sulb-crab",regimen:"High-dose ampicillin-sulbactam 9g IV q8h (= 27g/day total: 18g ampicillin + 9g sulbactam) + at least 1 additional agent",notes:"IDSA 2024 alternative (downgraded from preferred in 2023 update). Sulbactam component provides intrinsic Acinetobacter activity. Must be combined with at least one other agent: polymyxin B, minocycline (preferred over tigecycline), or cefiderocol. The 27g/day dosing (9g sulbactam) maximizes the sulbactam PK/PD target."},{drug:"polymyxin-b-crab",regimen:"Polymyxin B 2.5-3 mg/kg/day IV divided q12h (NOT colistimethate for systemic CRAB)",notes:"Component of CRAB combination therapy. Polymyxin B preferred over colistimethate (colistin) for systemic infections: more predictable PK, does not require conversion from prodrug, less nephrotoxic. Colistimethate has a role in urinary tract infections (converts to active colistin in urine) and nebulized therapy. Never use polymyxin monotherapy for CRAB — always combine."}]},{line:"Preferred — S. maltophilia Infections (in order of preference)",options:[{drug:"cefiderocol-steno",regimen:"Cefiderocol 2g IV q8h (with a second agent at least initially)",notes:"IDSA 2024 preferred (listed first). Stable against S. maltophilia's intrinsic L1 MBL and L2 serine BL. Siderophore entry bypasses efflux/porin resistance. Add a second agent initially (minocycline, TMP-SMX, or levofloxacin) until clinical improvement, then consider cefiderocol monotherapy."},{drug:"caz-avi-aztreonam-steno",regimen:"Ceftazidime-avibactam 2.5g IV q8h + Aztreonam 2g IV q8h",notes:"IDSA 2024 preferred (listed second). Same rationale as for MBL-CRE: aztreonam stable to L1 MBL, avibactam inhibits L2 serine BL. BDE testing endorsed by CLSI for this combination against S. maltophilia."},{drug:"tmp-smx-steno",regimen:"TMP-SMX 15 mg/kg/day IV divided q6-8h (with a second agent)",notes:"IDSA 2024 preferred (with second agent). Historically the first-line agent for S. maltophilia. Still effective but rising resistance (10-20% in some centers). IV dosing uses the TMP component for calculation. Combine with minocycline, levofloxacin, or cefiderocol."},{drug:"minocycline-steno",regimen:"Minocycline 200mg IV/PO q12h (with a second agent)",notes:"IDSA 2024 preferred (with second agent). Minocycline is preferred over tigecycline for S. maltophilia (better activity, fewer GI side effects). Good oral bioavailability for step-down. 70-80% S. maltophilia susceptibility in most centers."}]}],organismSpecific:[{organism:"CRAB (OXA-producing A. baumannii)",preferred:"Sulbactam-durlobactam + carbapenem",alternative:"High-dose amp-sulb (27g/day) + polymyxin B or minocycline or cefiderocol",notes:"CRAB treatment ALWAYS requires combination therapy. Monotherapy failure rates are unacceptable. Sulbactam-durlobactam changed the landscape (ATTACK trial) — if available, it is clearly preferred. If not, high-dose amp-sulb-based combination is the alternative. Tigecycline was removed from IDSA 2024 guidance for CRAB (minocycline preferred). Distinguish colonization from infection — many CRAB-positive cultures represent colonization."},{organism:"S. maltophilia",preferred:"Cefiderocol (+2nd agent), caz-avi + aztreonam, TMP-SMX (+2nd agent), minocycline (+2nd agent), levofloxacin (+2nd agent)",alternative:"Combinations of the above",notes:"S. maltophilia is intrinsically resistant to carbapenems (L1 MBL), aminoglycosides, and most beta-lactams. Ceftazidime breakpoints REMOVED by CLSI 2024 — do not test or use. TMP-SMX was historically first-line but resistance is increasing. Combination therapy preferred for serious infections. Colonization vs infection distinction is critical — S. maltophilia in respiratory cultures often represents colonization in ventilated patients."}],pearls:["SULBACTAM-DURLOBACTAM CHANGED CRAB TREATMENT: The ATTACK trial showed 28-day mortality of 19% (sulbactam-durlobactam) vs 32% (colistin-based). This is the first agent to demonstrate superiority over polymyxin-based therapy for CRAB. If your formulary carries it, sulbactam-durlobactam + carbapenem is now first-line. High-dose amp-sulb was downgraded to alternative in the 2024 update.","CRAB = COMBINATION THERAPY ALWAYS: No single agent is adequate for CRAB. Even sulbactam-durlobactam is given with a carbapenem backbone. High-dose amp-sulb is given with at least one additional agent. Polymyxin monotherapy for CRAB is associated with unacceptable failure rates. Every CRAB regimen should have at least 2 active components.","S. maltophilia: ceftazidime is DEAD for this organism. CLSI 2024 removed ceftazidime breakpoints for S. maltophilia. The intrinsic L2 serine beta-lactamase and inducible L1 metallo-beta-lactamase make ceftazidime unreliable. If your lab still reports ceftazidime for S. maltophilia, flag this as outdated.","Colonization vs infection is CRITICAL for CRAB and S. maltophilia: Both organisms are frequently cultured from respiratory specimens (sputum, BAL) in ICU patients without causing true infection. Treating colonization drives further resistance, exposes patients to drug toxicity, and wastes resources. Evaluate: are there clinical signs of infection (new fever, worsening WBC/oxygenation, new infiltrates)? Is there an alternative explanation? ID consultation is strongly recommended before starting CRAB or S. maltophilia-directed therapy.","Minocycline > tigecycline for CRAB and S. maltophilia: IDSA 2024 favors minocycline over tigecycline. Minocycline has better in vitro activity against both organisms, better GI tolerability, and oral bioavailability for step-down. Tigecycline was REMOVED from S. maltophilia combination therapy recommendations in the 2024 update."]}],drugMonographs:[{id:"ceftazidime-avibactam",name:"Ceftazidime-Avibactam",brandNames:"Avycaz",drugClass:"Cephalosporin + diazabicyclooctane β-lactamase inhibitor",mechanismOfAction:"Ceftazidime: binds PBP3, inhibiting cell wall synthesis (bactericidal, time-dependent). Avibactam: non-β-lactam β-lactamase inhibitor (diazabicyclooctane) that covalently and REVERSIBLY binds serine β-lactamases. Inhibits Class A (KPC, CTX-M, SHV, TEM), Class C (AmpC), and some Class D (OXA-48-like) enzymes. Does NOT inhibit Class B metallo-β-lactamases (NDM, VIM, IMP) — this is the critical gap. The reversible binding of avibactam means it can dissociate and inhibit another enzyme molecule, providing efficient inhibition even at lower concentrations than irreversible inhibitors.",spectrum:"With avibactam: Enterobacterales (including KPC-producing CRE, ESBL-E, AmpC-E, OXA-48-like producers), P. aeruginosa (including many DTR strains). When combined with aztreonam: MBL-producing Enterobacterales, S. maltophilia. GAPS: MBL-producers (when used ALONE — requires aztreonam addition), CRAB (minimal activity), anaerobes, gram-positives.",dosing:{standard:"2.5g (ceftazidime 2g + avibactam 0.5g) IV q8h, infused over 2h",with_aztreonam:"2.5g IV q8h + Aztreonam 2g IV q8h (administer simultaneously for MBL-CRE)",uti:"2.5g IV q8h (same dose for all indications)"},renalAdjustment:"CrCl 31-50: 1.25g IV q8h. CrCl 16-30: 0.94g IV q12h. CrCl 6-15: 0.94g IV q24h. CrCl <=5: 0.94g IV q48h. Hemodialysis: 0.94g IV q48h (administer after HD on dialysis days). ALL components are renally cleared — dose reduction is critical.",hepaticAdjustment:"No adjustment needed — renally eliminated.",adverseEffects:{common:"Diarrhea (8-12%), nausea (5-8%), vomiting, headache, constipation",serious:"C. difficile colitis, hypersensitivity (cross-reactive with cephalosporin allergy), neurotoxicity (seizures — ceftazidime component, especially in renal impairment), elevated LFTs (particularly with aztreonam combination — ~40% in phase 1 study)",rare:"Anaphylaxis, hemolytic anemia, encephalopathy"},drugInteractions:["Probenecid — decreases renal clearance of ceftazidime. Not typically clinically relevant at standard doses.","Valproic acid — as with all cephalosporins, potential for reduced VPA levels, though the interaction is most significant with carbapenems. Monitor VPA levels.","Chloramphenicol — may antagonize cephalosporin bactericidal activity (bacteriostatic agent). Avoid combination."],monitoring:"Renal function (dose adjustment critical). LFTs (especially when combined with aztreonam). Seizure monitoring (particularly in renal impairment or CNS disease). Clinical response. Repeat cultures to assess microbiological clearance, especially for CRE BSI. Monitor for resistance emergence — KPC omega loop mutations (D179Y) can cause caz-avi failure.",pregnancyLactation:"Category B. Limited human data. Animal studies showed no harm at therapeutic doses. Use only if clearly needed. Unknown if excreted in breast milk.",pharmacistPearls:["THE MOST VERSATILE NOVEL BL-BLI: Caz-avi is effective against KPC-CRE, ESBL-E, AmpC-E, OXA-48-CRE, DTR-PA, and (with aztreonam) MBL-CRE and S. maltophilia. No other single agent covers this breadth. However, this versatility means it should be used JUDICIOUSLY — resistance emergence is the biggest concern.","Caz-avi + aztreonam for MBL-CRE: The avibactam is the hero here, not the ceftazidime. Avibactam protects aztreonam from serine beta-lactamases co-produced by MBL organisms. Aztreonam is intrinsically stable to MBLs. Administer simultaneously q8h. Monitor LFTs closely.","RESISTANCE EMERGENCE IS THE ACHILLES HEEL: KPC mutations (omega loop — D179Y, T243M, D179Y/T243M) can abolish avibactam binding, causing caz-avi resistance. Paradoxically, these mutations may RESTORE meropenem activity. If caz-avi fails: (1) check meropenem MIC, (2) switch to mer-vab or imi-rele. This 'resistance seesaw' is well-described.","Renal dosing matters enormously: Caz-avi is entirely renally eliminated. Incorrect dose adjustment in renal impairment leads to subtherapeutic levels and treatment failure OR accumulation and toxicity. Use actual measured CrCl, not estimated, for dosing decisions in critically ill patients.","For DTR-PA: regional susceptibility varies. In some areas, ceftolozane-tazobactam has better DTR-PA activity than caz-avi. In others, the reverse is true. Know your institutional antibiogram for novel agents. Don't assume one is universally better than the other for Pseudomonas."]},{id:"meropenem-vaborbactam",name:"Meropenem-Vaborbactam",brandNames:"Vabomere",drugClass:"Carbapenem + cyclic boronic acid β-lactamase inhibitor",mechanismOfAction:"Meropenem: binds PBPs (primarily PBP-2), inhibiting cell wall synthesis. Bactericidal, time-dependent. Vaborbactam: cyclic boronic acid β-lactamase inhibitor. Forms reversible covalent bonds with serine β-lactamases. Potently inhibits Class A β-lactamases (KPC — its primary target, ESBLs, SHV, TEM). Does NOT inhibit Class B (MBLs), Class D (OXA-48-like) — key gaps. The boronic acid scaffold provides high binding affinity for KPC specifically, resulting in lower resistance emergence risk compared to avibactam.",spectrum:"KPC-producing CRE (primary indication — >95% activity), ESBL-E, AmpC-E, plus standard meropenem spectrum (Enterobacterales, P. aeruginosa, anaerobes, Streptococci). GAPS: MBL-producing CRE (NDM, VIM, IMP), OXA-48-like CRE (vaborbactam does not inhibit OXA-48), CRAB, S. maltophilia. For non-KPC CRE, the meropenem component alone may contribute activity if MIC is restored by vaborbactam.",dosing:{standard:"4g (meropenem 2g + vaborbactam 2g) IV q8h, infused over 3h",all_indications:"Same dose for all indications (UTI, BSI, IAI, pneumonia)"},renalAdjustment:"CrCl 30-49: 2g IV q8h. CrCl 15-29: 2g IV q12h. CrCl <15: 1g IV q12h. Hemodialysis: 1g IV q12h (administer after HD). CRRT: limited data, 2g IV q8h commonly used. Extended infusion over 3h maintained for all dose adjustments.",hepaticAdjustment:"No adjustment needed — renally eliminated.",adverseEffects:{common:"Headache (9%), diarrhea (5%), nausea, phlebitis/infusion site reactions",serious:"C. difficile colitis, seizures (meropenem component — risk increases in renal impairment and CNS disease), hypersensitivity (carbapenem cross-reactivity), thrombocytopenia",rare:"Anaphylaxis, encephalopathy, hepatitis"},drugInteractions:["Valproic acid — CRITICAL: ALL carbapenems (including meropenem-vaborbactam) reduce VPA levels by 60-100% within 24h. Switch VPA to levetiracetam BEFORE starting. This interaction is pharmacologically inevitable.","Probenecid — competes for renal tubular secretion, increasing meropenem levels. Generally not clinically significant."],monitoring:"Renal function (for dose adjustment). Seizure monitoring (meropenem component). Clinical response. Repeat cultures for CRE BSI to document clearance. CBC (thrombocytopenia risk with prolonged courses). Hepatic function (baseline and periodic).",pregnancyLactation:"Limited data. Meropenem is Category B. Vaborbactam has limited human pregnancy data. Use only if clearly needed.",pharmacistPearls:["SLIGHTLY FAVORED FOR KPC-CRE by IDSA 2024: Based on TANGO II trial (strongest clinical trial data for any BL-BLI vs CRE), observational studies showing higher cure rates and lower resistance emergence vs caz-avi, and potent KPC-specific inhibition. The preference is slight — all three preferred agents are acceptable.","LOWEST RESISTANCE EMERGENCE of the three preferred KPC agents: Boronic acid scaffold provides high-affinity KPC binding. KPC mutations that escape vaborbactam are less common than those escaping avibactam. Observational data: 0% resistance emergence with mer-vab vs 20% with caz-avi in one comparative study. This matters for prolonged courses.","The VPA interaction applies: Same as meropenem — switch valproate to levetiracetam before starting mer-vab. This is non-negotiable. The vaborbactam component does not change this interaction.","Extended infusion is standard: 3-hour infusion is built into the product labeling. This optimizes meropenem T>MIC, which is critical for CRE with elevated MICs. Do not administer as standard 30-minute infusion.","Does NOT cover MBL-CRE or OXA-48-CRE: Vaborbactam is KPC-specific in clinical impact. If the carbapenemase is NDM → need caz-avi + aztreonam or cefiderocol. If OXA-48-like → need caz-avi (avibactam inhibits OXA-48). Know the carbapenemase before selecting the agent."]},{id:"cefiderocol",name:"Cefiderocol",brandNames:"Fetroja",drugClass:"Siderophore cephalosporin (first-in-class)",mechanismOfAction:"Unique dual mechanism: (1) Siderophore component chelates iron and hijacks bacterial iron transport systems (TonB-dependent transporters) to actively transport the drug into the periplasm. This bypasses porin channels — the major route of entry for other beta-lactams — overcoming porin loss resistance. (2) Once inside, the cephalosporin moiety binds PBP-3, inhibiting cell wall synthesis. Bactericidal, time-dependent. The siderophore-mediated entry achieves periplasmic concentrations 3-5× higher than passive diffusion would achieve, overcoming many resistance mechanisms simultaneously.",spectrum:"THE BROADEST-SPECTRUM SINGLE AGENT FOR GRAM-NEGATIVE AMR: KPC-CRE (>95%), MBL-CRE including NDM (>90%), OXA-48-like CRE, DTR P. aeruginosa, CRAB, S. maltophilia, Burkholderia cepacia. Stable against ALL four Ambler classes (A, B, C, D). GAPS: gram-positives, anaerobes. CAUTION: CREDIBLE-CR trial showed numerically higher mortality in CRAB subgroup vs BAT — use combination therapy for CRAB.",dosing:{standard:"2g IV q8h, infused over 3h",all_serious:"Same dose for all serious infections",uti:"2g IV q8h (same dose)"},renalAdjustment:"CrCl 30-59: 1.5g IV q8h. CrCl 15-29: 1g IV q8h. CrCl <15: 0.75g IV q12h. Hemodialysis: 0.75g IV q12h (dose after HD). UNIQUE — augmented renal clearance (ARC): CrCl >120: increase to 2g IV q6h. Cefiderocol clearance increases linearly with CrCl — patients with ARC (common in burns, sepsis, young patients) require HIGHER doses.",hepaticAdjustment:"No adjustment needed — renally eliminated.",adverseEffects:{common:"Diarrhea (10%), nausea, constipation, rash, elevated LFTs",serious:"C. difficile colitis, hypersensitivity, seizures (rare, cephalosporin class), iron-related effects (theoretical — siderophore mechanism, but clinically insignificant iron chelation at therapeutic doses)",rare:"Anaphylaxis, CREDIBLE-CR mortality signal in CRAB (may be related to trial design/severity, not drug-specific — but led to caution for CRAB monotherapy)"},drugInteractions:["Minimal clinically significant drug interactions identified. Cefiderocol is primarily renally eliminated and not a significant CYP enzyme inducer/inhibitor.","Iron supplements — theoretical concern that exogenous iron could compete with siderophore-mediated uptake. Clinical significance uncertain but some experts avoid IV iron during cefiderocol therapy."],monitoring:"Renal function (critical — both for dose reduction AND for identifying augmented renal clearance requiring dose increase). Clinical response. Repeat cultures to document microbiological clearance. CBC. Hepatic function (LFT elevations reported). Monitor for resistance emergence — described with and without prior exposure.",pregnancyLactation:"Limited human data. Animal studies showed skeletal variations at high doses. Use only if clearly needed.",pharmacistPearls:["THE BROADEST SINGLE AGENT IN THE AMR TOOLKIT: Cefiderocol is active against ALL major AMR gram-negative phenotypes — KPC-CRE, MBL-CRE, OXA-48-CRE, DTR-PA, CRAB, S. maltophilia. No other single agent covers all six. This makes it invaluable when carbapenemase type is unknown or for empiric coverage of MDR gram-negatives. However, breadth means it must be preserved — don't use for ESBL-E or routine CRE when narrower BL-BLIs suffice.","AUGMENTED RENAL CLEARANCE (ARC) DOSE INCREASE: Cefiderocol is one of few drugs with UPWARD dose adjustment for ARC (CrCl >120). Young patients, burns, early sepsis, and pregnant women commonly have ARC. Standard dosing in ARC → subtherapeutic levels → treatment failure. Measure CrCl; if >120, increase to 2g q6h. This is a pharmacist-driven intervention.","CRAB CAUTION: CREDIBLE-CR trial showed numerically higher all-cause mortality with cefiderocol vs BAT in the CRAB subgroup (49% vs 18%). This may reflect imbalanced severity or trial limitations, but it led to the recommendation for COMBINATION therapy when using cefiderocol for CRAB. Cefiderocol monotherapy for CRAB is NOT recommended.","Siderophore mechanism is elegant but not invulnerable: Bacteria can develop resistance by: (1) mutating TonB-dependent transporters, (2) modifying siderophore receptors, (3) producing MBLs that can partially hydrolyze cefiderocol (NDM-5 variants). Resistance has been reported during therapy. For serious infections, combination therapy at least initially may reduce resistance emergence risk.","3-hour infusion is non-negotiable: Time-dependent killing means T>MIC drives efficacy. The 3h infusion maximizes the percentage of the dosing interval above the MIC. Shorter infusions reduce efficacy. Extended infusion programs should be established for cefiderocol just as for meropenem and pip-tazo."]}]},u={id:"bacteremia-endocarditis",name:"Bacteremia & Endocarditis",icon:"🩸",category:"Infectious Disease — AHA/IDSA Guidelines",overview:{definition:"Bacteremia is the presence of viable bacteria in the bloodstream, confirmed by positive blood cultures. Infective endocarditis (IE) is infection of the endocardial surface of the heart, most commonly involving cardiac valves. These conditions exist on a spectrum: all endocarditis causes bacteremia, but not all bacteremia causes endocarditis. The clinical challenge is determining which bacteremic patients have endocarditis, because this distinction fundamentally changes duration of therapy, need for surgery, and prognosis.",epidemiology:"S. aureus bacteremia (SAB) is the most clinically significant bloodstream infection in developed countries — incidence 20-50 per 100,000 person-years, 30-day mortality 20-30%. IE incidence is 3-10 per 100,000 person-years and rising, driven by healthcare-associated infections, injection drug use (IDU), and prosthetic valves. IDU-associated right-sided IE has surged with the opioid epidemic. Mortality for IE remains 15-30% despite modern therapy. Enterococcal bacteremia is the second most common healthcare-associated BSI and often signals an intra-abdominal or urinary source.",keyGuidelines:[{name:"AHA/ACC 2023 IE Guideline Update",detail:"Major revision of the 2015 AHA IE guideline. Key changes: expanded surgical indications, formal endorsement of early surgery for high-risk features, updated Duke criteria modifications, and strengthened recommendations for ID and cardiothoracic surgery consultation within 24h of IE diagnosis."},{name:"AHA 2015 IE Guideline",detail:"Foundation document for IE management. Defines modified Duke criteria, empiric and pathogen-directed regimens, surgical indications, and follow-up. Remains the most comprehensive single reference for IE."},{name:"IDSA SAB Bundle Recommendations",detail:"Informal but widely adopted 'SAB bundle': (1) Follow-up blood cultures q24-48h until clearance, (2) Echocardiography (TTE ± TEE), (3) ID consultation, (4) Source identification and control, (5) Appropriate antibiotic selection and duration. Adherence to the full bundle reduces mortality by 40-50% in observational studies."},{name:"IDSA 2024 AMR Guidance v4.0",detail:"Relevant for MRSA bacteremia treatment (vancomycin AUC-guided dosing, daptomycin as alternative), VRE bacteremia (daptomycin ± ampicillin synergy), and resistant gram-negative bacteremia."},{name:"ESC 2023 IE Guidelines",detail:"European perspective. Emphasizes multimodality imaging (PET/CT for prosthetic valve IE), earlier surgical referral, and endocarditis team approach. Largely concordant with AHA but more aggressive on imaging."}],landmarkTrials:[{name:"POET Trial (Iversen et al., NEJM 2019)",detail:"Paradigm-shifting RCT: Partial Oral Treatment of Endocarditis. 400 patients with left-sided IE (S. aureus, Streptococci, E. faecalis, CoNS) randomized to continued IV vs. switch to oral therapy after ≥10 days IV + clinical stability. Oral switch was NON-INFERIOR (composite of all-cause mortality, unplanned cardiac surgery, embolic events, relapse). Changed practice: oral step-down is now acceptable for SELECTED patients. Key caveats — excluded prosthetic valves <1 year, severe valve dysfunction, large vegetations, and aortic root abscess. Used HIGH-DOSE oral regimens (e.g., amoxicillin 1g q6h + rifampin, or other dual-oral combos)."},{name:"ARREST Trial (Thwaites et al., Lancet 2018)",detail:"Adjunctive Rifampicin for S. aureus Bacteremia. RCT of 758 patients — adding rifampicin to standard SAB therapy did NOT improve outcomes (bacteremia duration, mortality, treatment failure). Ended the long-standing debate about routine rifampicin in SAB. Reserve rifampicin for prosthetic material infections (PJI, prosthetic valve IE) where biofilm is a specific concern, not routine SAB."},{name:"CAMERA2 Trial (Tong et al., NEJM 2020)",detail:"Combination Antibiotics for MRSA. RCT of vancomycin vs. vancomycin + anti-staphylococcal beta-lactam (flucloxacillin or cefazolin) for MRSA bacteremia. Trial stopped early for SAFETY — combination arm had significantly more AKI (23% vs 6%) without mortality benefit. Do NOT routinely add beta-lactams to vancomycin for MRSA bacteremia — despite in vitro synergy, the clinical data does not support it."},{name:"Fowler et al., JAMA 2003 — TEE in SAB",detail:"Demonstrated that TEE identifies IE in 25% of SAB patients with negative TTE. Established that TEE should be performed in all patients with SAB at high risk for IE (prosthetic valves, implantable devices, persistent bacteremia, no identified source, IDU). Changed standard of care for SAB workup."},{name:"Holland et al., JAMA 2014 — Short vs Long Course SAB",detail:"Observational data establishing that uncomplicated SAB (no endocarditis, no metastatic infection, line-related source, clearance within 72h) can be treated for 14 days, while complicated SAB requires 4-6 weeks. Defines the 'uncomplicated SAB' criteria that remain in use today."},{name:"Kang et al., NEJM 2012 — Early Surgery in IE",detail:"RCT of early surgery (within 48h) vs. conventional treatment for left-sided IE with large vegetations and severe valve dysfunction. Early surgery reduced composite of death and embolic events. Strengthened the case for prompt surgical referral."}],riskFactors:"Endocarditis risk factors: Prosthetic heart valves (highest risk — 1-4% annual incidence), prior IE (recurrence risk 5-10%), IDU (right-sided predominance — tricuspid valve), structural heart disease (bicuspid aortic valve, mitral valve prolapse with regurgitation, degenerative valve disease), intracardiac devices (pacemakers, defibrillators), healthcare-associated bacteremia (central lines, HD catheters — rising proportion of IE cases). General bacteremia risk: Central venous catheters (CLABSI), immunosuppression, chronic comorbidities (diabetes, cirrhosis, ESRD on HD, malignancy), recent surgery/procedures, injection drug use, prolonged hospitalization."},subcategories:[{id:"sab-workup",name:"S. aureus Bacteremia — Workup & Risk Stratification",definition:"S. aureus bacteremia (SAB) is NEVER a contaminant. Every positive blood culture with S. aureus demands a full workup regardless of clinical appearance. The SAB bundle — follow-up cultures, echocardiography, ID consult, source control, and appropriate therapy — is the standard of care and reduces mortality by 40-50% when fully implemented.",clinicalPresentation:"SAB presentations range from indolent line infection to fulminant septic shock with multi-organ failure. Fever is present in >90% but may be absent in immunosuppressed or elderly patients. Key: look for METASTATIC FOCI — back pain (vertebral osteomyelitis/epidural abscess in 10-15% of SAB), new heart murmur (endocarditis), joint pain/swelling (septic arthritis), focal neurologic deficits (septic emboli, meningitis), splinter hemorrhages, Janeway lesions, Osler nodes. The absence of focal findings does NOT exclude complicated infection — occult endocarditis is found in 10-25% of SAB patients when TEE is performed.",diagnostics:"MANDATORY SAB WORKUP: (1) Blood cultures — at least 2 sets (4 bottles) from 2 separate sites before antibiotics. Follow-up cultures q24-48h until DOCUMENTED CLEARANCE (date of first negative culture = day 1 of therapy). (2) Echocardiography — TTE for all SAB patients. TEE if any of: prosthetic valve, intracardiac device, high clinical suspicion, positive TTE needing better characterization, persistent bacteremia >72h, no identified source, IDU, or prior IE. TEE sensitivity for native valve IE: 90-95% (vs TTE 50-60%). (3) Source identification — line removal if CLABSI, drain collections, image suspected metastatic foci. MRI spine if back pain. (4) ID consultation — associated with 50% relative mortality reduction in observational studies. (5) Labs: CBC, CMP, inflammatory markers (CRP, ESR, procalcitonin) for trending.",durationGuidance:{standard:"14 days from first negative blood culture (uncomplicated MSSA/MRSA)",severe:"28–42 days (complicated/endocarditis)",opatNote:"OPAT appropriate for uncomplicated Staph aureus bacteremia after initial IV stabilization × 14d",stewardshipNote:"AHA/IDSA 2023: Repeat blood cultures at 48–72h. Echocardiography for Staph aureus bacteremia."},empiricTherapy:[{line:"Empiric — Pending Susceptibilities",options:[{drug:"vancomycin",regimen:"Vancomycin IV (AUC/MIC target 400-600)",notes:"Empiric first-line for SAB until MSSA vs MRSA is determined. AUC-guided dosing is now the standard (2020 consensus) — replaces trough-based dosing. Typical loading dose: 25-30 mg/kg (actual body weight), then maintenance guided by AUC. CRITICAL: once susceptibilities return, de-escalate MSSA to cefazolin/nafcillin immediately — vancomycin is INFERIOR to beta-lactams for MSSA (slower bacteremia clearance, higher mortality in some studies).",evidence:"A-I",evidenceSource:"AHA/IDSA 2023"},{drug:"daptomycin",regimen:"Daptomycin 6-10 mg/kg IV once daily",notes:"Alternative empiric agent when vancomycin cannot be used (allergy, intolerance, renal toxicity). Use ≥8 mg/kg for suspected endocarditis or complicated infections. Rapidly bactericidal. CONTRAINDICATED in pneumonia (surfactant inactivation). If MSSA returns, still de-escalate to beta-lactam.",evidence:"B-II",evidenceSource:"AHA/IDSA 2023"}]},{line:"MSSA Definitive Therapy",options:[{drug:"cefazolin",regimen:"Cefazolin 2g IV q8h",notes:"PREFERRED agent for MSSA bacteremia and MSSA IE (native valve). Multiple observational studies and meta-analyses show non-inferiority or superiority to nafcillin/oxacillin with fewer adverse effects (less nephrotoxicity, less hepatotoxicity, less phlebitis). Q8h dosing is practical for OPAT. Duration: 14 days for uncomplicated SAB, 4-6 weeks for IE or complicated SAB.",evidence:"A-I",evidenceSource:"AHA/IDSA 2023"},{drug:"nafcillin-oxacillin",regimen:"Nafcillin or Oxacillin 2g IV q4h",notes:"Historical gold standard for MSSA. Still used by some ID physicians who prefer the rapid bactericidal activity and high-dose continuous infusion data. Disadvantages: q4h dosing (impractical for OPAT), significant phlebitis, oxacillin hepatotoxicity, nafcillin-associated interstitial nephritis. Most centers have transitioned to cefazolin. Reserve for cefazolin allergy (severe cephalosporin allergy — rare) or treatment failure on cefazolin (extremely rare).",evidence:"A-I",evidenceSource:"AHA/IDSA 2023"}]},{line:"MRSA Definitive Therapy",options:[{drug:"vancomycin",regimen:"Vancomycin IV (AUC/MIC 400-600)",notes:"Standard of care for MRSA bacteremia. AUC-guided dosing with Bayesian software is preferred. If vancomycin MIC ≥2 by broth microdilution (≥2 by E-test is less reliable), consider switching to daptomycin — treatment failure risk increases with higher MICs (MIC creep). Do NOT add rifampicin routinely (ARREST trial — no benefit, added toxicity). Duration: 14 days minimum for uncomplicated, 4-6 weeks for IE/complicated."},{drug:"daptomycin",regimen:"Daptomycin 8-10 mg/kg IV once daily",notes:"Preferred alternative to vancomycin for MRSA bacteremia when: vancomycin MIC ≥2, vancomycin intolerance/nephrotoxicity, persistent bacteremia on vancomycin >3-5 days. Dose at ≥8 mg/kg for bacteremia (6 mg/kg is the IE/bacteremia approved dose but many experts go higher). Monitor CPK weekly. If daptomycin MIC ≥2-4, consider ceftaroline or salvage regimens."}]},{line:"Complicated vs. Uncomplicated SAB — Duration Decision",options:[{drug:"uncomplicated-sab",regimen:"14 days IV therapy from first negative blood culture",notes:"ALL of the following must be met for uncomplicated SAB: (1) Follow-up blood cultures negative within 72h, (2) No endocarditis on TTE/TEE, (3) No prosthetic valves or intracardiac devices, (4) No metastatic infection (no osteomyelitis, septic arthritis, epidural abscess, septic emboli), (5) Removable source identified AND removed (e.g., line-related with line pulled). If ANY criterion is NOT met → complicated SAB."},{drug:"complicated-sab",regimen:"4-6 weeks IV therapy from first negative blood culture",notes:"Complicated SAB = endocarditis, metastatic infection, persistent bacteremia >72h, no removable source, prosthetic material, or failure to meet all uncomplicated criteria. Duration: 4 weeks for native valve IE, 6 weeks for prosthetic valve IE. Some metastatic foci (e.g., vertebral osteomyelitis) may warrant even longer therapy. ORAL STEP-DOWN: consider per POET trial criteria for selected patients after ≥10 days IV + clinical stability."}]}],organismSpecific:[{organism:"MSSA",preferred:"Cefazolin 2g IV q8h (preferred) or nafcillin 2g IV q4h",alternative:"Daptomycin 8-10 mg/kg IV daily if beta-lactam allergy (true anaphylaxis to all cephalosporins)",notes:"De-escalation from vancomycin to cefazolin for MSSA is one of the highest-impact stewardship interventions in inpatient medicine. Vancomycin is inferior to beta-lactams for MSSA bacteremia — slower clearance, potentially higher mortality. Cefazolin cross-reactivity with penicillin is ~1% — most 'penicillin-allergic' patients can safely receive cefazolin."},{organism:"MRSA (vancomycin MIC ≤1)",preferred:"Vancomycin IV (AUC/MIC 400-600)",alternative:"Daptomycin 8-10 mg/kg IV daily",notes:"Standard MRSA bacteremia management. AUC-guided dosing reduces nephrotoxicity vs. trough-based dosing. Monitor renal function q48-72h. If persistent bacteremia >5 days on vancomycin, switch to daptomycin ± salvage strategies."},{organism:"MRSA (vancomycin MIC = 2 or persistent)",preferred:"Daptomycin 8-10 mg/kg IV daily",alternative:"Daptomycin + ceftaroline 600mg IV q8h (salvage for persistent MRSA BSI)",notes:"Vancomycin MIC ≥2 is associated with treatment failure. Switch to daptomycin. For persistent MRSA bacteremia failing daptomycin: daptomycin + ceftaroline synergy is the most studied salvage regimen. Ceftaroline enhances daptomycin binding to the cell membrane. TMP-SMX IV, linezolid, and dalbavancin have anecdotal data but are not first-line for bacteremia/IE."}],pearls:["S. AUREUS IS NEVER A CONTAMINANT. Unlike CoNS, a single positive blood culture bottle with S. aureus is considered true bacteremia until proven otherwise. Treat every positive S. aureus blood culture seriously — even if the patient looks well.","THE SAB BUNDLE SAVES LIVES: Follow-up cultures, echo, ID consult, source control, appropriate antibiotics. Every element matters. Observational data consistently shows 40-50% relative mortality reduction with full bundle adherence. Push for compliance on every SAB patient.","DE-ESCALATE MSSA TO BETA-LACTAM: This is the single most impactful antibiotic stewardship intervention in SAB. Vancomycin is inferior to cefazolin/nafcillin for MSSA — slower bacteremia clearance, potentially higher mortality. Do not leave a patient on vancomycin once MSSA is confirmed.","DATE OF CLEARANCE = DAY 1: Duration of therapy for SAB starts counting from the date of the FIRST NEGATIVE blood culture, not from the date antibiotics were started. This is why follow-up cultures are mandatory — without them, you literally cannot determine the treatment duration.","BACK PAIN IN SAB = MRI SPINE: Vertebral osteomyelitis and epidural abscess occur in 10-15% of SAB. Any new back pain during SAB should prompt urgent MRI. Missing an epidural abscess is catastrophic (paraplegia). This is a common miss — always ask about back pain.","ARREST TRIAL SETTLED THE RIFAMPICIN DEBATE: Do NOT add rifampicin to standard SAB therapy. The ARREST trial (758 patients, RCT) showed no benefit and added toxicity/drug interactions. Reserve rifampicin for prosthetic material infections only (prosthetic valve IE, prosthetic joint infections).","CAMERA2 KILLED COMBINATION THERAPY FOR MRSA: Do NOT routinely add a beta-lactam (cefazolin/flucloxacillin) to vancomycin for MRSA bacteremia. CAMERA2 was stopped early for safety — more AKI without mortality benefit. Despite promising in vitro synergy, the clinical data says no.","PERSISTENT BACTEREMIA DEFINITION: Blood cultures still positive at 72+ hours despite appropriate antibiotics AND source control. For S. aureus, persistent BSI should prompt: (1) repeat imaging for occult foci, (2) TEE if not done, (3) consider switching from vancomycin to daptomycin for MRSA, (4) evaluate for endocarditis complications (abscess, fistula)."]},{id:"native-valve-ie",name:"Native Valve Infective Endocarditis",definition:"Infection of a native (non-prosthetic) heart valve, most commonly mitral and aortic. Diagnosis rests on the modified Duke criteria integrating clinical, microbiologic, echocardiographic, and pathologic findings. Management requires prolonged bactericidal antibiotic therapy (4-6 weeks) and surgical evaluation for all patients.",clinicalPresentation:"Classic triad: fever + new murmur + embolic phenomena — but the full triad is present in <50% at presentation. Fever is the most common finding (>90%). New or changing heart murmur (85%). Embolic events (20-50%): stroke, pulmonary emboli (right-sided), splenic infarcts, renal infarcts, mycotic aneurysms. Peripheral stigmata (less common in modern era): Janeway lesions (painless erythematous lesions on palms/soles — septic emboli), Osler nodes (painful nodules on finger/toe pads — immune complex), splinter hemorrhages (linear hemorrhages in nail beds), Roth spots (retinal hemorrhages with white center). Right-sided IE (tricuspid): presents with septic pulmonary emboli — cough, pleuritic chest pain, bilateral nodular infiltrates on CXR. Think right-sided IE in IDU with bilateral pulmonary nodules.",diagnostics:"MODIFIED DUKE CRITERIA (2023 update): MAJOR CRITERIA: (1) Blood cultures — 2 separate cultures with typical IE organism (S. aureus, viridans Streptococci, S. gallolyticus, HACEK, community-acquired Enterococcus without primary focus), OR persistently positive cultures (≥2 drawn >12h apart, or all of 3 or majority of ≥4 separate cultures with first and last >1h apart), OR single positive for Coxiella burnetii or IgG >1:800. (2) Imaging — echocardiography showing vegetation, abscess, pseudoaneurysm, intracardiac fistula, valvular perforation/aneurysm, or new partial dehiscence of prosthetic valve; OR abnormal FDG-PET/CT activity at prosthetic valve; OR paravalvular lesions on cardiac CT. MINOR CRITERIA: (1) Predisposing heart condition or IDU, (2) Fever ≥38°C, (3) Vascular phenomena (arterial emboli, septic pulmonary infarcts, mycotic aneurysm, intracranial hemorrhage, conjunctival hemorrhages, Janeway lesions), (4) Immunologic phenomena (glomerulonephritis, Osler nodes, Roth spots, positive RF), (5) Microbiologic evidence not meeting major criterion. DEFINITE IE: 2 major, or 1 major + 3 minor, or 5 minor. POSSIBLE IE: 1 major + 1 minor, or 3 minor.",durationGuidance:{standard:"4–6 weeks (native valve)",severe:"6 weeks (prosthetic valve/complicated)",opatNote:"OPAT eligible after initial clinical stabilization. Requires reliable venous access, daily clinical assessment, and close outpatient follow-up."},empiricTherapy:[{line:"Empiric — Native Valve (Pending Cultures)",options:[{drug:"vancomycin-plus-ceftriaxone-empiric",regimen:"Vancomycin IV (AUC-guided) + Ceftriaxone 2g IV q12h",notes:"Covers MRSA + MSSA + Streptococci + Enterococci + HACEK. Broad empiric regimen for acute IE when organism is unknown. Narrow once cultures return. If hemodynamically unstable, some add gentamicin 1mg/kg IV q8h for the first 3-5 days for synergistic killing (controversial — not routinely recommended due to nephrotoxicity).",evidence:"A-I",evidenceSource:"AHA/IDSA 2023"}]},{line:"MSSA Native Valve IE",options:[{drug:"cefazolin",regimen:"Cefazolin 2g IV q8h × 6 weeks",notes:"Preferred over nafcillin/oxacillin based on safety profile and practical advantages (q8h dosing enables OPAT). Non-inferior to nafcillin in multiple observational studies. AHA 2015 lists nafcillin/oxacillin as first-line but most ID pharmacists and many ID physicians have shifted to cefazolin.",evidence:"A-I",evidenceSource:"AHA/IDSA 2023"},{drug:"nafcillin-oxacillin",regimen:"Nafcillin or Oxacillin 12g/day IV continuous infusion or 2g IV q4h × 6 weeks",notes:"Traditional gold standard. Still preferred by some for aortic valve IE or complicated cases. Continuous infusion optimizes time-dependent killing. Major disadvantages: phlebitis, hepatotoxicity (oxacillin), interstitial nephritis (nafcillin), q4h dosing if intermittent.",evidence:"A-I",evidenceSource:"AHA/IDSA 2023"}]},{line:"MRSA Native Valve IE",options:[{drug:"vancomycin",regimen:"Vancomycin IV (AUC/MIC 400-600) × 6 weeks",notes:"Standard therapy for MRSA IE. AUC-guided dosing with Bayesian software. Monitor renal function closely — 6 weeks of vancomycin carries significant nephrotoxicity risk. Consider early switch to daptomycin if renal function deteriorates."},{drug:"daptomycin",regimen:"Daptomycin 8-10 mg/kg IV daily × 6 weeks",notes:"FDA-approved for right-sided S. aureus IE at 6 mg/kg, but most experts use 8-10 mg/kg for all IE. Preferred over vancomycin for MRSA IE by many ID pharmacists because of: concentration-dependent bactericidal activity, less nephrotoxicity, once-daily dosing, no need for therapeutic drug monitoring (just CPK). AHA guidelines list vancomycin as first-line and daptomycin as alternative, but practice is shifting."}]},{line:"Streptococcal Native Valve IE (Viridans group, S. gallolyticus)",options:[{drug:"penicillin-strep-ie",regimen:"Penicillin G 12-18 million units/day IV continuous or divided q4h × 4 weeks",notes:"For penicillin-susceptible strains (MIC ≤0.12). Can shorten to 2 weeks if combined with gentamicin 3mg/kg/day IV divided q8h (2-week short-course regimen — AHA endorsed for uncomplicated native valve IE with penicillin-susceptible Streptococci in patients with normal renal function)."},{drug:"ceftriaxone",regimen:"Ceftriaxone 2g IV once daily × 4 weeks",notes:"Equivalent efficacy to penicillin G. MAJOR ADVANTAGE: once-daily dosing makes it the preferred agent for OPAT. Can combine with gentamicin for 2-week short course (same criteria as penicillin). S. gallolyticus (formerly S. bovis) endocarditis: ALWAYS get colonoscopy — strong association with colorectal neoplasia (adenomas and carcinomas)."}]},{line:"Enterococcal Native Valve IE",options:[{drug:"ampicillin-gent-ie",regimen:"Ampicillin 2g IV q4h + Gentamicin 1mg/kg IV q8h × 4-6 weeks",notes:"Traditional regimen for ampicillin-susceptible, non-high-level gentamicin resistant (non-HLGR) E. faecalis. Gentamicin provides synergistic bactericidal activity. HLGR testing is mandatory — if HLGR positive, gentamicin is useless and should not be used. Duration: 4 weeks for native valve with symptoms <3 months, 6 weeks if symptoms >3 months."},{drug:"ampicillin-ceftriaxone-ie",regimen:"Ampicillin 2g IV q4h + Ceftriaxone 2g IV q12h × 6 weeks",notes:"PREFERRED regimen for E. faecalis IE per many experts. The double beta-lactam combination provides synergistic killing via binding of complementary PBPs (ampicillin = PBP4/5, ceftriaxone = PBP3). KEY ADVANTAGE: avoids aminoglycoside nephrotoxicity and ototoxicity over a 6-week course. Works even in HLGR strains (because synergy is beta-lactam based, not aminoglycoside based). Data from Spanish cohort studies (Fernández-Hidalgo) showed equivalent outcomes with less toxicity."},{drug:"daptomycin-vre-ie",regimen:"Daptomycin 10-12 mg/kg IV daily ± ampicillin (if ampicillin-susceptible) × 6 weeks",notes:"For VRE (E. faecium) endocarditis — one of the most challenging IE organisms. High-dose daptomycin is the backbone. Adding ampicillin (even if the organism is 'ampicillin-susceptible' VRE, which is rare) enhances daptomycin activity by increasing cell membrane binding. Linezolid 600mg IV/PO BID is an alternative but bacteriostatic — less ideal for endocarditis. Consult ID. Mortality for VRE IE approaches 40-50%."}]},{line:"Surgical Indications (Refer to CT Surgery)",options:[{drug:"surgery-indications",regimen:"Early surgical consultation for ALL left-sided IE",notes:"CLASS I (STRONG) indications for surgery: (1) Heart failure due to valve dysfunction (most common surgical indication), (2) Valve dehiscence/perforation/fistula, (3) Perivalvular abscess/pseudoaneurysm, (4) Persistent bacteremia >5-7 days despite appropriate therapy and source control, (5) Recurrent emboli despite appropriate antibiotics (especially with persistent vegetations >10mm), (6) Fungal IE (almost always requires surgery). CLASS IIa indications: large mobile vegetations >10mm (particularly with prior embolic event), early IE caused by highly virulent organisms (S. aureus, fungi) with valve destruction. Timing: emergency (within 24h) for refractory pulmonary edema or cardiogenic shock; urgent (within days) for uncontrolled infection or high embolic risk; elective (within 1-2 weeks) for progressive valve dysfunction."}]}],organismSpecific:[{organism:"Viridans group Streptococci (S. mutans, S. mitis, S. sanguinis, etc.)",preferred:"Penicillin G or ceftriaxone × 4 weeks (or 2-week short course with gentamicin)",alternative:"Vancomycin 15mg/kg IV q12h × 4 weeks if beta-lactam allergy",notes:"Most common cause of subacute native valve IE. Almost always penicillin-susceptible. Poor dentition is the classic risk factor. Subacute presentation: weeks of low-grade fever, malaise, weight loss. Blood cultures are almost always positive (>95%). Prognosis is GOOD with appropriate therapy — mortality <5% for uncomplicated viridans streptococcal IE."},{organism:"S. gallolyticus (formerly S. bovis biotype I)",preferred:"Same as viridans Streptococci — penicillin G or ceftriaxone",alternative:"Vancomycin if beta-lactam allergy",notes:"MANDATORY COLONOSCOPY for all S. gallolyticus bacteremia/IE — 25-80% association with colorectal neoplasia (polyps and carcinomas). This is not optional. If the initial colonoscopy is negative, repeat in 3-5 years. Also associated with chronic liver disease. Prognosis is similar to other Streptococcal IE."},{organism:"Enterococcus faecalis",preferred:"Ampicillin + ceftriaxone × 6 weeks (preferred) or ampicillin + gentamicin × 4-6 weeks (if non-HLGR)",alternative:"Vancomycin + gentamicin if ampicillin-resistant",notes:"Third most common IE organism. Check HLGR status — if HLGR positive, aminoglycosides are useless. Ampicillin + ceftriaxone double beta-lactam regimen avoids aminoglycoside toxicity and is now preferred by most experts. Source: often GU tract (TURP, urinary catheter) or GI tract. Duration is 6 weeks."},{organism:"HACEK organisms (Haemophilus, Aggregatibacter, Cardiobacterium, Eikenella, Kingella)",preferred:"Ceftriaxone 2g IV daily × 4 weeks",alternative:"Ampicillin-sulbactam 3g IV q6h × 4 weeks",notes:"Fastidious gram-negatives that are classic IE organisms. Slow-growing — may take 5-7 days to turn positive in culture (extended incubation). Respond well to ceftriaxone. Excellent prognosis with appropriate therapy. Some produce beta-lactamase — ampicillin alone is not reliable."}],pearls:["DUKE CRITERIA ARE A FRAMEWORK, NOT A CHECKLIST: Clinical judgment supersedes strict Duke criteria application. A patient with SAB, a vegetation on TEE, and septic emboli has endocarditis regardless of whether they technically meet 'definite' criteria. Conversely, 'possible IE' should be treated as IE until proven otherwise in high-risk patients.","S. GALLOLYTICUS = COLONOSCOPY. ALWAYS. No exceptions. 25-80% association with colorectal neoplasia. Failure to scope is a missed cancer diagnosis.","ORAL STEP-DOWN (POET TRIAL): After ≥10 days of IV therapy + clinical stability (afebrile, CRP decreasing, no signs of complications), selected patients with left-sided IE can switch to high-dose oral therapy. Key exclusions: prosthetic valve IE <1 year, aortic root abscess, large vegetations, severe valve dysfunction. Oral regimens must be HIGH-DOSE (e.g., amoxicillin 1g q6h, not standard doses). This is not permission to send everyone home on oral amoxicillin at day 10.","RIGHT-SIDED IE IN IDU: Tricuspid valve IE (predominantly S. aureus) in IDU can often be treated for 2 weeks (if MSSA, no metastatic infection, and vegetation <2cm) — this is a well-established shorter duration. Right-sided IE generally has better prognosis than left-sided. However, the opioid epidemic has complicated this — patients often leave AMA, relapse, and present with recurrent IE.","CULTURE-NEGATIVE ENDOCARDITIS: ~10% of IE cases have negative blood cultures. Causes: prior antibiotics (most common — always try to get cultures BEFORE antibiotics), fastidious organisms (HACEK, Bartonella, Coxiella burnetii, Tropheryma whipplei, Brucella), non-bacterial thrombotic endocarditis (marantic endocarditis in malignancy or antiphospholipid syndrome). Serologies for Bartonella and Coxiella should be sent in all culture-negative IE. 16S rRNA PCR on explanted valve tissue is definitive."]},{id:"prosthetic-valve-ie",name:"Prosthetic Valve Endocarditis",definition:"IE involving a prosthetic heart valve (mechanical or bioprosthetic), representing 20-30% of all IE cases. Classified as early (≤12 months post-surgery, typically healthcare-associated organisms) or late (>12 months, organisms resemble native valve IE). PVE carries higher mortality (20-40%) and more frequently requires surgical intervention compared to native valve IE.",clinicalPresentation:"Similar to native valve IE but often more indolent. Early PVE: acute presentation, high fevers, embolic events, rapid valve dysfunction. Late PVE: subacute, resembles native valve IE. Key differences from native valve IE: higher rate of perivalvular abscess (40-50% — much higher than native valve), valve dehiscence (rocking prosthesis on echo — pathognomonic), paravalvular leak (new regurgitant jet around the prosthesis). Higher rate of conduction abnormalities (new heart block suggests septal abscess extending into the conduction system — get ECG daily). PET/CT is particularly useful for prosthetic valve IE diagnosis when echo is equivocal.",diagnostics:"Same Duke criteria framework but with additional imaging modalities: (1) TEE is MANDATORY (TTE sensitivity for PVE is even lower due to acoustic shadowing from prosthetic material). (2) Cardiac CT can identify perivalvular abscess, pseudoaneurysm, and fistula with better spatial resolution than TEE. (3) FDG-PET/CT is a 2023 Duke major criterion — abnormal metabolic activity around a prosthetic valve is highly specific for PVE (especially useful when echo is equivocal). Sensitivity increases >3 months post-surgery (early post-op inflammation can cause false positives). (4) ECG daily — new PR prolongation or heart block suggests septal/aortic root abscess. (5) Blood cultures, inflammatory markers, and full septic workup as per native valve IE.",empiricTherapy:[{line:"Empiric — Early PVE (<12 months post-surgery)",options:[{drug:"vanc-gent-rifampin-early-pve",regimen:"Vancomycin IV + Gentamicin 1mg/kg IV q8h + Rifampin 300-450mg PO q8h",notes:"Broad coverage for healthcare-associated organisms: Staphylococci (including MRSA and CoNS), Enterococci, gram-negatives. Rifampin is included for biofilm-active coverage (prosthetic material). Narrow based on culture results. Gentamicin for synergy — use for first 2 weeks only, then reassess based on pathogen."}]},{line:"Empiric — Late PVE (>12 months post-surgery)",options:[{drug:"vanc-ceftriaxone-late-pve",regimen:"Vancomycin IV + Ceftriaxone 2g IV q12h",notes:"Similar coverage to native valve empiric regimen. Late PVE organisms resemble native valve IE (Streptococci, Staphylococci, Enterococci). Add rifampin once Staphylococcal PVE is confirmed. Narrow based on cultures."}]},{line:"Staphylococcal PVE (Directed Therapy)",options:[{drug:"mssa-pve",regimen:"Nafcillin/Cefazolin + Rifampin 300-450mg PO q8h × 6 weeks + Gentamicin × first 2 weeks",notes:"MSSA PVE: beta-lactam backbone + rifampin for biofilm + gentamicin for early synergistic killing. Rifampin is ESSENTIAL for prosthetic valve infections — it is the only commonly used antibiotic that penetrates and kills within biofilm. NEVER use rifampin as monotherapy (rapid resistance). Always use with a companion drug that has good activity against the organism."},{drug:"mrsa-pve",regimen:"Vancomycin IV (AUC-guided) + Rifampin 300-450mg PO q8h × 6 weeks + Gentamicin × first 2 weeks",notes:"MRSA PVE: vancomycin + rifampin + gentamicin. This is the ONE scenario where rifampin IS recommended in S. aureus infection (prosthetic material — unlike native valve SAB per ARREST trial). Duration: minimum 6 weeks from first negative blood culture. Higher surgical threshold — but surgery still indicated for valve dysfunction, abscess, persistent bacteremia, recurrent emboli."}]},{line:"Surgical Indications — PVE Specific",options:[{drug:"surgery-pve",regimen:"Lower threshold for surgery than native valve IE",notes:"Surgery is indicated for: valve dehiscence, perivalvular abscess, new paravalvular regurgitation, heart failure from prosthetic dysfunction, persistent bacteremia despite appropriate therapy, relapsing PVE, fungal PVE. Early PVE (especially Staphylococcal) has higher surgical rates (>50%). The endocarditis team (ID, CT surgery, cardiology) should evaluate ALL PVE patients for surgical candidacy."}]}],organismSpecific:[{organism:"CoNS (S. epidermidis, S. lugdunensis)",preferred:"Vancomycin + rifampin × 6 weeks + gentamicin × 2 weeks (most CoNS are methicillin-resistant)",alternative:"If methicillin-susceptible: nafcillin/cefazolin + rifampin + gentamicin",notes:"CoNS is the MOST COMMON cause of early PVE. S. epidermidis is the classic biofilm-forming organism on prosthetic material. Almost always methicillin-resistant (80-90%). S. lugdunensis is uniquely virulent among CoNS — behaves more like S. aureus, causes aggressive native valve IE. Treat S. lugdunensis like S. aureus (not like other CoNS)."},{organism:"Fungal (Candida, Aspergillus)",preferred:"Amphotericin B liposomal + surgery (almost always required)",alternative:"High-dose echinocandin (micafungin 150mg daily or caspofungin 150mg daily) for Candida if surgery not possible",notes:"Fungal IE is rare but devastating (mortality >50%). Almost always requires surgical valve replacement — antifungals alone are rarely curative for fungal IE. Lifelong suppressive therapy (fluconazole for Candida, voriconazole for Aspergillus) may be needed after surgery, especially if prosthetic valve cannot be fully debrided."}],pearls:["RIFAMPIN IS FOR PROSTHETICS, NOT NATIVE VALVES: The ARREST trial showed no benefit of rifampin in native valve SAB. But for prosthetic valve IE, rifampin is ESSENTIAL — it penetrates biofilm and kills sessile bacteria that other antibiotics cannot reach. Never use rifampin alone (resistance in 1-2 days). Always pair with an active companion drug.","EARLY vs LATE PVE: Early PVE (<12 months) = healthcare-associated organisms (CoNS, S. aureus, gram-negatives, fungi). Late PVE (>12 months) = community-acquired organisms (Streptococci, Enterococci, S. aureus). This distinction guides empiric therapy.","NEW HEART BLOCK = SEPTAL ABSCESS UNTIL PROVEN OTHERWISE: Any new conduction abnormality (PR prolongation, bundle branch block, complete heart block) in PVE suggests the infection has extended into the septum. This is a SURGICAL EMERGENCY — get CT surgery involved immediately.","PET/CT IS A GAME-CHANGER FOR PVE: When TTE/TEE are equivocal (common with prosthetic valves due to acoustic shadowing), FDG-PET/CT can identify perivalvular infection with high specificity. Now a formal Duke major criterion (2023 update). Best used >3 months post-surgery to avoid false positives from post-operative inflammation."]},{id:"gram-negative-bacteremia",name:"Gram-Negative Bacteremia",definition:"Bloodstream infection caused by gram-negative bacilli, most commonly Enterobacterales (E. coli, Klebsiella, Proteus) originating from urinary, intra-abdominal, or hepatobiliary sources. Management priorities: source identification and control, appropriate empiric therapy, and rapid de-escalation based on susceptibilities. Duration varies by source.",clinicalPresentation:"Gram-negative bacteremia often presents acutely: high fevers, rigors, hypotension, and rapid clinical deterioration. Source-specific presentations: urinary source — dysuria, flank pain, pyuria; intra-abdominal — abdominal pain, peritoneal signs; biliary — RUQ pain, jaundice (Charcot triad), cholangitis; pneumonia — cough, hypoxia, infiltrates; line-related — erythema/purulence at catheter site. E. coli is the most common organism, followed by Klebsiella. Pseudomonas bacteremia carries higher mortality and typically involves immunocompromised hosts or healthcare-associated sources.",diagnostics:"Blood cultures (2 sets from separate sites before antibiotics), source-directed imaging (CT abdomen for intra-abdominal source, renal US or CT for urinary obstruction, biliary US for cholangitis), urinalysis and urine culture, sputum culture if respiratory symptoms. For resistant organisms: request confirmatory susceptibility testing for ESBL, AmpC, and carbapenemase production (CRE). Follow-up blood cultures at 48-72h to document clearance (less rigidly mandated than SAB, but recommended for high-risk infections — Pseudomonas, CRE, immunocompromised, or persistent fever).",empiricTherapy:[{line:"Empiric — Community-Acquired, Low Resistance Risk",options:[{drug:"ceftriaxone",regimen:"Ceftriaxone 2g IV daily",notes:"Excellent first-line empiric for community-acquired GN bacteremia from urinary or intra-abdominal source. Covers most community E. coli, Klebsiella, Proteus. Does NOT cover ESBL producers, AmpC producers (Enterobacter, Citrobacter, Serratia), or Pseudomonas. Add metronidazole if intra-abdominal source suspected (anaerobic coverage)."}]},{line:"Empiric — Healthcare-Associated or MDR Risk Factors",options:[{drug:"piperacillin-tazobactam",regimen:"Piperacillin-tazobactam 4.5g IV q6h (extended infusion over 4h)",notes:"Broader empiric coverage including Pseudomonas. Extended infusion optimizes PK/PD for beta-lactams. Consider if recent healthcare exposure, prior resistant organisms, or immunocompromised. MERINO trial reminder: for ESBL bacteremia, pip-tazo was INFERIOR to meropenem (30-day mortality 12.3% vs 3.7%). De-escalate based on susceptibilities."},{drug:"meropenem",regimen:"Meropenem 1g IV q8h (extended infusion over 3h preferred)",notes:"Reserve for high suspicion of ESBL or AmpC-producing organisms, or critically ill patients. Definitive therapy for confirmed ESBL bacteremia (per MERINO trial). De-escalate as soon as susceptibilities allow — carbapenem stewardship matters."}]},{line:"Directed Therapy — Duration by Source",options:[{drug:"duration-gn-uti",regimen:"Urinary source: 7-14 days (shorter for uncomplicated, longer for complicated)",notes:"IDSA 2025 cUTI guideline supports 7 days for most complicated UTI with bacteremia, with IV-to-PO switch when clinically improving and susceptibilities allow. Fluoroquinolones and TMP-SMX have excellent oral bioavailability and can be used for step-down."},{drug:"duration-gn-iai",regimen:"Intra-abdominal source: 4-7 days after source control",notes:"STOP-IT trial established 4 days of antibiotics after adequate source control for complicated intra-abdominal infections. If source control is inadequate, longer duration is needed. Bacteremia from IAI source does not independently mandate longer therapy if source is controlled."},{drug:"duration-gn-unknown",regimen:"Unknown/other source: 7-14 days based on clinical response",notes:"Without clear source, treat for 10-14 days. If source is identified and controlled, shorter courses may be appropriate. Pseudomonas bacteremia: generally 14 days due to higher relapse risk. CRE bacteremia: 14 days with close follow-up."}]}],organismSpecific:[{organism:"E. coli (susceptible)",preferred:"Ceftriaxone, fluoroquinolone, or TMP-SMX (based on susceptibilities)",alternative:"Pip-tazo, ampicillin-sulbactam (if susceptible)",notes:"Most common GN BSI organism. ~80-85% remain ceftriaxone-susceptible in community settings. High fluoroquinolone resistance in some areas (20-40%). If susceptible to oral agents (FQ, TMP-SMX), early oral step-down is appropriate."},{organism:"ESBL-producing Enterobacterales",preferred:"Meropenem (per MERINO trial)",alternative:"TMP-SMX IV/PO if susceptible (emerging data supporting non-carbapenem options for urinary source), ceftazidime-avibactam",notes:"MERINO trial: pip-tazo INFERIOR to meropenem for ESBL bacteremia — do NOT use pip-tazo even if in vitro susceptible. Meropenem is standard. For non-severe infections with susceptible urinary source, some data supports TMP-SMX or ciprofloxacin for step-down."},{organism:"Pseudomonas aeruginosa",preferred:"Cefepime 2g IV q8h or pip-tazo 4.5g IV q6h or meropenem (based on susceptibilities)",alternative:"Ceftazidime, aztreonam (if beta-lactam allergic), ceftolozane-tazobactam (for MDR strains)",notes:"Always check susceptibilities — Pseudomonas resistance is highly variable. Double coverage (two active anti-pseudomonal agents) is NOT routinely recommended for bacteremia — a single susceptible agent is sufficient for definitive therapy. Pseudomonas bacteremia carries higher mortality and 14-day treatment is standard."}],pearls:["MERINO TRIAL: Pip-tazo is INFERIOR to meropenem for definitive treatment of ESBL bacteremia. This was an RCT — not observational data. Even if ESBL E. coli tests 'susceptible' to pip-tazo in vitro, use meropenem. The inoculum effect may explain the discrepancy between in vitro and in vivo results.","SOURCE CONTROL IS THE MOST IMPORTANT INTERVENTION: Antibiotics alone cannot cure bacteremia if the source is undrained. Obstructed kidney → percutaneous nephrostomy. Cholangitis → ERCP. Abscess → drain it. Line infection → pull the line. Always address the source.","IV-TO-ORAL STEP-DOWN IS SAFE: For GN bacteremia from a urinary source, early oral step-down (at 48-72h if clinically improving, afebrile, tolerating PO) is supported by multiple studies and the IDSA 2025 cUTI guideline. Use agents with high oral bioavailability: fluoroquinolones, TMP-SMX. Do not keep patients on unnecessary IV therapy.","FOLLOW-UP BLOOD CULTURES FOR GN BSI: Not as rigidly mandated as for SAB, but recommended for: Pseudomonas, CRE, immunocompromised patients, persistent fever, and when source control is uncertain. Documentation of clearance helps determine duration."]},{id:"opat-considerations",name:"OPAT — Outpatient Parenteral Antibiotic Therapy",definition:"Administration of IV antibiotics in the outpatient setting (home infusion, infusion center, or skilled nursing facility). Critical for completing prolonged courses of bactericidal therapy for endocarditis, osteomyelitis, and complicated bacteremia without extended hospitalization. Requires careful patient selection, monitoring protocols, and coordination between ID, pharmacy, and home health.",clinicalPresentation:"N/A — this subcategory covers management, not diagnosis.",diagnostics:"N/A — this subcategory covers management, not diagnosis.",empiricTherapy:[{line:"OPAT-Friendly Agents — Dosing Frequency Matters",options:[{drug:"ceftriaxone",regimen:"Ceftriaxone 2g IV once daily",notes:"THE ideal OPAT antibiotic — once-daily dosing, stable in elastomeric pump, broad spectrum, well-tolerated. First-line for Streptococcal IE, GN bacteremia step-down, many osteomyelitis regimens. Biliary sludging/pseudolithiasis risk with prolonged use — monitor LFTs, warn patients about RUQ pain."},{drug:"cefazolin",regimen:"Cefazolin 2g IV q8h (or q12h with probenecid in select cases)",notes:"Workhorse for MSSA infections (bacteremia, endocarditis, osteomyelitis). Q8h dosing is manageable with elastomeric pump (24h pump refilled daily by home health). The probenecid trick (1g PO BID) extends half-life for potential q12h dosing — used at some OPAT programs, limited evidence."},{drug:"daptomycin",regimen:"Daptomycin 6-10 mg/kg IV once daily",notes:"Excellent OPAT agent for MRSA/VRE: once-daily dosing, no therapeutic drug monitoring needed (just weekly CPK), minimal drug interactions. Gravity infusion over 30 min or IV push over 2 min (push approved for doses ≤500mg). Cost is the main limitation."},{drug:"ertapenem",regimen:"Ertapenem 1g IV once daily",notes:"Once-daily carbapenem for ESBL infections, complex polymicrobial infections (including anaerobes). Does NOT cover Pseudomonas or Acinetobacter. Ideal for OPAT when broader coverage is needed. Seizure risk (lower than other carbapenems but still present, especially in renal impairment)."}]},{line:"Monitoring on OPAT",options:[{drug:"opat-monitoring",regimen:"Weekly labs: CBC, CMP, CRP. Drug-specific: vancomycin AUC, aminoglycoside levels, CPK (daptomycin), LFTs (ceftriaxone, rifampin)",notes:"Standard OPAT monitoring: CBC with differential (neutropenia from prolonged beta-lactams), BMP (renal function), hepatic panel, CRP trending (inflammatory marker response). Drug-specific monitoring is essential. Vancomycin OPAT requires AUC-guided dosing — coordinate with pharmacy for levels and adjustments. Weekly clinical assessment by nurse or physician for line complications, drug adverse effects, and clinical response. PICC line care: dressing changes q7 days, flush per protocol, monitor for infection/thrombosis."}]},{line:"Patient Selection Criteria",options:[{drug:"opat-selection",regimen:"Clinical stability + reliable access + ability to recognize complications",notes:"Ideal OPAT candidates: clinically stable (afebrile ≥48h, improving), reliable IV access (PICC or midline), able to manage or have caregiver for infusion equipment, have reliable follow-up with ID/pharmacy, can recognize and report complications (fever, line issues, drug reactions). Contraindications to OPAT: active IDU (high line misuse risk — consider alternatives like daily infusion center), unstable housing, inability to comply with monitoring, ongoing hemodynamic instability. POET trial oral step-down may eliminate OPAT need for selected IE patients."}]}],organismSpecific:[],pearls:["POET TRIAL CHANGED OPAT FOR IE: Before POET, all left-sided IE required 4-6 weeks of IV therapy = mandatory OPAT (or prolonged hospitalization). Now, selected patients can switch to oral at ≥10 days, potentially avoiding OPAT altogether. This is a massive quality-of-life improvement.","PICC LINE COMPLICATIONS: DVT (2-5% per PICC), CLABSI (0.5-2 per 1000 catheter-days), mechanical complications (occlusion, migration, fracture). Midline catheters have lower DVT risk but shorter dwell time and cannot be used for vesicant drugs. For short courses (<14 days), consider midline over PICC.","OPAT FOR IDU PATIENTS: Active IDU is NOT an absolute contraindication to OPAT, but requires careful risk-benefit discussion and harm reduction approach. Options: (1) Daily observed therapy at infusion center, (2) Long-acting lipoglycopeptides (dalbavancin q2 weeks — emerging data), (3) Oral step-down per POET criteria if applicable, (4) Extended hospitalization with addiction medicine support. A one-size-fits-all approach fails these patients.","ERTAPENEM IS YOUR FRIEND: The only once-daily carbapenem, making it ideal for OPAT when ESBL or complex polymicrobial coverage is needed. Does NOT cover Pseudomonas — always confirm susceptibilities before OPAT discharge."]}],drugMonographs:[{id:"nafcillin",name:"Nafcillin",brandNames:"Nallpen (discontinued brand), generic",drugClass:"Anti-staphylococcal penicillin (penicillinase-resistant)",mechanismOfAction:"Binds PBPs (particularly PBP2) inhibiting cell wall synthesis. Bactericidal, time-dependent killing (optimize fT>MIC). Designed to resist hydrolysis by staphylococcal penicillinase (beta-lactamase). This is the ORIGINAL anti-MSSA drug. Narrow spectrum by design — targets Staphylococci specifically, with minimal gram-negative or anaerobic coverage.",spectrum:"MSSA (drug of choice historically), Streptococci (good activity). GAPS: MRSA (no activity — this is the defining resistance mechanism), gram-negatives, Enterococcus, anaerobes. Essentially a Staphylococcal-targeted antibiotic.",dosing:{standard:"2g IV q4h (most infections)",endocarditis:"12g/day — either 2g IV q4h or continuous infusion 12g/24h",osteomyelitis:"2g IV q4h × 6 weeks",meningitis:"2g IV q4h (good CSF penetration — unlike cefazolin)"},renalAdjustment:"No dose adjustment — primarily hepatically metabolized. This is an advantage in renal impairment patients. However, nafcillin itself can cause interstitial nephritis (paradoxical).",hepaticAdjustment:"Use with caution in hepatic impairment — hepatically cleared. Oxacillin (the related drug) is MORE hepatotoxic. Monitor LFTs if prolonged course.",adverseEffects:{common:"Phlebitis (very common — requires frequent IV site changes or central access), rash, nausea",serious:"Interstitial nephritis (higher than cefazolin), neutropenia (with prolonged courses >2 weeks — reversible), hepatotoxicity, hypokalemia",rare:"Anaphylaxis, seizures (at very high doses), hemorrhagic cystitis"},drugInteractions:["Warfarin — nafcillin is a potent CYP450 inducer. Can DECREASE warfarin effect significantly (opposite of most antibiotics which increase INR). Monitor INR closely when starting AND stopping nafcillin.","Cyclosporine — nafcillin decreases cyclosporine levels via CYP3A4 induction. Monitor levels.","Methotrexate — potential delayed clearance and increased toxicity."],monitoring:"CBC with differential q1-2 weeks (neutropenia risk), BMP (interstitial nephritis — rising creatinine, eosinophilia), LFTs for prolonged courses, signs of phlebitis at IV site. If on warfarin: INR closely when starting/stopping.",pregnancyLactation:"Pregnancy Category B. Crosses placenta. Excreted in breast milk. Generally considered safe in pregnancy when indicated.",pharmacistPearls:["CEFAZOLIN HAS LARGELY REPLACED NAFCILLIN: For most MSSA infections (including bacteremia and endocarditis), cefazolin 2g IV q8h is preferred. Advantages of cefazolin: q8h dosing (vs q4h), less phlebitis, less nephrotoxicity, less hepatotoxicity, OPAT-friendly. Multiple observational studies show non-inferiority or superiority. Reserve nafcillin for: meningitis (better CSF penetration than cefazolin) and treatment failure on cefazolin (rare).","CSF PENETRATION — THE ONE ADVANTAGE OVER CEFAZOLIN: Nafcillin achieves adequate CSF concentrations with inflamed meninges. Cefazolin does NOT reliably penetrate the CNS. For MSSA meningitis or brain abscess, nafcillin (or oxacillin) is preferred over cefazolin.","WARFARIN INTERACTION IS UNIQUE: Most antibiotics increase INR by disrupting gut flora vitamin K synthesis. Nafcillin does the OPPOSITE — it induces CYP enzymes and DECREASES INR. This catches many clinicians off guard. Monitor INR closely, and be aware that the effect reverses when nafcillin is stopped (INR may rebound upward).","CONTINUOUS INFUSION FOR ENDOCARDITIS: Nafcillin (and oxacillin) can be administered as continuous infusion (12g in 24h via pump). This maximizes fT>MIC and is preferred by some ID physicians for endocarditis. Practical for OPAT with elastomeric pumps.","NEUTROPENIA ON PROLONGED COURSES: ~5-15% incidence with courses >2 weeks. Mechanism is likely immune-mediated. Reversible upon discontinuation. Monitor CBC weekly. If ANC drops, consider switching to cefazolin (lower neutropenia risk)."]},{id:"vancomycin",name:"Vancomycin",brandNames:"Vancocin",drugClass:"Glycopeptide antibiotic",mechanismOfAction:"Binds to D-Ala-D-Ala terminus of peptidoglycan precursors, preventing cell wall cross-linking and synthesis. Bactericidal but SLOWLY bactericidal — slower kill kinetics than beta-lactams. This is why vancomycin is INFERIOR to cefazolin/nafcillin for MSSA. AUC/MIC is the PK/PD parameter that best predicts efficacy (2020 consensus — replaces trough-based dosing).",spectrum:"Gram-positive ONLY. Excellent: MRSA (drug of choice), MSSA (but inferior to beta-lactams), Streptococci, most Enterococci (NOT VRE — E. faecium with vanA/vanB). Excellent: CoNS, C. difficile (oral only — IV vancomycin does NOT reach the colon). GAPS: ALL gram-negatives, VRE, organisms with vanA/vanB resistance genes.",dosing:{auc_guided:"AUC/MIC target 400-600 (2020 consensus). Use Bayesian dosing software for precision. Typical: 15-20 mg/kg (actual body weight) q8-12h. Loading dose: 25-30 mg/kg (max 3g) for critically ill patients.",endocarditis:"AUC-guided, typically 15-20 mg/kg IV q8-12h × 6 weeks (native valve) or 6 weeks + rifampin (prosthetic valve)",bacteremia:"AUC-guided, 14 days (uncomplicated SAB) to 4-6 weeks (complicated/IE)",meningitis:"15-20 mg/kg IV q8-12h (target trough 15-20 for CNS penetration — AUC equivalent ~600-800) + adjunctive dexamethasone for pneumococcal meningitis",oral_c_diff:"125mg PO QID × 10 days (standard C. diff regimen — does NOT require IV-to-oral conversion, this is a different route and indication)"},renalAdjustment:"Renally eliminated — requires dose adjustment. AUC-guided dosing with Bayesian software automatically accounts for renal function. General guidance: CrCl 40-60: q12h dosing; CrCl 20-40: q24h; CrCl <20 or HD: dose after HD (check level pre-next dose). CRRT: 15-20 mg/kg q24h (highly variable — institution-dependent, use levels). The 2020 consensus strongly recommends AUC-guided dosing over trough-based — this has reduced vancomycin-associated AKI.",hepaticAdjustment:"No dose adjustment — renally eliminated. No hepatotoxicity.",adverseEffects:{common:"Nephrotoxicity (10-20% — major limiting toxicity, especially with concurrent nephrotoxins like pip-tazo), Red Man Syndrome (histamine-mediated infusion reaction — rate-related, NOT allergy; slow infusion to ≥1h per 500mg), thrombocytopenia (5-10%)",serious:"Acute kidney injury (dose-dependent, AUC-guided dosing reduces risk vs trough-based), ototoxicity (rare at modern doses but possible with prolonged courses or concurrent aminoglycosides), vancomycin-induced linear IgA bullous dermatosis (rare but distinctive rash), DRESS syndrome",rare:"Neutropenia (prolonged courses), anaphylaxis (distinct from Red Man Syndrome — true IgE-mediated), sensorineural hearing loss"},drugInteractions:["Piperacillin-tazobactam — SYNERGISTIC NEPHROTOXICITY. The combination of vancomycin + pip-tazo has higher AKI rates (20-35%) than vancomycin + cefepime (~10%) or vancomycin alone. Prefer vancomycin + cefepime when anti-pseudomonal coverage is needed alongside MRSA coverage.","Aminoglycosides — additive nephrotoxicity and ototoxicity. Minimize concurrent use; if necessary, monitor renal function and drug levels closely.","Loop diuretics (furosemide) — may enhance ototoxicity risk. Monitor hearing with prolonged concurrent use.","NSAIDs — may increase risk of AKI when combined with vancomycin.","Contrast dye — additive nephrotoxicity risk. Hydrate aggressively if contrast study needed during vancomycin therapy."],monitoring:"AUC-guided dosing with Bayesian software (2020 consensus): obtain 1-2 levels per dosing interval (typically a trough and/or peak), input into Bayesian calculator, target AUC/MIC 400-600. BMP q48-72h for renal function. CBC weekly (thrombocytopenia). For prolonged courses (>14 days): audiometry if symptoms, CBC for neutropenia. If concurrent pip-tazo: monitor renal function daily initially.",pregnancyLactation:"Pregnancy Category C (historical) / Use with caution. Limited data but vancomycin is often used in pregnancy when MRSA treatment is necessary. Theoretical ototoxicity risk to fetus — monitor levels carefully. Poorly excreted in breast milk — generally considered compatible with breastfeeding.",pharmacistPearls:["AUC-GUIDED DOSING IS THE STANDARD (2020 CONSENSUS): Trough-only monitoring is OUTDATED. AUC/MIC 400-600 predicts both efficacy and toxicity better than troughs. Bayesian dosing software (e.g., DoseMeRx, PrecisePK) uses 1-2 levels to estimate AUC. This has reduced AKI rates by 30-40% compared to trough-targeted dosing. If your institution still uses trough-only dosing, advocate for Bayesian AUC-guided protocols.","VANCOMYCIN + PIP-TAZO NEPHROTOXICITY: This combination causes AKI at significantly higher rates than vancomycin + cefepime or vancomycin + meropenem. Multiple meta-analyses confirm this. Prefer vancomycin + cefepime when empiric MRSA + Pseudomonas coverage is needed. If pip-tazo is required (e.g., polymicrobial IAI), monitor renal function very closely and switch to narrower therapy ASAP.","RED MAN SYNDROME IS NOT AN ALLERGY: Rate-related histamine release causing flushing, pruritus, and sometimes hypotension. Treatment: slow the infusion rate (≥1h per 500mg, or longer), premedicate with diphenhydramine 25-50mg. Do NOT chart as 'vancomycin allergy' — this inappropriately limits future use. True vancomycin allergy (IgE-mediated anaphylaxis, DRESS, linear IgA dermatosis) is rare but real.","ORAL VANCOMYCIN ≠ IV VANCOMYCIN: Oral vancomycin is ONLY for C. difficile infection. It is not absorbed systemically — it works locally in the GI tract. IV vancomycin does NOT reach the colonic lumen and is useless for C. diff. These are functionally two different drugs despite sharing a name.","VANCOMYCIN IS INFERIOR TO BETA-LACTAMS FOR MSSA: This cannot be overstated. Vancomycin has slower bactericidal kinetics, achieves lower tissue concentrations, and is associated with higher treatment failure rates for MSSA infections compared to cefazolin or nafcillin. The moment MSSA is confirmed, de-escalate to a beta-lactam. This is arguably the single most impactful antibiotic stewardship intervention in bloodstream infections.","MIC CREEP AND WHEN TO SWITCH: If vancomycin MIC ≥2 (by broth microdilution), treatment failure risk increases substantially. Switch to daptomycin for MRSA bacteremia/IE with MIC ≥2. Note: E-test MICs tend to read 1-2 dilutions higher than broth microdilution — confirm method before making treatment decisions."]},{id:"daptomycin",name:"Daptomycin",brandNames:"Cubicin, Cubicin RF",drugClass:"Cyclic lipopeptide (first-in-class)",mechanismOfAction:"Calcium-dependent insertion into gram-positive cell membranes, forming ion channels that cause rapid membrane depolarization, loss of membrane potential, and cell death. Concentration-dependent, rapidly bactericidal (Cmax/MIC). Unique mechanism — no cross-resistance with other antibiotic classes. CRITICAL: inactivated by pulmonary surfactant — ABSOLUTELY CONTRAINDICATED for pneumonia.",spectrum:"GRAM-POSITIVE ONLY. Excellent: MRSA (including hVISA/VISA with vancomycin MIC creep), MSSA, VRE (E. faecium — one of few bactericidal options), Streptococci, CoNS. GAPS: ALL gram-negatives, ALL anaerobes. CONTRAINDICATION: pneumonia (surfactant inactivation).",dosing:{ssti:"4 mg/kg IV once daily (FDA-approved for cSSTI)",bacteremia_ie:"6 mg/kg IV once daily (FDA-approved for SAB/right-sided IE), but most experts use 8-10 mg/kg",high_dose:"8-12 mg/kg IV once daily for: complicated bacteremia, left-sided IE, VRE infections, osteomyelitis, or vancomycin MIC ≥2",vre:"8-12 mg/kg IV daily (higher doses for serious VRE infections — limited dosing data, expert consensus)"},renalAdjustment:"CrCl ≥30: no adjustment. CrCl <30 (including HD): dose q48h (FDA label) — however, many experts maintain daily dosing for serious infections (PK data supports this in some studies). Administer after HD on dialysis days. CRRT: 8 mg/kg q48h (limited data, institution-dependent).",hepaticAdjustment:"No adjustment required. Not hepatically metabolized.",adverseEffects:{common:"CPK elevation (2-7%), myalgia, headache, GI symptoms (nausea, diarrhea)",serious:"Rhabdomyolysis (rare but potentially severe — dose-related), eosinophilic pneumonia (rare — presents with fever, dyspnea, infiltrates on imaging; resolves with discontinuation), peripheral neuropathy",rare:"Anaphylaxis, renal failure secondary to rhabdomyolysis, hepatotoxicity"},drugInteractions:["Statins — additive myopathy/CPK elevation risk. HOLD statins during daptomycin therapy and resume after completion. This is a common oversight.","Tobramycin — may increase daptomycin exposure. Monitor for toxicity.","Warfarin — no significant interaction (advantage over some other antibiotics)."],monitoring:"CPK weekly (MANDATORY — stop daptomycin if CPK >5-10× ULN with symptoms, or >10× ULN even without symptoms). Hold statins. Renal function q1-2 weeks (secondary to rhabdomyolysis risk). Eosinophil count if respiratory symptoms develop.",pregnancyLactation:"Pregnancy Category B. Limited human data. Animal studies show no teratogenicity. Use when benefit outweighs risk. Unknown if excreted in breast milk.",pharmacistPearls:["DOSE MATTERS — GO HIGH FOR SERIOUS INFECTIONS: The FDA-approved bacteremia/IE dose is 6 mg/kg, but most ID experts use 8-10 mg/kg for serious MRSA infections. Higher doses improve Cmax/MIC ratio (concentration-dependent killing) and reduce emergence of resistance. Some centers use 10-12 mg/kg for VRE IE. There is no well-defined upper limit, but CPK monitoring becomes more important at higher doses.","NEVER USE FOR PNEUMONIA: Daptomycin is inactivated by pulmonary surfactant. This is an absolute contraindication, not a relative one. A patient with MRSA bacteremia of unclear source who also has pneumonia should receive vancomycin or linezolid for the pulmonary component. Daptomycin will fail if the lung is the primary source.","HOLD THE STATIN: Statins and daptomycin both cause myopathy/CPK elevation. The combination increases rhabdomyolysis risk. Temporarily discontinue statins when starting daptomycin and resume when daptomycin is completed. This is easy to miss — add it to your admission checklist.","DAPTOMYCIN + CEFTAROLINE SYNERGY FOR SALVAGE: For persistent MRSA bacteremia failing vancomycin or even daptomycin alone, the combination of daptomycin + ceftaroline has the best-studied synergy data. Ceftaroline binds PBP2a (MRSA-specific PBP) and enhances daptomycin binding to the cell membrane. Multiple case series show clearance of persistent MRSA BSI with this combination.","DAPTOMYCIN + AMPICILLIN FOR VRE: In E. faecium IE, adding ampicillin (even if the organism is ampicillin-resistant) enhances daptomycin cell membrane binding. This paradoxical synergy is mediated by PBP effects altering membrane structure, not by direct antibacterial activity of ampicillin. Discuss with ID.","IV PUSH IS APPROVED: For doses ≤500mg, daptomycin can be given as a 2-minute IV push. This is convenient for OPAT and reduces infusion time. For doses >500mg, infuse over 30 minutes."]},{id:"ceftriaxone",name:"Ceftriaxone",brandNames:"Rocephin",drugClass:"Third-generation cephalosporin",mechanismOfAction:"Binds PBPs (primarily PBP3) inhibiting cell wall synthesis. Bactericidal, time-dependent killing. Third-generation cephalosporins have expanded gram-negative spectrum compared to first-generation but LESS gram-positive activity than cefazolin. Uniquely long half-life (6-9 hours) among cephalosporins, enabling once-daily dosing.",spectrum:"Gram-negative: Excellent — E. coli, Klebsiella (non-ESBL), Proteus, H. influenzae, N. meningitidis, N. gonorrhoeae, Salmonella, HACEK organisms. Gram-positive: Good Streptococcal activity (S. pneumoniae, viridans strep, S. pyogenes, S. agalactiae), moderate MSSA. GAPS: MRSA (no activity), ESBL producers, AmpC producers (Enterobacter, Citrobacter, Serratia — risk of AmpC induction), Pseudomonas (no activity — unlike ceftazidime or cefepime), Enterococcus, Listeria, anaerobes (variable — not reliable for B. fragilis), atypicals.",dosing:{standard:"1-2g IV once daily",endocarditis:"2g IV q12h (Enterococcal IE with ampicillin combination) or 2g IV once daily (Streptococcal IE)",meningitis:"2g IV q12h",gonorrhea:"500mg IM × 1 dose (2020 CDC guideline — previously 250mg, increased due to resistance concerns)",pneumonia:"1-2g IV once daily",bacteremia:"2g IV once daily (or q12h for serious infections)"},renalAdjustment:"Dual elimination — ~60% renal, ~40% biliary. No dose adjustment needed for renal impairment alone. In combined hepatic AND renal impairment: consider dose reduction. Hemodialysis: NOT removed by HD — no supplemental dosing needed. This dual elimination is a significant advantage.",hepaticAdjustment:"No adjustment for hepatic impairment alone. In combined hepatic AND renal impairment: reduce dose and monitor levels if available.",adverseEffects:{common:"Diarrhea (less than broader-spectrum agents), rash, injection site reactions (IM), eosinophilia",serious:"C. difficile colitis (moderate risk — less than fluoroquinolones but more than narrow-spectrum agents), biliary sludging/pseudolithiasis (calcium-ceftriaxone precipitates — particularly in prolonged courses; reversible upon discontinuation), hypersensitivity reactions",rare:"Hemolytic anemia (immune-mediated), pancreatitis (secondary to biliary sludging), seizures (very rare, high doses + renal impairment), leukopenia"},drugInteractions:["Calcium-containing IV solutions — DO NOT co-administer through the same line. Ceftriaxone-calcium precipitation can cause fatal embolic events. This risk is highest in neonates (contraindicated in neonates receiving calcium-containing IV products). In adults, flush lines between ceftriaxone and calcium-containing fluids.","Warfarin — may increase INR via disruption of vitamin K-producing gut flora. Monitor INR.","Ringer's lactate — contains calcium. Use normal saline for ceftriaxone infusion, not LR."],monitoring:"CBC for prolonged courses (leukopenia, thrombocytopenia, hemolytic anemia). LFTs and RUQ ultrasound if symptoms of biliary sludging (RUQ pain, nausea). CMP for combined hepatorenal impairment. Stool studies if diarrhea develops (C. diff).",pregnancyLactation:"Pregnancy Category B. Crosses placenta. Low concentrations in breast milk. Generally considered safe in pregnancy — widely used for STI treatment, pyelonephritis, and other infections in pregnant patients.",pharmacistPearls:["ONCE-DAILY DOSING = OPAT WORKHORSE: The long half-life enabling once-daily dosing makes ceftriaxone the single most commonly used OPAT antibiotic worldwide. Home health gives one dose per day — simple, reliable, cost-effective. This is a massive practical advantage over q4-8h drugs.","THE ENTEROCOCCAL IE COMBINATION: Ampicillin + ceftriaxone q12h for E. faecalis IE is now the PREFERRED regimen over ampicillin + gentamicin (avoids aminoglycoside toxicity). The synergy is PBP-mediated — ampicillin binds PBP4/5, ceftriaxone binds PBP3. This only works for E. faecalis (not E. faecium, which has inherent cephalosporin resistance).","BILIARY SLUDGING — A UNIQUE ADVERSE EFFECT: Ceftriaxone forms calcium-ceftriaxone precipitates in bile, causing sludging or pseudolithiasis. Usually asymptomatic but can cause RUQ pain mimicking cholecystitis. Risk increases with prolonged courses (>14 days) and high doses. Reversible upon discontinuation. Warn patients about RUQ symptoms during OPAT.","S. GALLOLYTICUS ENDOCARDITIS = COLONOSCOPY: If you see ceftriaxone prescribed for S. gallolyticus (formerly S. bovis) IE, ensure a colonoscopy is ordered. 25-80% association with colorectal neoplasia. This is a pharmacist intervention that catches a cancer diagnosis.","NO PSEUDOMONAS COVERAGE: Unlike ceftazidime and cefepime, ceftriaxone has NO reliable Pseudomonas activity. Do not use for suspected Pseudomonas infections. If Pseudomonas coverage is needed, use cefepime, pip-tazo, or meropenem."]},{id:"cefazolin",name:"Cefazolin",brandNames:"Ancef, Kefzol",drugClass:"First-generation cephalosporin",mechanismOfAction:"Binds PBPs (primarily PBP-1 and PBP-3), inhibiting cell wall synthesis. Bactericidal, time-dependent killing. First-generation cephalosporins have the BEST gram-positive activity within the cephalosporin class. Narrow spectrum = ADVANTAGE (less collateral damage, less resistance selection, less C. diff).",spectrum:"Gram-positive: Excellent MSSA (drug of choice for MSSA infections), Streptococci. Gram-negative: Limited — E. coli, Klebsiella (non-ESBL), Proteus mirabilis. GAPS: MRSA, Enterococcus, ESBL producers, AmpC producers, Pseudomonas, anaerobes (poor for B. fragilis), atypicals.",dosing:{standard:"1-2g IV q8h",bacteremia:"2g IV q8h",endocarditis_mssa:"2g IV q8h × 6 weeks (native valve) or 6 weeks + rifampin (prosthetic valve)",bone_joint:"2g IV q8h × 4-6 weeks",surgical_prophylaxis:"2g IV within 60 min before incision (3g if ≥120kg); redose q4h intra-op",ssti:"2g IV q8h"},renalAdjustment:"CrCl 35-54: standard dosing or 1g q8h. CrCl 11-34: 1g q12h. CrCl ≤10: 1g q24h. Hemodialysis: 1g after each HD session. CRRT: 2g q12h (institution-dependent).",hepaticAdjustment:"No adjustment needed — renally eliminated.",adverseEffects:{common:"Rash, diarrhea (low incidence), injection site pain",serious:"Allergic reactions (cross-reactivity with penicillin ~1% — much lower than previously believed), C. difficile (LOW risk — narrower spectrum), neutropenia (prolonged courses), interstitial nephritis (rare)",rare:"Anaphylaxis, hemolytic anemia, seizures (overdose or severe renal impairment)"},drugInteractions:["Probenecid — inhibits renal tubular secretion, increasing cefazolin levels and extending half-life. This is therapeutically exploited for OPAT (cefazolin q12h + probenecid 1g BID).","Warfarin — mild increase in INR possible. Monitor INR when initiating or stopping.","Aminoglycosides — potential additive nephrotoxicity. Monitor renal function."],monitoring:"CBC weekly for prolonged courses (neutropenia). BMP for renal function. Signs of allergic reaction. C. diff screening if diarrhea develops.",pregnancyLactation:"Pregnancy Category B. Widely used in pregnancy — standard for surgical prophylaxis during cesarean section, GBS prophylaxis alternative. Very low breast milk concentrations.",pharmacistPearls:["DRUG OF CHOICE FOR MSSA: Cefazolin has replaced nafcillin/oxacillin as the preferred agent for MSSA bacteremia and endocarditis in most centers. Non-inferior efficacy with significantly fewer adverse effects. Q8h dosing (vs q4h) makes OPAT feasible.","PENICILLIN ALLERGY AND CEFAZOLIN: Cross-reactivity between penicillin and cefazolin is ~1% (unique R1 side chain). Most patients with 'penicillin allergy' (including urticaria) can safely receive cefazolin. Only true penicillin anaphylaxis should prompt avoidance (or skin testing under allergist). Don't let a vague allergy history deprive patients of the best MSSA drug.","STEWARDSHIP IMPACT — THE MSSA DE-ESCALATION: Switching from vancomycin to cefazolin upon MSSA confirmation is one of the highest-impact stewardship interventions in inpatient medicine. Faster bacteremia clearance, potentially lower mortality, fewer adverse effects, lower cost. Build this into your rounding checklist.","LOW C. DIFF RISK: Narrower spectrum = less disruption of colonic flora = lower C. diff rates compared to pip-tazo, fluoroquinolones, and broad-spectrum cephalosporins. Clinically meaningful advantage."]}]},h={id:"c-difficile",name:"Clostridioides difficile Infection",icon:"🦠",category:"Infectious Disease — IDSA/SHEA 2021 + ACG 2021",overview:{definition:"Clostridioides difficile infection (CDI) is toxin-mediated colonic disease caused by C. difficile, an obligate anaerobic, spore-forming, gram-positive bacillus. The organism produces toxin A (enterotoxin) and toxin B (cytotoxin) that cause mucosal inflammation, fluid secretion, and pseudomembrane formation. CDI is the most common healthcare-associated infection in US hospitals and a leading cause of antibiotic-associated diarrhea. The spectrum ranges from mild diarrhea to fulminant colitis with toxic megacolon, perforation, and death.",epidemiology:"~500,000 CDI cases annually in the US, ~30,000 deaths. Incidence has been declining since the mid-2010s (due to improved infection prevention and antibiotic stewardship), but CDI remains a major burden. Community-acquired CDI is increasing and now accounts for ~40% of cases — these patients are younger, have fewer traditional risk factors, and are often not on antibiotics. The hypervirulent BI/NAP1/027 strain (associated with the early 2000s epidemic) produces binary toxin and higher toxin levels, causing more severe disease and higher mortality. Recurrence rate: 15-25% after first episode, rising to 40-65% after second recurrence.",keyGuidelines:[{name:"IDSA/SHEA 2021 Focused Update",detail:"THE definitive CDI guideline. Major change from 2017: fidaxomicin is now PREFERRED over oral vancomycin for initial and recurrent CDI episodes (conditional recommendation). This was a significant shift driven by the EXTEND trial showing lower recurrence with fidaxomicin. Also formalized bezlotoxumab for recurrence prevention and updated FMT recommendations."},{name:"ACG 2021 CDI Guidelines",detail:"American College of Gastroenterology guidelines. Largely concordant with IDSA/SHEA but provides additional detail on diagnosis (two-step testing algorithm), fulminant disease management, and FMT. Stronger recommendation for fidaxomicin as first-line."},{name:"IDSA/SHEA 2017 CDI Guidelines",detail:"Foundation document. Introduced severity-based treatment stratification: non-severe (oral vancomycin or fidaxomicin), severe (oral vancomycin), fulminant (oral vancomycin + IV metronidazole ± rectal vancomycin). Recommended against metronidazole as first-line (downgraded from 2010 guidelines). The 2021 update superseded parts of this but the severity framework remains intact."},{name:"AGA 2022 Fecal Microbiota Transplantation Guideline",detail:"American Gastroenterological Association clinical practice guideline on FMT. Recommends FMT for patients with ≥3 CDI episodes (including initial + 2 recurrences) who have failed appropriate antibiotic therapy. Discusses donor screening, delivery methods, and safety monitoring."}],landmarkTrials:[{name:"EXTEND Trial (Cornely et al., CID 2012)",detail:"The trial that changed CDI treatment. RCT of fidaxomicin vs. vancomycin PO for initial and first recurrent CDI. Fidaxomicin was NON-INFERIOR for clinical cure and SUPERIOR for sustained clinical response (lower recurrence: 13% vs 27% for non-NAP1 strains). This established fidaxomicin as the preferred agent, despite its higher cost. Recurrence reduction driven by fidaxomicin's narrow spectrum — it spares Bacteroides (protective anaerobes) while killing C. diff."},{name:"MODIFY I/II Trials (Wilcox et al., NEJM 2017)",detail:"RCTs establishing bezlotoxumab for CDI recurrence prevention. Bezlotoxumab (anti-toxin B monoclonal antibody) given as single IV infusion during CDI antibiotic treatment reduced recurrence from 27% to 17% (MODIFY I) and 26% to 16% (MODIFY II). NNT ~8-10. FDA-approved for CDI recurrence prevention in high-risk patients. Important: bezlotoxumab PREVENTS recurrence — it does not TREAT active CDI. Must be given alongside CDI antibiotics."},{name:"PUNCH CD3 Trial (Feuerstadt et al., NEJM 2022)",detail:"Landmark RCT for fecal microbiota, live-jslm (Rebyota/RBL). First FDA-approved fecal microbiota product. Single rectal administration after completion of CDI antibiotics reduced CDI recurrence at 8 weeks (70.6% success vs 57.5% placebo). Led to FDA approval in November 2022."},{name:"ECOSPOR III Trial (Feuerstadt et al., NEJM 2022)",detail:"RCT for SER-109 (fecal microbiota spores, live-brpk / Vowst). Oral capsule formulation of purified Firmicutes spores. Reduced CDI recurrence at 8 weeks (88% vs 60% placebo). FDA-approved as Vowst in April 2023 — first orally administered fecal microbiota product. Game-changer for recurrent CDI by eliminating the need for colonoscopic or rectal FMT delivery."},{name:"Johnson et al., CID 2014 — Vancomycin Taper/Pulse",detail:"Established the vancomycin taper-and-pulse regimen for recurrent CDI: standard dose × 10-14 days → taper (125mg BID × 7d → 125mg daily × 7d → 125mg q2-3d × 2-4 weeks). The pulse phase targets newly germinating spores. This regimen reduces recurrence to 25-35% for second recurrence (vs 45-65% with standard 10-day course). Remained standard of care until fidaxomicin and FMT products became available."}],riskFactors:"Major risk factors: (1) ANTIBIOTICS — the single most important risk factor. Highest risk: fluoroquinolones, clindamycin, 3rd/4th-generation cephalosporins, carbapenems. Moderate risk: penicillins, macrolides. Lower risk: TMP-SMX, nitrofurantoin, doxycycline. ANY antibiotic can cause CDI — including antibiotics used to TREAT CDI (paradoxical). (2) Age >65 (risk increases exponentially with age), (3) Hospitalization (exposure to C. diff spores in the environment), (4) PPI use (controversial but epidemiologically associated — gastric acid suppression may facilitate spore germination), (5) Immunosuppression (chemotherapy, organ transplant, IBD on immunomodulators), (6) Prior CDI (strongest risk factor for recurrence), (7) Chronic kidney disease, (8) IBD (both a risk factor for CDI and complicates management — CDI can trigger IBD flares)."},subcategories:[{id:"initial-non-severe",name:"Initial Episode — Non-Severe CDI",definition:"First episode of CDI without markers of severity. Non-severe CDI: WBC ≤15,000 AND creatinine <1.5 mg/dL (or <1.5× baseline). Presents with watery diarrhea (≥3 unformed stools in 24h), lower abdominal cramping, and low-grade fever. No hemodynamic instability, no signs of ileus or megacolon.",clinicalPresentation:"Watery, non-bloody diarrhea (≥3 unformed stools per 24h) is the hallmark. May have lower abdominal cramping, low-grade fever, mild leukocytosis. Onset typically 5-10 days after antibiotic exposure but can be delayed weeks. Stools may have a distinctive foul odor. NO hemodynamic instability, NO peritoneal signs, NO ileus. Important: CDI is a CLINICAL diagnosis confirmed by testing — do not test asymptomatic patients (asymptomatic colonization is common, especially in hospitalized patients).",diagnostics:"Two-step testing algorithm (IDSA/SHEA & ACG recommended): Step 1: GDH antigen + toxin EIA (or NAAT/PCR alone). Step 2: If GDH+/toxin−, perform confirmatory NAAT. Interpretation: GDH+/toxin+ = CDI confirmed (treat). GDH−/toxin− = CDI unlikely (do not treat). GDH+/toxin−/NAAT+ = C. diff present with gene for toxin production, but free toxin not detected — clinical judgment needed (may be colonization vs early disease). CRITICAL: Only test patients with clinically significant diarrhea (≥3 unformed stools/24h). Do NOT test formed stools. Do NOT perform 'test of cure' after treatment — PCR remains positive for weeks after clinical cure.",durationGuidance:{standard:"10 days",stewardshipNote:"IDSA/SHEA 2021: Fidaxomicin preferred over vancomycin to reduce recurrence. Avoid metronidazole for non-severe CDI."},empiricTherapy:[{line:"Preferred — First-Line (IDSA/SHEA 2021)",options:[{drug:"fidaxomicin",regimen:"Fidaxomicin 200mg PO BID × 10 days",notes:"IDSA/SHEA 2021 PREFERRED over vancomycin for initial CDI (conditional recommendation based on EXTEND trial data). Advantage: 50% lower recurrence rate compared to vancomycin for non-NAP1 strains. Mechanism of benefit: narrow-spectrum macrolide that kills C. diff while sparing protective anaerobes (Bacteroides). Allows microbiome recovery. LIMITATION: cost (~$3,000-5,000/course vs ~$50-100 for vancomycin). For non-severe initial CDI, both are effective — the fidaxomicin advantage is primarily in reducing RECURRENCE.",evidence:"A-I",evidenceSource:"IDSA/SHEA 2021"}]},{line:"Alternative — First-Line",options:[{drug:"vancomycin-oral",regimen:"Vancomycin 125mg PO QID × 10 days",notes:"Standard of care before 2021 guideline update. Still highly effective for initial cure (clinical cure rate ~90%). IDSA/SHEA 2021 made this 'alternative' rather than 'preferred' because of higher recurrence rate compared to fidaxomicin. If fidaxomicin is unavailable or cost-prohibitive, oral vancomycin remains an excellent option. Do NOT increase the dose to 250mg or 500mg for non-severe CDI — no added benefit, only added cost. IV vancomycin does NOT work for CDI (does not reach the colon)."}]},{line:"Not Recommended — Metronidazole for CDI (IDSA/SHEA 2021)",options:[{drug:"metronidazole",regimen:"Metronidazole 500mg PO TID × 10 days",notes:"DOWNGRADED in 2017 guidelines, further de-emphasized in 2021. Inferior to vancomycin for clinical cure (especially for severe CDI) and has higher recurrence rates. IDSA/SHEA 2021: metronidazole should ONLY be used when vancomycin and fidaxomicin are unavailable. Some guidelines allow metronidazole for non-severe INITIAL episode only, but this is increasingly seen as suboptimal. The only remaining role for metronidazole in CDI: IV metronidazole as ADJUNCTIVE therapy in fulminant CDI (reaches colonic tissue via systemic circulation when oral drugs cannot reach the colon due to ileus)."}]},{line:"Stewardship — Antibiotic Optimization",options:[{drug:"stewardship-cdi",regimen:"Discontinue or narrow the inciting antibiotic if possible",notes:"THE MOST IMPORTANT INTERVENTION. CDI is a disease of dysbiosis — the inciting antibiotic disrupted the protective microbiome, allowing C. diff to flourish. If the patient is on antibiotics for another infection, narrow the spectrum as much as possible. Discontinue antibiotics entirely if they are no longer needed. If antibiotics must continue: choose lower C. diff risk agents when possible (e.g., doxycycline, TMP-SMX over fluoroquinolones or clindamycin). Continue CDI-directed therapy for the full course even after other antibiotics are stopped."}]}],organismSpecific:[],pearls:["FIDAXOMICIN VS VANCOMYCIN — THE NUANCE: For INITIAL CURE, both are ~90% effective. Fidaxomicin's advantage is in RECURRENCE PREVENTION (13% vs 27% recurrence in EXTEND). If cost is a barrier, vancomycin is still excellent for a first episode. Save fidaxomicin for patients at high recurrence risk: age >65, immunosuppressed, still on antibiotics, severe CDI, prior CDI history.","DO NOT TEST ASYMPTOMATIC PATIENTS: C. diff colonization rates are high in hospitalized patients (5-15%). PCR (NAAT) will be positive in colonized patients who do NOT have disease. Testing formed stool = testing for colonization, not infection. This is the most common CDI testing error.","DO NOT TEST FOR CURE: After successful CDI treatment, NAAT/PCR remains positive for weeks to months (detects residual DNA/spores, not active infection). A 'test of cure' will be falsely positive and lead to unnecessary retreatment. Only retest if symptoms RECUR.","PPI DE-ESCALATION: If the patient is on a PPI, critically evaluate whether it's still needed. PPIs are associated with CDI risk (odds ratio ~1.5-2.0), CDI recurrence, and worse outcomes. De-escalate to H2 blocker or discontinue if the original indication no longer applies. This is an underutilized pharmacist intervention.","125MG IS THE DOSE — DON'T GO HIGHER: Vancomycin 125mg QID achieves stool concentrations far above the MIC for C. diff (~500-2000 μg/g vs MIC 0.5-2 μg/mL). Increasing to 250mg or 500mg for non-severe CDI adds cost without clinical benefit. Reserve higher doses (500mg QID) for fulminant disease."]},{id:"initial-severe",name:"Initial Episode — Severe CDI",definition:"CDI with markers of severity: WBC >15,000 OR creatinine ≥1.5 mg/dL (or ≥1.5× baseline). These cutoffs identify patients at higher risk of complications, treatment failure, and mortality. Management is more aggressive but the oral agents remain the same — the severity distinction primarily affects monitoring intensity and readiness for surgical intervention.",clinicalPresentation:"Profuse watery diarrhea (10-15+ episodes per day), significant abdominal pain and distension, fever >38.5°C, leukocytosis (WBC >15,000, sometimes >30,000 — leukemoid reaction), rising creatinine (dehydration, pre-renal AKI, or CDI-associated kidney injury), hypoalbuminemia (<3 g/dL — poor prognostic marker reflecting systemic inflammation and malnutrition). CT findings in severe CDI: colonic wall thickening, pericolonic fat stranding, ascites, 'accordion sign' (alternating bands of oral contrast and edematous mucosa).",diagnostics:"Same two-step testing algorithm as non-severe. HOWEVER, in severe CDI, additional studies are warranted: CT abdomen/pelvis if diagnostic uncertainty or concern for complications (megacolon, perforation, abscess), daily labs (CBC, CMP — trending WBC and creatinine), lactate (if any hemodynamic concern), albumin (prognostic marker). Surgical consultation should be obtained EARLY for severe CDI — not as a sign of futility, but as preparation if fulminant progression occurs.",empiricTherapy:[{line:"Preferred — Severe CDI (IDSA/SHEA 2021)",options:[{drug:"fidaxomicin",regimen:"Fidaxomicin 200mg PO BID × 10 days",notes:"IDSA/SHEA 2021 lists fidaxomicin as preferred for severe CDI as well (conditional recommendation). The EXTEND trial included severe CDI patients and fidaxomicin maintained its recurrence advantage. Same dosing as non-severe. If the patient progresses to fulminant despite fidaxomicin, transition to the fulminant CDI protocol."},{drug:"vancomycin-oral",regimen:"Vancomycin 125mg PO QID × 10 days",notes:"Alternative first-line for severe CDI. Same dose as non-severe — 125mg QID is sufficient. Clinical cure rates are high (~85-90%). The distinction between 'preferred' (fidaxomicin) and 'alternative' (vancomycin) is driven by recurrence data, not acute cure rates. If fidaxomicin is unavailable, vancomycin is the standard."}]},{line:"Adjunctive — Recurrence Prevention in Severe CDI",options:[{drug:"bezlotoxumab",regimen:"Bezlotoxumab 10 mg/kg IV × 1 dose (during CDI antibiotic treatment)",notes:"Consider bezlotoxumab for severe CDI patients at high recurrence risk: age ≥65, immunocompromised, prior CDI episode, severe CDI (this category), NAP1/027 strain. The MODIFY trials showed ~10% absolute reduction in recurrence. NNT ~8-10. Given as a single infusion during the CDI treatment course. Does NOT treat active CDI — it prevents recurrence by neutralizing toxin B. Cost: ~$4,500 per infusion. CAUTION: heart failure exacerbation reported in patients with underlying CHF — use with caution in decompensated HF."}]},{line:"Monitoring — Severe CDI",options:[{drug:"monitoring-severe",regimen:"Daily labs (CBC, CMP), surgical consult early, CT if clinical deterioration",notes:"Track WBC and creatinine daily. Rising WBC (>25,000 or leukemoid reaction), worsening creatinine, increasing lactate, new ileus, or hemodynamic instability = progression to fulminant CDI → escalate to fulminant protocol immediately. Surgical consultation should be obtained EARLY — colectomy has the best outcomes when performed before vasopressor requirement and organ failure develop."}]}],organismSpecific:[],pearls:["SEVERITY CRITERIA ARE IMPERFECT BUT USEFUL: WBC >15,000 and Cr ≥1.5 are the IDSA/SHEA severity markers. They're simple and practical, but miss some severe presentations (e.g., immunosuppressed patients who can't mount leukocytosis). Albumin <3 g/dL is an additional poor prognostic marker used by some clinicians. Clinical judgment should supplement the criteria.","EARLY SURGICAL CONSULT FOR ALL SEVERE CDI: This is not because surgery is imminent — it's because IF the patient progresses to fulminant disease, the window for beneficial colectomy is narrow. Outcomes are dramatically better when surgery occurs before vasopressor requirement and multi-organ failure. Having the surgeon already aware of the patient saves critical time.","HYPOALBUMINEMIA IS A RED FLAG: Albumin <2.5 g/dL in CDI is associated with increased treatment failure, recurrence, and mortality. It reflects both systemic inflammation and protein-losing enteropathy. Consider albumin supplementation for hemodynamic support, but this does not change the CDI treatment algorithm."]},{id:"fulminant",name:"Fulminant CDI (Previously 'Severe, Complicated')",definition:"Life-threatening CDI with systemic toxicity: hypotension/shock, ileus, toxic megacolon (colonic diameter >6cm on imaging), or organ failure. Mortality 30-50% even with aggressive management. Fulminant CDI is a SURGICAL EMERGENCY — medical therapy buys time, but colectomy may be life-saving.",clinicalPresentation:"Marked abdominal distension with diffuse tenderness, absent bowel sounds (ileus), hemodynamic instability requiring vasopressors, severely elevated WBC (>25,000 or leukemoid reaction >40,000), lactic acidosis, acute kidney injury, altered mental status. CRITICAL PARADOX: Diarrhea may DECREASE or STOP as the colon becomes atonic (ileus) — absence of diarrhea in the setting of known CDI with rising WBC and abdominal distension is OMINOUS, not reassuring. CT findings: megacolon (>6cm), diffuse wall thickening, pneumatosis (air in bowel wall — suggests ischemia/necrosis), free air (perforation — emergent surgery).",diagnostics:"Clinical diagnosis in the appropriate context — do not delay treatment for test results. CT abdomen/pelvis (look for megacolon, perforation, pneumatosis). Stat labs: CBC (leukocytosis/leukopenia), CMP (creatinine, electrolytes), lactate (lactic acidosis = tissue hypoperfusion), blood cultures (secondary bacteremia from translocation). Surgical consultation is MANDATORY for fulminant CDI.",empiricTherapy:[{line:"Fulminant CDI — Standard Medical Therapy",options:[{drug:"vancomycin-oral",regimen:"Vancomycin 500mg PO (or via NG tube) QID",notes:"HIGHER DOSE than standard CDI — 500mg QID (not 125mg). The rationale: in fulminant disease with ileus, drug delivery to the colon may be impaired. Higher oral doses may achieve better colonic concentrations. Administered PO or via nasogastric tube if the patient cannot swallow. Fidaxomicin is NOT well-studied in fulminant CDI — vancomycin is the standard here."},{drug:"metronidazole",regimen:"Metronidazole 500mg IV q8h",notes:"ADJUNCTIVE to oral/rectal vancomycin — IV metronidazole reaches colonic tissue via systemic circulation. This is the ONE remaining indication where IV metronidazole adds value in CDI. When the colon is atonic (ileus), oral drugs cannot reliably reach the diseased tissue. IV metronidazole provides a secondary route of drug delivery. Duration: until clinical improvement or colectomy."},{drug:"vancomycin-rectal",regimen:"Vancomycin 500mg in 100mL NS per rectum q6h (retention enema)",notes:"ADD to oral vancomycin + IV metronidazole when ileus is present. Rectal administration delivers drug directly to the diseased colon, bypassing the ileus-impaired oral route. Technique: 500mg in 100mL NS, administered as a retention enema via rectal tube. Patient in Trendelenburg position to facilitate proximal distribution. LIMITATION: only reaches the distal colon (sigmoid, rectum) — proximal colonic disease may not benefit. This is a temporizing measure while awaiting surgical decision."}]},{line:"Fulminant CDI — Surgical Options",options:[{drug:"colectomy",regimen:"Subtotal colectomy with end ileostomy",notes:"DEFINITIVE surgical treatment for fulminant CDI. Indications: perforation, megacolon not responding to medical therapy, multi-organ failure despite medical management, WBC >50,000 with clinical deterioration, lactate >5 with rising trend. TIMING IS EVERYTHING — colectomy before vasopressor requirement and organ failure has dramatically better survival (50-60%) than colectomy after shock/MOF (20-30%). This is why surgical consultation must happen EARLY in severe CDI."},{drug:"diverting-ileostomy",regimen:"Diverting loop ileostomy with colonic vancomycin lavage (Neal procedure)",notes:"COLON-SPARING alternative to subtotal colectomy. Technique: laparoscopic loop ileostomy + antegrade vancomycin flushes (500mg in 500mL NS q8h through the ileostomy, draining from a rectal tube). Preserves the colon for potential reversal. Small case series show improved survival compared to historical colectomy data. Increasingly used at centers with surgical expertise. Advantage: avoids permanent ostomy in survivors. Limitation: not all surgical teams have experience with this approach."}]}],organismSpecific:[],pearls:["DECREASING DIARRHEA WITH WORSENING LABS = ILEUS, NOT IMPROVEMENT: This is the most dangerous CDI trap. A patient whose diarrhea stops but WBC and lactate keep rising is developing colonic ileus — the disease is getting WORSE, not better. This clinical scenario demands urgent surgical evaluation.","THREE ROUTES OF DRUG DELIVERY IN FULMINANT CDI: (1) Oral/NG vancomycin 500mg QID — reaches proximal colon if motility preserved, (2) IV metronidazole — systemic delivery to colonic tissue, (3) Rectal vancomycin enema — delivers drug to distal colon when oral route fails. Using all three maximizes the chance of drug reaching the diseased colon.","LACTATE AND WBC TRENDS GUIDE SURGICAL TIMING: A single elevated lactate is concerning; a RISING lactate despite aggressive medical therapy is an urgent surgical indication. Similarly, WBC >50,000 or a leukemoid reaction with clinical deterioration = operate. Do not wait for perforation — by then, mortality approaches 80%.","TIGECYCLINE AS SALVAGE — LIMITED EVIDENCE: Some case reports describe IV tigecycline as salvage therapy for fulminant CDI. Tigecycline achieves biliary excretion and high colonic concentrations. This is NOT guideline-endorsed and should only be considered in patients who are not surgical candidates and are failing standard triple therapy."]},{id:"first-recurrence",name:"First Recurrence",definition:"CDI that recurs within 2-8 weeks of completing therapy for the initial episode. ~15-25% of patients will experience a first recurrence. Recurrence risk factors: age >65, continued antibiotic use (for other infections), immunosuppression, PPI use, prior CDI episodes, NAP1/027 strain, severe initial episode. The first recurrence is a critical decision point — treatment choice here significantly impacts the probability of subsequent recurrences.",clinicalPresentation:"Same as initial CDI: recurrence of watery diarrhea ≥3 stools/24h after a period of symptom resolution following initial treatment. Typically occurs within 2-8 weeks of completing the initial course. Symptoms are often similar in severity to the initial episode. Important: distinguish TRUE recurrence (new episode after symptom resolution) from TREATMENT FAILURE (symptoms never resolved during initial therapy — this is different and warrants reassessment of diagnosis and treatment).",diagnostics:"Retesting is reasonable if >2-4 weeks since last test and symptoms have clearly recurred after a period of resolution. Use toxin EIA or GDH/toxin combination — NAAT/PCR alone is problematic because it may remain positive from residual spores (not indicating new infection). Clinical context is essential: recurrent diarrhea + prior CDI + recent antibiotic exposure = high pretest probability. Do NOT test patients who remain symptomatic from initial episode — this is treatment failure, not recurrence.",empiricTherapy:[{line:"Preferred — First Recurrence (IDSA/SHEA 2021)",options:[{drug:"fidaxomicin",regimen:"Fidaxomicin 200mg PO BID × 10 days",notes:"STRONGLY preferred for first recurrence (IDSA/SHEA 2021). If the initial episode was treated with vancomycin, switching to fidaxomicin reduces subsequent recurrence by ~50% (EXTEND trial). If the initial episode was treated with fidaxomicin and still recurred, fidaxomicin can be repeated — there is no evidence of diminishing returns. The narrow spectrum preserving protective anaerobes is the key mechanistic advantage."},{drug:"fidaxomicin-extended-pulse",regimen:"Fidaxomicin 200mg PO BID × 5 days, then 200mg PO once daily every other day × 20 days",notes:"Extended-pulsed fidaxomicin (EFP) regimen from the EXTEND-EFP study. Even lower recurrence rates than standard 10-day fidaxomicin (~4% recurrence in some studies). The every-other-day dosing targets newly germinating spores while allowing microbiome recovery on 'off' days. Increasingly used by ID experts for first recurrence. Not yet in formal IDSA guidelines as a first-line recommendation but gaining traction rapidly."}]},{line:"Alternative — First Recurrence",options:[{drug:"vancomycin-taper-pulse",regimen:"Vancomycin taper-and-pulse: 125mg QID × 10-14d → 125mg BID × 7d → 125mg daily × 7d → 125mg q2-3d × 2-4 weeks",notes:"If fidaxomicin is unavailable or cost-prohibitive. The taper-and-pulse regimen reduces recurrence to ~25-35% (vs ~45-65% with standard 10-day re-treatment). The pulse phase targets C. diff spores that germinate after cessation of continuous therapy. Mechanism: spores are resistant to antibiotics, but newly germinated vegetative cells are susceptible. By pulsing antibiotics, you catch newly germinated bacteria before they can produce toxin."},{drug:"vancomycin-oral",regimen:"Vancomycin 125mg PO QID × 10 days (if initial episode treated with metronidazole)",notes:"If the initial episode was treated with metronidazole (which it shouldn't have been per 2021 guidelines, but sometimes is), a standard vancomycin course is appropriate for first recurrence. This effectively 'upgrades' therapy."}]},{line:"Adjunctive — Recurrence Prevention",options:[{drug:"bezlotoxumab",regimen:"Bezlotoxumab 10 mg/kg IV × 1 dose (during CDI antibiotic treatment)",notes:"Strongly consider for first recurrence — the MODIFY trials enrolled patients with recurrent CDI and showed benefit. Give as single infusion during the CDI treatment course. Particularly indicated if: age ≥65, immunocompromised, severe CDI, CDI while on concurrent antibiotics, NAP1/027 strain. NNT ~8-10. Cost ~$4,500 but may be cost-effective if it prevents hospitalization for subsequent recurrence."}]}],organismSpecific:[],pearls:["THE FIRST RECURRENCE IS THE MOST IMPORTANT TREATMENT DECISION IN CDI: Get it right, and you break the recurrence cycle. Get it wrong (e.g., another standard vancomycin course), and recurrence risk escalates to 40-65% for subsequent episodes. Use fidaxomicin, add bezlotoxumab if risk factors, and plan for microbiome restoration.","FIDAXOMICIN FOR RECURRENCE — THE COST-EFFECTIVENESS ARGUMENT: Fidaxomicin costs ~$3,000-5,000/course. A CDI recurrence requiring hospitalization costs $15,000-50,000+. If fidaxomicin reduces recurrence by 50%, it is COST-EFFECTIVE for high-risk patients. Frame the cost discussion this way when advocating for formulary access.","VANCOMYCIN TAPER-AND-PULSE REQUIRES PATIENT EDUCATION: The tapering schedule is confusing for patients. Write out the exact schedule with dates on the prescription. Call the patient mid-taper to ensure adherence. A pharmacist phone call can prevent a recurrence.","CONCOMITANT ANTIBIOTICS DRIVE RECURRENCE: If the patient is on systemic antibiotics for another infection during CDI treatment, recurrence risk approximately DOUBLES. Narrow the concurrent antibiotics as aggressively as possible. Choose low C. diff risk agents (doxycycline, TMP-SMX) over high-risk agents (fluoroquinolones, clindamycin, broad-spectrum cephalosporins)."]},{id:"multiple-recurrences",name:"Multiple Recurrences (≥2nd Recurrence)",definition:"Patients experiencing ≥2 CDI recurrences (i.e., 3+ total episodes) represent the most challenging CDI management scenario. Recurrence rate after second episode reaches 40-65%. These patients have profoundly disrupted gut microbiomes that cannot recover spontaneously. Microbiome restoration therapies (FMT products) become the cornerstone of management alongside antibiotic treatment.",clinicalPresentation:"Same as prior CDI episodes. Patients with multiple recurrences often develop anxiety about symptom recurrence, modified eating habits (reduced fiber intake due to fear of diarrhea), social isolation, and significant impact on quality of life. Malnutrition and weight loss are common. Some develop antibiotic-associated fatigue and prolonged dysbiosis symptoms between episodes.",diagnostics:"Same testing approach, but clinical correlation is even more important. After multiple recurrences, patients may develop conditioned diarrheal responses to stress or dietary triggers. Ensure each 'recurrence' is confirmed with positive toxin testing (not just PCR). Consider alternative diagnoses if testing is negative: post-infectious IBS (common after CDI), IBD flare (CDI and IBD frequently coexist), medication-induced diarrhea, other enteric infections.",empiricTherapy:[{line:"Antibiotic Treatment — Second Recurrence",options:[{drug:"fidaxomicin-extended-pulse",regimen:"Fidaxomicin extended-pulsed: 200mg BID × 5d, then 200mg once every other day × 20d",notes:"Preferred antibiotic for second and subsequent recurrences. The extended-pulsed regimen targets spore germination. This is the antibiotic phase before microbiome restoration therapy."},{drug:"vancomycin-taper-pulse",regimen:"Vancomycin taper-and-pulse (6-8 week regimen)",notes:"Alternative if fidaxomicin is unavailable. Extended taper may be necessary: 125mg QID × 14d → 125mg BID × 7d → 125mg daily × 7d → 125mg q2d × 14d → 125mg q3d × 14d. The longer the pulse phase, the more germinating spores are eliminated."}]},{line:"Microbiome Restoration — FDA-Approved Products",options:[{drug:"vowst",regimen:"Vowst (fecal microbiota spores, live-brpk / SER-109): 4 capsules PO daily × 3 days",notes:"FIRST oral fecal microbiota product (FDA-approved April 2023). Purified Firmicutes spores in capsule form. Given 2-6 days after completing CDI antibiotics. ECOSPOR III trial: 88% success vs 60% placebo. GAME-CHANGER: eliminates need for colonoscopic or rectal FMT delivery. Capsules must be swallowed whole (do not crush/chew). Refrigerated storage. Patients must take with water on an empty stomach."},{drug:"rebyota",regimen:"Rebyota (fecal microbiota, live-jslm / RBL): single rectal administration",notes:"FIRST FDA-approved fecal microbiota product (November 2022). Delivered rectally by healthcare provider. PUNCH CD3 trial: 70.6% success vs 57.5% placebo. Given 24-72 hours after completing CDI antibiotics. Patient retains rectal administration for 15 minutes. Single administration — no repeat dosing needed. Advantage over traditional FMT: standardized manufacturing, screened donors, quality control."}]},{line:"Traditional FMT (If FDA-Approved Products Unavailable)",options:[{drug:"fmt-colonoscopy",regimen:"FMT via colonoscopy — fresh or frozen donor stool",notes:"Traditional fecal microbiota transplantation performed at specialized centers. Highest single-procedure success rate (~85-90% for recurrent CDI). Delivered via colonoscopy into the cecum/right colon. Requires pre-procedure CDI antibiotic treatment (stop antibiotics 24-48h before FMT). Donor screening is rigorous (FDA requires IND for FMT using non-FDA-approved products). AGA 2022 guidelines recommend FMT for ≥3 total CDI episodes (initial + 2 recurrences)."},{drug:"fmt-capsules",regimen:"FMT capsules (investigational at some centers)",notes:"Non-FDA-approved FMT delivered via oral capsules. Available at some academic centers under IND. Less studied than colonoscopic FMT but shows similar efficacy in case series. Patient preference may favor oral over colonoscopic delivery."}]},{line:"Adjunctive for Multiple Recurrences",options:[{drug:"bezlotoxumab",regimen:"Bezlotoxumab 10 mg/kg IV × 1 (during CDI antibiotic treatment, before FMT)",notes:"Can be used in combination with FMT for multiply recurrent CDI. Give during the antibiotic treatment phase (before FMT). Neutralizes toxin B to reduce recurrence risk while microbiome restoration occurs. Cost-effective in multiply recurrent patients given the high per-episode hospitalization cost."}]}],organismSpecific:[],pearls:["FMT IS THE MOST EFFECTIVE INTERVENTION FOR RECURRENT CDI: ~85-90% cure rate for multiply recurrent CDI. The FDA-approved products (Vowst, Rebyota) have made microbiome restoration accessible without the logistical complexity of traditional FMT. Vowst (oral capsules, 3-day course) is particularly transformative — patients no longer need colonoscopy.","THE SEQUENCE MATTERS: Antibiotic treatment (fidaxomicin or vancomycin taper) → complete antibiotics → brief washout (24-72h) → microbiome restoration product (Vowst, Rebyota, or FMT). The antibiotic kills active C. diff, then the microbiome product restores colonization resistance to prevent recurrence.","POST-INFECTIOUS IBS IS REAL: Up to 25% of CDI patients develop post-infectious IBS symptoms (cramping, loose stools, urgency) even after microbiologic cure. This is NOT recurrent CDI and does NOT require re-treatment. Distinguish by negative toxin testing. Manage with IBS-directed therapy (dietary modification, anti-spasmodics).","PROBIOTICS FOR CDI PREVENTION — WEAK EVIDENCE: Saccharomyces boulardii and Lactobacillus-based probiotics have mixed evidence for CDI prevention. Not recommended by IDSA/SHEA. AGA conditionally recommends certain probiotic strains for CDI prevention in adults taking antibiotics, but NOT for CDI treatment. Never recommend probiotics as a substitute for appropriate CDI therapy.","CHRONIC SUPPRESSIVE VANCOMYCIN: For patients who cannot access FMT products and continue to recur, some experts use low-dose vancomycin 125mg PO daily as chronic suppression (especially if the patient must remain on systemic antibiotics). This is NOT guideline-endorsed but is used in practice as a bridge strategy."]},{id:"special-populations",name:"CDI in Special Populations",definition:"CDI management in populations requiring modified approaches: IBD patients (CDI mimics flares and complicates immunosuppressive therapy), immunocompromised patients (higher severity and recurrence), pregnant patients (limited treatment options), and pediatric patients (high colonization rates complicate diagnosis).",clinicalPresentation:"N/A — varies by population.",diagnostics:"N/A — varies by population.",empiricTherapy:[{line:"CDI in IBD Patients",options:[{drug:"ibd-cdi",regimen:"Standard CDI therapy (fidaxomicin preferred) + evaluate immunosuppression",notes:"CDI and IBD have a bidirectional relationship: CDI triggers IBD flares, and IBD treatment (immunosuppression) increases CDI risk. KEY CHALLENGE: Distinguishing CDI from IBD flare — test for CDI in ANY IBD patient with worsening diarrhea, even if the clinical picture looks like a typical flare. Treatment: standard CDI antibiotics. Do NOT escalate immunosuppression (steroids, biologics) for presumed IBD flare until CDI is ruled out. If CDI is confirmed: treat CDI first, then reassess IBD activity. Some guidelines suggest NOT de-escalating immunosuppression during active CDI (to prevent IBD flare), but this is controversial — individualize."}]},{line:"CDI in Immunocompromised Patients",options:[{drug:"immunocompromised-cdi",regimen:"Fidaxomicin (preferred) + bezlotoxumab (strongly consider) + close monitoring for severity progression",notes:"Immunocompromised patients (solid organ transplant, hematologic malignancy, chemotherapy, chronic steroids) have higher CDI incidence, severity, recurrence, and mortality. Low threshold for bezlotoxumab (MODIFY trials showed significant benefit in this subgroup). Close monitoring — immunosuppressed patients may not mount typical WBC response, so traditional severity markers may be unreliable. FMT: historically cautious in severely immunocompromised (theoretical risk of donor-derived bacteremia through disrupted mucosa), but safety data is accumulating. Consult ID and GI."}]},{line:"Stewardship — CDI Prevention Strategies",options:[{drug:"prevention",regimen:"Antibiotic stewardship + contact precautions + environmental cleaning",notes:"ANTIBIOTIC STEWARDSHIP IS THE #1 CDI PREVENTION STRATEGY: Every unnecessary antibiotic day increases CDI risk. High-impact interventions: restrict fluoroquinolones (strongest CDI association), promote narrow-spectrum agents, enforce automatic stop dates, prospective audit and feedback. INFECTION PREVENTION: Contact precautions (gown and gloves) for CDI patients. Soap and water hand hygiene (alcohol-based sanitizer does NOT kill C. diff spores). Terminal room cleaning with sporicidal agents (bleach-based products, UV light). PHARMACIST ROLE: Review all antibiotics on CDI patients for de-escalation opportunities, ensure PPI appropriateness, educate on hand hygiene."}]}],organismSpecific:[],pearls:["TEST EVERY IBD FLARE FOR CDI: This cannot be overstated. CDI occurs in 5-10% of IBD patients annually. An IBD flare that is actually CDI will WORSEN with steroids and immunosuppression. Test first, treat CDI if present, then reassess IBD activity.","IMMUNOCOMPROMISED PATIENTS BREAK THE RULES: WBC may not rise (can be leukopenic from chemotherapy), creatinine may be unreliable (chronic renal disease), and clinical presentation may be atypical. Have a LOW threshold for testing and a LOW threshold for treating empirically in high-risk immunocompromised patients with unexplained diarrhea.","HAND HYGIENE: ALCOHOL DOES NOT KILL C. DIFF SPORES. This is why soap and water hand hygiene is mandated for CDI contact precautions. The mechanical removal of spores through friction and water is the mechanism — not chemical killing. Reinforce this with nursing staff and trainees.","PROBIOTICS DURING ANTIBIOTICS — THE PHARMACIST CONVERSATION: Patients frequently ask about probiotics to prevent CDI during antibiotic therapy. The evidence is mixed (AGA weak conditional recommendation for certain strains). If a patient asks, a reasonable response: 'Some data suggests a small benefit for specific probiotic strains during antibiotics, but the evidence is not strong. The most important thing is taking the narrowest-spectrum antibiotic for the shortest appropriate duration.'"]}],drugMonographs:[{id:"fidaxomicin",name:"Fidaxomicin",brandNames:"Dificid",drugClass:"Macrocyclic antibiotic (narrow-spectrum, non-systemic)",mechanismOfAction:"Inhibits bacterial RNA polymerase (sigma subunit) — a distinct binding site from rifamycins, so no cross-resistance with rifampin. Bactericidal against C. difficile at fecal concentrations. CRITICAL PROPERTY: extremely narrow spectrum — active against C. difficile and some Clostridia but SPARES Bacteroides and other protective anaerobic gut flora. This selective preservation of the microbiome is the mechanistic basis for its lower recurrence rate compared to vancomycin (which kills protective anaerobes along with C. diff). Minimal systemic absorption — acts locally in the GI tract.",spectrum:"C. difficile (primary target — MIC90 0.25 μg/mL). Some activity against other Clostridia and certain gram-positive organisms. DOES NOT kill Bacteroides fragilis group (KEY ADVANTAGE — preserves colonization resistance). Minimal activity against Enterobacterales or other gram-negatives. NOT a systemic antibiotic — do not use for any infection other than CDI.",dosing:{standard:"200mg PO BID × 10 days (initial and recurrent CDI)",extended_pulse:"200mg PO BID × 5 days, then 200mg PO once every other day × 20 days (extended-pulsed fidaxomicin — for recurrence reduction)"},renalAdjustment:"No dose adjustment — minimal systemic absorption. Not renally eliminated.",hepaticAdjustment:"No dose adjustment — minimal systemic absorption.",adverseEffects:{common:"Nausea (7-11%), vomiting, abdominal pain, GI hemorrhage (rare, likely related to underlying CDI colitis rather than drug effect)",serious:"Hypersensitivity reactions (rare), anemia (uncommon, unclear causality)",rare:"Severe allergic reactions, elevated hepatic enzymes (minimal systemic exposure makes true hepatotoxicity unlikely)"},drugInteractions:["P-glycoprotein inhibitors (cyclosporine, ketoconazole, erythromycin, verapamil) — may increase fidaxomicin systemic absorption. Clinical significance unclear given minimal baseline absorption, but use with awareness.","No significant CYP450 interactions — fidaxomicin is not metabolized by CYP enzymes.","No interaction with oral vancomycin — can theoretically be used sequentially (vancomycin → fidaxomicin) though this is not standard."],monitoring:"Clinical response: resolution of diarrhea (typically within 2-5 days). No drug levels available or needed. No routine lab monitoring required. Monitor for treatment failure (persistent diarrhea >5-7 days) — re-evaluate diagnosis and consider escalation to fulminant CDI protocol if clinical deterioration.",pregnancyLactation:"Pregnancy Category B. Minimal systemic absorption makes fetal exposure unlikely. Limited human pregnancy data. Use when benefit outweighs risk. Unknown if excreted in breast milk (likely negligible given minimal absorption).",pharmacistPearls:["THE MICROBIOME IS THE MECHANISM: Fidaxomicin's lower recurrence rate is NOT because it kills C. diff better (clinical cure rates are similar to vancomycin at ~90%). It's because fidaxomicin preserves Bacteroides and other protective anaerobes that provide COLONIZATION RESISTANCE against C. diff re-establishment. Vancomycin kills these protective bacteria along with C. diff, leaving the colon vulnerable to re-colonization. This is a fundamentally different approach — treat the infection while protecting the ecosystem.","COST IS THE BARRIER — ADVOCATE FOR ACCESS: ~$3,000-5,000/course vs ~$50-100 for vancomycin. Frame the cost-effectiveness argument: one prevented recurrence saves $15,000-50,000+ in hospitalization costs. For high-risk patients (age >65, immunocompromised, prior CDI, severe initial episode), fidaxomicin is COST-EFFECTIVE. Push for formulary inclusion with prior authorization criteria targeting high-risk patients.","EXTENDED-PULSED DOSING IS THE FUTURE: The BID × 5d → every-other-day × 20d regimen further reduces recurrence compared to standard 10-day dosing. The mechanism is elegant: the 5-day kill phase eliminates vegetative C. diff, then the every-other-day pulse targets newly germinating spores while giving the microbiome recovery time on 'off' days. This is gaining traction among ID experts even though it's not yet in formal IDSA guidelines.","ORAL ONLY — NO IV FORMULATION: Fidaxomicin is only available as an oral tablet or suspension. It is NOT absorbed systemically and works locally in the GI tract. For patients with ileus who cannot take oral medications, fidaxomicin cannot be given IV — use the fulminant CDI protocol (oral/NG vancomycin 500mg QID + IV metronidazole + rectal vancomycin enemas).","NO CROSS-RESISTANCE WITH RIFAMPIN: Despite both targeting RNA polymerase, fidaxomicin binds a different site on the sigma subunit. Rifampin resistance does NOT predict fidaxomicin resistance. This is clinically relevant in patients who have been on rifampin for TB or prosthetic joint infections."]},{id:"vancomycin-oral",name:"Vancomycin (Oral)",brandNames:"Vancocin (oral capsules), Firvanq (oral solution)",drugClass:"Glycopeptide antibiotic — ORAL FORMULATION for CDI only",mechanismOfAction:"Same mechanism as IV vancomycin (binds D-Ala-D-Ala terminus of peptidoglycan precursors, inhibiting cell wall synthesis) but delivered LOCALLY to the GI tract. Oral vancomycin is NOT systemically absorbed in significant amounts (<5%). It works by achieving very high local concentrations in the colonic lumen (fecal levels 500-2000 μg/g — far exceeding the C. diff MIC of 0.5-2 μg/mL). CRITICAL DISTINCTION: Oral vancomycin and IV vancomycin are functionally different drugs with different indications. Oral = CDI. IV = MRSA/systemic infections. IV vancomycin does NOT reach the colonic lumen.",spectrum:"In the GI tract: C. difficile (target), but also kills Bacteroides, Bifidobacterium, and other protective anaerobes (DISADVANTAGE vs fidaxomicin — this is why vancomycin has higher recurrence rates). Does NOT provide systemic coverage — if the patient has a concurrent systemic infection requiring vancomycin, they need BOTH oral vancomycin for CDI AND IV vancomycin for the systemic infection.",dosing:{non_severe:"125mg PO QID × 10 days",severe:"125mg PO QID × 10 days (same as non-severe — no benefit to higher doses for severe non-fulminant CDI)",fulminant:"500mg PO/NG QID ± 500mg in 100mL NS per rectum q6h (retention enema)",taper_pulse:"125mg QID × 10-14d → 125mg BID × 7d → 125mg daily × 7d → 125mg q2-3d × 2-4 weeks (total course 6-8 weeks)"},renalAdjustment:"Not applicable — oral vancomycin is not systemically absorbed. No renal dose adjustment needed for CDI treatment. Note: in patients with significant colonic inflammation (fulminant CDI), small amounts of oral vancomycin may be absorbed systemically — clinically insignificant in most cases.",hepaticAdjustment:"Not applicable — not systemically absorbed.",adverseEffects:{common:"Nausea, abdominal pain, dysgeusia (taste disturbance — especially with oral solution), flatulence",serious:"Microbiome disruption (kills protective anaerobes — the primary disadvantage vs fidaxomicin, contributing to CDI recurrence), hypersensitivity reactions (rare — minimal systemic absorption)",rare:"Systemic absorption in severe colitis (theoretically could contribute to nephrotoxicity if concomitant IV vancomycin and fulminant CDI with inflamed colon, but clinically rare)"},drugInteractions:["Cholestyramine/colestipol — bile acid sequestrants can BIND oral vancomycin in the GI lumen, reducing its effectiveness. Separate administration by at least 2 hours. Historically, cholestyramine was used as CDI therapy — it should NOT be used concurrently with vancomycin.","IV vancomycin — separate indication. Oral and IV vancomycin can be used concurrently (oral for CDI + IV for MRSA) without dose adjustments to either."],monitoring:"Clinical response: diarrhea frequency should begin decreasing within 2-4 days. No drug levels needed for oral vancomycin (it's not systemically absorbed). If diarrhea is not improving by day 5-7: reassess (treatment failure? wrong diagnosis? fulminant progression?). For taper-and-pulse regimens: ensure patient understands the schedule (write it out with calendar dates).",pregnancyLactation:"Pregnancy Category B (historical). Minimal systemic absorption makes fetal exposure negligible. Considered safe in pregnancy for CDI treatment. Breast milk excretion negligible.",pharmacistPearls:["ORAL ≠ IV: These are different drugs for different indications. Oral vancomycin stays in the gut (CDI). IV vancomycin goes systemic (MRSA). IV vancomycin does NOT reach the colon and is USELESS for CDI. This is the most common vancomycin confusion — ensure prescribers specify the route correctly.","125MG IS ENOUGH: For non-severe and severe (non-fulminant) CDI, 125mg QID achieves fecal concentrations 500-2000× the MIC. Higher doses (250mg, 500mg) are NOT more effective for non-fulminant CDI and just cost more. Reserve 500mg QID for FULMINANT CDI only (where drug delivery is impaired by ileus).","THE CAPSULE VS SOLUTION COST TRICK: Oral vancomycin capsules (Vancocin) are expensive (~$800-1600 for 10-day course). The IV vancomycin vial can be reconstituted and administered ORALLY at a fraction of the cost (~$50-100). Many hospital pharmacies prepare oral vancomycin solution from IV powder — this is a standard, well-established practice. At discharge, Firvanq (branded oral solution) or compounded oral solution from IV vials are cost-saving alternatives to capsules.","TAPER-AND-PULSE REQUIRES PHARMACIST SUPPORT: The tapering schedule is complex and patients frequently make errors. Best practice: write out a calendar-based schedule with exact dates and doses. Pharmacist phone calls at the taper transitions dramatically improve adherence. This is a high-value pharmacist intervention for recurrent CDI.","MICROBIOME DAMAGE IS THE TRADE-OFF: Oral vancomycin kills C. diff effectively but also decimates protective Bacteroides and other anaerobes. This is why CDI recurs more often after vancomycin than after fidaxomicin. The microbiome damage also means that vancomycin-treated patients may benefit more from post-treatment microbiome restoration (Vowst, Rebyota, FMT) to re-establish colonization resistance."]},{id:"bezlotoxumab",name:"Bezlotoxumab",brandNames:"Zinplava",drugClass:"Human monoclonal antibody (anti-toxin B)",mechanismOfAction:"Binds and neutralizes C. difficile toxin B, the primary virulence factor mediating colonic epithelial damage. Does NOT have direct antibacterial activity — it does NOT kill C. diff organisms. Mechanism of action is PREVENTION of recurrence, not treatment of active disease. By neutralizing toxin B, bezlotoxumab reduces mucosal damage during any subsequent C. diff re-exposure, giving the host microbiome time to recover colonization resistance. Must be used IN CONJUNCTION with CDI-directed antibiotic therapy — it is not a standalone treatment.",spectrum:"Not applicable — bezlotoxumab is not an antibiotic. It is a toxin-neutralizing antibody. Effective only against C. difficile toxin B. Does not have direct antimicrobial activity against any organism.",dosing:{standard:"10 mg/kg IV × 1 dose, infused over 60 minutes",timing:"Administer during CDI antibiotic treatment (not after antibiotics are completed). The MODIFY trials gave bezlotoxumab while patients were actively receiving CDI antibiotics."},renalAdjustment:"No dose adjustment — monoclonal antibody eliminated by catabolism, not renal excretion.",hepaticAdjustment:"No dose adjustment — not hepatically metabolized in the traditional sense. Monoclonal antibody cleared by reticuloendothelial system.",adverseEffects:{common:"Infusion reactions (10% — nausea, fatigue, fever, headache, dizziness), nausea, diarrhea (ironic but usually mild and self-limited)",serious:"Heart failure exacerbation (MODIFY trials reported higher rates of heart failure events in bezlotoxumab-treated patients with underlying CHF — 12.7% vs 4.8%). FDA boxed warning for heart failure. Use with caution in decompensated HF.",rare:"Serious infusion reactions, anaphylaxis (very rare)"},drugInteractions:["No known significant drug-drug interactions. As a monoclonal antibody, bezlotoxumab does not interact with CYP450 enzymes or P-glycoprotein.","Can be administered with any CDI antibiotic (vancomycin, fidaxomicin, metronidazole) without dose adjustments."],monitoring:"Monitor for infusion reactions during and 1 hour after administration. In patients with heart failure: monitor volume status, weight, and symptoms of HF exacerbation. No drug levels available. Efficacy monitoring: assess for CDI recurrence at 4, 8, and 12 weeks post-treatment.",pregnancyLactation:"No adequate human data. Animal studies (monoclonal antibodies cross placenta) — theoretical fetal exposure. Use only if clearly needed. Unknown if excreted in breast milk.",pharmacistPearls:["PREVENTION, NOT TREATMENT: Bezlotoxumab does not treat active CDI. It prevents recurrence by neutralizing toxin B. Always use with CDI antibiotics. If a patient is acutely symptomatic, they need vancomycin or fidaxomicin — bezlotoxumab alone will not resolve the episode.","TARGET THE RIGHT PATIENTS: Not every CDI patient needs bezlotoxumab (NNT ~8-10). Highest value in: age ≥65, immunocompromised, recurrent CDI (any prior episode), severe CDI, CDI while on concurrent antibiotics, NAP1/027 strain. For a young, healthy patient with a first mild episode, the benefit is marginal and cost is high.","HEART FAILURE CAUTION: The MODIFY trials flagged higher HF events in patients with underlying CHF. This is an FDA boxed warning. For CDI patients with active decompensated HF, the risk-benefit calculation is less favorable. In compensated HF, most experts still use bezlotoxumab with close monitoring — the CDI recurrence risk may outweigh the HF risk.","TIMING MATTERS: Give bezlotoxumab DURING CDI antibiotic treatment, not after completion. The half-life is ~19 days, so a single dose provides weeks of toxin neutralization through the highest-risk period for recurrence. If a patient has already completed CDI antibiotics, bezlotoxumab can still be given, but timing during treatment is preferred.","COST-EFFECTIVENESS IN RECURRENT CDI: At ~$4,500 per infusion, bezlotoxumab is expensive for a single dose. But for patients at high recurrence risk, preventing even ONE CDI hospitalization ($15,000-50,000+) makes it cost-effective. The strongest cost-effectiveness data is in patients with ≥1 prior CDI recurrence."]},{id:"metronidazole",name:"Metronidazole",brandNames:"Flagyl",drugClass:"Nitroimidazole antibiotic/antiprotozoal",mechanismOfAction:"Prodrug that is reduced by anaerobic electron transport systems to form reactive intermediates that damage DNA, causing strand breakage and cell death. Only active against ANAEROBIC organisms (requires low redox potential for activation). Bactericidal. In CDI context: IV metronidazole reaches colonic tissue via systemic circulation — the ONLY route by which metronidazole reaches the colon when given IV (unlike oral vancomycin which stays in the lumen). This systemic-to-tissue route is why IV metronidazole is used adjunctively in fulminant CDI with ileus.",spectrum:"Anaerobes: Excellent — B. fragilis group (drug of choice for above-the-diaphragm anaerobic infections and historically for B. fragilis), Clostridium spp (including C. difficile), Prevotella, Fusobacterium, Peptostreptococcus. Protozoa: Giardia, Entamoeba histolytica, Trichomonas. Microaerophilic: H. pylori (combination therapy). GAPS: ALL aerobes (gram-positive and gram-negative), Actinomyces, Propionibacterium.",dosing:{cdi_oral:"500mg PO TID × 10 days (NOT recommended as first-line per IDSA/SHEA 2021 — only if vancomycin and fidaxomicin unavailable)",cdi_iv_adjunctive:"500mg IV q8h (adjunctive with oral/rectal vancomycin for fulminant CDI)",iai:"500mg IV q8h (standard anaerobic coverage for intra-abdominal infections)",h_pylori:"500mg PO BID (as part of triple or quadruple therapy)",bv:"500mg PO BID × 7 days (bacterial vaginosis)"},renalAdjustment:"Standard dosing for most levels of renal impairment. Hemodialysis: standard dose (metronidazole and metabolites are removed by HD — some sources recommend supplemental dose after HD, but standard dosing is typically adequate).",hepaticAdjustment:"Hepatically metabolized. Reduce dose or extend interval in severe hepatic impairment. Half-life prolonged significantly in liver disease. Monitor for neurotoxicity.",adverseEffects:{common:"Metallic taste (very common — patients frequently complain), nausea, anorexia, headache, dark/reddish-brown urine (harmless — warn patients)",serious:"Peripheral neuropathy (cumulative dose-related — typically with courses >2 weeks; can be irreversible), CNS toxicity (seizures, cerebellar dysfunction — ataxia, dysarthria), disulfiram-like reaction with alcohol",rare:"Optic neuropathy, pancreatitis, aseptic meningitis, leukopenia"},drugInteractions:["Alcohol — DISULFIRAM-LIKE REACTION. Severe nausea, vomiting, flushing, tachycardia. Patients must avoid alcohol during and for 48-72 hours after completing metronidazole. This includes alcohol in medications, mouthwash, and cooking wine.","Warfarin — metronidazole potently inhibits CYP2C9, significantly INCREASING warfarin levels and INR. One of the most clinically significant antibiotic-warfarin interactions. Reduce warfarin dose by ~25-50% and monitor INR closely when starting metronidazole.","Lithium — metronidazole may increase lithium levels. Monitor lithium concentrations.","Disulfiram — psychotic reactions reported when co-administered. Avoid concurrent use.","Phenytoin/phenobarbital — metronidazole may increase phenytoin levels (CYP inhibition). Phenobarbital may decrease metronidazole levels (CYP induction)."],monitoring:"For CDI (short courses): clinical response (diarrhea resolution). For prolonged courses (>14 days): neurological exam (peripheral neuropathy — numbness, tingling in extremities; cerebellar signs — ataxia, tremor). If neuropathy develops, STOP metronidazole immediately — neuropathy may be irreversible if treatment continues. CBC for prolonged courses. INR if on warfarin.",pregnancyLactation:"Pregnancy Category B. Historically controversial (carcinogenic in rodents) but extensive human data shows no increased teratogenicity. Used commonly in pregnancy for bacterial vaginosis, trichomoniasis, and anaerobic infections. Avoid in first trimester if alternatives exist (theoretical concern, not evidence-based). Excreted in breast milk — AAP rates as compatible with breastfeeding, but taste changes in breast milk may occur.",pharmacistPearls:["METRONIDAZOLE IS NO LONGER FIRST-LINE FOR CDI: This is a critical stewardship point. Metronidazole was downgraded in 2017 (IDSA/SHEA) and further de-emphasized in 2021. For CDI: use vancomycin or fidaxomicin. The ONLY remaining CDI role for metronidazole is as ADJUNCTIVE IV therapy in fulminant CDI (reaches colonic tissue when oral drugs cannot due to ileus).","PERIPHERAL NEUROPATHY IS CUMULATIVE AND POTENTIALLY IRREVERSIBLE: Risk increases significantly with courses >14 days and cumulative doses. This is NOT a minor side effect — patients can develop permanent numbness and functional impairment. For any course >14 days, perform neurological assessment and ask about tingling/numbness at each visit. Stop immediately if neuropathy develops.","THE ALCOHOL WARNING IS REAL: The disulfiram-like reaction is severe (projectile vomiting, flushing, tachycardia, chest pain). Warn patients explicitly. It persists for 48-72 hours AFTER the last dose. Check for alcohol in other medications (cough syrups, tinctures, elixirs).","WARFARIN INTERACTION IS MAJOR: Metronidazole is one of the STRONGEST CYP2C9 inhibitors among antibiotics. INR can double or triple within days. Pre-emptively reduce warfarin dose by 25-50% and check INR within 3-5 days of starting metronidazole. This interaction causes serious bleeding events when missed.","IV METRONIDAZOLE IN FULMINANT CDI — THE RATIONALE: When the colon is ileus (no motility), oral vancomycin sits in the stomach and proximal small bowel — it cannot reach the diseased colon. IV metronidazole is absorbed systemically and delivered to colonic TISSUE via the bloodstream. This provides drug delivery from the systemic side while oral/rectal vancomycin attempts luminal delivery. This is why the fulminant CDI protocol uses all three routes."]}]},g={id:"bone-joint",name:"Bone & Joint Infections",icon:"🦴",category:"Infectious Disease — IDSA 2015 + OVIVA 2019",overview:{definition:"Bone and joint infections encompass osteomyelitis (infection of bone), septic arthritis (infection of a joint space), and prosthetic joint infections (PJI). These infections are characterized by difficult-to-eradicate organisms that form biofilms on necrotic bone or prosthetic material, requiring prolonged antibiotic courses (often 4-6+ weeks) and frequently surgical intervention. The key pharmacologic challenge is delivering adequate antibiotic concentrations to avascular bone tissue and biofilm-embedded organisms.",epidemiology:"Osteomyelitis incidence: 2-5 per 10,000 person-years. Vertebral osteomyelitis (most common form in adults) incidence rising due to aging population, IDU, and healthcare-associated bacteremia. Septic arthritis: 2-10 per 100,000 person-years; monoarticular (usually knee) in 80-90%. PJI: 1-2% of primary joint replacements, 3-5% of revision arthroplasties — represents a massive burden given >1 million hip/knee replacements annually in the US. S. aureus is the dominant organism across all categories (40-60% of native bone/joint infections).",keyGuidelines:[{name:"IDSA 2015 Vertebral Osteomyelitis Guidelines",detail:"THE definitive osteomyelitis guideline. Key recommendations: image-guided biopsy before antibiotics when feasible, 6-week parenteral (or oral with OVIVA caveats) therapy for most vertebral osteomyelitis, CRP trending for treatment response, MRI as gold standard imaging. Emphasizes pathogen-directed therapy over empiric prolonged courses."},{name:"IDSA 2013 Prosthetic Joint Infection Guidelines",detail:"Comprehensive PJI management guideline. Defines DAIR (debridement, antibiotics, implant retention) vs. one-stage vs. two-stage exchange criteria. Rifampin for Staphylococcal PJI with retained implants. Duration: 3 months (hip) to 6 months (knee) for two-stage exchange after reimplantation."},{name:"2018 International Consensus Meeting (ICM) on PJI",detail:"Updated PJI diagnostic criteria: major criteria (sinus tract, two positive cultures of same organism) and minor criteria (elevated serum CRP, elevated serum D-dimer, elevated synovial WBC, elevated synovial alpha-defensin, single positive culture, positive histology). Scoring system for PJI diagnosis."},{name:"ACR/AAHKS 2023 Management of PJI Guideline",detail:"Joint rheumatology/orthopedic guideline. Conditional recommendations on DAIR eligibility, antibiotic selection, and when to pursue one-stage vs. two-stage exchange. Aligns with IDSA on rifampin for Staphylococcal PJI."}],landmarkTrials:[{name:"OVIVA Trial (Li et al., NEJM 2019)",detail:"PARADIGM-SHIFTING RCT: Oral Versus Intravenous Antibiotics for Bone and Joint Infection. 1,054 patients with bone/joint infections (osteomyelitis, septic arthritis, PJI, fracture-related infections) randomized to continued IV vs. oral step-down after ≤7 days of IV therapy. Oral was NON-INFERIOR (treatment failure 14.6% vs 14.8%). Changed practice: oral step-down is now acceptable for MOST bone/joint infections when using agents with excellent oral bioavailability and bone penetration. Key caveats: must use the RIGHT oral agents (fluoroquinolones, rifampin combinations, linezolid, TMP-SMX — NOT amoxicillin or cephalexin monotherapy for bone infections)."},{name:"DATIPO Trial (Wouthuyzen-Bakker et al., 2021)",detail:"RCT evaluating 6 vs 12 weeks of antibiotics after DAIR for PJI. Results suggest 6 weeks may be sufficient for selected PJI cases treated with DAIR, though practice remains variable. Supports the trend toward shorter courses when surgical source control is adequate."},{name:"Zimmerli et al., NEJM 1998 — Rifampin for Staphylococcal PJI",detail:"Seminal RCT establishing rifampin + ciprofloxacin for Staphylococcal PJI with retained implants. Rifampin combination had 100% cure vs. 58% without rifampin. Established the principle that rifampin is ESSENTIAL for biofilm infections on prosthetic material. Every Staphylococcal PJI management plan should include rifampin (with an appropriate companion drug)."},{name:"IDSA POET-like oral step-down extrapolation",detail:"While POET was an endocarditis trial, its principles of oral step-down after initial IV stabilization have been adopted alongside OVIVA for bone/joint infections. The combined message: prolonged IV therapy via PICC is not always necessary, and high-dose oral regimens with bone-penetrating agents are a viable alternative."}],riskFactors:"Osteomyelitis: hematogenous seeding from bacteremia (vertebral osteomyelitis in adults, long-bone metaphysis in children), contiguous spread from soft tissue infection (diabetic foot, decubitus ulcers, post-surgical), trauma/open fractures, vascular insufficiency (diabetic/PVD). Septic arthritis: pre-existing joint disease (RA, OA, gout — damaged joints are vulnerable), recent joint surgery/injection, prosthetic joints, bacteremia from any source, immunosuppression (diabetes, cirrhosis, ESRD, rheumatologic immunosuppressants), IDU, skin breakdown overlying joints. PJI: revision arthroplasty (3-5x risk vs. primary), prior PJI, obesity (BMI >40), diabetes, RA, immunosuppression, prolonged operative time, superficial surgical site infection."},subcategories:[{id:"vertebral-osteomyelitis",name:"Vertebral Osteomyelitis (Native Spine)",definition:"Infection of the vertebral body ± intervertebral disc (spondylodiscitis). The most common form of osteomyelitis in adults. Usually hematogenous (bacteremia seeds the vertebral endplate). S. aureus causes 40-60% of cases. Lumbar spine is most commonly affected (50%), followed by thoracic (35%) and cervical (15%). Can be complicated by epidural abscess (15-20%), paravertebral abscess, or spinal cord compression — neurologic emergency.",clinicalPresentation:"Insidious onset: weeks to months of progressive back pain (axial, localized, worse at night, not relieved by rest). Fever in 50-60% (often low-grade). Neurologic deficits in 15-30%: radiculopathy (nerve root compression), myelopathy (cord compression — weakness, sensory changes, bowel/bladder dysfunction). CRITICAL: new neurologic deficits = EMERGENT MRI and neurosurgical consultation. Risk factors to seek: recent bacteremia, IDU, spinal procedures, endocarditis, immunosuppression. Physical exam: point tenderness over affected vertebrae, paraspinal muscle spasm, limited range of motion.",diagnostics:"MRI spine with gadolinium = GOLD STANDARD (sensitivity 97%, specificity 93%). Look for: vertebral body edema, endplate erosion, disc space enhancement, epidural abscess, paravertebral collection. CT-guided needle biopsy: obtain BEFORE antibiotics whenever possible — culture yield drops from 70-80% to 30-50% after antibiotics. Biopsy is CRITICAL because pathogen-directed therapy for 6 weeks is far better than empiric broad-spectrum therapy for 6 weeks. Blood cultures: positive in 50-70% (S. aureus) — always obtain before antibiotics. Labs: CRP is the best trending marker (follow q1-2 weeks to assess treatment response). ESR also elevated but slower to respond. WBC often normal.",empiricTherapy:[{line:"Pre-Biopsy — Hold Antibiotics if Possible",options:[{drug:"hold-antibiotics",regimen:"Defer antibiotics until biopsy cultures obtained (if clinically stable)",notes:"THE MOST IMPORTANT DECISION IN VERTEBRAL OSTEOMYELITIS: If the patient is hemodynamically stable without sepsis or progressive neurologic deficits, HOLD antibiotics until CT-guided biopsy is performed. The 24-48h delay to obtain cultures before starting antibiotics is worth it — it changes the entire course of therapy. A biopsy that identifies MSSA means 6 weeks of cefazolin. Without a pathogen, you're stuck guessing with broad-spectrum empiric therapy. Exception: unstable patient, sepsis, or neurologic emergency — start empiric antibiotics immediately."}]},{line:"Empiric — When Antibiotics Cannot Wait",options:[{drug:"vancomycin",regimen:"Vancomycin IV (AUC-guided) + Ceftriaxone 2g IV daily",notes:"Covers MRSA + MSSA + Streptococci + most Enterobacterales. This is the standard empiric combination when you must start before cultures. Vancomycin for MRSA, ceftriaxone for gram-negatives and Streptococci. If cultures return MSSA, de-escalate to cefazolin immediately. If epidural abscess with concern for Pseudomonas (post-procedural, healthcare-associated): substitute cefepime for ceftriaxone."}]},{line:"Pathogen-Directed Therapy (After Culture Results)",options:[{drug:"cefazolin",regimen:"Cefazolin 2g IV q8h × 6 weeks (MSSA)",notes:"PREFERRED for MSSA vertebral osteomyelitis. Transition to oral step-down after initial IV period per OVIVA data: high-dose oral agents with bone penetration (e.g., levofloxacin 750mg daily + rifampin 300-450mg BID for Staph, or TMP-SMX DS 2 tabs BID for MSSA). CRP trending guides response."},{drug:"vancomycin",regimen:"Vancomycin IV (AUC-guided) × 6 weeks (MRSA)",notes:"Standard for MRSA vertebral osteomyelitis. AUC/MIC 400-600. Monitor renal function closely over 6-week course. Oral step-down options for MRSA: TMP-SMX DS 2 tabs BID, linezolid 600mg BID (monitor for myelosuppression — limit to 4-6 weeks if possible), or doxycycline 100mg BID (if susceptible). Some ID physicians use daptomycin as the initial IV agent then step down."},{drug:"ceftriaxone",regimen:"Ceftriaxone 2g IV daily × 6 weeks (Streptococci, susceptible GN)",notes:"Once-daily dosing makes this ideal for OPAT. Excellent for Streptococcal vertebral osteomyelitis and susceptible gram-negative infections. Oral step-down: levofloxacin 750mg daily (if susceptible) or amoxicillin 1g TID (for Streptococci)."}]},{line:"Duration & Monitoring",options:[{drug:"duration-osteo",regimen:"6 weeks total (parenteral + oral per OVIVA)",notes:"IDSA 2015: 6 weeks of parenteral (or equivalent oral per OVIVA) therapy. Start counting from day 1 of appropriate therapy after surgical debridement (if performed). CRP should be trended q1-2 weeks — a decreasing CRP confirms response. If CRP is not declining by week 2-3: re-evaluate (inadequate source control? wrong pathogen? abscess not drained? wrong antibiotic?). Repeat MRI only if clinical concern for worsening (NOT routine — MRI findings lag behind clinical improvement by weeks to months)."}]}],organismSpecific:[{organism:"S. aureus (MSSA)",preferred:"Cefazolin 2g IV q8h → oral step-down (levofloxacin + rifampin, or TMP-SMX)",alternative:"Nafcillin 2g IV q4h (if cefazolin allergy)",notes:"Most common organism. De-escalate from vancomycin as soon as MSSA confirmed. OVIVA-supported oral step-down with bone-penetrating agents after initial IV stabilization (typically 5-7 days). Rifampin combinations are particularly effective for bone infections but only when used with a companion drug."},{organism:"S. aureus (MRSA)",preferred:"Vancomycin IV (AUC-guided) → oral TMP-SMX or linezolid",alternative:"Daptomycin 8-10 mg/kg IV daily",notes:"Oral step-down: TMP-SMX DS 2 tabs BID is the workhorse for MRSA osteomyelitis oral therapy (good bone penetration, tolerable long-term). Linezolid 600mg BID is effective but limit duration due to myelosuppression (CBC weekly). Doxycycline 100mg BID if susceptible."},{organism:"Streptococci (viridans, S. pyogenes, S. agalactiae)",preferred:"Ceftriaxone 2g IV daily × 6 weeks → oral amoxicillin 1g TID",alternative:"Penicillin G IV",notes:"Ceftriaxone is ideal — once-daily OPAT. Oral step-down to high-dose amoxicillin works well given excellent Streptococcal susceptibility. S. agalactiae (GBS): common in elderly/diabetic vertebral osteomyelitis — often from urinary source."},{organism:"Enterobacterales (E. coli, Klebsiella)",preferred:"Ceftriaxone (if susceptible) → oral ciprofloxacin or levofloxacin",alternative:"Ertapenem 1g IV daily (if ESBL)",notes:"Fluoroquinolones have the best oral bioavailability and bone penetration for gram-negative osteomyelitis. Oral step-down to ciprofloxacin 750mg BID or levofloxacin 750mg daily is well-supported. For ESBL: ertapenem IV for OPAT, with limited oral options (discuss with ID)."},{organism:"Pseudomonas aeruginosa",preferred:"Cefepime 2g IV q8h or ciprofloxacin 750mg PO BID (if susceptible)",alternative:"Meropenem if resistant",notes:"Less common in vertebral osteomyelitis except post-procedural or IDU-associated. Ciprofloxacin is one of few oral antipseudomonal agents — makes OVIVA-style oral step-down possible. Duration: 6-8 weeks."},{organism:"Culture-negative (biopsy negative despite holding antibiotics)",preferred:"Vancomycin + ceftriaxone empirically × 6 weeks",alternative:"Consultation with ID for atypical organisms (TB, Brucella, fungi)",notes:"20-30% of biopsies are culture-negative. Consider: prior antibiotics suppressing growth, atypical organisms (Mycobacterium TB — especially in endemic areas or immunocompromised; Brucella — travel to endemic regions, livestock exposure; Coccidioides — Southwest US; Blastomyces). If culture-negative, send additional studies: AFB culture/smear, fungal culture, Brucella serologies, 16S rRNA PCR if tissue available."}],pearls:["GET THE BIOPSY BEFORE ANTIBIOTICS: This is the #1 principle. Holding antibiotics for 24-48h to obtain a CT-guided biopsy does not meaningfully worsen outcomes in stable patients, but it dramatically improves your ability to target therapy. A 6-week course of cefazolin (guided by MSSA culture) is far better than a 6-week course of vancomycin + cefepime (empiric guessing).","OVIVA CHANGED EVERYTHING: Before OVIVA, bone/joint infections meant 6 weeks of IV antibiotics via PICC = mandatory OPAT. Now, oral step-down after initial IV stabilization is standard for most patients. The key is using the RIGHT oral agents: fluoroquinolones, TMP-SMX, rifampin combinations, linezolid, doxycycline. NOT cephalexin or amoxicillin monotherapy for Staphylococcal osteomyelitis.","CRP IS YOUR BEST FRIEND FOR TRENDING: CRP responds faster than ESR and correlates with treatment response. Trend CRP q1-2 weeks. A falling CRP = things are working. A plateau or rise = re-evaluate everything (source control, pathogen, antibiotic choice). ESR takes weeks to months to normalize — less useful for real-time decisions.","EPIDURAL ABSCESS IS THE FEARED COMPLICATION: 15-20% of vertebral osteomyelitis cases have concurrent epidural abscess. Any new neurologic deficit (weakness, sensory changes, bowel/bladder dysfunction) = emergent MRI and neurosurgical consultation. Delayed diagnosis leads to irreversible paraplegia. ALWAYS ask about neurologic symptoms in SAB patients with back pain.","DO NOT REPEAT MRI ROUTINELY: MRI findings in osteomyelitis lag behind clinical improvement by weeks to months. A patient who is clinically improving with falling CRP does not need a repeat MRI at 6 weeks — it will still look bad and cause unnecessary concern. Repeat MRI only for: clinical worsening, new neurologic deficits, or failure to respond to appropriate therapy."]},{id:"septic-arthritis",name:"Septic Arthritis (Native Joint)",definition:"Direct bacterial infection of a joint space, most commonly the knee (50%), followed by hip, shoulder, and ankle. Monoarticular in 80-90% of cases. A medical emergency — purulent joint fluid causes rapid cartilage destruction within hours to days. S. aureus is responsible for 40-60% of cases. N. gonorrhoeae should be considered in sexually active young adults.",clinicalPresentation:"Acute onset of monoarticular joint pain, swelling, warmth, and erythema with severely limited range of motion. The joint is usually held in the position of maximum capsular volume (flexion for knee and hip). Fever in 60-80%. Risk factors: pre-existing joint disease (RA, OA, crystal arthropathy — damaged joints are vulnerable), recent joint surgery or injection, prosthetic joint, bacteremia, immunosuppression, IDU, skin infections. CRITICAL: Do NOT assume a hot swollen joint is gout — always aspirate to rule out septic arthritis, especially if fever is present. Crystal arthropathy and septic arthritis can COEXIST.",diagnostics:"ARTHROCENTESIS IS MANDATORY — aspirate the joint before antibiotics. Synovial fluid analysis: WBC >50,000/μL with >90% PMNs is highly suggestive (sensitivity ~60-80%), but lower counts do not exclude (especially in immunocompromised, partially treated, or prosthetic joints). Gram stain: positive in 50-75% of Staphylococcal cases, <50% for Streptococci, <25% for GN. Culture: gold standard — positive in 70-90%. Blood cultures: positive in 40-50% (always obtain). Crystal analysis: rule out gout/pseudogout BUT crystals do not exclude concurrent infection. CRP/ESR: elevated but nonspecific. Imaging: plain radiographs (baseline, rule out osteomyelitis), ultrasound (detect effusion, guide aspiration — especially hip), MRI if concern for adjacent osteomyelitis.",empiricTherapy:[{line:"Empiric — Pending Cultures",options:[{drug:"vancomycin",regimen:"Vancomycin IV (AUC-guided)",notes:"First-line empiric for native joint septic arthritis. Covers MRSA and MSSA (though inferior to beta-lactams for MSSA — will de-escalate once cultures return). Most septic arthritis is gram-positive (S. aureus 40-60%, Streptococci 15-20%). Add gram-negative coverage (ceftriaxone) if: immunocompromised, IDU, healthcare-associated, GI/GU source suspected."},{drug:"ceftriaxone",regimen:"Ceftriaxone 2g IV daily (add to vancomycin if GN risk)",notes:"For gram-negative coverage in high-risk patients. Also first-line empiric in suspected gonococcal arthritis (sexually active young adult with migratory polyarthralgia → monoarthritis + skin lesions). NAAT for GC/CT on urogenital, rectal, and pharyngeal sites."}]},{line:"Pathogen-Directed Therapy",options:[{drug:"cefazolin",regimen:"Cefazolin 2g IV q8h × 3-4 weeks (MSSA)",notes:"De-escalate from vancomycin upon MSSA confirmation. Duration: 3-4 weeks for native joint septic arthritis (shorter than osteomyelitis if no bone involvement). Oral step-down per OVIVA: consider after 1-2 weeks IV if clinically responding, using bone-penetrating oral agents."},{drug:"ceftriaxone-gc",regimen:"Ceftriaxone 1g IV/IM daily × 7-14 days (gonococcal)",notes:"Gonococcal arthritis: excellent prognosis. Ceftriaxone 1g IV daily until clinical improvement (usually 24-48h), then oral step-down to cefixime or ciprofloxacin (if susceptible) to complete 7-14 days. Treat concurrent chlamydia empirically (azithromycin 1g or doxycycline 100mg BID × 7d)."}]},{line:"Surgical Drainage",options:[{drug:"drainage-native",regimen:"Serial arthrocentesis or arthroscopic lavage",notes:"Purulent joints must be drained. Options: (1) Serial bedside arthrocentesis (daily or as needed until effusion resolves — works well for knee), (2) Arthroscopic lavage/debridement (preferred for hip, shoulder, and joints difficult to aspirate adequately), (3) Open arthrotomy (reserved for failed arthroscopic drainage, hip joint in some centers, or when debridement of necrotic tissue is needed). HIP SEPTIC ARTHRITIS: usually requires surgical drainage (deep joint, difficult to aspirate adequately at bedside)."}]}],organismSpecific:[{organism:"S. aureus (MSSA/MRSA)",preferred:"Cefazolin (MSSA) or vancomycin/daptomycin (MRSA) × 3-4 weeks",alternative:"TMP-SMX or linezolid for MRSA oral step-down",notes:"Most common cause. Aggressive joint destruction. Prompt drainage + antibiotics. Duration 3-4 weeks if no adjacent osteomyelitis; extend to 6 weeks if bone involvement confirmed on imaging."},{organism:"Streptococci (pyogenes, agalactiae, pneumoniae)",preferred:"Ceftriaxone 2g IV daily → oral amoxicillin 1g TID",alternative:"Penicillin G IV",notes:"S. agalactiae (GBS) increasingly common in elderly/diabetic. Good prognosis with appropriate therapy. Duration: 3-4 weeks."},{organism:"N. gonorrhoeae",preferred:"Ceftriaxone 1g IV daily → oral step-down",alternative:"Consult ID for cephalosporin allergy",notes:"Think about this in every sexually active young adult with acute monoarthritis. Two forms: disseminated gonococcal infection (DGI) with migratory polyarthralgia + dermatitis-arthritis syndrome, and purulent monoarthritis. Excellent prognosis. Always test for concurrent chlamydia and treat empirically."},{organism:"Gram-negatives (E. coli, Pseudomonas)",preferred:"Ceftriaxone or cefepime (based on susceptibilities)",alternative:"Ciprofloxacin PO for oral step-down",notes:"More common in elderly, immunocompromised, IDU, and GU/GI-source bacteremia. Pseudomonas: consider in IDU (sternoclavicular joint classically). Duration: 3-4 weeks."}],pearls:["ASPIRATE FIRST, THEN ANTIBIOTICS: Synovial fluid culture is the gold standard. Once antibiotics are started, culture yield drops significantly. If the joint is hot and swollen, aspirate it — even in the middle of the night. The tap is both diagnostic AND therapeutic (decompresses the joint).","CRYSTALS DON'T EXCLUDE INFECTION: Finding urate or CPPD crystals in synovial fluid does NOT rule out concurrent septic arthritis. Up to 5% of septic joints have concurrent crystal disease. If the clinical picture suggests infection (fever, very high WBC count, immunocompromised), treat for BOTH and let cultures guide final management.","HIP SEPTIC ARTHRITIS = SURGICAL EMERGENCY: The hip joint is deep, difficult to aspirate adequately at bedside, and highly susceptible to avascular necrosis from increased intra-articular pressure. Most orthopedic surgeons prefer operative drainage for hip septic arthritis rather than serial bedside aspiration.","GONOCOCCAL ARTHRITIS HAS EXCELLENT PROGNOSIS: Unlike other forms of septic arthritis, gonococcal arthritis rarely causes permanent joint damage if treated promptly. Short course of ceftriaxone is usually curative. Always screen for concurrent STIs."]},{id:"prosthetic-joint-infection",name:"Prosthetic Joint Infection (PJI)",definition:"Infection of a prosthetic joint (hip, knee, shoulder, etc.). Classified by timing: early (<3 months post-op, typically aggressive organisms acquired at surgery — S. aureus, GN), delayed (3-12 months, indolent organisms — CoNS, Cutibacterium acnes), and late (>12 months, usually hematogenous seeding from distant source). PJI management requires close collaboration between orthopedics, ID, and pharmacy. Cure rates depend heavily on surgical approach selection.",clinicalPresentation:"Early PJI: acute onset wound drainage, erythema, warmth, pain at surgical site within weeks of surgery. Delayed PJI: progressive joint pain and stiffness without dramatic inflammatory signs — often misdiagnosed as aseptic loosening for months. Late PJI: acute onset joint pain after a period of good function — often preceded by documented bacteremia (dental procedure, UTI, skin infection). Sinus tract communicating with the prosthesis = PJI by definition (IDSA major criterion). Periprosthetic fracture with unexplained loosening should raise concern for occult PJI.",diagnostics:"2018 ICM criteria (scoring system): MAJOR CRITERIA (either = definite PJI): (1) Sinus tract communicating with joint, (2) Two positive cultures of same organism from separate samples. MINOR CRITERIA (scored): Elevated serum CRP (>1 mg/dL for chronic, >10 for acute), elevated D-dimer (>860 ng/mL), elevated synovial WBC (>3,000 for chronic PJI, >10,000 for acute), positive synovial alpha-defensin, elevated synovial CRP, positive histology (>5 PMN/HPF), single positive culture, positive leukocyte esterase (++ on strip). CRITICAL: obtain at least 3-5 intraoperative tissue cultures (ideally 5-6) from different areas. Hold antibiotics ≥2 weeks pre-operatively if possible to maximize culture yield. Sonication of explanted prosthesis increases sensitivity for biofilm organisms.",empiricTherapy:[{line:"Surgical Strategy — The Most Important Decision",options:[{drug:"dair",regimen:"DAIR: Debridement, Antibiotics, and Implant Retention",notes:"Criteria for DAIR: (1) Early PJI (<30 days post-op) OR acute hematogenous PJI with symptoms <3 weeks, (2) Stable, well-fixed implant, (3) Intact soft tissue envelope, (4) Susceptible organism (ideally Staphylococcus amenable to rifampin), (5) NOT a highly virulent or resistant organism. DAIR success: 55-75% (organism-dependent — better for Streptococci, worse for MRSA and resistant GN). If ANY DAIR criterion is not met → exchange arthroplasty."},{drug:"two-stage",regimen:"Two-Stage Exchange: Explant → antibiotic spacer → 6-8 weeks antibiotics → reimplantation",notes:"Gold standard for chronic PJI, PJI failing DAIR, resistant organisms, compromised soft tissues. Stage 1: remove all prosthetic components and cement, aggressive debridement, place antibiotic-loaded cement spacer. Pathogen-directed systemic antibiotics × 6-8 weeks (some use 4-6 weeks after spacer). Stage 2: reimplant after antibiotic holiday + negative inflammatory markers ± re-aspiration. Success: 85-95%."},{drug:"one-stage",regimen:"One-Stage Exchange: Explant + immediate reimplantation in single surgery",notes:"Gaining popularity in selected cases: healthy patient, susceptible organism (especially Streptococci), no sinus tract, healthy soft tissues. Advantage: single surgery, faster functional recovery. The INFORM trial (2022) showed non-inferiority of one-stage vs. two-stage for selected hip and knee PJI. Success: 85-95% in appropriate candidates."}]},{line:"Antibiotic Therapy for DAIR (Staphylococcal PJI)",options:[{drug:"cefazolin-rifampin-dair",regimen:"Cefazolin 2g IV q8h + Rifampin 300-450mg PO q12h × 2-6 weeks IV, then oral companion + rifampin to complete 3 months (hip) or 6 months (knee)",notes:"For MSSA PJI treated with DAIR. Rifampin is ESSENTIAL — it penetrates biofilm and kills sessile organisms on prosthetic material. NEVER use rifampin alone (resistance in 1-2 days). Start rifampin only AFTER initial debridement and once bacteremia has cleared (rifampin resistance can emerge if used during active bacteremia). Oral companion drugs for rifampin: levofloxacin 500mg daily (preferred for MSSA), TMP-SMX DS 1 tab BID, or doxycycline 100mg BID."},{drug:"vanc-rifampin-dair",regimen:"Vancomycin IV (AUC-guided) + Rifampin 300-450mg PO q12h × 2-6 weeks IV, then oral companion + rifampin to complete 3-6 months",notes:"For MRSA PJI treated with DAIR. Same rifampin principles. Oral companions for MRSA: TMP-SMX DS 1 tab BID + rifampin (most common), linezolid 600mg BID + rifampin (limit linezolid duration — myelosuppression), or doxycycline 100mg BID + rifampin (if susceptible). Total duration: 3 months (hip) or 6 months (knee)."}]},{line:"Antibiotic Therapy for Two-Stage Exchange",options:[{drug:"two-stage-abx",regimen:"Pathogen-directed IV/oral therapy × 4-6 weeks between stages",notes:"After stage 1 (explant + debridement): pathogen-directed systemic antibiotics for 4-6 weeks. Rifampin is NOT needed during the spacer phase (no retained implant — no biofilm target). After completion of antibiotics: 2-4 week antibiotic-free holiday. Check CRP, aspirate joint if feasible. If markers normalizing and aspirate negative → proceed to stage 2 (reimplant). After stage 2: some protocols use perioperative prophylaxis only; others use 4-6 weeks of pathogen-directed therapy post-reimplantation. Practice varies."}]}],organismSpecific:[{organism:"Staphylococcus aureus (MSSA/MRSA)",preferred:"DAIR + rifampin combination (if DAIR criteria met); two-stage exchange if chronic",alternative:"Daptomycin IV for MRSA if vancomycin intolerant",notes:"Most important principle: RIFAMPIN for any retained prosthetic material. For two-stage exchange, rifampin is used post-reimplantation (stage 2), not during the spacer phase."},{organism:"CoNS (S. epidermidis — most common cause of delayed PJI)",preferred:"Vancomycin + rifampin (most CoNS are methicillin-resistant) for DAIR; pathogen-directed for exchange",alternative:"Daptomycin + rifampin",notes:"S. epidermidis is THE biofilm organism. Low virulence but tenacious — forms thick biofilm on prosthetic surfaces. Usually methicillin-resistant (80-90%). Responds well to DAIR + rifampin if detected early. Delayed PJI (3-12 months) with progressive pain and loosening is the classic CoNS PJI presentation."},{organism:"Cutibacterium acnes (shoulder PJI)",preferred:"Penicillin G or amoxicillin × 6 weeks",alternative:"Ceftriaxone, clindamycin",notes:"The DOMINANT organism in shoulder PJI (>50% in some series). Extremely slow-growing — cultures must be held for 14 days (standard 5-day incubation misses it). Low virulence, indolent presentation. Responds well to simple penicillin derivatives. Consider this organism in any shoulder PJI with negative standard cultures."},{organism:"Streptococci",preferred:"Ceftriaxone 2g IV daily + rifampin for DAIR; ceftriaxone alone for exchange",alternative:"Penicillin G or amoxicillin",notes:"Good prognosis — DAIR cure rates for Streptococcal PJI are higher than Staphylococcal PJI (>80%). Rifampin still recommended for retained implants. One-stage exchange may be particularly appropriate for Streptococcal PJI."}],pearls:["RIFAMPIN IS MANDATORY FOR STAPHYLOCOCCAL PJI WITH RETAINED IMPLANTS: The Zimmerli trial showed 100% cure with rifampin vs. 58% without. Rifampin penetrates biofilm and kills sessile bacteria. NEVER use rifampin monotherapy (resistance in 1-2 days). Always pair with an active companion drug. Start rifampin AFTER debridement and bloodstream clearance.","HOLD CULTURES 14 DAYS FOR SHOULDER PJI: Cutibacterium acnes is the dominant shoulder PJI pathogen and takes 10-14 days to grow. Standard 5-day culture incubation misses it. If your microbiology lab discards shoulder PJI cultures at 5 days, you are systematically missing the most common pathogen.","3 MONTHS (HIP) vs 6 MONTHS (KNEE) FOR DAIR: The longer duration for knee PJI reflects poorer soft tissue coverage and higher failure rates compared to hip PJI treated with DAIR. This is IDSA 2013 guidance and remains standard.","ANTIBIOTIC-LOADED CEMENT SPACERS: The spacer delivers high local antibiotic concentrations (vancomycin + tobramycin or gentamicin is the most common combination). This is adjunctive to systemic antibiotics, not a replacement. The spacer also maintains joint space and limb length between stages.","THE RIFAMPIN DRUG INTERACTION LIST IS ENORMOUS: Rifampin is one of the most potent CYP inducer known. It reduces levels of: warfarin, statins, oral contraceptives, calcineurin inhibitors (cyclosporine, tacrolimus), HIV antiretrovirals, azole antifungals, methadone, and dozens more. Review the entire medication list before starting rifampin. This is a critical pharmacist intervention."]},{id:"diabetic-foot-osteo",name:"Diabetic Foot Osteomyelitis",definition:"Osteomyelitis complicating diabetic foot infections (DFI), occurring in 20-60% of moderate-severe DFIs. Usually contiguous spread from an overlying infected ulcer (not hematogenous). The diagnostic challenge is distinguishing osteomyelitis from Charcot neuroarthropathy and soft tissue infection. Management decisions include medical-only treatment vs. surgical resection, which fundamentally changes antibiotic duration.",clinicalPresentation:"Chronic non-healing diabetic foot ulcer with underlying bone exposure or palpable bone on probing. Probe-to-bone (PTB) test: positive when a sterile metal probe inserted through the ulcer contacts gritty bone (PPV ~89% in high pre-test probability patients). Sausage toe: diffuse swelling of entire digit suggests underlying osteomyelitis. Often minimal systemic symptoms (no fever, normal WBC) due to peripheral neuropathy and vascular insufficiency masking inflammatory response.",diagnostics:"Probe-to-bone test (perform on every DFI ulcer). Plain radiographs: cortical erosion, periosteal reaction, but 30-50% sensitivity (changes take 2-3 weeks to appear). MRI: gold standard — sensitivity 90%, specificity 80% for DFI osteomyelitis. ESR >70 mm/h: high specificity for osteomyelitis in DFI setting. BONE BIOPSY: gold standard for definitive diagnosis and pathogen identification. Obtain percutaneous or intraoperative bone biopsy BEFORE starting antibiotics whenever possible. Surface wound cultures DO NOT reflect bone pathogens — they grow colonizers.",empiricTherapy:[{line:"Medical Management (No Bone Resection)",options:[{drug:"medical-osteo",regimen:"Pathogen-directed therapy × 4-6 weeks (based on BONE culture, not wound swab)",notes:"If treating medically without surgery: 4-6 weeks of antibiotics directed by bone biopsy culture. OVIVA supports oral step-down with appropriate agents. CRP and clinical response guide adequacy. CRITICAL: surface wound swab cultures do NOT guide osteomyelitis therapy — you must have bone culture. If no bone biopsy is obtainable, empiric coverage of the most likely pathogens (S. aureus ± GN based on clinical context)."}]},{line:"Post-Surgical Resection (Complete Bone Removal)",options:[{drug:"post-resection",regimen:"1-2 weeks of antibiotics post-resection if clean margins",notes:"If infected bone is COMPLETELY resected with confirmed clean margins on histology: antibiotics can be shortened dramatically to 1-2 weeks (some experts use 5-7 days post-resection). This is a paradigm shift from 6-week courses — adequate surgery can substitute for prolonged antibiotics. The pathology report confirming clean margins is essential."}]}],organismSpecific:[{organism:"S. aureus (MSSA/MRSA)",preferred:"Cefazolin or vancomycin (based on susceptibility)",alternative:"TMP-SMX or linezolid for oral step-down",notes:"Most common single organism in DFI osteomyelitis. Bone biopsy culture is the only reliable way to confirm. OVIVA-style oral step-down with appropriate agents is reasonable."},{organism:"Polymicrobial (chronic DFI)",preferred:"Broad-spectrum based on deep culture (e.g., pip-tazo + vancomycin)",alternative:"Ertapenem + vancomycin",notes:"Chronic DFI osteomyelitis is often polymicrobial — Staphylococci + Streptococci + Enterobacterales + anaerobes. This is why bone biopsy matters — treating every organism from a wound swab leads to unnecessarily broad 6-week regimens."}],pearls:["SURFACE WOUND CULTURES ARE USELESS FOR OSTEOMYELITIS: This cannot be overstated. The organisms colonizing the surface of a chronic diabetic ulcer (Pseudomonas, Corynebacterium, mixed flora) are NOT the organisms infecting the bone. ALWAYS obtain bone cultures (biopsy or intraoperative). A 6-week antibiotic course should never be based on a surface swab.","OVIVA + SURGERY = PARADIGM SHIFT: For DFI osteomyelitis treated with complete bone resection and clean margins, antibiotics can be as short as 5-7 days. This is dramatically different from the traditional 6-week IV dogma. The surgery does the heavy lifting; antibiotics are adjunctive.","VASCULAR ASSESSMENT BEFORE ANTIBIOTICS: No antibiotic can cure osteomyelitis in an ischemic limb. Check ankle-brachial index, toe pressures, or transcutaneous oxygen. If vascular disease is present, revascularization is needed for healing. Multidisciplinary approach (vascular surgery + ID + podiatry + wound care) is essential.","PROBE-TO-BONE: FREE, FAST, AND INFORMATIVE: Every clinician seeing DFI should perform this test. Positive PTB in a high-risk patient has PPV ~89% for osteomyelitis. Negative PTB has NPV ~56% (doesn't rule it out). Takes 30 seconds and requires only a sterile blunt probe."]}],drugMonographs:[{id:"rifampin",name:"Rifampin",brandNames:"Rifadin, Rimactane",drugClass:"Rifamycin antibiotic (RNA polymerase inhibitor)",mechanismOfAction:"Inhibits DNA-dependent RNA polymerase, blocking RNA transcription. BACTERICIDAL with rapid, concentration-dependent killing. CRITICAL PROPERTY: rifampin penetrates and is active within BIOFILM — the protective matrix that organisms form on prosthetic material, dead bone, and foreign bodies. This is the only commonly used antibiotic with clinically meaningful biofilm activity. This property makes rifampin ESSENTIAL for prosthetic material infections (PJI, prosthetic valve IE). Rifampin also penetrates intracellularly, killing S. aureus within macrophages and osteoblasts.",spectrum:"Gram-positive: Excellent — S. aureus (MSSA and MRSA), CoNS, Streptococci. Gram-negative: moderate activity against some (not clinically used). Mycobacteria: first-line for TB (M. tuberculosis), M. leprae. UNIQUE: biofilm-embedded organisms. GAPS: Enterococcus, most gram-negatives, anaerobes. CRITICAL RULE: NEVER use rifampin as monotherapy — resistance develops in 1-2 days via single-step RNA polymerase mutations. ALWAYS combine with an active companion drug.",dosing:{pji:"300-450mg PO every 12h (most common for PJI/bone infections)",prosthetic_valve_ie:"300-450mg PO every 8h",tb:"10 mg/kg/day PO (max 600mg) once daily",meningococcal_prophylaxis:"600mg PO q12h × 2 days"},renalAdjustment:"No dose adjustment — hepatically metabolized, biliary excretion. Not removed by hemodialysis.",hepaticAdjustment:"USE WITH CAUTION in hepatic impairment. Rifampin is hepatotoxic — monitor LFTs baseline and periodically. In severe hepatic disease, consider dose reduction or alternative agents.",adverseEffects:{common:"GI intolerance (nausea, anorexia), orange/red discoloration of body fluids (urine, tears, sweat, saliva — WARN PATIENTS, stains contact lenses), elevated LFTs (transaminases)",serious:"Hepatotoxicity (1-3%, dose-dependent — monitor LFTs), thrombocytopenia (immune-mediated, especially with intermittent dosing), acute kidney injury (interstitial nephritis, especially with intermittent dosing), flu-like syndrome (with intermittent/resumed dosing)",rare:"Severe hepatic failure, hemolytic anemia, acute renal failure, shock-like syndrome (with intermittent high-dose use)"},drugInteractions:["WARFARIN — rifampin is one of the most potent CYP inducers known. Dramatically reduces warfarin levels. May need 2-3x the usual warfarin dose. Monitor INR very closely when starting AND stopping (rebound increase when rifampin discontinued).","ORAL CONTRACEPTIVES — rendered ineffective. Must use alternative contraception during rifampin therapy.","CALCINEURIN INHIBITORS (cyclosporine, tacrolimus) — levels drastically reduced. Transplant patients on rifampin need very close monitoring and major dose increases.","STATINS — most statins are CYP3A4 substrates. Levels significantly reduced by rifampin. May need to increase statin dose or switch agents.","HIV ANTIRETROVIRALS (particularly PIs and NNRTIs) — complex interactions. Consult ID/pharmacist for HIV patients needing rifampin.","METHADONE — rifampin reduces methadone levels, can precipitate withdrawal. Critical in IDU patients with PJI or endocarditis.","AZOLE ANTIFUNGALS — voriconazole, itraconazole, posaconazole levels dramatically reduced. Concomitant use often contraindicated.","DAPTOMYCIN — rifampin may reduce daptomycin efficacy (antagonism in some in vitro models). Some experts avoid this combination, though clinical data is limited."],monitoring:"LFTs at baseline, then q2-4 weeks (hepatotoxicity). CBC with platelets (thrombocytopenia). Renal function. Drug interactions — review ENTIRE medication list before starting. Clinical efficacy — CRP trending for bone/joint infections. Warn about orange discoloration of body fluids.",pregnancyLactation:"Pregnancy Category C. Teratogenic in animals at high doses. Use only when clearly needed. Crosses placenta. Excreted in breast milk. For TB in pregnancy: rifampin is part of standard treatment despite category C designation — benefits outweigh risks.",pharmacistPearls:["THE DRUG INTERACTION LIST IS YOUR JOB: Rifampin interacts with EVERYTHING metabolized by CYP450 (CYP3A4, CYP2C9, CYP2C19, CYP1A2). Before starting rifampin, the pharmacist MUST review the entire medication list. Common catches: warfarin (dose increase needed), oral contraceptives (backup needed), statins (increase dose or switch), methadone (increase dose or withdraw), calcineurin inhibitors (transplant patients — major dose changes). This review is arguably the highest-value pharmacist intervention in PJI management.","NEVER MONOTHERAPY: Resistance to rifampin develops via single-step RNA polymerase mutations at a frequency of 10⁻⁷ to 10⁻⁸. Monotherapy selects resistant mutants in 1-2 days. ALWAYS combine with an active companion drug. The companion should have independent activity against the organism.","START RIFAMPIN AFTER DEBRIDEMENT AND BLOODSTREAM CLEARANCE: Do not start rifampin on day 1 of empiric therapy for a bacteremic patient. The high bacterial load during bacteremia increases the probability of selecting rifampin-resistant mutants. Wait until surgical debridement is complete and blood cultures are clearing, THEN add rifampin.","ORANGE BODY FLUIDS: Warn patients that urine, tears, sweat, and saliva will turn orange/red. This stains contact lenses permanently — switch to glasses. Stains are harmless but alarming if unexpected. This counseling point prevents unnecessary ER visits.","THE ARREST TRIAL DISTINCTION: Rifampin is NOT beneficial for native valve SAB (ARREST trial — no benefit, added toxicity). BUT rifampin IS essential for prosthetic material infections (PJI, prosthetic valve IE — Zimmerli trial showed dramatic benefit). The distinction is BIOFILM: prosthetic material has biofilm, native valves do not."]},{id:"linezolid",name:"Linezolid",brandNames:"Zyvox",drugClass:"Oxazolidinone antibiotic (first-in-class)",mechanismOfAction:"Binds to 23S ribosomal RNA of the 50S subunit, preventing formation of the 70S initiation complex and blocking protein synthesis. BACTERIOSTATIC against most organisms (Staphylococci, Enterococci), but bactericidal against Streptococci. Unique binding site — no cross-resistance with other protein synthesis inhibitors. 100% oral bioavailability — IV and PO are bioequivalent.",spectrum:"Gram-positive ONLY. Excellent: MRSA, MSSA, VRE (E. faecium AND E. faecalis — one of few oral VRE-active agents), Streptococci, CoNS, Nocardia. GAPS: ALL gram-negatives, ALL anaerobes (minimal activity). NOTE: bacteriostatic against Staphylococci — this matters for endocarditis and bacteremia where bactericidal agents are preferred (daptomycin, beta-lactams).",dosing:{standard:"600mg IV or PO q12h",bone_joint:"600mg PO BID (OVIVA-supported for oral step-down in bone infections)",pneumonia:"600mg IV/PO q12h (MRSA pneumonia — linezolid preferred over vancomycin for lung penetration)",ssti:"600mg IV/PO q12h × 10-14 days",vre:"600mg IV/PO q12h"},renalAdjustment:"No dose adjustment — not primarily renally eliminated. HOWEVER: two metabolites accumulate in renal impairment and may contribute to toxicity (myelosuppression). Monitor CBC more closely in renal impairment.",hepaticAdjustment:"No adjustment for mild-moderate. Limited data in severe hepatic impairment.",adverseEffects:{common:"GI (nausea, diarrhea), headache, thrombocytopenia (dose and duration-dependent — most common with courses >2 weeks)",serious:"Myelosuppression (thrombocytopenia 2-5%, anemia, neutropenia — reversible, monitor CBC weekly), peripheral neuropathy (cumulative, courses >4 weeks), optic neuritis (rare, reversible if caught early), lactic acidosis (mitochondrial toxicity — rare but potentially fatal)",rare:"Serotonin syndrome (weak MAO inhibitor — see drug interactions), severe lactic acidosis, irreversible peripheral neuropathy (if prolonged use unmonitored)"},drugInteractions:["SEROTONERGIC DRUGS — linezolid is a weak, reversible MAO inhibitor. Risk of serotonin syndrome with SSRIs, SNRIs, trazodone, meperidine, tramadol, buspirone, St. John's wort. MANAGEMENT: for courses <14 days, many experts continue serotonergic agents with close monitoring. For longer courses, consider holding the serotonergic agent or choosing an alternative antibiotic. The risk is real but often overstated for short courses.","Tyramine-containing foods — theoretical risk of hypertensive crisis due to MAO inhibition. Clinical significance is low with reversible MAO inhibition, but counsel patients to avoid large quantities of aged cheeses, fermented meats, and tap beer.","Sympathomimetics (pseudoephedrine, phenylephrine) — potential for hypertension. Avoid or monitor."],monitoring:"CBC with platelets WEEKLY (mandatory — thrombocytopenia is dose-limiting). For courses >4 weeks: visual acuity testing (optic neuritis), neurologic assessment (peripheral neuropathy — numbness/tingling in extremities). Lactate if unexplained acidosis. Serotonin syndrome monitoring if on serotonergic agents.",pregnancyLactation:"Pregnancy Category C. Animal studies show decreased fetal viability at high doses. Limited human data. Use only when benefit clearly outweighs risk. Excreted in breast milk in animal studies.",pharmacistPearls:["100% ORAL BIOAVAILABILITY = NO REASON FOR IV: Linezolid PO and IV achieve identical serum levels. If the patient can swallow, use oral. IV linezolid costs 10-20x more than oral for no pharmacokinetic benefit. This is one of the most impactful IV-to-PO stewardship interventions.","THROMBOCYTOPENIA IS THE DOSE-LIMITING TOXICITY: Onset typically after 10-14 days. Monitor platelets weekly without exception. Risk factors: renal impairment, baseline low platelets, duration >2 weeks. Usually reversible upon discontinuation. If platelets drop <100K or >50% from baseline, reassess risk-benefit.","BONE PENETRATION MAKES IT VALUABLE FOR OSTEOMYELITIS: Linezolid achieves bone concentrations that are 40-60% of serum — among the highest of any antibiotic. Combined with 100% oral bioavailability, it's an excellent OVIVA-style oral step-down option for MRSA osteomyelitis. Duration limitation (myelosuppression >4-6 weeks) is the main constraint.","THE MAO INHIBITOR INTERACTION IS REAL BUT NUANCED: For short courses (≤14 days), many ID pharmacists and physicians continue SSRIs/SNRIs with monitoring rather than holding them. For bone/joint infections requiring weeks of linezolid, the serotonergic drug should be held or an alternative antibiotic chosen. The key is duration-dependent risk assessment.","MRSA PNEUMONIA: LINEZOLID > VANCOMYCIN: Vancomycin achieves poor lung concentrations (epithelial lining fluid levels are only 10-25% of serum). Linezolid achieves ELF concentrations exceeding serum levels. For MRSA pneumonia, linezolid is preferred. The ZEPHyR trial showed numerical superiority of linezolid over vancomycin for MRSA nosocomial pneumonia (though primary endpoint differences were debated)."]}]},f={id:"cns-infections",name:"CNS Infections",icon:"🧠",category:"Infectious Disease — IDSA 2004/2017 + ESCMID 2016",overview:{definition:"Central nervous system infections encompass bacterial meningitis (infection of the meninges), encephalitis (infection of brain parenchyma), and brain abscess (focal suppurative collection within the brain). These infections represent true medical emergencies where delays in antibiotic therapy of even 1-2 hours measurably increase mortality. The blood-brain barrier (BBB) creates unique pharmacologic challenges — most antibiotics achieve poor CNS penetration, requiring higher doses, specific drug selection, and sometimes intrathecal administration.",epidemiology:"Bacterial meningitis: incidence 1-2 per 100,000 in developed countries (dramatically reduced by pneumococcal and meningococcal conjugate vaccines). S. pneumoniae and N. meningitidis account for >80% of community-acquired cases in adults. Listeria monocytogenes risk increases with age >50, immunosuppression, and pregnancy. Neonatal meningitis: GBS and E. coli dominate. Post-neurosurgical meningitis: Staphylococci and gram-negatives. Brain abscess: 1,500-2,500 cases/year in the US. Sources: contiguous spread (sinusitis, otitis, dental infection), hematogenous (endocarditis, lung abscess, IDU), or post-neurosurgical/trauma. Mortality for bacterial meningitis: 15-25% overall (S. pneumoniae ~20-30%, N. meningitidis ~10%, Listeria ~20-30%).",keyGuidelines:[{name:"IDSA 2004 Bacterial Meningitis Guidelines",detail:"Foundation document for meningitis management. Established empiric regimens by age group, adjunctive dexamethasone for pneumococcal meningitis, and pathogen-specific therapy. Despite age, remains the most cited meningitis guideline. Key updates have been incorporated via expert consensus rather than formal guideline revision."},{name:"IDSA 2017 Healthcare-Associated Ventriculitis/Meningitis",detail:"Guidelines for post-neurosurgical, post-traumatic, and device-related CNS infections. Covers external ventricular drain (EVD) infections, VP shunt infections, and post-craniotomy meningitis. Emphasizes intraventricular antibiotic administration for difficult-to-treat pathogens."},{name:"ESCMID 2016 Community-Acquired Bacterial Meningitis",detail:"European guidelines with updated evidence review. Stronger emphasis on adjunctive dexamethasone, updated duration recommendations, and management of complications (cerebral edema, hydrocephalus, vasculitis)."},{name:"AAN/IDSA 2008 Brain Abscess Practice Parameters",detail:"Guidance on diagnosis (ring-enhancing lesion on contrast CT/MRI), aspiration vs. excision criteria, and empiric antibiotic regimens based on suspected source (dental → anaerobes + Streptococci; otogenic → Pseudomonas + anaerobes; hematogenous → S. aureus + mixed)."}],landmarkTrials:[{name:"de Gans & van de Beek, NEJM 2002 — Dexamethasone in Meningitis",detail:"Landmark RCT: adjunctive dexamethasone (10mg IV q6h × 4 days) started BEFORE or WITH the first dose of antibiotics reduced mortality and neurologic sequelae in adults with bacterial meningitis, particularly PNEUMOCOCCAL meningitis (mortality 14% vs 34%). This trial established dexamethasone as standard of care. KEY: dexamethasone must be given BEFORE or simultaneous with the first antibiotic dose — giving it hours later provides no benefit."},{name:"van de Beek et al., NEJM 2006 — Meningitis Clinical Features",detail:"Large prospective cohort defining the clinical spectrum of community-acquired bacterial meningitis. The classic triad (fever + neck stiffness + altered mental status) was present in only 44% of patients, but 95% had at least 2 of 4 symptoms (headache, fever, neck stiffness, altered consciousness). Established that absence of ALL classic features essentially rules out bacterial meningitis."},{name:"Brouwer et al., Cochrane 2015 — Dexamethasone Meta-analysis",detail:"Cochrane systematic review confirming dexamethasone benefit in high-income countries for S. pneumoniae meningitis. No significant benefit demonstrated for meningococcal or other etiologies, and no benefit in low-income settings (possibly due to later presentation and HIV co-infection). Reinforced that the dexamethasone benefit is primarily for pneumococcal meningitis."}],riskFactors:"Bacterial meningitis: age extremes (neonates, >50 years), asplenia/complement deficiency (N. meningitidis, S. pneumoniae), CSF leaks (basilar skull fractures, post-neurosurgical), cochlear implants (S. pneumoniae), immunosuppression (HIV, transplant, chronic steroids → Listeria, Cryptococcus), crowded living (military barracks, dormitories → N. meningitidis). Brain abscess: contiguous infection (chronic sinusitis, otitis media, dental abscess), hematogenous spread (endocarditis, pulmonary AVM in hereditary hemorrhagic telangiectasia, IDU), penetrating trauma, recent neurosurgery, immunosuppression (Toxoplasma in HIV, Nocardia in transplant, Aspergillus in neutropenia)."},subcategories:[{id:"community-bacterial-meningitis",name:"Community-Acquired Bacterial Meningitis",definition:"Acute bacterial infection of the leptomeninges (pia and arachnoid mater) and subarachnoid space acquired outside the healthcare setting. This is a MEDICAL EMERGENCY — every hour of delay in antibiotic administration increases mortality by 3-7%. When meningitis is suspected, the first antibiotic dose takes priority over ALL other interventions (LP, CT, cultures). Time to antibiotics is the single most modifiable prognostic factor.",clinicalPresentation:"Classic triad: fever + neck stiffness + altered mental status — but present in only 44% of patients. At least 2 of 4 (headache, fever, neck stiffness, altered consciousness) present in 95%. Headache is the most common symptom (~85%). Kernig sign (pain with knee extension while hip flexed) and Brudzinski sign (involuntary hip flexion with passive neck flexion) have poor sensitivity (~5%) but high specificity — their absence does NOT rule out meningitis. Petechial/purpuric rash = MENINGOCOCCEMIA until proven otherwise (medical emergency — empiric antibiotics IMMEDIATELY, even before LP). Seizures in 20-30%. Cranial nerve palsies (VI most common — false localizing sign from increased ICP). Papilledema (late sign of raised ICP).",diagnostics:"LUMBAR PUNCTURE IS DIAGNOSTIC — obtain ASAP but DO NOT DELAY ANTIBIOTICS for LP. If LP will be delayed (CT needed first, coagulopathy, etc.), start antibiotics + dexamethasone BEFORE LP. CSF findings in bacterial meningitis: WBC 1,000-5,000/μL (>90% PMNs), protein elevated (>100-500 mg/dL), glucose low (<40 mg/dL or CSF/serum glucose ratio <0.4), Gram stain positive in 60-90% (highest for pneumococcus, lowest for Listeria). CSF culture: positive in 70-85% (reduced if antibiotics given first — but still worth obtaining). CSF latex agglutination/PCR: useful when cultures are negative (especially post-antibiotic). Blood cultures: positive in 50-75% — ALWAYS obtain before antibiotics. CT scan before LP: indicated ONLY when risk of herniation — criteria: immunocompromised, history of CNS disease, new-onset seizure, papilledema, altered consciousness, focal neurologic deficit. Most patients do NOT need CT before LP.",durationGuidance:{standard:"10–14 days (S. pneumoniae/Listeria)",severe:"21 days (Listeria/gram-negative bacilli)",stewardshipNote:"IDSA 2004 (updated): Listeria 21d, N. meningitidis 5–7d, S. pneumoniae 10–14d, gram-negatives 21d."},empiricTherapy:[{line:"Empiric — Adults 18-50 years (IMMEDIATE — within minutes)",options:[{drug:"ceftriaxone-vanco-meningitis",regimen:"Vancomycin 15-20 mg/kg IV + Ceftriaxone 2g IV q12h + Dexamethasone 0.15 mg/kg IV q6h × 4 days",notes:"STANDARD empiric regimen for community-acquired bacterial meningitis in adults 18-50. Vancomycin covers ceftriaxone-resistant S. pneumoniae (ceftriaxone MIC ≥2). Ceftriaxone covers susceptible S. pneumoniae and N. meningitidis. Dexamethasone MUST be given BEFORE or SIMULTANEOUSLY with the first antibiotic dose — reduces mortality and neurologic sequelae (de Gans trial). If given hours later, it provides no benefit. TIMING IS EVERYTHING: do not delay antibiotics for LP, imaging, or any other test.",evidence:"A-I",evidenceSource:"IDSA 2004"}]},{line:"Empiric — Adults >50 years or Immunocompromised (ADD Listeria coverage)",options:[{drug:"ceftriaxone-vanco-ampicillin",regimen:"Vancomycin IV + Ceftriaxone 2g IV q12h + Ampicillin 2g IV q4h + Dexamethasone",notes:"ADD AMPICILLIN for Listeria coverage in patients >50 years, immunocompromised (HIV, transplant, chronic steroids, pregnancy, alcoholism, malignancy). Ceftriaxone does NOT cover Listeria (inherent resistance to cephalosporins). Ampicillin is the drug of choice for Listeria meningitis. If the patient has no Listeria risk factors AND is <50 years, ampicillin can be omitted.",evidence:"A-I",evidenceSource:"IDSA 2004"}]},{line:"Empiric — Neonates (<1 month)",options:[{drug:"neonatal-meningitis",regimen:"Ampicillin 75 mg/kg IV q6h + Cefotaxime 50 mg/kg IV q6h (or Gentamicin)",notes:"Covers GBS (S. agalactiae), E. coli (including K1 capsule), and Listeria. Cefotaxime preferred over ceftriaxone in neonates (ceftriaxone causes biliary sludging and displaces bilirubin from albumin → kernicterus risk). Cefotaxime is the only cephalosporin approved for neonatal meningitis in many guidelines. Gentamicin alternative for E. coli synergy if cefotaxime unavailable."}]},{line:"Pathogen-Directed Therapy (After CSF Culture/Gram Stain)",options:[{drug:"pneumococcal-meningitis",regimen:"Ceftriaxone 2g IV q12h × 10-14 days (if MIC <1) ± vancomycin if MIC ≥1",notes:"S. pneumoniae (gram-positive diplococci): most common adult meningitis. CONTINUE dexamethasone for full 4 days. If ceftriaxone MIC <0.06: can use penicillin G 4 million units IV q4h. If MIC 0.1-1.0: ceftriaxone alone. If MIC ≥2: ceftriaxone + vancomycin (maintain both). Duration: 10-14 days."},{drug:"meningococcal-meningitis",regimen:"Ceftriaxone 2g IV q12h × 7 days (or Penicillin G if susceptible)",notes:"N. meningitidis (gram-negative diplococci): PUBLIC HEALTH EMERGENCY — requires immediate health department notification and close contact chemoprophylaxis (rifampin, ciprofloxacin, or ceftriaxone). Dexamethasone: uncertain benefit for meningococcal meningitis — continue if started empirically but the evidence is less clear than for pneumococcal. Duration: 7 days."},{drug:"listeria-meningitis",regimen:"Ampicillin 2g IV q4h × 21 days ± Gentamicin (first 7 days for synergy)",notes:"Listeria monocytogenes (gram-positive rods): CEPHALOSPORINS DO NOT COVER LISTERIA. This is why ampicillin is added empirically in patients >50 or immunocompromised. TMP-SMX is the alternative for penicillin-allergic patients (the ONLY reliable alternative). Meropenem has some activity but is not well-studied. Duration: ≥21 days (longer than other meningitis — Listeria has high relapse rate with shorter courses). STOP dexamethasone if Listeria confirmed — dexamethasone may worsen Listeria outcomes (impairs cell-mediated immunity needed for intracellular pathogen clearance)."}]}],organismSpecific:[{organism:"S. pneumoniae",preferred:"Ceftriaxone 2g IV q12h (if MIC <1) + dexamethasone × 4 days",alternative:"Meropenem 2g IV q8h if severe cephalosporin allergy",notes:"Most common and deadliest adult meningitis pathogen (20-30% mortality). Mortality significantly reduced by adjunctive dexamethasone (de Gans trial). Check ceftriaxone MIC — if ≥1, keep vancomycin on board. Penicillin resistance via PBP alterations does NOT preclude ceftriaxone use unless ceftriaxone-specific MIC is also elevated. Duration: 10-14 days."},{organism:"N. meningitidis",preferred:"Ceftriaxone 2g IV q12h × 7 days",alternative:"Penicillin G 4 million units IV q4h (if susceptible)",notes:"Excellent prognosis with treatment (~10% mortality). POST-EXPOSURE PROPHYLAXIS for close contacts is MANDATORY: rifampin 600mg PO BID × 2 days, ciprofloxacin 500mg PO × 1 dose, or ceftriaxone 250mg IM × 1 dose. Healthcare workers with close contact (intubation, mouth-to-mouth) also need prophylaxis."},{organism:"L. monocytogenes",preferred:"Ampicillin 2g IV q4h ± gentamicin synergy × ≥21 days",alternative:"TMP-SMX 5 mg/kg IV q6h (the ONLY reliable alternative for penicillin allergy)",notes:"Intracellular pathogen — requires cell-mediated immunity for clearance. Cephalosporins, carbapenems, and fluoroquinolones are NOT reliable. STOP dexamethasone if Listeria confirmed. Rhombencephalitis (brainstem involvement) is a classic Listeria presentation."},{organism:"H. influenzae (rare in vaccinated populations)",preferred:"Ceftriaxone 2g IV q12h × 7 days",alternative:"Meropenem, chloramphenicol",notes:"Rare since Hib vaccine introduction. Still occurs in unvaccinated or under-vaccinated. Non-typeable H. influenzae can cause meningitis in elderly/immunocompromised. Duration: 7 days."}],pearls:["ANTIBIOTICS FIRST — EVERYTHING ELSE SECOND: Do NOT wait for CT, LP, or any other test if bacterial meningitis is suspected. Every hour of delay increases mortality by 3-7%. Draw blood cultures, then start vancomycin + ceftriaxone + dexamethasone IMMEDIATELY. LP can happen after.","DEXAMETHASONE TIMING IS CRITICAL: Must be given BEFORE or WITH the first antibiotic dose. If you've already given antibiotics hours ago, starting dexamethasone now provides no proven benefit. In practice: hang dexamethasone in the IV line, then immediately start antibiotics. STOP dexamethasone if Listeria is confirmed — it impairs the cell-mediated immunity needed to clear this intracellular pathogen.","CT BEFORE LP: MOST PATIENTS DON'T NEED IT: The fear of herniation from LP drives unnecessary CT scans that delay antibiotics. IDSA criteria for CT before LP: immunocompromised, history of CNS disease, new-onset seizure (<1 week), papilledema, altered consciousness, focal neurologic deficit. If NONE of these → proceed directly to LP without CT.","MENINGOCOCCAL PROPHYLAXIS IS A PUBLIC HEALTH OBLIGATION: Close contacts (household members, kissing contacts, daycare, military barracks) need prophylaxis within 24h. Options: rifampin 600mg BID × 2 days, ciprofloxacin 500mg × 1 dose (easiest), or ceftriaxone 250mg IM × 1 (preferred in pregnancy). Healthcare workers only need prophylaxis if direct exposure to respiratory secretions.","LISTERIA GAPS IN CEPHALOSPORINS: Listeria monocytogenes is intrinsically resistant to all cephalosporins. If you omit ampicillin in a patient >50 who has Listeria meningitis, ceftriaxone + vancomycin will NOT cover it. This is a potentially fatal omission. Always add ampicillin for patients >50, immunocompromised, pregnant, or alcoholic."]},{id:"healthcare-cns",name:"Healthcare-Associated Meningitis/Ventriculitis",definition:"CNS infection occurring after neurosurgical procedures, penetrating head trauma, or related to CNS devices (VP shunts, external ventricular drains, intrathecal pumps). Organisms differ substantially from community-acquired meningitis: Staphylococci (including MRSA and CoNS), aerobic gram-negatives (Pseudomonas, Acinetobacter, Enterobacterales), and Cutibacterium acnes predominate. Treatment often requires intraventricular antibiotic administration.",clinicalPresentation:"Post-neurosurgical: fever, headache, altered consciousness, meningismus, new neurologic deficits, or wound infection (erythema/drainage at surgical site). VP shunt infection: fever, shunt malfunction (headache, nausea, vomiting, altered consciousness), abdominal signs (peritonitis if distal shunt infection). EVD-associated ventriculitis: fever, change in CSF parameters (increasing WBC, decreasing glucose), altered consciousness. Challenge: post-operative inflammation and blood in CSF can mimic infection — clinical correlation essential.",diagnostics:"CSF analysis: bacterial meningitis pattern (elevated WBC, elevated protein, decreased glucose) but often less dramatic than community-acquired. CSF culture is gold standard — but contamination risk is higher with hardware. CSF lactate >4 mmol/L suggests infection (helpful to distinguish from post-operative inflammation). Serial CSF sampling: trending WBC and glucose can differentiate infection from chemical/post-operative meningitis. Device-associated: culture the device/CSF simultaneously. CT head: hydrocephalus, abscess, hardware malposition.",empiricTherapy:[{line:"Empiric — Post-Neurosurgical/Post-Trauma",options:[{drug:"vancomycin-cefepime-meningitis",regimen:"Vancomycin 15-20 mg/kg IV q8-12h + Cefepime 2g IV q8h (or Meropenem 2g IV q8h)",notes:"Covers MRSA + Pseudomonas + Enterobacterales + Staphylococci. Vancomycin for MRSA/CoNS. Cefepime or meropenem for gram-negatives including Pseudomonas. MENINGITIS DOSING: higher than standard — vancomycin target trough 15-20 (or AUC equivalent for CNS penetration), cefepime 2g q8h, meropenem 2g q8h. Note for meropenem: use STANDARD infusion (not extended) for meningitis — need high peak levels for CSF penetration."}]},{line:"Intraventricular Antibiotics (Adjunctive for Refractory Cases)",options:[{drug:"intrathecal-vanc",regimen:"Intraventricular vancomycin 10-20mg/day (via EVD or Ommaya reservoir)",notes:"For healthcare-associated ventriculitis/meningitis not responding to systemic antibiotics alone. Intraventricular route achieves CSF concentrations far exceeding what systemic dosing can achieve. IDSA 2017 recommends considering intraventricular antibiotics for gram-positive infections not responding to systemic therapy within 48-72h."},{drug:"intrathecal-gent",regimen:"Intraventricular gentamicin 4-8mg/day (via EVD or Ommaya reservoir)",notes:"For gram-negative ventriculitis — aminoglycosides achieve poor CSF penetration systemically but excellent concentrations intraventricularly. Alternative: polymyxin B or colistin intraventricularly for MDR gram-negatives (Acinetobacter, CRE). Coordinate dosing with EVD drainage — clamp drain for 15-60 min after instillation."}]},{line:"Device Management",options:[{drug:"device-removal",regimen:"Remove or externalize infected device whenever possible",notes:"VP shunt infection: removal + external drainage + antibiotics is the gold standard (cure rate >90% vs. 30-40% with antibiotics alone and shunt retention). EVD infection: replace the drain (exchange to contralateral side) + systemic ± intraventricular antibiotics. Treat until CSF is sterile for 48-72h and clinical improvement, then consider re-internalization."}]}],organismSpecific:[{organism:"CoNS (S. epidermidis — most common VP shunt pathogen)",preferred:"Vancomycin IV ± intraventricular vancomycin + device removal",alternative:"Linezolid (excellent CSF penetration)",notes:"Indolent biofilm infection on shunt tubing. Device removal is essential for cure in most cases. Rifampin can be added for biofilm activity if device is retained (similar principle to PJI)."},{organism:"S. aureus (MSSA/MRSA)",preferred:"Nafcillin (MSSA — better CSF penetration than cefazolin) or vancomycin (MRSA)",alternative:"TMP-SMX IV (good CSF penetration for MRSA)",notes:"More aggressive than CoNS. Often presents acutely with wound infection/dehiscence. Device removal strongly recommended."},{organism:"Gram-negatives (Pseudomonas, Acinetobacter, Enterobacterales)",preferred:"Cefepime or meropenem IV ± intraventricular aminoglycoside",alternative:"For MDR: intraventricular colistin/polymyxin B",notes:"Increasingly common in ICU settings. MDR gram-negative ventriculitis is one of the most challenging infections to treat. Intraventricular antibiotics are often required. Cefiderocol has emerging CNS penetration data. Consult ID."}],pearls:["DEVICE REMOVAL IS PARAMOUNT: Trying to sterilize a VP shunt with antibiotics alone has ~30-40% cure rate. Removing the device + antibiotics achieves >90%. Always involve neurosurgery early for device management decisions.","MEROPENEM DOSING FOR MENINGITIS: Use 2g IV q8h via STANDARD infusion (30-minute bolus) — NOT extended infusion. For meningitis, you need high PEAK concentrations to drive drug across the BBB. Extended infusion optimizes time above MIC (good for systemic infections) but produces lower peaks (bad for CNS penetration).","CSF LACTATE HELPS DISTINGUISH INFECTION FROM POST-OP INFLAMMATION: Post-neurosurgical CSF often has elevated WBC and protein from surgical trauma/blood. CSF lactate >4 mmol/L has good specificity for bacterial infection and can help guide antibiotic decisions in ambiguous cases.","NAFCILLIN FOR MSSA CNS INFECTIONS: Cefazolin has poor CNS penetration even with inflamed meninges. For MSSA meningitis or brain abscess, use nafcillin or oxacillin (adequate CSF levels with inflamed meninges). This is one of the few remaining indications where nafcillin is preferred over cefazolin."]},{id:"brain-abscess",name:"Brain Abscess",definition:"Focal suppurative infection of the brain parenchyma, progressing from cerebritis (early, ill-defined) to a well-encapsulated abscess. The source determines the likely pathogens: dental/sinus origin → Streptococci (especially S. anginosus group) + anaerobes; otogenic → Pseudomonas + anaerobes + Proteus; hematogenous → S. aureus + Streptococci; post-traumatic/surgical → Staphylococci + gram-negatives. In immunocompromised patients, consider Toxoplasma, Nocardia, Aspergillus, and Mycobacteria.",clinicalPresentation:"Classic triad: headache + fever + focal neurologic deficit — present in <50% (similar to endocarditis, the full triad is often absent). Headache is the most common symptom (70-90%), often progressive. Fever in only 50%. Focal deficits depend on location: frontal (personality changes, hemiparesis), temporal (aphasia if dominant hemisphere, visual field deficits), cerebellar (ataxia, nystagmus — otogenic source). Seizures in 25-50%. Papilledema from mass effect. Rupture into ventricles: sudden catastrophic deterioration with meningitis (high mortality).",diagnostics:"MRI with gadolinium = GOLD STANDARD: ring-enhancing lesion with central restricted diffusion on DWI (distinguishes abscess from tumor — abscesses show restricted diffusion, tumors typically do not). CT with contrast: ring-enhancing lesion, often with surrounding edema. CT is less sensitive than MRI, especially for early cerebritis and posterior fossa lesions. ASPIRATION/BIOPSY: stereotactic aspiration for diagnosis (culture + Gram stain) AND therapy (decompression). Obtain before antibiotics if possible, but do NOT delay antibiotics if patient is deteriorating. Blood cultures: positive in 10-30% (higher in hematogenous abscesses). Source investigation: dental exam, sinus CT, echocardiography (endocarditis source), chest imaging (lung abscess, AVM).",durationGuidance:{standard:"4–8 weeks total (6–8 weeks IV for surgical cases)",opatNote:"OPAT for IV antibiotics after surgical drainage feasible in stable patients"},empiricTherapy:[{line:"Empiric — Unknown Source or Dental/Sinus Origin",options:[{drug:"ceftriaxone-metro-abscess",regimen:"Ceftriaxone 2g IV q12h + Metronidazole 500mg IV q8h ± Vancomycin",notes:"Covers Streptococci (especially S. anginosus/milleri group — THE classic abscess-forming organism) + anaerobes + gram-negatives. Add vancomycin if: post-surgical, post-traumatic, IDU, or MRSA risk. Metronidazole provides excellent CNS penetration (40-100% of serum levels) and covers anaerobes that ceftriaxone misses. Duration: 4-8 weeks total (longer for larger abscesses or incomplete drainage).",evidence:"A-I",evidenceSource:"IDSA 2004"}]},{line:"Empiric — Post-Neurosurgical/Post-Traumatic",options:[{drug:"vanc-cefepime-metro",regimen:"Vancomycin IV + Cefepime 2g IV q8h + Metronidazole 500mg IV q8h",notes:"Covers MRSA + Pseudomonas + anaerobes + Enterobacterales. Post-surgical and post-traumatic abscesses have a different microbiologic profile (Staphylococci, gram-negatives) than community-acquired (Streptococci, anaerobes). Meropenem 2g IV q8h can substitute for cefepime + metronidazole (covers both gram-negatives and anaerobes) — but standard infusion for CNS penetration."}]},{line:"Surgical Management",options:[{drug:"surgical-abscess",regimen:"Stereotactic aspiration (preferred) or craniotomy with excision",notes:"ASPIRATION indications: abscess >2.5cm, accessible location, diagnostic uncertainty, mass effect. Most abscesses are managed with aspiration + antibiotics. May need repeat aspiration if abscess re-accumulates. EXCISION: reserved for multiloculated abscesses, posterior fossa (risk of brainstem compression), failed aspiration, traumatic abscess with foreign material. MEDICAL MANAGEMENT ALONE (no surgery): considered for small abscesses (<2.5cm), multiple small abscesses, early cerebritis stage, deep/eloquent location, and when patient is a poor surgical candidate."}]},{line:"Duration & Monitoring",options:[{drug:"duration-abscess",regimen:"4-8 weeks of IV/oral antibiotics with serial imaging",notes:"Total duration depends on: size (larger = longer), drainage adequacy, organism, and clinical/radiographic response. Oral step-down is reasonable after 2-4 weeks of IV if clinical improvement and abscess shrinking on imaging. OVIVA principles apply — high-dose oral agents with good CNS penetration (metronidazole, fluoroquinolones, TMP-SMX, linezolid). Serial MRI q2-4 weeks to monitor response. Abscess capsule may persist for months on imaging even after cure — follow size trend, not complete resolution."}]}],organismSpecific:[{organism:"Streptococcus anginosus/milleri group",preferred:"Ceftriaxone 2g IV q12h or penicillin G 4MU IV q4h",alternative:"Meropenem 2g IV q8h",notes:"THE classic brain abscess organism. S. anginosus, S. intermedius, and S. constellatus have unique propensity for abscess formation anywhere in the body (brain, liver, lung). Usually from dental/sinus contiguous spread. Typically penicillin-susceptible. Excellent prognosis with appropriate therapy + drainage."},{organism:"Anaerobes (Bacteroides, Fusobacterium, Prevotella)",preferred:"Metronidazole 500mg IV q8h (excellent CNS penetration)",alternative:"Meropenem",notes:"Often mixed with Streptococci in dental/sinus-source abscesses. Metronidazole is the drug of choice for the anaerobic component — 40-100% CSF/serum ratio, one of the best BBB-penetrating antibiotics available."},{organism:"S. aureus (hematogenous or post-surgical)",preferred:"Nafcillin 2g IV q4h (MSSA) or vancomycin IV (MRSA)",alternative:"Linezolid or TMP-SMX for MRSA (good CNS penetration)",notes:"Hematogenous S. aureus brain abscess: always evaluate for endocarditis (TEE). IMPORTANT: use nafcillin (NOT cefazolin) for MSSA brain abscess — cefazolin has poor CNS penetration."},{organism:"Toxoplasma gondii (HIV/AIDS, CD4 <100)",preferred:"Pyrimethamine + sulfadiazine + leucovorin × 6+ weeks",alternative:"TMP-SMX (high-dose) if sulfadiazine unavailable",notes:"Most common cause of brain abscess in AIDS patients. Multiple ring-enhancing lesions + positive Toxoplasma IgG + CD4 <100 = empiric treatment without biopsy. Improvement expected within 10-14 days — if no response, biopsy to rule out CNS lymphoma. After treatment: lifelong secondary prophylaxis until immune reconstitution on ART."},{organism:"Nocardia (transplant, chronic steroids)",preferred:"TMP-SMX (high-dose) ± imipenem or amikacin for severe disease",alternative:"Linezolid (good activity and CNS penetration)",notes:"Think Nocardia in any immunocompromised patient with brain + lung lesions (Nocardia disseminates from pulmonary source). Gram stain shows beaded, branching, weakly acid-fast positive gram-positive rods. Treatment duration: months to years depending on immune status."}],pearls:["DWI ON MRI: THE KEY TO DISTINGUISHING ABSCESS FROM TUMOR: Restricted diffusion (bright on DWI, dark on ADC) within a ring-enhancing lesion strongly suggests abscess over tumor. Tumors typically show facilitated diffusion centrally. This MRI finding is the single most useful radiologic tool for diagnosis.","METRONIDAZOLE IS YOUR BEST FRIEND FOR BRAIN ABSCESS: 40-100% CNS penetration is exceptional among antibiotics. Always include metronidazole in empiric brain abscess regimens (unless pure Staphylococcal from hematogenous source). It covers the anaerobic component that other agents miss.","S. ANGINOSUS GROUP = THINK ABSCESS: If the microbiology lab calls with S. anginosus, S. intermedius, or S. constellatus from blood cultures, immediately think about occult abscess formation — brain, liver, lung, or intra-abdominal. These organisms have a unique propensity for suppurative, walled-off infections.","DEXAMETHASONE FOR EDEMA, NOT INFECTION: Unlike meningitis, adjunctive corticosteroids for brain abscess are reserved for significant EDEMA and MASS EFFECT only — steroids may reduce antibiotic penetration into the abscess cavity and impair immune response. Use dexamethasone for herniation risk, then taper quickly.","SEIZURE PROPHYLAXIS: Brain abscess carries high seizure risk (25-50%). Most experts recommend anticonvulsant prophylaxis (levetiracetam preferred — no CYP interactions) for the acute phase, then reassess at 3-6 months. Avoid phenytoin if possible (CYP interactions with multiple antibiotics, especially metronidazole)."]}],drugMonographs:[{id:"ampicillin",name:"Ampicillin",brandNames:"Principen (discontinued), generic",drugClass:"Aminopenicillin",mechanismOfAction:"Binds PBPs inhibiting cell wall synthesis. Bactericidal, time-dependent killing. Extended spectrum compared to penicillin G — covers some gram-negative organisms (E. coli, H. influenzae — non-beta-lactamase producing, Proteus mirabilis) in addition to gram-positives. CRITICAL CNS ROLE: drug of choice for Listeria monocytogenes (which is inherently resistant to all cephalosporins).",spectrum:"Gram-positive: Streptococci (excellent), Enterococcus faecalis (drug of choice — intrinsic activity unlike most cephalosporins), Listeria monocytogenes (drug of choice). Gram-negative: E. coli and Proteus mirabilis (if non-beta-lactamase producing — but resistance is high), H. influenzae (non-beta-lactamase producing). GAPS: MRSA, beta-lactamase producing organisms (most E. coli, H. influenzae now resistant), Pseudomonas, Klebsiella (inherent resistance), anaerobes (poor for B. fragilis).",dosing:{meningitis_listeria:"2g IV q4h (meningitis dosing — higher than standard)",enterococcal_ie:"2g IV q4h + ceftriaxone or gentamicin",standard:"1-2g IV q4-6h",gu_prophylaxis:"2g IV (GBS prophylaxis in labor)"},renalAdjustment:"CrCl 10-30: extend interval to q6-8h. CrCl <10: q12h. Hemodialysis: dose after HD.",hepaticAdjustment:"No adjustment needed — renally eliminated.",adverseEffects:{common:"Rash (5-10% — especially in EBV mononucleosis patients: 70-100% get maculopapular rash, NOT true allergy), diarrhea, nausea",serious:"Hypersensitivity/anaphylaxis (cross-reactivity with penicillin — same drug class), C. difficile colitis, seizures (high-dose IV, especially with renal impairment), interstitial nephritis",rare:"Hemolytic anemia, severe cutaneous reactions (SJS/TEN)"},drugInteractions:["Allopurinol — increased incidence of rash (mechanism unclear). Monitor but not a contraindication.","Warfarin — may increase INR via disruption of gut flora vitamin K synthesis.","Methotrexate — decreased renal clearance of methotrexate. Monitor for methotrexate toxicity."],monitoring:"Renal function (especially for meningitis dosing). Signs of allergic reaction. Seizure monitoring with high-dose IV therapy. CBC for prolonged courses.",pregnancyLactation:"Pregnancy Category B. Widely used in pregnancy — standard for GBS prophylaxis in labor, UTI treatment, and Listeria coverage in meningitis. Excreted in breast milk in low concentrations. Compatible with breastfeeding.",pharmacistPearls:["LISTERIA COVERAGE = AMPICILLIN: No cephalosporin covers Listeria. If Listeria meningitis is in the differential (age >50, immunocompromised, pregnant, alcoholic), ampicillin MUST be included in the empiric regimen. Omitting it can be fatal.","EBV RASH IS NOT AN ALLERGY: The classic teaching — 70-100% of patients with EBV mononucleosis develop a maculopapular rash when given ampicillin/amoxicillin. This is NOT an IgE-mediated allergy and does NOT predict future penicillin allergy. Do NOT document this as a penicillin allergy. This incorrect allergy documentation deprives patients of beta-lactams for the rest of their lives.","ENTEROCOCCAL IE: AMPICILLIN IS THE BACKBONE: For E. faecalis endocarditis, ampicillin + ceftriaxone (double beta-lactam synergy) is now PREFERRED over ampicillin + gentamicin (avoids aminoglycoside toxicity). Ampicillin's inherent Enterococcal activity makes it irreplaceable in this regimen."]},{id:"meropenem",name:"Meropenem",brandNames:"Merrem",drugClass:"Carbapenem antibiotic",mechanismOfAction:"Binds PBPs (primarily PBP-2 and PBP-3) inhibiting cell wall synthesis. Bactericidal, time-dependent killing. Carbapenems are the broadest-spectrum beta-lactams — stable against most beta-lactamases including ESBLs and AmpC. UNIQUE to meropenem: lower seizure risk than imipenem (does not antagonize GABA receptors), making it preferred for CNS infections.",spectrum:"The broadest-spectrum standard antibiotic. Gram-positive: Streptococci (excellent), MSSA (good), E. faecalis (moderate). Gram-negative: Enterobacterales including ESBL and AmpC producers (excellent), Pseudomonas (good), H. influenzae, Neisseria. Anaerobes: excellent (B. fragilis). GAPS: MRSA (no activity), E. faecium (no activity), Stenotrophomonas (intrinsically resistant), atypicals, CRE (resistant by definition — need novel BL-BLIs).",dosing:{standard:"1g IV q8h (extended infusion over 3h for non-CNS infections)",meningitis:"2g IV q8h — STANDARD INFUSION (30-min bolus, NOT extended — need high peaks for BBB penetration)",brain_abscess:"2g IV q8h (standard infusion)",febrile_neutropenia:"1g IV q8h (extended infusion)",esbl_bacteremia:"1g IV q8h (extended infusion preferred per MERINO trial)"},renalAdjustment:"CrCl 26-50: 1g q12h. CrCl 10-25: 500mg-1g q12h. CrCl <10: 500mg-1g q24h. HD: dose after HD. CRRT: 1g q8h (institution-dependent). For meningitis dosing: adjust proportionally but maintain q8h frequency.",hepaticAdjustment:"No adjustment — renally eliminated.",adverseEffects:{common:"Diarrhea, nausea, headache, rash",serious:"C. difficile colitis (broad-spectrum = high C. diff risk), seizures (LOWER risk than imipenem — preferred for CNS infections), hypersensitivity reactions",rare:"Severe cutaneous reactions, hepatotoxicity, neutropenia (prolonged courses), thrombocytopenia"},drugInteractions:["VALPROIC ACID — HARD STOP interaction. All carbapenems reduce VPA levels by 60-100% within 24h. Increasing VPA dose does NOT compensate. Switch to levetiracetam (or another AED) before starting meropenem. Resume VPA after meropenem is completed.","Probenecid — increases meropenem levels. Avoid combination."],monitoring:"Renal function (BMP q48-72h). Seizure monitoring (lower risk than imipenem but still possible in renal impairment, CNS disease, elderly). CBC for prolonged courses. C. diff surveillance. LFTs periodically.",pregnancyLactation:"Pregnancy Category B. Limited human data but no evidence of teratogenicity. Used in pregnancy for serious infections when benefits outweigh risks. Low concentrations in breast milk.",pharmacistPearls:["MENINGITIS DOSING = STANDARD INFUSION: This is counterintuitive for pharmacists trained in extended-infusion carbapenems. For meningitis and brain abscess, use 2g IV q8h via 30-minute BOLUS infusion. The BBB is penetrated based on PEAK concentration, not time above MIC. Extended infusion produces lower peaks — wrong strategy for CNS infections.","VALPROIC ACID: THE HARDEST OF HARD STOPS: Every carbapenem (meropenem, ertapenem, imipenem, doripenem) drastically reduces VPA levels. The interaction is NOT manageable by increasing the VPA dose. Switch the antiepileptic to levetiracetam for the duration of carbapenem therapy. This pharmacist intervention prevents breakthrough seizures.","SEIZURE ADVANTAGE OVER IMIPENEM: Meropenem does NOT antagonize GABA receptors (unlike imipenem). This makes it the preferred carbapenem for all CNS infections and for patients with seizure risk factors (renal impairment, elderly, CNS disease). If a patient seizes on imipenem, switching to meropenem may resolve the issue.","CARBAPENEM STEWARDSHIP: Meropenem is the broadest-spectrum standard antibiotic. Every unnecessary day selects for CRE. De-escalate aggressively when culture data allows. For brain abscess, oral step-down to metronidazole + a fluoroquinolone (or TMP-SMX) after initial IV response is reasonable per OVIVA principles."]}]},y={id:"fungal-infections",name:"Fungal Infections",icon:"🍄",category:"IDSA 2016 Candidiasis & Aspergillosis Guidelines · Antifungal Stewardship",overview:{definition:"Invasive fungal infections (IFIs) are life-threatening infections caused by opportunistic fungi, primarily Candida species (candidemia, invasive candidiasis) and Aspergillus species (invasive pulmonary aspergillosis, disseminated aspergillosis). Candidemia is the 4th most common bloodstream infection in US hospitals with crude mortality of 25–40%. Invasive aspergillosis carries mortality >50% in immunocompromised hosts. Early antifungal therapy and source control are critical determinants of outcome.",epidemiology:"Candidemia: Incidence 8–10 per 100,000 hospitalizations. C. albicans remains most common (~50%) but C. glabrata (15–25%), C. parapsilosis (10–15%), C. tropicalis (5–10%), and C. krusei (2–5%) are rising. C. auris is an emerging MDR threat with >90% fluconazole resistance and outbreaks in healthcare facilities. ICU patients account for ~40% of candidemia episodes. Invasive aspergillosis: Primarily affects severely immunocompromised patients — prolonged neutropenia (>10 days), allogeneic HSCT recipients, solid organ transplant recipients on high-dose immunosuppression, and patients receiving ≥0.3 mg/kg/day prednisone equivalent for ≥3 weeks. Incidence 5–25% in high-risk hematologic malignancy patients. A. fumigatus is the dominant species (>90% of invasive disease).",keyGuidelines:[{name:"IDSA 2016 Clinical Practice Guideline for the Management of Candidiasis",detail:"Comprehensive guideline covering candidemia, chronic disseminated candidiasis, and organ-specific invasive candidiasis. KEY CHANGES from prior: echinocandins elevated to first-line for candidemia in all patients (previously fluconazole preferred in non-critically ill). Fluconazole de-escalation encouraged once species and susceptibility confirmed. Strong recommendation for ophthalmologic exam in all candidemia patients. CVC removal recommended within 24–48 hours when feasible."},{name:"IDSA 2016 Practice Guidelines for Diagnosis and Management of Aspergillosis",detail:"Guidelines for invasive pulmonary aspergillosis, chronic pulmonary aspergillosis, and allergic forms. Voriconazole remains first-line for invasive aspergillosis. Isavuconazole non-inferior per SECURE trial. Combination therapy (voriconazole + echinocandin) may benefit some patients per subgroup analysis of the voriconazole-anidulafungin combination study. Therapeutic drug monitoring for voriconazole strongly recommended (trough 1–5.5 mcg/mL)."},{name:"ESCMID 2022 Guideline for the Diagnosis and Management of Candida Diseases",detail:"European guideline incorporating newer data on echinocandin resistance, C. auris management, biofilm-related infections, and step-down strategies. Affirms echinocandin first-line. Adds guidance on rezafungin (new long-acting echinocandin) and ibrexafungerp. Emphasizes antifungal stewardship and de-escalation."}],landmarkTrials:[{name:"Reboli et al., NEJM 2007 — Anidulafungin vs Fluconazole for Candidemia",detail:"Landmark RCT (ROCKER study) establishing echinocandin superiority over fluconazole for candidemia. Anidulafungin had higher global response rate (75.6% vs 60.2%, p=0.01) at end of IV therapy. This trial, combined with similar micafungin and caspofungin data, was the primary evidence driving echinocandins to first-line status in the 2016 IDSA guidelines. Mortality trended lower with anidulafungin but did not reach statistical significance."},{name:"Herbrecht et al., NEJM 2002 — Voriconazole vs Amphotericin B for Invasive Aspergillosis",detail:"Pivotal RCT establishing voriconazole as first-line for invasive aspergillosis. Voriconazole had significantly better response rates (52.8% vs 31.6%) and survival (70.8% vs 57.9% at 12 weeks) compared to amphotericin B deoxycholate. Also demonstrated better tolerability. This trial fundamentally changed aspergillosis treatment from amphotericin B to voriconazole as standard of care."},{name:"Maertens et al., Lancet 2016 — SECURE Trial: Isavuconazole for Invasive Aspergillosis/Mucormycosis",detail:"Pivotal non-inferiority trial comparing isavuconazole to voriconazole for primary treatment of invasive aspergillosis. Isavuconazole was non-inferior (overall mortality 18.6% vs 20.2%). KEY ADVANTAGES of isavuconazole: no QTc prolongation (actually shortens QTc), no hepatotoxicity signal, no visual disturbances, IV formulation without cyclodextrin (safe in renal impairment), and predictable pharmacokinetics allowing less frequent TDM."},{name:"Marr et al., Ann Intern Med 2015 — Voriconazole + Anidulafungin Combination vs Voriconazole Monotherapy",detail:"RCT examining combination antifungal therapy for invasive aspergillosis. Primary endpoint (6-week mortality) showed a trend favoring combination (19.3% vs 27.5%, p=0.087) that did not reach significance. POST-HOC subgroup analysis: patients with galactomannan-proven IA had significant mortality benefit with combination (15.7% vs 27.3%). This trial is the basis for considering combination therapy in select high-risk patients, though not universally recommended."}],riskFactors:"Candidemia: Central venous catheters (strongest modifiable risk factor), broad-spectrum antibiotics (especially anti-anaerobic agents), ICU stay >3 days, TPN, recent abdominal surgery (especially GI anastomotic leak), neutropenia, immunosuppression (steroids, chemotherapy), renal failure requiring dialysis, Candida colonization at multiple sites (colonization index), prior fluconazole exposure (selects for resistant species). Invasive aspergillosis: Prolonged neutropenia (>10 days ANC <500), allogeneic HSCT (especially with GVHD requiring steroids), solid organ transplant (lung transplant highest risk), hematologic malignancy (AML induction, MDS), chronic high-dose corticosteroids (≥20mg prednisone ≥3 weeks), inherited or acquired immunodeficiency (CGD, AIDS with CD4 <100), novel immunotherapies (ibrutinib, ruxolitinib — impair macrophage/neutrophil function)."},subcategories:[{id:"candidemia",name:"Candidemia & Invasive Candidiasis",definition:"Candidemia is defined as ≥1 blood culture positive for Candida species. Invasive candidiasis encompasses candidemia plus deep-seated organ involvement (endocarditis, osteomyelitis, endophthalmitis, hepatosplenic candidiasis, CNS candidiasis). Candidemia requires treatment even if catheter-related and patient appears clinically stable — untreated candidemia has mortality >40%. All patients with candidemia must have an ophthalmologic exam (endophthalmitis in 10–15%) and repeat blood cultures every 24–48 hours until clearance.",clinicalPresentation:"Candidemia often presents identically to bacterial sepsis: fever, tachycardia, hypotension, leukocytosis. NO pathognomonic features distinguish it from bacteremia clinically. Key distinguishing features that should raise suspicion: persistent fever despite broad-spectrum antibacterials in an ICU patient with risk factors, new-onset endophthalmitis symptoms (eye pain, floaters, visual changes), hepatosplenic candidiasis presenting as persistent fever and elevated ALP in a recovering neutropenic patient, skin lesions (erythematous papules/nodules with central pallor) in disseminated disease. Candiduria is common in ICU patients and usually represents colonization — treat only if symptomatic or high-risk (neutropenic, renal transplant, undergoing urologic surgery).",diagnostics:"Blood cultures: GOLD STANDARD but sensitivity only 50–75% for candidemia. Time to positivity usually 2–5 days (slower than most bacteria). Species identification and susceptibility testing are ESSENTIAL — guide de-escalation and predict resistance. β-D-glucan (BDG): Serum marker for invasive fungal infection, sensitivity 65–85% for candidiasis. Useful as adjunct but many false positives (hemodialysis, albumin infusion, surgical gauze, bacteremia with Streptococcus). NOT specific for Candida — elevated in aspergillosis, PJP, and other fungi. T2Candida panel: PCR-based rapid diagnostic (3–5 hours), detects C. albicans/tropicalis, C. parapsilosis, C. glabrata/krusei directly from blood. Sensitivity 91%, specificity 98%. Major advantage: faster species identification allowing earlier targeted therapy. Repeat blood cultures: Obtain every 24–48 hours until clearance. Duration of therapy is counted from the FIRST NEGATIVE blood culture, not from treatment initiation. Echocardiography: Consider TTE in all candidemia patients, TEE if prosthetic valves, prolonged candidemia, or clinical suspicion of endocarditis.",empiricTherapy:[{line:"Preferred — First-Line Empiric",options:[{drug:"micafungin",regimen:"Micafungin 100 mg IV once daily",notes:"IDSA 2016 first-line for candidemia regardless of severity or species. Echinocandins preferred over fluconazole because: (1) broader spectrum covering C. glabrata and C. krusei, (2) fungicidal vs. fungistatic, (3) better outcomes in RCTs (Reboli 2007). Continue until species identification and susceptibility allow de-escalation."},{drug:"caspofungin",regimen:"Caspofungin 70 mg IV load × 1, then 50 mg IV daily",notes:"Alternative echinocandin. Equivalent efficacy to micafungin. Loading dose required on day 1. More drug interactions (cyclosporine — hepatotoxicity risk, rifampin — reduces caspofungin levels). Dose adjust for hepatic impairment (Child-Pugh B: 35 mg daily after load)."},{drug:"anidulafungin",regimen:"Anidulafungin 200 mg IV load × 1, then 100 mg IV daily",notes:"Third echinocandin option. Best evidence from the Reboli NEJM 2007 trial. No hepatic or renal dose adjustment needed. Non-enzymatic degradation (no CYP metabolism) means fewest drug interactions of the echinocandins. Preferred when drug interactions are a concern."}]},{line:"Alternative — De-escalation / Fluconazole-Susceptible",options:[{drug:"fluconazole",regimen:"Fluconazole 800 mg (12 mg/kg) IV/PO load × 1, then 400 mg (6 mg/kg) IV/PO daily",notes:"STEP-DOWN therapy once: (1) patient is clinically stable, (2) Candida species confirmed susceptible (MIC ≤2 mcg/mL), (3) blood cultures are clearing, (4) no metastatic complications. Loading dose is critical and frequently omitted. IV-to-PO switch: bioavailability is ~90%, so same dose PO. NOT appropriate for C. glabrata (dose-dependent susceptibility), C. krusei (intrinsically resistant), or critically ill patients on vasopressors."}]},{line:"Reserve — Amphotericin B",options:[{drug:"amphotericin-b",regimen:"Amphotericin B liposomal (AmBisome) 3–5 mg/kg IV daily",notes:"Reserve for: (1) echinocandin-resistant Candida (rare but increasing), (2) CNS candidiasis (echinocandins do not penetrate CNS), (3) endocarditis (in combination), (4) C. auris with pan-echinocandin resistance. Always use LIPID formulation — conventional amphotericin B deoxycholate has unacceptable nephrotoxicity. Monitor: daily BMP (creatinine, potassium, magnesium), CBC."}]},{line:"Duration & Source Control",options:[{drug:"",regimen:"Duration: 14 days from FIRST NEGATIVE blood culture + resolution of symptoms/signs",notes:"CVC removal: Strongly recommended within 24–48 hours when feasible. CVC retention is associated with higher mortality and prolonged candidemia. If CVC cannot be removed (e.g., limited access), ensure echinocandin therapy and consider locking solutions for biofilm. Ophthalmologic exam: Within 1 week of diagnosis in non-neutropenic patients, within 1 week of neutrophil recovery in neutropenic patients. If endophthalmitis present: extend treatment to ≥4–6 weeks and consider intravitreal amphotericin B."}]}],organismSpecific:[{organism:"C. albicans (fluconazole-susceptible)",preferred:"Echinocandin → de-escalate to fluconazole 400 mg PO daily once stable + cultures clearing",alternative:"Fluconazole 800 mg load, then 400 mg daily (if non-critically ill, stable, no prior azole exposure)",notes:"Most common species (~50%). Predictably fluconazole-susceptible. De-escalation from echinocandin to fluconazole is recommended once susceptibility confirmed and patient stable. Fluconazole has excellent bioavailability allowing early IV-to-PO conversion."},{organism:"C. glabrata",preferred:"Echinocandin (micafungin 100 mg IV daily or caspofungin or anidulafungin) for full duration",alternative:"If susceptible: high-dose fluconazole 800 mg daily (MIC ≤32 AND confirmed susceptible-dose dependent). Voriconazole 200 mg BID if fluconazole-resistant but voriconazole-susceptible.",notes:"Second most common species (15–25%). Intrinsically fluconazole dose-dependent susceptible (MIC 8–32) and increasingly resistant (10–15% now resistant). ALWAYS obtain susceptibility testing. FKS mutations confer echinocandin resistance (1–3% overall, but 8–12% in patients with prior echinocandin exposure). If echinocandin-resistant: amphotericin B."},{organism:"C. krusei",preferred:"Echinocandin for full duration",alternative:"Voriconazole 200 mg IV/PO BID (load 400 mg BID × 2 doses)",notes:"INTRINSICALLY fluconazole-resistant (chromosomal resistance mechanism). Echinocandin preferred because of consistent susceptibility. Voriconazole is an alternative with good in vitro activity. Never use fluconazole — will fail regardless of dose."},{organism:"C. parapsilosis",preferred:"Fluconazole 800 mg load, then 400 mg daily",alternative:"Echinocandin if fluconazole-resistant (rare)",notes:"UNIQUE among Candida: echinocandins have higher MICs against C. parapsilosis (intrinsic FKS polymorphism). Clinical significance debated — most experts still start echinocandin empirically then de-escalate to fluconazole once species identified. Strong association with CVC biofilm — CVC removal especially important. Also associated with TPN and neonates."},{organism:"C. auris",preferred:"Echinocandin at standard dosing (micafungin 100 mg IV daily preferred)",alternative:"If echinocandin-resistant: amphotericin B liposomal 3–5 mg/kg IV daily. If pan-resistant: combination therapy (consider amphotericin B + flucytosine, or investigate newer agents)",notes:"EMERGING MDR THREAT. >90% fluconazole-resistant, 30–40% amphotericin B-resistant, ~5% echinocandin-resistant. Requires STRICT contact precautions and infection control measures. Often misidentified by conventional methods — requires MALDI-TOF or molecular identification. CDC urgent threat pathogen. Susceptibility testing mandatory for all isolates. Healthcare facility outbreaks documented — persistent environmental contamination."}],pearls:["The single most impactful intervention in candidemia is EARLY CVC REMOVAL — within 24–48 hours. Delayed removal independently predicts mortality. Fight for this in your interdisciplinary rounds.","Duration counting: 14 days starts from the FIRST NEGATIVE blood culture, NOT from antifungal initiation. If it takes 5 days for cultures to clear, total treatment will be ~19 days minimum. This is the most common duration error.","Loading doses for fluconazole (800 mg × 1) are frequently omitted but pharmacokinetically essential. Fluconazole has a long half-life (~30 hours) and without a loading dose takes 5–7 days to reach steady state. In candidemia, you cannot afford to wait.","Don't forget the eye exam. Candida endophthalmitis occurs in 10–15% of candidemia patients and changes the treatment duration (4–6 weeks minimum) and may require intravitreal therapy. It is a pharmacist's role to remind the team.","C. parapsilosis + echinocandin: Clinical data shows echinocandins still work clinically despite higher MICs, but many ID experts prefer fluconazole step-down once C. parapsilosis is confirmed. Know your institution's approach.","Echinocandin resistance in C. glabrata (FKS mutations) is more common than you think in patients with prior echinocandin exposure. If a patient has had echinocandins in the past 90 days and grows C. glabrata, request FKS mutation testing or at minimum interpret MICs carefully.","β-D-glucan can be falsely elevated by: hemodialysis filters (especially cellulose membranes), IV immunoglobulin, albumin, amoxicillin-clavulanate, Bactrim (TMP-SMX), piperacillin-tazobactam, surgical gauze, and bacteremia (especially Streptococcus). Know these before over-interpreting a positive result.","C. auris infection control: If your institution identifies C. auris, this is an infection control emergency. Requires contact precautions, dedicated equipment, daily chlorhexidine bathing, and enhanced environmental cleaning. Pharmacy role: ensure appropriate empiric therapy and notify infection prevention immediately."]},{id:"invasive-aspergillosis",name:"Invasive Pulmonary Aspergillosis",definition:"Invasive pulmonary aspergillosis (IPA) is a life-threatening mold infection predominantly caused by A. fumigatus in immunocompromised hosts. Characterized by tissue invasion with angioinvasion leading to hemorrhagic infarction, cavitation, and potential dissemination. Mortality 30–60% even with treatment, depending on immune status and time to diagnosis. A 'proven' diagnosis requires histopathology; 'probable' diagnosis per EORTC/MSG criteria combines host factors + clinical/radiologic features + mycologic evidence (galactomannan, culture, PCR).",clinicalPresentation:"Classic presentation in neutropenic patient: persistent fever despite broad-spectrum antibacterials for ≥96 hours, pleuritic chest pain, hemoptysis, dyspnea. CT chest findings: early — nodules with 'halo sign' (ground-glass opacity surrounding nodule, representing hemorrhagic infarction); late — 'air crescent sign' (crescent of air within cavity, seen during neutrophil recovery as necrotic tissue separates). Non-neutropenic immunocompromised patients (steroids, SOT recipients): presentation may be subacute with non-specific infiltrates, consolidation, or ground-glass opacities that mimic bacterial pneumonia or organizing pneumonia. High index of suspicion is critical. Tracheobronchial aspergillosis: ulcerative or pseudomembranous tracheobronchitis, particularly in lung transplant recipients — may be missed if bronchoscopy not performed.",diagnostics:"CT chest: HIGH-RESOLUTION CT is the imaging modality of choice. Obtain early (don't wait for conventional CXR progression). Halo sign in neutropenic patient is highly suggestive. Galactomannan (GM): Serum sensitivity 70–80% in hematologic malignancy/HSCT, but only 20–30% in SOT recipients (lower fungal burden). BAL galactomannan has higher sensitivity (80–90%). Use cutoff ≥1.0 ODI for BAL (more specific than ≥0.5). FALSE POSITIVES: piperacillin-tazobactam (less common with newer formulations but still occurs), cross-reactivity with other molds, mucositis/GI disruption, and dietary sources (Plasmalyte, some pasta products). β-D-glucan: Elevated in aspergillosis but non-specific. Aspergillus PCR: Increasingly validated, EORTC/MSG now includes as mycologic criterion. Can be performed on blood or BAL. Culture: Low sensitivity from blood (<1% positive), BAL culture positive in 30–60%. Positive respiratory culture in high-risk host should NOT be dismissed as colonization. Biopsy: Gold standard for proven diagnosis but often impractical due to thrombocytopenia and coagulopathy in the target population.",empiricTherapy:[{line:"Preferred — First-Line",options:[{drug:"voriconazole",regimen:"Voriconazole 6 mg/kg IV q12h × 2 doses (load), then 4 mg/kg IV q12h; PO: 200 mg q12h (≥40 kg)",notes:"IDSA 2016 first-line based on Herbrecht 2002 NEJM trial. THERAPEUTIC DRUG MONITORING IS MANDATORY — target trough 1.0–5.5 mcg/mL. Subtherapeutic levels (<1.0) associated with treatment failure, supratherapeutic (>5.5) associated with hepatotoxicity and neurotoxicity. Highly variable pharmacokinetics (CYP2C19 polymorphisms). Obtain first trough on day 5 of therapy. IV formulation contains sulfobutyl ether β-cyclodextrin (SBECD) — accumulates in CrCl <50, switch to PO if possible (PO bioavailability >96%)."}]},{line:"Alternative — First-Line",options:[{drug:"isavuconazole",regimen:"Isavuconazonium sulfate 372 mg (= 200 mg isavuconazole) IV/PO q8h × 6 doses (48 hr loading), then 372 mg IV/PO daily",notes:"Non-inferior to voriconazole per SECURE trial (Maertens 2016). KEY ADVANTAGES: (1) no QTc prolongation (SHORTENS QT — avoid if baseline short QT syndrome), (2) IV formulation WITHOUT cyclodextrin (safe in renal impairment), (3) fewer visual disturbances, (4) less hepatotoxicity, (5) more predictable PKs (TDM less critical but still recommended in some populations). ALSO active against Mucorales (unlike voriconazole) — useful when diagnosis uncertain between aspergillosis and mucormycosis. Becoming many centers' preferred first-line over voriconazole."}]},{line:"Alternative — Echinocandin Combination",options:[{drug:"micafungin",regimen:"Voriconazole (standard dosing) + Micafungin 150 mg IV daily OR Caspofungin 70/50 mg IV daily",notes:"Combination therapy based on Marr 2015 trial: trend toward mortality benefit (19.3% vs 27.5%) that was not statistically significant overall, but subgroup with galactomannan-positive IA showed significant benefit. Consider combination in: (1) proven/probable IA with high fungal burden, (2) breakthrough on azole prophylaxis, (3) hematologic malignancy with prolonged neutropenia. NOT universally recommended — discuss with ID."}]},{line:"Salvage Therapy",options:[{drug:"amphotericin-b",regimen:"Amphotericin B liposomal (AmBisome) 3–5 mg/kg IV daily",notes:"Salvage for voriconazole/isavuconazole failure or intolerance. Higher doses (5 mg/kg) used in severe disease or CNS involvement. Also first-line if mucormycosis suspected (voriconazole has NO Mucorales activity). Monitor nephrotoxicity, electrolytes daily."},{drug:"caspofungin",regimen:"Caspofungin 70 mg IV load, then 50 mg IV daily",notes:"Echinocandin monotherapy is salvage only — NOT adequate as primary therapy for aspergillosis (fungistatic, not fungicidal against Aspergillus). May be used in combination (see above) or when azoles and amphotericin B are not tolerable."}]},{line:"Duration & Monitoring",options:[{drug:"",regimen:"Minimum 6–12 weeks; continue until resolution of immunosuppression + radiographic improvement",notes:"Duration highly individualized. Minimum 6 weeks even with good response. In HSCT patients or those with ongoing immunosuppression, treatment often continues for months. Serial GM and CT chest q2–4 weeks to monitor response. IMMUNE RECONSTITUTION: neutrophil recovery is the most important prognostic factor. G-CSF and reduction of immunosuppression should be aggressively pursued. Secondary prophylaxis: after completing treatment, consider maintenance voriconazole/isavuconazole during subsequent immunosuppressive cycles."}]}],organismSpecific:[{organism:"Aspergillus fumigatus (susceptible)",preferred:"Voriconazole (with TDM) or isavuconazole",alternative:"Liposomal amphotericin B 3–5 mg/kg/day",notes:">90% of invasive aspergillosis. Generally susceptible to azoles, though azole-resistant A. fumigatus (TR34/L98H and TR46/Y121F/T289A mutations) is an emerging concern globally. Resistance prevalence: <2% US, 5–30% Netherlands/UK (environmental azole use in agriculture). If azole-resistant A. fumigatus suspected (treatment failure, known local resistance): liposomal amphotericin B or voriconazole + echinocandin combination."},{organism:"Aspergillus terreus",preferred:"Voriconazole or isavuconazole",alternative:"Echinocandin (caspofungin/micafungin) or isavuconazole + echinocandin",notes:"INTRINSICALLY amphotericin B-resistant (higher MICs, poor clinical outcomes with amphotericin B). Voriconazole or isavuconazole preferred. If species identification shows A. terreus, do NOT use amphotericin B as salvage — switch to azole-based therapy."},{organism:"Aspergillus niger",preferred:"Voriconazole or isavuconazole",alternative:"Liposomal amphotericin B",notes:"Generally susceptible to azoles and amphotericin B. More commonly causes otomycosis and aspergilloma than invasive disease. When invasive, treat similarly to A. fumigatus. May have slightly higher amphotericin B MICs — check susceptibility."}],pearls:["Voriconazole TDM is NOT optional — it is MANDATORY. The therapeutic window is narrow (1.0–5.5 mcg/mL) and interpatient variability is enormous due to CYP2C19 polymorphisms. Poor metabolizers: toxic levels on standard doses. Ultra-rapid metabolizers: subtherapeutic. Get the first trough on day 5, then weekly until stable.","Isavuconazole is increasingly becoming the preferred first-line at many centers over voriconazole: no cyclodextrin in IV formulation (renal-safe), no visual disturbances, less hepatotoxicity, activity against Mucorales, and more predictable PKs. Know your institution's preferred agent.","Piperacillin-tazobactam can cause false-positive galactomannan — this has been a known issue for years. While newer manufacturing processes have reduced it, it still occurs. If GM turns positive in a patient on pip-tazo, interpret cautiously and consider confirmatory BAL GM.","The 'halo sign' on CT chest has a narrow diagnostic window — it's most visible in the first 5–7 days of infection and disappears as neutrophils recover. Early CT imaging is critical. Don't wait for CXR to show something before ordering CT.","Voriconazole + fluoroquinolone QTc risk: Voriconazole inhibits CYP3A4 and can increase fluoroquinolone levels. Monitor QTc closely if co-administered. Also: voriconazole + tacrolimus requires tacrolimus dose reduction by 50–66% and close TDM.","Isavuconazole SHORTENS the QTc interval. This is actually a contraindication if the patient has familial short QT syndrome (very rare). But it makes it the preferred azole in patients already on QT-prolonging medications.","Breakthrough aspergillosis on azole prophylaxis: If a patient develops aspergillosis while on posaconazole or voriconazole prophylaxis, check drug levels first (compliance/absorption issue?) then consider switching to a different class (amphotericin B) or combination therapy. Don't simply increase the dose of the same azole."]},{id:"antifungal-stewardship",name:"Antifungal Stewardship & De-escalation",definition:"Antifungal stewardship encompasses systematic interventions to optimize antifungal use, improve patient outcomes, reduce resistance, and control costs. Key domains: (1) empiric-to-targeted de-escalation, (2) IV-to-PO conversion, (3) duration optimization, (4) prophylaxis appropriateness review, (5) TDM-guided dosing. Antifungals account for significant pharmacy spend — echinocandins cost $100–400/day, liposomal amphotericin B $500–1500/day. Stewardship interventions can safely reduce costs by 20–40%.",clinicalPresentation:"N/A — this section covers stewardship principles, not a clinical syndrome.",diagnostics:"N/A — see candidemia and aspergillosis sections for diagnostic approaches.",empiricTherapy:[{line:"Stewardship — Echinocandin-to-Fluconazole De-escalation",options:[{drug:"fluconazole",regimen:"Switch echinocandin → fluconazole 400 mg PO daily",notes:"CRITERIA FOR SAFE DE-ESCALATION: (1) Candida species confirmed susceptible to fluconazole (C. albicans, C. tropicalis, C. parapsilosis with MIC ≤2), (2) patient clinically improving (afebrile, hemodynamically stable, off vasopressors), (3) blood cultures clearing, (4) no metastatic complications (endophthalmitis, endocarditis, osteomyelitis), (5) able to tolerate oral medications. Average time to de-escalation: 5–7 days. This is the single highest-impact antifungal stewardship intervention."}]},{line:"Stewardship — IV-to-PO Azole Conversion",options:[{drug:"voriconazole",regimen:"Switch voriconazole IV → voriconazole 200 mg PO q12h",notes:"Voriconazole oral bioavailability >96% — IV offers no pharmacokinetic advantage over PO. Switch as soon as patient can tolerate oral medications. IMPORTANT: Avoid taking with high-fat meals (reduces absorption by 34%). Also: PO tablets may actually give MORE predictable levels than IV in patients with renal impairment (avoids cyclodextrin accumulation)."},{drug:"fluconazole",regimen:"Switch fluconazole IV → same dose PO",notes:"Fluconazole oral bioavailability ~90%. Same dose IV and PO. One of the easiest IV-to-PO conversions in all of infectious disease. No food restrictions. Pharmacy should proactively recommend this conversion."}]},{line:"Stewardship — Prophylaxis Review",options:[{drug:"fluconazole",regimen:"Review appropriateness of antifungal prophylaxis",notes:"Appropriate prophylaxis: (1) Fluconazole 400 mg daily for allogeneic HSCT (engraftment through day +75), (2) Posaconazole 300 mg daily for AML/MDS induction chemotherapy with expected neutropenia >7 days, (3) Fluconazole 400 mg daily for high-risk liver transplant recipients. INAPPROPRIATE (common): continuing prophylaxis beyond risk period, prophylaxis in ICU patients without neutropenia (routine fluconazole in surgical ICU not recommended by guidelines), prophylaxis based solely on positive BDG without clinical correlation."}]},{line:"Stewardship — TDM Optimization",options:[{drug:"voriconazole",regimen:"Voriconazole trough target: 1.0–5.5 mcg/mL",notes:"TDM schedule: Day 5 (steady state), then weekly until therapeutic and stable, then with dose changes, interacting drug changes, or clinical failure. Subtherapeutic (<1.0): Increase dose by 50%. Supratherapeutic (>5.5): Hold 1 dose, reduce by 50%, recheck in 3–5 days. CYP2C19 genotyping: Consider in patients with extreme levels despite standard dosing (PM vs UM phenotype). Posaconazole: Trough >1.0 mcg/mL for prophylaxis, >1.0–1.5 for treatment. Itraconazole: Trough >0.5 for prophylaxis, >1.0 for treatment."}]}],organismSpecific:[],pearls:["Echinocandin-to-fluconazole de-escalation in candidemia saves $200–350/day and is safe when criteria are met. This should be on every pharmacist's radar for every patient with candidemia. Set a calendar reminder for day 5 to reassess.","The 'antifungal timeout' at 72–96 hours: For patients started on empiric antifungals (especially in ICU), reassess at 72–96 hours with culture data, BDG result, and clinical response. If cultures negative, BDG negative, and alternative diagnosis identified → STOP antifungals. Many empiric courses can be safely discontinued.","Fluconazole drug interactions to flag proactively: (1) Warfarin — increases INR (inhibits CYP2C9), (2) Tacrolimus/cyclosporine — increases levels (CYP3A4), (3) Phenytoin — bidirectional interaction, (4) Statins — increased myopathy risk, (5) Sulfonylureas — hypoglycemia. These are high-frequency, clinically significant interactions that pharmacists should intercept.","Cost awareness: Micafungin ~$100–150/day, Caspofungin ~$150–300/day, Anidulafungin ~$150–250/day, Liposomal amphotericin B ~$500–1500/day, Fluconazole ~$5–15/day PO. Every day of unnecessary echinocandin or amphotericin B matters. Be the steward.","Azole resistance surveillance: If your institution sends susceptibility testing to a reference lab and turnaround is >5 days, work with microbiology to explore faster options (MALDI-TOF with susceptibility panels, molecular testing). Delayed susceptibility data delays de-escalation."]},{id:"cryptococcal-meningitis",name:"Cryptococcal Meningitis",definition:"CNS infection caused by Cryptococcus neoformans (most common, associated with HIV/AIDS) or C. gattii (can infect immunocompetent hosts, associated with Pacific Northwest). The most common cause of meningitis in HIV-positive patients globally. Classically presents as subacute meningitis with elevated intracranial pressure. Treatment follows a 3-phase approach: induction → consolidation → maintenance.",clinicalPresentation:"Subacute onset (1–2 weeks) of headache, fever, altered mental status, nausea/vomiting. Neck stiffness may be ABSENT (unlike bacterial meningitis). Elevated intracranial pressure is COMMON and is the primary cause of morbidity and mortality — presents with severe headache, visual changes (papilledema, CN VI palsy), vomiting, altered consciousness. Disseminated disease may involve skin (umbilicated papules resembling molluscum — classic in AIDS), lungs (nodules, consolidation), and rarely other organs. In HIV patients: typically CD4 <100 cells/μL. In non-HIV immunocompromised: transplant recipients on calcineurin inhibitors, chronic corticosteroids.",diagnostics:"Lumbar puncture: ESSENTIAL — and serves dual diagnostic and therapeutic purpose (pressure management). CSF findings: elevated opening pressure (>20 cmH2O in >70% of patients, often >30–40), lymphocytic pleocytosis (may be minimal in severely immunosuppressed), low glucose, elevated protein. India ink: Classic test, sensitivity 60–80% in HIV patients (lower in non-HIV). Being replaced by antigen testing. CSF cryptococcal antigen (CrAg): Sensitivity >95%, specificity >95%. Lateral flow assay (LFA) preferred — rapid (10 min), inexpensive, highly accurate. GOLD STANDARD diagnostic test. CSF culture: Positive in >95% of HIV-associated cases. Also quantitative culture useful for monitoring clearance (early fungicidal activity). Serum CrAg: Sensitivity >95% for meningitis. Useful as screening test in HIV patients with CD4 <100 before symptoms develop (screen-and-treat strategy). Repeat LPs: Therapeutic LPs to manage elevated ICP — remove CSF to normalize pressure (<20 cmH2O or 50% reduction if very high). Daily LPs may be needed in severe cases.",empiricTherapy:[{line:"Preferred — Induction (HIV-associated)",options:[{drug:"amphotericin-b",regimen:"Amphotericin B liposomal 3–4 mg/kg IV daily + Flucytosine 25 mg/kg PO q6h × 2 weeks",notes:"ACTHUNG trial + AMBITION trial evidence. Amphotericin B + flucytosine is the MOST EFFECTIVE induction regimen, achieving the fastest CSF sterilization (~1 week). Flucytosine is critical — do NOT omit. If flucytosine unavailable, amphotericin B + fluconazole 800 mg daily is an alternative but inferior induction. Monitor flucytosine levels (target peak 30–80 mcg/mL), CBC (myelosuppression), and renal function daily."}]},{line:"Alternative — Induction (Resource-Limited)",options:[{drug:"fluconazole",regimen:"Fluconazole 1200 mg PO daily + Flucytosine 25 mg/kg PO q6h × 2 weeks",notes:"ACTHUNG trial: High-dose fluconazole + flucytosine is the best oral-only induction option. Faster CSF sterilization than fluconazole monotherapy. Important in resource-limited settings without amphotericin B access. Also validated: single high-dose amphotericin B liposomal (10 mg/kg × 1) + flucytosine + fluconazole (AMBITION trial) as simplified induction."}]},{line:"Consolidation (Week 2–10)",options:[{drug:"fluconazole",regimen:"Fluconazole 400–800 mg PO daily × 8 weeks",notes:"Begin after successful 2-week induction (clinical improvement, CSF sterilizing). Higher dose (800 mg) preferred in HIV patients. Continue with ART optimization — but timing of ART initiation is critical (see pearls)."}]},{line:"Maintenance (Week 10+)",options:[{drug:"fluconazole",regimen:"Fluconazole 200 mg PO daily — continue until CD4 >100 × 1 year + undetectable viral load",notes:"Secondary prophylaxis. Can discontinue once immune reconstitution achieved: CD4 >100 for ≥1 year on ART with suppressed viral load. If CD4 drops below 100 again, restart maintenance fluconazole."}]},{line:"Adjunctive — ICP Management",options:[{drug:"",regimen:"Therapeutic lumbar punctures: daily or as needed to maintain opening pressure <20 cmH2O",notes:"ELEVATED ICP IS THE PRIMARY KILLER in cryptococcal meningitis. Aggressive pressure management with serial LPs is essential. Remove enough CSF to achieve OP <20 or 50% reduction. VP shunt or lumbar drain for refractory elevated ICP. DO NOT use corticosteroids for ICP management in cryptococcal meningitis — the Day et al. NEJM 2014 trial showed dexamethasone INCREASED mortality."}]}],organismSpecific:[{organism:"C. neoformans (HIV-associated)",preferred:"Liposomal amphotericin B + flucytosine × 2 weeks → fluconazole 400–800 mg × 8 weeks → fluconazole 200 mg maintenance",alternative:"Fluconazole 1200 mg + flucytosine × 2 weeks if amphotericin B not available",notes:"Most common. Serum CrAg screening for all HIV patients with CD4 <100 is cost-effective and reduces mortality. TIMING OF ART: Delay ART initiation to 4–6 weeks AFTER starting antifungal induction. Earlier ART increases risk of immune reconstitution inflammatory syndrome (IRIS) and death."},{organism:"C. gattii",preferred:"Same induction as C. neoformans. Longer consolidation may be needed (consider 6–18 months total)",alternative:"Surgery for large cryptococcomas",notes:"Can infect immunocompetent hosts. Associated with Pacific Northwest (BC, Oregon, Washington). Forms larger cryptococcomas (mass lesions) more frequently than C. neoformans. May require neurosurgical intervention. Generally more resistant to fluconazole — consider higher doses and longer treatment."}],pearls:["THE MOST IMPORTANT INTERVENTION in cryptococcal meningitis is aggressive ICP management with serial LPs. Elevated ICP causes most early deaths. Do NOT rely on mannitol or steroids — they don't work here. Steroids INCREASE mortality (Day et al., NEJM 2014).","ART timing in HIV-associated cryptococcal meningitis: DO NOT start ART immediately. The COAT trial (Boulware et al., NEJM 2014) showed that early ART (within 1–2 weeks) DOUBLED mortality compared to delayed ART (4–6 weeks). The risk of cryptococcal IRIS is real and lethal.","Flucytosine is the most commonly omitted drug in cryptococcal meningitis treatment, yet it is the MOST IMPACTFUL addition to amphotericin B. It accelerates CSF sterilization from ~14 days to ~7 days. If your institution doesn't stock it, request it. Dose adjust for renal impairment. Monitor levels if available (peak 30–80 mcg/mL).","Screen-and-treat strategy: In HIV-positive patients newly diagnosed with CD4 <100, check serum CrAg. If positive but asymptomatic, perform LP to rule out subclinical meningitis. If LP negative, pre-emptive fluconazole 800 mg × 2 weeks then 400 mg × 8 weeks prevents progression to meningitis.","The AMBITION trial (Jarvis et al., NEJM 2022) validated a simplified induction: single high-dose liposomal amphotericin B (10 mg/kg × 1 dose) + flucytosine + fluconazole. Non-inferior to standard 7-day amphotericin B + flucytosine. This is a game-changer for resource-limited settings and simplifies logistics enormously."]}],drugMonographs:[{id:"fluconazole",name:"Fluconazole",brandNames:"Diflucan",drugClass:"Triazole antifungal",mechanismOfAction:"Inhibits fungal cytochrome P450 enzyme 14-α-demethylase (CYP51/lanosterol demethylase), blocking conversion of lanosterol to ergosterol. Ergosterol depletion disrupts fungal cell membrane integrity, increasing permeability and inhibiting cell growth. FUNGISTATIC against Candida (does not kill, inhibits growth). Selective for fungal CYP51 over human CYP enzymes, but still has significant CYP450 inhibition in humans (CYP2C9, CYP2C19, CYP3A4).",spectrum:"Candida albicans (excellent), C. tropicalis (good), C. parapsilosis (excellent — preferred agent), C. lusitaniae (good). LIMITED/RESISTANT: C. glabrata (dose-dependent susceptibility, 10–15% resistant), C. krusei (INTRINSICALLY RESISTANT — never use), C. auris (>90% resistant). NO activity against: Aspergillus spp., Mucorales, Scedosporium, Fusarium. Good CNS penetration (~70% of serum levels — useful for cryptococcal meningitis, NOT adequate for aspergillosis which requires voriconazole).",dosing:{candidemia:"Loading: 800 mg (12 mg/kg) IV/PO × 1, then 400 mg (6 mg/kg) IV/PO daily",mucosal_candidiasis:"Oropharyngeal: 200 mg × 1, then 100 mg daily × 7–14 days. Esophageal: 400 mg × 1, then 200–400 mg daily × 14–21 days",cryptococcal_consolidation:"400–800 mg PO daily × 8 weeks (after induction with amphotericin B)",cryptococcal_maintenance:"200 mg PO daily until CD4 >100 × 1 year + viral suppression",prophylaxis_HSCT:"400 mg PO daily from conditioning through day +75 (or until engraftment)",candiduria:"200–400 mg daily × 14 days (only if symptomatic or high-risk)"},renalAdjustment:"CrCl >50: No adjustment. CrCl ≤50 (not on dialysis): Reduce maintenance dose by 50% (loading dose remains full). Hemodialysis: 100% of dose after each session (fluconazole is significantly dialyzed, ~50% removed per session). CVVH/CVVHD: Standard dosing (200–400 mg daily) — dialysis clearance approximates normal GFR.",hepaticAdjustment:"Use with caution in hepatic impairment. No specific dose adjustment recommended, but monitor LFTs closely. Hepatotoxicity is rare but potentially fatal — idiosyncratic, not dose-dependent. Discontinue if ALT >5× ULN or symptomatic hepatitis.",adverseEffects:{common:"Nausea (7–10%), headache (5%), abdominal pain (3%), diarrhea (3%), rash (2%). Generally well-tolerated — best tolerated of all systemic antifungals.",serious:"Hepatotoxicity (rare, <1%, but can be fatal — cholestatic or hepatocellular), QTc prolongation (dose-dependent, clinically significant at high doses ≥800 mg), Stevens-Johnson syndrome (very rare), alopecia (dose-dependent, reversible, seen with prolonged high-dose therapy).",rare:"Adrenal insufficiency (all azoles can suppress steroidogenesis, more common with ketoconazole), agranulocytosis, anaphylaxis."},drugInteractions:["WARFARIN (CYP2C9 inhibition): Increases INR significantly — reduce warfarin dose by 25–50% and monitor INR within 3–5 days. One of the most common clinically significant fluconazole interactions.","TACROLIMUS / CYCLOSPORINE (CYP3A4 inhibition): Increases calcineurin inhibitor levels. Monitor closely and reduce tacrolimus dose by ~50% when starting fluconazole.","PHENYTOIN (bidirectional CYP2C9): Fluconazole increases phenytoin levels AND phenytoin may reduce fluconazole efficacy. Monitor both levels.","STATINS (CYP3A4): Increased risk of rhabdomyolysis with simvastatin, lovastatin (contraindicated). Atorvastatin: use with caution, consider dose reduction.","SULFONYLUREAS (CYP2C9): Increased hypoglycemia risk with glipizide, glyburide. Monitor blood glucose and consider dose reduction.","OPIOIDS — Methadone (CYP3A4/2B6): Increases methadone levels, risk of QTc prolongation and respiratory depression. Fentanyl: increased levels possible.","RIFAMPIN: Potent CYP inducer reduces fluconazole levels by ~25%. Consider increasing fluconazole dose to 800 mg daily if co-administered."],monitoring:"Baseline: LFTs, BMP (creatinine for dose adjustment), ECG if using high doses (≥800 mg) or concomitant QTc-prolonging drugs. During therapy: LFTs weekly for first month, then monthly. BMP if renal function changing. Repeat blood cultures q24–48h for candidemia until clearance. Fluconazole TDM: NOT routinely required (predictable linear pharmacokinetics), but can be useful in obese patients (>120 kg), patients on RRT, or when drug interactions are complex.",pregnancyLactation:"Category D (1st trimester) / Category C (2nd–3rd trimester). HIGH-DOSE fluconazole (≥400 mg) in first trimester associated with craniofacial and skeletal malformations (fluconazole embryopathy). Single-dose 150 mg for vaginal candidiasis appears safe. AVOID chronic high-dose use in pregnancy. Excreted in breast milk at concentrations similar to plasma — AAP considers compatible with breastfeeding at lower doses but consider risk/benefit at higher doses.",pharmacistPearls:["LOADING DOSE IS ESSENTIAL: Fluconazole half-life is ~30 hours. Without a loading dose (800 mg for serious infection), it takes 5–7 days to reach steady state. In candidemia, this delay can be fatal. The loading dose is the single most commonly omitted step in fluconazole prescribing.","IV-to-PO conversion: Oral bioavailability ~90%. There is almost NEVER a pharmacokinetic reason to keep a patient on IV fluconazole if they can swallow. This is one of the easiest and most impactful IV-to-PO conversions you'll make. Same dose, same frequency.","Fluconazole does NOT cover Aspergillus — this seems obvious but the number of times empiric fluconazole is prescribed for suspected IPA in neutropenic patients is staggering. If you suspect aspergillosis, you need voriconazole, isavuconazole, or amphotericin B.","C. glabrata + fluconazole: The MIC breakpoint is ≤2 (susceptible), 4 (susceptible-dose dependent), ≥8 (resistant). 'Susceptible-dose dependent' means it MAY work at 800 mg/day but there's little clinical data supporting this. Most experts use echinocandin for C. glabrata and avoid fluconazole entirely. Know your institution's antibiogram.","Alopecia occurs with prolonged fluconazole use (>3 months) and is dose-dependent. Patients are often distressed — reassure them it's reversible after discontinuation. It's NOT a reason to stop medically necessary therapy, but they should be warned proactively."]},{id:"micafungin",name:"Micafungin",brandNames:"Mycamine",drugClass:"Echinocandin antifungal (lipopeptide)",mechanismOfAction:"Inhibits synthesis of β-(1,3)-D-glucan, an essential component of the fungal cell wall (not present in mammalian cells). This non-competitive inhibition of glucan synthase results in osmotic instability and cell lysis. FUNGICIDAL against Candida (kills, doesn't just inhibit). FUNGISTATIC against Aspergillus (inhibits hyphal tip growth). The unique mechanism of action means NO cross-resistance with azoles or amphotericin B.",spectrum:"EXCELLENT: Candida albicans, C. glabrata, C. tropicalis, C. krusei, C. dubliniensis. GOOD BUT HIGHER MICs: C. parapsilosis (intrinsic FKS polymorphism — MICs 0.5–2 vs. ≤0.06 for other species; clinical significance debated). Aspergillus spp. (fungistatic — NOT adequate as monotherapy, used in combination). NO ACTIVITY: Cryptococcus neoformans (no glucan synthase target), Mucorales (zygomycetes), Fusarium, Scedosporium, Trichosporon.",dosing:{candidemia:"100 mg IV once daily (no loading dose needed — steady state in ~4 days, but adequate levels achieved with first dose)",esophageal_candidiasis:"150 mg IV once daily",prophylaxis_HSCT:"50 mg IV once daily",aspergillosis_combination:"150 mg IV once daily (when used in combination with voriconazole for salvage/combination)"},renalAdjustment:"No dose adjustment required at any level of renal impairment including hemodialysis and CVVH. Micafungin is NOT dialyzable (high protein binding >99%, large molecular weight). This makes echinocandins the SIMPLEST antifungal to dose in renal impairment.",hepaticAdjustment:"Mild-moderate (Child-Pugh A/B): No dose adjustment. Severe (Child-Pugh C): Limited data — use with caution, no specific dose reduction recommended but monitor closely. Micafungin has been associated with hepatotoxicity (see adverse effects).",adverseEffects:{common:"Nausea (3%), vomiting (2%), diarrhea (2%), headache (2%), phlebitis at infusion site (2%), abnormal LFTs (3–5%). Generally VERY well-tolerated — the best safety profile of any systemic antifungal.",serious:"Hepatotoxicity (elevated ALT/AST, rare hepatocellular injury — FDA black box warning in Japan, not US), hemolytic anemia (rare), anaphylaxis (<1%), histamine-like infusion reactions.",rare:"Renal toxicity (uncommon, much less than amphotericin B), leukopenia, thrombocytopenia. Animal studies showed hepatocellular tumors at doses >therapeutic — no human signal to date, but this is why some guidelines limit prophylaxis duration."},drugInteractions:["MINIMAL drug interactions — major advantage over azoles. Echinocandins do not significantly interact with CYP450 enzymes.","SIROLIMUS: Micafungin may increase sirolimus exposure by ~20%. Monitor sirolimus levels when initiating or discontinuing micafungin.","NIFEDIPINE: Micafungin may increase nifedipine levels. Monitor for hypotension if co-administered.","ITRACONAZOLE: Micafungin may slightly increase itraconazole levels. Likely not clinically significant.","Note: Unlike caspofungin, micafungin does NOT have the hepatotoxicity interaction with cyclosporine. This makes micafungin preferred over caspofungin in transplant patients on calcineurin inhibitors."],monitoring:"Baseline: LFTs, CBC. During therapy: LFTs weekly (watch for hepatocellular pattern). CBC if prolonged therapy. Micafungin TDM: NOT routinely available or recommended — standard dosing is generally adequate. No renal monitoring needed for drug-related nephrotoxicity. For candidemia: repeat blood cultures every 24–48 hours until clearance.",pregnancyLactation:"Category C. Animal studies showed visceral abnormalities at high doses. Very limited human data. Use only if benefit outweighs risk. Consider amphotericin B (Category B) as the preferred antifungal in pregnancy for serious fungal infections. Unknown if excreted in breast milk.",pharmacistPearls:["Micafungin 100 mg IV daily for candidemia is the SIMPLEST antifungal to dose: no loading dose, no renal adjustment, no hepatic adjustment for mild-moderate disease, minimal drug interactions. This is why many institutions prefer it as the first-line echinocandin.","Echinocandins do NOT cover Cryptococcus — this is a critical distinction. If a patient has candidemia and you're using micafungin, that's correct. If they have cryptococcal meningitis, micafungin is useless. The cell wall target (β-glucan) is present in Candida and Aspergillus but NOT Cryptococcus.","C. parapsilosis + echinocandin: The higher MICs are real (0.5–2 vs. ≤0.06 for C. albicans), but clinical outcomes data are mixed. The IDSA 2016 guidelines still accept echinocandin for C. parapsilosis but recommend considering fluconazole step-down once species identified. Know your institution's practice pattern.","Micafungin vs. caspofungin in transplant patients: Micafungin is preferred because caspofungin + cyclosporine can cause hepatotoxicity. Micafungin doesn't have this interaction. This is a pharmacist-level nuance that many physicians don't know.","For candidemia, do NOT stop micafungin just because blood cultures are negative. The 14-day clock starts from the first negative culture. If it takes 5 days to clear, total therapy is at minimum 19 days. Premature discontinuation is a common error."]},{id:"voriconazole",name:"Voriconazole",brandNames:"Vfend",drugClass:"Triazole antifungal (second-generation)",mechanismOfAction:"Same mechanism as fluconazole (CYP51/14-α-demethylase inhibition) but with broader affinity for fungal CYP51 enzymes, including Aspergillus CYP51. This broader binding explains the extended spectrum compared to fluconazole. FUNGICIDAL against Aspergillus (unique among azoles). FUNGISTATIC against Candida. More potent CYP450 inhibitor in humans than fluconazole — more drug interactions.",spectrum:"EXCELLENT: Aspergillus spp. (A. fumigatus, A. flavus, A. niger — first-line), Candida spp. (all species including C. krusei and many C. glabrata), Scedosporium apiospermum, Fusarium spp. (variable). GOOD: Rare molds where other options limited. NO ACTIVITY: Mucorales (zygomycetes — Rhizopus, Mucor) — this is a CRITICAL gap. If mucormycosis is in the differential, use isavuconazole or amphotericin B instead. Cryptococcus: active in vitro but NOT first-line (fluconazole preferred for CNS penetration at standard doses).",dosing:{invasive_aspergillosis:"IV: 6 mg/kg q12h × 2 doses (load), then 4 mg/kg q12h. PO (≥40 kg): 400 mg q12h × 2 doses (load), then 200 mg q12h",candidemia:"Same dosing as aspergillosis (used less commonly, usually for fluconazole-resistant species)",esophageal_candidiasis:"200 mg PO q12h × 14–21 days"},renalAdjustment:"Oral: No renal adjustment needed (not renally cleared). IV: AVOID IV formulation if CrCl <50 mL/min — the SBECD (sulfobutyl ether β-cyclodextrin) vehicle accumulates and is nephrotoxic. Switch to PO (bioavailability >96%, so PO is pharmacokinetically equivalent). If IV is absolutely required in renal impairment: monitor SBECD levels if available, or accept the risk with close renal monitoring. Hemodialysis: Voriconazole is not significantly dialyzed, but SBECD is. If using IV on dialysis, administer after sessions. PO preferred.",hepaticAdjustment:"Mild-moderate (Child-Pugh A/B): Use standard loading dose, REDUCE maintenance by 50%. Severe (Child-Pugh C): Avoid if possible — extensive hepatic metabolism makes levels unpredictable. If used, reduce maintenance dose by 50% and monitor TDM closely. Voriconazole-associated hepatotoxicity is dose-dependent and correlated with trough >5.5 mcg/mL.",adverseEffects:{common:"Visual disturbances (30%! — photopsia, color changes, blurred vision; reversible, occur within 30 min of dosing, resolve in 30–60 min; due to retinal photoreceptor inhibition), hepatotoxicity (elevated LFTs in 10–15%), rash (6%), nausea (5%), headache.",serious:"Hepatotoxicity (including hepatic failure, correlated with trough >5.5), QTc prolongation (risk increases with supratherapeutic levels), periostitis/fluorosis (with prolonged use >6 months — bone pain, elevated fluoride), phototoxicity (severe sunburn risk — sunscreen + photoprotection mandatory), squamous cell carcinoma (associated with prolonged use >1 year, especially in transplant patients — dermatologic screening recommended).",rare:"Stevens-Johnson syndrome/TEN, pancreatitis, optic neuritis, hallucinations (trough >5.5)."},drugInteractions:["TACROLIMUS (CYP3A4): Voriconazole increases tacrolimus levels 2–3×. REDUCE tacrolimus dose by 50–66% and check levels within 3 days. This is the single most dangerous voriconazole interaction in transplant patients.","CYCLOSPORINE (CYP3A4): Increases levels ~1.7×. Reduce cyclosporine dose by 50% and monitor levels.","SIROLIMUS: CONTRAINDICATED — voriconazole increases sirolimus levels >10×. Must use alternative immunosuppressant or alternative antifungal.","PHENYTOIN / CARBAMAZEPINE: Potent CYP inducers dramatically reduce voriconazole levels. Avoid combination if possible. If necessary, increase voriconazole dose to 5 mg/kg IV q12h or 400 mg PO q12h and follow TDM closely.","RIFAMPIN / RIFABUTIN: Rifampin CONTRAINDICATED — reduces voriconazole levels by >95%. Rifabutin: reduce rifabutin dose, increase voriconazole dose, and monitor both levels.","WARFARIN (CYP2C9): Increases INR. More potent interaction than fluconazole. Monitor INR closely.","QTc-PROLONGING DRUGS: Additive risk. Avoid or closely monitor ECG with fluoroquinolones, ondansetron (high-dose), methadone, certain antipsychotics.","EFAVIRENZ: CONTRAINDICATED at standard doses — dramatic bidirectional interaction. If necessary, increase voriconazole to 400 mg q12h and reduce efavirenz to 300 mg daily (complex, TDM essential).","OPIOIDS — Methadone, oxycodone, fentanyl: Increased levels via CYP3A4 inhibition. Monitor for sedation/respiratory depression."],monitoring:"THERAPEUTIC DRUG MONITORING IS MANDATORY. Trough target: 1.0–5.5 mcg/mL. First trough: Day 5 of therapy (steady state reached by day 5–7). Frequency: Weekly until stable therapeutic range, then with dose changes, addition/removal of interacting drugs, or clinical failure/toxicity. LFTs: Baseline, then weekly for first month, then bimonthly. ECG: Baseline and periodically (QTc). Visual assessment: Document visual symptoms at each encounter. Dermatologic exam: Every 6 months if prolonged therapy (skin cancer screening). Fluoride level: If >6 months of therapy and bone pain.",pregnancyLactation:"Category D — TERATOGENIC. Animal studies show cleft palate, hydronephrosis, skeletal abnormalities at therapeutic doses. CONTRAINDICATED in pregnancy. Women of childbearing potential should use effective contraception during therapy and for 30 days after discontinuation. Unknown if excreted in breast milk — avoid during lactation.",pharmacistPearls:["Voriconazole TDM is the pharmacist's bread and butter in antifungal stewardship. The therapeutic window (1.0–5.5) is narrow and the interpatient variability is enormous. CYP2C19 poor metabolizers (~15–20% of Asian patients, ~3–5% of Caucasians) can have toxic levels on standard doses. Ultra-rapid metabolizers can be subtherapeutic. YOU are the TDM expert — own this.","Visual disturbances (photopsia) occur in ~30% of patients — they see bright spots, color changes, or halos around lights. This is NOT dangerous and is reversible. However, patients are often terrified. Counsel proactively: 'You may notice visual changes about 30 minutes after each dose — this is expected, temporary (resolves in ~1 hour), and not harmful to your eyes.'","IV-to-PO conversion: Voriconazole oral bioavailability is >96%. The IV formulation adds SBECD nephrotoxicity risk. Switch to PO as soon as the patient can swallow. This is one case where PO is actually SAFER than IV.","Voriconazole + sunlight = severe phototoxicity and long-term skin cancer risk. Every patient on voriconazole needs SPF 50+ sunscreen, protective clothing, and UV-blocking sunglasses. For transplant patients on chronic voriconazole, annual dermatologic screening is recommended. This is a pharmacist counseling point that is frequently missed.","The voriconazole-sirolimus interaction is CONTRAINDICATED — not 'use with caution,' CONTRAINDICATED. Sirolimus levels increase >10× with voriconazole. If a transplant patient needs voriconazole, the immunosuppression regimen must be converted from sirolimus to an alternative (usually tacrolimus with dose reduction). Coordinate this with the transplant team proactively.","No Mucorales coverage: If the differential includes mucormycosis (e.g., diabetic patient with rhinocerebral disease, post-transplant with lung lesions where aspergillosis vs. mucormycosis unclear), do NOT use voriconazole empirically. Use isavuconazole (covers both) or amphotericin B. Voriconazole may actually be a RISK FACTOR for breakthrough mucormycosis in prophylaxis settings."]},{id:"amphotericin-b",name:"Amphotericin B (Liposomal)",brandNames:"AmBisome",drugClass:"Polyene antifungal (lipid formulation)",mechanismOfAction:"Binds to ergosterol in the fungal cell membrane, creating pores that increase membrane permeability, causing leakage of intracellular contents and cell death. FUNGICIDAL — directly damages the cell membrane. Also has immunomodulatory effects (enhances macrophage and neutrophil function). The liposomal formulation encapsulates amphotericin B in true liposomes, which preferentially deliver drug to fungal cell membranes and RES tissues, reducing renal and infusion toxicity compared to conventional amphotericin B deoxycholate. ALWAYS USE LIPID FORMULATION — conventional amphotericin B deoxycholate is nephrotoxic and should be avoided except when lipid formulations are unavailable.",spectrum:"BROADEST SPECTRUM of any antifungal. Candida spp. (all, including C. auris — though some resistance emerging), Aspergillus spp. (except A. terreus — INTRINSICALLY RESISTANT), Cryptococcus neoformans (essential for induction), Mucorales/Zygomycetes (Rhizopus, Mucor, Lichtheimia — first-line), Histoplasma, Blastomyces, Coccidioides (endemic mycoses), Fusarium, Trichosporon (variable). RESISTANT: A. terreus, some C. lusitaniae isolates.",dosing:{candidemia:"3 mg/kg IV daily (reserve for echinocandin-intolerant or resistant Candida, CNS candidiasis)",invasive_aspergillosis:"3–5 mg/kg IV daily (salvage therapy; higher doses for severe/CNS disease)",cryptococcal_meningitis:"3–4 mg/kg IV daily × 2 weeks (+ flucytosine) for induction",mucormycosis:"5–10 mg/kg IV daily (HIGH DOSE — mucormycosis requires aggressive dosing)",empiric_febrile_neutropenia:"3 mg/kg IV daily (when fungal infection suspected but not documented)",endemic_mycoses:"3–5 mg/kg IV daily for severe histoplasmosis, blastomycosis, coccidioidomycosis",single_dose_crypto_induction:"10 mg/kg IV × 1 dose (AMBITION trial protocol, with flucytosine + fluconazole)"},renalAdjustment:"No formal dose adjustment, but nephrotoxicity is the primary dose-limiting toxicity even with lipid formulations. Monitor creatinine daily. If creatinine doubles or rises above 2.5 mg/dL: consider dose reduction, alternate-day dosing, or switching to an alternative antifungal if clinically feasible. Aggressive pre-hydration: 500 mL–1L NS before each infusion significantly reduces nephrotoxicity. Hemodialysis: Not significantly dialyzed — no supplemental dosing needed. The nephrotoxicity mechanism is direct tubular injury (not dependent on GFR).",hepaticAdjustment:"No dose adjustment required. Hepatotoxicity is uncommon with amphotericin B. Liposomal formulation may cause transient LFT elevations but rarely clinically significant.",adverseEffects:{common:"Nephrotoxicity (15–30% with liposomal, vs. 50–60% with conventional), hypokalemia (30–40% — renal potassium wasting), hypomagnesemia (25%), infusion-related reactions (fever, rigors, chills — 15–20%, less with liposomal, premedicate with acetaminophen ± diphenhydramine ± meperidine for rigors), anemia (normocytic, from suppressed EPO production, 10–15%).",serious:"Acute kidney injury (can be severe, may require RRT in prolonged courses), cardiac arrhythmias (from electrolyte disturbances — fatal hypokalemia/hypomagnesemia), anaphylaxis (rare, 0.1%), cardiac arrest (with rapid infusion — NEVER give as IV push).",rare:"Hearing loss (especially with concurrent aminoglycosides), thrombocytopenia, hepatotoxicity, leukoencephalopathy (extremely rare)."},drugInteractions:["NEPHROTOXIC AGENTS (aminoglycosides, cyclosporine, tacrolimus, IV contrast, NSAIDs, vancomycin): Additive nephrotoxicity. Avoid concurrent nephrotoxins when possible. If unavoidable, aggressive hydration and daily renal monitoring.","POTASSIUM-WASTING DIURETICS (furosemide, hydrochlorothiazide): Additive hypokalemia — can be severe and fatal. Monitor potassium at least daily, replace aggressively.","CORTICOSTEROIDS: Additive hypokalemia. Very common co-administration in transplant patients — monitor K+ closely.","DIGOXIN: Amphotericin B-induced hypokalemia potentiates digoxin toxicity. Monitor both potassium and digoxin levels.","FLUCYTOSINE: Amphotericin B nephrotoxicity can reduce flucytosine clearance, increasing flucytosine toxicity (myelosuppression). Monitor flucytosine levels (peak 30–80 mcg/mL) and CBC when co-administered.","AZOLES (fluconazole, voriconazole): Theoretical antagonism (azoles deplete ergosterol, amphotericin B requires ergosterol for binding). Clinical significance unclear and generally not a concern in practice."],monitoring:"DAILY: BMP (creatinine, potassium, magnesium, bicarbonate). Potassium and magnesium replacement is an almost daily requirement during amphotericin B therapy — prepare standing replacement protocols. LFTs: Baseline and weekly. CBC: Baseline and weekly (anemia develops over 2–4 weeks). PRE-HYDRATION: 500 mL–1L NS prior to each infusion — reduces nephrotoxicity. This is non-negotiable. PREMEDICATIONS: Acetaminophen 650 mg PO + diphenhydramine 25–50 mg IV ± meperidine 25–50 mg IV (for rigors) given 30 min before infusion. Infusion rate: Over 2 hours (1 hour if tolerated). NEVER give as IV push.",pregnancyLactation:"Category B — the PREFERRED antifungal in pregnancy for serious infections. Extensive human experience with no documented teratogenicity. Used as first-line for candidemia and cryptococcal meningitis in pregnant patients. Liposomal formulation preferred over conventional for reduced toxicity. Unknown if excreted in breast milk, but systemically absorbed amounts in infant likely minimal.",pharmacistPearls:["ALWAYS use the LIPID formulation (AmBisome = liposomal, Abelcet = lipid complex). NEVER conventional amphotericin B deoxycholate (Fungizone) unless lipid formulations are truly unavailable. The nephrotoxicity difference is dramatic: ~20% vs ~50%. Medication errors between formulations are reported — verify product at dispensing.","Pre-hydration with NS is the single most effective intervention to prevent nephrotoxicity. It should be a standing order, not optional. 500 mL–1L NS before each dose, every single time.","Potassium and magnesium wasting is EXPECTED and UNIVERSAL with prolonged amphotericin B therapy. Set up standing replacement protocols. Patients will need 40–80 mEq KCl and 2–4g MgSO4 supplementation daily during treatment. Check levels daily and replace proactively. Hypomagnesemia makes hypokalemia refractory — always replace Mg first.","Amphotericin B is the pregnancy antifungal — Category B with decades of human safety data. When a pregnant patient needs treatment for candidemia, cryptococcal meningitis, or any serious fungal infection, amphotericin B is the go-to. Don't hesitate.","For mucormycosis, dose HIGH: 5–10 mg/kg/day. Standard 3 mg/kg dosing used for candidemia and aspergillosis is INADEQUATE for mucormycosis. Combined with surgical debridement, high-dose amphotericin B is the backbone of mucormycosis treatment.","The AMBITION trial's single-dose protocol (10 mg/kg × 1) for cryptococcal meningitis induction is a paradigm shift. One dose of liposomal amphotericin B with oral flucytosine + fluconazole was non-inferior to 7-day amphotericin B. This simplifies logistics enormously, especially in resource-limited settings. Know this protocol."]}]},b={id:"advanced-agents",name:"Advanced & Resistant Pathogen Agents",icon:"🛡",category:"Infectious Disease",overview:{definition:"Antimicrobial agents used primarily for multidrug-resistant (MDR), extensively drug-resistant (XDR), and pan-drug-resistant (PDR) organisms. Includes aminoglycosides for once-daily extended-interval dosing, novel beta-lactam/beta-lactamase inhibitor combinations, polymyxins, oxazolidinones, antifungals with extended-spectrum activity, and liposomal amphotericin B. These agents represent the last lines of defense against the most resistant organisms and require careful stewardship.",epidemiology:"MDR Gram-negative infections cause >700,000 deaths annually worldwide. ESKAPE pathogens (Enterococcus, Staph aureus, Klebsiella, Acinetobacter, Pseudomonas, Enterobacter) drive increasing resistance. Novel beta-lactam/BLI combinations have transformed treatment options for CRE and MDR Pseudomonas since 2014. Polymyxin use declining due to nephrotoxicity but remains critical for pan-resistant Acinetobacter.",keyGuidelines:[{name:"IDSA 2022 Guidance on Resistant Gram-Negative Infections",detail:"First IDSA guidance document specifically addressing CRE, ESBL-E, difficult-to-treat Pseudomonas, and carbapenem-resistant Acinetobacter baumannii. Defines preferred and alternative regimens for each resistance phenotype."},{name:"ASHP/IDSA/SIDP 2020 Vancomycin Monitoring Consensus",detail:"Updated guidance recommending AUC-guided monitoring over trough-only. Target AUC/MIC 400–600 mg·h/L for S. aureus infections."},{name:"IDSA 2016 Candidiasis Guidelines",detail:"Echinocandin first-line for candidemia. Defines step-down criteria to fluconazole. Liposomal AmB for azole-refractory or CNS disease."},{name:"ESCMID/ECMM/ERS 2022 Aspergillosis Guidelines",detail:"Voriconazole/isavuconazole first-line for IA. Posaconazole primary prophylaxis in AML/HSCT."}],landmarkTrials:[{name:"ASPECT-cUTI / ASPECT-NP Trials (Ceftolozane-Tazobactam)",detail:"Ceftolozane-tazobactam non-inferior to levofloxacin (cUTI) and meropenem (nosocomial pneumonia) including MDR Pseudomonas aeruginosa. Key enabling trials for FDA approval."},{name:"RESTORE-IMI 1 & 2 (Imipenem-Cilastatin-Relebactam)",detail:"IMI-R superior to colistin + imipenem for CRE and MDR Pseudomonas in both cUTI/IAI and HAP/VAP. Established IC-R as a preferred option over polymyxins."},{name:"ATTAIN 1 & 2 Trials (Tedizolid)",detail:"Tedizolid 200mg QD × 6 days non-inferior to linezolid 600mg BID × 10 days for ABSSSI including MRSA. Shorter duration, once-daily dosing, potentially better tolerability."},{name:"Hartford Nomogram (Aminoglycosides)",detail:"Established 7 mg/kg extended-interval dosing for gentamicin/tobramycin. AUC-guided approach reduces nephrotoxicity while maintaining efficacy through concentration-dependent killing."}],riskFactors:"Prior antibiotic exposure (especially broad-spectrum), healthcare exposure, ICU admission, immunosuppression, solid organ or stem cell transplant, prolonged hospitalization, invasive devices, prior MDR organism isolation, travel to endemic regions."},subcategories:[{id:"cre-management",name:"Carbapenem-Resistant Enterobacteriaceae (CRE)",definition:"Enterobacteriaceae non-susceptible to at least one carbapenem (or producing carbapenemase). Includes KPC, NDM, OXA-48, VIM, IMP producers. One of the most critical AMR threats globally.",clinicalPresentation:"Any infection type: UTI, bacteremia, pneumonia, IAI. Suspect in patients with prior carbapenem exposure, healthcare contact in endemic regions, or prior MDR organism colonization.",diagnostics:"Culture and susceptibility testing essential. Carbapenemase PCR panel (KPC, NDM, OXA-48, VIM, IMP) guides therapy. MIC testing required — not just S/I/R breakpoints. Check ceftazidime-avibactam and meropenem-vaborbactam susceptibility. Consult ID and clinical pharmacy for complex cases.",durationGuidance:{standard:"7–14 days (source and severity dependent)",severe:"14 days (bacteremia) — repeat blood cultures at 48h",stewardshipNote:"IDSA 2022: Use targeted regimens based on carbapenemase type. KPC — ceftazidime-avibactam or meropenem-vaborbactam preferred. NDM — aztreonam-avibactam (investigational), ceftazidime-avibactam + aztreonam. Combination therapy only when synergy demonstrated."},empiricTherapy:[{line:"KPC-producing CRE",options:[{drug:"ceftazidime-avibactam",regimen:"Ceftazidime-Avibactam 2.5g IV q8h (adjust for renal function)",notes:"Preferred for KPC-CRE and OXA-48. Does NOT cover NDM. Check local susceptibility.",evidence:"A-II",evidenceSource:"IDSA 2022"},{drug:"meropenem-vaborbactam",regimen:"Meropenem-Vaborbactam 4g IV q8h (infuse over 3h)",notes:"Alternative for KPC-CRE. Does NOT cover NDM, OXA-48, or Acinetobacter.",evidence:"A-II",evidenceSource:"IDSA 2022"}]},{line:"NDM-producing CRE",options:[{drug:"ceftazidime-avibactam",regimen:"Ceftazidime-Avibactam 2.5g IV q8h + Aztreonam 2g IV q6h (extended infusion)",notes:"Combination required — CAZ-AVI restores aztreonam activity against MBL-producers. Ceftazidime-avibactam protects aztreonam from hydrolysis. ID consult mandatory.",evidence:"B-II",evidenceSource:"IDSA 2022"}]},{line:"Salvage / Pan-resistant",options:[{drug:"colistin",regimen:"Colistin (CMS) — load 9 MU IV, then 4.5 MU IV q12h (CrCl-adjusted), always in combination",notes:"Use only when all other options exhausted. Nephrotoxicity in 30-50%. Never monotherapy. Combination with meropenem, rifampin, or fosfomycin based on MIC data.",evidence:"C-III",evidenceSource:"IDSA 2022"}]}],pearls:["Never use ceftazidime-avibactam monotherapy for NDM-producers — avibactam does NOT inhibit metallo-beta-lactamases. This is a potentially fatal prescribing error.","MIC testing is mandatory before treating CRE — zone diameter breakpoints are unreliable. Use broth microdilution.","Consult ID and clinical pharmacy for all CRE infections — outcomes are significantly better with specialist involvement.","Check the IDSA 2022 AMR guidance table — treatment choice depends on which carbapenemase is present."]},{id:"mdr-pseudomonas",name:"Difficult-to-Treat Pseudomonas aeruginosa (DTR-PA)",definition:"Pseudomonas non-susceptible to all first-line agents: piperacillin-tazobactam, cefepime, ceftazidime, meropenem, imipenem, aztreonam, AND ciprofloxacin/levofloxacin. Growing global problem.",clinicalPresentation:"VAP, HAP, bacteremia, complicated UTI, wound infections. ICU patients, CF patients, prior antibiotic exposure at high risk.",diagnostics:"Full susceptibility panel required. Test ceftolozane-tazobactam, imipenem-cilastatin-relebactam, ceftazidime-avibactam. CF patients require special testing (agar dilution).",durationGuidance:{standard:"7 days (HAP/VAP per IDSA/ATS 2016)",severe:"14 days (bacteremia, inadequate source control)",stewardshipNote:"Combination therapy no longer recommended for DTR-PA in most cases when susceptible to novel agents. ID consult mandatory."},empiricTherapy:[{line:"Preferred (DTR-PA)",options:[{drug:"ceftolozane-tazobactam",regimen:"Ceftolozane-Tazobactam 3g IV q8h (HAP/VAP: 1.5g q8h for cUTI/IAI) — standard infusion 1h",notes:"Excellent anti-pseudomonal activity. Stable against most Pseudomonas resistance mechanisms except MBL.",evidence:"A-II",evidenceSource:"IDSA 2022"},{drug:"imipenem-cilastatin-relebactam",regimen:"Imipenem-Cilastatin-Relebactam 1.25g IV q6h (infuse over 30 min)",notes:"Active against KPC and AmpC producers. Restores imipenem activity. RESTORE-IMI trials support use.",evidence:"A-II",evidenceSource:"IDSA 2022"}]}],pearls:["Ceftolozane-tazobactam is NOT active against ESBL-producing Enterobacteriaceae or KPC-CRE.","Imipenem-cilastatin-relebactam does NOT cover NDM-producers or Acinetobacter.","For CF patients with chronic Pseudomonas, susceptibility testing with agar dilution may give more reliable results than automated systems.","Always obtain ID consultation for DTR-PA infections — mortality is significantly higher without appropriate therapy."]}],drugMonographs:[{id:"gentamicin",name:"Gentamicin",brandNames:"Garamycin",drugClass:"Aminoglycoside",mechanismOfAction:"Binds irreversibly to the 30S ribosomal subunit (16S rRNA), causing misreading of mRNA and premature chain termination. Uptake into bacterial cell is dependent on electron transport chain (aerobic organisms only). Concentration-dependent bactericidal activity.",spectrum:"Gram-negative: Excellent against Enterobacteriaceae (E. coli, Klebsiella, Enterobacter, Serratia, Proteus), Pseudomonas aeruginosa. Gram-positive: Synergy with cell wall-active agents (penicillin/vancomycin) for Enterococcus and Staphylococcus endocarditis. GAPS: Anaerobes, Streptococci (intrinsic resistance), Stenotrophomonas. Increasing resistance in MDR gram-negatives.",dosing:{extended_interval:"7 mg/kg IV q24h (Hartford Nomogram) — use IBW if non-obese; AdjBW if obese",synergy_endocarditis:"1 mg/kg IV q8h (MSSA/Enterococcal endocarditis synergy dosing)",traditional:"1.7 mg/kg IV q8h (conventional dosing — monitor troughs <2 mg/L)",intrathecal:"4–8 mg IT q24h (gram-negative meningitis, adjunct to IV therapy)"},renalAdjustment:"Extended interval: CrCl 40-59 → q36h; CrCl 20-39 → q48h; CrCl <20 → conventional dosing recommended; HD/PD → dose post-dialysis, redose based on levels. Monitor levels regardless of interval. Use clinical pharmacokinetics service for complex cases.",hepaticAdjustment:"No hepatic adjustment needed. Gentamicin is eliminated unchanged by kidneys. However, hepatic disease is often associated with altered Vd — consult PK service.",adverseEffects:{common:"Nephrotoxicity (proximal tubule injury, ATN with prolonged use or trough accumulation), ototoxicity (cochlear — high-frequency hearing loss initially; vestibular — ataxia, oscillopsia)",serious:"Permanent sensorineural hearing loss (cochlear), irreversible vestibular toxicity, acute tubular necrosis, neuromuscular blockade (rare, high doses)",rare:"Neuromuscular blockade (avoid in myasthenia gravis), fetal ototoxicity with in-utero exposure",fdaBoxedWarnings:"Nephrotoxicity and ototoxicity. Risk increased with prolonged therapy, high doses, renal impairment, and concurrent nephrotoxins. Irreversible ototoxicity can occur without warning."},drugInteractions:["Vancomycin — additive nephrotoxicity; avoid concurrent use when possible; if necessary monitor renal function daily","Loop diuretics (furosemide, ethacrynic acid) — additive ototoxicity; ethacrynic acid most hazardous","Amphotericin B — additive nephrotoxicity","Cisplatin — additive nephrotoxicity and ototoxicity","Neuromuscular blocking agents — potentiation of blockade","NSAIDs — reduce renal prostaglandin-mediated afferent arteriole dilation, increase nephrotoxicity risk","Cyclosporine/tacrolimus — additive nephrotoxicity in transplant patients"],monitoring:"Extended interval: obtain random level 6–14h post-infusion; plot on Hartford Nomogram for interval selection. Traditional: peak 5–10 mg/L (drawn 30 min post-infusion), trough <2 mg/L (drawn 30 min pre-dose). Serum creatinine 2–3×/week. Audiology if prolonged therapy. Urine output monitoring.",pregnancyLactation:"Category D. Aminoglycosides cross the placenta. Fetal ototoxicity reported with streptomycin (less data with gentamicin, but theoretical risk same class). Avoid unless life-threatening infection with no alternatives. Minimal excretion in breast milk — oral absorption poor, low systemic risk for infant.",pkpdDriver:{driver:"Concentration-dependent (Cmax/MIC)",target:"Cmax/MIC ≥8–10 (extended interval); AUC/MIC ≥70–100 for synergy dosing",extendedInfusion:"NOT applicable — give as 30–60 min IV infusion to achieve high Cmax"},opatEligibility:{eligible:"yes",administration:"IV q24h (extended interval) — ideal for OPAT; once-daily self-administration or nurse visit",monitoring:"Weekly serum creatinine, BUN; audiometry for courses >2 weeks; random level at steady-state (dose 3–4) for interval confirmation",considerations:["Extended-interval dosing preferred for OPAT — once-daily administration, reduced toxicity","Not appropriate for CrCl <40 mL/min without close PK monitoring","Vestibular toxicity may not be obvious — ask about balance/dizziness at each visit","Audiometry baseline recommended for courses >2 weeks"]},pharmacistPearls:["The Hartford Nomogram was designed for GENTAMICIN specifically. The 7 mg/kg dose with nomogram-guided intervals has equivalent efficacy and LESS nephrotoxicity than traditional dosing in most patients.","Use IBW for dosing in non-obese patients. Use AdjBW [IBW + 0.4×(TBW–IBW)] if obese (TBW >1.25×IBW). Using TBW in obese patients overdoses dramatically.","Extended-interval dosing uses the principle of concentration-dependent killing + post-antibiotic effect (PAE). Once you achieve Cmax/MIC ≥10, a drug-free interval actually enhances killing.","Conventional dosing (1.7 mg/kg q8h) is ONLY indicated for endocarditis synergy dosing and possibly Enterococcal infections — most other indications benefit from extended interval.","Trough level monitoring for conventional dosing must be drawn 30 min BEFORE the dose, not during infusion or too early after dose.","Nephrotoxicity is dose-cumulative and predictable — highest risk with troughs >2 mg/L, prolonged courses (>14 days), and concurrent nephrotoxins. It is usually reversible.","Ototoxicity can be cochlear (hearing loss, tinnitus) OR vestibular (balance, oscillopsia). Vestibular toxicity is often missed — ask about balance problems specifically."]},{id:"aztreonam",name:"Aztreonam",brandNames:"Azactam",drugClass:"Monobactam (beta-lactam antibiotic)",mechanismOfAction:"Binds specifically to penicillin-binding protein 3 (PBP3) of aerobic gram-negative bacteria. Inhibits cell wall peptidoglycan synthesis, leading to cell lysis. Unique structure with a monocyclic beta-lactam ring — no cross-reactivity with penicillins or cephalosporins in terms of the ring system.",spectrum:"Exclusively aerobic gram-negative: E. coli, Klebsiella, Proteus, Serratia, Pseudomonas aeruginosa, Haemophilus, Neisseria. ZERO gram-positive activity. ZERO anaerobic activity. Key advantage: no cross-allergenicity with penicillins/carbapenems (different ring structure). Cross-reactivity with ceftazidime (identical R1 side chain) — avoid if ceftazidime allergy.",dosing:{standard:"1–2g IV/IM q8h",severe:"2g IV q6h (severe gram-negative infections, Pseudomonas)",cystic_fibrosis:"2g IV q6–8h (aggressive dosing for CF exacerbations)",inhalation:"75mg inhaled TID (Cayston — for CF/Pseudomonas chronic suppression)"},renalAdjustment:"CrCl 10–30: reduce by 50% (standard dose q8h → q12h or half dose). CrCl <10: 25% of usual dose. HD: supplemental dose post-dialysis. No active metabolites.",hepaticAdjustment:"Mild-moderate hepatic disease: no adjustment. Severe hepatic dysfunction: reduce dose by 20-25%. Aztreonam excreted primarily renally but partially metabolized.",adverseEffects:{common:"Local site reactions (IV/IM), rash (typically morbilliform), nausea, diarrhea",serious:"C. difficile colitis (all antibiotics), hepatotoxicity (rare), phlebitis",rare:"Seizures (extremely rare at standard doses), severe rash"},drugInteractions:["Furosemide, probenecid — increase aztreonam serum levels (competitive tubular secretion)","Imipenem — potential antagonism if used together (in-vitro) — separate if combination needed","Ceftazidime-avibactam — SYNERGISTIC combination for NDM-CRE: CAZ-AVI protects aztreonam from MBL hydrolysis while aztreonam provides bactericidal activity"],monitoring:"Renal function (primary elimination). CBC, LFTs for prolonged courses. C. diff monitoring for diarrhea.",pregnancyLactation:"Category B. No teratogenicity in animal studies. Limited human data. Use only if benefit outweighs risk. Minimal excretion in breast milk.",ivToPoSwitch:{poBioavailability:"Poor oral bioavailability — no oral formulation available",switchCriteria:"Not applicable — IV/IM only (parenteral) or inhaled (Cayston) for CF",note:"No oral step-down possible. Consider switching to alternative oral agent if clinically appropriate."},opatEligibility:{eligible:"yes",administration:"IV q6-8h via PICC or port; inhaled Cayston for CF prophylaxis",monitoring:"Renal function weekly; LFTs for prolonged courses",considerations:["Key advantage for OPAT: safe in penicillin-allergic patients (no cross-reactivity with penicillin or carbapenems)","Exception: avoid if history of IMMEDIATE reaction to ceftazidime (shared R1 side chain)","Provides no gram-positive coverage — ensure empiric gram-positive coverage addressed separately","Inhaled aztreonam (Cayston) used for CF chronic Pseudomonas suppression"]},pharmacistPearls:["Aztreonam is the antibiotic of choice for serious gram-negative infections in patients with severe penicillin/carbapenem allergy. However, it does NOT cover gram-positives or anaerobes — ensure adequate coverage for those.","Ceftazidime allergy DOES cross-react with aztreonam (identical R1 side chain on both molecules). This is one of the few true cross-reactions between different beta-lactam classes.","Aztreonam + ceftazidime-avibactam is a powerful combination for NDM-producing CRE: avibactam protects aztreonam from metallo-beta-lactamase hydrolysis.","Aztreonam does NOT cause positive results on beta-lactam skin testing in most penicillin-allergic patients. However, if concerned, refer to allergy for evaluation.","Aztreonam has no activity against gram-positive organisms. A common clinical error is treating gram-positive bacteremia with aztreonam based on susceptibility report — aztreonam is not indicated."]},{id:"ceftolozane-tazobactam",name:"Ceftolozane-Tazobactam",brandNames:"Zerbaxa",drugClass:"5th-generation cephalosporin / beta-lactamase inhibitor combination",mechanismOfAction:"Ceftolozane (novel cephalosporin with modified R1 side chain) binds multiple PBPs in Pseudomonas aeruginosa with high affinity. Tazobactam inhibits class A and some class C beta-lactamases. The unique structure evades many Pseudomonas resistance mechanisms (efflux pumps, porin loss). Does NOT inhibit class B (metallo-BLI) or class D (OXA) beta-lactamases.",spectrum:"Outstanding Pseudomonas aeruginosa activity (including many MDR strains). Good Enterobacteriaceae (including ESBL-producers — tazobactam inhibits ESBL). Weak anaerobic coverage. NO MRSA. NO Acinetobacter. NO CRE (carbapenem-resistant). Stenotrophomomas variable.",dosing:{cuti_iai:"1.5g (1g ceftolozane/0.5g tazobactam) IV q8h",hap_vap:"3g (2g/1g) IV q8h (higher dose for pulmonary infections)",adjustment_note:"Dose based on CrCl — see renal adjustment"},renalAdjustment:"CrCl 30–50: 750mg q8h (for cUTI/IAI) or 1.5g q8h (HAP/VAP). CrCl 15–29: 375mg q8h or 750mg q8h. CrCl <15/HD: supplemental dose post-HD. Consult package insert or clinical pharmacist — complex renal dosing.",hepaticAdjustment:"No hepatic dose adjustment required.",adverseEffects:{common:"Nausea, diarrhea, headache, fever, hypokalemia (tazobactam component)",serious:"C. difficile colitis, hepatotoxicity (rare), thrombocytosis",rare:"Hypersensitivity, seizures (rare)",contraindications:"Severe hypersensitivity to cephalosporins or piperacillin-tazobactam."},drugInteractions:["Probenecid — increases ceftolozane exposure (blocks tubular secretion) — avoid combination","No significant CYP450 interactions"],monitoring:"Renal function (adjust dose). C. diff monitoring. CBC, LFTs for prolonged courses.",pregnancyLactation:"Category not assigned (post-2014 FDA labeling). No adequate human data. Animal studies showed no adverse effects. Use only when benefit outweighs risk.",pkpdDriver:{driver:"Time-dependent (T>MIC)",target:"fT>MIC ≥40–70% (free drug time above MIC)",extendedInfusion:"Consider extended infusion (1h standard; 3h for higher MIC targets or severe infections) — increases fT>MIC"},opatEligibility:{eligible:"conditional",administration:"IV q8h via PICC/port — requires infusion pump for extended-infusion protocol",monitoring:"Renal function 2×/week; clinical response at 3–5 days",considerations:["OPAT requires frequent renal monitoring due to dose-adjustment complexity","Extended infusion beneficial — coordinate with OPAT pharmacy for infusion bags","High cost — obtain prior authorization; document MDR Pseudomonas susceptibility","Not appropriate for oral step-down — IV only"]},pharmacistPearls:["Ceftolozane-tazobactam is specifically designed for MDR Pseudomonas aeruginosa — it is NOT the right drug for ESBL Klebsiella (use ertapenem) or CRE (use ceftazidime-avibactam).","The HAP/VAP dose (3g q8h) is DOUBLE the cUTI/IAI dose (1.5g q8h). This is because pulmonary PK/PD modeling requires higher exposures. Common prescribing error: using the lower dose for pneumonia.","Does NOT inhibit metallo-beta-lactamases (NDM, VIM, IMP) — if MBL suspected, this drug will fail.","Extended infusion over 3 hours significantly improves pharmacodynamic target attainment for Pseudomonas strains with MIC ≥4 mg/L. Work with clinical pharmacy to implement.","Resistance during therapy has been reported — obtain follow-up cultures if patient fails to respond."]},{id:"imipenem-cilastatin-relebactam",name:"Imipenem-Cilastatin-Relebactam",brandNames:"Recarbrio",drugClass:"Carbapenem / beta-lactamase inhibitor combination",mechanismOfAction:"Imipenem (carbapenem) binds multiple PBPs causing cell wall inhibition and lysis. Cilastatin inhibits renal dehydropeptidase I (prevents imipenem hydrolysis in proximal tubules). Relebactam (diazabicyclooctane BLI) inhibits class A (KPC, ESBL) and class C (AmpC) beta-lactamases, restoring imipenem activity against resistant strains. Does NOT inhibit class B (metallo-BLI) or most class D (OXA-48+).",spectrum:"Enterobacteriaceae (including KPC-CRE), Pseudomonas aeruginosa (including DTR strains), Acinetobacter (variable). Gram-positive: MSSA, E. faecalis, Streptococcus. Anaerobes: Bacteroides, Peptostreptococcus. GAPS: MRSA, VRE, NDM/OXA-48-CRE (relebactam does not inhibit these), Stenotrophomonas.",dosing:{standard:"1.25g (500mg/500mg/250mg) IV q6h, infused over 30 minutes",renal_adjusted:"See table — dose adjusted for CrCl <90 mL/min"},renalAdjustment:"CrCl 60–89: 1g q6h. CrCl 30–59: 0.75g q6h. CrCl 15–29: 0.5g q6h. CrCl <15/HD: 0.5g q12h (dose after HD on HD days). Monitoring required.",hepaticAdjustment:"No hepatic dose adjustment. Primarily renally eliminated.",adverseEffects:{common:"Nausea, diarrhea, vomiting, elevated transaminases, phlebitis",serious:"Seizures (imipenem — lower seizure threshold than other carbapenems, particularly in patients with CNS disease or renal impairment with inadequate dose reduction), C. difficile colitis",rare:"Encephalopathy, hypotension",fdaBoxedWarnings:"Serious CNS adverse reactions including seizures — particularly in patients with CNS disorders and those with renal dysfunction receiving doses not adjusted for renal function."},drugInteractions:["Valproic acid — MAJOR: imipenem reduces valproic acid levels by 60-70% within 2 days. Risk of seizure due to sub-therapeutic valproate. Avoid combination; if necessary, consult neurology and monitor levels closely.","Ganciclovir — additive seizure risk when used concomitantly","Cyclosporine — additive CNS toxicity (tremors, seizures)"],monitoring:"Renal function (complex dosing). Seizure precautions. Valproic acid levels if co-prescribed. CBC, LFTs for prolonged therapy.",pregnancyLactation:"Category C. Animal studies showed some fetal harm. Limited human data. Use only for serious infections where benefits outweigh risks.",pkpdDriver:{driver:"Time-dependent (T>MIC)",target:"fT>MIC ≥40% (static), ≥80% (bactericidal) — free drug time above MIC",extendedInfusion:"Extended infusion over 3h improves target attainment — 0.5g component infused over 3h"},opatEligibility:{eligible:"conditional",administration:"IV q6h — requires daily nursing or patient education for q6h pump administration",monitoring:"Renal function 2-3×/week due to complex dose-adjustment; seizure monitoring",considerations:["q6h dosing is burdensome for OPAT — consider ertapenem (q24h) if susceptible","Avoid in patients with prior seizures or significant CNS disease without neurology input","Relebactam component not available separately — this is the complete branded product","High cost; requires prior authorization for MDR indication"]},pharmacistPearls:["CRITICAL: Imipenem DRAMATICALLY reduces valproic acid levels (>60% reduction within 2 days). This is one of the most dangerous drug-drug interactions in infectious disease. If a patient is on valproic acid, either avoid imipenem/IC-R or transition valproate to a different antiepileptic with neurology guidance.","Imipenem has the lowest seizure threshold of all carbapenems — particularly dangerous in patients with prior seizures, CNS lesions, or renal impairment (if dose not properly adjusted).","IC-Relebactam is preferred over colistin for carbapenem-resistant Pseudomonas and KPC-CRE based on RESTORE-IMI trial data — significantly better safety profile.","Relebactam does NOT inhibit metallo-beta-lactamases (NDM, VIM) or OXA-48. If these are present, IC-R will fail. Carbapenemase testing is mandatory before use.","The RESTORE-IMI 2 trial showed IC-R was non-inferior to piperacillin-tazobactam for HAP/VAP, with activity against pip-tazo resistant Pseudomonas."]},{id:"colistin",name:"Colistin (Polymyxin E)",brandNames:"Coly-Mycin M (colistimethate sodium — prodrug); Colistin (active form)",drugClass:"Polymyxin antibiotic",mechanismOfAction:"Colistimethate sodium (CMS) is the inactive prodrug — converts to colistin (active) in vivo and in solution. Colistin disrupts the outer membrane of gram-negative bacteria by competitively displacing Ca²⁺ and Mg²⁺ from lipopolysaccharide (LPS) phosphate groups, increasing membrane permeability and causing cell lysis. Concentration-dependent bactericidal activity. Does NOT enter gram-positive cells (no outer membrane).",spectrum:"Gram-negative only: Acinetobacter baumannii, Pseudomonas aeruginosa, Klebsiella pneumoniae. The 'drug of last resort' for pan-drug-resistant organisms. GAPS: Proteus, Providencia, Serratia, Morganella (intrinsically resistant — lack LPS modifications), gram-positive, anaerobes, fungi.",dosing:{loading:"Loading dose: 9 MU CMS IV over 30 min (to rapidly achieve target concentrations)",maintenance:"Maintenance: 4.5 MU CMS IV q12h (normal renal function). DOSE IN MIU OF CMS not mg of colistin base — units are confusing, always double-check.",inhaled:"Inhaled: 1–2 MIU CMS via nebulizer q12h (for pulmonary MDR infections as adjunct to IV)",note:"Dosing is complex and confusing — colistin base activity (CBA) vs colistimethate sodium (CMS) mg vs MIU. Consult clinical pharmacy for all patients."},renalAdjustment:"CRITICAL and complex. CMS is primarily renally eliminated; colistin (active) accumulates in renal insufficiency causing toxicity. CrCl 50–79: load 9 MU, then 5.5 MU/day in 2 doses. CrCl 30–49: 4.5 MU/day. CrCl 10–29: 3.5 MU/day. HD: dose post-HD. ID/PK consultation mandatory — incorrect dosing causes nephrotoxicity without efficacy.",hepaticAdjustment:"No specific hepatic adjustment — primarily renally eliminated.",adverseEffects:{common:"Nephrotoxicity (30–50% of patients; ATN/AKI — usually reversible), neurotoxicity (paresthesias, dizziness, slurred speech, ataxia — in up to 27%)",serious:"Severe acute kidney injury (potentially requiring dialysis), respiratory failure/neuromuscular blockade (rare), respiratory failure with nebulized form (bronchospasm)",rare:"Apnea (neuromuscular blockade at high serum levels), severe respiratory failure with inhaled route",fdaBoxedWarnings:"Nephrotoxicity and neurotoxicity. Reserve for infections due to susceptible organisms when safer alternatives are not available. Renal function should be monitored carefully; dosing adjustments required."},drugInteractions:["Aminoglycosides — additive nephrotoxicity; avoid if possible","Vancomycin — additive nephrotoxicity; use with extreme caution","Neuromuscular blocking agents — potentiation of NMB; may cause respiratory arrest","Amphotericin B — additive nephrotoxicity","Loop diuretics — additive nephrotoxicity","Non-depolarizing muscle relaxants — enhanced neuromuscular blockade"],monitoring:"Serum creatinine DAILY. Urine output hourly in critical patients. Serum colistin levels if available (PK-guided dosing). Neurological assessment (slurred speech, paresthesias, confusion — often early toxicity warning). Avoid concomitant nephrotoxins if at all possible. Electrolytes daily (hypokalemia, hypomagnesemia common).",pregnancyLactation:"Category C. Avoid unless benefit clearly outweighs risk — fetal risk extrapolated from nephrotoxicity profile. Limited human data. Not recommended in breastfeeding.",pkpdDriver:{driver:"AUC/MIC-dependent",target:"AUC/MIC ≥50 (free drug); always use in combination — never monotherapy except in extreme circumstances",extendedInfusion:"Loading dose mandatory to achieve target Css rapidly; maintenance as described"},opatEligibility:{eligible:"no",administration:"IV only — requires ICU or intensive monitoring setting",monitoring:"Daily renal function, electrolytes, neurological assessment — not suitable for OPAT",considerations:["Nephrotoxicity and complex renal dosing require close inpatient monitoring","Only appropriate when no other options exist — always consult ID","Inhaled colistin as ADJUNCT to IV therapy in pulmonary MDR infections may be used in stable patients transitioning to subacute care","PK/PD service consultation is standard of care for colistin dosing"]},pharmacistPearls:["DOSING CONFUSION IS A PATIENT SAFETY ISSUE: Colistin doses are expressed in different units by different manufacturers and references — colistimethate sodium (CMS) MIU, mg of CMS, or colistin base activity (CBA). ALWAYS verify units with the specific product you have. This has caused fatal overdoses.","A loading dose is mandatory — CMS conversion to active colistin is slow (t½ CMS → colistin ~7h). Without loading, therapeutic levels are not achieved for 12–24h in a critically ill patient.","Nephrotoxicity is 30–50% in clinical practice. Hydration, avoidance of other nephrotoxins, and dose optimization are critical mitigation strategies.","NEVER use colistin as monotherapy if any other agent shows activity — combination with carbapenem, rifampin, or fosfomycin improves outcomes and reduces resistance emergence.","Colistin resistance during therapy is a real risk — follow-up cultures are essential.","The emergence of novel agents (IC-relebactam, ceftazidime-avibactam, ceftolozane-tazobactam) has significantly reduced the indications for colistin. If any of these agents cover the organism, they are preferred."]},{id:"tedizolid",name:"Tedizolid",brandNames:"Sivextro",drugClass:"Oxazolidinone antibiotic (2nd generation)",mechanismOfAction:"Binds to the 50S ribosomal subunit (23S rRNA, domain V) — same mechanism as linezolid but with enhanced binding affinity (lower MIC vs. most organisms). Inhibits translation initiation complex formation (blocks 70S ribosome assembly). Bacteriostatic against most organisms; bactericidal against some staphylococci.",spectrum:"Gram-positive only: MRSA (excellent), MSSA, VRE (E. faecalis and E. faecium), streptococci (including viridans), Streptococcus pneumoniae (including DRSP), Listeria. GAPS: All gram-negatives, anaerobic gram-negatives. Activity against some linezolid-resistant strains (different binding interaction). NO activity against fungi.",dosing:{absssi:"200mg IV or PO once daily × 6 days",hap_consideration:"200mg IV q24h (not FDA-approved for HAP, but studied; controversial data)"},renalAdjustment:"No dose adjustment required for any degree of renal impairment, including dialysis. This is a significant advantage over linezolid (linezolid metabolites accumulate in renal impairment).",hepaticAdjustment:"No dose adjustment required for hepatic impairment. Tedizolid undergoes hepatic glucuronidation (UGT pathways) and is eliminated via biliary/fecal route.",adverseEffects:{common:"Nausea, headache, diarrhea, vomiting (GI effects generally less than linezolid)",serious:"Myelosuppression (thrombocytopenia, anemia, neutropenia — LESS common than linezolid in trials; monitor CBC if extended use)",rare:"Serotonin syndrome (5-HT mechanism similar to linezolid but slightly lower theoretical risk), optic neuropathy with prolonged use, peripheral neuropathy"},drugInteractions:["MAO inhibitors — CONTRAINDICATED: serotonin syndrome and hypertensive crisis risk (same as linezolid)","Serotonergic drugs (SSRIs, SNRIs, TCA, triptans, meperidine, dextromethorphan) — risk of serotonin syndrome; assess risk:benefit","Adrenergic drugs (sympathomimetics, vasopressors) — potential enhanced pressor response (monoamine oxidase mechanism)","Tyramine-rich foods — unlike MAOIs, tedizolid interaction appears less significant than linezolid (selective vs. non-selective MAO inhibition), but still counsel patients","Rifampin — reduces tedizolid exposure (OATP1B inhibition); avoid combination or monitor"],monitoring:"CBC at baseline and weekly for courses >6 days (especially platelets — serotonin pathway in platelets). Monitor for signs of serotonin syndrome. Visual symptoms (optic neuropathy) for prolonged courses.",pregnancyLactation:"Category C. Animal embryo-fetal toxicity data. No adequate human data. Avoid unless benefits outweigh risks.",ivToPoSwitch:{poBioavailability:">90% oral bioavailability — nearly complete absorption",switchCriteria:"Switch to oral immediately once patient tolerating oral intake — same dose (200mg PO QD). No dose adjustment needed for IV→PO switch.",note:"The >90% bioavailability makes tedizolid an ideal IV→PO switch candidate. IV-equivalent oral therapy means hospitalization for IV access is not clinically justified."},opatEligibility:{eligible:"yes",administration:"PO 200mg once daily — no IV access required for oral step-down. IV option if oral not feasible.",monitoring:"CBC weekly if >6-day course. Serotonin symptom assessment.",considerations:["Once-daily oral dosing is ideal for outpatient management of MRSA SSTI","Avoid serotonergic drugs during therapy","More expensive than linezolid — document clinical indication","6-day course for ABSSSI supported by ATTAIN trials (vs. 10 days for linezolid)"]},pharmacistPearls:["Tedizolid 200mg QD × 6 days vs. linezolid 600mg BID × 10 days — non-inferior for MRSA ABSSSI per ATTAIN trials. Shorter course, once daily = significant patient advantage.","The key pharmacist advantage of tedizolid over linezolid: NO dose adjustment in renal failure, and generally better tolerated (less myelosuppression, less GI effects). Reserve linezolid for when cost is the primary driver.","Both tedizolid and linezolid are monoamine oxidase inhibitors. Serotonin syndrome with concomitant serotonergic agents (SSRIs, SNRIs) is a real risk — always reconcile medications.","Tedizolid is bacteriostatic for most organisms. Do NOT use for bacteremia, endocarditis, or osteomyelitis as primary therapy — these require bactericidal agents.","Oral bioavailability >90% — this is equivalent to IV. IV-to-PO switch at day 1–2 of therapy is appropriate and cost-effective.","Cost: tedizolid is significantly more expensive than linezolid. In formulary-restricted settings, document MRSA + linezolid intolerance or failure to justify tedizolid."]},{id:"posaconazole",name:"Posaconazole",brandNames:"Noxafil (oral suspension, tablets, IV), Posanol",drugClass:"Triazole antifungal",mechanismOfAction:"Inhibits lanosterol 14α-demethylase (CYP51) in the ergosterol biosynthesis pathway. Blocks conversion of lanosterol to ergosterol — depletes fungal cell membrane ergosterol, disrupting membrane integrity and function. Extended spectrum compared to fluconazole/voriconazole due to structural modifications allowing binding to resistant CYP51 variants.",spectrum:"Extended-spectrum triazole: Aspergillus (including some voriconazole-resistant strains), Candida (most species including non-albicans), Mucorales (Mucor, Rhizopus — unique among azoles), Fusarium (variable), Histoplasma, Coccidioides, Blastomyces, Cryptococcus. KEY advantage over voriconazole: Mucorales coverage. Limited activity against Candida krusei.",dosing:{prophylaxis_tablet:"300mg PO BID day 1 (load), then 300mg PO QD (DR tablets — preferred formulation)",prophylaxis_suspension:"200mg PO TID (oral suspension — requires high-fat meal or acidic drink for absorption, inconsistent)",treatment_invasive:"300mg IV q12h day 1, then 300mg IV QD (IV preferred for invasive disease — reliable levels)",prophylaxis_iv:"300mg IV QD for patients unable to take oral"},renalAdjustment:"IV formulation contains sulfobutylether-beta-cyclodextrin (SBECD) vehicle — avoid IV if CrCl <50 mL/min due to SBECD accumulation (nephrotoxic). Oral formulations safe in all degrees of renal impairment.",hepaticAdjustment:"No dose adjustment in mild-moderate hepatic disease. Use with caution in severe hepatic impairment; monitor LFTs closely.",adverseEffects:{common:"Nausea, vomiting, diarrhea, abdominal pain, headache, elevated LFTs",serious:"Hepatotoxicity (monitor LFTs), QT prolongation (additive with other QT-prolonging drugs), adrenal insufficiency with prolonged use (CYP3A4 inhibition affects cortisol metabolism)",rare:"Severe hepatic toxicity, visual disturbances (less common than voriconazole), photosensitivity"},drugInteractions:["Posaconazole is a POTENT CYP3A4 inhibitor and P-glycoprotein inhibitor — MAJOR interactions","Calcineurin inhibitors (tacrolimus, cyclosporine, sirolimus) — dramatically increase levels; reduce dose by 50-75% and monitor levels frequently","Statins metabolized by CYP3A4 (simvastatin, lovastatin, atorvastatin) — markedly increased statin levels → rhabdomyolysis risk; hold or switch to pravastatin","Rifampin/rifabutin — dramatically reduce posaconazole levels; avoid combination","Midazolam — levels increased 5-fold; respiratory depression risk","QT-prolonging agents (quinolones, macrolides, antiarrhythmics) — additive QT prolongation","Phenytoin, carbamazepine, barbiturates — reduce posaconazole levels significantly; monitor","Methadone, fentanyl — increased opioid levels; monitor for toxicity"],monitoring:"LFTs at baseline and during therapy. QT interval (ECG). Serum posaconazole trough level (target ≥0.5-1 mg/L for prophylaxis; ≥1-2 mg/L for treatment). Electrolytes (especially K, Mg — correct hypokalemia/hypomagnesemia to reduce QT risk). Monitor all co-administered drugs for interactions.",pregnancyLactation:"Category C. Teratogenic in animal studies. Avoid in pregnancy unless life-threatening fungal infection with no alternatives. Contraception required during therapy.",ivToPoSwitch:{poBioavailability:"Delayed-release tablets: high (>90%), food-independent. Oral suspension: variable (40-60%), requires food",switchCriteria:"Switch to DR tablets when tolerating oral intake. Avoid oral suspension when possible — unreliable absorption. IV→PO switch preferred to DR tablets 300mg QD.",note:"DR tablet formulation has superior, predictable bioavailability vs. suspension. Suspension requires high-fat meal or acidic beverage — significant barrier in ill/NPO patients."},opatEligibility:{eligible:"yes",administration:"PO 300mg DR tablet QD — once daily, food-independent (DR tablets). No IV access required for oral prophylaxis/step-down",monitoring:"LFTs, serum drug levels, QT monitoring, calcineurin inhibitor levels if applicable",considerations:["Ideal for prophylaxis in AML/HSCT outpatients — once-daily oral tablet","Extensive drug interactions require medication reconciliation before OPAT","Calcineurin inhibitor doses require significant adjustment when starting posaconazole","Levels should be checked in patients who may have absorption issues (mucositis, GI disease)"]},pharmacistPearls:["THE critical distinction: Posaconazole is the ONLY triazole with reliable Mucorales (mucormycosis) coverage. If the question is 'broad antifungal prophylaxis in immunocompromised patient including Mucor coverage' — posaconazole, isavuconazole, or L-AmB are the options.","Oral suspension is the old formulation — avoid it when possible. Absorption is highly variable, food-dependent, and unreliable in mucositis or GI dysfunction (exactly when prophylaxis is needed most). The DR tablet (300mg QD) is the current standard.","Drug interactions are extensive and severe. ALWAYS conduct a full medication reconciliation. Tacrolimus/cyclosporine dose reduction of 50-75% is typically required — failure to do so causes calcineurin inhibitor toxicity.","Posaconazole prophylaxis is standard of care (IDSA 2016, ESCMID 2022) in AML patients receiving remission-induction chemotherapy — reduces IA incidence from ~12% to ~5% and improves survival.","Therapeutic drug monitoring (TDM) is recommended for treatment (target trough ≥1-2 mg/L) and optional for prophylaxis (target ≥0.5-1 mg/L). Drug levels help ensure adequate exposure and avoid toxicity.","Correct hypokalemia and hypomagnesemia before starting posaconazole — electrolyte abnormalities potentiate QT prolongation."]},{id:"liposomal-amphotericin-b",name:"Liposomal Amphotericin B (L-AmB)",brandNames:"AmBisome",drugClass:"Polyene antifungal — liposomal formulation",mechanismOfAction:"Binds ergosterol in fungal cell membranes with high affinity, forming transmembrane pores that cause electrolyte leakage and cell death. Liposomal encapsulation (unilamellar lipid vesicles) delivers drug directly to fungal cell membranes while dramatically reducing binding to mammalian cell cholesterol — this is the basis of the superior safety profile vs. conventional AmB deoxycholate. Concentration-dependent fungicidal activity.",spectrum:"Broadest antifungal spectrum available: ALL Candida species (including azole-resistant), ALL Aspergillus species, ALL Mucorales (Mucor, Rhizopus, Lichtheimia), Fusarium, Cryptococcus, Histoplasma, Coccidioides, Blastomyces, endemic fungi, Dimorphic fungi. Essentially no clinically relevant primary resistance. Drug of LAST RESORT and drug of FIRST RESORT when spectrum uncertainty is high.",dosing:{candidemia:"3-5 mg/kg IV QD",invasive_aspergillosis:"3-5 mg/kg IV QD (second-line after voriconazole/isavuconazole)",cryptococcal_meningitis:"3-4 mg/kg IV QD (induction, with flucytosine × 2 weeks)",mucormycosis:"5-10 mg/kg IV QD (high dose — Mucorales less susceptible than Candida/Aspergillus)",empiric_febrile_neutropenia:"3 mg/kg IV QD",cns_or_renal_disease:"6 mg/kg IV QD (higher doses for CNS/renal candidiasis)"},renalAdjustment:"No dose adjustment required — a KEY advantage over conventional AmB. L-AmB is safe in significant renal impairment (CrCl <10, hemodialysis). This is one of the most important clinical advantages of the liposomal formulation.",hepaticAdjustment:"No dose adjustment in hepatic impairment. Primarily eliminated via biliary route.",adverseEffects:{common:"Infusion-related reactions (fever, rigors, chills, nausea — much less than conventional AmB, occurs in ~10% vs. 70-80%). Premedicate with acetaminophen ± diphenhydramine. Hypokalemia, hypomagnesemia (tubular loss).",serious:"Nephrotoxicity (MUCH less than conventional AmB but still possible — incidence ~15-20% vs. 50-80% with deoxycholate). Hypokalemia can be severe and require significant supplementation.",rare:"Hepatotoxicity, back/chest pain during infusion (associated with lipid component), anaphylaxis (rare)",contraindications:"Known hypersensitivity to amphotericin B or the liposomal formulation components."},drugInteractions:["Aminoglycosides — additive nephrotoxicity; monitor renal function","Calcineurin inhibitors (cyclosporine, tacrolimus) — additive nephrotoxicity","Potassium-depleting diuretics (loop, thiazide) — additive hypokalemia","Antineoplastic agents (vincristine, cyclophosphamide) — additive toxicity (pulmonary/nephrotoxicity)","Corticosteroids — additive hypokalemia; electrolyte monitoring critical","Flucytosine — SYNERGISTIC combination for cryptococcal meningitis induction therapy; also additive toxicity","Digoxin — hypokalemia from AmB increases digoxin toxicity risk","Azole antifungals — reduced AmB activity (ergosterol depletion by azoles reduces AmB binding site) — avoid combination unless specific clinical indication"],monitoring:"Serum creatinine, BUN, electrolytes (K, Mg, Na, bicarbonate) DAILY for the first 2 weeks; then 2-3×/week. CBC weekly. LFTs. Input/output. Renal potassium wasting often requires aggressive supplementation (2-4g KCl/day not uncommon). Monitor for infusion reactions — particularly first dose.",pregnancyLactation:"Category B (L-AmB). Conventional AmB is the preferred antifungal for life-threatening fungal infections in pregnancy. L-AmB preferred over conventional for reduced toxicity. Use when indicated — systemic fungal infections in pregnancy are serious and treatment is required.",pkpdDriver:{driver:"AUC/MIC-dependent",target:"AUC/MIC ≥25-50 for Candida; higher targets for Aspergillus and Mucorales",extendedInfusion:"Infuse over 2h (standard) — reducing infusion time to 1h associated with more infusion reactions; 4h infusion may improve tolerability in sensitive patients"},opatEligibility:{eligible:"conditional",administration:"IV QD via PICC/port — once daily infusion over 2h is feasible for OPAT in stable patients",monitoring:"Daily electrolytes in first 2 weeks (K, Mg), then 3×/week; renal function 2-3×/week",considerations:["Electrolyte monitoring intensity limits OPAT feasibility unless daily labs can be drawn","Oral step-down not possible — no oral amphotericin formulation","OPAT most feasible for prophylaxis dosing (3 mg/kg) vs. treatment of active invasive disease","Ensure reliable IV access — tissue irritant if extravasated","Consider transition to azole (fluconazole, voriconazole, or posaconazole) once susceptibility confirmed and patient stable"]},pharmacistPearls:["L-AmB ≠ Conventional AmB: Do NOT interchange without clinical justification. L-AmB (AmBisome) is the preferred formulation due to dramatically improved safety. Conventional amphotericin B deoxycholate (Fungizone) has 50-80% nephrotoxicity and 70-80% infusion reaction rates — it should not be used when L-AmB is available.","Premedicate: Acetaminophen 650mg + diphenhydramine 25mg 30 min before infusion reduces infusion reactions. Some patients also benefit from hydrocortisone 50mg IV for recurrent severe infusion reactions.","Aggressive potassium and magnesium supplementation is the norm, not the exception. Patients on full-dose L-AmB may need 40-100 mEq KCl/day to maintain normokalemia — this is drug-induced renal tubular loss.","For cryptococcal meningitis induction: L-AmB 4-6 mg/kg/day + flucytosine 100 mg/kg/day × 2 weeks is the gold standard (WHO-endorsed). After induction, consolidate with fluconazole 400mg/day × 8 weeks, then maintenance 200mg/day.","Mucormycosis requires HIGH-DOSE L-AmB (5-10 mg/kg/day) — the MIC for Mucorales is significantly higher than for Candida/Aspergillus. Standard doses (3 mg/kg) are subtherapeutic for mucormycosis.","ABCD, ABLC, L-AmB are all lipid-associated formulations but they are NOT interchangeable. AmBisome (L-AmB) is a true liposomal formulation with the best safety data. ABLC (Abelcet) and ABCD (Amphotec) have different toxicity profiles."]}]},v={id:"febrile-neutropenia",name:"Febrile Neutropenia",icon:"🩻",category:"Infectious Disease",overview:{definition:"Febrile neutropenia (FN) is defined as a single oral temperature ≥38.3°C (101°F) OR a sustained temperature ≥38.0°C (100.4°F) for ≥1 hour in a patient with neutropenia (ANC <500 cells/μL, or ANC <1000 cells/μL with a predicted nadir of <500 cells/μL within 48 hours). FN is a medical emergency — untreated, gram-negative bacteremia in neutropenic patients carries mortality approaching 50% within 24–48 hours. Empiric broad-spectrum antibiotics must be started within 60 minutes of triage in high-risk patients. Risk stratification (MASCC score or CISNE score) guides the decision between outpatient oral therapy and inpatient IV antibiotics.",epidemiology:"FN occurs in approximately 10–50% of patients with solid tumors and >80% of patients with hematologic malignancies receiving intensive chemotherapy. Incidence is highest with AML induction therapy, allogeneic HSCT conditioning, and high-dose chemotherapy regimens. Mortality from FN has declined over decades due to risk stratification, empiric antipseudomonal therapy, antifungal prophylaxis, and G-CSF use — overall mortality is now 2–5% in low-risk patients and up to 10–20% in high-risk patients with documented bacteremia. Gram-positive organisms now account for 60–70% of documented bacteremias (largely due to indwelling catheters and mucositis), while gram-negatives — though less frequent — carry disproportionately high mortality and remain the primary empiric coverage target. Invasive fungal infections (IFI) emerge in patients with prolonged neutropenia (>7–10 days) and represent a second wave of infectious mortality.",keyGuidelines:[{name:"IDSA 2010 Febrile Neutropenia Guideline",detail:"The foundational US practice guideline for clinical assessment and antimicrobial management of FN. Key recommendations: (1) Risk stratification with MASCC score to identify low-risk patients eligible for outpatient oral therapy. (2) Antipseudomonal beta-lactam monotherapy (cefepime, piperacillin-tazobactam, or meropenem) as empiric first-line for high-risk FN. (3) Vancomycin NOT recommended routinely as empiric therapy — add only for specific indications. (4) Empiric antifungal therapy for persistent fever after 4–7 days of antibiotics. (5) Quinolone prophylaxis for high-risk patients with expected neutropenia >7 days. Despite being from 2010, this guideline remains the primary US reference."},{name:"NCCN 2024 Prevention and Treatment of Cancer-Related Infections",detail:"Comprehensive, annually updated guideline covering FN management, prophylaxis, and G-CSF use. NCCN 2024 updates include: refined risk stratification incorporating CISNE score for solid tumor patients, strengthened recommendations for posaconazole prophylaxis in AML/MDS patients, expanded OPAT criteria for low-risk FN, updated G-CSF primary prophylaxis thresholds (≥20% febrile neutropenia risk), and guidance on Clostridioides difficile prevention in patients receiving FQ prophylaxis. NCCN categorizes evidence as: Category 1 (high-level evidence + uniform NCCN consensus), Category 2A (lower-level evidence + uniform NCCN consensus), Category 2B (lower-level evidence + non-uniform NCCN consensus)."},{name:"MASCC Risk Index (Multinational Association for Supportive Care in Cancer)",detail:"The MASCC score is the most validated risk stratification tool for FN. Maximum score = 26. Low risk = score ≥21 (associated with serious medical complication rate <10% and mortality <1%). High risk = score <21. Scoring variables: burden of illness (no or mild symptoms = 5, moderate symptoms = 3, severe symptoms = 0), no hypotension (5 points), no COPD (4 points), solid tumor or no prior fungal infection in hematologic malignancy (4 points), outpatient status at onset of fever (3 points), no dehydration (3 points), age <60 years (2 points). Low-risk patients (score ≥21) are candidates for oral step-down therapy and outpatient management after a period of IV observation and clinical assessment."},{name:"CISNE Score (Clinical Index of Stable Febrile Neutropenia)",detail:"An alternative risk stratification tool specifically validated in solid tumor outpatients with FN who clinically appear stable. CISNE scoring: ECOG PS ≥2 (2 points), stress-induced hyperglycemia (2 points), COPD (1 point), cardiovascular disease history (1 point), NCI mucositis grade ≥2 (1 point), monocytes <200/μL (1 point). CISNE 0 = very low risk (complication rate ~1.1%); CISNE 1–2 = low-intermediate risk (~6%); CISNE ≥3 = high risk (~36%). CISNE is complementary to MASCC — a patient can score low-risk on MASCC but high-risk on CISNE. NCCN 2024 recommends using CISNE in addition to MASCC for solid tumor patients."},{name:"ASCO G-CSF Guideline 2015 (Updated 2024)",detail:"Guidelines for G-CSF primary prophylaxis. Primary prophylaxis recommended when risk of FN is ≥20% based on patient, disease, and regimen-specific factors. Secondary prophylaxis (after a prior FN episode) recommended to maintain dose intensity when dose reduction is not acceptable. G-CSF shortens duration of neutropenia, reduces FN incidence by ~50%, and decreases infection-related mortality. Preferred agents: filgrastim (G-CSF), pegfilgrastim (pegylated G-CSF, preferred for most outpatient regimens due to single-dose convenience). Sargramostim (GM-CSF) is less commonly used."}],landmarkTrials:[{name:"EMPIRICUS Trial (Legrand et al., JAMA 2016)",detail:"RCT of micafungin vs. placebo for empiric antifungal therapy in non-neutropenic ICU patients with suspected IFI. While not exclusively a FN trial, demonstrated that empiric antifungal therapy without diagnostic evidence did NOT improve 28-day survival and increased unnecessary antifungal exposure. This has tempered enthusiasm for purely empiric (versus pre-emptive) antifungal strategies in some settings. Reinforces the value of diagnostic-driven (pre-emptive) antifungal approaches using biomarkers (galactomannan, beta-D-glucan) over reflexive empiric use."},{name:"Bow et al. (NEJM 1998) — Fluconazole vs Amphotericin B Empiric Antifungal",detail:"Landmark RCT establishing fluconazole as equivalent to amphotericin B deoxycholate for empiric antifungal therapy in neutropenic patients with persistent fever. This trial was pivotal in moving the field away from routine empiric amphotericin B and validating azole-based empiric strategies. However, fluconazole lacks Aspergillus and mold coverage, limiting its use to low-risk patients without mold-specific risk factors."},{name:"Walsh et al. (NEJM 1999) — Liposomal Amphotericin B vs Conventional AmB for Empiric Antifungal",detail:"RCT demonstrating that liposomal amphotericin B (AmBisome 3 mg/kg/day) was equivalent in efficacy to conventional amphotericin B for empiric antifungal therapy in neutropenic patients with persistent fever, with significantly less nephrotoxicity (19% vs 34% infusion reactions, 19% vs 34% creatinine doubling). Established liposomal formulations as preferred when amphotericin B is needed. However, this was pre-echinocandin era."},{name:"Walsh et al. (NEJM 2004) — Caspofungin vs Liposomal Amphotericin B for Empiric Antifungal",detail:"RCT demonstrating caspofungin was non-inferior to liposomal amphotericin B for empiric antifungal therapy in FN patients. Caspofungin had better overall success (33.9% vs 33.7%) with significantly better tolerability. This trial, combined with the micafungin data, established echinocandins as an alternative to liposomal amphotericin B for empiric antifungal therapy in FN, particularly when Candida is more likely than Aspergillus."},{name:"Freifeld et al. (NEJM 1999) — Oral vs IV Antibiotics for Low-Risk FN",detail:"RCT (IDSA-sponsored) of ciprofloxacin + amoxicillin-clavulanate PO vs ceftriaxone + amikacin IV for low-risk FN. Oral combination was equally effective (success rates 71% vs 67%, p=NS) with similar safety. This trial established the evidence base for oral outpatient management of low-risk FN and directly informed the IDSA 2010 guideline recommendation for ciprofloxacin + amoxicillin-clavulanate as first-line oral therapy for low-risk patients."},{name:"Kern et al. (NEJM 1999) — Oral Moxifloxacin Monotherapy for Low-Risk FN",detail:"European RCT demonstrating that oral moxifloxacin monotherapy was equivalent to IV ceftriaxone + amikacin for low-risk FN. Supported the concept of oral monotherapy as an alternative for selected low-risk patients, though ciprofloxacin + amoxicillin-clavulanate combination remains the IDSA guideline recommendation."},{name:"GIMEMA/EORTC — Antifungal Prophylaxis Trials (Cornely et al., NEJM 2007)",detail:"Landmark RCT establishing posaconazole superiority over fluconazole/itraconazole for antifungal prophylaxis in AML/MDS patients receiving remission induction or salvage chemotherapy. Posaconazole reduced IFI (2% vs 8%, p<0.001), invasive aspergillosis (1% vs 7%, p<0.001), and IFI-related mortality (1% vs 4%, p=0.046). This trial directly led to posaconazole becoming the preferred prophylactic antifungal for high-risk AML/MDS patients in IDSA, NCCN, and ECIL guidelines."},{name:"Wingard et al. (Blood 2010) — Voriconazole vs Fluconazole Prophylaxis in Allogeneic HSCT",detail:"RCT in allogeneic HSCT recipients. Voriconazole reduced invasive aspergillosis vs. fluconazole (1.5% vs 3%, p=0.02) and improved 180-day fungal infection-free survival. However, no significant difference in overall survival and more adverse events (hepatotoxicity, visual disturbances) with voriconazole. Established voriconazole as an effective option for HSCT prophylaxis, with the choice between voriconazole and fluconazole depending on individual risk factors for Aspergillus vs Candida."}],riskFactors:"Host factors increasing FN risk and severity: Type of malignancy (AML/ALL highest risk, lymphoma/multiple myeloma intermediate, solid tumors variable), chemotherapy regimen intensity and myelosuppressive potential, duration of expected neutropenia (>7 days = prolonged = high risk), age >65, ECOG performance status ≥2, mucositis severity (NCI grade ≥2 = viridans streptococcal risk + oral route contraindicated), comorbidities (COPD, cardiac disease, diabetes), prior FN or fungal infection, indwelling central venous catheters (gram-positive bacteremia risk), prior antibiotic/antifungal exposure (resistance selection), malnutrition and poor functional status. Regimen-specific risk: CHOP → ~10–15% FN; R-CHOP → 15–20%; Docetaxel-containing → 20–40%; AML induction (7+3) → >80%; ICE, ESHAP → >20%; high-dose cyclophosphamide + stem cell mobilization → high risk. Patient-specific risk modifiers: Hepatic or renal dysfunction impairs antibiotic clearance; prior antibiotic prophylaxis with fluoroquinolones may select for resistant organisms."},subcategories:[{id:"low-risk-fn",name:"Low-Risk Febrile Neutropenia",definition:"Low-risk FN is defined by MASCC score ≥21 (predicted serious complication rate <10%, mortality <1%) OR CISNE score 0 (complication rate ~1.1%) in solid tumor outpatients who appear clinically stable. These patients are candidates for oral antibiotic therapy and, in selected cases, outpatient management. Key low-risk features: solid tumor (not hematologic malignancy), ANC nadir expected to be brief (<7 days), outpatient status at fever onset, no significant comorbidities, no evidence of hepatic or renal insufficiency, no hemodynamic instability, no mucositis precluding oral intake, and no indwelling catheter infection.",clinicalPresentation:"Patients with low-risk FN typically appear clinically well or only mildly ill. Fever is often the sole finding without clear source on examination. MASCC SCORE ASSESSMENT (required at triage): (1) Burden of illness: no/mild symptoms = 5 pts, moderate = 3 pts, severe/moribund = 0 pts. (2) No hypotension (SBP ≥90 mmHg) = 5 pts. (3) No COPD = 4 pts. (4) Solid tumor OR no prior invasive fungal infection (in hematologic malignancy) = 4 pts. (5) Outpatient status at fever onset = 3 pts. (6) No dehydration requiring IV fluids = 3 pts. (7) Age <60 years = 2 pts. Maximum score = 26. Score ≥21 = LOW RISK. CISNE SCORE (for solid tumor outpatients): ECOG PS ≥2 (2 pts), stress-induced hyperglycemia (2 pts), COPD (1 pt), cardiovascular disease (1 pt), NCI mucositis grade ≥2 (1 pt), monocytes <200/μL (1 pt). CISNE 0 = very low risk; CISNE 1–2 = low-intermediate; CISNE ≥3 = high risk. Physical exam: assess for focal infection source (sinuses, oral mucosa, pharynx, lung auscultation, skin including catheter sites, perirectal area — avoid digital rectal exam in neutropenic patients).",diagnostics:"MINIMUM WORKUP FOR ALL FN PATIENTS (regardless of risk): (1) Blood cultures — obtain AT LEAST 2 sets (4 bottles) before starting antibiotics. If central line present: 1 set from each catheter lumen AND 1 peripheral set (differential time-to-positivity >2 hours supports CLABSI). (2) CBC with differential — confirm ANC, assess platelet count (bleeding risk during procedures). (3) Comprehensive metabolic panel — assess renal and hepatic function (guides antibiotic dosing). (4) Urinalysis + urine culture. (5) Chest X-ray — if respiratory symptoms present; not required for all low-risk patients. (6) Additional cultures directed by symptoms (sputum, wound). LOW-RISK SPECIFIC: After initial IV evaluation and culture collection, low-risk patients (MASCC ≥21, CISNE 0, clinically stable) may be transitioned to oral therapy. IDSA 2010 recommends a period of IV observation in the ED or clinic (2–4 hours minimum) before oral step-down. Patients must meet ALL criteria before oral/outpatient management: afebrile for ≥1h after acetaminophen/NSAIDs, hemodynamically stable, tolerating oral intake, reliable patient/caregiver, prompt return access if deterioration, and close follow-up within 24 hours.",durationGuidance:{standard:"Continue until ANC ≥500 cells/μL AND afebrile for ≥48 hours. Minimum 3 days of antibiotics even if ANC recovers and fever resolves sooner. For low-risk patients with negative cultures who defervesce promptly: IDSA 2010 supports de-escalation to observation (without antibiotics) when ANC ≥500 cells/μL after ≥5–7 days of therapy in clinically well patients.",stewardshipNote:"IDSA 2010 (Strong, A-I): Low-risk patients who meet outpatient criteria can be managed entirely with oral antibiotics as outpatients after initial ED/clinic assessment and 2–4 hours of IV observation. Oral ciprofloxacin + amoxicillin-clavulanate is the recommended regimen. Avoid oral monotherapy with fluoroquinolone alone if the patient received fluoroquinolone prophylaxis (high risk of breakthrough on same class). Antibiotic stewardship in FN includes early oral step-down, de-escalation with culture-directed therapy, and avoiding unnecessary antifungal escalation without evidence of fungal infection."},empiricTherapy:[{line:"First-Line — Oral Outpatient (IDSA 2010, A-I for low-risk)",options:[{drug:"cipro-amox-clav",regimen:"Ciprofloxacin 500–750 mg PO q12h + Amoxicillin-Clavulanate 875/125 mg PO q12h",notes:"IDSA 2010 (Evidence: A-I). The STANDARD oral regimen for low-risk FN. Evidence basis: Freifeld et al. NEJM 1999 RCT. Ciprofloxacin provides antipseudomonal and gram-negative coverage; amoxicillin-clavulanate adds streptococcal coverage (viridans streptococcal risk from mucositis) and broadens spectrum. CRITICAL: This combination is essential — ciprofloxacin monotherapy is INADEQUATE (poor streptococcal coverage; viridans streptococcal bacteremia from mucositis can be rapidly fatal). Duration: continue until ANC ≥500 and afebrile ≥48h. IMPORTANT CAVEAT: If patient received fluoroquinolone prophylaxis, do NOT use ciprofloxacin as empiric therapy — consider IV antipseudomonal beta-lactam instead (risk of breakthrough infection with resistant organisms).",evidence:"A-I",evidenceSource:"IDSA 2010"},{drug:"levofloxacin-oral",regimen:"Levofloxacin 750 mg PO daily (if ciprofloxacin + amox-clav not tolerated)",notes:"Alternative for patients who cannot tolerate the combination regimen. Levofloxacin 750 mg daily provides broader spectrum than ciprofloxacin alone, including better streptococcal coverage. However, FDA fluoroquinolone safety label (2016): boxed warnings for tendinopathy, peripheral neuropathy, CNS effects, and aortic aneurysm — use with appropriate clinical judgment. SAME CAVEAT: do not use if patient was on fluoroquinolone prophylaxis. Evidence: B-II (IDSA 2010).",evidence:"B-II",evidenceSource:"IDSA 2010"}]},{line:"Initial IV (If Cannot Immediately Discharge — Observe and Step Down)",options:[{drug:"cefepime-initial",regimen:"Cefepime 2g IV q8h × first 2–4 hours during ED/clinic evaluation, then step down to oral if criteria met",notes:"For low-risk patients presenting to ED who are started on IV empirically: initiate cefepime or pip-tazo IV while cultures are collected and risk stratification is completed. If MASCC ≥21 and all outpatient criteria met after 2–4h of observation → transition to oral ciprofloxacin + amoxicillin-clavulanate. Do not delay oral step-down for low-risk patients who meet criteria. IV continuation not required and increases healthcare costs and risks (line infections, hospital-acquired complications).",evidence:"B-II",evidenceSource:"IDSA 2010"}]},{line:"Beta-Lactam Allergy — Low Risk",options:[{drug:"aztreonam-fn",regimen:"Aztreonam 2g IV q8h + Vancomycin 15–20 mg/kg IV q8–12h (for severe penicillin allergy precluding all beta-lactams)",notes:"For patients with documented severe IgE-mediated penicillin allergy where cross-reactivity with cephalosporins is a concern. Aztreonam provides gram-negative (including Pseudomonas) coverage. Add vancomycin for gram-positive coverage. Note: cross-reactivity between penicillin and cephalosporins is <1–2% in patients with confirmed penicillin allergy (sIgE to penicillin determinants). Most 'penicillin-allergic' patients can safely receive cefepime — consider allergy reconciliation before defaulting to aztreonam-based regimens.",evidence:"B-III",evidenceSource:"IDSA 2010"}]}],organismSpecific:[{organism:"Gram-Negative Bacteremia (E. coli, Klebsiella, Pseudomonas aeruginosa)",preferred:"De-escalate to pathogen-directed therapy based on susceptibilities. Pseudomonas: cefepime 2g IV q8h, pip-tazo 4.5g IV q6h, or meropenem 1g IV q8h. E. coli/Klebsiella (susceptible): ceftriaxone 2g IV daily or ciprofloxacin 500mg PO BID.",alternative:"Ciprofloxacin 400mg IV q12h (gram-negative, ciprofloxacin-susceptible). For ESBL producers: meropenem 1g IV q8h or ertapenem 1g IV daily.",notes:"Gram-negative bacteremia — though less frequent than gram-positives in the modern era — carries the highest mortality in FN (up to 30–50% in Pseudomonas BSI). Pseudomonas aeruginosa is the most feared pathogen: rapidly fatal if empiric coverage is delayed or inadequate. Any delay in appropriate antipseudomonal therapy >1–2 hours markedly worsens outcomes. Blood culture results typically return in 12–24h — adjust therapy immediately upon identification and susceptibility data. ESBL-producing E. coli and Klebsiella are increasingly common in FN patients with prior antibiotic exposure — know your institution's local rates."},{organism:"Viridans Group Streptococci (S. mitis, S. oralis, S. salivarius)",preferred:"Penicillin G 2–4 million units IV q4–6h OR ampicillin 2g IV q4h (if MIC ≤0.12 mcg/mL). Ceftriaxone 2g IV daily if intermediate penicillin susceptibility.",alternative:"Vancomycin 15–20 mg/kg IV q8–12h (AUC-guided) for penicillin-resistant isolates or anaphylaxis to beta-lactams. Linezolid 600mg IV/PO BID (salvage).",notes:"Viridans streptococci are the most common cause of gram-positive bacteremia in FN, particularly in patients with severe mucositis (NCI grade ≥3) from high-dose chemotherapy (AML induction, HSCT conditioning). The mucositis disrupts the oral mucosal barrier, allowing normal oropharyngeal flora to translocate. S. mitis and S. oralis can cause particularly severe sepsis syndrome (ARDS, multiorgan failure) in this setting — often called 'streptococcal toxic shock.' Penicillin resistance rates have increased (up to 25–30% in some institutions). This is the primary reason ciprofloxacin alone is NEVER adequate for low-risk FN — amoxicillin-clavulanate must be paired for streptococcal coverage. Antifungal prophylaxis (posaconazole) does NOT reduce viridans streptococcal risk."},{organism:"Coagulase-Negative Staphylococci (CoNS — S. epidermidis, S. haemolyticus)",preferred:"Vancomycin 15–20 mg/kg IV q8–12h (AUC/MIC target 400–600) if definitive CoNS bacteremia from a reliable culture source confirmed.",alternative:"Daptomycin 6–8 mg/kg IV daily if vancomycin intolerance or MIC creep. Linezolid 600mg IV/PO BID.",notes:"CoNS are the most common blood culture isolate in FN patients, but also the most common contaminant. A single positive bottle in a stable patient may represent contamination — wait for repeat culture positivity (≥2 sets) before committing to full vancomycin therapy. IDSA 2010 recommends AGAINST routine empiric vancomycin — add vancomycin for suspected CoNS bacteremia only when: multiple positive culture bottles from separate venipunctures, clinically deteriorating patient, or positive from peripheral blood AND catheter with differential time to positivity. OPAT with vancomycin IV or oral linezolid may be appropriate after catheter source assessment."},{organism:"Staphylococcus aureus (MSSA)",preferred:"Cefazolin 2g IV q8h (preferred over nafcillin — equivalent efficacy, less toxicity, q8h dosing for OPAT).",alternative:"Nafcillin 2g IV q4h or oxacillin 2g IV q4h if cefazolin unavailable. Dicloxacillin 500mg PO QID for oral step-down (limited data in FN).",notes:"MSSA is an uncommon but serious cause of FN bacteremia, usually from catheter or skin sources. De-escalate from vancomycin to cefazolin immediately upon MSSA identification — vancomycin is INFERIOR to beta-lactams for MSSA (slower bacteremia clearance, higher mortality). This de-escalation step is one of the highest-impact stewardship interventions in FN management. Evaluate for complications: endocarditis workup (TTE/TEE) if >3 days bacteremia, follow-up blood cultures to document clearance."}],pearls:["MASCC SCORE ≥21 IS REQUIRED — NOT OPTIONAL — before discharging a FN patient on oral antibiotics. Do not rely on clinical gestalt alone. Calculate the score explicitly and document it. Patients who 'look fine' but score <21 need IV therapy and inpatient management.","CIPROFLOXACIN ALONE IS NEVER ADEQUATE FOR LOW-RISK FN. The critical teaching point: oral ciprofloxacin has poor activity against viridans streptococci. Mucositis (common in chemotherapy patients) breaks down the oral mucosal barrier, allowing viridans streptococci to enter the bloodstream. Without the amoxicillin-clavulanate component, you will miss this pathogen. Always prescribe the combination.","FLUOROQUINOLONE PROPHYLAXIS CHANGES THE EMPIRIC APPROACH: If a patient was receiving FQ prophylaxis (ciprofloxacin or levofloxacin) and develops FN, do NOT use a fluoroquinolone as empiric therapy. These patients are at high risk for breakthrough bacteremia with FQ-resistant organisms (ESBL-producing Enterobacterales, resistant Pseudomonas). Use an antipseudomonal beta-lactam instead.","OUTPATIENT FN CRITERIA ARE STRICT — ALL MUST BE MET: (1) MASCC ≥21 AND CISNE 0–2, (2) Clinically stable (afebrile after antipyretics, SBP ≥90, HR <100, RR <20, O2 sat normal), (3) Tolerating oral medications, (4) No evidence of active infection source requiring IV access, (5) Reliable patient/caregiver with phone contact, (6) Access to emergency care within 1 hour, (7) Follow-up appointment within 24 hours arranged. Missing even one criterion = inpatient IV therapy.","24-HOUR FOLLOW-UP IS NON-NEGOTIABLE FOR OUTPATIENT FN. The 'window of risk' is the first 24–48 hours when cultures may turn positive and clinical deterioration can occur rapidly. A phone check at 12 hours + in-person reassessment at 24 hours is the minimum standard. Give patients explicit return precautions (worsening fever, rigors, hypotension, confusion, dyspnea) and ensure they understand to return IMMEDIATELY.","DO NOT ROUTINELY OBTAIN CHEST IMAGING IN ASYMPTOMATIC LOW-RISK FN. IDSA 2010: CXR is not required for all FN patients — reserve for those with respiratory symptoms (cough, dyspnea, desaturation). Routine CXR in asymptomatic FN has very low yield and adds cost/radiation. High-resolution CT chest is preferred over plain film when pulmonary infection is clinically suspected in the neutropenic host."]},{id:"high-risk-fn",name:"High-Risk Febrile Neutropenia",definition:"High-risk FN is defined by MASCC score <21, OR anticipated prolonged neutropenia (ANC <100 cells/μL expected for >7 days), OR profound neutropenia (ANC <100 cells/μL), OR significant comorbidities (hepatic/renal insufficiency, hemodynamic instability, uncontrolled malignancy), OR hematologic malignancy with active disease, OR allogeneic HSCT recipients. ALL high-risk patients require IMMEDIATE hospitalization and empiric IV antipseudomonal antibiotic therapy (within 60 minutes of triage). Any delay in appropriate empiric therapy in high-risk FN is directly associated with increased mortality — particularly for gram-negative bacteremia where the window for intervention is narrow.",clinicalPresentation:"High-risk patients may present with frank sepsis (hypotension, tachycardia, altered mentation, organ dysfunction) or with isolated fever and profound neutropenia (ANC <100) without obvious sepsis physiology — do not be reassured by a 'stable' appearance in the context of ANC <100. INITIAL ASSESSMENT: (1) Vital signs — any hemodynamic instability mandates immediate IV antibiotics + fluid resuscitation. (2) Oropharyngeal exam — grade mucositis (NCI grade 1–4): Grade 1 = erythema; Grade 2 = patchy ulcerations; Grade 3 = confluent ulcerations, unable to eat solid food; Grade 4 = tissue necrosis, unable to eat or drink. Grade ≥3 = viridans streptococcal risk + oral route CONTRAINDICATED. (3) Catheter sites — examine all lumens, tunneled catheter exit sites, and implanted port sites for erythema, discharge, tenderness. (4) Lung exam — new crackles or consolidation. (5) Skin — any eschars, purpuric lesions (bacteremia), necrotic skin (mold infection). (6) Abdomen — typhlitis (neutropenic enterocolitis): RLQ pain/tenderness in neutropenic patient = emergency; CT abdomen required. CALCULATE MASCC SCORE EXPLICITLY. Document ANC nadir, expected duration of neutropenia, and prior antibiotic/antifungal history.",diagnostics:"MANDATORY HIGH-RISK FN WORKUP: (1) Blood cultures × ≥2 sets from EACH catheter lumen AND peripheral venipuncture — simultaneous draw, document time of draw on each bottle. Differential time to positivity (DTTP) >2h from catheter vs peripheral = CLABSI (88% sensitivity, 90% specificity). (2) CBC with differential, CMP, LFTs — baseline for dosing and toxicity monitoring. (3) Urinalysis + urine culture. (4) CXR — all high-risk patients. (5) Procalcitonin (PCT) — obtain at baseline; PCT ≥0.5 ng/mL supports bacterial infection and may guide de-escalation or discontinuation. (6) Beta-D-glucan (BDG) + galactomannan (serum) — consider for patients with prolonged neutropenia >7 days or fever persisting >4 days despite antibiotics (pre-emptive antifungal strategy). (7) Additional source-directed cultures: sputum (if cough), stool for C. difficile PCR (if diarrhea), wound/ulcer swab. (8) CT chest (HIGH-RESOLUTION) — for ANY respiratory symptoms in neutropenic patient (plain CXR misses up to 40% of pulmonary infiltrates in neutropenia). CT abdomen/pelvis — for abdominal pain (typhlitis, appendicitis, colitis). (9) Ophthalmology consultation — if candidemia suspected (endophthalmitis in 10–15%). REPEAT CULTURES: At 48–72h if fever persists or clinical deterioration; do not repeat cultures routinely every 24h without clinical indication (low yield, increases contamination rates).",durationGuidance:{standard:"Until ANC ≥500 cells/μL sustained for ≥2 consecutive days AND afebrile for ≥48 hours AND clinical improvement. Minimum 7 days for most high-risk FN episodes.",severe:"14–21 days for documented bacterial infection (organism-specific therapy from first negative blood culture). 4–6 weeks for endocarditis or osteomyelitis. Duration of antifungal therapy: ≥14 days from first negative blood culture for candidemia (document clearance); ≥6–12 weeks for invasive aspergillosis.",opatNote:"OPAT (outpatient parenteral antibiotic therapy) may be appropriate for selected HIGH-RISK patients who have clinically stabilized after 5–7 days of inpatient IV therapy, have a new ANC trend upward (>200 cells/μL), are afebrile for ≥48h, and have no ongoing catheter-related issues. Cefepime IV q8h via pump, ertapenem 1g IV daily (if Pseudomonas risk low), or other regimens may be appropriate for OPAT. Must have home health nurse access and close ID follow-up.",stewardshipNote:"ANTIBIOTIC STEWARDSHIP IN HIGH-RISK FN: (1) De-escalate from antipseudomonal coverage to narrower spectrum once culture data available and patient stabilized (e.g., E. coli bacteremia → ceftriaxone or ciprofloxacin if susceptible). (2) Discontinue vancomycin at 48–72h if no gram-positive pathogen identified and patient improving (IDSA A-II). (3) Avoid adding metronidazole or anaerobic coverage empirically unless typhlitis or intra-abdominal infection suspected. (4) Procalcitonin-guided de-escalation: PCT <0.5 ng/mL (or >80% decline from peak) supports antibiotic discontinuation in afebrile, neutrophil-recovering patients. (5) Pre-emptive vs empiric antifungal strategy: using BDG/galactomannan to guide antifungal initiation rather than fever duration alone reduces unnecessary antifungal exposure by 20–30% without compromising outcomes."},empiricTherapy:[{line:"Monotherapy — Antipseudomonal Beta-Lactam (IDSA 2010 First-Line, A-I)",options:[{drug:"cefepime",regimen:"Cefepime 2g IV q8h",notes:"IDSA 2010 preferred first-line monotherapy (A-I). Fourth-generation cephalosporin with excellent antipseudomonal activity and broad gram-negative + gram-positive spectrum. Does NOT cover MRSA, Enterococcus, or anaerobes. DOSING NOTE: 2g q8h is the standard for FN; continuous infusion (6g over 24h by elastomeric pump) has pharmacodynamic advantages for organisms with higher MICs. RENAL DOSING: CrCl 30–60 → 1–2g q12h; CrCl 11–29 → 1–2g q24h; HD → 0.5–1g after each HD session. CNS TOXICITY RISK: neurotoxicity (encephalopathy, myoclonus, seizures) at higher exposures — especially in renal failure. Monitor closely in elderly and renally impaired patients. Consider EEG if altered mental status develops on cefepime.",evidence:"A-I",evidenceSource:"IDSA 2010"},{drug:"piperacillin-tazobactam",regimen:"Piperacillin-Tazobactam 4.5g IV q6h (or 3.375g IV q6h for less severe)",notes:"IDSA 2010 alternative first-line monotherapy (A-I). Broad-spectrum: antipseudomonal + anaerobic coverage + good gram-positive activity. Particularly advantageous when typhlitis, perirectal infection, or intra-abdominal source is suspected (anaerobic coverage included). Standard dosing: 4.5g IV q6h; extended infusion (3-hour infusion of 3.375g q8h or 4.5g q8h) pharmacodynamically superior for organisms with higher MICs — consider for critically ill patients or when Pseudomonas susceptibility is borderline. RENAL DOSING: CrCl 20–40 → 3.375g q8h; CrCl <20/HD → 2.25g q8h (additional 0.75g after HD). GALACTOMANNAN FALSE POSITIVES: pip-tazo can cause false-positive serum galactomannan — interpret serum GM cautiously in patients on pip-tazo; BAL GM preferred if pulmonary aspergillosis suspected.",evidence:"A-I",evidenceSource:"IDSA 2010"},{drug:"meropenem",regimen:"Meropenem 1g IV q8h (2g IV q8h for Pseudomonas or suspected resistant organisms)",notes:"IDSA 2010 alternative first-line monotherapy (A-I). Reserve as the broadest coverage option — covers Pseudomonas, ESBL producers, AmpC producers, anaerobes, streptococci. Preferred as empiric first-line in: (1) Patients with prior gram-negative bacteremia due to ESBL-producing organisms, (2) Recent hospitalization in regions with high ESBL prevalence, (3) Clinically unstable or septic shock presentations where broadest coverage is critical, (4) Suspected typhlitis or abdominal source. STEWARDSHIP NOTE: Carbapenems should not be used routinely as first-line when cefepime or pip-tazo are appropriate — carbapenem overuse drives carbapenem-resistant Enterobacterales (CRE) emergence. RENAL DOSING: CrCl 26–50 → 1g q12h; CrCl 10–25 → 500mg q12h; CrCl <10/HD → 500mg q24h.",evidence:"A-I",evidenceSource:"IDSA 2010"}]},{line:"ADD Vancomycin — Only If Specific Indications Present (IDSA 2010, A-I)",options:[{drug:"vancomycin-fn",regimen:"Vancomycin 25–30 mg/kg IV loading dose (actual body weight, max 3g), then 15–20 mg/kg IV q8–12h (AUC/MIC target 400–600 mcg·h/mL using Bayesian software)",notes:"IDSA 2010 (A-I): Vancomycin should NOT be routinely added to empiric FN therapy. Evidence shows routine addition of vancomycin does NOT improve outcomes, increases nephrotoxicity risk, and prolongs therapy duration unnecessarily. ADD VANCOMYCIN ONLY FOR THE FOLLOWING INDICATIONS: (1) Clinically apparent catheter-related infection (exit site erythema/discharge, tunneled catheter tenderness, positive blood cultures flagging from catheter before peripheral). (2) Skin or soft tissue infection (cellulitis, wound infection). (3) Hemodynamic instability or suspected septic shock (broader empiric coverage until source identified). (4) Blood cultures positive for gram-positive organisms (add while awaiting species ID and susceptibilities). (5) Suspected mucositis-associated viridans streptococcal sepsis (NCI grade 3–4 mucositis + severe sepsis picture). (6) Known MRSA colonization with new pulmonary infiltrates or bacteremia. REASSESSMENT AT 48–72H: Discontinue vancomycin if no gram-positive pathogen isolated and patient improving (A-II). AUC-GUIDED DOSING: 2020 ASHP/IDSA/SIDP consensus guidelines mandate AUC/MIC 400–600 monitoring over trough-based dosing — use Bayesian software (e.g., InsightRx, Vanderbilt AUC calculator).",evidence:"A-I",evidenceSource:"IDSA 2010"}]},{line:"ADD Metronidazole — For Suspected Anaerobic/Intra-Abdominal Source",options:[{drug:"metronidazole-fn",regimen:"Metronidazole 500mg IV q8h (or 1g IV q12h for extended infusion)",notes:"Add anaerobic coverage when: (1) Typhlitis (neutropenic enterocolitis) — RLQ pain + fever in neutropenic patient; CT-confirmed bowel wall thickening. (2) Perirectal abscess (do NOT perform digital rectal exam — can introduce bacteremia; use imaging). (3) Intra-abdominal source (diverticulitis, appendicitis). (4) Oral/dental source with suspected anaerobic involvement. NOTE: Piperacillin-tazobactam already has anaerobic coverage — metronidazole is redundant and should NOT be added if pip-tazo is the backbone agent. Add metronidazole only when cefepime or meropenem is used as the primary antipseudomonal agent in suspected anaerobic infection.",evidence:"B-III",evidenceSource:"IDSA 2010"}]},{line:"ADD Antifungal — Persistent Fever >4–7 Days Despite Antibiotics",options:[{drug:"micafungin-fn",regimen:"Micafungin 100–150 mg IV daily (echinocandin preferred if Candida suspected)",notes:"EMPIRIC ANTIFUNGAL: Add after 4–7 days of persistent fever despite adequate antibacterial therapy, in the setting of prolonged neutropenia. Echinocandin (micafungin, caspofungin, anidulafungin) preferred when: (1) Prior azole exposure or prophylaxis, (2) Hemodynamic instability, (3) Candida species unknown. Micafungin 100 mg daily (standard); 150 mg daily for higher-risk patients (obese, hematologic malignancy, critically ill). PRE-EMPTIVE STRATEGY: Many centers now use BDG and serum galactomannan at day 4–5 of persistent fever to guide antifungal initiation rather than fever duration alone — this reduces unnecessary antifungal therapy by 20–30% without compromising outcomes. BDG >80 pg/mL or serum GM >0.5 ODI supports antifungal initiation. Duration: minimum 14 days for candidemia from first negative blood culture; 6–12 weeks for invasive aspergillosis.",evidence:"A-I (Walsh 2004 trial)",evidenceSource:"IDSA 2010"},{drug:"voriconazole-fn",regimen:"Voriconazole 6 mg/kg IV q12h × 2 loading doses, then 4 mg/kg IV q12h; OR 200 mg PO q12h (if able to take orally)",notes:"PREFERRED when Aspergillus (or other mold) is suspected: CT chest showing halo sign, nodules, or cavitary lesions; prolonged neutropenia >10 days; HSCT recipient. Voriconazole covers Aspergillus fumigatus, A. flavus, A. niger (but NOT Mucorales). THERAPEUTIC DRUG MONITORING mandatory: target trough 1.0–5.5 mcg/mL. Supratherapeutic levels → hepatotoxicity, visual disturbances, encephalopathy. Subtherapeutic → treatment failure. SIGNIFICANT DRUG INTERACTIONS: inhibits CYP2C19, CYP2C9, CYP3A4 — major interactions with tacrolimus (reduce dose 66%), cyclosporine (reduce dose 50%), sirolimus (CONTRAINDICATED), carbamazepine, rifampin, phenytoin. Avoid in patients with CrCl <50 if using IV formulation (cyclodextrin vehicle accumulates; switch to PO).",evidence:"A-I (for suspected aspergillosis)",evidenceSource:"IDSA 2010"},{drug:"liposomal-amphotericin-fn",regimen:"Amphotericin B liposomal (AmBisome) 3 mg/kg IV daily",notes:"FOR EMPIRIC ANTIFUNGAL when echinocandin and azole are both contraindicated, or when Mucorales (mucormycosis) is suspected (CT chest showing reverse halo sign, rhinocerebral extension). Voriconazole has NO Mucorales activity — use amphotericin B or isavuconazole for suspected mucormycosis. NEPHROTOXICITY MONITORING: daily BMP (creatinine, potassium, magnesium, sodium). Pre-hydration with 1L NS reduces nephrotoxicity. Hypokalemia and hypomagnesemia are nearly universal — supplement aggressively. Avoid concurrent nephrotoxins (vancomycin, aminoglycosides, calcineurin inhibitors) when possible.",evidence:"A-I (Walsh 1999 trial)",evidenceSource:"IDSA 2010"}]},{line:"ADD MRSA Coverage — Specific High-Risk Scenarios",options:[{drug:"vancomycin-mrsa-fn",regimen:"Vancomycin IV (AUC/MIC 400–600) — see dosing above",notes:"ADD vancomycin for MRSA-specific coverage in: (1) Hemodynamic instability (septic shock) — until source clarified. (2) Skin or soft tissue infection (SSTI) with MRSA risk factors. (3) Central catheter infection with purulence/tunnel tract involvement. (4) Prior MRSA colonization or infection. (5) Chest CT showing necrotizing pneumonia or cavitary lesion consistent with MRSA. Discontinue at 48–72h if no MRSA/gram-positive pathogen confirmed. AUC-guided dosing is the standard — do not use trough-only monitoring.",evidence:"A-I",evidenceSource:"IDSA 2010"},{drug:"daptomycin-fn",regimen:"Daptomycin 6–10 mg/kg IV daily (higher doses for bacteremia/endocarditis)",notes:"ALTERNATIVE to vancomycin for gram-positive/MRSA coverage when: vancomycin MIC ≥2 (vancomycin heteroresistance), vancomycin nephrotoxicity, prior vancomycin failure, or concurrent nephrotoxic drug combinations. CONTRAINDICATED for pneumonia — daptomycin is inactivated by pulmonary surfactant. Monitor CPK weekly (myopathy risk, especially at higher doses). No need for TDM, but CPK monitoring essential.",evidence:"B-II",evidenceSource:"IDSA 2010"}]},{line:"Aminoglycoside — Do NOT Use as Routine Combination (A-I, Not Recommended)",options:[{drug:"amikacin-fn",regimen:"Amikacin 15–20 mg/kg IV once daily (extended-interval dosing) — ONLY if specific documented resistance scenario",notes:"IDSA 2010 (A-I): Aminoglycoside combination therapy with antipseudomonal beta-lactams is NOT recommended for routine FN empiric therapy. No mortality benefit from combination in RCTs; significantly higher nephrotoxicity and ototoxicity with combination therapy. SPECIFIC INDICATIONS (narrow): (1) Documented gram-negative bacteremia with resistant organism susceptible only to aminoglycoside + another agent (e.g., CRE with limited options), (2) Suspected Pseudomonas with carbapenem resistance and aminoglycoside susceptibility confirmed. Extended-interval dosing (15–20 mg/kg once daily) is standard; goal peak 56–64 mcg/mL and trough <1 mcg/mL (gentamicin/tobramycin: 5–7 mg/kg daily, peak 20–30, trough <1). Avoid in patients with CrCl <60 — dose adjustment required and toxicity risk high.",evidence:"A-I (not recommended routinely)",evidenceSource:"IDSA 2010"}]},{line:"G-CSF — Adjunctive Therapy for Selected High-Risk FN",options:[{drug:"filgrastim-fn",regimen:"Filgrastim (G-CSF) 5 mcg/kg/day SC (round to nearest vial: 300 mcg or 480 mcg) until ANC ≥1000–2000 cells/μL post-nadir; OR Pegfilgrastim 6 mg SC × 1 dose (NOT for acute FN treatment — prophylaxis only)",notes:"IDSA/ASCO G-CSF GUIDANCE: Therapeutic G-CSF (during FN episode) is recommended for patients with HIGH-RISK features: (1) Expected prolonged neutropenia >10 days, (2) Age >65, (3) Uncontrolled/progressive malignancy, (4) Documented pneumonia, septic shock, or invasive fungal infection, (5) Prior FN episode. G-CSF shortens duration of neutropenia by 1–3 days and reduces infectious complications. NOT universally recommended for all FN — low-risk patients with expected rapid ANC recovery do not clearly benefit. PEGFILGRASTIM TIMING: If patient received pegfilgrastim ≤14 days before current FN episode, the depot effect may still be active — check timing before re-administering. PRIMARY PROPHYLAXIS: Filgrastim or pegfilgrastim recommended when FN risk from chemotherapy regimen is ≥20%. SECONDARY PROPHYLAXIS: After a prior FN episode, G-CSF in subsequent cycles maintains dose intensity.",evidence:"A-I (high-risk features)",evidenceSource:"NCCN 2024"}]}],organismSpecific:[{organism:"Pseudomonas aeruginosa Bacteremia",preferred:"Cefepime 2g IV q8h (or pip-tazo 4.5g IV q6h) based on susceptibilities. If MDR Pseudomonas: meropenem 2g IV q8h (extended infusion 3h) + consider polymyxin B or ceftolozane-tazobactam if carbapenem-resistant.",alternative:"Ciprofloxacin 400mg IV q8h (if susceptible, and as de-escalation option). Ceftazidime-avibactam 2.5g IV q8h for carbapenem-resistant isolates with KPC or OXA-48 (NOT MBL). Ceftolozane-tazobactam 1.5g IV q8h for MDR Pseudomonas (MBL-producing strains).",notes:"Pseudomonas bacteremia carries the highest mortality of any organism in FN (up to 30–50%) — the primary reason antipseudomonal beta-lactams are first-line empiric therapy. Any delay in appropriate coverage is directly associated with mortality. DEFINITIVE THERAPY: Select the narrowest effective agent based on susceptibility data. Combination therapy (beta-lactam + FQ or aminoglycoside) is NOT superior to monotherapy with active agents in most clinical studies for non-ICU patients, but some experts prefer double coverage for severe Pseudomonas bacteremia or endocarditis. Monitor blood cultures for clearance. Echocardiography if bacteremia persists >3–5 days."},{organism:"ESBL-Producing E. coli or Klebsiella pneumoniae",preferred:"Meropenem 1g IV q8h (definitive therapy for ESBL bacteremia). Ertapenem 1g IV daily (acceptable for non-Pseudomonas ESBL bacteremia once stable — OPAT-friendly).",alternative:"Ceftazidime-avibactam 2.5g IV q8h if KPC-producing carbapenem-resistant Klebsiella (CRKp). Temocillin (European) for non-CNS/non-ESBL bacteremia if available. Fosfomycin (UTI only) or nitrofurantoin (UTI only) for ESBL urinary tract sources if susceptible.",notes:"ESBL-producing Enterobacterales are increasingly common in FN patients with prior healthcare exposure, prior fluoroquinolone prophylaxis, or travel to endemic regions. Carbapenems are the definitive treatment — cefepime is UNRELIABLE for ESBL bacteremia (inoculum effect, heteroresistance). Do NOT use third-generation cephalosporins (ceftriaxone, cefotaxime) for ESBL infections even if susceptibility testing shows 'susceptible.' Pip-tazo clinical outcomes data for ESBL bacteremia is conflicting — MERINO trial showed meropenem superior to pip-tazo for ESBL bacteremia (mortality 12.3% vs 3.7%, p=0.90 — actually substantially lower mortality with meropenem) — carbapenem is preferred for bacteremia. OPAT consideration: ertapenem 1g IV daily is a convenient once-daily option suitable for OPAT once patient is stable."},{organism:"Klebsiella pneumoniae Carbapenemase (KPC)-Producing CRE",preferred:"Ceftazidime-avibactam 2.5g IV q8h (first-line for KPC, OXA-48). Consider combination with aztreonam for MBL (metallo-beta-lactamase) producers (aztreonam 2g IV q6h + ceftazidime-avibactam for NDM/VIM/IMP).",alternative:"Meropenem-vaborbactam 4g IV q8h (3-hour infusion) for KPC-producing CRE. Imipenem-cilastatin-relebactam 1.25g IV q6h for KPC-producing CRE. Polymyxin B 1.25–1.5 mg/kg IV q12h in combination with meropenem or fosfomycin (salvage only).",notes:"CRE in FN carries mortality of 40–70% — one of the most feared pathogens in neutropenic oncology patients. INSTITUTIONAL AWARENESS: Know your hospital's CRE resistance mechanisms (KPC vs MBL vs OXA) — this determines which beta-lactam/beta-lactamase inhibitor combination is active. For NDM/VIM/IMP (MBL producers): ceftazidime-avibactam has NO MBL activity alone — combine with aztreonam. Rapid molecular testing (Verigene, BioFire) can identify resistance mechanisms from positive blood cultures within 2–4 hours — collaborate with pharmacy to ensure results are acted on immediately."},{organism:"Staphylococcus aureus MRSA — Catheter or Skin Source",preferred:"Vancomycin IV (AUC/MIC 400–600) — full SAB workup (follow-up cultures q24–48h, TTE/TEE, ID consult). Duration: minimum 14 days for uncomplicated SAB from first negative blood culture; 4–6 weeks for endocarditis.",alternative:"Daptomycin 8–10 mg/kg IV daily (for vancomycin MIC ≥2, intolerance, or persistent bacteremia on vancomycin). Ceftaroline 600mg IV q8h + daptomycin (salvage for persistent MRSA bacteremia).",notes:"MRSA SAB in neutropenic patients requires the same comprehensive workup as MRSA SAB in non-neutropenic patients — it is never a 'simple' line infection. Remove the central venous catheter as soon as possible (within 24–48h if attributable to line). Follow-up blood cultures every 24–48 hours until documented clearance — date of first negative blood culture is Day 1 of duration. ID consultation reduces mortality by 40–50% in SAB. Do NOT add rifampin to vancomycin for native-site MRSA bacteremia — ARREST trial showed no benefit and increased drug interactions."},{organism:"Enterococcus faecium (VRE) Bacteremia",preferred:"Daptomycin 6–10 mg/kg IV daily ± ampicillin (if ampicillin-susceptible, rare for E. faecium). Linezolid 600mg IV/PO BID (bacteriostatic — less preferred for bacteremia).",alternative:"For selected stable patients with VRE UTI source: nitrofurantoin or fosfomycin (non-bacteremic only). Quinupristin-dalfopristin (Q/D) for E. faecium only (NOT E. faecalis) — significant myalgia, hepatotoxicity; rarely used.",notes:"VRE bacteremia mortality in neutropenic patients is 25–40%. Source identification and control is critical (GI/rectal reservoir, perianal abscess, compromised GI mucosa). High-dose daptomycin (8–10 mg/kg) recommended for VRE bacteremia. If daptomycin MIC is rising (≥4 mcg/mL): consider daptomycin + ampicillin combination (paradoxically, ampicillin increases VRE susceptibility to daptomycin even in ampicillin-resistant strains by disrupting cell wall synthesis and enhancing daptomycin membrane binding). Linezolid is bacteriostatic — myelosuppression risk with prolonged use in already cytopenics patients; reserve for salvage or oral step-down."},{organism:"Candida Species (Candidemia in Neutropenic Host)",preferred:"Micafungin 100 mg IV daily (first-line, IDSA 2016 echinocandin recommendation). Caspofungin 70 mg IV load × 1, then 50 mg IV daily. Anidulafungin 200 mg IV load × 1, then 100 mg IV daily.",alternative:"Liposomal amphotericin B 3–5 mg/kg IV daily (for echinocandin resistance, CNS candidiasis, or C. auris with resistance). Fluconazole 800 mg IV/PO load × 1, then 400 mg IV/PO daily (de-escalation for C. albicans/tropicalis after identification and susceptibility confirm — NOT initial empiric).",notes:"Candidemia in neutropenic patients requires the same workup as non-neutropenic candidemia: (1) Repeat blood cultures every 24–48h until clearance — duration 14 days from first negative. (2) CVC removal (within 24–48h) reduces mortality. (3) Ophthalmology exam (after neutrophil recovery — funduscopy unreliable in severe neutropenia due to lack of inflammatory response). (4) Echocardiography if prolonged candidemia. C. parapsilosis: echinocandin MICs are higher (intrinsic FKS polymorphism) — de-escalate to fluconazole once species confirmed and patient stable. C. glabrata: maintain echinocandin, obtain FKS mutation testing if prior echinocandin exposure. C. auris: contact precautions, echinocandin preferred (MDR, often FQ/fluconazole resistant)."}],pearls:["ANTIBIOTICS WITHIN 60 MINUTES IN HIGH-RISK FN. This is not a goal — it is the standard. Mortality doubles for every hour of delay in appropriate empiric antibiotics for gram-negative bacteremia in neutropenia. Triage nurses and pharmacists must recognize FN as a sepsis-level emergency. If the pharmacy cannot dispense cefepime within 30 minutes of the order, escalate the process.","ANTIPSEUDOMONAL BETA-LACTAM MONOTHERAPY IS THE STANDARD — NOT DOUBLE COVERAGE. Decades of RCT data show combination therapy (e.g., cefepime + aminoglycoside, pip-tazo + vancomycin empirically) does NOT improve outcomes and increases toxicity. Monotherapy with cefepime, pip-tazo, or meropenem provides equivalent efficacy with less nephrotoxicity, less selection pressure, and simpler management. Resist the urge to add 'extra coverage' empirically.","VANCOMYCIN IS NOT PART OF ROUTINE EMPIRIC FN THERAPY. The IDSA 2010 guideline is explicit: routine empiric vancomycin does not improve outcomes in FN. It should be added ONLY for specific indications (catheter infection, skin/soft tissue infection, hemodynamic instability, gram-positive on rapid blood culture identification). Unnecessary vancomycin = nephrotoxicity + drug interactions + resistance selection. Set a 48–72h automatic stop order or reassessment.","CEFEPIME NEUROTOXICITY — KNOW THE RISK. Cefepime encephalopathy (confusion, myoclonus, nonconvulsive status epilepticus) is underrecognized and can be misattributed to metabolic encephalopathy, opioids, or disease progression. Risk factors: AKI, reduced CrCl (accumulation), older age, pre-existing CNS pathology. If an FN patient develops altered mental status on cefepime, check renal function, dose, and consider EEG. This is a pharmacist-critical monitoring point.","TYPHLITIS (NEUTROPENIC ENTEROCOLITIS) IS A SURGICAL AND MEDICAL EMERGENCY. RLQ pain in a neutropenic patient = presumptive typhlitis until proven otherwise. Obtain urgent CT abdomen/pelvis. Broaden antibiotic coverage to include anaerobes (metronidazole + pip-tazo or meropenem alone). Surgical consultation is essential — perforation is a life-threatening complication. Do NOT perform digital rectal exam — bacteremia risk. Serial abdominal exams every 4–6h in hospitalized neutropenic patients with abdominal symptoms.","G-CSF IN ACTIVE FN: Therapeutic G-CSF (filgrastim 5 mcg/kg/day SC) accelerates ANC recovery in high-risk FN but does NOT reduce mortality in most RCTs. Reserve for specific high-risk features: expected prolonged neutropenia >10 days, septic shock, pneumonia, invasive fungal infection, age >65, or progressive disease. Don't use G-CSF therapeutically for all FN episodes — the ASCO guidelines are clear that routine use in all FN patients is not recommended. PRIMARY PROPHYLAXIS is where G-CSF has the strongest evidence (≥20% FN risk)."]},{id:"fn-with-fungal-risk",name:"Febrile Neutropenia — Persistent / Fungal Risk",definition:"Persistent FN is defined as ongoing fever despite 4–7 days of adequate broad-spectrum antibacterial therapy, with negative or inconclusive bacterial cultures, in a neutropenic patient. This pattern strongly suggests an occult infection — most critically invasive fungal infection (IFI). IFI is the leading cause of infectious mortality in patients with prolonged neutropenia (ANC <500 for >10 days). The two dominant pathogens are Candida species (especially in HSCT recipients and patients with prolonged IV access/TPN) and Aspergillus species (especially in AML patients, allogeneic HSCT, and patients receiving high-dose corticosteroids). Empiric antifungal therapy is added at day 4–7, or earlier if: suggestive CT chest findings (halo sign, nodules), rising beta-D-glucan (BDG), positive serum galactomannan, or clinical deterioration.",clinicalPresentation:"Persistent fever in the neutropenic host after 4–7 days of antibacterial therapy, without an identified bacterial source. Clinical clues to fungal infection: PULMONARY: new onset cough, pleuritic chest pain, hemoptysis (Aspergillus — angioinvasive), dyspnea (PCP, diffuse candidiasis); CT CHEST: halo sign (ground-glass opacity surrounding a pulmonary nodule = early angioinvasive aspergillosis), air crescent sign (late finding, appearing with neutrophil recovery as necrotic tissue separates), reverse halo/atoll sign (suggests mucormycosis or organizing pneumonia), multiple bilateral nodules (hematogenous fungal dissemination). SINUS: nasal congestion, facial pain, epistaxis, periorbital swelling (Aspergillus sinusitis), black eschar on nasal mucosa (mucormycosis — a true emergency requiring urgent surgical debridement). SKIN: erythematous papules/nodules with central pallor (disseminated candidiasis), necrotic skin lesions (disseminated Aspergillus). HEPATOSPLENIC (CHRONIC DISSEMINATED) CANDIDIASIS: fever persisting AFTER ANC recovery, elevated ALP, 'bull's eye' lesions on CT/MRI of liver and spleen — occurs when neutrophils finally recover and mount inflammatory response against established Candida foci. OCULAR: candida endophthalmitis — white fluffy vitreous infiltrates on funduscopy (painful visual changes + FN + positive blood culture = urgent ophthalmology). BDG AND GALACTOMANNAN: BDG >80 pg/mL supports IFI diagnosis (sensitive but non-specific — false positives from pip-tazo, dialysis, beta-glucan-containing foods, Streptococcal bacteremia); galactomannan >0.5 ODI (serum) or >1.0 ODI (BAL) supports invasive aspergillosis. Serial monitoring twice weekly in high-risk patients increases sensitivity.",diagnostics:"FUNGAL DIAGNOSTIC WORKUP IN PERSISTENT FN: (1) CT Chest (HIGH-RESOLUTION): MANDATORY at day 4–5 of persistent fever despite antibiotics. Plain CXR has 40–60% sensitivity for pulmonary fungal infection in neutropenic patients — CT is required. Look for: halo sign (early IPA), air crescent sign (late IPA), reverse halo (mucormycosis), nodules, consolidation, cavitation. (2) Serum Galactomannan (GM): Obtain twice weekly in high-risk patients (AML, allogeneic HSCT). Sensitivity 60–80% for IPA in hematologic malignancy (lower in solid tumors, SOT, and non-neutropenic patients). FALSE POSITIVES: piperacillin-tazobactam (less common with newer formulations but still occurs), cross-reactivity with Histoplasma, Blastomyces, Penicillium, Fusarium, Alternaria; dietary sources (some pasta, cereals). (3) Serum Beta-D-Glucan (BDG): Twice weekly in high-risk prolonged neutropenia. Non-specific: elevated in Candida, Aspergillus, PCP, Fusarium — does NOT detect Mucorales (no glucan in cell wall). (4) BAL (Bronchoalveolar Lavage): If CT chest abnormality and patient can tolerate bronchoscopy (platelets >50k, no severe coagulopathy). BAL GM ≥1.0 ODI has higher specificity than serum; fungal culture, bacterial culture, PCP PCR, viral PCR (CMV, HHV-6, RSV, rhinovirus). (5) CT Sinuses/Neck: For sinus symptoms — early mucormycosis requires CT (bony erosion, extension to orbit or brain). (6) Ophthalmology Exam: For suspected candidemia — schedule after neutrophil recovery in neutropenic patients (funduscopic exam is unreliable during severe neutropenia). (7) Serum Cryptococcal Antigen (CrAg): For HSCT recipients or HIV-positive patients with meningeal symptoms or unexplained FN. (8) PCR-Based Assays: Aspergillus PCR (blood or BAL) — increasing validation as adjunct diagnostic; now an EORTC/MSG mycologic criterion. T2Candida Panel: rapid multiplex PCR from blood (3–5 hours) detecting 5 most common Candida species with sensitivity 91%, specificity 98% — useful for early species identification in suspected candidemia.",durationGuidance:{standard:"Empiric antifungal therapy: Continue until ANC ≥500 cells/μL for ≥2 days AND clinically well AND no documented fungal infection (can discontinue empiric antifungal without documented IFI if afebrile + ANC recovering). Documented candidemia: 14 days from FIRST NEGATIVE blood culture. Documented invasive aspergillosis: minimum 6–12 weeks, individualized based on immune status and radiographic response.",severe:"Invasive aspergillosis in HSCT/AML: 6–12 weeks minimum, often continued through subsequent immunosuppressive cycles as secondary prophylaxis. Mucormycosis: surgical debridement + amphotericin B ≥6 weeks (or until all necrotic tissue debrided and immune reconstitution achieved). Chronic disseminated candidiasis (hepatosplenic): azole therapy (fluconazole 400–800 mg daily) for ≥6 months or until all lesions resolved on imaging.",opatNote:"OPAT for antifungal therapy: Voriconazole (200 mg PO BID) and fluconazole (400–800 mg PO daily) have excellent oral bioavailability (>96% and ~90%, respectively) — transition to oral as soon as patient can take oral medications. Micafungin and other echinocandins are IV only — rezafungin (once-weekly echinocandin, FDA approved 2023) may enable less frequent IV dosing for OPAT-eligible patients with candidemia. Isavuconazole (372 mg PO daily — once-daily dosing) is a convenient option for Aspergillus OPAT.",stewardshipNote:"ANTIFUNGAL STEWARDSHIP IN FN: (1) Pre-emptive vs empiric antifungal: using BDG/GM biomarkers and CT findings to guide antifungal initiation (pre-emptive strategy) rather than fever duration alone reduces unnecessary antifungal exposure by 20–30% without compromising outcomes — implement in high-risk institutions. (2) Echinocandin-to-azole de-escalation: transition from echinocandin to oral fluconazole (C. albicans, C. tropicalis) or oral voriconazole/isavuconazole (Aspergillus) once species identified, patient stable, and cultures clearing. (3) IV-to-PO conversion: voriconazole and fluconazole have near-complete oral bioavailability — switch to oral the moment patient can swallow. (4) Antifungal prophylaxis review: ongoing prophylaxis with posaconazole 300 mg daily after AML induction reduces IFI by 75% — ensure appropriate patients are on posaconazole prophylaxis BEFORE the next chemotherapy cycle. (5) Duration limits: empiric antifungals without documented IFI should be discontinued when ANC recovers and fever resolves; no need to continue for an arbitrary fixed duration."},empiricTherapy:[{line:"Antifungal Prophylaxis — AML/MDS (Prevention Before FN Episode)",options:[{drug:"posaconazole-prophylaxis",regimen:"Posaconazole Delayed-Release Tablet (DRT) 300 mg PO daily (load 300 mg BID × 1 day) — PREFERRED over suspension",notes:"IDSA 2010 + NCCN 2024 (Category 1): Posaconazole is the PREFERRED antifungal prophylaxis for AML/MDS patients receiving induction or salvage chemotherapy expected to result in prolonged neutropenia (>7 days). Evidence: Cornely et al. NEJM 2007 — posaconazole reduced IFI (2% vs 8%, p<0.001) and invasive aspergillosis (1% vs 7%, p<0.001) vs fluconazole/itraconazole. DRUG FORMULATION MATTERS: Delayed-release tablet achieves more reliable PK than the suspension (suspension requires high-fat meal and acidic pH for absorption — unreliable in mucositis). Check TDM: target trough ≥0.5–0.7 mcg/mL for prophylaxis (obtain within first week). MAJOR DRUG INTERACTIONS: posaconazole is a strong CYP3A4 inhibitor — increases tacrolimus, cyclosporine, sirolimus, midazolam, statins, vincristine (vincristine neurotoxicity!). Avoid coadministration with rifampin, carbamazepine, phenytoin (reduce posaconazole levels by 80%). CHECK QTCF: posaconazole prolongs QTc — avoid with other QT-prolonging agents if possible.",evidence:"A-I",evidenceSource:"IDSA 2010"},{drug:"fluconazole-prophylaxis",regimen:"Fluconazole 400 mg PO/IV daily (for allogeneic HSCT — engraftment through day +75; for patients with lower IPA risk)",notes:"Fluconazole prophylaxis is recommended for allogeneic HSCT recipients during the engraftment phase (conditioning through day +75 or longer if prolonged neutropenia). Evidence: multiple RCTs demonstrating reduction in candidiasis and candidemia mortality. LIMITATION: NO ASPERGILLUS ACTIVITY — fluconazole does not prevent invasive mold infections. In centers with high Aspergillus prevalence or for patients receiving intensive conditioning (matched unrelated donor, cord blood, haploidentical), posaconazole or voriconazole is preferred. Fluconazole is appropriate for standard myeloablative HSCT in centers with low Aspergillus incidence.",evidence:"A-I (for HSCT engraftment phase)",evidenceSource:"IDSA 2010"},{drug:"voriconazole-prophylaxis",regimen:"Voriconazole 200 mg PO q12h (avoid high-fat meals; TDM trough target 1.0–5.5 mcg/mL)",notes:"Voriconazole prophylaxis for allogeneic HSCT recipients with high Aspergillus risk (unrelated donor, cord blood, significant GVHD, prolonged steroid use). Evidence: Wingard et al. Blood 2010 — reduced invasive aspergillosis vs fluconazole (1.5% vs 3%, p=0.02) in allogeneic HSCT. Comparable aspergillosis prevention to posaconazole with less favorable tolerability (visual disturbances, hepatotoxicity, phototoxicity, QTc effects). TDM mandatory. IMPORTANT: voriconazole has NO Mucorales activity — if mucormycosis is a concern, choose posaconazole or liposomal amphotericin B. Breakthrough mucormycosis on voriconazole prophylaxis has been reported.",evidence:"B-I",evidenceSource:"NCCN 2024"}]},{line:"Antibacterial Prophylaxis — High-Risk Prolonged Neutropenia",options:[{drug:"ciprofloxacin-ppx",regimen:"Ciprofloxacin 500 mg PO BID — for expected neutropenia >7 days (AML induction, HSCT)",notes:"IDSA 2010 (A-I): Fluoroquinolone prophylaxis reduces FN incidence by 50% and infection-related mortality in patients expected to have prolonged profound neutropenia. NCCN 2024 recommends fluoroquinolone prophylaxis for: neutropenia expected >7 days (AML induction, intensive lymphoma regimens, HSCT). CRITICAL CAVEATS: (1) Increased FQ resistance — widespread prophylaxis selects for FQ-resistant gram-negatives (especially ESBL-producing E. coli). If FN develops while on FQ prophylaxis, use IV antipseudomonal beta-lactam (NOT a fluoroquinolone). (2) C. difficile risk — FQ prophylaxis increases CDI risk; concomitant proton pump inhibitors further increase risk. Monitor for diarrhea. (3) QTc effects if combined with azole antifungals. Levofloxacin 500 mg PO daily is an alternative — CALGB 10403 and other trials show similar efficacy to ciprofloxacin.",evidence:"A-I",evidenceSource:"IDSA 2010"}]},{line:"Empiric Antifungal — Persistent Fever Day 4–7 (If Candida Pattern Suspected)",options:[{drug:"micafungin-empiric",regimen:"Micafungin 100–150 mg IV daily",notes:"PREFERRED empiric antifungal at 4–7 days of persistent FN when: Candida is more likely than Aspergillus (shorter neutropenia duration, solid tumor, prior candidiasis, no new CT chest findings), prior azole prophylaxis use, hemodynamically unstable patient (avoid azoles until stable). Evidence: Walsh et al. NEJM 2004 (caspofungin non-inferior to liposomal AmB). Broad Candida spectrum; NO activity against Aspergillus or Mucorales. Once Candida species identified and susceptibility confirmed: de-escalate to fluconazole 400 mg PO daily if fluconazole-susceptible and patient stable.",evidence:"A-I",evidenceSource:"IDSA 2010"},{drug:"caspofungin-empiric",regimen:"Caspofungin 70 mg IV × 1 load, then 50 mg IV daily",notes:"Alternative echinocandin for empiric antifungal in persistent FN. FDA-approved indication for empiric antifungal in FN (the only echinocandin with this labeled indication, though all are used). Evidence: Walsh 2004 NEJM trial compared caspofungin vs liposomal AmB — caspofungin was non-inferior with better tolerability. More drug interactions than micafungin or anidulafungin (cyclosporine — hepatotoxicity; rifampin — reduces caspofungin levels requiring 70 mg daily maintenance dose). Hepatic dose adjustment: Child-Pugh B → 35 mg daily after load.",evidence:"A-I",evidenceSource:"IDSA 2010"}]},{line:"Empiric/Pre-emptive Antifungal — Persistent Fever + Mold Risk (CT Chest Abnormality or Galactomannan Positive)",options:[{drug:"voriconazole-empiric-fn",regimen:"Voriconazole 6 mg/kg IV q12h × 2 loading doses, then 4 mg/kg IV q12h; transition to 200 mg PO q12h when stable. TDM trough target 1.0–5.5 mcg/mL.",notes:"PREFERRED for suspected invasive aspergillosis (halo sign on CT, positive galactomannan, prolonged neutropenia >10 days, HSCT recipient, high-dose corticosteroids). Evidence: IDSA 2016 aspergillosis guidelines — voriconazole first-line for IPA. MONITORING: obtain first trough on day 5; check LFTs, visual symptoms, and QTc weekly. MAJOR INTERACTIONS: inhibits CYP2C19/2C9/3A4 — reduce tacrolimus by 66%, cyclosporine by 50%; CONTRAINDICATED with sirolimus, rifampin, carbamazepine. IV formulation contains cyclodextrin vehicle — accumulates in CrCl <50; switch to oral PO if renal impairment develops.",evidence:"A-I (for suspected IPA)",evidenceSource:"IDSA 2010"},{drug:"isavuconazole-empiric-fn",regimen:"Isavuconazonium sulfate (CRESEMBA) 372 mg (= 200 mg isavuconazole) IV/PO q8h × 6 doses over 48 hours (loading phase), then 372 mg IV/PO daily",notes:"ALTERNATIVE to voriconazole for suspected IPA with advantages: (1) No QTc prolongation (shortens QTc — avoid in short QT syndrome), (2) IV without cyclodextrin — safe in all levels of renal impairment, (3) Less visual disturbances, (4) Covers Mucorales (unlike voriconazole) — preferred when diagnosis uncertain between aspergillosis and mucormycosis, (5) Once-daily dosing after load, (6) More predictable pharmacokinetics (TDM less critical but still recommended). Evidence: SECURE trial (Maertens 2016) — non-inferior to voriconazole for primary IPA therapy. NCCN 2024: isavuconazole is preferred by many hematology centers as first-line for IPA due to better tolerability profile.",evidence:"A-I (non-inferior to voriconazole)",evidenceSource:"NCCN 2024"},{drug:"liposomal-amphotericin-empiric-fn",regimen:"Amphotericin B liposomal (AmBisome) 3 mg/kg IV daily (increase to 5 mg/kg for CNS or severe disease; 5–10 mg/kg for mucormycosis)",notes:"FOR EMPIRIC ANTIFUNGAL: When azoles cannot be used (severe drug interactions, hepatotoxicity, azole-resistant organism suspected) or when Mucorales is the primary concern (CT showing reverse halo sign, sinus/palatal involvement, rhinocerebral extension). WALSH 1999 TRIAL: liposomal AmB equivalent to conventional AmB for empiric FN antifungal with less nephrotoxicity (19% vs 34% creatinine doubling) and fewer infusion reactions. NEPHROTOXICITY MANAGEMENT: Pre-hydrate with 1L NS before each infusion. Aggressive electrolyte replacement (hypokalemia and hypomagnesemia are near-universal). Monitor daily BMP. Avoid concurrent nephrotoxins. Target K+ ≥3.5, Mg2+ ≥1.8 with IV replacement as needed.",evidence:"A-I",evidenceSource:"IDSA 2010"}]},{line:"Mucormycosis — Surgical Emergency + Antifungal",options:[{drug:"liposomal-amphotericin-mucor",regimen:"Amphotericin B liposomal 5–10 mg/kg IV daily + Urgent surgical debridement + Reverse immunosuppression (reduce steroids, manage hyperglycemia, correct acidosis)",notes:"MUCORMYCOSIS IS A SURGICAL AND MEDICAL EMERGENCY. Any delay in surgical debridement (including rhinosinusitis, orbital involvement, cutaneous necrotizing infection) worsens prognosis dramatically. ANTIFUNGAL: High-dose liposomal AmB (5 mg/kg minimum; some centers use 7.5–10 mg/kg for CNS or disseminated disease). Posaconazole (300 mg PO/IV daily) or isavuconazole (372 mg daily after loading) are step-down options after clinical improvement and surgery. VORICONAZOLE IS INEFFECTIVE AGAINST MUCORALES — do not use. CT imaging of sinuses, orbits, and brain is mandatory. PET/CT may define extent of disease. Correct all predisposing factors: hyperglycemia, acidosis (DKA predisposes), iron overload (deferasirox has in vitro anti-Mucorales activity; clinical benefit uncertain), reduce steroids as much as oncologically acceptable. Adjunctive hyperbaric oxygen — limited data, center-specific.",evidence:"A-II (AmB) + surgical (mandatory)",evidenceSource:"IDSA 2010"}]},{line:"PCP (Pneumocystis jirovecii Pneumonia) — Prophylaxis and Treatment",options:[{drug:"tmp-smx-pcp",regimen:"TMP-SMX (Bactrim DS) 1 DS tablet (160/800 mg) PO daily OR 1 SS tablet daily OR 1 DS tablet PO TIW — PROPHYLAXIS. TMP-SMX 15–20 mg/kg/day IV (of TMP component) divided q6–8h — TREATMENT",notes:"PCP PROPHYLAXIS: Required for patients on ≥20 mg/day of prednisone equivalent for ≥1 month, patients with CD4 <200 (HIV+), HSCT recipients (through day +180 or longer with ongoing immunosuppression), patients receiving temozolomide, fludarabine, or other T-cell depleting agents. TMP-SMX is first-line prophylaxis — also provides prophylaxis against Toxoplasma and bacterial infections. ALTERNATIVES for TMP-SMX intolerance: Dapsone 100 mg PO daily (check G6PD first), atovaquone 1500 mg PO daily with fatty food, inhaled pentamidine 300 mg monthly via Respigard nebulizer. TREATMENT of confirmed PCP: TMP-SMX 15–20 mg/kg/day IV × 21 days + prednisone 40 mg BID × 5 days then taper (if PaO2 <70 mmHg or A-a gradient >35). TOXICITY: Myelosuppression, renal impairment, hypersensitivity (rash, fever, SJS — rare). Monitoring: CBC weekly, CMP.",evidence:"A-I (prophylaxis)",evidenceSource:"NCCN 2024"}]}],organismSpecific:[{organism:"Aspergillus fumigatus (IPA)",preferred:"Voriconazole 6 mg/kg IV q12h × 2 load doses, then 4 mg/kg IV q12h (TDM trough 1.0–5.5 mcg/mL). OR Isavuconazole 372 mg q8h × 6 doses, then 372 mg daily.",alternative:"Liposomal amphotericin B 3–5 mg/kg IV daily (if voriconazole not tolerated or azole resistance suspected). Caspofungin/micafungin (in combination or salvage — NOT monotherapy for IPA).",notes:"A. fumigatus causes >90% of invasive aspergillosis in neutropenic patients. Angioinvasive — penetrates blood vessel walls causing hemorrhagic infarction and high mortality. Triazole resistance (TR34/L98H mutation) is increasing globally (~1–3% in US, higher in Netherlands/UK) — consider if treatment failure, refractory disease, or patient traveled to high-prevalence region. Combination therapy (voriconazole + echinocandin): consider for severe/refractory IPA with high galactomannan burden — Marr et al. 2015 (subgroup with proven IPA showed mortality benefit). Minimum treatment duration: 6–12 weeks from diagnosis, individualized by immune reconstitution and radiographic response. Secondary prophylaxis recommended during subsequent immunosuppressive cycles."},{organism:"Mucor/Rhizopus (Mucormycosis)",preferred:"Liposomal amphotericin B 5–10 mg/kg IV daily + urgent surgical debridement + reverse immunosuppression + correct hyperglycemia/acidosis.",alternative:"Isavuconazole 372 mg daily (step-down or if AmB not tolerated). Posaconazole 300 mg daily (step-down after AmB induction). Amphotericin B + posaconazole or isavuconazole combination (limited data).",notes:"Mucormycosis mortality is 40–80% — early recognition and aggressive surgery are paramount. Rhinosinusitis form: black eschar on nasal mucosa, palate necrosis, proptosis, facial swelling — these are LATE signs; treat before they appear. Pulmonary form: reverse halo sign (atoll sign) on CT chest is suggestive but not pathognomonic. CRITICAL DIAGNOSTIC: tissue biopsy with culture and histopathology is required for definitive diagnosis (serum GM and BDG are NEGATIVE in mucormycosis — do not use to rule in/out). Iron availability is a key virulence factor — avoid deferoxamine (iron chelator that PROVIDES iron to Mucorales and worsens infection); deferasirox has in vitro activity but clinical benefit unproven."},{organism:"Candida albicans (Candidemia, Hepatosplenic)",preferred:"Micafungin 100 mg IV daily → de-escalate to fluconazole 400 mg PO daily after confirmation of susceptibility + clinical stability. For hepatosplenic candidiasis: fluconazole 400–800 mg PO daily × ≥6 months.",alternative:"Caspofungin or anidulafungin (alternative echinocandins). Liposomal AmB if CNS involvement.",notes:"Hepatosplenic (chronic disseminated) candidiasis presents paradoxically AFTER neutrophil recovery — rising ALP, persistent fever, and 'bull's eye' lesions on CT/MRI. The inflammatory response (neutrophil influx) unmasks existing candidal foci. Treatment requires prolonged azole therapy (minimum 6 months, until complete resolution on imaging). Do not discontinue early — relapse rates are high. IFN-γ adjunct therapy has been used in refractory cases (limited data). Liposomal AmB can be used for induction followed by fluconazole step-down."},{organism:"Pneumocystis jirovecii (PCP)",preferred:"TMP-SMX 15–20 mg/kg/day IV (of TMP component) divided q6–8h × 21 days + prednisone 40 mg BID × 5 days → 40 mg daily × 5 days → 20 mg daily × 11 days (if hypoxic: PaO2 <70 or A-a gradient >35).",alternative:"Pentamidine 4 mg/kg IV daily × 21 days (if TMP-SMX not tolerated — significant toxicity: hypoglycemia, nephrotoxicity, hypotension). Atovaquone 750 mg PO BID × 21 days (mild-moderate PCP, can take orally). Primaquine + clindamycin (mild-moderate PCP alternative).",notes:"PCP in neutropenic/immunocompromised patients presents differently from HIV-PCP: more acute onset (days not weeks), less insidious, higher oxygen requirement, more heterogeneous CT findings. BAL is the diagnostic test of choice (induced sputum has lower sensitivity in non-HIV). PCP PCR from BAL is highly sensitive but can detect colonization — interpret in clinical context. Treat any immunocompromised patient with new diffuse bilateral infiltrates and hypoxia for PCP empirically while awaiting BAL confirmation. Prophylaxis compliance monitoring is a key pharmacist role."}],pearls:["POSACONAZOLE PROPHYLAXIS IN AML: THIS IS ONE OF THE HIGHEST-IMPACT INTERVENTIONS IN FN MANAGEMENT. The 2007 NEJM trial showed posaconazole reduced IFI from 8% to 2% and improved survival in AML/MDS patients. Use the DELAYED-RELEASE TABLET (not suspension — absorption is unreliable with mucositis, vomiting, and variable gastric pH). Verify posaconazole levels if clinical concern for prophylaxis failure (target trough ≥0.5–0.7 mcg/mL). Document that the next cycle of AML induction includes posaconazole on the discharge/outpatient medication reconciliation.","GALACTOMANNAN INTERPRETATION REQUIRES CONTEXT. A positive serum GM (≥0.5 ODI) in a patient on pip-tazo may be a false positive (pip-tazo contains piperazine-based beta-lactam fragments that cross-react with the GM assay — though newer formulations have reduced this, it still occurs). Repeat GM or switch to BAL GM (more specific) if pip-tazo is the primary antibiotic. Conversely, a NEGATIVE GM does not exclude aspergillosis in patients on voriconazole or posaconazole prophylaxis (antifungals suppress galactomannan release).","BETA-D-GLUCAN FALSE POSITIVES ARE COMMON IN FN PATIENTS. BDG is elevated by: (1) IVIG or albumin infusion (contains glucan), (2) Hemodialysis (cellulose membrane), (3) TMP-SMX (Bactrim), (4) Pip-tazo, (5) Amoxicillin-clavulanate, (6) Bacteremia with Gram-positive organisms (especially Streptococcus), (7) Surgical gauze or sponges left in body cavities. A positive BDG in the context of these exposures is non-specific. BDG is most useful as a NEGATIVE PREDICTIVE test — a persistently negative BDG makes IFI unlikely (sensitivity 77–80% for candidemia, 70–90% for aspergillosis). Monitor trends, not single values.","MUCOSITIS GRADE DETERMINES ORAL ROUTE VIABILITY. NCI Mucositis Grading: Grade 1 = erythema, minimal pain, eating normally; Grade 2 = patchy ulcerations, modified diet; Grade 3 = confluent ulcerations, unable to eat solid food, IV hydration needed; Grade 4 = tissue necrosis, severe pain, unable to eat or drink, parenteral nutrition. KEY THRESHOLDS: Grade ≥2 = oral fluoroquinolone + amox-clav is not reliable (absorption unpredictable, GI transit rapid). Grade ≥2 mucositis = ORAL ROUTE CONTRAINDICATED for antibiotics; use IV. Additionally, grade ≥2 = HIGH RISK for viridans streptococcal bacteremia from mucosal translocation — vancomycin coverage should be lower threshold in this setting. Grade ≥3 mucositis = viridans streptococcal sepsis risk VERY HIGH — consider prophylactic penicillin or ampicillin in selected patients (not standard, institution-specific).","G-CSF PRIMARY PROPHYLAXIS THRESHOLDS — KNOW THESE COLD. ASCO/NCCN guidelines: G-CSF PRIMARY PROPHYLAXIS recommended when FN risk ≥20%. High-risk chemotherapy regimens (>20% FN risk): CHOP-21 (DLBCL), dose-dense AC (breast), docetaxel-based regimens, TAC (breast), FOLFOX/FOLFIRI with bevacizumab, AML induction, HSCT conditioning. Intermediate-risk (10–20%): R-CVP, CHOP-14, ABVD. For intermediate-risk patients, additional risk factors (age >65, prior chemo/RT, poor performance status, HIV, open wounds, baseline cytopenias) push into primary prophylaxis territory. PEGFILGRASTIM: preferred over filgrastim for convenience (single SC injection given 24–72h AFTER last chemotherapy dose and ≥14 days before next cycle). On-body injector allows same-day administration. Never give pegfilgrastim within 24h before chemotherapy (stimulates proliferating cells that will be killed by chemo).","FLUOROQUINOLONE PROPHYLAXIS CREATES A DIAGNOSTIC AND THERAPEUTIC DILEMMA. If a patient receives FQ prophylaxis and develops FN: (1) The causative organism may be FQ-resistant — do NOT use ciprofloxacin or levofloxacin empirically. (2) Use IV antipseudomonal beta-lactam (cefepime 2g q8h) regardless of MASCC score (cannot safely use oral FQ-based regimen). (3) Blood cultures from FQ-prophylaxis recipients have higher rates of gram-negative resistance and ESBL-producing organisms — request extended susceptibility testing. (4) C. difficile risk is increased after FQ exposure — monitor for diarrhea. This is one of the key reasons antibiotic stewardship in oncology should assess whether FQ prophylaxis is truly indicated for each individual patient."]}],drugMonographs:[]},I={id:"diabetic-foot",name:"Diabetic Foot Infections",icon:"🦶",category:"Infectious Disease",overview:{definition:"Diabetic foot infections (DFI) are infections of soft tissue and/or bone in the foot of a patient with diabetes mellitus, typically arising from a neuropathic, ischemic, or neuroischemic ulcer. The IDSA/IWGDF 2023 guidelines classify DFI by severity: uninfected (Grade 1 — wound without clinical infection), mild (Grade 2 — superficial skin/subcutaneous tissue infection, ≤2cm perilesional erythema), moderate (Grade 3 — deeper soft tissue infection OR >2cm erythema OR systemic/metabolic stability preserved despite deep involvement), and severe (Grade 4 — DFI with ≥2 SIRS criteria: fever >38°C or <36°C, HR >90, RR >20, WBC >12,000 or <4,000 or >10% bands). DFI is distinct from other SSTIs because of the critical interplay between infection, peripheral neuropathy, peripheral arterial disease (PAD), and poor wound healing intrinsic to diabetes. Antibiotics treat infection — they do not heal wounds or improve vascular supply. Multidisciplinary care is mandatory.",epidemiology:"Diabetic foot complications are the leading cause of non-traumatic lower extremity amputation worldwide. Approximately 15-25% of people with diabetes will develop a foot ulcer during their lifetime. Of diabetic foot ulcers (DFUs), 50-60% become infected at some point. Infected DFUs account for up to 20% of diabetes-related hospitalizations in the US. DFI-related amputations carry a 5-year mortality of 50-70%, rivaling many malignancies. Osteomyelitis complicates 20-60% of moderate-severe DFIs and is the primary driver of amputation decisions. Healthcare costs for DFI exceed $9 billion annually in the US. Prevalence is increasing with the global diabetes epidemic.",keyGuidelines:[{name:"IDSA/IWGDF 2023 Diabetic Foot Infection Guidelines",detail:"The most current and comprehensive guideline for DFI management, jointly published by the Infectious Diseases Society of America and the International Working Group on the Diabetic Foot. Key updates from prior versions: (1) Endorsement of shorter antibiotic courses for soft tissue DFI (1-2 weeks mild, 2-3 weeks moderate-severe); (2) Post-resection osteomyelitis antibiotic courses as short as 5 days if clean bone margins confirmed; (3) Strong emphasis on bone biopsy for osteomyelitis diagnosis and culture-directed therapy; (4) MRI as gold-standard imaging for suspected osteomyelitis; (5) Multidisciplinary foot care team recommended as standard of care; (6) OPAT and oral step-down (OVIVA principles) explicitly endorsed for appropriate candidates. Evidence graded A-I through C-III."},{name:"IWGDF 2023 Wound Classification Guidelines",detail:"The IWGDF provides the foundational wound classification system used to stratify DFI severity. The SINBAD score (Site, Ischemia, Neuropathy, Bacterial infection, Area, Depth) and the WIFi classification (Wound, Ischemia, Foot Infection) are recommended for systematic wound assessment. These classifications predict amputation risk, guide surgical decision-making, and inform antibiotic duration. The Wound, Ischemia, and Foot Infection (WIFi) threat level (very low, low, moderate, high) drives the vascular and surgical intervention pathway."},{name:"Wagner Wound Classification (1981, widely used)",detail:"The Wagner grading system classifies diabetic foot wounds by depth and tissue involvement: Grade 0 (intact skin, but at risk), Grade 1 (superficial ulcer — dermis only), Grade 2 (deep ulcer — to tendon/capsule/bone without abscess), Grade 3 (deep ulcer with abscess, osteomyelitis, or joint sepsis), Grade 4 (gangrene of part of foot), Grade 5 (gangrene of whole foot). Wagner Grade 3 and above have the highest amputation risk and require aggressive surgical and antibiotic management."},{name:"University of Texas (UT) Wound Classification System",detail:"A 2-dimensional classification system combining wound depth (Grades 0-III) with presence/absence of infection (stage A — no infection/ischemia, B — infection only, C — ischemia only, D — infection + ischemia). UT Grade IIID (full-thickness wound + osteomyelitis/joint infection + ischemia) has the highest amputation risk (~90%). The UT system is more predictive of outcomes than the Wagner system and is recommended by IWGDF 2023."},{name:"OVIVA Trial (Li et al., NEJM 2019)",detail:"Landmark RCT demonstrating oral antibiotics are non-inferior to IV antibiotics for bone and joint infections including osteomyelitis. Treatment failure: 14.6% (oral) vs 14.8% (IV). Established the principle of early oral step-down as acceptable for osteomyelitis when appropriate high-bioavailability agents are used. Directly applicable to DFI osteomyelitis management per IDSA/IWGDF 2023."}],landmarkTrials:[{name:"OVIVA Trial (Li et al., NEJM 2019)",detail:"1,054 patients with bone and joint infections randomized to oral vs. continued IV antibiotics after ≤7 days of IV therapy. Primary outcome (treatment failure at 1 year): 14.6% oral vs 14.8% IV — non-inferior. Oral step-down included fluoroquinolones, linezolid, TMP-SMX, rifampin combinations, and clindamycin. NOT amoxicillin or cephalexin alone. This trial changed the landscape: routine 6-week IV therapy via PICC is no longer required for osteomyelitis, including DFI-related osteomyelitis. Key caveats: the RIGHT oral agents must be selected (high bioavailability + bone penetration)."},{name:"Ertapenem vs Pip-Tazo for DFI — Lipsky et al. (2005, Clin Infect Dis)",detail:"Multicenter RCT of ertapenem (1g IV once daily) vs. piperacillin-tazobactam (3.375g IV q6h) for moderate-severe DFI. Clinical success rates were equivalent (~75% per arm). Ertapenem's once-daily dosing was associated with fewer complications and was deemed more convenient for OPAT. Established ertapenem as a first-line option for moderate DFI and OPAT step-down (with caveats — no Pseudomonas or MRSA coverage)."},{name:"IDSA Post-Op Osteomyelitis Duration Study — Ha Van et al. (2003)",detail:"Prospective cohort showing that for DFI osteomyelitis with complete surgical resection of all infected bone (confirmed histologically), a median antibiotic course of only 5-7 days post-operatively was associated with >90% remission at 1 year. This landmark observation shifted practice dramatically — adequate surgical resection substantially reduces antibiotic duration requirements. Endorsed by IDSA/IWGDF 2023."},{name:"Probe-to-Bone Test — Lavery et al. Validation Cohort",detail:"In patients with high pre-test probability (clinic population with DFI), the probe-to-bone (PTB) test has PPV of 89% for osteomyelitis. In patients with lower pre-test probability (ED population), PPV drops to ~53%. Sensitivity 66%, specificity 85% overall. The PTB test is recommended by IDSA/IWGDF 2023 as the primary bedside screening tool for DFI osteomyelitis. Takes 30 seconds. Positive PTB in a patient with a chronic DFU should prompt MRI and bone biopsy."},{name:"Conservative vs Surgical Management of DFI Osteomyelitis — Lazaro-Martinez et al. (2014)",detail:"RCT comparing primary surgical resection vs. medical-only antibiotic treatment for DFI forefoot osteomyelitis. Surgical group: 78% remission at 1 year. Medical group: 68% remission. Both acceptable; surgical group had shorter antibiotic duration (4 vs. 15 weeks). The study validated the medical-only approach as legitimate for selected patients — not every DFI osteomyelitis requires amputation. Patient selection (adequate vascularity, non-MDR organism, compliant patient) is critical."},{name:"IDSA 2023 Duration Analysis — Soft Tissue DFI",detail:"IDSA/IWGDF 2023 conducted systematic review of antibiotic duration for soft tissue DFI. Conclusion: 1-2 weeks for mild DFI (5-7 days often sufficient) and 2-3 weeks for moderate-severe soft tissue DFI are adequate when infection has clinically resolved. Longer courses do not improve outcomes and increase adverse events. The key concept: treat the INFECTION, not the WOUND — antibiotics should stop when infection signs resolve, not when the ulcer heals."}],riskFactors:"HOST FACTORS: Diabetes mellitus (particularly poorly controlled, HbA1c >9%), peripheral neuropathy (loss of protective sensation — the ulcer goes unfelt), peripheral arterial disease (ABI <0.9 — ischemia impairs healing and antibiotic delivery), retinopathy and nephropathy (markers of microvascular disease), obesity (BMI >30), immunosuppression (steroids, transplant medications, HIV), ESRD/dialysis (impaired immune response + altered drug pharmacokinetics), prior foot ulcer or amputation (scar tissue, altered biomechanics). INFECTION RISK FACTORS: Wound chronicity (>30 days — increased biofilm, polymicrobial flora), wound depth (penetrating to fascia/tendon/bone), wound size (>2cm), prior antibiotic exposure (predisposes to MDR organisms), prior hospitalization (healthcare-associated flora — MRSA, MDR gram-negatives), prior MRSA colonization or infection, living in a nursing facility, prior osteomyelitis. MRSA-SPECIFIC RISK FACTORS: Prior MRSA infection/colonization, hospitalization or nursing home residence within 90 days, local MRSA prevalence >30%, injection drug use, contact with MRSA-colonized individual, prior MRSA-positive wound culture. PSEUDOMONAS-SPECIFIC RISK FACTORS: Macerated or water-exposed wounds (swimming, soaking, hydrotherapy), warm/tropical climates, prior fluoroquinolone exposure, prior Pseudomonas infection, recent hospitalization (particularly ICU), immunocompromised state. ANAEROBIC/POLYMICROBIAL RISK FACTORS: Necrotic tissue, fetid odor, gas in soft tissue on imaging, chronic deep wound, prior broad-spectrum antibiotic exposure."},subcategories:[{id:"mild-dfi",name:"Mild Diabetic Foot Infection",definition:"IDSA/IWGDF 2023 Grade 2 (Mild): Infection involving only the skin and subcutaneous tissue, with perilesional erythema ≤2cm from the wound edge. No deeper tissue involvement (fascia, muscle, tendon, joint, or bone). No systemic signs of infection (afebrile, hemodynamically stable, no leukocytosis, no metabolic derangement). Primarily caused by gram-positive cocci — Staphylococcus aureus and beta-hemolytic Streptococci. MRSA is less common in mild, antibiotic-naive DFI but should be considered if risk factors present. Gram-negative and anaerobic coverage generally NOT required for mild DFI.",clinicalPresentation:"Superficial ulcer (typically neuropathic, plantar location, callus surrounding) with surrounding erythema ≤2cm, warmth, tenderness (may be muted due to peripheral neuropathy), or induration. Purulent drainage may be present. NO fever, NO tachycardia, NO hypotension. Patient ambulatory and not systemically ill. Erythema confined to within 2cm of wound margins. No lymphangitis, no fluctuance suggesting deeper abscess, no crepitus. Key examination: probe the wound with a sterile blunt probe to assess depth and assess for probe-to-bone positivity (PTB positive in mild DFI is unusual but should trigger upgraded classification if confirmed). Check for surrounding skin breakdown, interdigital maceration (entry point for organisms), and tinea pedis.",diagnostics:"CLINICAL DIAGNOSIS — mild DFI is primarily diagnosed by clinical criteria. Deep wound culture: obtain by curettage of the ulcer base or punch biopsy AFTER debridement of overlying necrotic/callus tissue (superficial swabs grow colonizers, not pathogens — avoid). Imaging: plain radiographs of the foot (baseline — rule out cortical erosion suggesting osteomyelitis, gas in soft tissue, foreign body). If PTB test is positive or if concern for deeper involvement exists despite 'mild' clinical presentation: obtain MRI. Labs: CBC (WBC typically normal in mild DFI — leukocytosis should prompt reclassification to moderate-severe), CRP, ESR (baseline for tracking), blood glucose (poor glycemic control impairs healing). Blood cultures NOT routinely needed for mild DFI. If osteomyelitis is suspected, do NOT be reassured by normal plain radiographs — bone changes take 2-3 weeks to appear radiographically.",durationGuidance:{standard:"5–7 days (mild, antibiotic-naive, resolving infection)",severe:"Up to 14 days if slow clinical response or broader wound involvement",stewardshipNote:"IDSA/IWGDF 2023: Mild DFI often requires only 5-7 days of antibiotics. The goal is to treat the INFECTION — antibiotics should stop when clinical signs of infection resolve (erythema receding, purulence resolving, wound improving), NOT when the ulcer heals. Prolonging antibiotics beyond infection resolution to 'help healing' is a common stewardship target. Wounds heal through local wound care, offloading, and vascular optimization — not prolonged antibiotics."},empiricTherapy:[{line:"First-Line — Mild DFI, No MRSA Risk, Outpatient Oral",options:[{drug:"amox-clav-mild-dfi",regimen:"Amoxicillin-clavulanate 875/125mg PO BID × 5-7 days",notes:"IDSA/IWGDF 2023 first-line for mild DFI. Covers gram-positive cocci (Streptococci, MSSA), some gram-negatives (E. coli, Klebsiella — less relevant in mild DFI), and anaerobes. The beta-lactamase inhibitor component (clavulanate) extends coverage to MSSA and anaerobes. BID dosing improves adherence over TID regimens. Avoid if penicillin allergy. GI tolerability: take with food to reduce nausea/diarrhea from clavulanate. Do NOT use if MRSA risk factors present.",evidence:"A-I",evidenceSource:"IDSA/IWGDF 2023"},{drug:"cephalexin-mild-dfi",regimen:"Cephalexin 500mg PO QID (or 1000mg PO BID) × 5-7 days",notes:"Reasonable first-line alternative for mild, acute DFI in antibiotic-naive patients. Covers Streptococci and MSSA. No anaerobic or MRSA coverage. BID high-dose regimen (1g BID) achieves comparable T>MIC to QID dosing and dramatically improves adherence — many ID pharmacists now prefer 1g BID. Use when the wound is acute, superficial, and likely monomicrobial gram-positive etiology. De-escalation target if cultures confirm MSSA.",evidence:"A-II",evidenceSource:"IDSA/IWGDF 2023"},{drug:"clindamycin-mild-dfi",regimen:"Clindamycin 300-450mg PO TID × 5-7 days",notes:"Alternative for penicillin-allergic patients. Covers Streptococci, MSSA, and most CA-MRSA (check local susceptibility — clindamycin resistance rising to 15-25% in some areas). D-test required if erythromycin-resistant isolate is clindamycin-susceptible (inducible resistance via erm gene — will fail clinically despite in vitro susceptibility). Also covers anaerobes — useful for wounds with any necrotic component. Higher C. diff risk than beta-lactams.",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023"}]},{line:"First-Line — Mild DFI WITH MRSA Risk Factors, Outpatient Oral",options:[{drug:"tmp-smx-mild-dfi",regimen:"TMP-SMX DS (160/800mg) 1-2 tablets PO BID × 5-7 days",notes:"Add to mild DFI regimen when MRSA risk factors present (prior MRSA, nursing home resident, prior hospitalization, known MRSA contact, local MRSA prevalence >30%). Excellent CA-MRSA activity (>95% susceptible). IMPORTANT LIMITATION: TMP-SMX has poor Streptococcal coverage — for mild DFI with surrounding cellulitis, consider adding amoxicillin or cephalexin to address the Streptococcal gap. Renally adjust for CrCl <30 mL/min (avoid or reduce dose). Monitor potassium (amiloride-like potassium-sparing effect — risk of hyperkalemia with ACE/ARB, common in diabetics).",evidence:"A-II",evidenceSource:"IDSA/IWGDF 2023"},{drug:"doxycycline-mild-dfi",regimen:"Doxycycline 100mg PO BID × 5-7 days",notes:"Alternative for MRSA-risk mild DFI, especially when TMP-SMX is not tolerated or contraindicated. CA-MRSA susceptibility >95%. BID dosing. Same Streptococcal gap as TMP-SMX — pair with amoxicillin if significant surrounding cellulitis. Photosensitivity risk (counsel patient to use sunscreen). Take with full glass of water upright to prevent esophageal ulceration. No renal dose adjustment required (unlike TMP-SMX).",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023"}]},{line:"Penicillin Allergy Alternatives (Non-Anaphylactic History)",options:[{drug:"clindamycin-pen-allergy-mild",regimen:"Clindamycin 300mg PO TID × 5-7 days",notes:"For mild DFI with non-severe penicillin allergy. Covers gram-positives + anaerobes. Check D-test. For confirmed anaphylactic penicillin allergy, cross-reactivity with cephalosporins is <2% for dissimilar side chains — many ID pharmacists advocate for cephalosporins even in documented penicillin allergy (discuss with prescriber/patient). Azithromycin is NOT recommended for DFI — poor Staphylococcal activity.",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023"}]}],organismSpecific:[{organism:"S. aureus (MSSA) — most common in mild DFI",preferred:"Cephalexin 500-1000mg PO BID-QID, dicloxacillin 500mg PO QID, amoxicillin-clavulanate 875/125mg PO BID",alternative:"Clindamycin 300mg PO TID (if susceptible, D-test negative); TMP-SMX DS BID (limited Streptococcal coverage)",notes:"MSSA is the dominant pathogen in mild, acute DFI in antibiotic-naive patients. Definitive therapy with a narrow anti-staphylococcal agent (cephalexin, dicloxacillin) is preferred over broad-spectrum when MSSA is confirmed. De-escalate from amoxicillin-clavulanate to cephalexin when MSSA confirmed on culture. Dicloxacillin requires empty stomach (1h before or 2h after meals) — poor adherence in practice."},{organism:"Beta-Hemolytic Streptococci (Group A, B, C, G)",preferred:"Amoxicillin 500mg PO TID, cephalexin 500mg PO QID, amoxicillin-clavulanate 875/125mg PO BID",alternative:"Clindamycin 300mg PO TID; penicillin VK 500mg PO QID",notes:"Group A Strep (S. pyogenes) and Group B Strep (S. agalactiae) are common in DFI cellulitis, particularly in older diabetics. ALL beta-hemolytic streptococci are universally penicillin-susceptible — narrow to penicillin or amoxicillin when confirmed. TMP-SMX has POOR Streptococcal coverage — do NOT use as sole agent if Streptococci suspected."},{organism:"MRSA — mild DFI with risk factors",preferred:"TMP-SMX DS 1-2 tabs PO BID, doxycycline 100mg PO BID",alternative:"Clindamycin 300-450mg PO TID (if susceptible and D-test negative)",notes:"MRSA is NOT the expected pathogen in mild, antibiotic-naive DFI. However, when risk factors are present (prior MRSA, recent hospitalization, nursing home residence), empiric MRSA coverage is warranted. CA-MRSA (USA300) susceptibility: TMP-SMX >95%, doxycycline >95%, clindamycin variable (15-25% resistance in some US cities). For mild DFI, IV vancomycin is NOT needed — oral agents are equivalent."}],pearls:["The 2cm erythema boundary is a clinical anchor, not an absolute rule: The IDSA/IWGDF definition of mild DFI uses ≤2cm perilesional erythema as the boundary between mild and moderate. However, this is a guideline — erythema that is clearly superficial, non-spreading, and in an otherwise well patient can still be treated as mild even if marginally >2cm. Clinical context (is the patient sick? is the infection spreading?) matters more than measuring with a ruler.","Mark the borders immediately with a skin marker: Border marking with a pen and timestamp (and ideally a photo in the medical record) is the single most useful tool for tracking DFI progression. Erythema that expands beyond the border despite 24-48 hours of antibiotics means the infection is worsening or the organism is resistant — do NOT wait for 72 hours to reassess in mild DFI. Reassess at 48h and upgrade classification if not improving.","Wound cultures in mild DFI: obtain DEEP cultures from the wound base by curettage — do NOT swab the surface. Surface swabs in chronic DFI grow colonizers (Pseudomonas, Corynebacterium, mixed flora) that do not represent the infecting pathogen. Deep curettage or punch biopsy after debridement cultures the true pathogen. This distinction is critical for guiding targeted therapy.","The Streptococcal gap of TMP-SMX and doxycycline: Both excellent oral MRSA agents have unreliable Streptococcal coverage. For mild DFI with significant surrounding cellulitis (which is predominantly Streptococcal in etiology), using TMP-SMX or doxycycline alone leaves a real gap. Consider adding amoxicillin 500mg TID or cephalexin 500mg QID to address the Streptococcal component. This combination covers both MRSA and Streptococci.","Glycemic control is a therapeutic intervention: Hyperglycemia (glucose >200 mg/dL chronically) impairs neutrophil chemotaxis, phagocytosis, and reactive oxygen species generation. Optimizing blood glucose is a legitimate adjunct to antibiotic therapy and improves outcomes. A pharmacist rounding with the ID team should flag persistently elevated glucoses and communicate with the endocrinology team.","Offloading is non-negotiable: No antibiotic can heal a neuropathic ulcer that continues to receive repetitive pressure loading. Total contact casting (TCC) is the gold standard for offloading plantar neuropathic ulcers. If the patient refuses or is non-compliant with offloading, antibiotic therapy will fail regardless of agent selection. This is a wound care intervention, not an antibiotic failure.","Probe-to-bone test in mild DFI: A positive PTB in a patient classified as mild DFI should trigger immediate reconsideration and MRI imaging. If PTB is positive, the infection is almost certainly deeper than mild — reclassify and obtain imaging. The PTB test takes 30 seconds and should be performed on every DFI evaluation."]},{id:"moderate-dfi",name:"Moderate Diabetic Foot Infection",definition:"IDSA/IWGDF 2023 Grade 3 (Moderate): Infection extending deeper than the skin/subcutaneous tissue — involving fascia, muscle, tendon, joint, or bone — OR perilesional erythema >2cm from wound edge, OR lymphangitis, in a patient WITHOUT systemic signs of infection (no fever, hemodynamically stable, no metabolic derangement). This category encompasses a broad clinical spectrum: from cellulitis >2cm (no deep tissue involvement) to frank osteomyelitis without systemic compromise. Microbiology is more complex than mild DFI — polymicrobial infections are the norm in chronic wounds. Gram-positive cocci (S. aureus, Streptococci) remain important, but gram-negative rods (E. coli, Klebsiella, Proteus) and anaerobes are frequently co-pathogens in chronic, deep moderate DFI.",clinicalPresentation:"Ulcer with erythema extending >2cm from wound edge, OR lymphangitis (linear red streaking proximal to wound), OR clinical evidence of deeper tissue involvement (fascia, tendon, muscle palpable or visible in wound, joint capsule visible). Positive probe-to-bone test suggests osteomyelitis (upgrade classification and obtain MRI). Sausage toe (diffuse fusiform swelling of a digit) is pathognomonic for phalangeal osteomyelitis. Patient is ambulatory and not systemically ill — no fever, HR <90, hemodynamically stable. Purulent drainage, fetid odor (suggests anaerobic involvement), or necrotic tissue in wound base are common. Wagner Grade 2-3 correlates with moderate DFI.",diagnostics:"Deep wound culture (curettage or biopsy of wound base, NOT swab): essential for culture-directed de-escalation. Probe-to-bone test: perform on every moderate DFI — positive PTB warrants MRI. Plain radiographs of foot: obtain as baseline (cortical erosion, periosteal reaction, gas in soft tissue). MRI foot with and without gadolinium: gold standard if osteomyelitis suspected (sensitivity 90%, specificity 80%). Do NOT delay MRI — bone destruction is not reversible. ESR (>70 mm/h has high specificity for osteomyelitis in DFI context) and CRP (excellent for trending treatment response — check at baseline and every 1-2 weeks). CBC with differential (WBC should be normal or mildly elevated in moderate DFI without systemic signs — leukocytosis >12,000 should trigger reclassification). BMP (renal function for antibiotic dosing, electrolytes, glucose — poor glycemic control impairs healing). Blood cultures: obtain for moderate DFI requiring IV therapy, particularly if fever or hemodynamic instability develops. Bone biopsy: the gold standard for definitive osteomyelitis diagnosis and culture — pursue whenever feasible, ideally before starting antibiotics. Vascular assessment: ABI and toe pressures if PAD suspected — critical before attributing treatment failure to antibiotic inadequacy.",durationGuidance:{standard:"2–3 weeks (soft tissue only, clinically resolving)",severe:"4–6 weeks (with confirmed osteomyelitis, medical management)",opatNote:"OPAT is frequently used for moderate DFI requiring IV therapy. Once-daily ertapenem is the preferred OPAT agent (no Pseudomonas or MRSA coverage — ensure cultures don't require those). Add daptomycin or vancomycin via OPAT if MRSA confirmed. IV-to-PO switch should be pursued as soon as clinically feasible using high-bioavailability agents (fluoroquinolones, TMP-SMX, linezolid, clindamycin).",stewardshipNote:"OVIVA trial 2019: Oral antibiotics non-inferior to IV for bone/joint infections including osteomyelitis. Consider early oral step-down with: ciprofloxacin or levofloxacin (gram-negatives, moderate Pseudomonas activity), TMP-SMX DS (MRSA, gram-positives), clindamycin (gram-positives, anaerobes), or linezolid (MRSA, gram-positives with excellent bone penetration). Fluoroquinolones have the best bioavailability (~100%) and bone penetration — preferred for gram-negative osteomyelitis step-down. The key question before oral step-down: is the gut absorbing? If patient has gastroparesis (common in long-standing diabetes), oral absorption may be unreliable."},empiricTherapy:[{line:"First-Line — Moderate DFI, Oral Candidate (No IV Required)",options:[{drug:"amox-clav-moderate-oral",regimen:"Amoxicillin-clavulanate 875/125mg PO BID × 2-3 weeks",notes:"Appropriate for moderate DFI with erythema >2cm but no deep tissue involvement, ambulatory patient, reliable GI absorption, no MRSA risk, no Pseudomonas risk. Covers MSSA, Streptococci, most Enterobacterales, and anaerobes. Add TMP-SMX or doxycycline if MRSA risk present. Duration: 2 weeks for soft tissue only; extend to 3 weeks if slow response. Reassess clinically at 72 hours.",evidence:"A-II",evidenceSource:"IDSA/IWGDF 2023"},{drug:"clinda-cipro-moderate-oral",regimen:"Clindamycin 300-450mg PO TID + Ciprofloxacin 500mg PO BID × 2-3 weeks",notes:"Alternative oral combination for moderate DFI with MRSA risk or deeper wound features. Clindamycin: covers MSSA, most CA-MRSA, Streptococci, and anaerobes. Ciprofloxacin: covers gram-negatives including moderate Pseudomonas activity. Together: comprehensive polymicrobial coverage without IV therapy. Check D-test for clindamycin if erythromycin-resistant isolate. This combination is especially useful for chronic wounds where gram-negatives are likely co-pathogens.",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023"}]},{line:"First-Line — Moderate DFI, IV Required (Hospitalized or OPAT)",options:[{drug:"ertapenem-moderate-iv",regimen:"Ertapenem 1g IV q24h ± Vancomycin IV (AUC/MIC 400-600) if MRSA risk",notes:"IDSA/IWGDF preferred IV regimen for moderate DFI requiring hospitalization. Ertapenem provides: MSSA, Streptococci, Enterobacterales (including most ESBL producers), and anaerobic coverage. Once-daily dosing is ideal for OPAT. CRITICAL GAPS: NO Pseudomonas aeruginosa coverage, NO MRSA coverage. Add vancomycin if MRSA risk factors present. Substitute pip-tazo or meropenem if Pseudomonas risk exists (macerated wound, hydrotherapy, prior Pseudomonas, tropical exposure). Ertapenem is renally eliminated — dose-adjust for CrCl <30 mL/min (500mg q24h).",evidence:"A-I",evidenceSource:"IDSA/IWGDF 2023"},{drug:"pip-tazo-moderate-iv",regimen:"Piperacillin-tazobactam 4.5g IV q6h (extended infusion over 4h) ± Vancomycin IV",notes:"Alternative to ertapenem for moderate DFI when Pseudomonas coverage is needed (macerated wound, water exposure, prior Pseudomonas cultures). Pip-tazo covers MSSA, Streptococci, Enterobacterales, Pseudomonas aeruginosa, and anaerobes. Extended infusion (4-hour infusion q6h) optimizes T>MIC PK/PD target and is strongly preferred by ID pharmacists. Add vancomycin for MRSA coverage. De-escalate based on cultures — if Pseudomonas not recovered, step down to ertapenem or oral agents.",evidence:"A-II",evidenceSource:"IDSA/IWGDF 2023"},{drug:"cefazolin-moderate-iv",regimen:"Cefazolin 2g IV q8h (soft tissue, low-risk, no deep involvement) ± add anaerobic coverage (metronidazole 500mg IV q8h) if necrotic wound",notes:"Acceptable for moderate DFI with primarily gram-positive etiology (early infection, no chronic wound features, no gram-negative risk). Cefazolin covers MSSA and Streptococci. No MRSA, no Pseudomonas, limited anaerobic coverage. Add metronidazole 500mg IV/PO q8h if necrotic wound or fetid discharge. Add vancomycin if MRSA risk. This narrow regimen is appropriate only for selected moderate DFI — do NOT use for chronic deep wounds without culture data.",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023"}]},{line:"MRSA Coverage — Add When Risk Factors Present",options:[{drug:"vancomycin-moderate-mrsa",regimen:"Vancomycin IV (AUC/MIC-guided, target AUC/MIC 400-600) — add to gram-negative backbone",notes:"Add vancomycin to ertapenem or pip-tazo backbone when MRSA risk factors are present: prior MRSA, recent hospitalization/nursing home, local MRSA prevalence >30%, prior wound culture showing MRSA, IV drug use. AUC-guided dosing is the 2020 ASHP/IDSA/SIDP consensus standard — Bayesian dosing software strongly preferred over trough-only monitoring. De-escalate to targeted oral agent (TMP-SMX, doxycycline, linezolid) as soon as patient is clinically stable and GI absorption reliable.",evidence:"A-I",evidenceSource:"IDSA/IWGDF 2023"},{drug:"daptomycin-moderate-mrsa",regimen:"Daptomycin 6 mg/kg IV q24h — alternative to vancomycin for MRSA, particularly in renal impairment or vancomycin intolerance",notes:"Alternative MRSA coverage agent. Once-daily dosing (OPAT-friendly). Rapidly bactericidal. Do NOT use for pulmonary infections (inactivated by surfactant). Monitor CPK weekly — myopathy risk, especially with concurrent statin use. Daptomycin may be preferred over vancomycin for DFI when: vancomycin AUC-guided dosing not available, prior vancomycin-associated nephrotoxicity, vancomycin MIC creep (vancomycin MIC ≥2 µg/mL), or in patients with baseline renal impairment where vancomycin toxicity risk is elevated.",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023"}]},{line:"Oral Step-Down (IV to PO) — After Clinical Stabilization",options:[{drug:"cipro-moderate-step-down",regimen:"Ciprofloxacin 500-750mg PO BID (gram-negative coverage, Pseudomonas if susceptible)",notes:"Excellent PO bioavailability (~80%). Best oral option for gram-negative osteomyelitis step-down (OVIVA data). Does NOT cover MRSA or anaerobes. Pair with TMP-SMX or doxycycline if MRSA step-down needed. Fluoroquinolone cautions: FDA boxed warning (tendinopathy, peripheral neuropathy, CNS effects — particularly relevant in diabetics who already have peripheral neuropathy). Avoid if prior fluoroquinolone exposure within 90 days (resistance risk). Check fluoroquinolone susceptibility on culture before using for step-down.",evidence:"A-II",evidenceSource:"IDSA/IWGDF 2023"},{drug:"tmp-smx-moderate-step-down",regimen:"TMP-SMX DS 1-2 tablets PO BID (MRSA, gram-positive step-down)",notes:"Excellent oral MRSA agent with good soft tissue and bone penetration. Renally eliminated — adjust for CrCl <30 mL/min (avoid or reduce dose to 1 DS tab BID). Hyperkalemia risk — monitor K at day 3-5, especially in patients on ACE/ARBs (nearly universal in diabetic patients with nephropathy). False creatinine rise: TMP blocks tubular creatinine secretion — creatinine will rise without true GFR decline; monitor cystatin C or clinical assessment rather than stopping TMP-SMX for this reason.",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023"},{drug:"linezolid-moderate-step-down",regimen:"Linezolid 600mg PO/IV BID (MRSA, gram-positive, excellent bone penetration)",notes:"100% oral bioavailability — oral equals IV in bone/tissue concentrations. Excellent for MRSA step-down with bone penetration superior to most alternatives. Limitations: cost (expensive, especially without PA approval), myelosuppression (CBC weekly — thrombocytopenia and anemia risk if >14 days, more common in renal impairment), serotonin syndrome risk (avoid with serotonergic drugs: SSRIs, SNRIs, MAOIs, tramadol), lactic acidosis with prolonged use (mitochondrial toxicity). Reserve for confirmed MRSA soft tissue/bone infection when TMP-SMX not tolerated or contraindicated. Limit duration <6 weeks when possible.",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023"}]}],organismSpecific:[{organism:"S. aureus (MSSA) — common in moderate DFI",preferred:"Cefazolin 2g IV q8h (IV); cephalexin 1000mg PO BID or dicloxacillin 500mg PO QID (oral step-down); amoxicillin-clavulanate 875/125mg PO BID (outpatient)",alternative:"Nafcillin or oxacillin 2g IV q4h (superior bactericidal activity vs. cefazolin — use if concurrent bacteremia); clindamycin PO/IV if susceptible",notes:"De-escalate from vancomycin to cefazolin (or nafcillin for bacteremia) as soon as MSSA is confirmed — this is one of the highest-yield stewardship interventions. Cefazolin is preferred over nafcillin in most DFI cases due to simplified dosing (q8h vs q4h), less phlebitis, and equivalent outcomes for non-bacteremic infections. For MSSA bacteremia from DFI, obtain echocardiogram and consult ID."},{organism:"S. aureus (MRSA) — moderate DFI with risk factors",preferred:"Vancomycin IV (AUC/MIC-guided) [inpatient]; TMP-SMX DS 1-2 tabs PO BID [outpatient or step-down]; daptomycin 6 mg/kg IV q24h [OPAT alternative]",alternative:"Linezolid 600mg IV/PO BID; clindamycin PO (if susceptible, D-test negative); doxycycline 100mg PO BID (if susceptible)",notes:"MRSA osteomyelitis from DFI: IV vancomycin preferred initial therapy; oral step-down per OVIVA to TMP-SMX DS or linezolid after initial IV stabilization. Vancomycin MIC ≥2 µg/mL (vancomycin-intermediate S. aureus — VISA): use daptomycin or ceftaroline as alternatives — consult ID."},{organism:"Beta-Hemolytic Streptococci (Group B — S. agalactiae most common in diabetics)",preferred:"Ceftriaxone 2g IV q24h (IV); amoxicillin 1g PO TID or cephalexin 500mg PO QID (oral)",alternative:"Penicillin G 3-4 MU IV q4h (bacteremia); clindamycin (if penicillin allergy and susceptible)",notes:"Group B Strep (S. agalactiae) is particularly prevalent in moderate DFI in elderly diabetic patients, often originating from urinary tract colonization. All beta-hemolytic streptococci are universally penicillin-susceptible. Narrow to penicillin or amoxicillin when Streptococcus is the sole or dominant pathogen on bone/deep tissue culture."},{organism:"Enterobacterales (E. coli, Klebsiella, Proteus, Morganella) — moderate DFI, chronic wounds",preferred:"Ertapenem 1g IV q24h (ESBL or broad coverage); ceftriaxone 2g IV q24h (if susceptible, non-ESBL); ciprofloxacin 500mg PO BID (oral, if susceptible)",alternative:"Cefepime 2g IV q8h (non-ESBL, Pseudomonas coverage not needed); pip-tazo 4.5g IV q6h",notes:"Gram-negatives are co-pathogens in moderate-severe DFI, particularly in chronic wounds >4 weeks or those with prior antibiotic exposure. Check ESBL status (E. coli and Klebsiella ESBL is increasingly prevalent — 15-30% in some US centers). ESBL producers: treat with ertapenem (preferred OPAT agent) or meropenem (severe). Fluoroquinolone oral step-down for gram-negative bone/soft tissue infections — verify susceptibility. Proteus mirabilis is intrinsically resistant to nitrofurantoin and is a common co-pathogen — confirm resistance patterns."},{organism:"ESBL-Producing Enterobacterales — moderate DFI with prior antibiotics or healthcare exposure",preferred:"Ertapenem 1g IV q24h (OPAT-friendly, definitive ESBL therapy); meropenem 1g IV q8h (severe or if ertapenem MIC borderline)",alternative:"Ceftolozane-tazobactam (ESBL + Pseudomonas); ceftazidime-avibactam (ESBL + KPC); fosfomycin IV (not available in US); temocillin (not available in US)",notes:"ESBL-producing E. coli or Klebsiella: carbapenems are the definitive treatment. Ertapenem is preferred for OPAT. Do NOT use cephalosporins even if susceptible by disk diffusion — ESBL inoculum effect causes in vivo failure despite in vitro susceptibility (a critical laboratory-clinical discordance). Oral step-down for ESBL is challenging — ciprofloxacin only if confirmed susceptible and not used empirically. Consult ID for non-carbapenem options."},{organism:"Pseudomonas aeruginosa — macerated wounds, water/hydrotherapy exposure, prior fluoroquinolone use",preferred:"Piperacillin-tazobactam 4.5g IV q6h (extended infusion); cefepime 2g IV q8h; ciprofloxacin 750mg PO BID or 400mg IV q8h (if susceptible, oral step-down)",alternative:"Meropenem 1g IV q8h (carbapenem-susceptible); ceftazidime-avibactam (MDR Pseudomonas); ceftolozane-tazobactam (MDR Pseudomonas)",notes:"Pseudomonas in DFI is associated with: macerated wounds (patient soaking feet in water), warm climates, hydrotherapy, prior fluoroquinolone exposure, and healthcare-associated infections. Do NOT assume Pseudomonas is a clinically relevant pathogen based on surface swab alone — it may be a colonizer. If deep tissue culture or bone biopsy grows Pseudomonas, treat definitively. Ciprofloxacin 750mg PO BID is one of the few oral antipseudomonal options (OVIVA-style step-down viable if susceptible)."},{organism:"Anaerobes (Bacteroides, Peptostreptococcus, Prevotella) — deep/necrotic wounds, gas on imaging",preferred:"Amoxicillin-clavulanate PO (outpatient), pip-tazo IV or ertapenem IV (inpatient), metronidazole 500mg PO/IV TID (if adding to beta-lactam backbone)",alternative:"Clindamycin (if resistant to beta-lactams; note rising Bacteroides resistance to clindamycin >30% in some areas)",notes:"Anaerobes are important co-pathogens in: deep/necrotic DFI wounds, wounds with fetid odor, gas on soft tissue imaging (gas gangrene warning — emergent surgery), and chronic wounds with poor blood supply (ischemic tissue favors anaerobic growth). Metronidazole is the most reliable anaerobic agent and can be added to any regimen lacking anaerobic coverage. Bacteroides fragilis is increasingly clindamycin-resistant — metronidazole is preferred for definitive Bacteroides coverage."}],pearls:["Polymicrobial infection is the rule in moderate DFI: Unlike mild DFI (predominantly monomicrobial gram-positive), moderate DFI with chronic wounds harbors polymicrobial flora. A single surface swab growing 4-5 organisms does NOT mean you need to cover all 4-5 — you need BONE biopsy or DEEP tissue culture to identify the true pathogen(s). Treating every colonizer from a surface swab leads to unjustified broad-spectrum 6-week courses and drives resistance.","Vascular assessment before blaming antibiotics for failure: If a moderate DFI is not responding to appropriate antibiotics, ALWAYS check vascular status before escalating therapy. ABI <0.9 suggests PAD — antibiotic delivery to ischemic tissue is severely compromised. No antibiotic achieves therapeutic concentrations in ischemic tissue. Revascularization (angioplasty, bypass) is often the intervention that allows wound healing, not broader antibiotics. Refer to vascular surgery proactively.","IV-to-PO switch timing: The OVIVA trial showed that switching to oral antibiotics after as few as 7 days of IV therapy was non-inferior for bone/joint infections. For soft tissue DFI, the threshold is even lower — switch to oral as soon as the patient can tolerate PO with reliable GI absorption and there are appropriate oral agents available. Diabetic gastroparesis is a real consideration: if blood glucoses are very high (>300 mg/dL) and the patient has slow gastric emptying, oral absorption may be unreliable until glycemia is controlled.","Fluoroquinolone pearls for DFI bone/tissue penetration: Ciprofloxacin and levofloxacin achieve bone concentrations at 30-50% of plasma levels — higher than most other oral agents. Levofloxacin 750mg once daily is simpler than ciprofloxacin 750mg BID and has better gram-positive coverage. However: fluoroquinolone resistance in Pseudomonas (and Enterobacterales) is escalating rapidly (20-40% in many US centers). ALWAYS check susceptibility before using for step-down in culture-confirmed gram-negative infection. The FDA boxed warning (tendinopathy, peripheral neuropathy) is particularly relevant in diabetics who already have neuropathy — use judicious informed consent.","ESR as an osteomyelitis monitoring tool: ESR >70 mm/h is highly specific (but not sensitive) for osteomyelitis in DFI. CRP is more useful for monitoring treatment response — it falls faster (within days of appropriate therapy) vs. ESR (weeks to months). Use CRP weekly to track response. A CRP failing to fall after 2-3 weeks of appropriate therapy should trigger: re-evaluation of source control, bone biopsy if not yet obtained, MRI reassessment, and ID consultation.","Wound care team integration is essential: The pharmacist's role extends beyond antibiotic selection. Advocate for formal wound care team consultation (podiatry, wound care nursing, vascular surgery) on every moderate DFI. The healing endpoint is determined by the wound care team (ulcer closure), not by the ID service. Antibiotics stop when the INFECTION resolves, not when the WOUND closes — these are different endpoints."]},{id:"severe-dfi",name:"Severe Diabetic Foot Infection",definition:"IDSA/IWGDF 2023 Grade 4 (Severe): Any diabetic foot infection with ≥2 systemic inflammatory response syndrome (SIRS) criteria: temperature >38°C or <36°C, heart rate >90 bpm, respiratory rate >20 breaths/min (or PaCO2 <32 mmHg), WBC >12,000/µL or <4,000/µL or >10% band forms. Alternatively, any DFI causing metabolic instability (severe hyperglycemia/acidosis, uremia, electrolyte abnormalities). Severe DFI represents a systemic infection — hospitalization, IV antibiotics, and emergent surgical consultation are mandatory. Empiric therapy must cover all likely pathogens: gram-positive cocci (MRSA coverage essential), gram-negative rods (including Pseudomonas), and anaerobes. Source control (surgical debridement, drainage, or amputation) is the cornerstone of treatment — prolonged antibiotics cannot substitute for inadequate surgical management.",clinicalPresentation:"Acutely ill, systemically toxic patient with a diabetic foot wound. Fever (or hypothermia in severe sepsis), tachycardia, tachypnea, altered mental status. Locally: purulent, malodorous wound with surrounding necrosis, extensive erythema, bullae or blisters (ischemic component), crepitus on palpation (gas — emergent surgery), pain out of proportion (suggestive of necrotizing fasciitis — surgical emergency), skin color changes (dusky, violaceous, or frank gangrene). Laboratory: leukocytosis (or leukopenia), elevated CRP/procalcitonin, hyperglycemia (often severe, >400 mg/dL), metabolic acidosis (high-gap in severe cases — lactic acidosis from ischemia or DKA). Wagner Grade 3-5 correlates with severe DFI. URGENT: assess for necrotizing fasciitis (pain out of proportion, crepitus, rapid spread) — this is a surgical emergency requiring OR within hours.",diagnostics:"Blood cultures: MANDATORY — obtain 2 sets before starting antibiotics. Deep wound cultures (intraoperative if going to OR — most reliable). Plain radiographs STAT: gas in soft tissue (fascial planes — emergency), cortical destruction (osteomyelitis), extent of bony involvement. CT soft tissue: rapid assessment of tissue gas, extent of infection, fluid collections requiring drainage. MRI foot: gold standard for osteomyelitis characterization (may be obtained after initial stabilization if not emergent OR). Procalcitonin: elevated procalcitonin (>0.5 ng/mL) in DFI correlates with bacteremia risk and guides IV vs. oral decision. Lactate: obtain if hemodynamic instability (rules out lactic acidosis, guides fluid resuscitation). CBC, CMP, coagulation panel, HbA1c. Vascular surgery consultation for ABI/toe pressures — ischemia assessment is critical for amputation planning.",durationGuidance:{standard:"2–4 weeks (soft tissue only, after adequate source control)",severe:"4–6 weeks (osteomyelitis with medical-only management or incomplete bone resection)",opatNote:"OPAT after initial inpatient stabilization is appropriate for severe DFI that has been surgically debrided and is clinically improving. Once-daily regimens preferred for OPAT: ertapenem 1g q24h (if no MRSA/Pseudomonas), daptomycin 6-8 mg/kg q24h (MRSA), ceftriaxone 2g q24h (gram-positive/gram-negative susceptible organisms). Ensure OPAT infrastructure with twice-weekly labs (CBC, BMP, vancomycin AUC if applicable).",stewardshipNote:"Source control (debridement, incision/drainage, amputation if needed) is the cornerstone of severe DFI treatment. Prolonged antibiotics do NOT compensate for inadequate surgical management — if the patient is not improving on IV antibiotics, the question is almost never 'wrong antibiotic' but rather 'inadequate source control.' Surgically re-assess non-responders. After adequate source control, antibiotic duration for soft tissue severe DFI is 2-4 weeks — NOT indefinite."},empiricTherapy:[{line:"First-Line — Severe DFI, Empiric Broad-Spectrum, IV",options:[{drug:"pip-tazo-vanc-severe",regimen:"Piperacillin-tazobactam 4.5g IV q6h (extended infusion over 4h) + Vancomycin IV (AUC/MIC 400-600)",notes:"Standard empiric regimen for severe DFI. Pip-tazo covers: MSSA, Streptococci, Enterobacterales, Pseudomonas aeruginosa, and anaerobes. Vancomycin adds MRSA coverage. Extended infusion pip-tazo (4h over 30 min q6h) significantly improves T>MIC target attainment for susceptible and intermediate Pseudomonas — pharmacist-driven intervention with high impact. AUC-guided vancomycin dosing (Bayesian software) reduces nephrotoxicity while ensuring efficacy. De-escalate based on blood cultures and deep wound cultures within 48-72h.",evidence:"A-I",evidenceSource:"IDSA/IWGDF 2023"},{drug:"meropenem-vanc-severe",regimen:"Meropenem 1g IV q8h + Vancomycin IV (AUC/MIC 400-600)",notes:"Reserve for severe DFI with: prior MDR gram-negative cultures, recent hospitalization, prior broad-spectrum antibiotic exposure within 90 days, or failed pip-tazo therapy. Meropenem covers Enterobacterales (including ESBL), Pseudomonas, and anaerobes — broader than pip-tazo for resistant gram-negatives. Add vancomycin for MRSA. This is not first-line empiric — reserve to prevent unnecessary carbapenem use and emergence of carbapenem-resistant organisms (CRO). Consult antimicrobial stewardship.",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023"}]},{line:"MRSA Coverage Options — IV",options:[{drug:"vancomycin-severe-mrsa",regimen:"Vancomycin IV — AUC/MIC target 400-600 mg·h/L (Bayesian dosing strongly preferred)",notes:"Standard MRSA coverage for severe DFI. Initiate with loading dose (25-35 mg/kg IV once for severe infection) followed by maintenance dosing guided by Bayesian pharmacokinetic software. Monitor AUC daily for first 2-3 days, then every 2-3 days when stable. Nephrotoxicity risk is real, particularly with concurrent nephrotoxins (NSAIDs — common in diabetics), contrast agents, or baseline CKD. Transition to oral MRSA agent (TMP-SMX, linezolid) when clinically stable and GI function adequate.",evidence:"A-I",evidenceSource:"IDSA/IWGDF 2023"},{drug:"daptomycin-severe-mrsa",regimen:"Daptomycin 6-8 mg/kg IV q24h — alternative or adjunct to vancomycin for MRSA",notes:"Daptomycin 6 mg/kg for serious MRSA soft tissue infection; consider 8-10 mg/kg for DFI osteomyelitis (higher doses improve bone penetration and maintain activity against biofilm-embedded organisms per pharmacodynamic data). Once-daily dosing. Monitor CPK weekly — suspend statins during daptomycin therapy (myopathy risk). Preferred over vancomycin when: vancomycin MIC ≥2 µg/mL, prior vancomycin nephrotoxicity, or OPAT (once-daily vs. intermittent vancomycin infusions). Do NOT use for pneumonia.",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023"}]},{line:"Necrotizing Fasciitis — Emergent Regimen (If NSTI Suspected)",options:[{drug:"nsti-dfi-regimen",regimen:"Vancomycin IV + Piperacillin-tazobactam 4.5g IV q6h + Clindamycin 900mg IV q8h (toxin suppression)",notes:"If necrotizing fasciitis is suspected in addition to DFI (pain out of proportion, crepitus, rapidly spreading necrosis, skin blistering, hemodynamic instability): EMERGENT surgery consultation + triple therapy. Add clindamycin 900mg IV q8h for toxin suppression (Eagle effect — at high bacterial inocula, cell-wall agents are less effective; clindamycin inhibits toxin synthesis regardless of growth phase). TIME TO SURGERY IS THE DOMINANT PROGNOSTIC VARIABLE — do not delay OR for further imaging if clinical picture strongly suggests necrotizing fasciitis.",evidence:"A-I",evidenceSource:"IDSA 2014 SSTI Guidelines (NF component)"}]},{line:"ESBL or MDR Gram-Negative Suspected/Confirmed",options:[{drug:"meropenem-esbl-severe",regimen:"Meropenem 1g IV q8h (ESBL confirmed or high-risk severe DFI)",notes:"When deep tissue or blood culture grows ESBL-producing E. coli or Klebsiella in severe DFI: meropenem is the definitive therapy. Ertapenem is also acceptable for ESBL if not critically ill (lacks Pseudomonas coverage — avoid if Pseudomonas co-pathogen suspected). Cefepime is NOT reliable for ESBL (inoculum effect causes in vivo failure despite in vitro susceptibility in some patients). Do NOT use extended-spectrum cephalosporins for ESBL-confirmed infections.",evidence:"A-I",evidenceSource:"IDSA/IWGDF 2023"},{drug:"caz-avi-cre-severe",regimen:"Ceftazidime-avibactam 2.5g IV q8h (extended infusion) — for KPC-producing Klebsiella or MDR Pseudomonas",notes:"Reserve for carbapenem-resistant Enterobacterales (CRE) — specifically KPC producers. Ceftazidime-avibactam covers KPC, OXA-48, and extended-spectrum beta-lactamases but NOT metallo-beta-lactamases (NDM, VIM, IMP — which require aztreonam-avibactam or colistin-based regimens). Always confirm mechanism of carbapenem resistance before choosing therapy. Consult ID and antimicrobial stewardship. This is a high-cost, restricted antibiotic — appropriate use critical.",evidence:"B-III",evidenceSource:"IDSA AMR Guidance 2023"}]}],organismSpecific:[{organism:"S. aureus (MSSA) — severe DFI (bacteremia common)",preferred:"Cefazolin 2g IV q8h (first-line for MSSA, superior to vancomycin); nafcillin 2g IV q4h (if bacteremia — slightly superior bactericidal kinetics)",alternative:"Vancomycin IV (empiric, until MSSA confirmed — de-escalate immediately upon MSSA confirmation)",notes:"DE-ESCALATION from vancomycin to cefazolin upon MSSA confirmation is one of the most high-impact stewardship interventions. Multiple studies show cefazolin is equivalent or superior to nafcillin/oxacillin for MSSA bacteremia with fewer adverse effects. For MSSA bacteremia from DFI: mandatory echocardiogram + ID consultation to rule out endocarditis — treat bacteremia as SAB (Staphylococcal aureus bacteremia), not just DFI source."},{organism:"S. aureus (MRSA) — severe DFI",preferred:"Vancomycin IV (AUC/MIC 400-600); daptomycin 8-10 mg/kg IV q24h (especially for osteomyelitis, OPAT, or vancomycin-intolerant)",alternative:"Ceftaroline 600mg IV q8h (MRSA with vancomycin failure or MIC ≥2 µg/mL); linezolid 600mg IV/PO BID (soft tissue — excellent penetration, but bacteriostatic not bactericidal)",notes:"For MRSA osteomyelitis: vancomycin is standard IV; daptomycin at high doses (8-10 mg/kg) has superior bone penetration and activity against biofilm-embedded MRSA. Oral step-down for MRSA osteomyelitis: TMP-SMX DS 2 tabs BID or linezolid 600mg BID — both supported by OVIVA data for osteomyelitis setting. Vancomycin MIC ≥2 µg/mL (VISA/hVISA): associated with treatment failure — switch to daptomycin or ceftaroline."},{organism:"Pseudomonas aeruginosa — severe DFI",preferred:"Piperacillin-tazobactam 4.5g IV q6h extended infusion; cefepime 2g IV q8h (if pip-tazo resistance); ciprofloxacin 750mg PO BID or 400mg IV q8h (oral step-down if susceptible)",alternative:"Meropenem 1g IV q8h (carbapenem-susceptible Pseudomonas); ceftolozane-tazobactam (MDR Pseudomonas); ceftazidime-avibactam (XDR Pseudomonas with OprD mutation)",notes:"Pseudomonas bacteremia from DFI is uncommon but carries high mortality. Extended infusion pip-tazo or cefepime is strongly preferred for PK/PD optimization. Dual anti-pseudomonal therapy (e.g., pip-tazo + ciprofloxacin) was historically used for severe Pseudomonas infections but is no longer recommended by most guidelines — monotherapy with adequate PK/PD optimization is preferred. Check susceptibility to ALL anti-pseudomonal agents including polymyxins for MDR strains."},{organism:"Polymicrobial severe DFI (mixed gram-positives + gram-negatives + anaerobes)",preferred:"Pip-tazo 4.5g IV q6h (extended infusion) + vancomycin IV — covers entire polymicrobial spectrum",alternative:"Meropenem + vancomycin (higher ESBL/MDR risk); ertapenem + vancomycin (no Pseudomonas risk)",notes:"Polymicrobial bacteremia from severe DFI requires coverage of all bacteremic organisms until clinical improvement and culture-directed de-escalation. The most important concept: do NOT routinely cover all wound-swab organisms — target only organisms from blood cultures or deep tissue cultures. Surface swabs in severe DFI commonly grow 4-6 organisms; treating all of them empirically IV is not evidence-based."},{organism:"Enterococcus — severe DFI (rare primary pathogen; frequently a co-colonizer)",preferred:"Ampicillin 2g IV q4h (E. faecalis, ampicillin-susceptible); vancomycin IV (E. faecalis — second-line); linezolid or daptomycin (VRE — E. faecium)",alternative:"Ceftaroline (limited Enterococcal activity); consultation with ID for VRE bacteremia",notes:"Enterococcus is commonly isolated from DFI wounds but is rarely a primary pathogen — it is usually a colonizer. IDSA/IWGDF 2023: routine empiric anti-enterococcal coverage is NOT recommended for most DFIs (analogous to IAI guidance). However, if Enterococcus is isolated from blood culture in severe DFI: treat definitively. E. faecalis (ampicillin-susceptible): ampicillin is bactericidal and superior to vancomycin. E. faecium (often ampicillin-resistant): vancomycin or linezolid for VSE; daptomycin or linezolid for VRE."}],pearls:["Source control is the cornerstone — antibiotics are adjunctive: A severe DFI that is not responding to appropriate IV antibiotics at 48-72 hours almost always has inadequate source control as the explanation, NOT the wrong antibiotic. The 'wrong antibiotic' explanation should only be considered after confirming: (1) surgical debridement was complete, (2) all abscesses were drained, (3) necrotic tissue was removed, (4) the organism on culture matches the empiric regimen. If source control is incomplete, escalating antibiotics is ineffective — the patient needs to return to the OR.","Extended infusion piperacillin-tazobactam is a high-impact pharmacist intervention: Pip-tazo is a time-dependent antibiotic (pharmacodynamic driver: T>MIC). Traditional q6h 30-minute infusions achieve T>MIC of 50-60% for susceptible organisms. Extended infusion (4h infusion q6h) increases T>MIC to 80-100% — clinically significant improvement in target attainment for intermediate-susceptibility Pseudomonas and other organisms. Multiple studies show clinical outcome improvement with extended infusion. This is a straightforward pharmacist-driven intervention that requires no additional cost.","Procalcitonin for antibiotic duration guidance: Procalcitonin-guided antibiotic cessation is validated in respiratory infections but emerging data support use in severe DFI/bacteremia. Procalcitonin >0.25 ng/mL at 48h suggests ongoing bacterial infection — consider continuing IV antibiotics. Procalcitonin declining by >80% from peak, in conjunction with clinical improvement, supports transition to oral step-down or stopping antibiotics in soft tissue DFI. This is not a substitute for clinical judgment but is a useful objective marker.","Daptomycin dose escalation for osteomyelitis: Standard daptomycin dosing is 4 mg/kg (FDA-approved for SSTI) and 6 mg/kg (bacteremia). For DFI osteomyelitis, many ID physicians and pharmacists use 8-10 mg/kg based on pharmacodynamic modeling showing improved AUC/MIC target attainment in bone tissue and against biofilm-embedded MRSA. Clinical evidence supporting 8-10 mg/kg for osteomyelitis is observational, not RCT-based, but the practice is widely adopted. Monitor CPK weekly at any daptomycin dose.","Amputation is sometimes the best antimicrobial therapy: For severe DFI with gangrene, extensive osteomyelitis, or MDR organisms in non-viable tissue, amputation provides the most definitive source control. After amputation with clean stump margins, antibiotic duration can be dramatically shortened (days to 1-2 weeks for soft tissue infection surrounding the amputation site). A DFI patient declining indicated amputation who is then treated indefinitely with antibiotics is a major stewardship concern — antibiotics cannot cure gangrenous or non-perfused tissue.","Glycemic emergency management: Severe DFI commonly precipitates hyperglycemic crises (DKA or HHS). Insulin infusion protocols for BG >300 mg/dL in severe DFI are an important pharmacist-managed intervention. Resolving the metabolic emergency restores neutrophil function and improves antibiotic efficacy. The pharmacist bridges the DFI management (antibiotics) with the acute care management (insulin, electrolytes) — a unique value-added role in severe DFI."]},{id:"dfi-osteomyelitis",name:"Diabetic Foot Osteomyelitis",definition:"Osteomyelitis complicating diabetic foot infection — contiguous spread of infection from an overlying infected ulcer into the underlying bone cortex and marrow. Occurs in 20-60% of moderate-severe DFIs. The diagnostic challenge: distinguishing osteomyelitis from Charcot neuroarthropathy (which mimics osteomyelitis on imaging) and from colonized but non-infected bone. The therapeutic challenge: achieving adequate antibiotic concentrations in avascular, biofilm-colonized bone and deciding between medical-only management vs. surgical resection. The management paradigm has shifted dramatically with OVIVA (oral non-inferior to IV) and post-resection data (5-day post-op course if clean margins). Bone biopsy is the gold standard for diagnosis and for culture-directed therapy — surface wound cultures do NOT reflect bone pathogens.",clinicalPresentation:"Chronic non-healing diabetic foot ulcer — particularly plantar, overlying a bony prominence — that has failed to close despite appropriate wound care. Probe-to-bone (PTB) test: positive when sterile metal probe inserted through ulcer contacts bone with gritty sensation (PPV ~89% in clinic populations with high pre-test probability; PPV lower in ED populations). Sausage toe (dactylitis): diffuse fusiform swelling of an entire digit — highly suggestive of phalangeal osteomyelitis. Bare bone visible in wound base. Minimally tender or painless (peripheral neuropathy). Often NO fever, NO leukocytosis — systemic signs are frequently absent in DFI osteomyelitis. Fetid odor suggests polymicrobial involvement with anaerobes. Imaging showing cortical erosion or periosteal reaction overlying an ulcer is virtually diagnostic.",diagnostics:"PROBE-TO-BONE TEST (PTB): First-line bedside assessment. Insert a sterile blunt metal probe through the ulcer. Positive = gritty sensation of contacting bone. PPV ~89% in high pre-test probability population (clinic DFI patients). NPV ~56% (does NOT rule out osteomyelitis). Sensitivity 66%, specificity 85%. Positive PTB in moderate-severe DFI = presumptive osteomyelitis until proven otherwise. PLAIN RADIOGRAPHS: Obtain immediately — cortical erosion, periosteal reaction, bone destruction, gas in soft tissue. Sensitivity only 30-50% in early osteomyelitis (bone changes take 2-3 weeks to appear). Normal XR does NOT rule out osteomyelitis. MRI WITH AND WITHOUT GADOLINIUM: Gold standard for DFI osteomyelitis. Sensitivity 90%, specificity 80%. Shows marrow edema (T2 hyperintensity), cortical destruction, soft tissue extent, and concurrent joint involvement. MRI is essential before committing to bone resection. Cannot distinguish Charcot from osteomyelitis definitively in some cases — clinical and microbiologic correlation required. BONE BIOPSY: Gold standard for definitive diagnosis (histology + culture). Obtain BEFORE starting antibiotics whenever possible — antibiotics reduce bone culture yield from 70-80% to 30-50%. Two approaches: (1) Percutaneous CT-guided biopsy (best for deep bones, minimal contamination risk — preferred when the overlying skin is intact or when there is concern for contamination via the ulcer), (2) Intraoperative bone biopsy (gold standard if patient goes to OR — send bone to both pathology and microbiology). Surface wound swabs DO NOT predict bone culture results — they grow colonizers, not the bone pathogen. ESR AND CRP: ESR >70 mm/h = high specificity for osteomyelitis in DFI setting (sensitivity only 72%). CRP: excellent for monitoring treatment response — trend every 1-2 weeks. A CRP failing to decline after 2-3 weeks should trigger re-evaluation. NUCLEAR MEDICINE IMAGING: MRI-labeled WBC scan or PET-CT: used when MRI is contraindicated (hardware, claustrophobia) or when Charcot vs. osteomyelitis distinction is critical. Less readily available; interpret with ID guidance. VASCULAR ASSESSMENT: ABI, toe pressures, or transcutaneous oxygen tension (TcPO2 <30 mmHg = severe ischemia, poor healing regardless of antibiotic adequacy). This step is mandatory — no antibiotic heals osteomyelitis in an ischemic limb.",durationGuidance:{standard:"6 weeks total (IV or IV→oral per OVIVA) — medical management without bone resection",severe:"3 months (non-surgical, conservative management for extensive osteomyelitis or patient refusing surgery)",opatNote:"OPAT is strongly preferred after initial inpatient stabilization. Once-daily options: ertapenem 1g IV q24h (MSSA, Enterobacterales, anaerobes — no MRSA/Pseudomonas), daptomycin 6-10 mg/kg IV q24h (MRSA, gram-positives), ceftriaxone 2g IV q24h (Streptococci, susceptible gram-negatives). Ensure OPAT monitoring protocol: weekly CBC, BMP, drug levels if applicable. OPAT pharmacist follow-up every 48-72h for first 2 weeks, then weekly.",stewardshipNote:"PARADIGM SHIFT — If complete surgical resection of infected bone is achieved with confirmed clean margins on histopathology, post-operative antibiotic duration can be as short as 5-7 days (IDSA/IWGDF 2023; Ha Van et al. 2003). The surgery does the therapeutic work — antibiotics are only required to treat residual soft tissue infection. This represents a dramatic reduction from the historical dogma of 6 weeks post-amputation antibiotics. OVIVA 2019: For medically managed osteomyelitis, oral non-inferior to IV for bone/joint infections — use fluoroquinolones, TMP-SMX, linezolid, or clindamycin (NOT amoxicillin or cephalexin monotherapy) for oral step-down. Early oral step-down after 7-10 days of IV is now standard of care when appropriate agents are available."},empiricTherapy:[{line:"Medical Management — Empiric, Pending Bone Culture",options:[{drug:"vanc-erta-osteo-empiric",regimen:"Vancomycin IV (AUC 400-600) + Ertapenem 1g IV q24h (empiric, pending bone biopsy results)",notes:"Broad empiric coverage pending bone culture: vancomycin for MRSA/gram-positives, ertapenem for Enterobacterales/anaerobes/MSSA. HOLD antibiotics for 48-72 hours (if clinically stable) to allow bone biopsy — culture yield plummets after antibiotics started. If bone biopsy cannot be obtained or must be delayed, start empiric therapy and accept empiric limitations. Narrow aggressively within 48-72h of culture results. Do NOT continue broad empiric coverage for 6 weeks without organism identification — this drives resistance and increases toxicity.",evidence:"B-III",evidenceSource:"IDSA/IWGDF 2023"}]},{line:"Medical Management — Pathogen-Directed, MSSA Osteomyelitis",options:[{drug:"cefazolin-mssa-osteo",regimen:"Cefazolin 2g IV q8h × 2-6 weeks → oral step-down (levofloxacin 750mg PO q24h + rifampin 300mg PO q12h, OR TMP-SMX DS 2 tabs PO BID) to complete 6 weeks total",notes:"Gold standard for MSSA osteomyelitis. Initial IV cefazolin for 1-2 weeks achieves rapid bactericidal activity in bone. OVIVA-supported oral step-down after initial IV period: levofloxacin 750mg daily (excellent bone penetration ~30-50% of serum concentrations) ± rifampin 300mg BID (biofilm penetration — see pearl below). Rifampin combination for osteomyelitis: data is strongest for Staphylococcal PJI (Zimmerli trial), but extrapolated to DFI osteomyelitis by many ID specialists — use with companion drug only (resistance develops rapidly with rifampin monotherapy). CRP trending every 2 weeks confirms treatment response.",evidence:"A-I",evidenceSource:"IDSA/IWGDF 2023"},{drug:"diclox-mssa-osteo-oral",regimen:"Dicloxacillin 500mg PO QID × 6 weeks (mild-moderate MSSA osteomyelitis, OVIVA-eligible patients)",notes:"For selected MSSA DFI osteomyelitis in OVIVA-eligible patients: oral from the start or after ≤7 days IV. Dicloxacillin achieves adequate serum concentrations for MSSA osteomyelitis but bone penetration is lower than fluoroquinolones. Must be taken on empty stomach. Most ID experts prefer fluoroquinolone or TMP-SMX oral step-down over dicloxacillin for bone infections — better bone concentration data. Discuss with ID.",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023"}]},{line:"Medical Management — Pathogen-Directed, MRSA Osteomyelitis",options:[{drug:"vanc-mrsa-osteo",regimen:"Vancomycin IV (AUC/MIC 400-600) × 2-6 weeks → oral TMP-SMX DS 2 tabs PO BID to complete 6 weeks total",notes:"Standard IV therapy for MRSA DFI osteomyelitis. AUC-guided Bayesian dosing is mandatory — trough-only monitoring is no longer standard (2020 consensus). Target AUC/MIC 400-600 mg·h/L. Oral step-down: TMP-SMX DS 2 tabs BID (workhorse for MRSA osteomyelitis — excellent bone penetration, generally tolerated long-term). Monitor: creatinine (false rise from tubular creatinine secretion block — educate team this is not true AKI), potassium (hyperkalemia risk — check weekly), CBC. Linezolid 600mg BID is alternative oral step-down if TMP-SMX not tolerated.",evidence:"A-I",evidenceSource:"IDSA/IWGDF 2023"},{drug:"dapto-mrsa-osteo-opat",regimen:"Daptomycin 8-10 mg/kg IV q24h × 6 weeks (MRSA osteomyelitis, OPAT-preferred regimen)",notes:"Daptomycin at 8-10 mg/kg is preferred over vancomycin by many ID specialists for MRSA DFI osteomyelitis in the OPAT setting: (1) Once-daily dosing (easier for home infusion), (2) No AUC monitoring required (CPK monitoring suffices), (3) Higher tissue concentrations at 8-10 mg/kg (superior bone penetration), (4) Activity against biofilm-embedded MRSA. Clinical evidence for high-dose daptomycin in osteomyelitis is observational. CPK monitoring weekly — myopathy risk increases above 6 mg/kg. Suspend concurrent statins.",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023"}]},{line:"Medical Management — Pathogen-Directed, Gram-Negative Osteomyelitis",options:[{drug:"cipro-gn-osteo",regimen:"Ciprofloxacin 750mg PO BID × 6 weeks (gram-negative osteomyelitis, susceptible organism)",notes:"Fluoroquinolones are the BEST oral agents for gram-negative osteomyelitis — highest oral bioavailability (~80%) and highest bone penetration ratio of any oral class. Ciprofloxacin 750mg BID achieves bone concentrations at 30-50% of peak serum concentration. OVIVA strongly supports oral fluoroquinolones for gram-negative bone infections. Check susceptibility before using — resistance in E. coli is 15-25%, Pseudomonas 20-40% in many US centers. Levofloxacin 750mg once daily is an alternative with better gram-positive coverage and simpler dosing.",evidence:"A-I",evidenceSource:"IDSA/IWGDF 2023"},{drug:"ertapenem-esbl-osteo",regimen:"Ertapenem 1g IV q24h × 6 weeks (ESBL-producing Enterobacterales osteomyelitis, OPAT setting)",notes:"For ESBL-producing gram-negative DFI osteomyelitis: ertapenem 1g IV once daily is the preferred OPAT agent. Does NOT cover Pseudomonas — ensure Pseudomonas is not a co-pathogen. Once-daily dosing compatible with home infusion nurse visits every other day. Renally eliminated — adjust for CrCl <30 mL/min. Oral step-down for ESBL osteomyelitis is challenging — fluoroquinolone only if confirmed susceptible.",evidence:"A-II",evidenceSource:"IDSA/IWGDF 2023"}]},{line:"Surgical Resection — Post-Operative Antibiotic Duration",options:[{drug:"post-resection-clean-margins",regimen:"Antibiotics for 5-7 days post-operatively (complete bone resection with histologically confirmed clean margins)",notes:"PARADIGM SHIFT (IDSA/IWGDF 2023; Ha Van 2003): If ALL infected bone is resected with pathologically confirmed clean margins, only 5-7 days of post-operative antibiotics are needed — to treat residual soft tissue infection, not residual bone infection. The surgery has eliminated the bone infection. Antibiotics post-resection address any surrounding soft tissue component. This dramatically reduces treatment burden vs. historical 6-week post-op courses. CRITICAL: 'clean margins' must be confirmed by pathology (absence of osteomyelitis on histology at resection edge) — not just clinical or surgical judgment.",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023"},{drug:"post-resection-dirty-margins",regimen:"Antibiotics for 2-4 weeks post-operatively (incomplete resection or positive margins on histology)",notes:"When intraoperative cultures are positive and/or histology shows residual osteomyelitis at the resection margin: treat as ongoing osteomyelitis. Duration: 2-4 weeks from the date of resection (not from initial diagnosis). The goal is pathogen-directed therapy guided by intraoperative bone culture. Surface wound cultures from the amputation stump do NOT guide this therapy — intraoperative bone cultures are the essential data point.",evidence:"B-III",evidenceSource:"IDSA/IWGDF 2023"}]}],organismSpecific:[{organism:"S. aureus (MSSA) — most common single organism in DFI osteomyelitis",preferred:"Cefazolin 2g IV q8h (IV phase); levofloxacin 750mg PO q24h ± rifampin 300mg PO q12h (oral step-down for bone); TMP-SMX DS 2 tabs PO BID (alternative oral step-down)",alternative:"Nafcillin 2g IV q4h (bacteremia — superior bactericidal activity); dicloxacillin 500mg PO QID (oral — adequate but lower bone penetration than fluoroquinolones)",notes:"MSSA is the most common single organism when bone biopsy is performed. However, 20-30% of DFI osteomyelitis is truly polymicrobial even on bone culture. OVIVA-supported oral step-down: levofloxacin for gram-positive osteomyelitis has good evidence. Rifampin combination for MSSA osteomyelitis is used by many ID physicians for biofilm penetration — always pair with levofloxacin or TMP-SMX (never rifampin monotherapy)."},{organism:"S. aureus (MRSA) — DFI osteomyelitis",preferred:"Vancomycin IV (AUC/MIC 400-600) [IV phase]; TMP-SMX DS 2 tabs PO BID [oral step-down]; linezolid 600mg PO BID [oral step-down alternative]",alternative:"Daptomycin 8-10 mg/kg IV q24h (OPAT-preferred); doxycycline 100mg PO BID (if susceptible, less data for osteomyelitis vs. SSTI)",notes:"MRSA osteomyelitis is the most challenging DFI scenario. Biofilm-embedded MRSA is resistant to killing by vancomycin (poor biofilm penetration). Daptomycin at high doses (8-10 mg/kg) has superior biofilm activity. TMP-SMX as oral step-down for MRSA osteomyelitis: well-established by OVIVA and retrospective data. Linezolid achieves excellent bone concentrations (105% of serum — one of the best bone penetrators). Rifampin for MRSA osteomyelitis: used by some ID experts but less data than for MSSA/PJI — use with caution and always with companion drug."},{organism:"Streptococcus agalactiae (Group B Strep) — DFI osteomyelitis in elderly diabetics",preferred:"Ceftriaxone 2g IV q24h (OPAT-convenient); amoxicillin 1g PO TID (oral step-down)",alternative:"Penicillin G 3-4 MU IV q4h (bactericidal osteomyelitis treatment); cephalexin 500mg PO QID (oral)",notes:"Group B Strep is particularly prevalent in osteomyelitis of the elderly diabetic patient, often due to urinary tract source. Penicillin-susceptible universally — narrow to penicillin or amoxicillin when confirmed. Ceftriaxone once-daily is ideal for OPAT. 6-week course for medical management; shorter if complete resection achieved."},{organism:"Enterobacterales (E. coli, Klebsiella, Proteus) — DFI osteomyelitis, chronic wounds",preferred:"Ertapenem 1g IV q24h (ESBL or initial IV therapy); ciprofloxacin 750mg PO BID or levofloxacin 750mg PO q24h (oral step-down if susceptible)",alternative:"Ceftriaxone 2g IV q24h (susceptible, non-ESBL); meropenem 1g IV q8h (severe/resistant)",notes:"Gram-negative osteomyelitis in DFI: fluoroquinolone step-down is the best oral option (highest bone penetration of any oral class). Check susceptibilities carefully — fluoroquinolone resistance in Enterobacterales is increasing. For ESBL: ertapenem IV for duration, or consider fluoroquinolone oral step-down only if confirmed susceptible. For osteomyelitis Proteus species: susceptible to ampicillin (if non-ESBL), cephalosporins, fluoroquinolones — avoid nitrofurantoin (intrinsic resistance)."},{organism:"Culture-Negative DFI Osteomyelitis (after adequate bone biopsy, held pre-antibiotic)",preferred:"Empiric coverage of most likely pathogens based on clinical context: vancomycin + ertapenem (moderate-severe, polymicrobial risk); amoxicillin-clavulanate PO (mild, outpatient)",alternative:"Consult ID for atypical organisms if culture-negative despite holding antibiotics before biopsy",notes:"True culture-negative osteomyelitis after proper technique (percutaneous or intraoperative bone biopsy, held before antibiotics, adequate lab processing) occurs in 20-30% of cases. Consider: prior antibiotics suppressing growth (most common cause), slow-growing organisms (Cutibacterium acnes — hold cultures 14 days), Mycobacteria (AFB stain and culture), fungi (endemic mycoses in high-risk regions). 16S rRNA PCR from bone tissue can identify organisms not growing on standard culture — request when unexplained culture negativity. Empiric broad-spectrum for 6 weeks is less ideal than pathogen-directed therapy but may be necessary."}],pearls:["Biofilm is why short antibiotic courses fail in untreated osteomyelitis: Bone-infecting organisms (particularly S. aureus) form biofilm on necrotic bone and sequestra. Within a biofilm, bacteria exist in a sessile, metabolically quiescent state with dramatically altered gene expression — they become 100-1000x more tolerant to antibiotics than planktonic organisms. This is the fundamental reason osteomyelitis requires weeks of therapy rather than days. The only way to definitively overcome biofilm is: (1) surgical removal of all infected/necrotic bone (sequestrum, debridement), or (2) prolonged antibiotic exposure exceeding the biofilm tolerance threshold. Incomplete surgery + short antibiotics = relapse. This is why the post-resection clean margin data (5-7 days) is so powerful — the surgery eliminates the biofilm substrate.","OVIVA changed the IV-oral debate for osteomyelitis permanently: Before OVIVA (2019), 6 weeks of IV antibiotics via PICC was the near-universal standard for osteomyelitis. OVIVA demonstrated oral non-inferiority in 1,054 bone/joint infection patients. The key message is NOT 'oral is always fine' — it is 'the RIGHT oral agents are equivalent.' Right oral agents: fluoroquinolones (best bone penetration), TMP-SMX (MRSA), linezolid (MRSA, gram-positives), rifampin combinations (Staphylococci with biofilm — never monotherapy), clindamycin (gram-positives, anaerobes). WRONG oral agents for osteomyelitis: amoxicillin monotherapy, cephalexin — these have inadequate bone penetration for osteomyelitis. Knowing this distinction is a core pharmacist competency in DFI management.","Surface wound swabs are misleading and should not guide osteomyelitis therapy: This point cannot be overstated. Multiple studies demonstrate that surface swab cultures in chronic DFIs grow organisms that DO NOT match bone biopsy cultures in 50-70% of cases. A 6-week course of IV antibiotics directed at Pseudomonas aeruginosa grown on a surface swab — when the bone culture actually grows MSSA — is a patient safety event. Advocate for bone biopsy before starting any prolonged antibiotic course for osteomyelitis. If bone biopsy is truly not obtainable, explicitly document the reason and acknowledge the uncertainty driving empiric coverage.","Vascular assessment before attributing treatment failure to antibiotic inadequacy: ABI <0.5 or toe pressure <30 mmHg represents severe ischemia. In ischemic limbs, tissue antibiotic concentrations are severely reduced — the antibiotic cannot reach the infection. A patient with DFI osteomyelitis and PAD who is failing appropriate antibiotics almost certainly needs revascularization first, before changing antibiotics. ABI and toe pressures (or TcPO2) should be obtained at initial evaluation and before any major antibiotic change in a non-responding DFI. Vascular surgery consultation is mandatory for ABI <0.6.","Fluoroquinolone bone penetration vs. resistance risk balance: Fluoroquinolones achieve the highest bone-to-serum concentration ratios of any oral antibiotic class (30-50% bone penetration). They are the most studied and most effective oral agents for gram-negative osteomyelitis. However: (1) FDA boxed warning for peripheral neuropathy, tendinopathy, and CNS effects — particularly concerning in diabetics with pre-existing peripheral neuropathy, (2) Rapidly increasing resistance (E. coli resistance to ciprofloxacin is now 15-25% in many US centers — always check susceptibility before prescribing for culture-directed gram-negative osteomyelitis), (3) Prior fluoroquinolone use within 90 days should deter empiric fluoroquinolone use. In MRSA DFI osteomyelitis, fluoroquinolones have no role as monotherapy — pair with rifampin or use TMP-SMX/linezolid.","Linezolid for gram-positive bone and tissue concentrations — practical pearls: Linezolid achieves bone concentrations of 105% of simultaneous plasma concentrations — one of the very highest bone penetrators of any antibiotic. It is effective for MRSA osteomyelitis in OVIVA-eligible patients and is FDA-approved for gram-positive infections. PRACTICAL LIMITATIONS: (1) Cost — linezolid is expensive and often requires prior authorization; (2) Myelosuppression — CBC weekly; thrombocytopenia occurs in 2-3% at 14 days, up to 20-30% at 28+ days — particularly in renal impairment where the drug accumulates; (3) Serotonin syndrome — review the patient's full medication list (SSRIs, SNRIs, tramadol, triptans, MAOIs — very common drug interactions in the diabetic elderly population); (4) Lactic acidosis — rare but potentially fatal with prolonged use (mitochondrial toxicity affecting lactate metabolism); limit to <6 weeks when possible.","The multidisciplinary team is not optional: DFI osteomyelitis management requires: ID physician (antibiotic selection, duration, step-down decisions), infectious disease pharmacist (OPAT coordination, PK/PD optimization, drug interactions, monitoring), podiatry/orthopedic surgery (bone debridement, amputation decision), vascular surgery (revascularization assessment), wound care nursing (dressing management, offloading education), endocrinology (glycemic optimization), and social work (OPAT feasibility, housing, adherence support). No single service can optimize all these variables simultaneously. The pharmacist in this team plays a coordination and advocacy role that directly impacts antibiotic stewardship, patient safety, and clinical outcomes."]}],drugMonographs:[]},A={id:"sepsis",name:"Sepsis & Septic Shock",icon:"🔴",category:"Critical Care / Infectious Disease",overview:{definition:"Sepsis-3 (Singer et al., JAMA 2016): Sepsis is life-threatening organ dysfunction caused by a dysregulated host response to infection. Organ dysfunction is defined by a SOFA score increase ≥2 points (associated with in-hospital mortality >10%). Septic shock: vasopressor requirement to maintain MAP ≥65 mmHg AND serum lactate >2 mmol/L despite adequate fluid resuscitation — in-hospital mortality >40%. Quick-SOFA (qSOFA ≥2): altered mentation + RR ≥22 + SBP ≤100 is a rapid bedside screen outside the ICU. The terms 'severe sepsis' and SIRS criteria for sepsis diagnosis have been retired. Key principle: time-to-antibiotics is the primary modifiable determinant of mortality — every hour of delay in antibiotic administration associated with ~7% increase in mortality for septic shock.",epidemiology:"Sepsis affects ~1.7 million adults annually in the US with ~270,000 deaths per year — exceeding prostate cancer, breast cancer, and AIDS combined. It is the most expensive condition treated in US hospitals (>$24 billion/year). Worldwide, sepsis causes ~11 million deaths annually (20% of all global deaths). In-hospital mortality: 10–30% for sepsis, 40–60% for septic shock. ICU survivors face Post-Intensive Care Syndrome (PICS): long-term cognitive impairment, physical disability, PTSD, and depression. Source distribution: pulmonary 35–40%, urinary 20–25%, intra-abdominal/biliary 15–20%, skin/soft tissue 10%, primary bacteremia/catheter-related 10%. Gram-positive organisms account for ~50% of bacteremias; gram-negatives ~40%; fungi ~5–10%. MRSA causes ~20% of all S. aureus bacteremia. Gram-negative bacteremia carries disproportionately high immediate mortality — Pseudomonas aeruginosa bacteremia in ICU patients has 30-day mortality of 30–50%.",keyGuidelines:[{name:"Surviving Sepsis Campaign (SSC) 2021 International Guidelines",detail:"The SSC 2021 is the global standard of care for sepsis/septic shock. Key antimicrobial recommendations: (1) Administer broad-spectrum antibiotics within 1 hour of septic shock or sepsis with organ dysfunction; within 3 hours of sepsis without shock. (2) Obtain blood cultures (≥2 sets) BEFORE antibiotics if possible without delaying >45 minutes. (3) Empiric combination gram-positive (MRSA) coverage for septic shock without clear source. (4) Procalcitonin-guided de-escalation — target PCT decline >80% from peak or PCT <0.5 ng/mL for antibiotic discontinuation. (5) Do NOT use dual gram-negative coverage once organism identified (no synergy benefit for bacteremia, adds toxicity). (6) Source control within 6–12 hours (drainage, debridement, catheter removal). (7) Fluid resuscitation: 30 mL/kg IV balanced crystalloid for MAP <65 or lactate ≥4 mmol/L within 3 hours. (8) Norepinephrine first-line vasopressor (MAP target ≥65 mmHg). (9) Hydrocortisone 200 mg/day IV for vasopressor-refractory septic shock. (10) Balanced crystalloids (LR, Plasma-Lyte) preferred over 0.9% NS."},{name:"Sepsis-3 Task Force (Singer et al., JAMA 2016)",detail:"Landmark consensus paper retiring SIRS criteria for sepsis diagnosis (SIRS is too non-specific — occurs in surgery, burns, pancreatitis). Introduced SOFA score as the operational criterion for organ dysfunction (≥2 point increase). Validated qSOFA (RR ≥22, altered mentation, SBP ≤100 — 2/3 = screen positive) as a rapid bedside tool outside the ICU. Established Septic Shock as requiring BOTH vasopressors for MAP ≥65 mmHg AND lactate >2 mmol/L (mortality >40%). Retired 'severe sepsis' as a separate category. This paradigm shift changed ICU admission criteria and antibiotic initiation thresholds globally."},{name:"IDSA 2024 Sepsis Antimicrobial Guidance",detail:"IDSA 2024 infectious disease-specific guidance: (1) Antibiogram-guided empiric selection based on local susceptibility patterns. (2) 7-day antibiotic courses for most sepsis with source control (supported by BALANCE trial 2024). (3) PCT-guided discontinuation. (4) Strongly against routine empiric antifungals without specific Candida risk factors (TPN, prolonged broad-spectrum abx, multi-site Candida colonization, immunocompromised, GI perforation). (5) For high-risk MRSA sepsis (prior MRSA, HD, IVDU, healthcare contact), add vancomycin or daptomycin empirically. (6) ESBL bacteremia: carbapenems are standard — pip-tazo has failed non-inferiority (MERINO trial). (7) De-escalate at 48–72h based on culture results and clinical trajectory."},{name:"BALANCE Trial 2024 — 7 vs. 14 Days for Non-Endocarditis Bacteremia",detail:"Landmark RCT (n=3,608 patients) comparing 7-day vs. 14-day antibiotic courses for bacteremia (excluding endocarditis). 90-day mortality was non-inferior in the 7-day group (14.5% vs. 16.1%). The 7-day course was associated with fewer adverse events, lower C. difficile incidence, and reduced costs. Exceptions where longer therapy may be warranted: S. aureus bacteremia with metastatic foci, endocarditis, immunocompromised patients. This trial strongly supports 7-day antibiotic courses for most bacteremia-associated sepsis when source is controlled and clinical improvement is evident."}],landmarkTrials:[{name:"MERINO Trial (Paul et al., JAMA 2018) — Pip-Tazo vs. Meropenem for ESBL Bacteremia",detail:"391 patients with E. coli or Klebsiella bacteremia (predominantly ESBL-producing) treated with piperacillin-tazobactam vs. meropenem. 30-day mortality: 12.3% (pip-tazo) vs. 3.7% (meropenem) — pip-tazo FAILED non-inferiority. The 'Eagle/inoculum effect' causes pip-tazo MIC to rise dramatically at high bacterial densities. MERINO definitively established: carbapenems (meropenem/ertapenem) — NOT pip-tazo — are the definitive treatment for ESBL-producing Enterobacterales bacteremia, regardless of in vitro susceptibility."},{name:"ARISE, ProCESS, ProMISe Trials (2014–2015) — EGDT vs. Standard Care",detail:"Three RCTs (ARISE n=1,600, ProCESS n=1,341, ProMISe n=1,260) failed to show benefit of the Rivers EGDT protocol (targeting CVP 8-12, ScvO2 ≥70%, MAP ≥65, UO ≥0.5 mL/kg/hr) over standard care. 90-day mortality was similar (~18–24% across all arms). EGDT required more blood transfusions, dobutamine, and resources without benefit. These trials validated protocolized standard care — early antibiotics + fluid resuscitation + vasopressors — as sufficient, and effectively retired the Rivers protocol."},{name:"SMART Trial (Semler et al., NEJM 2018) — Balanced Crystalloids vs. Normal Saline",detail:"15,802 ICU patients randomized to balanced crystalloids (LR or Plasma-Lyte) vs. 0.9% NS. Primary outcome MAKE-30 (death, new RRT, or persistent creatinine elevation): 14.3% balanced vs. 15.4% NS (OR 0.90, p=0.04). Sepsis patients had greater benefit. Excess NS causes hyperchloremic metabolic acidosis and may worsen renal outcomes. SSC 2021 recommends balanced crystalloids over NS; NS remains acceptable when balanced crystalloids unavailable."},{name:"ANDROMEDA-SHOCK Trial (Hernandez et al., JAMA 2019) — CRT vs. Lactate-Guided Resuscitation",detail:"424 septic shock patients randomized to capillary refill time (CRT)-guided vs. serum lactate-guided resuscitation. CRT-guided group trended toward lower 28-day mortality (34.9% vs. 43.4%, p=0.06), received less fluid, shorter vasopressor duration. Established peripheral perfusion assessment (CRT ≤3 seconds) as a valid complementary resuscitation endpoint to lactate clearance."},{name:"ADRENAL Trial (Venkatesh et al., NEJM 2018) — Hydrocortisone in Septic Shock",detail:"3,800 ventilated patients with septic shock randomized to hydrocortisone 200mg/day vs. placebo. 90-day mortality: 27.9% hydrocortisone vs. 28.8% placebo (p=0.50 — no significant difference). BUT: hydrocortisone significantly reduced vasopressor duration, ICU LOS, and time to shock resolution. SSC 2021 still recommends low-dose corticosteroids for vasopressor-refractory septic shock based on physiological rationale and shock-resolution benefit."}],riskFactors:"HOST FACTORS: Age extremes (neonates, elderly >65 — impaired immune response); functional immunosuppression (chemotherapy, high-dose corticosteroids ≥20 mg prednisone/day, biologic agents, calcineurin inhibitors); solid organ transplant (first year highest risk); HIV/AIDS (CD4 <200); hematologic malignancies (leukemia, lymphoma, myeloma); diabetes mellitus (impaired neutrophil function, vascular disease, autonomic neuropathy); chronic organ failure (cirrhosis Child-Pugh B/C, ESRD/dialysis, CHF NYHA III-IV, COPD GOLD 3-4); malnutrition; chronic alcohol use disorder; pregnancy (group B Streptococcus, E. coli, UTI-related). HEALTHCARE-ASSOCIATED RISK FACTORS: Indwelling vascular catheters (CVL, PICC, HD catheter — primary gram-positive bacteremia risk); urinary catheters (Candida, gram-negative UTI); mechanical ventilation (VAP); recent surgery (especially GI/biliary/urologic); recent broad-spectrum antibiotics (C. diff, Candida, MDR selection); prolonged hospitalization ≥5 days; nursing home/LTAC residence; prior MRSA or VRE colonization. MDR RISK FLAGS: MRSA — prior MRSA, HD, IVDU, healthcare contact within 90 days. ESBL — prior ESBL isolation, prior fluoroquinolone/cephalosporin exposure, travel to endemic region. Candida — TPN ≥5 days + broad-spectrum abx, abdominal surgery with GI perforation, transplant, Candida colonization ≥2 sites. Pseudomonas — structural lung disease (bronchiectasis, cystic fibrosis), prior Pseudomonas, prolonged ICU, immunocompromised."},subcategories:[{id:"sepsis-community",name:"Community-Acquired Sepsis",definition:"Sepsis arising outside the hospital or within <48 hours of admission without recent healthcare contact (no hospitalization, no outpatient IV therapy, no HD, no nursing home residence within 90 days). Common sources: pneumonia (S. pneumoniae, atypicals, gram-negatives), urinary tract (E. coli, Klebsiella), intra-abdominal (polymicrobial), skin/soft tissue (S. aureus, Streptococcus). MDR coverage generally NOT required without specific risk factors. De-escalate aggressively once culture results available.",clinicalPresentation:"Temperature >38.3°C or <36°C (fever or hypothermia — hypothermia is an ominous sign); HR >90 bpm; RR >20 or PaCO2 <32 mmHg; altered mentation (early sign — do not dismiss); hypotension (SBP <90 or MAP <65 mmHg); oliguria (UO <0.5 mL/kg/hr for ≥2h); elevated lactate (>2 mmol/L = tissue hypoperfusion). Septic shock: hypotension requiring vasopressors + lactate >2 mmol/L despite adequate fluids. Source-specific: pneumonia — cough, dyspnea, pleuritic chest pain, infiltrate on CXR; UTI — dysuria, flank pain, CVA tenderness (though may be absent in elderly); IAI — abdominal pain, guarding/rigidity, rebound, absent bowel sounds; SSTI — warmth, erythema, fluctuance, skin breakdown.",diagnostics:"CULTURES (before antibiotics, do not delay >45 min): Blood cultures ×2 (different sites, 10 mL per bottle) — essential even with clear source. Urine culture and UA. Source-specific: CXR (pneumonia), CT abdomen/pelvis with IV contrast (IAI — abscess, perforation, biliary obstruction), wound culture (SSTI). LABS: CBC with differential, BMP (creatinine, BUN, glucose, electrolytes), LFTs (total bilirubin — SOFA component), lactate (repeat if >2 mmol/L to monitor clearance), coagulation (PT, aPTT, fibrinogen — DIC screen in severe sepsis), blood gas (pH, PaO2, bicarbonate — acid-base status). BIOMARKERS: Procalcitonin (PCT) at baseline — elevated in bacterial sepsis (>2 ng/mL supports bacterial etiology); use serial PCT to guide de-escalation. CRP (less specific than PCT). IMAGING: CXR for all patients; CT or ultrasound for undifferentiated source. SOFA score: calculate and reassess every 12–24h for organ dysfunction tracking.",durationGuidance:{standard:"7–10 days total for most community-acquired sepsis when source controlled and clinical improvement confirmed",severe:"14 days for S. aureus bacteremia; extend individualized for endocarditis (4–6 weeks); 7 days for most UTI-related sepsis",opatNote:"OPAT appropriate after 3–5 days of IV therapy when hemodynamically stable and source controlled. Oral step-down preferred when high-bioavailability agents available (fluoroquinolones, TMP-SMX, amoxicillin-clavulanate). Use PCT-guided therapy.",stewardshipNote:"Use PCT to guide de-escalation: PCT decline >80% from peak OR absolute PCT <0.5 ng/mL supports antibiotic discontinuation. Avoid extending empiric broad-spectrum therapy beyond 72h without clear clinical indication. BALANCE trial (2024): 7-day courses non-inferior to 14-day for bacteremia."},empiricTherapy:[{line:"First-Line Empiric — No MDR/MRSA Risk Factors",options:[{drug:"ceftriaxone",regimen:"Ceftriaxone 2g IV q24h ± Azithromycin 500mg IV/PO q24h (if CAP)",notes:"Preferred for urinary, biliary, and community pneumonia sources. Add azithromycin if atypical pneumonia suspected (CAP). Not reliable for ESBL, AmpC, or Pseudomonas. Excellent CNS penetration for meningitis (2g IV q12h for meningitis dosing).",evidence:"A-I",evidenceSource:"SSC 2021, IDSA CAP 2019"},{drug:"piperacillin-tazobactam",regimen:"Piperacillin-Tazobactam 4.5g IV q8h over 4h (extended infusion preferred) OR 3.375g IV q6h",notes:"Broader empiric coverage including anaerobes, Enterococcus faecalis, and most Pseudomonas. Preferred when abdominal/biliary source suspected or polymicrobial coverage needed. CRITICAL: Do NOT use as definitive therapy for ESBL bacteremia (MERINO trial — 3.3× higher mortality vs. meropenem). Extended 4h infusion optimizes T>MIC target attainment.",evidence:"A-I",evidenceSource:"SSC 2021; MERINO Trial JAMA 2018"},{drug:"cefepime",regimen:"Cefepime 2g IV q8h",notes:"Good gram-negative coverage including Pseudomonas aeruginosa. Appropriate when Pseudomonas risk present (structural lung disease, known colonization). No anaerobic coverage — add metronidazole 500mg IV q8h for abdominal source. Monitor for cefepime-induced neurotoxicity (encephalopathy, myoclonus) in renal impairment.",evidence:"A-I",evidenceSource:"SSC 2021"}]},{line:"Add-On for MRSA Coverage (When Risk Factors Present)",options:[{drug:"vancomycin",regimen:"Vancomycin IV — AUC-guided dosing (target AUC/MIC 400–600 per ASHP/IDSA 2020)",notes:"Add empirically when: prior MRSA infection/colonization, HD patient, IVDU, recent hospitalization within 90 days, suspected catheter-related BSI, skin/soft tissue source with MRSA risk, septic shock without clear source. De-escalate at 48–72h if blood cultures negative for MRSA and gram-positive not identified. AUC-guided dosing with pharmacy consult required.",evidence:"A-I",evidenceSource:"SSC 2021; ASHP/IDSA Vancomycin Guidelines 2020"},{drug:"daptomycin",regimen:"Daptomycin 8–10mg/kg IV q24h (high-dose for bacteremia/endocarditis)",notes:"Alternative to vancomycin for MRSA bacteremia — non-inferior to vancomycin in RCTs. Preferred if: vancomycin MIC ≥2, VRE enterococcal bacteremia, or prior vancomycin nephrotoxicity. Do NOT use for pneumonia (inactivated by pulmonary surfactant). Monitor CPK weekly for myopathy.",evidence:"A-I",evidenceSource:"Fowler et al., NEJM 2006"}]},{line:"Empiric Antifungal — Only if Specific Candida Risk Factors",options:[{drug:"micafungin",regimen:"Micafungin 100mg IV q24h OR Caspofungin 70mg IV ×1 then 50mg IV q24h",notes:"Do NOT add empiric antifungals routinely — SSC 2021 recommends against empiric antifungal for sepsis without specific risk factors. Reserve for: TPN-dependent + broad-spectrum abx ≥5 days + septic shock without source; abdominal surgery with GI perforation + Candida colonization; immunocompromised + persistent fever. Echinocandins are first-line for candidemia per IDSA 2016. Obtain ophthalmology fundoscopic exam if Candida in blood (endophthalmitis changes management).",evidence:"B-II",evidenceSource:"SSC 2021; IDSA Candidiasis 2016"}]}],pearls:["TIME IS TISSUE: For septic shock, each hour of antibiotic delay associated with ~7% mortality increase. Do NOT delay antibiotics to obtain imaging or await culture results.","Blood cultures before antibiotics — but do not delay antibiotics >45 minutes to get cultures. Two sets from different sites (peripheral + central or bilateral peripheral), 10 mL per bottle. Only 1-3 sets reduces sensitivity — always get ≥2 sets.","Empiric antibiotic breadth should match the likely source and local MDR epidemiology. Avoid over-treating community-acquired sepsis with carbapenem-level empiric therapy unless ESBL/MDR risk factors are present.","De-escalation is not optional — it is a patient safety and stewardship obligation. At 48–72h, review cultures, narrow to narrowest effective agent. 'I'll continue broad spectrum just to be safe' thinking leads to CDI, MDR selection, and adverse drug effects.","MERINO rule: Never use piperacillin-tazobactam as definitive therapy for ESBL bacteremia, regardless of in vitro susceptibility. The inoculum effect causes treatment failure. Use meropenem or ertapenem.","Lactate is not just a severity marker — it is an actionable resuscitation target. Lactate >2 mmol/L = cryptic shock (requires treatment even with normal BP). Reassess lactate at 2–4h. Lactate clearance ≥10% at 2h associated with improved outcomes."]},{id:"sepsis-hcap",name:"Healthcare-Associated Sepsis",definition:"Sepsis arising ≥48–72h after hospital admission OR in patients with significant healthcare exposure within the prior 90 days: hospitalization ≥2 days, hemodialysis, home IV therapy, nursing home/LTAC residence, outpatient wound care, or prior surgery. Risk for MRSA, ESBL-producing Enterobacterales, Pseudomonas aeruginosa, Acinetobacter baumannii, VRE, and Candida spp. is substantially elevated vs. community-acquired sepsis. Empiric therapy must be broader, with rapid de-escalation upon culture results.",clinicalPresentation:"Clinical presentation similar to community-acquired sepsis but often more subtle in elderly/immunocompromised patients. Key clues for HCAP: patient with indwelling catheter (CLABSI, CAUTI), recent ventilation (VAP — new fever + purulent secretions + infiltrate in ventilated patient), post-operative fever (SSI — wound erythema, drainage), C. diff (watery diarrhea in patient on broad-spectrum abx). CLABSI features: fever/rigors temporally related to catheter flush, erythema at catheter insertion site, multiple positive blood cultures (peripheral + central), quantitative blood cultures with colony count 3× higher from central vs. peripheral. Consider catheter removal for S. aureus bacteremia — high risk for metastatic seeding (osteomyelitis, endocarditis).",diagnostics:"CULTURES: Blood cultures ×2 (peripheral + from each vascular access device if CLABSI suspected — quantitative if available). Catheter tip culture (if removed). Urine culture (UA + C&S). Wound culture (deep swab or aspirate — not superficial swab). Tracheal aspirate or BAL for VAP. LABS: Same as community-acquired + procalcitonin. MDR SCREENING: If MDR risk, obtain rectal swab for CRE PCR (KPC, NDM) and MRSA nasal swab — results in 24–48h guide modification. IMAGING: CT chest/abdomen/pelvis with IV contrast for undifferentiated HCAP source. ECHOCARDIOGRAM: Transthoracic (or TEE) for S. aureus bacteremia — rule out endocarditis, which changes duration (4–6 weeks) and management.",durationGuidance:{standard:"7–14 days based on source, organism, and clinical response",severe:"14–28 days for S. aureus bacteremia with metastatic foci or endocarditis; 14–21 days for Pseudomonas or Acinetobacter bacteremia",opatNote:"OPAT feasible after clinical stabilization and source control — IV-only agents (vancomycin, carbapenems) require PICC/port. Prefer oral step-down (linezolid, TMP-SMX, fluoroquinolones) when susceptibility allows per OVIVA trial.",stewardshipNote:"Avoid empiric carbapenem continuation without ESBL or MDR confirmation. Use PCT-guided therapy. Consult Infectious Diseases for MDR organisms. BALANCE trial supports 7-day courses for most non-endocarditis bacteremia."},empiricTherapy:[{line:"First-Line Empiric HCAP (MRSA + Gram-Negative Coverage)",options:[{drug:"vancomycin-piptazo",regimen:"Vancomycin IV (AUC-guided) + Piperacillin-Tazobactam 4.5g IV q8h extended infusion",notes:"Standard empiric combination for HCAP without prior MDR isolates. Covers MRSA (vancomycin) + gram-negative including Pseudomonas (pip-tazo). De-escalate vancomycin if MRSA not identified at 48–72h. Switch from pip-tazo to meropenem if ESBL found in blood cultures (MERINO trial).",evidence:"B-II",evidenceSource:"SSC 2021; IDSA HCAP guidance"},{drug:"vancomycin-meropenem",regimen:"Vancomycin IV (AUC-guided) + Meropenem 2g IV q8h over 3h (extended infusion)",notes:"Preferred over pip-tazo combination when: prior ESBL isolate from patient, recent hospitalization in high-ESBL facility, abdominal source with high inoculum risk, immunocompromised, or local ESBL prevalence >20% in healthcare settings. Extended 3h infusion maximizes T>MIC for higher-MIC organisms (MIC 2–8 mg/L range).",evidence:"A-I",evidenceSource:"SSC 2021; MERINO Trial"}]},{line:"Suspected Carbapenem-Resistant Organism (CRO) — Immediately Consult ID",options:[{drug:"ceftazidime-avibactam",regimen:"Ceftazidime-Avibactam 2.5g IV q8h (for KPC-CRE) ± Aztreonam (for MBL-CRE/NDM)",notes:"For suspected KPC-producing CRE: ceftazidime-avibactam is first-line. For MBL-producing CRE (NDM, VIM, IMP): ceftazidime-avibactam does NOT cover MBLs — must add aztreonam (see Advanced & Resistant Pathogen Agents section for detailed management). Consult Infectious Diseases immediately. Obtain carbapenem resistance testing (CRE PCR panel, carbapenem MIC). Ceftazidime-avibactam + aztreonam combination covers all CRE classes.",evidence:"B-II",evidenceSource:"IDSA CRE Guidance 2023"}]},{line:"Suspected Candida Sepsis — High-Risk Patients",options:[{drug:"micafungin-hcap",regimen:"Micafungin 100mg IV q24h (first-line) OR Caspofungin 70mg IV ×1 then 50mg IV q24h",notes:"Add empiric antifungal when multiple Candida risk factors present in HCAP: TPN dependence + broad-spectrum abx ≥5 days + septic shock without source, multi-site Candida colonization (≥2 non-contiguous sites), recent abdominal surgery with GI perforation, solid organ transplant. Fluconazole acceptable only for hemodynamically stable patients with no prior azole exposure and low-risk for resistant Candida.",evidence:"B-II",evidenceSource:"SSC 2021; IDSA Candidiasis Guidelines 2016"}]}],pearls:["S. aureus bacteremia rule: ALL S. aureus bacteremias require echocardiography (TEE preferred over TTE for endocarditis sensitivity), follow-up blood cultures every 24–48h until clearance documented, ophthalmology consultation (endophthalmitis risk), and minimum 14 days IV antibiotics — even if source seems clear. Metastatic seeding is common.","CLABSI management: Remove the catheter when possible — catheter salvage for S. aureus or Candida bacteremia is associated with treatment failure. For coagulase-negative Staphylococci, catheter salvage may be attempted with antibiotic lock therapy in select patients with limited access.","Vancomycin AUC/MIC monitoring (ASHP/IDSA 2020): Target AUC/MIC 400–600 for MRSA sepsis. Use Bayesian dosing programs (not trough-only). Nephrotoxicity risk correlates with duration and concurrent nephrotoxins. Check baseline SCr and reassess daily in critically ill.","ESBL detection: Routine susceptibility testing may not identify ESBL-producing organisms. If E. coli or Klebsiella bacteremia is present with prior ESBL history, fluoroquinolone exposure, or healthcare contact — empirically escalate to meropenem/ertapenem regardless of in vitro pip-tazo susceptibility.","Rapid molecular diagnostics (BioFire FilmArray, VERIGENE, Accelerate Pheno): Pathogen and resistance gene identification from positive blood cultures in 1–5 hours. Can direct antibiotic stewardship intervention 24–48h before final susceptibility results. Consult ID or pharmacy to optimize rapid diagnostics use."]},{id:"septic-shock",name:"Septic Shock",definition:"Sepsis-3: Septic shock = sepsis + vasopressor requirement to maintain MAP ≥65 mmHg + serum lactate >2 mmol/L despite adequate fluid resuscitation. In-hospital mortality >40%. Requires immediate, aggressive resuscitation: (1) Blood cultures ×2, (2) broad-spectrum antibiotics within 1 hour, (3) 30 mL/kg IV balanced crystalloid within 3 hours, (4) norepinephrine for MAP <65 mmHg. Source identification and control within 6–12 hours. Empiric antibiotic selection must be maximally broad with de-escalation at 48–72h.",clinicalPresentation:"Presenting signs: High fever OR hypothermia (hypothermia is ominous), rigors/shaking chills (especially with bacteremia), profound hypotension (SBP <90 mmHg) unresponsive to 1–2L IV fluid challenge, altered mentation (confusion, agitation, somnolence), mottled skin/delayed capillary refill (peripheral vasoconstriction), oliguria (<0.5 mL/kg/hr), tachycardia >100 bpm, tachypnea >22 breaths/min, elevated lactate (>4 mmol/L = severe shock). SOFA ≥2 with organ dysfunction: elevated creatinine (renal), elevated bilirubin (hepatic), low PaO2/FiO2 (respiratory), elevated INR/bilirubin (hepatic), GCS <15 (neurological), vasopressor requirement (cardiovascular). Distributive shock physiology: high CO/CI, low SVR — warm extremities initially (warm shock) progressing to cold extremities as cardiac function depresses.",diagnostics:"Same as community-acquired sepsis diagnostics + SOFA score calculation at presentation and q12–24h. Bedside POCUS: cardiac (assess LV/RV function, pericardial effusion — sepsis cardiomyopathy), IVC (volume responsiveness assessment), pulmonary (B-lines = pulmonary edema vs. A-lines = hypovolemia). Consider PA catheter or PiCCO hemodynamic monitoring in refractory shock. ScvO2 (central venous O2 saturation) via central line: target >70% — persistently low suggests inadequate resuscitation or high O2 extraction. BIOMARKERS: lactate q2–4h until trending down; PCT at baseline and q48h for de-escalation guidance; BNP/proBNP for cardiac dysfunction assessment.",durationGuidance:{standard:"7–10 days for most sources with source control and clinical improvement; use PCT decline to guide shorter courses",severe:"14–21+ days for endocarditis, S. aureus bacteremia with seeding, bone/joint involvement, or persistent bacteremia",stewardshipNote:"Septic shock does NOT justify 14-day empiric antibiotics. Daily antibiotic time-out: assess de-escalation at every clinical review. Once organism and susceptibilities known — narrow immediately. Continuing broad-spectrum therapy drives resistance."},empiricTherapy:[{line:"Immediate Broad-Spectrum Empiric — Septic Shock (Within 1 Hour)",options:[{drug:"vanco-meropenem",regimen:"Vancomycin IV (AUC-guided, 25–30 mg/kg loading dose) + Meropenem 2g IV q8h over 3h ± Micafungin 100mg IV q24h if Candida risk",notes:"SSC 2021 recommended combination for septic shock of unclear source or healthcare-associated. Covers MRSA (vanco), ESBL (mero), Pseudomonas (mero), anaerobes (mero). Add micafungin if Candida risk factors present (see criteria above). Administer vancomycin loading dose first (25–30 mg/kg IV over 1–2h) to achieve rapid therapeutic levels. De-escalate within 48–72h based on culture data.",evidence:"A-I",evidenceSource:"SSC 2021"}]},{line:"Vasopressor and Adjunctive Therapy (Non-Antimicrobial — For Reference)",options:[{drug:"norepinephrine",regimen:"Norepinephrine 0.01–3 mcg/kg/min IV (first-line vasopressor; MAP target ≥65 mmHg)",notes:"SSC 2021 first-line vasopressor. Add vasopressin 0.03 units/min IV as vasopressor-sparing agent when NE >0.25 mcg/kg/min. Epinephrine as rescue third vasopressor. For refractory vasoplegic shock: hydrocortisone 200mg/day IV continuous infusion (ADRENAL trial: reduces vasopressor duration without clear 90-day mortality benefit). Angiotensin II (Giapreza) as salvage option for catecholamine-refractory shock. Target MAP ≥65 mmHg — higher targets (MAP 80–85) not beneficial except in chronic hypertension (SEPSISPAM trial).",evidence:"A-I",evidenceSource:"SSC 2021; SEPSISPAM Trial NEJM 2014"}]}],pearls:["Hour-1 bundle: (1) Blood cultures ×2 before antibiotics. (2) Lactate — repeat if >2 mmol/L. (3) Broad-spectrum antibiotics within 1 hour. (4) 30 mL/kg IV balanced crystalloid for MAP <65 or lactate ≥4 mmol/L. (5) Vasopressors for MAP <65 mmHg unresponsive to fluids. EVERY HOUR OF DELAY IN ANTIBIOTICS = higher mortality.","Vancomycin in septic shock — loading dose matters: Give 25–30 mg/kg IV over 1–2 hours to rapidly achieve therapeutic concentrations. Standard maintenance dosing without a loading dose takes 12–24h to reach target AUC — unacceptable in septic shock.","Extended infusion antibiotics for septic shock: PIP-TAZO 4.5g IV over 4h q8h and MEROPENEM 2g IV over 3h q8h dramatically improve PD target attainment (T>MIC). Hemodynamically unstable patients have altered Vd and clearance — extended infusion compensates for pharmacokinetic variability.","Source control is the antimicrobial adjuvant that works: Drainage of abscess, removal of infected catheter, debridement of necrotic tissue, resection of gangrenous bowel — these interventions reduce bacterial inoculum dramatically and improve antimicrobial efficacy. Source control within 6–12h of septic shock identification.","Valproic acid interaction with carbapenems: Meropenem, imipenem, ertapenem, and doripenem reduce valproic acid levels by 60–100% within 24–48 hours. A patient with epilepsy on VPA who receives a carbapenem is at high risk for breakthrough seizures. Always check the full medication list before ordering carbapenems — switch VPA to levetiracetam or lacosamide if carbapenem is needed.","Procalcitonin-guided de-escalation: PCT decline >80% from peak OR absolute PCT <0.5 ng/mL correlates with successful infection control. Use serial PCT to guide antibiotic discontinuation and prevent unnecessarily prolonged courses. PCT is less reliable for specific organisms (Legionella, viral infections, fungal infections — PCT may not rise)."]}],drugMonographs:[]},o=[s,c,l,d,m,p,u,h,g,f,y,b,v,I,A],S=(()=>{const i=new Set,a=[];return o.forEach(e=>{e.drugMonographs.forEach(t=>{i.has(t.id)||(i.add(t.id),a.push({...t,parentDisease:e}))})}),a.sort((e,t)=>e.name.localeCompare(t.name))})(),T=o.reduce((i,a)=>i+a.subcategories.length,0),w=Object.fromEntries(o.map(i=>[i.id,i])),E=Object.fromEntries(o.map(i=>[i.id,Object.fromEntries(i.subcategories.map(a=>[a.id,a]))])),C=Object.fromEntries(S.map(i=>[i.id,{disease:i.parentDisease,monograph:i}])),P=(()=>{const i={};return o.forEach(a=>{a.drugMonographs.forEach(e=>{i[e.id]??=[],i[e.id].push(a)})}),i})(),D=(()=>{const i=[];return o.forEach(a=>{i.push({type:"disease",disease:a,text:[a.name,a.overview.definition,a.category].filter(Boolean).join(" ").toLowerCase()}),a.subcategories.forEach(e=>{const t=[e.name,e.definition,...e.pearls??[]];e.empiricTherapy?.forEach(n=>{t.push(n.line),n.options.forEach(r=>{t.push(r.regimen),t.push(r.notes??"")})}),e.organismSpecific?.forEach(n=>{t.push(n.organism,n.notes??"",n.preferred??"",n.alternative??"")}),i.push({type:"subcategory",disease:a,subcategory:e,text:t.filter(Boolean).join(" ").toLowerCase(),matchClassify:n=>e.name.toLowerCase().includes(n)||e.definition.toLowerCase().includes(n)?"name":e.pearls?.some(r=>r.toLowerCase().includes(n))?"pearl":"empiric"}),e.organismSpecific?.forEach(n=>{i.push({type:"organism",disease:a,subcategory:e,organism:n,text:[n.organism,n.preferred,n.alternative,n.notes].filter(Boolean).join(" ").toLowerCase()})})}),a.drugMonographs.forEach(e=>{i.push({type:"drug",disease:a,drug:e,text:[e.name,e.brandNames,e.drugClass,e.spectrum,e.mechanismOfAction,...e.pharmacistPearls??[],...e.drugInteractions??[]].filter(Boolean).join(" ").toLowerCase()})})}),i})();function R(i){return C[i]??null}export{S as A,w as D,C as M,E as S,T,D as a,o as b,P as c,R as f};
